window.bibleReaderData = window.bibleReaderData || {chapters:{}};
window.bibleReaderData.chapters = window.bibleReaderData.chapters || {};
(function(chapters){ for (const b in chapters){ window.bibleReaderData.chapters[b]=window.bibleReaderData.chapters[b]||{}; for (const c in chapters[b]){ window.bibleReaderData.chapters[b][c]=window.bibleReaderData.chapters[b][c]||{}; Object.assign(window.bibleReaderData.chapters[b][c], chapters[b][c]); } } })({"MAT":{"1":{"en":[{"v":1,"t":"The book of the genealogy of Jesus Christ, the son of David, the son of Abraham."},{"v":2,"t":"Abraham became the father of Isaac. Isaac became the father of Jacob. Jacob became the father of Judah and his brothers."},{"v":3,"t":"Judah became the father of Perez and Zerah by Tamar. Perez became the father of Hezron. Hezron became the father of Ram."},{"v":4,"t":"Ram became the father of Amminadab. Amminadab became the father of Nahshon. Nahshon became the father of Salmon."},{"v":5,"t":"Salmon became the father of Boaz by Rahab. Boaz became the father of Obed by Ruth. Obed became the father of Jesse."},{"v":6,"t":"Jesse became the father of King David. David the king became the father of Solomon by her who had been Uriah’s wife."},{"v":7,"t":"Solomon became the father of Rehoboam. Rehoboam became the father of Abijah. Abijah became the father of Asa."},{"v":8,"t":"Asa became the father of Jehoshaphat. Jehoshaphat became the father of Joram. Joram became the father of Uzziah."},{"v":9,"t":"Uzziah became the father of Jotham. Jotham became the father of Ahaz. Ahaz became the father of Hezekiah."},{"v":10,"t":"Hezekiah became the father of Manasseh. Manasseh became the father of Amon. Amon became the father of Josiah."},{"v":11,"t":"Josiah became the father of Jechoniah and his brothers at the time of the exile to Babylon."},{"v":12,"t":"After the exile to Babylon, Jechoniah became the father of Shealtiel. Shealtiel became the father of Zerubbabel."},{"v":13,"t":"Zerubbabel became the father of Abiud. Abiud became the father of Eliakim. Eliakim became the father of Azor."},{"v":14,"t":"Azor became the father of Zadok. Zadok became the father of Achim. Achim became the father of Eliud."},{"v":15,"t":"Eliud became the father of Eleazar. Eleazar became the father of Matthan. Matthan became the father of Jacob."},{"v":16,"t":"Jacob became the father of Joseph, the husband of Mary, from whom was born Jesus, who is called Christ."},{"v":17,"t":"So all the generations from Abraham to David are fourteen generations; from David to the exile to Babylon fourteen generations; and from the carrying away to Babylon to the Christ, fourteen generations."},{"v":18,"t":"Now the birth of Jesus Christ was like this: After his mother, Mary, was engaged to Joseph, before they came together, she was found pregnant by the Holy Spirit."},{"v":19,"t":"Joseph, her husband, being a righteous man, and not willing to make her a public example, intended to put her away secretly."},{"v":20,"t":"But when he thought about these things, behold, an angel of the Lord appeared to him in a dream, saying, “Joseph, son of David, don’t be afraid to take to yourself Mary as your wife, for that which is conceived in her is of the Holy Spirit."},{"v":21,"t":"She shall give birth to a son. You shall name him Jesus, for it is he who shall save his people from their sins.”"},{"v":22,"t":"Now all this has happened that it might be fulfilled which was spoken by the Lord through the prophet, saying,"},{"v":23,"t":"“Behold, the virgin shall be with child, and shall give birth to a son. They shall call his name Immanuel,” which is, being interpreted, “God with us.”"},{"v":24,"t":"Joseph arose from his sleep, and did as the angel of the Lord commanded him, and took his wife to himself;"},{"v":25,"t":"and didn’t know her sexually until she had given birth to her firstborn son. He named him Jesus."}]},"2":{"en":[{"v":1,"t":"Now when Jesus was born in Bethlehem of Judea in the days of King Herod, behold, wise men from the east came to Jerusalem, saying,"},{"v":2,"t":"“Where is he who is born King of the Jews? For we saw his star in the east, and have come to worship him.”"},{"v":3,"t":"When King Herod heard it, he was troubled, and all Jerusalem with him."},{"v":4,"t":"Gathering together all the chief priests and scribes of the people, he asked them where the Christ would be born."},{"v":5,"t":"They said to him, “In Bethlehem of Judea, for this is written through the prophet,"},{"v":6,"t":"‘You Bethlehem, land of Judah, are in no way least among the princes of Judah; for out of you shall come a governor who shall shepherd my people, Israel.’”"},{"v":7,"t":"Then Herod secretly called the wise men, and learned from them exactly what time the star appeared."},{"v":8,"t":"He sent them to Bethlehem, and said, “Go and search diligently for the young child. When you have found him, bring me word, so that I also may come and worship him.”"},{"v":9,"t":"They, having heard the king, went their way; and behold, the star, which they saw in the east, went before them until it came and stood over where the young child was."},{"v":10,"t":"When they saw the star, they rejoiced with exceedingly great joy."},{"v":11,"t":"They came into the house and saw the young child with Mary, his mother, and they fell down and worshiped him. Opening their treasures, they offered to him gifts: gold, frankincense, and myrrh."},{"v":12,"t":"Being warned in a dream not to return to Herod, they went back to their own country another way."},{"v":13,"t":"Now when they had departed, behold, an angel of the Lord appeared to Joseph in a dream, saying, “Arise and take the young child and his mother, and flee into Egypt, and stay there until I tell you, for Herod will seek the young child to destroy him.”"},{"v":14,"t":"He arose and took the young child and his mother by night and departed into Egypt,"},{"v":15,"t":"and was there until the death of Herod, that it might be fulfilled which was spoken by the Lord through the prophet, saying, “Out of Egypt I called my son.”"},{"v":16,"t":"Then Herod, when he saw that he was mocked by the wise men, was exceedingly angry, and sent out and killed all the male children who were in Bethlehem and in all the surrounding countryside, from two years old and under, according to the exact time which he had learned from the wise men."},{"v":17,"t":"Then that which was spoken by Jeremiah the prophet was fulfilled, saying,"},{"v":18,"t":"“A voice was heard in Ramah, lamentation, weeping and great mourning, Rachel weeping for her children; she wouldn’t be comforted, because they are no more.”"},{"v":19,"t":"But when Herod was dead, behold, an angel of the Lord appeared in a dream to Joseph in Egypt, saying,"},{"v":20,"t":"“Arise and take the young child and his mother, and go into the land of Israel, for those who sought the young child’s life are dead.”"},{"v":21,"t":"He arose and took the young child and his mother, and came into the land of Israel."},{"v":22,"t":"But when he heard that Archelaus was reigning over Judea in the place of his father, Herod, he was afraid to go there. Being warned in a dream, he withdrew into the region of Galilee,"},{"v":23,"t":"and came and lived in a city called Nazareth; that it might be fulfilled which was spoken through the prophets that he will be called a Nazarene."}]},"3":{"en":[{"v":1,"t":"In those days, John the Baptizer came, preaching in the wilderness of Judea, saying,"},{"v":2,"t":"“Repent, for the Kingdom of Heaven is at hand!”"},{"v":3,"t":"For this is he who was spoken of by Isaiah the prophet, saying, “The voice of one crying in the wilderness, make the way of the Lord ready! Make his paths straight!”"},{"v":4,"t":"Now John himself wore clothing made of camel’s hair with a leather belt around his waist. His food was locusts and wild honey."},{"v":5,"t":"Then people from Jerusalem, all of Judea, and all the region around the Jordan went out to him."},{"v":6,"t":"They were baptized by him in the Jordan, confessing their sins."},{"v":7,"t":"But when he saw many of the Pharisees and Sadducees coming for his baptism, he said to them, “You offspring of vipers, who warned you to flee from the wrath to come?"},{"v":8,"t":"Therefore produce fruit worthy of repentance!"},{"v":9,"t":"Don’t think to yourselves, ‘We have Abraham for our father,’ for I tell you that God is able to raise up children to Abraham from these stones."},{"v":10,"t":"Even now the ax lies at the root of the trees. Therefore every tree that doesn’t produce good fruit is cut down, and cast into the fire."},{"v":11,"t":"“I indeed baptize you in water for repentance, but he who comes after me is mightier than I, whose sandals I am not worthy to carry. He will baptize you in the Holy Spirit."},{"v":12,"t":"His winnowing fork is in his hand, and he will thoroughly cleanse his threshing floor. He will gather his wheat into the barn, but the chaff he will burn up with unquenchable fire.”"},{"v":13,"t":"Then Jesus came from Galilee to the Jordan to John, to be baptized by him."},{"v":14,"t":"But John would have hindered him, saying, “I need to be baptized by you, and you come to me?”"},{"v":15,"t":"But Jesus, answering, said to him, “Allow it now, for this is the fitting way for us to fulfill all righteousness.” Then he allowed him."},{"v":16,"t":"Jesus, when he was baptized, went up directly from the water: and behold, the heavens were opened to him. He saw the Spirit of God descending as a dove, and coming on him."},{"v":17,"t":"Behold, a voice out of the heavens said, “This is my beloved Son, with whom I am well pleased.”"}]},"4":{"en":[{"v":1,"t":"Then Jesus was led up by the Spirit into the wilderness to be tempted by the devil."},{"v":2,"t":"When he had fasted forty days and forty nights, he was hungry afterward."},{"v":3,"t":"The tempter came and said to him, “If you are the Son of God, command that these stones become bread.”"},{"v":4,"t":"But he answered, “It is written, ‘Man shall not live by bread alone, but by every word that proceeds out of God’s mouth.’”"},{"v":5,"t":"Then the devil took him into the holy city. He set him on the pinnacle of the temple,"},{"v":6,"t":"and said to him, “If you are the Son of God, throw yourself down, for it is written, ‘He will command his angels concerning you,’ and, ‘On their hands they will bear you up, so that you don’t dash your foot against a stone.’”"},{"v":7,"t":"Jesus said to him, “Again, it is written, ‘You shall not test the Lord, your God.’”"},{"v":8,"t":"Again, the devil took him to an exceedingly high mountain, and showed him all the kingdoms of the world and their glory."},{"v":9,"t":"He said to him, “I will give you all of these things, if you will fall down and worship me.”"},{"v":10,"t":"Then Jesus said to him, “Get behind me, Satan! For it is written, ‘You shall worship the Lord your God, and you shall serve him only.’”"},{"v":11,"t":"Then the devil left him, and behold, angels came and served him."},{"v":12,"t":"Now when Jesus heard that John was delivered up, he withdrew into Galilee."},{"v":13,"t":"Leaving Nazareth, he came and lived in Capernaum, which is by the sea, in the region of Zebulun and Naphtali,"},{"v":14,"t":"that it might be fulfilled which was spoken through Isaiah the prophet, saying,"},{"v":15,"t":"“The land of Zebulun and the land of Naphtali, toward the sea, beyond the Jordan, Galilee of the Gentiles,"},{"v":16,"t":"the people who sat in darkness saw a great light; to those who sat in the region and shadow of death, to them light has dawned.”"},{"v":17,"t":"From that time, Jesus began to preach, and to say, “Repent! For the Kingdom of Heaven is at hand.”"},{"v":18,"t":"Walking by the sea of Galilee, he saw two brothers: Simon, who is called Peter, and Andrew, his brother, casting a net into the sea; for they were fishermen."},{"v":19,"t":"He said to them, “Come after me, and I will make you fishers for men.”"},{"v":20,"t":"They immediately left their nets and followed him."},{"v":21,"t":"Going on from there, he saw two other brothers, James the son of Zebedee, and John his brother, in the boat with Zebedee their father, mending their nets. He called them."},{"v":22,"t":"They immediately left the boat and their father, and followed him."},{"v":23,"t":"Jesus went about in all Galilee, teaching in their synagogues, preaching the Good News of the Kingdom, and healing every disease and every sickness among the people."},{"v":24,"t":"The report about him went out into all Syria. They brought to him all who were sick, afflicted with various diseases and torments, possessed with demons, epileptics, and paralytics; and he healed them."},{"v":25,"t":"Great multitudes from Galilee, Decapolis, Jerusalem, Judea, and from beyond the Jordan followed him."}]},"5":{"en":[{"v":1,"t":"Seeing the multitudes, he went up onto the mountain. When he had sat down, his disciples came to him."},{"v":2,"t":"He opened his mouth and taught them, saying,"},{"v":3,"t":"“Blessed are the poor in spirit, for theirs is the Kingdom of Heaven."},{"v":4,"t":"Blessed are those who mourn, for they shall be comforted."},{"v":5,"t":"Blessed are the gentle, for they shall inherit the earth."},{"v":6,"t":"Blessed are those who hunger and thirst for righteousness, for they shall be filled."},{"v":7,"t":"Blessed are the merciful, for they shall obtain mercy."},{"v":8,"t":"Blessed are the pure in heart, for they shall see God."},{"v":9,"t":"Blessed are the peacemakers, for they shall be called children of God."},{"v":10,"t":"Blessed are those who have been persecuted for righteousness’ sake, for theirs is the Kingdom of Heaven."},{"v":11,"t":"“Blessed are you when people reproach you, persecute you, and say all kinds of evil against you falsely, for my sake."},{"v":12,"t":"Rejoice, and be exceedingly glad, for great is your reward in heaven. For that is how they persecuted the prophets who were before you."},{"v":13,"t":"“You are the salt of the earth, but if the salt has lost its flavor, with what will it be salted? It is then good for nothing, but to be cast out and trodden under the feet of men."},{"v":14,"t":"You are the light of the world. A city located on a hill can’t be hidden."},{"v":15,"t":"Neither do you light a lamp and put it under a measuring basket, but on a stand; and it shines to all who are in the house."},{"v":16,"t":"Even so, let your light shine before men, that they may see your good works and glorify your Father who is in heaven."},{"v":17,"t":"“Don’t think that I came to destroy the law or the prophets. I didn’t come to destroy, but to fulfill."},{"v":18,"t":"For most certainly, I tell you, until heaven and earth pass away, not even one smallest letter or one tiny pen stroke shall in any way pass away from the law, until all things are accomplished."},{"v":19,"t":"Therefore, whoever shall break one of these least commandments and teach others to do so, shall be called least in the Kingdom of Heaven; but whoever shall do and teach them shall be called great in the Kingdom of Heaven."},{"v":20,"t":"For I tell you that unless your righteousness exceeds that of the scribes and Pharisees, there is no way you will enter into the Kingdom of Heaven."},{"v":21,"t":"“You have heard that it was said to the ancient ones, ‘You shall not murder;’ and ‘Whoever murders will be in danger of the judgment.’"},{"v":22,"t":"But I tell you that everyone who is angry with his brother without a cause will be in danger of the judgment. Whoever says to his brother, ‘Raca!’ will be in danger of the council. Whoever says, ‘You fool!’ will be in danger of the fire of Gehenna."},{"v":23,"t":"“If therefore you are offering your gift at the altar, and there remember that your brother has anything against you,"},{"v":24,"t":"leave your gift there before the altar, and go your way. First be reconciled to your brother, and then come and offer your gift."},{"v":25,"t":"Agree with your adversary quickly while you are with him on the way; lest perhaps the prosecutor deliver you to the judge, and the judge deliver you to the officer, and you be cast into prison."},{"v":26,"t":"Most certainly I tell you, you shall by no means get out of there until you have paid the last penny."},{"v":27,"t":"“You have heard that it was said, ‘You shall not commit adultery;’"},{"v":28,"t":"but I tell you that everyone who gazes at a woman to lust after her has committed adultery with her already in his heart."},{"v":29,"t":"If your right eye causes you to stumble, pluck it out and throw it away from you. For it is more profitable for you that one of your members should perish than for your whole body to be cast into Gehenna."},{"v":30,"t":"If your right hand causes you to stumble, cut it off, and throw it away from you. For it is more profitable for you that one of your members should perish, than for your whole body to be cast into Gehenna."},{"v":31,"t":"“It was also said, ‘Whoever shall put away his wife, let him give her a writing of divorce,’"},{"v":32,"t":"but I tell you that whoever puts away his wife, except for the cause of sexual immorality, makes her an adulteress; and whoever marries her when she is put away commits adultery."},{"v":33,"t":"“Again you have heard that it was said to the ancient ones, ‘You shall not make false vows, but shall perform to the Lord your vows,’"},{"v":34,"t":"but I tell you, don’t swear at all: neither by heaven, for it is the throne of God;"},{"v":35,"t":"nor by the earth, for it is the footstool of his feet; nor by Jerusalem, for it is the city of the great King."},{"v":36,"t":"Neither shall you swear by your head, for you can’t make one hair white or black."},{"v":37,"t":"But let your ‘Yes’ be ‘Yes’ and your ‘No’ be ‘No.’ Whatever is more than these is of the evil one."},{"v":38,"t":"“You have heard that it was said, ‘An eye for an eye, and a tooth for a tooth.’"},{"v":39,"t":"But I tell you, don’t resist him who is evil; but whoever strikes you on your right cheek, turn to him the other also."},{"v":40,"t":"If anyone sues you to take away your coat, let him have your cloak also."},{"v":41,"t":"Whoever compels you to go one mile, go with him two."},{"v":42,"t":"Give to him who asks you, and don’t turn away him who desires to borrow from you."},{"v":43,"t":"“You have heard that it was said, ‘You shall love your neighbor and hate your enemy.’"},{"v":44,"t":"But I tell you, love your enemies, bless those who curse you, do good to those who hate you, and pray for those who mistreat you and persecute you,"},{"v":45,"t":"that you may be children of your Father who is in heaven. For he makes his sun to rise on the evil and the good, and sends rain on the just and the unjust."},{"v":46,"t":"For if you love those who love you, what reward do you have? Don’t even the tax collectors do the same?"},{"v":47,"t":"If you only greet your friends, what more do you do than others? Don’t even the tax collectors do the same?"},{"v":48,"t":"Therefore you shall be perfect, just as your Father in heaven is perfect."}]},"6":{"en":[{"v":1,"t":"“Be careful that you don’t do your charitable giving before men, to be seen by them, or else you have no reward from your Father who is in heaven."},{"v":2,"t":"Therefore, when you do merciful deeds, don’t sound a trumpet before yourself, as the hypocrites do in the synagogues and in the streets, that they may get glory from men. Most certainly I tell you, they have received their reward."},{"v":3,"t":"But when you do merciful deeds, don’t let your left hand know what your right hand does,"},{"v":4,"t":"so that your merciful deeds may be in secret, then your Father who sees in secret will reward you openly."},{"v":5,"t":"“When you pray, you shall not be as the hypocrites, for they love to stand and pray in the synagogues and in the corners of the streets, that they may be seen by men. Most certainly, I tell you, they have received their reward."},{"v":6,"t":"But you, when you pray, enter into your inner room, and having shut your door, pray to your Father who is in secret; and your Father who sees in secret will reward you openly."},{"v":7,"t":"In praying, don’t use vain repetitions as the Gentiles do; for they think that they will be heard for their much speaking."},{"v":8,"t":"Therefore don’t be like them, for your Father knows what things you need before you ask him."},{"v":9,"t":"Pray like this: “‘Our Father in heaven, may your name be kept holy."},{"v":10,"t":"Let your Kingdom come. Let your will be done on earth as it is in heaven."},{"v":11,"t":"Give us today our daily bread."},{"v":12,"t":"Forgive us our debts, as we also forgive our debtors."},{"v":13,"t":"Bring us not into temptation, but deliver us from the evil one. For yours is the Kingdom, the power, and the glory forever. Amen.’"},{"v":14,"t":"“For if you forgive men their trespasses, your heavenly Father will also forgive you."},{"v":15,"t":"But if you don’t forgive men their trespasses, neither will your Father forgive your trespasses."},{"v":16,"t":"“Moreover when you fast, don’t be like the hypocrites, with sad faces. For they disfigure their faces that they may be seen by men to be fasting. Most certainly I tell you, they have received their reward."},{"v":17,"t":"But you, when you fast, anoint your head and wash your face,"},{"v":18,"t":"so that you are not seen by men to be fasting, but by your Father who is in secret; and your Father, who sees in secret, will reward you."},{"v":19,"t":"“Don’t lay up treasures for yourselves on the earth, where moth and rust consume, and where thieves break through and steal;"},{"v":20,"t":"but lay up for yourselves treasures in heaven, where neither moth nor rust consume, and where thieves don’t break through and steal;"},{"v":21,"t":"for where your treasure is, there your heart will be also."},{"v":22,"t":"“The lamp of the body is the eye. If therefore your eye is sound, your whole body will be full of light."},{"v":23,"t":"But if your eye is evil, your whole body will be full of darkness. If therefore the light that is in you is darkness, how great is the darkness!"},{"v":24,"t":"“No one can serve two masters, for either he will hate the one and love the other, or else he will be devoted to one and despise the other. You can’t serve both God and Mammon."},{"v":25,"t":"Therefore I tell you, don’t be anxious for your life: what you will eat, or what you will drink; nor yet for your body, what you will wear. Isn’t life more than food, and the body more than clothing?"},{"v":26,"t":"See the birds of the sky, that they don’t sow, neither do they reap, nor gather into barns. Your heavenly Father feeds them. Aren’t you of much more value than they?"},{"v":27,"t":"“Which of you by being anxious, can add one moment to his lifespan?"},{"v":28,"t":"Why are you anxious about clothing? Consider the lilies of the field, how they grow. They don’t toil, neither do they spin,"},{"v":29,"t":"yet I tell you that even Solomon in all his glory was not dressed like one of these."},{"v":30,"t":"But if God so clothes the grass of the field, which today exists and tomorrow is thrown into the oven, won’t he much more clothe you, you of little faith?"},{"v":31,"t":"“Therefore don’t be anxious, saying, ‘What will we eat?’, ‘What will we drink?’ or, ‘With what will we be clothed?’"},{"v":32,"t":"For the Gentiles seek after all these things; for your heavenly Father knows that you need all these things."},{"v":33,"t":"But seek first God’s Kingdom and his righteousness; and all these things will be given to you as well."},{"v":34,"t":"Therefore don’t be anxious for tomorrow, for tomorrow will be anxious for itself. Each day’s own evil is sufficient."}]},"7":{"en":[{"v":1,"t":"“Don’t judge, so that you won’t be judged."},{"v":2,"t":"For with whatever judgment you judge, you will be judged; and with whatever measure you measure, it will be measured to you."},{"v":3,"t":"Why do you see the speck that is in your brother’s eye, but don’t consider the beam that is in your own eye?"},{"v":4,"t":"Or how will you tell your brother, ‘Let me remove the speck from your eye,’ and behold, the beam is in your own eye?"},{"v":5,"t":"You hypocrite! First remove the beam out of your own eye, and then you can see clearly to remove the speck out of your brother’s eye."},{"v":6,"t":"“Don’t give that which is holy to the dogs, neither throw your pearls before the pigs, lest perhaps they trample them under their feet, and turn and tear you to pieces."},{"v":7,"t":"“Ask, and it will be given you. Seek, and you will find. Knock, and it will be opened for you."},{"v":8,"t":"For everyone who asks receives. He who seeks finds. To him who knocks it will be opened."},{"v":9,"t":"Or who is there among you who, if his son asks him for bread, will give him a stone?"},{"v":10,"t":"Or if he asks for a fish, who will give him a serpent?"},{"v":11,"t":"If you then, being evil, know how to give good gifts to your children, how much more will your Father who is in heaven give good things to those who ask him!"},{"v":12,"t":"Therefore, whatever you desire for men to do to you, you shall also do to them; for this is the law and the prophets."},{"v":13,"t":"“Enter in by the narrow gate; for the gate is wide and the way is broad that leads to destruction, and there are many who enter in by it."},{"v":14,"t":"How narrow is the gate and the way is restricted that leads to life! There are few who find it."},{"v":15,"t":"“Beware of false prophets, who come to you in sheep’s clothing, but inwardly are ravening wolves."},{"v":16,"t":"By their fruits you will know them. Do you gather grapes from thorns or figs from thistles?"},{"v":17,"t":"Even so, every good tree produces good fruit, but the corrupt tree produces evil fruit."},{"v":18,"t":"A good tree can’t produce evil fruit, neither can a corrupt tree produce good fruit."},{"v":19,"t":"Every tree that doesn’t grow good fruit is cut down and thrown into the fire."},{"v":20,"t":"Therefore by their fruits you will know them."},{"v":21,"t":"“Not everyone who says to me, ‘Lord, Lord,’ will enter into the Kingdom of Heaven, but he who does the will of my Father who is in heaven."},{"v":22,"t":"Many will tell me in that day, ‘Lord, Lord, didn’t we prophesy in your name, in your name cast out demons, and in your name do many mighty works?’"},{"v":23,"t":"Then I will tell them, ‘I never knew you. Depart from me, you who work iniquity.’"},{"v":24,"t":"“Everyone therefore who hears these words of mine and does them, I will liken him to a wise man who built his house on the rock."},{"v":25,"t":"The rain came down, the floods came, and the winds blew and beat on that house; and it didn’t fall, for it was founded on the rock."},{"v":26,"t":"Everyone who hears these words of mine and doesn’t do them will be like a foolish man who built his house on the sand."},{"v":27,"t":"The rain came down, the floods came, and the winds blew and beat on that house; and it fell—and its fall was great.”"},{"v":28,"t":"When Jesus had finished saying these things, the multitudes were astonished at his teaching,"},{"v":29,"t":"for he taught them with authority, and not like the scribes."}]},"8":{"en":[{"v":1,"t":"When he came down from the mountain, great multitudes followed him."},{"v":2,"t":"Behold, a leper came to him and worshiped him, saying, “Lord, if you want to, you can make me clean.”"},{"v":3,"t":"Jesus stretched out his hand and touched him, saying, “I want to. Be made clean.” Immediately his leprosy was cleansed."},{"v":4,"t":"Jesus said to him, “See that you tell nobody; but go, show yourself to the priest, and offer the gift that Moses commanded, as a testimony to them.”"},{"v":5,"t":"When he came into Capernaum, a centurion came to him, asking him for help,"},{"v":6,"t":"saying, “Lord, my servant lies in the house paralyzed, grievously tormented.”"},{"v":7,"t":"Jesus said to him, “I will come and heal him.”"},{"v":8,"t":"The centurion answered, “Lord, I’m not worthy for you to come under my roof. Just say the word, and my servant will be healed."},{"v":9,"t":"For I am also a man under authority, having under myself soldiers. I tell this one, ‘Go,’ and he goes; and tell another, ‘Come,’ and he comes; and tell my servant, ‘Do this,’ and he does it.”"},{"v":10,"t":"When Jesus heard it, he marveled and said to those who followed, “Most certainly I tell you, I haven’t found so great a faith, not even in Israel."},{"v":11,"t":"I tell you that many will come from the east and the west, and will sit down with Abraham, Isaac, and Jacob in the Kingdom of Heaven,"},{"v":12,"t":"but the children of the Kingdom will be thrown out into the outer darkness. There will be weeping and gnashing of teeth.”"},{"v":13,"t":"Jesus said to the centurion, “Go your way. Let it be done for you as you have believed.” His servant was healed in that hour."},{"v":14,"t":"When Jesus came into Peter’s house, he saw his wife’s mother lying sick with a fever."},{"v":15,"t":"He touched her hand, and the fever left her. So she got up and served him."},{"v":16,"t":"When evening came, they brought to him many possessed with demons. He cast out the spirits with a word, and healed all who were sick,"},{"v":17,"t":"that it might be fulfilled which was spoken through Isaiah the prophet, saying, “He took our infirmities and bore our diseases.”"},{"v":18,"t":"Now when Jesus saw great multitudes around him, he gave the order to depart to the other side."},{"v":19,"t":"A scribe came and said to him, “Teacher, I will follow you wherever you go.”"},{"v":20,"t":"Jesus said to him, “The foxes have holes and the birds of the sky have nests, but the Son of Man has nowhere to lay his head.”"},{"v":21,"t":"Another of his disciples said to him, “Lord, allow me first to go and bury my father.”"},{"v":22,"t":"But Jesus said to him, “Follow me, and leave the dead to bury their own dead.”"},{"v":23,"t":"When he got into a boat, his disciples followed him."},{"v":24,"t":"Behold, a violent storm came up on the sea, so much that the boat was covered with the waves; but he was asleep."},{"v":25,"t":"The disciples came to him and woke him up, saying, “Save us, Lord! We are dying!”"},{"v":26,"t":"He said to them, “Why are you fearful, O you of little faith?” Then he got up, rebuked the wind and the sea, and there was a great calm."},{"v":27,"t":"The men marveled, saying, “What kind of man is this, that even the wind and the sea obey him?”"},{"v":28,"t":"When he came to the other side, into the country of the Gergesenes, two people possessed by demons met him there, coming out of the tombs, exceedingly fierce, so that nobody could pass that way."},{"v":29,"t":"Behold, they cried out, saying, “What do we have to do with you, Jesus, Son of God? Have you come here to torment us before the time?”"},{"v":30,"t":"Now there was a herd of many pigs feeding far away from them."},{"v":31,"t":"The demons begged him, saying, “If you cast us out, permit us to go away into the herd of pigs.”"},{"v":32,"t":"He said to them, “Go!” They came out and went into the herd of pigs; and behold, the whole herd of pigs rushed down the cliff into the sea and died in the water."},{"v":33,"t":"Those who fed them fled and went away into the city and told everything, including what happened to those who were possessed with demons."},{"v":34,"t":"Behold, all the city came out to meet Jesus. When they saw him, they begged that he would depart from their borders."}]},"9":{"en":[{"v":1,"t":"He entered into a boat and crossed over, and came into his own city."},{"v":2,"t":"Behold, they brought to him a man who was paralyzed, lying on a bed. Jesus, seeing their faith, said to the paralytic, “Son, cheer up! Your sins are forgiven you.”"},{"v":3,"t":"Behold, some of the scribes said to themselves, “This man blasphemes.”"},{"v":4,"t":"Jesus, knowing their thoughts, said, “Why do you think evil in your hearts?"},{"v":5,"t":"For which is easier, to say, ‘Your sins are forgiven;’ or to say, ‘Get up, and walk’?"},{"v":6,"t":"But that you may know that the Son of Man has authority on earth to forgive sins—” (then he said to the paralytic), “Get up, and take up your mat, and go to your house.”"},{"v":7,"t":"He arose and departed to his house."},{"v":8,"t":"But when the multitudes saw it, they marveled and glorified God, who had given such authority to men."},{"v":9,"t":"As Jesus passed by from there, he saw a man called Matthew sitting at the tax collection office. He said to him, “Follow me.” He got up and followed him."},{"v":10,"t":"As he sat in the house, behold, many tax collectors and sinners came and sat down with Jesus and his disciples."},{"v":11,"t":"When the Pharisees saw it, they said to his disciples, “Why does your teacher eat with tax collectors and sinners?”"},{"v":12,"t":"When Jesus heard it, he said to them, “Those who are healthy have no need for a physician, but those who are sick do."},{"v":13,"t":"But you go and learn what this means: ‘I desire mercy, and not sacrifice,’ for I came not to call the righteous, but sinners to repentance.”"},{"v":14,"t":"Then John’s disciples came to him, saying, “Why do we and the Pharisees fast often, but your disciples don’t fast?”"},{"v":15,"t":"Jesus said to them, “Can the friends of the bridegroom mourn as long as the bridegroom is with them? But the days will come when the bridegroom will be taken away from them, and then they will fast."},{"v":16,"t":"No one puts a piece of unshrunk cloth on an old garment; for the patch would tear away from the garment, and a worse hole is made."},{"v":17,"t":"Neither do people put new wine into old wineskins, or else the skins would burst, and the wine be spilled, and the skins ruined. No, they put new wine into fresh wineskins, and both are preserved.”"},{"v":18,"t":"While he told these things to them, behold, a ruler came and worshiped him, saying, “My daughter has just died, but come and lay your hand on her, and she will live.”"},{"v":19,"t":"Jesus got up and followed him, as did his disciples."},{"v":20,"t":"Behold, a woman who had a discharge of blood for twelve years came behind him, and touched the fringe of his garment;"},{"v":21,"t":"for she said within herself, “If I just touch his garment, I will be made well.”"},{"v":22,"t":"But Jesus, turning around and seeing her, said, “Daughter, cheer up! Your faith has made you well.” And the woman was made well from that hour."},{"v":23,"t":"When Jesus came into the ruler’s house and saw the flute players and the crowd in noisy disorder,"},{"v":24,"t":"he said to them, “Make room, because the girl isn’t dead, but sleeping.” They were ridiculing him."},{"v":25,"t":"But when the crowd was sent out, he entered in, took her by the hand, and the girl arose."},{"v":26,"t":"The report of this went out into all that land."},{"v":27,"t":"As Jesus passed by from there, two blind men followed him, calling out and saying, “Have mercy on us, son of David!”"},{"v":28,"t":"When he had come into the house, the blind men came to him. Jesus said to them, “Do you believe that I am able to do this?” They told him, “Yes, Lord.”"},{"v":29,"t":"Then he touched their eyes, saying, “According to your faith be it done to you.”"},{"v":30,"t":"Then their eyes were opened. Jesus strictly commanded them, saying, “See that no one knows about this.”"},{"v":31,"t":"But they went out and spread abroad his fame in all that land."},{"v":32,"t":"As they went out, behold, a mute man who was demon possessed was brought to him."},{"v":33,"t":"When the demon was cast out, the mute man spoke. The multitudes marveled, saying, “Nothing like this has ever been seen in Israel!”"},{"v":34,"t":"But the Pharisees said, “By the prince of the demons, he casts out demons.”"},{"v":35,"t":"Jesus went about all the cities and the villages, teaching in their synagogues and preaching the Good News of the Kingdom, and healing every disease and every sickness among the people."},{"v":36,"t":"But when he saw the multitudes, he was moved with compassion for them because they were harassed and scattered, like sheep without a shepherd."},{"v":37,"t":"Then he said to his disciples, “The harvest indeed is plentiful, but the laborers are few."},{"v":38,"t":"Pray therefore that the Lord of the harvest will send out laborers into his harvest.”"}]},"10":{"en":[{"v":1,"t":"He called to himself his twelve disciples, and gave them authority over unclean spirits, to cast them out, and to heal every disease and every sickness."},{"v":2,"t":"Now the names of the twelve apostles are these. The first, Simon, who is called Peter; Andrew, his brother; James the son of Zebedee; John, his brother;"},{"v":3,"t":"Philip; Bartholomew; Thomas; Matthew the tax collector; James the son of Alphaeus; Lebbaeus, who was also called Thaddaeus;"},{"v":4,"t":"Simon the Zealot; and Judas Iscariot, who also betrayed him."},{"v":5,"t":"Jesus sent these twelve out and commanded them, saying, “Don’t go among the Gentiles, and don’t enter into any city of the Samaritans."},{"v":6,"t":"Rather, go to the lost sheep of the house of Israel."},{"v":7,"t":"As you go, preach, saying, ‘The Kingdom of Heaven is at hand!’"},{"v":8,"t":"Heal the sick, cleanse the lepers, and cast out demons. Freely you received, so freely give."},{"v":9,"t":"Don’t take any gold, silver, or brass in your money belts."},{"v":10,"t":"Take no bag for your journey, neither two coats, nor sandals, nor staff: for the laborer is worthy of his food."},{"v":11,"t":"Into whatever city or village you enter, find out who in it is worthy, and stay there until you go on."},{"v":12,"t":"As you enter into the household, greet it."},{"v":13,"t":"If the household is worthy, let your peace come on it, but if it isn’t worthy, let your peace return to you."},{"v":14,"t":"Whoever doesn’t receive you or hear your words, as you go out of that house or that city, shake the dust off your feet."},{"v":15,"t":"Most certainly I tell you, it will be more tolerable for the land of Sodom and Gomorrah in the day of judgment than for that city."},{"v":16,"t":"“Behold, I send you out as sheep among wolves. Therefore be wise as serpents and harmless as doves."},{"v":17,"t":"But beware of men, for they will deliver you up to councils, and in their synagogues they will scourge you."},{"v":18,"t":"Yes, and you will be brought before governors and kings for my sake, for a testimony to them and to the nations."},{"v":19,"t":"But when they deliver you up, don’t be anxious how or what you will say, for it will be given you in that hour what you will say."},{"v":20,"t":"For it is not you who speak, but the Spirit of your Father who speaks in you."},{"v":21,"t":"“Brother will deliver up brother to death, and the father his child. Children will rise up against parents and cause them to be put to death."},{"v":22,"t":"You will be hated by all men for my name’s sake, but he who endures to the end will be saved."},{"v":23,"t":"But when they persecute you in this city, flee into the next, for most certainly I tell you, you will not have gone through the cities of Israel until the Son of Man has come."},{"v":24,"t":"“A disciple is not above his teacher, nor a servant above his lord."},{"v":25,"t":"It is enough for the disciple that he be like his teacher, and the servant like his lord. If they have called the master of the house Beelzebul, how much more those of his household!"},{"v":26,"t":"Therefore don’t be afraid of them, for there is nothing covered that will not be revealed, or hidden that will not be known."},{"v":27,"t":"What I tell you in the darkness, speak in the light; and what you hear whispered in the ear, proclaim on the housetops."},{"v":28,"t":"Don’t be afraid of those who kill the body, but are not able to kill the soul. Rather, fear him who is able to destroy both soul and body in Gehenna."},{"v":29,"t":"“Aren’t two sparrows sold for an assarion coin? Not one of them falls to the ground apart from your Father’s will."},{"v":30,"t":"But the very hairs of your head are all numbered."},{"v":31,"t":"Therefore don’t be afraid. You are of more value than many sparrows."},{"v":32,"t":"Everyone therefore who confesses me before men, I will also confess him before my Father who is in heaven."},{"v":33,"t":"But whoever denies me before men, I will also deny him before my Father who is in heaven."},{"v":34,"t":"“Don’t think that I came to send peace on the earth. I didn’t come to send peace, but a sword."},{"v":35,"t":"For I came to set a man at odds against his father, and a daughter against her mother, and a daughter-in-law against her mother-in-law."},{"v":36,"t":"A man’s foes will be those of his own household."},{"v":37,"t":"He who loves father or mother more than me is not worthy of me; and he who loves son or daughter more than me isn’t worthy of me."},{"v":38,"t":"He who doesn’t take his cross and follow after me isn’t worthy of me."},{"v":39,"t":"He who seeks his life will lose it; and he who loses his life for my sake will find it."},{"v":40,"t":"“He who receives you receives me, and he who receives me receives him who sent me."},{"v":41,"t":"He who receives a prophet in the name of a prophet will receive a prophet’s reward. He who receives a righteous man in the name of a righteous man will receive a righteous man’s reward."},{"v":42,"t":"Whoever gives one of these little ones just a cup of cold water to drink in the name of a disciple, most certainly I tell you, he will in no way lose his reward.”"}]},"11":{"en":[{"v":1,"t":"When Jesus had finished directing his twelve disciples, he departed from there to teach and preach in their cities."},{"v":2,"t":"Now when John heard in the prison the works of Christ, he sent two of his disciples"},{"v":3,"t":"and said to him, “Are you he who comes, or should we look for another?”"},{"v":4,"t":"Jesus answered them, “Go and tell John the things which you hear and see:"},{"v":5,"t":"the blind receive their sight, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised up, and the poor have good news preached to them."},{"v":6,"t":"Blessed is he who finds no occasion for stumbling in me.”"},{"v":7,"t":"As these went their way, Jesus began to say to the multitudes concerning John, “What did you go out into the wilderness to see? A reed shaken by the wind?"},{"v":8,"t":"But what did you go out to see? A man in soft clothing? Behold, those who wear soft clothing are in kings’ houses."},{"v":9,"t":"But why did you go out? To see a prophet? Yes, I tell you, and much more than a prophet."},{"v":10,"t":"For this is he, of whom it is written, ‘Behold, I send my messenger before your face, who will prepare your way before you.’"},{"v":11,"t":"Most certainly I tell you, among those who are born of women there has not arisen anyone greater than John the Baptizer; yet he who is least in the Kingdom of Heaven is greater than he."},{"v":12,"t":"From the days of John the Baptizer until now, the Kingdom of Heaven suffers violence, and the violent take it by force."},{"v":13,"t":"For all the prophets and the law prophesied until John."},{"v":14,"t":"If you are willing to receive it, this is Elijah, who is to come."},{"v":15,"t":"He who has ears to hear, let him hear."},{"v":16,"t":"“But to what shall I compare this generation? It is like children sitting in the marketplaces, who call to their companions"},{"v":17,"t":"and say, ‘We played the flute for you, and you didn’t dance. We mourned for you, and you didn’t lament.’"},{"v":18,"t":"For John came neither eating nor drinking, and they say, ‘He has a demon.’"},{"v":19,"t":"The Son of Man came eating and drinking, and they say, ‘Behold, a gluttonous man and a drunkard, a friend of tax collectors and sinners!’ But wisdom is justified by her children.”"},{"v":20,"t":"Then he began to denounce the cities in which most of his mighty works had been done, because they didn’t repent."},{"v":21,"t":"“Woe to you, Chorazin! Woe to you, Bethsaida! For if the mighty works had been done in Tyre and Sidon which were done in you, they would have repented long ago in sackcloth and ashes."},{"v":22,"t":"But I tell you, it will be more tolerable for Tyre and Sidon on the day of judgment than for you."},{"v":23,"t":"You, Capernaum, who are exalted to heaven, you will go down to Hades. For if the mighty works had been done in Sodom which were done in you, it would have remained until today."},{"v":24,"t":"But I tell you that it will be more tolerable for the land of Sodom on the day of judgment, than for you.”"},{"v":25,"t":"At that time, Jesus answered, “I thank you, Father, Lord of heaven and earth, that you hid these things from the wise and understanding, and revealed them to infants."},{"v":26,"t":"Yes, Father, for so it was well-pleasing in your sight."},{"v":27,"t":"All things have been delivered to me by my Father. No one knows the Son, except the Father; neither does anyone know the Father, except the Son and he to whom the Son desires to reveal him."},{"v":28,"t":"“Come to me, all you who labor and are heavily burdened, and I will give you rest."},{"v":29,"t":"Take my yoke upon you and learn from me, for I am gentle and humble in heart; and you will find rest for your souls."},{"v":30,"t":"For my yoke is easy, and my burden is light.”"}]},"12":{"en":[{"v":1,"t":"At that time, Jesus went on the Sabbath day through the grain fields. His disciples were hungry and began to pluck heads of grain and to eat."},{"v":2,"t":"But the Pharisees, when they saw it, said to him, “Behold, your disciples do what is not lawful to do on the Sabbath.”"},{"v":3,"t":"But he said to them, “Haven’t you read what David did when he was hungry, and those who were with him:"},{"v":4,"t":"how he entered into God’s house and ate the show bread, which was not lawful for him to eat, nor for those who were with him, but only for the priests?"},{"v":5,"t":"Or have you not read in the law that on the Sabbath day the priests in the temple profane the Sabbath and are guiltless?"},{"v":6,"t":"But I tell you that one greater than the temple is here."},{"v":7,"t":"But if you had known what this means, ‘I desire mercy, and not sacrifice,’ you wouldn’t have condemned the guiltless."},{"v":8,"t":"For the Son of Man is Lord of the Sabbath.”"},{"v":9,"t":"He departed from there and went into their synagogue."},{"v":10,"t":"And behold, there was a man with a withered hand. They asked him, “Is it lawful to heal on the Sabbath day?” so that they might accuse him."},{"v":11,"t":"He said to them, “What man is there among you who has one sheep, and if this one falls into a pit on the Sabbath day, won’t he grab on to it and lift it out?"},{"v":12,"t":"Of how much more value then is a man than a sheep! Therefore it is lawful to do good on the Sabbath day.”"},{"v":13,"t":"Then he told the man, “Stretch out your hand.” He stretched it out; and it was restored whole, just like the other."},{"v":14,"t":"But the Pharisees went out and conspired against him, how they might destroy him."},{"v":15,"t":"Jesus, perceiving that, withdrew from there. Great multitudes followed him; and he healed them all,"},{"v":16,"t":"and commanded them that they should not make him known,"},{"v":17,"t":"that it might be fulfilled which was spoken through Isaiah the prophet, saying,"},{"v":18,"t":"“Behold, my servant whom I have chosen, my beloved in whom my soul is well pleased. I will put my Spirit on him. He will proclaim justice to the nations."},{"v":19,"t":"He will not strive, nor shout, neither will anyone hear his voice in the streets."},{"v":20,"t":"He won’t break a bruised reed. He won’t quench a smoking flax, until he leads justice to victory."},{"v":21,"t":"In his name, the nations will hope.”"},{"v":22,"t":"Then one possessed by a demon, blind and mute, was brought to him; and he healed him, so that the blind and mute man both spoke and saw."},{"v":23,"t":"All the multitudes were amazed, and said, “Can this be the son of David?”"},{"v":24,"t":"But when the Pharisees heard it, they said, “This man does not cast out demons except by Beelzebul, the prince of the demons.”"},{"v":25,"t":"Knowing their thoughts, Jesus said to them, “Every kingdom divided against itself is brought to desolation, and every city or house divided against itself will not stand."},{"v":26,"t":"If Satan casts out Satan, he is divided against himself. How then will his kingdom stand?"},{"v":27,"t":"If I by Beelzebul cast out demons, by whom do your children cast them out? Therefore they will be your judges."},{"v":28,"t":"But if I by the Spirit of God cast out demons, then God’s Kingdom has come upon you."},{"v":29,"t":"Or how can one enter into the house of the strong man and plunder his goods, unless he first bind the strong man? Then he will plunder his house."},{"v":30,"t":"“He who is not with me is against me, and he who doesn’t gather with me, scatters."},{"v":31,"t":"Therefore I tell you, every sin and blasphemy will be forgiven men, but the blasphemy against the Spirit will not be forgiven men."},{"v":32,"t":"Whoever speaks a word against the Son of Man, it will be forgiven him; but whoever speaks against the Holy Spirit, it will not be forgiven him, either in this age, or in that which is to come."},{"v":33,"t":"“Either make the tree good and its fruit good, or make the tree corrupt and its fruit corrupt; for the tree is known by its fruit."},{"v":34,"t":"You offspring of vipers, how can you, being evil, speak good things? For out of the abundance of the heart, the mouth speaks."},{"v":35,"t":"The good man out of his good treasure brings out good things, and the evil man out of his evil treasure brings out evil things."},{"v":36,"t":"I tell you that every idle word that men speak, they will give account of it in the day of judgment."},{"v":37,"t":"For by your words you will be justified, and by your words you will be condemned.”"},{"v":38,"t":"Then certain of the scribes and Pharisees answered, “Teacher, we want to see a sign from you.”"},{"v":39,"t":"But he answered them, “An evil and adulterous generation seeks after a sign, but no sign will be given to it but the sign of Jonah the prophet."},{"v":40,"t":"For as Jonah was three days and three nights in the belly of the huge fish, so will the Son of Man be three days and three nights in the heart of the earth."},{"v":41,"t":"The men of Nineveh will stand up in the judgment with this generation and will condemn it, for they repented at the preaching of Jonah; and behold, someone greater than Jonah is here."},{"v":42,"t":"The Queen of the South will rise up in the judgment with this generation and will condemn it, for she came from the ends of the earth to hear the wisdom of Solomon; and behold, someone greater than Solomon is here."},{"v":43,"t":"“When an unclean spirit has gone out of a man, he passes through waterless places seeking rest, and doesn’t find it."},{"v":44,"t":"Then he says, ‘I will return into my house from which I came;’ and when he has come back, he finds it empty, swept, and put in order."},{"v":45,"t":"Then he goes and takes with himself seven other spirits more evil than he is, and they enter in and dwell there. The last state of that man becomes worse than the first. Even so will it be also to this evil generation.”"},{"v":46,"t":"While he was yet speaking to the multitudes, behold, his mother and his brothers stood outside, seeking to speak to him."},{"v":47,"t":"One said to him, “Behold, your mother and your brothers stand outside, seeking to speak to you.”"},{"v":48,"t":"But he answered him who spoke to him, “Who is my mother? Who are my brothers?”"},{"v":49,"t":"He stretched out his hand toward his disciples, and said, “Behold, my mother and my brothers!"},{"v":50,"t":"For whoever does the will of my Father who is in heaven, he is my brother, and sister, and mother.”"}]},"13":{"en":[{"v":1,"t":"On that day Jesus went out of the house and sat by the seaside."},{"v":2,"t":"Great multitudes gathered to him, so that he entered into a boat and sat; and all the multitude stood on the beach."},{"v":3,"t":"He spoke to them many things in parables, saying, “Behold, a farmer went out to sow."},{"v":4,"t":"As he sowed, some seeds fell by the roadside, and the birds came and devoured them."},{"v":5,"t":"Others fell on rocky ground, where they didn’t have much soil, and immediately they sprang up, because they had no depth of earth."},{"v":6,"t":"When the sun had risen, they were scorched. Because they had no root, they withered away."},{"v":7,"t":"Others fell among thorns. The thorns grew up and choked them."},{"v":8,"t":"Others fell on good soil and yielded fruit: some one hundred times as much, some sixty, and some thirty."},{"v":9,"t":"He who has ears to hear, let him hear.”"},{"v":10,"t":"The disciples came, and said to him, “Why do you speak to them in parables?”"},{"v":11,"t":"He answered them, “To you it is given to know the mysteries of the Kingdom of Heaven, but it is not given to them."},{"v":12,"t":"For whoever has, to him will be given, and he will have abundance; but whoever doesn’t have, from him will be taken away even that which he has."},{"v":13,"t":"Therefore I speak to them in parables, because seeing they don’t see, and hearing, they don’t hear, neither do they understand."},{"v":14,"t":"In them the prophecy of Isaiah is fulfilled, which says, ‘By hearing you will hear, and will in no way understand; Seeing you will see, and will in no way perceive;"},{"v":15,"t":"for this people’s heart has grown callous, their ears are dull of hearing, and they have closed their eyes; or else perhaps they might perceive with their eyes, hear with their ears, understand with their heart, and would turn again, and I would heal them.’"},{"v":16,"t":"“But blessed are your eyes, for they see; and your ears, for they hear."},{"v":17,"t":"For most certainly I tell you that many prophets and righteous men desired to see the things which you see, and didn’t see them; and to hear the things which you hear, and didn’t hear them."},{"v":18,"t":"“Hear, then, the parable of the farmer."},{"v":19,"t":"When anyone hears the word of the Kingdom and doesn’t understand it, the evil one comes and snatches away that which has been sown in his heart. This is what was sown by the roadside."},{"v":20,"t":"What was sown on the rocky places, this is he who hears the word and immediately with joy receives it;"},{"v":21,"t":"yet he has no root in himself, but endures for a while. When oppression or persecution arises because of the word, immediately he stumbles."},{"v":22,"t":"What was sown among the thorns, this is he who hears the word, but the cares of this age and the deceitfulness of riches choke the word, and he becomes unfruitful."},{"v":23,"t":"What was sown on the good ground, this is he who hears the word and understands it, who most certainly bears fruit and produces, some one hundred times as much, some sixty, and some thirty.”"},{"v":24,"t":"He set another parable before them, saying, “The Kingdom of Heaven is like a man who sowed good seed in his field,"},{"v":25,"t":"but while people slept, his enemy came and sowed darnel weeds also among the wheat, and went away."},{"v":26,"t":"But when the blade sprang up and produced grain, then the darnel weeds appeared also."},{"v":27,"t":"The servants of the householder came and said to him, ‘Sir, didn’t you sow good seed in your field? Where did these darnel weeds come from?’"},{"v":28,"t":"“He said to them, ‘An enemy has done this.’ “The servants asked him, ‘Do you want us to go and gather them up?’"},{"v":29,"t":"“But he said, ‘No, lest perhaps while you gather up the darnel weeds, you root up the wheat with them."},{"v":30,"t":"Let both grow together until the harvest, and in the harvest time I will tell the reapers, “First, gather up the darnel weeds, and bind them in bundles to burn them; but gather the wheat into my barn.”’”"},{"v":31,"t":"He set another parable before them, saying, “The Kingdom of Heaven is like a grain of mustard seed which a man took, and sowed in his field,"},{"v":32,"t":"which indeed is smaller than all seeds. But when it is grown, it is greater than the herbs and becomes a tree, so that the birds of the air come and lodge in its branches.”"},{"v":33,"t":"He spoke another parable to them. “The Kingdom of Heaven is like yeast which a woman took and hid in three measures of meal, until it was all leavened.”"},{"v":34,"t":"Jesus spoke all these things in parables to the multitudes; and without a parable, he didn’t speak to them,"},{"v":35,"t":"that it might be fulfilled which was spoken through the prophet, saying, “I will open my mouth in parables; I will utter things hidden from the foundation of the world.”"},{"v":36,"t":"Then Jesus sent the multitudes away, and went into the house. His disciples came to him, saying, “Explain to us the parable of the darnel weeds of the field.”"},{"v":37,"t":"He answered them, “He who sows the good seed is the Son of Man,"},{"v":38,"t":"the field is the world, the good seeds are the children of the Kingdom, and the darnel weeds are the children of the evil one."},{"v":39,"t":"The enemy who sowed them is the devil. The harvest is the end of the age, and the reapers are angels."},{"v":40,"t":"As therefore the darnel weeds are gathered up and burned with fire; so will it be at the end of this age."},{"v":41,"t":"The Son of Man will send out his angels, and they will gather out of his Kingdom all things that cause stumbling and those who do iniquity,"},{"v":42,"t":"and will cast them into the furnace of fire. There will be weeping and gnashing of teeth."},{"v":43,"t":"Then the righteous will shine like the sun in the Kingdom of their Father. He who has ears to hear, let him hear."},{"v":44,"t":"“Again, the Kingdom of Heaven is like treasure hidden in the field, which a man found and hid. In his joy, he goes and sells all that he has and buys that field."},{"v":45,"t":"“Again, the Kingdom of Heaven is like a man who is a merchant seeking fine pearls,"},{"v":46,"t":"who having found one pearl of great price, he went and sold all that he had and bought it."},{"v":47,"t":"“Again, the Kingdom of Heaven is like a dragnet that was cast into the sea and gathered some fish of every kind,"},{"v":48,"t":"which, when it was filled, fishermen drew up on the beach. They sat down and gathered the good into containers, but the bad they threw away."},{"v":49,"t":"So it will be in the end of the world. The angels will come and separate the wicked from among the righteous,"},{"v":50,"t":"and will cast them into the furnace of fire. There will be weeping and gnashing of teeth.”"},{"v":51,"t":"Jesus said to them, “Have you understood all these things?” They answered him, “Yes, Lord.”"},{"v":52,"t":"He said to them, “Therefore every scribe who has been made a disciple in the Kingdom of Heaven is like a man who is a householder, who brings out of his treasure new and old things.”"},{"v":53,"t":"When Jesus had finished these parables, he departed from there."},{"v":54,"t":"Coming into his own country, he taught them in their synagogue, so that they were astonished and said, “Where did this man get this wisdom and these mighty works?"},{"v":55,"t":"Isn’t this the carpenter’s son? Isn’t his mother called Mary, and his brothers James, Joses, Simon, and Judas?"},{"v":56,"t":"Aren’t all of his sisters with us? Where then did this man get all of these things?”"},{"v":57,"t":"They were offended by him. But Jesus said to them, “A prophet is not without honor, except in his own country and in his own house.”"},{"v":58,"t":"He didn’t do many mighty works there because of their unbelief."}]},"14":{"en":[{"v":1,"t":"At that time, Herod the tetrarch heard the report concerning Jesus,"},{"v":2,"t":"and said to his servants, “This is John the Baptizer. He is risen from the dead. That is why these powers work in him.”"},{"v":3,"t":"For Herod had arrested John, bound him, and put him in prison for the sake of Herodias, his brother Philip’s wife."},{"v":4,"t":"For John said to him, “It is not lawful for you to have her.”"},{"v":5,"t":"When he would have put him to death, he feared the multitude, because they counted him as a prophet."},{"v":6,"t":"But when Herod’s birthday came, the daughter of Herodias danced among them and pleased Herod."},{"v":7,"t":"Therefore he promised with an oath to give her whatever she should ask."},{"v":8,"t":"She, being prompted by her mother, said, “Give me here on a platter the head of John the Baptizer.”"},{"v":9,"t":"The king was grieved, but for the sake of his oaths and of those who sat at the table with him, he commanded it to be given,"},{"v":10,"t":"and he sent and beheaded John in the prison."},{"v":11,"t":"His head was brought on a platter and given to the young lady; and she brought it to her mother."},{"v":12,"t":"His disciples came, took the body, and buried it. Then they went and told Jesus."},{"v":13,"t":"Now when Jesus heard this, he withdrew from there in a boat to a deserted place apart. When the multitudes heard it, they followed him on foot from the cities."},{"v":14,"t":"Jesus went out, and he saw a great multitude. He had compassion on them and healed their sick."},{"v":15,"t":"When evening had come, his disciples came to him, saying, “This place is deserted, and the hour is already late. Send the multitudes away, that they may go into the villages, and buy themselves food.”"},{"v":16,"t":"But Jesus said to them, “They don’t need to go away. You give them something to eat.”"},{"v":17,"t":"They told him, “We only have here five loaves and two fish.”"},{"v":18,"t":"He said, “Bring them here to me.”"},{"v":19,"t":"He commanded the multitudes to sit down on the grass; and he took the five loaves and the two fish, and looking up to heaven, he blessed, broke and gave the loaves to the disciples; and the disciples gave to the multitudes."},{"v":20,"t":"They all ate and were filled. They took up twelve baskets full of that which remained left over from the broken pieces."},{"v":21,"t":"Those who ate were about five thousand men, in addition to women and children."},{"v":22,"t":"Immediately Jesus made the disciples get into the boat and go ahead of him to the other side, while he sent the multitudes away."},{"v":23,"t":"After he had sent the multitudes away, he went up into the mountain by himself to pray. When evening had come, he was there alone."},{"v":24,"t":"But the boat was now in the middle of the sea, distressed by the waves, for the wind was contrary."},{"v":25,"t":"In the fourth watch of the night, Jesus came to them, walking on the sea."},{"v":26,"t":"When the disciples saw him walking on the sea, they were troubled, saying, “It’s a ghost!” and they cried out for fear."},{"v":27,"t":"But immediately Jesus spoke to them, saying, “Cheer up! It is I! Don’t be afraid.”"},{"v":28,"t":"Peter answered him and said, “Lord, if it is you, command me to come to you on the waters.”"},{"v":29,"t":"He said, “Come!” Peter stepped down from the boat and walked on the waters to come to Jesus."},{"v":30,"t":"But when he saw that the wind was strong, he was afraid, and beginning to sink, he cried out, saying, “Lord, save me!”"},{"v":31,"t":"Immediately Jesus stretched out his hand, took hold of him, and said to him, “You of little faith, why did you doubt?”"},{"v":32,"t":"When they got up into the boat, the wind ceased."},{"v":33,"t":"Those who were in the boat came and worshiped him, saying, “You are truly the Son of God!”"},{"v":34,"t":"When they had crossed over, they came to the land of Gennesaret."},{"v":35,"t":"When the people of that place recognized him, they sent into all that surrounding region and brought to him all who were sick;"},{"v":36,"t":"and they begged him that they might just touch the fringe of his garment. As many as touched it were made whole."}]},"15":{"en":[{"v":1,"t":"Then Pharisees and scribes came to Jesus from Jerusalem, saying,"},{"v":2,"t":"“Why do your disciples disobey the tradition of the elders? For they don’t wash their hands when they eat bread.”"},{"v":3,"t":"He answered them, “Why do you also disobey the commandment of God because of your tradition?"},{"v":4,"t":"For God commanded, ‘Honor your father and your mother,’ and, ‘He who speaks evil of father or mother, let him be put to death.’"},{"v":5,"t":"But you say, ‘Whoever may tell his father or his mother, “Whatever help you might otherwise have gotten from me is a gift devoted to God,”"},{"v":6,"t":"he shall not honor his father or mother.’ You have made the commandment of God void because of your tradition."},{"v":7,"t":"You hypocrites! Well did Isaiah prophesy of you, saying,"},{"v":8,"t":"‘These people draw near to me with their mouth, and honor me with their lips; but their heart is far from me."},{"v":9,"t":"And they worship me in vain, teaching as doctrine rules made by men.’”"},{"v":10,"t":"He summoned the multitude, and said to them, “Hear, and understand."},{"v":11,"t":"That which enters into the mouth doesn’t defile the man; but that which proceeds out of the mouth, this defiles the man.”"},{"v":12,"t":"Then the disciples came and said to him, “Do you know that the Pharisees were offended when they heard this saying?”"},{"v":13,"t":"But he answered, “Every plant which my heavenly Father didn’t plant will be uprooted."},{"v":14,"t":"Leave them alone. They are blind guides of the blind. If the blind guide the blind, both will fall into a pit.”"},{"v":15,"t":"Peter answered him, “Explain the parable to us.”"},{"v":16,"t":"So Jesus said, “Do you also still not understand?"},{"v":17,"t":"Don’t you understand that whatever goes into the mouth passes into the belly and then out of the body?"},{"v":18,"t":"But the things which proceed out of the mouth come out of the heart, and they defile the man."},{"v":19,"t":"For out of the heart come evil thoughts, murders, adulteries, sexual sins, thefts, false testimony, and blasphemies."},{"v":20,"t":"These are the things which defile the man; but to eat with unwashed hands doesn’t defile the man.”"},{"v":21,"t":"Jesus went out from there and withdrew into the region of Tyre and Sidon."},{"v":22,"t":"Behold, a Canaanite woman came out from those borders and cried, saying, “Have mercy on me, Lord, you son of David! My daughter is severely possessed by a demon!”"},{"v":23,"t":"But he answered her not a word. His disciples came and begged him, saying, “Send her away; for she cries after us.”"},{"v":24,"t":"But he answered, “I wasn’t sent to anyone but the lost sheep of the house of Israel.”"},{"v":25,"t":"But she came and worshiped him, saying, “Lord, help me.”"},{"v":26,"t":"But he answered, “It is not appropriate to take the children’s bread and throw it to the dogs.”"},{"v":27,"t":"But she said, “Yes, Lord, but even the dogs eat the crumbs which fall from their masters’ table.”"},{"v":28,"t":"Then Jesus answered her, “Woman, great is your faith! Be it done to you even as you desire.” And her daughter was healed from that hour."},{"v":29,"t":"Jesus departed from there and came near to the sea of Galilee; and he went up on the mountain and sat there."},{"v":30,"t":"Great multitudes came to him, having with them the lame, blind, mute, maimed, and many others, and they put them down at his feet. He healed them,"},{"v":31,"t":"so that the multitude wondered when they saw the mute speaking, the injured healed, the lame walking, and the blind seeing—and they glorified the God of Israel."},{"v":32,"t":"Jesus summoned his disciples and said, “I have compassion on the multitude, because they have continued with me now three days and have nothing to eat. I don’t want to send them away fasting, or they might faint on the way.”"},{"v":33,"t":"The disciples said to him, “Where could we get so many loaves in a deserted place as to satisfy so great a multitude?”"},{"v":34,"t":"Jesus said to them, “How many loaves do you have?” They said, “Seven, and a few small fish.”"},{"v":35,"t":"He commanded the multitude to sit down on the ground;"},{"v":36,"t":"and he took the seven loaves and the fish. He gave thanks and broke them, and gave to the disciples, and the disciples to the multitudes."},{"v":37,"t":"They all ate and were filled. They took up seven baskets full of the broken pieces that were left over."},{"v":38,"t":"Those who ate were four thousand men, in addition to women and children."},{"v":39,"t":"Then he sent away the multitudes, got into the boat, and came into the borders of Magdala."}]},"16":{"en":[{"v":1,"t":"The Pharisees and Sadducees came, and testing him, asked him to show them a sign from heaven."},{"v":2,"t":"But he answered them, “When it is evening, you say, ‘It will be fair weather, for the sky is red.’"},{"v":3,"t":"In the morning, ‘It will be foul weather today, for the sky is red and threatening.’ Hypocrites! You know how to discern the appearance of the sky, but you can’t discern the signs of the times!"},{"v":4,"t":"An evil and adulterous generation seeks after a sign, and there will be no sign given to it, except the sign of the prophet Jonah.” He left them and departed."},{"v":5,"t":"The disciples came to the other side and had forgotten to take bread."},{"v":6,"t":"Jesus said to them, “Take heed and beware of the yeast of the Pharisees and Sadducees.”"},{"v":7,"t":"They reasoned among themselves, saying, “We brought no bread.”"},{"v":8,"t":"Jesus, perceiving it, said, “Why do you reason among yourselves, you of little faith, because you have brought no bread?"},{"v":9,"t":"Don’t you yet perceive or remember the five loaves for the five thousand, and how many baskets you took up,"},{"v":10,"t":"or the seven loaves for the four thousand, and how many baskets you took up?"},{"v":11,"t":"How is it that you don’t perceive that I didn’t speak to you concerning bread? But beware of the yeast of the Pharisees and Sadducees.”"},{"v":12,"t":"Then they understood that he didn’t tell them to beware of the yeast of bread, but of the teaching of the Pharisees and Sadducees."},{"v":13,"t":"Now when Jesus came into the parts of Caesarea Philippi, he asked his disciples, saying, “Who do men say that I, the Son of Man, am?”"},{"v":14,"t":"They said, “Some say John the Baptizer, some, Elijah, and others, Jeremiah or one of the prophets.”"},{"v":15,"t":"He said to them, “But who do you say that I am?”"},{"v":16,"t":"Simon Peter answered, “You are the Christ, the Son of the living God.”"},{"v":17,"t":"Jesus answered him, “Blessed are you, Simon Bar Jonah, for flesh and blood has not revealed this to you, but my Father who is in heaven."},{"v":18,"t":"I also tell you that you are Peter, and on this rock I will build my assembly, and the gates of Hades will not prevail against it."},{"v":19,"t":"I will give to you the keys of the Kingdom of Heaven, and whatever you bind on earth will have been bound in heaven; and whatever you release on earth will have been released in heaven.”"},{"v":20,"t":"Then he commanded the disciples that they should tell no one that he was Jesus the Christ."},{"v":21,"t":"From that time, Jesus began to show his disciples that he must go to Jerusalem and suffer many things from the elders, chief priests, and scribes, and be killed, and the third day be raised up."},{"v":22,"t":"Peter took him aside and began to rebuke him, saying, “Far be it from you, Lord! This will never be done to you.”"},{"v":23,"t":"But he turned and said to Peter, “Get behind me, Satan! You are a stumbling block to me, for you are not setting your mind on the things of God, but on the things of men.”"},{"v":24,"t":"Then Jesus said to his disciples, “If anyone desires to come after me, let him deny himself, take up his cross, and follow me."},{"v":25,"t":"For whoever desires to save his life will lose it, and whoever will lose his life for my sake will find it."},{"v":26,"t":"For what will it profit a man if he gains the whole world and forfeits his life? Or what will a man give in exchange for his life?"},{"v":27,"t":"For the Son of Man will come in the glory of his Father with his angels, and then he will render to everyone according to his deeds."},{"v":28,"t":"Most certainly I tell you, there are some standing here who will in no way taste of death until they see the Son of Man coming in his Kingdom.”"}]},"17":{"en":[{"v":1,"t":"After six days, Jesus took with him Peter, James, and John his brother, and brought them up into a high mountain by themselves."},{"v":2,"t":"He was changed before them. His face shone like the sun, and his garments became as white as the light."},{"v":3,"t":"Behold, Moses and Elijah appeared to them talking with him."},{"v":4,"t":"Peter answered and said to Jesus, “Lord, it is good for us to be here. If you want, let’s make three tents here: one for you, one for Moses, and one for Elijah.”"},{"v":5,"t":"While he was still speaking, behold, a bright cloud overshadowed them. Behold, a voice came out of the cloud, saying, “This is my beloved Son, in whom I am well pleased. Listen to him.”"},{"v":6,"t":"When the disciples heard it, they fell on their faces, and were very afraid."},{"v":7,"t":"Jesus came and touched them and said, “Get up, and don’t be afraid.”"},{"v":8,"t":"Lifting up their eyes, they saw no one, except Jesus alone."},{"v":9,"t":"As they were coming down from the mountain, Jesus commanded them, saying, “Don’t tell anyone what you saw, until the Son of Man has risen from the dead.”"},{"v":10,"t":"His disciples asked him, saying, “Then why do the scribes say that Elijah must come first?”"},{"v":11,"t":"Jesus answered them, “Elijah indeed comes first, and will restore all things;"},{"v":12,"t":"but I tell you that Elijah has come already, and they didn’t recognize him, but did to him whatever they wanted to. Even so the Son of Man will also suffer by them.”"},{"v":13,"t":"Then the disciples understood that he spoke to them of John the Baptizer."},{"v":14,"t":"When they came to the multitude, a man came to him, kneeling down to him and saying,"},{"v":15,"t":"“Lord, have mercy on my son, for he is epileptic and suffers grievously; for he often falls into the fire, and often into the water."},{"v":16,"t":"So I brought him to your disciples, and they could not cure him.”"},{"v":17,"t":"Jesus answered, “Faithless and perverse generation! How long will I be with you? How long will I bear with you? Bring him here to me.”"},{"v":18,"t":"Jesus rebuked the demon, and it went out of him, and the boy was cured from that hour."},{"v":19,"t":"Then the disciples came to Jesus privately, and said, “Why weren’t we able to cast it out?”"},{"v":20,"t":"He said to them, “Because of your unbelief. For most certainly I tell you, if you have faith as a grain of mustard seed, you will tell this mountain, ‘Move from here to there,’ and it will move; and nothing will be impossible for you."},{"v":21,"t":"But this kind doesn’t go out except by prayer and fasting.”"},{"v":22,"t":"While they were staying in Galilee, Jesus said to them, “The Son of Man is about to be delivered up into the hands of men,"},{"v":23,"t":"and they will kill him, and the third day he will be raised up.” They were exceedingly sorry."},{"v":24,"t":"When they had come to Capernaum, those who collected the didrachma coins came to Peter, and said, “Doesn’t your teacher pay the didrachma?”"},{"v":25,"t":"He said, “Yes.” When he came into the house, Jesus anticipated him, saying, “What do you think, Simon? From whom do the kings of the earth receive toll or tribute? From their children, or from strangers?”"},{"v":26,"t":"Peter said to him, “From strangers.” Jesus said to him, “Therefore the children are exempt."},{"v":27,"t":"But, lest we cause them to stumble, go to the sea, cast a hook, and take up the first fish that comes up. When you have opened its mouth, you will find a stater coin. Take that, and give it to them for me and you.”"}]},"18":{"en":[{"v":1,"t":"In that hour the disciples came to Jesus, saying, “Who then is greatest in the Kingdom of Heaven?”"},{"v":2,"t":"Jesus called a little child to himself, and set him in the middle of them"},{"v":3,"t":"and said, “Most certainly I tell you, unless you turn and become as little children, you will in no way enter into the Kingdom of Heaven."},{"v":4,"t":"Whoever therefore humbles himself as this little child is the greatest in the Kingdom of Heaven."},{"v":5,"t":"Whoever receives one such little child in my name receives me,"},{"v":6,"t":"but whoever causes one of these little ones who believe in me to stumble, it would be better for him if a huge millstone were hung around his neck and that he were sunk in the depths of the sea."},{"v":7,"t":"“Woe to the world because of occasions of stumbling! For it must be that the occasions come, but woe to that person through whom the occasion comes!"},{"v":8,"t":"If your hand or your foot causes you to stumble, cut it off and cast it from you. It is better for you to enter into life maimed or crippled, rather than having two hands or two feet to be cast into the eternal fire."},{"v":9,"t":"If your eye causes you to stumble, pluck it out and cast it from you. It is better for you to enter into life with one eye, rather than having two eyes to be cast into the Gehenna of fire."},{"v":10,"t":"See that you don’t despise one of these little ones, for I tell you that in heaven their angels always see the face of my Father who is in heaven."},{"v":11,"t":"For the Son of Man came to save that which was lost."},{"v":12,"t":"“What do you think? If a man has one hundred sheep, and one of them goes astray, doesn’t he leave the ninety-nine, go to the mountains, and seek that which has gone astray?"},{"v":13,"t":"If he finds it, most certainly I tell you, he rejoices over it more than over the ninety-nine which have not gone astray."},{"v":14,"t":"Even so it is not the will of your Father who is in heaven that one of these little ones should perish."},{"v":15,"t":"“If your brother sins against you, go, show him his fault between you and him alone. If he listens to you, you have gained back your brother."},{"v":16,"t":"But if he doesn’t listen, take one or two more with you, that at the mouth of two or three witnesses every word may be established."},{"v":17,"t":"If he refuses to listen to them, tell it to the assembly. If he refuses to hear the assembly also, let him be to you as a Gentile or a tax collector."},{"v":18,"t":"Most certainly I tell you, whatever things you bind on earth will have been bound in heaven, and whatever things you release on earth will have been released in heaven."},{"v":19,"t":"Again, assuredly I tell you, that if two of you will agree on earth concerning anything that they will ask, it will be done for them by my Father who is in heaven."},{"v":20,"t":"For where two or three are gathered together in my name, there I am in the middle of them.”"},{"v":21,"t":"Then Peter came and said to him, “Lord, how often shall my brother sin against me, and I forgive him? Until seven times?”"},{"v":22,"t":"Jesus said to him, “I don’t tell you until seven times, but, until seventy times seven."},{"v":23,"t":"Therefore the Kingdom of Heaven is like a certain king who wanted to settle accounts with his servants."},{"v":24,"t":"When he had begun to settle, one was brought to him who owed him ten thousand talents."},{"v":25,"t":"But because he couldn’t pay, his lord commanded him to be sold, with his wife, his children, and all that he had, and payment to be made."},{"v":26,"t":"The servant therefore fell down and knelt before him, saying, ‘Lord, have patience with me, and I will repay you all!’"},{"v":27,"t":"The lord of that servant, being moved with compassion, released him and forgave him the debt."},{"v":28,"t":"“But that servant went out and found one of his fellow servants who owed him one hundred denarii, and he grabbed him and took him by the throat, saying, ‘Pay me what you owe!’"},{"v":29,"t":"“So his fellow servant fell down at his feet and begged him, saying, ‘Have patience with me, and I will repay you!’"},{"v":30,"t":"He would not, but went and cast him into prison until he should pay back that which was due."},{"v":31,"t":"So when his fellow servants saw what was done, they were exceedingly sorry, and came and told their lord all that was done."},{"v":32,"t":"Then his lord called him in and said to him, ‘You wicked servant! I forgave you all that debt because you begged me."},{"v":33,"t":"Shouldn’t you also have had mercy on your fellow servant, even as I had mercy on you?’"},{"v":34,"t":"His lord was angry, and delivered him to the tormentors until he should pay all that was due to him."},{"v":35,"t":"So my heavenly Father will also do to you, if you don’t each forgive your brother from your hearts for his misdeeds.”"}]},"19":{"en":[{"v":1,"t":"When Jesus had finished these words, he departed from Galilee and came into the borders of Judea beyond the Jordan."},{"v":2,"t":"Great multitudes followed him, and he healed them there."},{"v":3,"t":"Pharisees came to him, testing him and saying, “Is it lawful for a man to divorce his wife for any reason?”"},{"v":4,"t":"He answered, “Haven’t you read that he who made them from the beginning made them male and female,"},{"v":5,"t":"and said, ‘For this cause a man shall leave his father and mother, and shall be joined to his wife; and the two shall become one flesh’?"},{"v":6,"t":"So that they are no more two, but one flesh. What therefore God has joined together, don’t let man tear apart.”"},{"v":7,"t":"They asked him, “Why then did Moses command us to give her a certificate of divorce and divorce her?”"},{"v":8,"t":"He said to them, “Moses, because of the hardness of your hearts, allowed you to divorce your wives, but from the beginning it has not been so."},{"v":9,"t":"I tell you that whoever divorces his wife, except for sexual immorality, and marries another, commits adultery; and he who marries her when she is divorced commits adultery.”"},{"v":10,"t":"His disciples said to him, “If this is the case of the man with his wife, it is not expedient to marry.”"},{"v":11,"t":"But he said to them, “Not all men can receive this saying, but those to whom it is given."},{"v":12,"t":"For there are eunuchs who were born that way from their mother’s womb, and there are eunuchs who were made eunuchs by men; and there are eunuchs who made themselves eunuchs for the Kingdom of Heaven’s sake. He who is able to receive it, let him receive it.”"},{"v":13,"t":"Then little children were brought to him that he should lay his hands on them and pray; and the disciples rebuked them."},{"v":14,"t":"But Jesus said, “Allow the little children, and don’t forbid them to come to me; for the Kingdom of Heaven belongs to ones like these.”"},{"v":15,"t":"He laid his hands on them, and departed from there."},{"v":16,"t":"Behold, one came to him and said, “Good teacher, what good thing shall I do, that I may have eternal life?”"},{"v":17,"t":"He said to him, “Why do you call me good? No one is good but one, that is, God. But if you want to enter into life, keep the commandments.”"},{"v":18,"t":"He said to him, “Which ones?” Jesus said, “‘You shall not murder.’ ‘You shall not commit adultery.’ ‘You shall not steal.’ ‘You shall not offer false testimony.’"},{"v":19,"t":"‘Honor your father and your mother.’ And, ‘You shall love your neighbor as yourself.’”"},{"v":20,"t":"The young man said to him, “All these things I have observed from my youth. What do I still lack?”"},{"v":21,"t":"Jesus said to him, “If you want to be perfect, go, sell what you have, and give to the poor, and you will have treasure in heaven; and come, follow me.”"},{"v":22,"t":"But when the young man heard this, he went away sad, for he was one who had great possessions."},{"v":23,"t":"Jesus said to his disciples, “Most certainly I say to you, a rich man will enter into the Kingdom of Heaven with difficulty."},{"v":24,"t":"Again I tell you, it is easier for a camel to go through a needle’s eye than for a rich man to enter into God’s Kingdom.”"},{"v":25,"t":"When the disciples heard it, they were exceedingly astonished, saying, “Who then can be saved?”"},{"v":26,"t":"Looking at them, Jesus said, “With men this is impossible, but with God all things are possible.”"},{"v":27,"t":"Then Peter answered, “Behold, we have left everything and followed you. What then will we have?”"},{"v":28,"t":"Jesus said to them, “Most certainly I tell you that you who have followed me, in the regeneration when the Son of Man will sit on the throne of his glory, you also will sit on twelve thrones, judging the twelve tribes of Israel."},{"v":29,"t":"Everyone who has left houses, or brothers, or sisters, or father, or mother, or wife, or children, or lands, for my name’s sake, will receive one hundred times, and will inherit eternal life."},{"v":30,"t":"But many will be last who are first, and first who are last."}]},"20":{"en":[{"v":1,"t":"“For the Kingdom of Heaven is like a man who was the master of a household, who went out early in the morning to hire laborers for his vineyard."},{"v":2,"t":"When he had agreed with the laborers for a denarius a day, he sent them into his vineyard."},{"v":3,"t":"He went out about the third hour, and saw others standing idle in the marketplace."},{"v":4,"t":"He said to them, ‘You also go into the vineyard, and whatever is right I will give you.’ So they went their way."},{"v":5,"t":"Again he went out about the sixth and the ninth hour, and did likewise."},{"v":6,"t":"About the eleventh hour he went out and found others standing idle. He said to them, ‘Why do you stand here all day idle?’"},{"v":7,"t":"“They said to him, ‘Because no one has hired us.’ “He said to them, ‘You also go into the vineyard, and you will receive whatever is right.’"},{"v":8,"t":"“When evening had come, the lord of the vineyard said to his manager, ‘Call the laborers and pay them their wages, beginning from the last to the first.’"},{"v":9,"t":"“When those who were hired at about the eleventh hour came, they each received a denarius."},{"v":10,"t":"When the first came, they supposed that they would receive more; and they likewise each received a denarius."},{"v":11,"t":"When they received it, they murmured against the master of the household,"},{"v":12,"t":"saying, ‘These last have spent one hour, and you have made them equal to us who have borne the burden of the day and the scorching heat!’"},{"v":13,"t":"“But he answered one of them, ‘Friend, I am doing you no wrong. Didn’t you agree with me for a denarius?"},{"v":14,"t":"Take that which is yours, and go your way. It is my desire to give to this last just as much as to you."},{"v":15,"t":"Isn’t it lawful for me to do what I want to with what I own? Or is your eye evil, because I am good?’"},{"v":16,"t":"So the last will be first, and the first last. For many are called, but few are chosen.”"},{"v":17,"t":"As Jesus was going up to Jerusalem, he took the twelve disciples aside, and on the way he said to them,"},{"v":18,"t":"“Behold, we are going up to Jerusalem, and the Son of Man will be delivered to the chief priests and scribes, and they will condemn him to death,"},{"v":19,"t":"and will hand him over to the Gentiles to mock, to scourge, and to crucify; and the third day he will be raised up.”"},{"v":20,"t":"Then the mother of the sons of Zebedee came to him with her sons, kneeling and asking a certain thing of him."},{"v":21,"t":"He said to her, “What do you want?” She said to him, “Command that these, my two sons, may sit, one on your right hand and one on your left hand, in your Kingdom.”"},{"v":22,"t":"But Jesus answered, “You don’t know what you are asking. Are you able to drink the cup that I am about to drink, and be baptized with the baptism that I am baptized with?” They said to him, “We are able.”"},{"v":23,"t":"He said to them, “You will indeed drink my cup, and be baptized with the baptism that I am baptized with; but to sit on my right hand and on my left hand is not mine to give, but it is for whom it has been prepared by my Father.”"},{"v":24,"t":"When the ten heard it, they were indignant with the two brothers."},{"v":25,"t":"But Jesus summoned them, and said, “You know that the rulers of the nations lord it over them, and their great ones exercise authority over them."},{"v":26,"t":"It shall not be so among you; but whoever desires to become great among you shall be your servant."},{"v":27,"t":"Whoever desires to be first among you shall be your bondservant,"},{"v":28,"t":"even as the Son of Man came not to be served, but to serve, and to give his life as a ransom for many.”"},{"v":29,"t":"As they went out from Jericho, a great multitude followed him."},{"v":30,"t":"Behold, two blind men sitting by the road, when they heard that Jesus was passing by, cried out, “Lord, have mercy on us, you son of David!”"},{"v":31,"t":"The multitude rebuked them, telling them that they should be quiet, but they cried out even more, “Lord, have mercy on us, you son of David!”"},{"v":32,"t":"Jesus stood still and called them, and asked, “What do you want me to do for you?”"},{"v":33,"t":"They told him, “Lord, that our eyes may be opened.”"},{"v":34,"t":"Jesus, being moved with compassion, touched their eyes; and immediately their eyes received their sight, and they followed him."}]},"21":{"en":[{"v":1,"t":"When they came near to Jerusalem and came to Bethsphage, to the Mount of Olives, then Jesus sent two disciples,"},{"v":2,"t":"saying to them, “Go into the village that is opposite you, and immediately you will find a donkey tied, and a colt with her. Untie them and bring them to me."},{"v":3,"t":"If anyone says anything to you, you shall say, ‘The Lord needs them,’ and immediately he will send them.”"},{"v":4,"t":"All this was done that it might be fulfilled which was spoken through the prophet, saying,"},{"v":5,"t":"“Tell the daughter of Zion, behold, your King comes to you, humble, and riding on a donkey, on a colt, the foal of a donkey.”"},{"v":6,"t":"The disciples went and did just as Jesus commanded them,"},{"v":7,"t":"and brought the donkey and the colt and laid their clothes on them; and he sat on them."},{"v":8,"t":"A very great multitude spread their clothes on the road. Others cut branches from the trees and spread them on the road."},{"v":9,"t":"The multitudes who went in front of him, and those who followed, kept shouting, “Hosanna to the son of David! Blessed is he who comes in the name of the Lord! Hosanna in the highest!”"},{"v":10,"t":"When he had come into Jerusalem, all the city was stirred up, saying, “Who is this?”"},{"v":11,"t":"The multitudes said, “This is the prophet, Jesus, from Nazareth of Galilee.”"},{"v":12,"t":"Jesus entered into the temple of God and drove out all of those who sold and bought in the temple, and overthrew the money changers’ tables and the seats of those who sold the doves."},{"v":13,"t":"He said to them, “It is written, ‘My house shall be called a house of prayer,’ but you have made it a den of robbers!”"},{"v":14,"t":"The lame and the blind came to him in the temple, and he healed them."},{"v":15,"t":"But when the chief priests and the scribes saw the wonderful things that he did, and the children who were crying in the temple and saying, “Hosanna to the son of David!” they were indignant,"},{"v":16,"t":"and said to him, “Do you hear what these are saying?” Jesus said to them, “Yes. Did you never read, ‘Out of the mouth of children and nursing babies, you have perfected praise’?”"},{"v":17,"t":"He left them and went out of the city to Bethany, and camped there."},{"v":18,"t":"Now in the morning, as he returned to the city, he was hungry."},{"v":19,"t":"Seeing a fig tree by the road, he came to it and found nothing on it but leaves. He said to it, “Let there be no fruit from you forever!” Immediately the fig tree withered away."},{"v":20,"t":"When the disciples saw it, they marveled, saying, “How did the fig tree immediately wither away?”"},{"v":21,"t":"Jesus answered them, “Most certainly I tell you, if you have faith and don’t doubt, you will not only do what was done to the fig tree, but even if you told this mountain, ‘Be taken up and cast into the sea,’ it would be done."},{"v":22,"t":"All things, whatever you ask in prayer, believing, you will receive.”"},{"v":23,"t":"When he had come into the temple, the chief priests and the elders of the people came to him as he was teaching, and said, “By what authority do you do these things? Who gave you this authority?”"},{"v":24,"t":"Jesus answered them, “I also will ask you one question, which if you tell me, I likewise will tell you by what authority I do these things."},{"v":25,"t":"The baptism of John, where was it from? From heaven or from men?” They reasoned with themselves, saying, “If we say, ‘From heaven,’ he will ask us, ‘Why then did you not believe him?’"},{"v":26,"t":"But if we say, ‘From men,’ we fear the multitude, for all hold John as a prophet.”"},{"v":27,"t":"They answered Jesus, and said, “We don’t know.” He also said to them, “Neither will I tell you by what authority I do these things."},{"v":28,"t":"But what do you think? A man had two sons, and he came to the first, and said, ‘Son, go work today in my vineyard.’"},{"v":29,"t":"He answered, ‘I will not,’ but afterward he changed his mind, and went."},{"v":30,"t":"He came to the second, and said the same thing. He answered, ‘I’m going, sir,’ but he didn’t go."},{"v":31,"t":"Which of the two did the will of his father?” They said to him, “The first.” Jesus said to them, “Most certainly I tell you that the tax collectors and the prostitutes are entering into God’s Kingdom before you."},{"v":32,"t":"For John came to you in the way of righteousness, and you didn’t believe him; but the tax collectors and the prostitutes believed him. When you saw it, you didn’t even repent afterward, that you might believe him."},{"v":33,"t":"“Hear another parable. There was a man who was a master of a household who planted a vineyard, set a hedge about it, dug a wine press in it, built a tower, leased it out to farmers, and went into another country."},{"v":34,"t":"When the season for the fruit came near, he sent his servants to the farmers to receive his fruit."},{"v":35,"t":"The farmers took his servants, beat one, killed another, and stoned another."},{"v":36,"t":"Again, he sent other servants more than the first; and they treated them the same way."},{"v":37,"t":"But afterward he sent to them his son, saying, ‘They will respect my son.’"},{"v":38,"t":"But the farmers, when they saw the son, said among themselves, ‘This is the heir. Come, let’s kill him and seize his inheritance.’"},{"v":39,"t":"So they took him and threw him out of the vineyard, then killed him."},{"v":40,"t":"When therefore the lord of the vineyard comes, what will he do to those farmers?”"},{"v":41,"t":"They told him, “He will miserably destroy those miserable men, and will lease out the vineyard to other farmers who will give him the fruit in its season.”"},{"v":42,"t":"Jesus said to them, “Did you never read in the Scriptures, ‘The stone which the builders rejected was made the head of the corner. This was from the Lord. It is marvelous in our eyes’?"},{"v":43,"t":"“Therefore I tell you, God’s Kingdom will be taken away from you and will be given to a nation producing its fruit."},{"v":44,"t":"He who falls on this stone will be broken to pieces, but on whomever it will fall, it will scatter him as dust.”"},{"v":45,"t":"When the chief priests and the Pharisees heard his parables, they perceived that he spoke about them."},{"v":46,"t":"When they sought to seize him, they feared the multitudes, because they considered him to be a prophet."}]},"22":{"en":[{"v":1,"t":"Jesus answered and spoke to them again in parables, saying,"},{"v":2,"t":"“The Kingdom of Heaven is like a certain king, who made a wedding feast for his son,"},{"v":3,"t":"and sent out his servants to call those who were invited to the wedding feast, but they would not come."},{"v":4,"t":"Again he sent out other servants, saying, ‘Tell those who are invited, “Behold, I have prepared my dinner. My cattle and my fatlings are killed, and all things are ready. Come to the wedding feast!”’"},{"v":5,"t":"But they made light of it, and went their ways, one to his own farm, another to his merchandise;"},{"v":6,"t":"and the rest grabbed his servants, treated them shamefully, and killed them."},{"v":7,"t":"When the king heard that, he was angry, and sent his armies, destroyed those murderers, and burned their city."},{"v":8,"t":"“Then he said to his servants, ‘The wedding is ready, but those who were invited weren’t worthy."},{"v":9,"t":"Go therefore to the intersections of the highways, and as many as you may find, invite to the wedding feast.’"},{"v":10,"t":"Those servants went out into the highways and gathered together as many as they found, both bad and good. The wedding was filled with guests."},{"v":11,"t":"“But when the king came in to see the guests, he saw there a man who didn’t have on wedding clothing,"},{"v":12,"t":"and he said to him, ‘Friend, how did you come in here not wearing wedding clothing?’ He was speechless."},{"v":13,"t":"Then the king said to the servants, ‘Bind him hand and foot, take him away, and throw him into the outer darkness. That is where the weeping and grinding of teeth will be.’"},{"v":14,"t":"For many are called, but few chosen.”"},{"v":15,"t":"Then the Pharisees went and took counsel how they might entrap him in his talk."},{"v":16,"t":"They sent their disciples to him, along with the Herodians, saying, “Teacher, we know that you are honest, and teach the way of God in truth, no matter whom you teach; for you aren’t partial to anyone."},{"v":17,"t":"Tell us therefore, what do you think? Is it lawful to pay taxes to Caesar, or not?”"},{"v":18,"t":"But Jesus perceived their wickedness, and said, “Why do you test me, you hypocrites?"},{"v":19,"t":"Show me the tax money.” They brought to him a denarius."},{"v":20,"t":"He asked them, “Whose is this image and inscription?”"},{"v":21,"t":"They said to him, “Caesar’s.” Then he said to them, “Give therefore to Caesar the things that are Caesar’s, and to God the things that are God’s.”"},{"v":22,"t":"When they heard it, they marveled, and left him and went away."},{"v":23,"t":"On that day Sadducees (those who say that there is no resurrection) came to him. They asked him,"},{"v":24,"t":"saying, “Teacher, Moses said, ‘If a man dies, having no children, his brother shall marry his wife and raise up offspring for his brother.’"},{"v":25,"t":"Now there were with us seven brothers. The first married and died, and having no offspring left his wife to his brother."},{"v":26,"t":"In the same way, the second also, and the third, to the seventh."},{"v":27,"t":"After them all, the woman died."},{"v":28,"t":"In the resurrection therefore, whose wife will she be of the seven? For they all had her.”"},{"v":29,"t":"But Jesus answered them, “You are mistaken, not knowing the Scriptures, nor the power of God."},{"v":30,"t":"For in the resurrection they neither marry nor are given in marriage, but are like God’s angels in heaven."},{"v":31,"t":"But concerning the resurrection of the dead, haven’t you read that which was spoken to you by God, saying,"},{"v":32,"t":"‘I am the God of Abraham, and the God of Isaac, and the God of Jacob’? God is not the God of the dead, but of the living.”"},{"v":33,"t":"When the multitudes heard it, they were astonished at his teaching."},{"v":34,"t":"But the Pharisees, when they heard that he had silenced the Sadducees, gathered themselves together."},{"v":35,"t":"One of them, a lawyer, asked him a question, testing him."},{"v":36,"t":"“Teacher, which is the greatest commandment in the law?”"},{"v":37,"t":"Jesus said to him, “‘You shall love the Lord your God with all your heart, with all your soul, and with all your mind.’"},{"v":38,"t":"This is the first and great commandment."},{"v":39,"t":"A second likewise is this, ‘You shall love your neighbor as yourself.’"},{"v":40,"t":"The whole law and the prophets depend on these two commandments.”"},{"v":41,"t":"Now while the Pharisees were gathered together, Jesus asked them a question,"},{"v":42,"t":"saying, “What do you think of the Christ? Whose son is he?” They said to him, “Of David.”"},{"v":43,"t":"He said to them, “How then does David in the Spirit call him Lord, saying,"},{"v":44,"t":"‘The Lord said to my Lord, sit on my right hand, until I make your enemies a footstool for your feet’?"},{"v":45,"t":"“If then David calls him Lord, how is he his son?”"},{"v":46,"t":"No one was able to answer him a word, neither did any man dare ask him any more questions from that day forward."}]},"23":{"en":[{"v":1,"t":"Then Jesus spoke to the multitudes and to his disciples,"},{"v":2,"t":"saying, “The scribes and the Pharisees sit on Moses’ seat."},{"v":3,"t":"All things therefore whatever they tell you to observe, observe and do, but don’t do their works; for they say, and don’t do."},{"v":4,"t":"For they bind heavy burdens that are grievous to be borne, and lay them on men’s shoulders; but they themselves will not lift a finger to help them."},{"v":5,"t":"But they do all their works to be seen by men. They make their phylacteries broad and enlarge the fringes of their garments,"},{"v":6,"t":"and love the place of honor at feasts, the best seats in the synagogues,"},{"v":7,"t":"the salutations in the marketplaces, and to be called ‘Rabbi, Rabbi’ by men."},{"v":8,"t":"But you are not to be called ‘Rabbi’, for one is your teacher, the Christ, and all of you are brothers."},{"v":9,"t":"Call no man on the earth your father, for one is your Father, he who is in heaven."},{"v":10,"t":"Neither be called masters, for one is your master, the Christ."},{"v":11,"t":"But he who is greatest among you will be your servant."},{"v":12,"t":"Whoever exalts himself will be humbled, and whoever humbles himself will be exalted."},{"v":13,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you devour widows’ houses, and as a pretense you make long prayers. Therefore you will receive greater condemnation."},{"v":14,"t":"“But woe to you, scribes and Pharisees, hypocrites! Because you shut up the Kingdom of Heaven against men; for you don’t enter in yourselves, neither do you allow those who are entering in to enter."},{"v":15,"t":"Woe to you, scribes and Pharisees, hypocrites! For you travel around by sea and land to make one proselyte; and when he becomes one, you make him twice as much a son of Gehenna as yourselves."},{"v":16,"t":"“Woe to you, you blind guides, who say, ‘Whoever swears by the temple, it is nothing; but whoever swears by the gold of the temple, he is obligated.’"},{"v":17,"t":"You blind fools! For which is greater, the gold or the temple that sanctifies the gold?"},{"v":18,"t":"And, ‘Whoever swears by the altar, it is nothing; but whoever swears by the gift that is on it, he is obligated.’"},{"v":19,"t":"You blind fools! For which is greater, the gift, or the altar that sanctifies the gift?"},{"v":20,"t":"He therefore who swears by the altar, swears by it and by everything on it."},{"v":21,"t":"He who swears by the temple, swears by it and by him who has been living in it."},{"v":22,"t":"He who swears by heaven, swears by the throne of God and by him who sits on it."},{"v":23,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you tithe mint, dill, and cumin, and have left undone the weightier matters of the law: justice, mercy, and faith. But you ought to have done these, and not to have left the other undone."},{"v":24,"t":"You blind guides, who strain out a gnat, and swallow a camel!"},{"v":25,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you clean the outside of the cup and of the platter, but within they are full of extortion and unrighteousness."},{"v":26,"t":"You blind Pharisee, first clean the inside of the cup and of the platter, that its outside may become clean also."},{"v":27,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you are like whitened tombs, which outwardly appear beautiful, but inwardly are full of dead men’s bones and of all uncleanness."},{"v":28,"t":"Even so you also outwardly appear righteous to men, but inwardly you are full of hypocrisy and iniquity."},{"v":29,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you build the tombs of the prophets and decorate the tombs of the righteous,"},{"v":30,"t":"and say, ‘If we had lived in the days of our fathers, we wouldn’t have been partakers with them in the blood of the prophets.’"},{"v":31,"t":"Therefore you testify to yourselves that you are children of those who killed the prophets."},{"v":32,"t":"Fill up, then, the measure of your fathers."},{"v":33,"t":"You serpents, you offspring of vipers, how will you escape the judgment of Gehenna?"},{"v":34,"t":"Therefore, behold, I send to you prophets, wise men, and scribes. Some of them you will kill and crucify; and some of them you will scourge in your synagogues and persecute from city to city,"},{"v":35,"t":"that on you may come all the righteous blood shed on the earth, from the blood of righteous Abel to the blood of Zachariah son of Barachiah, whom you killed between the sanctuary and the altar."},{"v":36,"t":"Most certainly I tell you, all these things will come upon this generation."},{"v":37,"t":"“Jerusalem, Jerusalem, who kills the prophets and stones those who are sent to her! How often I would have gathered your children together, even as a hen gathers her chicks under her wings, and you would not!"},{"v":38,"t":"Behold, your house is left to you desolate."},{"v":39,"t":"For I tell you, you will not see me from now on, until you say, ‘Blessed is he who comes in the name of the Lord!’”"}]},"24":{"en":[{"v":1,"t":"Jesus went out from the temple, and was going on his way. His disciples came to him to show him the buildings of the temple."},{"v":2,"t":"But he answered them, “You see all of these things, don’t you? Most certainly I tell you, there will not be left here one stone on another, that will not be thrown down.”"},{"v":3,"t":"As he sat on the Mount of Olives, the disciples came to him privately, saying, “Tell us, when will these things be? What is the sign of your coming, and of the end of the age?”"},{"v":4,"t":"Jesus answered them, “Be careful that no one leads you astray."},{"v":5,"t":"For many will come in my name, saying, ‘I am the Christ,’ and will lead many astray."},{"v":6,"t":"You will hear of wars and rumors of wars. See that you aren’t troubled, for all this must happen, but the end is not yet."},{"v":7,"t":"For nation will rise against nation, and kingdom against kingdom; and there will be famines, plagues, and earthquakes in various places."},{"v":8,"t":"But all these things are the beginning of birth pains."},{"v":9,"t":"“Then they will deliver you up to oppression and will kill you. You will be hated by all of the nations for my name’s sake."},{"v":10,"t":"Then many will stumble, and will deliver up one another, and will hate one another."},{"v":11,"t":"Many false prophets will arise and will lead many astray."},{"v":12,"t":"Because iniquity will be multiplied, the love of many will grow cold."},{"v":13,"t":"But he who endures to the end will be saved."},{"v":14,"t":"This Good News of the Kingdom will be preached in the whole world for a testimony to all the nations, and then the end will come."},{"v":15,"t":"“When, therefore, you see the abomination of desolation, which was spoken of through Daniel the prophet, standing in the holy place (let the reader understand),"},{"v":16,"t":"then let those who are in Judea flee to the mountains."},{"v":17,"t":"Let him who is on the housetop not go down to take out the things that are in his house."},{"v":18,"t":"Let him who is in the field not return back to get his clothes."},{"v":19,"t":"But woe to those who are with child and to nursing mothers in those days!"},{"v":20,"t":"Pray that your flight will not be in the winter nor on a Sabbath,"},{"v":21,"t":"for then there will be great suffering, such as has not been from the beginning of the world until now, no, nor ever will be."},{"v":22,"t":"Unless those days had been shortened, no flesh would have been saved. But for the sake of the chosen ones, those days will be shortened."},{"v":23,"t":"“Then if any man tells you, ‘Behold, here is the Christ!’ or, ‘There!’ don’t believe it."},{"v":24,"t":"For false christs and false prophets will arise, and they will show great signs and wonders, so as to lead astray, if possible, even the chosen ones."},{"v":25,"t":"“Behold, I have told you beforehand."},{"v":26,"t":"“If therefore they tell you, ‘Behold, he is in the wilderness,’ don’t go out; or ‘Behold, he is in the inner rooms,’ don’t believe it."},{"v":27,"t":"For as the lightning flashes from the east, and is seen even to the west, so will the coming of the Son of Man be."},{"v":28,"t":"For wherever the carcass is, that is where the vultures gather together."},{"v":29,"t":"“But immediately after the suffering of those days, the sun will be darkened, the moon will not give its light, the stars will fall from the sky, and the powers of the heavens will be shaken;"},{"v":30,"t":"and then the sign of the Son of Man will appear in the sky. Then all the tribes of the earth will mourn, and they will see the Son of Man coming on the clouds of the sky with power and great glory."},{"v":31,"t":"He will send out his angels with a great sound of a trumpet, and they will gather together his chosen ones from the four winds, from one end of the sky to the other."},{"v":32,"t":"“Now from the fig tree learn this parable: When its branch has now become tender and produces its leaves, you know that the summer is near."},{"v":33,"t":"Even so you also, when you see all these things, know that he is near, even at the doors."},{"v":34,"t":"Most certainly I tell you, this generation will not pass away until all these things are accomplished."},{"v":35,"t":"Heaven and earth will pass away, but my words will not pass away."},{"v":36,"t":"“But no one knows of that day and hour, not even the angels of heaven, but my Father only."},{"v":37,"t":"As the days of Noah were, so will the coming of the Son of Man be."},{"v":38,"t":"For as in those days which were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noah entered into the ship,"},{"v":39,"t":"and they didn’t know until the flood came and took them all away, so will the coming of the Son of Man be."},{"v":40,"t":"Then two men will be in the field: one will be taken and one will be left."},{"v":41,"t":"Two women will be grinding at the mill: one will be taken and one will be left."},{"v":42,"t":"Watch therefore, for you don’t know in what hour your Lord comes."},{"v":43,"t":"But know this, that if the master of the house had known in what watch of the night the thief was coming, he would have watched, and would not have allowed his house to be broken into."},{"v":44,"t":"Therefore also be ready, for in an hour that you don’t expect, the Son of Man will come."},{"v":45,"t":"“Who then is the faithful and wise servant, whom his lord has set over his household, to give them their food in due season?"},{"v":46,"t":"Blessed is that servant whom his lord finds doing so when he comes."},{"v":47,"t":"Most certainly I tell you that he will set him over all that he has."},{"v":48,"t":"But if that evil servant should say in his heart, ‘My lord is delaying his coming,’"},{"v":49,"t":"and begins to beat his fellow servants, and eat and drink with the drunkards,"},{"v":50,"t":"the lord of that servant will come in a day when he doesn’t expect it and in an hour when he doesn’t know it,"},{"v":51,"t":"and will cut him in pieces and appoint his portion with the hypocrites. That is where the weeping and grinding of teeth will be."}]},"25":{"en":[{"v":1,"t":"“Then the Kingdom of Heaven will be like ten virgins who took their lamps and went out to meet the bridegroom."},{"v":2,"t":"Five of them were foolish, and five were wise."},{"v":3,"t":"Those who were foolish, when they took their lamps, took no oil with them,"},{"v":4,"t":"but the wise took oil in their vessels with their lamps."},{"v":5,"t":"Now while the bridegroom delayed, they all slumbered and slept."},{"v":6,"t":"But at midnight there was a cry, ‘Behold! The bridegroom is coming! Come out to meet him!’"},{"v":7,"t":"Then all those virgins arose, and trimmed their lamps."},{"v":8,"t":"The foolish said to the wise, ‘Give us some of your oil, for our lamps are going out.’"},{"v":9,"t":"But the wise answered, saying, ‘What if there isn’t enough for us and you? You go rather to those who sell, and buy for yourselves.’"},{"v":10,"t":"While they went away to buy, the bridegroom came, and those who were ready went in with him to the wedding feast, and the door was shut."},{"v":11,"t":"Afterward the other virgins also came, saying, ‘Lord, Lord, open to us.’"},{"v":12,"t":"But he answered, ‘Most certainly I tell you, I don’t know you.’"},{"v":13,"t":"Watch therefore, for you don’t know the day nor the hour in which the Son of Man is coming."},{"v":14,"t":"“For it is like a man going into another country, who called his own servants and entrusted his goods to them."},{"v":15,"t":"To one he gave five talents, to another two, to another one, to each according to his own ability. Then he went on his journey."},{"v":16,"t":"Immediately he who received the five talents went and traded with them, and made another five talents."},{"v":17,"t":"In the same way, he also who got the two gained another two."},{"v":18,"t":"But he who received the one talent went away and dug in the earth and hid his lord’s money."},{"v":19,"t":"“Now after a long time the lord of those servants came, and settled accounts with them."},{"v":20,"t":"He who received the five talents came and brought another five talents, saying, ‘Lord, you delivered to me five talents. Behold, I have gained another five talents in addition to them.’"},{"v":21,"t":"“His lord said to him, ‘Well done, good and faithful servant. You have been faithful over a few things, I will set you over many things. Enter into the joy of your lord.’"},{"v":22,"t":"“He also who got the two talents came and said, ‘Lord, you delivered to me two talents. Behold, I have gained another two talents in addition to them.’"},{"v":23,"t":"“His lord said to him, ‘Well done, good and faithful servant. You have been faithful over a few things. I will set you over many things. Enter into the joy of your lord.’"},{"v":24,"t":"“He also who had received the one talent came and said, ‘Lord, I knew you that you are a hard man, reaping where you didn’t sow, and gathering where you didn’t scatter."},{"v":25,"t":"I was afraid, and went away and hid your talent in the earth. Behold, you have what is yours.’"},{"v":26,"t":"“But his lord answered him, ‘You wicked and slothful servant. You knew that I reap where I didn’t sow, and gather where I didn’t scatter."},{"v":27,"t":"You ought therefore to have deposited my money with the bankers, and at my coming I should have received back my own with interest."},{"v":28,"t":"Take away therefore the talent from him and give it to him who has the ten talents."},{"v":29,"t":"For to everyone who has will be given, and he will have abundance, but from him who doesn’t have, even that which he has will be taken away."},{"v":30,"t":"Throw out the unprofitable servant into the outer darkness, where there will be weeping and gnashing of teeth.’"},{"v":31,"t":"“But when the Son of Man comes in his glory, and all the holy angels with him, then he will sit on the throne of his glory."},{"v":32,"t":"Before him all the nations will be gathered, and he will separate them one from another, as a shepherd separates the sheep from the goats."},{"v":33,"t":"He will set the sheep on his right hand, but the goats on the left."},{"v":34,"t":"Then the King will tell those on his right hand, ‘Come, blessed of my Father, inherit the Kingdom prepared for you from the foundation of the world;"},{"v":35,"t":"for I was hungry and you gave me food to eat. I was thirsty and you gave me drink. I was a stranger and you took me in."},{"v":36,"t":"I was naked and you clothed me. I was sick and you visited me. I was in prison and you came to me.’"},{"v":37,"t":"“Then the righteous will answer him, saying, ‘Lord, when did we see you hungry and feed you, or thirsty and give you a drink?"},{"v":38,"t":"When did we see you as a stranger and take you in, or naked and clothe you?"},{"v":39,"t":"When did we see you sick or in prison and come to you?’"},{"v":40,"t":"“The King will answer them, ‘Most certainly I tell you, because you did it to one of the least of these my brothers, you did it to me.’"},{"v":41,"t":"Then he will say also to those on the left hand, ‘Depart from me, you cursed, into the eternal fire which is prepared for the devil and his angels;"},{"v":42,"t":"for I was hungry, and you didn’t give me food to eat; I was thirsty, and you gave me no drink;"},{"v":43,"t":"I was a stranger, and you didn’t take me in; naked, and you didn’t clothe me; sick, and in prison, and you didn’t visit me.’"},{"v":44,"t":"“Then they will also answer, saying, ‘Lord, when did we see you hungry, or thirsty, or a stranger, or naked, or sick, or in prison, and didn’t help you?’"},{"v":45,"t":"“Then he will answer them, saying, ‘Most certainly I tell you, because you didn’t do it to one of the least of these, you didn’t do it to me.’"},{"v":46,"t":"These will go away into eternal punishment, but the righteous into eternal life.”"}]},"26":{"en":[{"v":1,"t":"When Jesus had finished all these words, he said to his disciples,"},{"v":2,"t":"“You know that after two days the Passover is coming, and the Son of Man will be delivered up to be crucified.”"},{"v":3,"t":"Then the chief priests, the scribes, and the elders of the people were gathered together in the court of the high priest, who was called Caiaphas."},{"v":4,"t":"They took counsel together that they might take Jesus by deceit and kill him."},{"v":5,"t":"But they said, “Not during the feast, lest a riot occur among the people.”"},{"v":6,"t":"Now when Jesus was in Bethany, in the house of Simon the leper,"},{"v":7,"t":"a woman came to him having an alabaster jar of very expensive ointment, and she poured it on his head as he sat at the table."},{"v":8,"t":"But when his disciples saw this, they were indignant, saying, “Why this waste?"},{"v":9,"t":"For this ointment might have been sold for much and given to the poor.”"},{"v":10,"t":"However, knowing this, Jesus said to them, “Why do you trouble the woman? She has done a good work for me."},{"v":11,"t":"For you always have the poor with you, but you don’t always have me."},{"v":12,"t":"For in pouring this ointment on my body, she did it to prepare me for burial."},{"v":13,"t":"Most certainly I tell you, wherever this Good News is preached in the whole world, what this woman has done will also be spoken of as a memorial of her.”"},{"v":14,"t":"Then one of the twelve, who was called Judas Iscariot, went to the chief priests"},{"v":15,"t":"and said, “What are you willing to give me if I deliver him to you?” So they weighed out for him thirty pieces of silver."},{"v":16,"t":"From that time he sought opportunity to betray him."},{"v":17,"t":"Now on the first day of unleavened bread, the disciples came to Jesus, saying to him, “Where do you want us to prepare for you to eat the Passover?”"},{"v":18,"t":"He said, “Go into the city to a certain person, and tell him, ‘The Teacher says, “My time is at hand. I will keep the Passover at your house with my disciples.”’”"},{"v":19,"t":"The disciples did as Jesus commanded them, and they prepared the Passover."},{"v":20,"t":"Now when evening had come, he was reclining at the table with the twelve disciples."},{"v":21,"t":"As they were eating, he said, “Most certainly I tell you that one of you will betray me.”"},{"v":22,"t":"They were exceedingly sorrowful, and each began to ask him, “It isn’t me, is it, Lord?”"},{"v":23,"t":"He answered, “He who dipped his hand with me in the dish will betray me."},{"v":24,"t":"The Son of Man goes even as it is written of him, but woe to that man through whom the Son of Man is betrayed! It would be better for that man if he had not been born.”"},{"v":25,"t":"Judas, who betrayed him, answered, “It isn’t me, is it, Rabbi?” He said to him, “You said it.”"},{"v":26,"t":"As they were eating, Jesus took bread, gave thanks for it, and broke it. He gave to the disciples and said, “Take, eat; this is my body.”"},{"v":27,"t":"He took the cup, gave thanks, and gave to them, saying, “All of you drink it,"},{"v":28,"t":"for this is my blood of the new covenant, which is poured out for many for the remission of sins."},{"v":29,"t":"But I tell you that I will not drink of this fruit of the vine from now on, until that day when I drink it anew with you in my Father’s Kingdom.”"},{"v":30,"t":"When they had sung a hymn, they went out to the Mount of Olives."},{"v":31,"t":"Then Jesus said to them, “All of you will be made to stumble because of me tonight, for it is written, ‘I will strike the shepherd, and the sheep of the flock will be scattered.’"},{"v":32,"t":"But after I am raised up, I will go before you into Galilee.”"},{"v":33,"t":"But Peter answered him, “Even if all will be made to stumble because of you, I will never be made to stumble.”"},{"v":34,"t":"Jesus said to him, “Most certainly I tell you that tonight, before the rooster crows, you will deny me three times.”"},{"v":35,"t":"Peter said to him, “Even if I must die with you, I will not deny you.” All of the disciples also said likewise."},{"v":36,"t":"Then Jesus came with them to a place called Gethsemane, and said to his disciples, “Sit here, while I go there and pray.”"},{"v":37,"t":"He took with him Peter and the two sons of Zebedee, and began to be sorrowful and severely troubled."},{"v":38,"t":"Then Jesus said to them, “My soul is exceedingly sorrowful, even to death. Stay here and watch with me.”"},{"v":39,"t":"He went forward a little, fell on his face, and prayed, saying, “My Father, if it is possible, let this cup pass away from me; nevertheless, not what I desire, but what you desire.”"},{"v":40,"t":"He came to the disciples and found them sleeping, and said to Peter, “What, couldn’t you watch with me for one hour?"},{"v":41,"t":"Watch and pray, that you don’t enter into temptation. The spirit indeed is willing, but the flesh is weak.”"},{"v":42,"t":"Again, a second time he went away and prayed, saying, “My Father, if this cup can’t pass away from me unless I drink it, your desire be done.”"},{"v":43,"t":"He came again and found them sleeping, for their eyes were heavy."},{"v":44,"t":"He left them again, went away, and prayed a third time, saying the same words."},{"v":45,"t":"Then he came to his disciples and said to them, “Are you still sleeping and resting? Behold, the hour is at hand, and the Son of Man is betrayed into the hands of sinners."},{"v":46,"t":"Arise, let’s be going. Behold, he who betrays me is at hand.”"},{"v":47,"t":"While he was still speaking, behold, Judas, one of the twelve, came, and with him a great multitude with swords and clubs, from the chief priests and elders of the people."},{"v":48,"t":"Now he who betrayed him had given them a sign, saying, “Whoever I kiss, he is the one. Seize him.”"},{"v":49,"t":"Immediately he came to Jesus, and said, “Greetings, Rabbi!” and kissed him."},{"v":50,"t":"Jesus said to him, “Friend, why are you here?” Then they came and laid hands on Jesus, and took him."},{"v":51,"t":"Behold, one of those who were with Jesus stretched out his hand and drew his sword, and struck the servant of the high priest, and cut off his ear."},{"v":52,"t":"Then Jesus said to him, “Put your sword back into its place, for all those who take the sword will die by the sword."},{"v":53,"t":"Or do you think that I couldn’t ask my Father, and he would even now send me more than twelve legions of angels?"},{"v":54,"t":"How then would the Scriptures be fulfilled that it must be so?”"},{"v":55,"t":"In that hour Jesus said to the multitudes, “Have you come out as against a robber with swords and clubs to seize me? I sat daily in the temple teaching, and you didn’t arrest me."},{"v":56,"t":"But all this has happened that the Scriptures of the prophets might be fulfilled.” Then all the disciples left him and fled."},{"v":57,"t":"Those who had taken Jesus led him away to Caiaphas the high priest, where the scribes and the elders were gathered together."},{"v":58,"t":"But Peter followed him from a distance to the court of the high priest, and entered in and sat with the officers, to see the end."},{"v":59,"t":"Now the chief priests, the elders, and the whole council sought false testimony against Jesus, that they might put him to death,"},{"v":60,"t":"and they found none. Even though many false witnesses came forward, they found none. But at last two false witnesses came forward"},{"v":61,"t":"and said, “This man said, ‘I am able to destroy the temple of God, and to build it in three days.’”"},{"v":62,"t":"The high priest stood up and said to him, “Have you no answer? What is this that these testify against you?”"},{"v":63,"t":"But Jesus stayed silent. The high priest answered him, “I adjure you by the living God that you tell us whether you are the Christ, the Son of God.”"},{"v":64,"t":"Jesus said to him, “You have said so. Nevertheless, I tell you, after this you will see the Son of Man sitting at the right hand of Power, and coming on the clouds of the sky.”"},{"v":65,"t":"Then the high priest tore his clothing, saying, “He has spoken blasphemy! Why do we need any more witnesses? Behold, now you have heard his blasphemy."},{"v":66,"t":"What do you think?” They answered, “He is worthy of death!”"},{"v":67,"t":"Then they spat in his face and beat him with their fists, and some slapped him,"},{"v":68,"t":"saying, “Prophesy to us, you Christ! Who hit you?”"},{"v":69,"t":"Now Peter was sitting outside in the court, and a maid came to him, saying, “You were also with Jesus, the Galilean!”"},{"v":70,"t":"But he denied it before them all, saying, “I don’t know what you are talking about.”"},{"v":71,"t":"When he had gone out onto the porch, someone else saw him and said to those who were there, “This man also was with Jesus of Nazareth.”"},{"v":72,"t":"Again he denied it with an oath, “I don’t know the man.”"},{"v":73,"t":"After a little while those who stood by came and said to Peter, “Surely you are also one of them, for your speech makes you known.”"},{"v":74,"t":"Then he began to curse and to swear, “I don’t know the man!” Immediately the rooster crowed."},{"v":75,"t":"Peter remembered the word which Jesus had said to him, “Before the rooster crows, you will deny me three times.” Then he went out and wept bitterly."}]},"27":{"en":[{"v":1,"t":"Now when morning had come, all the chief priests and the elders of the people took counsel against Jesus to put him to death."},{"v":2,"t":"They bound him, led him away, and delivered him up to Pontius Pilate, the governor."},{"v":3,"t":"Then Judas, who betrayed him, when he saw that Jesus was condemned, felt remorse, and brought back the thirty pieces of silver to the chief priests and elders,"},{"v":4,"t":"saying, “I have sinned in that I betrayed innocent blood.” But they said, “What is that to us? You see to it.”"},{"v":5,"t":"He threw down the pieces of silver in the sanctuary and departed. Then he went away and hanged himself."},{"v":6,"t":"The chief priests took the pieces of silver and said, “It’s not lawful to put them into the treasury, since it is the price of blood.”"},{"v":7,"t":"They took counsel, and bought the potter’s field with them to bury strangers in."},{"v":8,"t":"Therefore that field has been called “The Field of Blood” to this day."},{"v":9,"t":"Then that which was spoken through Jeremiah the prophet was fulfilled, saying, “They took the thirty pieces of silver, the price of him upon whom a price had been set, whom some of the children of Israel priced,"},{"v":10,"t":"and they gave them for the potter’s field, as the Lord commanded me.”"},{"v":11,"t":"Now Jesus stood before the governor; and the governor asked him, saying, “Are you the King of the Jews?” Jesus said to him, “So you say.”"},{"v":12,"t":"When he was accused by the chief priests and elders, he answered nothing."},{"v":13,"t":"Then Pilate said to him, “Don’t you hear how many things they testify against you?”"},{"v":14,"t":"He gave him no answer, not even one word, so that the governor marveled greatly."},{"v":15,"t":"Now at the feast the governor was accustomed to release to the multitude one prisoner whom they desired."},{"v":16,"t":"They had then a notable prisoner called Barabbas."},{"v":17,"t":"When therefore they were gathered together, Pilate said to them, “Whom do you want me to release to you? Barabbas, or Jesus who is called Christ?”"},{"v":18,"t":"For he knew that because of envy they had delivered him up."},{"v":19,"t":"While he was sitting on the judgment seat, his wife sent to him, saying, “Have nothing to do with that righteous man, for I have suffered many things today in a dream because of him.”"},{"v":20,"t":"Now the chief priests and the elders persuaded the multitudes to ask for Barabbas and destroy Jesus."},{"v":21,"t":"But the governor answered them, “Which of the two do you want me to release to you?” They said, “Barabbas!”"},{"v":22,"t":"Pilate said to them, “What then shall I do to Jesus who is called Christ?” They all said to him, “Let him be crucified!”"},{"v":23,"t":"But the governor said, “Why? What evil has he done?” But they cried out exceedingly, saying, “Let him be crucified!”"},{"v":24,"t":"So when Pilate saw that nothing was being gained, but rather that a disturbance was starting, he took water and washed his hands before the multitude, saying, “I am innocent of the blood of this righteous person. You see to it.”"},{"v":25,"t":"All the people answered, “May his blood be on us and on our children!”"},{"v":26,"t":"Then he released Barabbas to them, but Jesus he flogged and delivered to be crucified."},{"v":27,"t":"Then the governor’s soldiers took Jesus into the Praetorium, and gathered the whole garrison together against him."},{"v":28,"t":"They stripped him and put a scarlet robe on him."},{"v":29,"t":"They braided a crown of thorns and put it on his head, and a reed in his right hand; and they kneeled down before him and mocked him, saying, “Hail, King of the Jews!”"},{"v":30,"t":"They spat on him, and took the reed and struck him on the head."},{"v":31,"t":"When they had mocked him, they took the robe off him, and put his clothes on him, and led him away to crucify him."},{"v":32,"t":"As they came out, they found a man of Cyrene, Simon by name, and they compelled him to go with them, that he might carry his cross."},{"v":33,"t":"When they came to a place called “Golgotha”, that is to say, “The place of a skull,”"},{"v":34,"t":"they gave him sour wine to drink mixed with gall. When he had tasted it, he would not drink."},{"v":35,"t":"When they had crucified him, they divided his clothing among them, casting lots,"},{"v":36,"t":"and they sat and watched him there."},{"v":37,"t":"They set up over his head the accusation against him written, “THIS IS JESUS, THE KING OF THE JEWS.”"},{"v":38,"t":"Then there were two robbers crucified with him, one on his right hand and one on the left."},{"v":39,"t":"Those who passed by blasphemed him, wagging their heads"},{"v":40,"t":"and saying, “You who destroy the temple and build it in three days, save yourself! If you are the Son of God, come down from the cross!”"},{"v":41,"t":"Likewise the chief priests also mocking with the scribes, the Pharisees, and the elders, said,"},{"v":42,"t":"“He saved others, but he can’t save himself. If he is the King of Israel, let him come down from the cross now, and we will believe in him."},{"v":43,"t":"He trusts in God. Let God deliver him now, if he wants him; for he said, ‘I am the Son of God.’”"},{"v":44,"t":"The robbers also who were crucified with him cast on him the same reproach."},{"v":45,"t":"Now from the sixth hour there was darkness over all the land until the ninth hour."},{"v":46,"t":"About the ninth hour Jesus cried with a loud voice, saying, “Eli, Eli, lima sabachthani?” That is, “My God, my God, why have you forsaken me?”"},{"v":47,"t":"Some of them who stood there, when they heard it, said, “This man is calling Elijah.”"},{"v":48,"t":"Immediately one of them ran and took a sponge, filled it with vinegar, put it on a reed, and gave him a drink."},{"v":49,"t":"The rest said, “Let him be. Let’s see whether Elijah comes to save him.”"},{"v":50,"t":"Jesus cried again with a loud voice, and yielded up his spirit."},{"v":51,"t":"Behold, the veil of the temple was torn in two from the top to the bottom. The earth quaked and the rocks were split."},{"v":52,"t":"The tombs were opened, and many bodies of the saints who had fallen asleep were raised;"},{"v":53,"t":"and coming out of the tombs after his resurrection, they entered into the holy city and appeared to many."},{"v":54,"t":"Now the centurion and those who were with him watching Jesus, when they saw the earthquake and the things that were done, were terrified, saying, “Truly this was the Son of God!”"},{"v":55,"t":"Many women were there watching from afar, who had followed Jesus from Galilee, serving him."},{"v":56,"t":"Among them were Mary Magdalene, Mary the mother of James and Joses, and the mother of the sons of Zebedee."},{"v":57,"t":"When evening had come, a rich man from Arimathaea named Joseph, who himself was also Jesus’ disciple, came."},{"v":58,"t":"This man went to Pilate and asked for Jesus’ body. Then Pilate commanded the body to be given up."},{"v":59,"t":"Joseph took the body and wrapped it in a clean linen cloth"},{"v":60,"t":"and laid it in his own new tomb, which he had cut out in the rock. Then he rolled a large stone against the door of the tomb, and departed."},{"v":61,"t":"Mary Magdalene was there, and the other Mary, sitting opposite the tomb."},{"v":62,"t":"Now on the next day, which was the day after the Preparation Day, the chief priests and the Pharisees were gathered together to Pilate,"},{"v":63,"t":"saying, “Sir, we remember what that deceiver said while he was still alive: ‘After three days I will rise again.’"},{"v":64,"t":"Command therefore that the tomb be made secure until the third day, lest perhaps his disciples come at night and steal him away, and tell the people, ‘He is risen from the dead;’ and the last deception will be worse than the first.”"},{"v":65,"t":"Pilate said to them, “You have a guard. Go, make it as secure as you can.”"},{"v":66,"t":"So they went with the guard and made the tomb secure, sealing the stone."}]},"28":{"en":[{"v":1,"t":"Now after the Sabbath, as it began to dawn on the first day of the week, Mary Magdalene and the other Mary came to see the tomb."},{"v":2,"t":"Behold, there was a great earthquake, for an angel of the Lord descended from the sky and came and rolled away the stone from the door and sat on it."},{"v":3,"t":"His appearance was like lightning, and his clothing white as snow."},{"v":4,"t":"For fear of him, the guards shook, and became like dead men."},{"v":5,"t":"The angel answered the women, “Don’t be afraid, for I know that you seek Jesus, who has been crucified."},{"v":6,"t":"He is not here, for he has risen, just like he said. Come, see the place where the Lord was lying."},{"v":7,"t":"Go quickly and tell his disciples, ‘He has risen from the dead, and behold, he goes before you into Galilee; there you will see him.’ Behold, I have told you.”"},{"v":8,"t":"They departed quickly from the tomb with fear and great joy, and ran to bring his disciples word."},{"v":9,"t":"As they went to tell his disciples, behold, Jesus met them, saying, “Rejoice!” They came and took hold of his feet, and worshiped him."},{"v":10,"t":"Then Jesus said to them, “Don’t be afraid. Go tell my brothers that they should go into Galilee, and there they will see me.”"},{"v":11,"t":"Now while they were going, behold, some of the guards came into the city and told the chief priests all the things that had happened."},{"v":12,"t":"When they were assembled with the elders and had taken counsel, they gave a large amount of silver to the soldiers,"},{"v":13,"t":"saying, “Say that his disciples came by night and stole him away while we slept."},{"v":14,"t":"If this comes to the governor’s ears, we will persuade him and make you free of worry.”"},{"v":15,"t":"So they took the money and did as they were told. This saying was spread abroad among the Jews, and continues until today."},{"v":16,"t":"But the eleven disciples went into Galilee, to the mountain where Jesus had sent them."},{"v":17,"t":"When they saw him, they bowed down to him; but some doubted."},{"v":18,"t":"Jesus came to them and spoke to them, saying, “All authority has been given to me in heaven and on earth."},{"v":19,"t":"Go and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit,"},{"v":20,"t":"teaching them to observe all things that I commanded you. Behold, I am with you always, even to the end of the age.” Amen."}]}},"MRK":{"1":{"en":[{"v":1,"t":"The beginning of the Good News of Jesus Christ, the Son of God."},{"v":2,"t":"As it is written in the prophets, “Behold, I send my messenger before your face, who will prepare your way before you:"},{"v":3,"t":"the voice of one crying in the wilderness, ‘Make ready the way of the Lord! Make his paths straight!’”"},{"v":4,"t":"John came baptizing in the wilderness and preaching the baptism of repentance for forgiveness of sins."},{"v":5,"t":"All the country of Judea and all those of Jerusalem went out to him. They were baptized by him in the Jordan river, confessing their sins."},{"v":6,"t":"John was clothed with camel’s hair and a leather belt around his waist. He ate locusts and wild honey."},{"v":7,"t":"He preached, saying, “After me comes he who is mightier than I, the strap of whose sandals I am not worthy to stoop down and loosen."},{"v":8,"t":"I baptized you in water, but he will baptize you in the Holy Spirit.”"},{"v":9,"t":"In those days, Jesus came from Nazareth of Galilee, and was baptized by John in the Jordan."},{"v":10,"t":"Immediately coming up from the water, he saw the heavens parting and the Spirit descending on him like a dove."},{"v":11,"t":"A voice came out of the sky, “You are my beloved Son, in whom I am well pleased.”"},{"v":12,"t":"Immediately the Spirit drove him out into the wilderness."},{"v":13,"t":"He was there in the wilderness forty days, tempted by Satan. He was with the wild animals; and the angels were serving him."},{"v":14,"t":"Now after John was taken into custody, Jesus came into Galilee, preaching the Good News of God’s Kingdom,"},{"v":15,"t":"and saying, “The time is fulfilled, and God’s Kingdom is at hand! Repent, and believe in the Good News.”"},{"v":16,"t":"Passing along by the sea of Galilee, he saw Simon and Andrew, the brother of Simon, casting a net into the sea, for they were fishermen."},{"v":17,"t":"Jesus said to them, “Come after me, and I will make you into fishers for men.”"},{"v":18,"t":"Immediately they left their nets, and followed him."},{"v":19,"t":"Going on a little further from there, he saw James the son of Zebedee, and John his brother, who were also in the boat mending the nets."},{"v":20,"t":"Immediately he called them, and they left their father, Zebedee, in the boat with the hired servants, and went after him."},{"v":21,"t":"They went into Capernaum, and immediately on the Sabbath day he entered into the synagogue and taught."},{"v":22,"t":"They were astonished at his teaching, for he taught them as having authority, and not as the scribes."},{"v":23,"t":"Immediately there was in their synagogue a man with an unclean spirit, and he cried out,"},{"v":24,"t":"saying, “Ha! What do we have to do with you, Jesus, you Nazarene? Have you come to destroy us? I know who you are: the Holy One of God!”"},{"v":25,"t":"Jesus rebuked him, saying, “Be quiet, and come out of him!”"},{"v":26,"t":"The unclean spirit, convulsing him and crying with a loud voice, came out of him."},{"v":27,"t":"They were all amazed, so that they questioned among themselves, saying, “What is this? A new teaching? For with authority he commands even the unclean spirits, and they obey him!”"},{"v":28,"t":"The report of him went out immediately everywhere into all the region of Galilee and its surrounding area."},{"v":29,"t":"Immediately, when they had come out of the synagogue, they came into the house of Simon and Andrew, with James and John."},{"v":30,"t":"Now Simon’s wife’s mother lay sick with a fever, and immediately they told him about her."},{"v":31,"t":"He came and took her by the hand and raised her up. The fever left her immediately, and she served them."},{"v":32,"t":"At evening, when the sun had set, they brought to him all who were sick and those who were possessed by demons."},{"v":33,"t":"All the city was gathered together at the door."},{"v":34,"t":"He healed many who were sick with various diseases and cast out many demons. He didn’t allow the demons to speak, because they knew him."},{"v":35,"t":"Early in the morning, while it was still dark, he rose up and went out, and departed into a deserted place, and prayed there."},{"v":36,"t":"Simon and those who were with him searched for him."},{"v":37,"t":"They found him and told him, “Everyone is looking for you.”"},{"v":38,"t":"He said to them, “Let’s go elsewhere into the next towns, that I may preach there also, because I came out for this reason.”"},{"v":39,"t":"He went into their synagogues throughout all Galilee, preaching and casting out demons."},{"v":40,"t":"A leper came to him, begging him, kneeling down to him, and saying to him, “If you want to, you can make me clean.”"},{"v":41,"t":"Being moved with compassion, he stretched out his hand, and touched him, and said to him, “I want to. Be made clean.”"},{"v":42,"t":"When he had said this, immediately the leprosy departed from him and he was made clean."},{"v":43,"t":"He strictly warned him and immediately sent him out,"},{"v":44,"t":"and said to him, “See that you say nothing to anybody, but go show yourself to the priest and offer for your cleansing the things which Moses commanded, for a testimony to them.”"},{"v":45,"t":"But he went out, and began to proclaim it much, and to spread about the matter, so that Jesus could no more openly enter into a city, but was outside in desert places. People came to him from everywhere."}]},"2":{"en":[{"v":1,"t":"When he entered again into Capernaum after some days, it was heard that he was at home."},{"v":2,"t":"Immediately many were gathered together, so that there was no more room, not even around the door; and he spoke the word to them."},{"v":3,"t":"Four people came, carrying a paralytic to him."},{"v":4,"t":"When they could not come near to him for the crowd, they removed the roof where he was. When they had broken it up, they let down the mat that the paralytic was lying on."},{"v":5,"t":"Jesus, seeing their faith, said to the paralytic, “Son, your sins are forgiven you.”"},{"v":6,"t":"But there were some of the scribes sitting there and reasoning in their hearts,"},{"v":7,"t":"“Why does this man speak blasphemies like that? Who can forgive sins but God alone?”"},{"v":8,"t":"Immediately Jesus, perceiving in his spirit that they so reasoned within themselves, said to them, “Why do you reason these things in your hearts?"},{"v":9,"t":"Which is easier, to tell the paralytic, ‘Your sins are forgiven;’ or to say, ‘Arise, and take up your bed, and walk’?"},{"v":10,"t":"But that you may know that the Son of Man has authority on earth to forgive sins”—he said to the paralytic—"},{"v":11,"t":"“I tell you, arise, take up your mat, and go to your house.”"},{"v":12,"t":"He arose, and immediately took up the mat and went out in front of them all, so that they were all amazed and glorified God, saying, “We never saw anything like this!”"},{"v":13,"t":"He went out again by the seaside. All the multitude came to him, and he taught them."},{"v":14,"t":"As he passed by, he saw Levi the son of Alphaeus sitting at the tax office. He said to him, “Follow me.” And he arose and followed him."},{"v":15,"t":"He was reclining at the table in his house, and many tax collectors and sinners sat down with Jesus and his disciples, for there were many, and they followed him."},{"v":16,"t":"The scribes and the Pharisees, when they saw that he was eating with the sinners and tax collectors, said to his disciples, “Why is it that he eats and drinks with tax collectors and sinners?”"},{"v":17,"t":"When Jesus heard it, he said to them, “Those who are healthy have no need for a physician, but those who are sick. I came not to call the righteous, but sinners to repentance.”"},{"v":18,"t":"John’s disciples and the Pharisees were fasting, and they came and asked him, “Why do John’s disciples and the disciples of the Pharisees fast, but your disciples don’t fast?”"},{"v":19,"t":"Jesus said to them, “Can the groomsmen fast while the bridegroom is with them? As long as they have the bridegroom with them, they can’t fast."},{"v":20,"t":"But the days will come when the bridegroom will be taken away from them, and then they will fast in that day."},{"v":21,"t":"No one sews a piece of unshrunk cloth on an old garment, or else the patch shrinks and the new tears away from the old, and a worse hole is made."},{"v":22,"t":"No one puts new wine into old wineskins; or else the new wine will burst the skins, and the wine pours out, and the skins will be destroyed; but they put new wine into fresh wineskins.”"},{"v":23,"t":"He was going on the Sabbath day through the grain fields; and his disciples began, as they went, to pluck the ears of grain."},{"v":24,"t":"The Pharisees said to him, “Behold, why do they do that which is not lawful on the Sabbath day?”"},{"v":25,"t":"He said to them, “Did you never read what David did when he had need and was hungry—he, and those who were with him?"},{"v":26,"t":"How he entered into God’s house at the time of Abiathar the high priest, and ate the show bread, which is not lawful to eat except for the priests, and gave also to those who were with him?”"},{"v":27,"t":"He said to them, “The Sabbath was made for man, not man for the Sabbath."},{"v":28,"t":"Therefore the Son of Man is lord even of the Sabbath.”"}]},"3":{"en":[{"v":1,"t":"He entered again into the synagogue, and there was a man there whose hand was withered."},{"v":2,"t":"They watched him, whether he would heal him on the Sabbath day, that they might accuse him."},{"v":3,"t":"He said to the man whose hand was withered, “Stand up.”"},{"v":4,"t":"He said to them, “Is it lawful on the Sabbath day to do good or to do harm? To save a life or to kill?” But they were silent."},{"v":5,"t":"When he had looked around at them with anger, being grieved at the hardening of their hearts, he said to the man, “Stretch out your hand.” He stretched it out, and his hand was restored as healthy as the other."},{"v":6,"t":"The Pharisees went out, and immediately conspired with the Herodians against him, how they might destroy him."},{"v":7,"t":"Jesus withdrew to the sea with his disciples; and a great multitude followed him from Galilee, from Judea,"},{"v":8,"t":"from Jerusalem, from Idumaea, beyond the Jordan, and those from around Tyre and Sidon. A great multitude, hearing what great things he did, came to him."},{"v":9,"t":"He spoke to his disciples that a little boat should stay near him because of the crowd, so that they wouldn’t press on him."},{"v":10,"t":"For he had healed many, so that as many as had diseases pressed on him that they might touch him."},{"v":11,"t":"The unclean spirits, whenever they saw him, fell down before him and cried, “You are the Son of God!”"},{"v":12,"t":"He sternly warned them that they should not make him known."},{"v":13,"t":"He went up into the mountain and called to himself those whom he wanted, and they went to him."},{"v":14,"t":"He appointed twelve, that they might be with him, and that he might send them out to preach"},{"v":15,"t":"and to have authority to heal sicknesses and to cast out demons:"},{"v":16,"t":"Simon (to whom he gave the name Peter);"},{"v":17,"t":"James the son of Zebedee; and John, the brother of James, (whom he called Boanerges, which means, Sons of Thunder);"},{"v":18,"t":"Andrew; Philip; Bartholomew; Matthew; Thomas; James, the son of Alphaeus; Thaddaeus; Simon the Zealot;"},{"v":19,"t":"and Judas Iscariot, who also betrayed him. Then he came into a house."},{"v":20,"t":"The multitude came together again, so that they could not so much as eat bread."},{"v":21,"t":"When his friends heard it, they went out to seize him; for they said, “He is insane.”"},{"v":22,"t":"The scribes who came down from Jerusalem said, “He has Beelzebul,” and, “By the prince of the demons he casts out the demons.”"},{"v":23,"t":"He summoned them and said to them in parables, “How can Satan cast out Satan?"},{"v":24,"t":"If a kingdom is divided against itself, that kingdom cannot stand."},{"v":25,"t":"If a house is divided against itself, that house cannot stand."},{"v":26,"t":"If Satan has risen up against himself, and is divided, he can’t stand, but has an end."},{"v":27,"t":"But no one can enter into the house of the strong man to plunder unless he first binds the strong man; then he will plunder his house."},{"v":28,"t":"“Most certainly I tell you, all sins of the descendants of man will be forgiven, including their blasphemies with which they may blaspheme;"},{"v":29,"t":"but whoever may blaspheme against the Holy Spirit never has forgiveness, but is subject to eternal condemnation.”"},{"v":30,"t":"—because they said, “He has an unclean spirit.”"},{"v":31,"t":"His mother and his brothers came, and standing outside, they sent to him, calling him."},{"v":32,"t":"A multitude was sitting around him, and they told him, “Behold, your mother, your brothers, and your sisters are outside looking for you.”"},{"v":33,"t":"He answered them, “Who are my mother and my brothers?”"},{"v":34,"t":"Looking around at those who sat around him, he said, “Behold, my mother and my brothers!"},{"v":35,"t":"For whoever does the will of God is my brother, my sister, and mother.”"}]},"4":{"en":[{"v":1,"t":"Again he began to teach by the seaside. A great multitude was gathered to him, so that he entered into a boat in the sea and sat down. All the multitude were on the land by the sea."},{"v":2,"t":"He taught them many things in parables, and told them in his teaching,"},{"v":3,"t":"“Listen! Behold, the farmer went out to sow."},{"v":4,"t":"As he sowed, some seed fell by the road, and the birds came and devoured it."},{"v":5,"t":"Others fell on the rocky ground, where it had little soil, and immediately it sprang up, because it had no depth of soil."},{"v":6,"t":"When the sun had risen, it was scorched; and because it had no root, it withered away."},{"v":7,"t":"Others fell among the thorns, and the thorns grew up and choked it, and it yielded no fruit."},{"v":8,"t":"Others fell into the good ground and yielded fruit, growing up and increasing. Some produced thirty times, some sixty times, and some one hundred times as much.”"},{"v":9,"t":"He said, “Whoever has ears to hear, let him hear.”"},{"v":10,"t":"When he was alone, those who were around him with the twelve asked him about the parables."},{"v":11,"t":"He said to them, “To you is given the mystery of God’s Kingdom, but to those who are outside, all things are done in parables,"},{"v":12,"t":"that ‘seeing they may see and not perceive, and hearing they may hear and not understand, lest perhaps they should turn again, and their sins should be forgiven them.’”"},{"v":13,"t":"He said to them, “Don’t you understand this parable? How will you understand all of the parables?"},{"v":14,"t":"The farmer sows the word."},{"v":15,"t":"The ones by the road are the ones where the word is sown; and when they have heard, immediately Satan comes and takes away the word which has been sown in them."},{"v":16,"t":"These in the same way are those who are sown on the rocky places, who, when they have heard the word, immediately receive it with joy."},{"v":17,"t":"They have no root in themselves, but are short-lived. When oppression or persecution arises because of the word, immediately they stumble."},{"v":18,"t":"Others are those who are sown among the thorns. These are those who have heard the word,"},{"v":19,"t":"and the cares of this age, and the deceitfulness of riches, and the lusts of other things entering in choke the word, and it becomes unfruitful."},{"v":20,"t":"Those which were sown on the good ground are those who hear the word, accept it, and bear fruit, some thirty times, some sixty times, and some one hundred times.”"},{"v":21,"t":"He said to them, “Is a lamp brought to be put under a basket or under a bed? Isn’t it put on a stand?"},{"v":22,"t":"For there is nothing hidden except that it should be made known, neither was anything made secret but that it should come to light."},{"v":23,"t":"If any man has ears to hear, let him hear.”"},{"v":24,"t":"He said to them, “Take heed what you hear. With whatever measure you measure, it will be measured to you; and more will be given to you who hear."},{"v":25,"t":"For whoever has, to him more will be given; and he who doesn’t have, even that which he has will be taken away from him.”"},{"v":26,"t":"He said, “God’s Kingdom is as if a man should cast seed on the earth,"},{"v":27,"t":"and should sleep and rise night and day, and the seed should spring up and grow, though he doesn’t know how."},{"v":28,"t":"For the earth bears fruit by itself: first the blade, then the ear, then the full grain in the ear."},{"v":29,"t":"But when the fruit is ripe, immediately he puts in the sickle, because the harvest has come.”"},{"v":30,"t":"He said, “How will we liken God’s Kingdom? Or with what parable will we illustrate it?"},{"v":31,"t":"It’s like a grain of mustard seed, which, when it is sown in the earth, though it is less than all the seeds that are on the earth,"},{"v":32,"t":"yet when it is sown, grows up and becomes greater than all the herbs, and puts out great branches, so that the birds of the sky can lodge under its shadow.”"},{"v":33,"t":"With many such parables he spoke the word to them, as they were able to hear it."},{"v":34,"t":"Without a parable he didn’t speak to them; but privately to his own disciples he explained everything."},{"v":35,"t":"On that day, when evening had come, he said to them, “Let’s go over to the other side.”"},{"v":36,"t":"Leaving the multitude, they took him with them, even as he was, in the boat. Other small boats were also with him."},{"v":37,"t":"A big wind storm arose, and the waves beat into the boat, so much that the boat was already filled."},{"v":38,"t":"He himself was in the stern, asleep on the cushion; and they woke him up and asked him, “Teacher, don’t you care that we are dying?”"},{"v":39,"t":"He awoke and rebuked the wind, and said to the sea, “Peace! Be still!” The wind ceased and there was a great calm."},{"v":40,"t":"He said to them, “Why are you so afraid? How is it that you have no faith?”"},{"v":41,"t":"They were greatly afraid and said to one another, “Who then is this, that even the wind and the sea obey him?”"}]},"5":{"en":[{"v":1,"t":"They came to the other side of the sea, into the country of the Gadarenes."},{"v":2,"t":"When he had come out of the boat, immediately a man with an unclean spirit met him out of the tombs."},{"v":3,"t":"He lived in the tombs. Nobody could bind him any more, not even with chains,"},{"v":4,"t":"because he had been often bound with fetters and chains, and the chains had been torn apart by him, and the fetters broken in pieces. Nobody had the strength to tame him."},{"v":5,"t":"Always, night and day, in the tombs and in the mountains, he was crying out, and cutting himself with stones."},{"v":6,"t":"When he saw Jesus from afar, he ran and bowed down to him,"},{"v":7,"t":"and crying out with a loud voice, he said, “What have I to do with you, Jesus, you Son of the Most High God? I adjure you by God, don’t torment me.”"},{"v":8,"t":"For he said to him, “Come out of the man, you unclean spirit!”"},{"v":9,"t":"He asked him, “What is your name?” He said to him, “My name is Legion, for we are many.”"},{"v":10,"t":"He begged him much that he would not send them away out of the country."},{"v":11,"t":"Now on the mountainside there was a great herd of pigs feeding."},{"v":12,"t":"All the demons begged him, saying, “Send us into the pigs, that we may enter into them.”"},{"v":13,"t":"At once Jesus gave them permission. The unclean spirits came out and entered into the pigs. The herd of about two thousand rushed down the steep bank into the sea, and they were drowned in the sea."},{"v":14,"t":"Those who fed the pigs fled, and told it in the city and in the country. The people came to see what it was that had happened."},{"v":15,"t":"They came to Jesus, and saw him who had been possessed by demons sitting, clothed, and in his right mind, even him who had the legion; and they were afraid."},{"v":16,"t":"Those who saw it declared to them what happened to him who was possessed by demons, and about the pigs."},{"v":17,"t":"They began to beg him to depart from their region."},{"v":18,"t":"As he was entering into the boat, he who had been possessed by demons begged him that he might be with him."},{"v":19,"t":"He didn’t allow him, but said to him, “Go to your house, to your friends, and tell them what great things the Lord has done for you and how he had mercy on you.”"},{"v":20,"t":"He went his way, and began to proclaim in Decapolis how Jesus had done great things for him, and everyone marveled."},{"v":21,"t":"When Jesus had crossed back over in the boat to the other side, a great multitude was gathered to him; and he was by the sea."},{"v":22,"t":"Behold, one of the rulers of the synagogue, Jairus by name, came; and seeing him, he fell at his feet"},{"v":23,"t":"and begged him much, saying, “My little daughter is at the point of death. Please come and lay your hands on her, that she may be made healthy, and live.”"},{"v":24,"t":"He went with him, and a great multitude followed him, and they pressed upon him on all sides."},{"v":25,"t":"A certain woman who had a discharge of blood for twelve years,"},{"v":26,"t":"and had suffered many things by many physicians, and had spent all that she had, and was no better, but rather grew worse,"},{"v":27,"t":"having heard the things concerning Jesus, came up behind him in the crowd and touched his clothes."},{"v":28,"t":"For she said, “If I just touch his clothes, I will be made well.”"},{"v":29,"t":"Immediately the flow of her blood was dried up, and she felt in her body that she was healed of her affliction."},{"v":30,"t":"Immediately Jesus, perceiving in himself that the power had gone out from him, turned around in the crowd and asked, “Who touched my clothes?”"},{"v":31,"t":"His disciples said to him, “You see the multitude pressing against you, and you say, ‘Who touched me?’”"},{"v":32,"t":"He looked around to see her who had done this thing."},{"v":33,"t":"But the woman, fearing and trembling, knowing what had been done to her, came and fell down before him, and told him all the truth."},{"v":34,"t":"He said to her, “Daughter, your faith has made you well. Go in peace, and be cured of your disease.”"},{"v":35,"t":"While he was still speaking, people came from the synagogue ruler’s house, saying, “Your daughter is dead. Why bother the Teacher any more?”"},{"v":36,"t":"But Jesus, when he heard the message spoken, immediately said to the ruler of the synagogue, “Don’t be afraid, only believe.”"},{"v":37,"t":"He allowed no one to follow him except Peter, James, and John the brother of James."},{"v":38,"t":"He came to the synagogue ruler’s house, and he saw an uproar, weeping, and great wailing."},{"v":39,"t":"When he had entered in, he said to them, “Why do you make an uproar and weep? The child is not dead, but is asleep.”"},{"v":40,"t":"They ridiculed him. But he, having put them all out, took the father of the child, her mother, and those who were with him, and went in where the child was lying."},{"v":41,"t":"Taking the child by the hand, he said to her, “Talitha cumi!” which means, being interpreted, “Girl, I tell you, get up!”"},{"v":42,"t":"Immediately the girl rose up and walked, for she was twelve years old. They were amazed with great amazement."},{"v":43,"t":"He strictly ordered them that no one should know this, and commanded that something should be given to her to eat."}]},"6":{"en":[{"v":1,"t":"He went out from there. He came into his own country, and his disciples followed him."},{"v":2,"t":"When the Sabbath had come, he began to teach in the synagogue, and many hearing him were astonished, saying, “Where did this man get these things?” and, “What is the wisdom that is given to this man, that such mighty works come about by his hands?"},{"v":3,"t":"Isn’t this the carpenter, the son of Mary and brother of James, Joses, Judah, and Simon? Aren’t his sisters here with us?” So they were offended at him."},{"v":4,"t":"Jesus said to them, “A prophet is not without honor, except in his own country, and among his own relatives, and in his own house.”"},{"v":5,"t":"He could do no mighty work there, except that he laid his hands on a few sick people and healed them."},{"v":6,"t":"He marveled because of their unbelief. He went around the villages teaching."},{"v":7,"t":"He called to himself the twelve, and began to send them out two by two; and he gave them authority over the unclean spirits."},{"v":8,"t":"He commanded them that they should take nothing for their journey, except a staff only: no bread, no wallet, no money in their purse,"},{"v":9,"t":"but to wear sandals, and not put on two tunics."},{"v":10,"t":"He said to them, “Wherever you enter into a house, stay there until you depart from there."},{"v":11,"t":"Whoever will not receive you nor hear you, as you depart from there, shake off the dust that is under your feet for a testimony against them. Assuredly, I tell you, it will be more tolerable for Sodom and Gomorrah in the day of judgment than for that city!”"},{"v":12,"t":"They went out and preached that people should repent."},{"v":13,"t":"They cast out many demons, and anointed many with oil who were sick and healed them."},{"v":14,"t":"King Herod heard this, for his name had become known, and he said, “John the Baptizer has risen from the dead, and therefore these powers are at work in him.”"},{"v":15,"t":"But others said, “He is Elijah.” Others said, “He is a prophet, or like one of the prophets.”"},{"v":16,"t":"But Herod, when he heard this, said, “This is John, whom I beheaded. He has risen from the dead.”"},{"v":17,"t":"For Herod himself had sent out and arrested John and bound him in prison for the sake of Herodias, his brother Philip’s wife, for he had married her."},{"v":18,"t":"For John had said to Herod, “It is not lawful for you to have your brother’s wife.”"},{"v":19,"t":"Herodias set herself against him and desired to kill him, but she couldn’t,"},{"v":20,"t":"for Herod feared John, knowing that he was a righteous and holy man, and kept him safe. When he heard him, he did many things, and he heard him gladly."},{"v":21,"t":"Then a convenient day came when Herod on his birthday made a supper for his nobles, the high officers, and the chief men of Galilee."},{"v":22,"t":"When the daughter of Herodias herself came in and danced, she pleased Herod and those sitting with him. The king said to the young lady, “Ask me whatever you want, and I will give it to you.”"},{"v":23,"t":"He swore to her, “Whatever you ask of me, I will give you, up to half of my kingdom.”"},{"v":24,"t":"She went out and said to her mother, “What shall I ask?” She said, “The head of John the Baptizer.”"},{"v":25,"t":"She came in immediately with haste to the king and requested, “I want you to give me right now the head of John the Baptizer on a platter.”"},{"v":26,"t":"The king was exceedingly sorry, but for the sake of his oaths and of his dinner guests, he didn’t wish to refuse her."},{"v":27,"t":"Immediately the king sent out a soldier of his guard and commanded to bring John’s head; and he went and beheaded him in the prison,"},{"v":28,"t":"and brought his head on a platter, and gave it to the young lady; and the young lady gave it to her mother."},{"v":29,"t":"When his disciples heard this, they came and took up his corpse and laid it in a tomb."},{"v":30,"t":"The apostles gathered themselves together to Jesus, and they told him all things, whatever they had done, and whatever they had taught."},{"v":31,"t":"He said to them, “Come away into a deserted place, and rest awhile.” For there were many coming and going, and they had no leisure so much as to eat."},{"v":32,"t":"They went away in the boat to a deserted place by themselves."},{"v":33,"t":"They saw them going, and many recognized him and ran there on foot from all the cities. They arrived before them and came together to him."},{"v":34,"t":"Jesus came out, saw a great multitude, and he had compassion on them because they were like sheep without a shepherd; and he began to teach them many things."},{"v":35,"t":"When it was late in the day, his disciples came to him and said, “This place is deserted, and it is late in the day."},{"v":36,"t":"Send them away, that they may go into the surrounding country and villages and buy themselves bread, for they have nothing to eat.”"},{"v":37,"t":"But he answered them, “You give them something to eat.” They asked him, “Shall we go and buy two hundred denarii worth of bread and give them something to eat?”"},{"v":38,"t":"He said to them, “How many loaves do you have? Go see.” When they knew, they said, “Five, and two fish.”"},{"v":39,"t":"He commanded them that everyone should sit down in groups on the green grass."},{"v":40,"t":"They sat down in ranks, by hundreds and by fifties."},{"v":41,"t":"He took the five loaves and the two fish; and looking up to heaven, he blessed and broke the loaves, and he gave to his disciples to set before them, and he divided the two fish among them all."},{"v":42,"t":"They all ate and were filled."},{"v":43,"t":"They took up twelve baskets full of broken pieces and also of the fish."},{"v":44,"t":"Those who ate the loaves were five thousand men."},{"v":45,"t":"Immediately he made his disciples get into the boat and go ahead to the other side, to Bethsaida, while he himself sent the multitude away."},{"v":46,"t":"After he had taken leave of them, he went up the mountain to pray."},{"v":47,"t":"When evening had come, the boat was in the middle of the sea, and he was alone on the land."},{"v":48,"t":"Seeing them distressed in rowing, for the wind was contrary to them, about the fourth watch of the night he came to them, walking on the sea; and he would have passed by them,"},{"v":49,"t":"but they, when they saw him walking on the sea, supposed that it was a ghost, and cried out;"},{"v":50,"t":"for they all saw him and were troubled. But he immediately spoke with them and said to them, “Cheer up! It is I! Don’t be afraid.”"},{"v":51,"t":"He got into the boat with them; and the wind ceased, and they were very amazed among themselves, and marveled;"},{"v":52,"t":"for they hadn’t understood about the loaves, but their hearts were hardened."},{"v":53,"t":"When they had crossed over, they came to land at Gennesaret and moored to the shore."},{"v":54,"t":"When they had come out of the boat, immediately the people recognized him,"},{"v":55,"t":"and ran around that whole region, and began to bring those who were sick on their mats to where they heard he was."},{"v":56,"t":"Wherever he entered—into villages, or into cities, or into the country—they laid the sick in the marketplaces and begged him that they might just touch the fringe of his garment; and as many as touched him were made well."}]},"7":{"en":[{"v":1,"t":"Then the Pharisees and some of the scribes gathered together to him, having come from Jerusalem."},{"v":2,"t":"Now when they saw some of his disciples eating bread with defiled, that is unwashed, hands, they found fault."},{"v":3,"t":"(For the Pharisees and all the Jews don’t eat unless they wash their hands and forearms, holding to the tradition of the elders."},{"v":4,"t":"They don’t eat when they come from the marketplace unless they bathe themselves, and there are many other things which they have received to hold to: washings of cups, pitchers, bronze vessels, and couches.)"},{"v":5,"t":"The Pharisees and the scribes asked him, “Why don’t your disciples walk according to the tradition of the elders, but eat their bread with unwashed hands?”"},{"v":6,"t":"He answered them, “Well did Isaiah prophesy of you hypocrites, as it is written, ‘This people honors me with their lips, but their heart is far from me."},{"v":7,"t":"They worship me in vain, teaching as doctrines the commandments of men.’"},{"v":8,"t":"“For you set aside the commandment of God, and hold tightly to the tradition of men—the washing of pitchers and cups, and you do many other such things.”"},{"v":9,"t":"He said to them, “Full well do you reject the commandment of God, that you may keep your tradition."},{"v":10,"t":"For Moses said, ‘Honor your father and your mother;’ and, ‘He who speaks evil of father or mother, let him be put to death.’"},{"v":11,"t":"But you say, ‘If a man tells his father or his mother, “Whatever profit you might have received from me is Corban,”’” that is to say, given to God,"},{"v":12,"t":"“then you no longer allow him to do anything for his father or his mother,"},{"v":13,"t":"making void the word of God by your tradition which you have handed down. You do many things like this.”"},{"v":14,"t":"He called all the multitude to himself and said to them, “Hear me, all of you, and understand."},{"v":15,"t":"There is nothing from outside of the man that going into him can defile him; but the things which proceed out of the man are those that defile the man."},{"v":16,"t":"If anyone has ears to hear, let him hear!”"},{"v":17,"t":"When he had entered into a house away from the multitude, his disciples asked him about the parable."},{"v":18,"t":"He said to them, “Are you also without understanding? Don’t you perceive that whatever goes into the man from outside can’t defile him,"},{"v":19,"t":"because it doesn’t go into his heart, but into his stomach, then into the latrine, making all foods clean?”"},{"v":20,"t":"He said, “That which proceeds out of the man, that defiles the man."},{"v":21,"t":"For from within, out of the hearts of men, proceed evil thoughts, adulteries, sexual sins, murders, thefts,"},{"v":22,"t":"covetings, wickedness, deceit, lustful desires, an evil eye, blasphemy, pride, and foolishness."},{"v":23,"t":"All these evil things come from within and defile the man.”"},{"v":24,"t":"From there he arose and went away into the borders of Tyre and Sidon. He entered into a house and didn’t want anyone to know it, but he couldn’t escape notice."},{"v":25,"t":"For a woman whose little daughter had an unclean spirit, having heard of him, came and fell down at his feet."},{"v":26,"t":"Now the woman was a Greek, a Syrophoenician by race. She begged him that he would cast the demon out of her daughter."},{"v":27,"t":"But Jesus said to her, “Let the children be filled first, for it is not appropriate to take the children’s bread and throw it to the dogs.”"},{"v":28,"t":"But she answered him, “Yes, Lord. Yet even the dogs under the table eat the children’s crumbs.”"},{"v":29,"t":"He said to her, “For this saying, go your way. The demon has gone out of your daughter.”"},{"v":30,"t":"She went away to her house, and found the child having been laid on the bed, with the demon gone out."},{"v":31,"t":"Again he departed from the borders of Tyre and Sidon, and came to the sea of Galilee through the middle of the region of Decapolis."},{"v":32,"t":"They brought to him one who was deaf and had an impediment in his speech. They begged him to lay his hand on him."},{"v":33,"t":"He took him aside from the multitude privately and put his fingers into his ears; and he spat and touched his tongue."},{"v":34,"t":"Looking up to heaven, he sighed, and said to him, “Ephphatha!” that is, “Be opened!”"},{"v":35,"t":"Immediately his ears were opened, and the impediment of his tongue was released, and he spoke clearly."},{"v":36,"t":"He commanded them that they should tell no one, but the more he commanded them, so much the more widely they proclaimed it."},{"v":37,"t":"They were astonished beyond measure, saying, “He has done all things well. He makes even the deaf hear and the mute speak!”"}]},"8":{"en":[{"v":1,"t":"In those days, when there was a very great multitude, and they had nothing to eat, Jesus called his disciples to himself and said to them,"},{"v":2,"t":"“I have compassion on the multitude, because they have stayed with me now three days and have nothing to eat."},{"v":3,"t":"If I send them away fasting to their home, they will faint on the way, for some of them have come a long way.”"},{"v":4,"t":"His disciples answered him, “From where could one satisfy these people with bread here in a deserted place?”"},{"v":5,"t":"He asked them, “How many loaves do you have?” They said, “Seven.”"},{"v":6,"t":"He commanded the multitude to sit down on the ground, and he took the seven loaves. Having given thanks, he broke them and gave them to his disciples to serve, and they served the multitude."},{"v":7,"t":"They also had a few small fish. Having blessed them, he said to serve these also."},{"v":8,"t":"They ate and were filled. They took up seven baskets of broken pieces that were left over."},{"v":9,"t":"Those who had eaten were about four thousand. Then he sent them away."},{"v":10,"t":"Immediately he entered into the boat with his disciples and came into the region of Dalmanutha."},{"v":11,"t":"The Pharisees came out and began to question him, seeking from him a sign from heaven and testing him."},{"v":12,"t":"He sighed deeply in his spirit and said, “Why does this generation seek a sign? Most certainly I tell you, no sign will be given to this generation.”"},{"v":13,"t":"He left them, and again entering into the boat, departed to the other side."},{"v":14,"t":"They forgot to take bread; and they didn’t have more than one loaf in the boat with them."},{"v":15,"t":"He warned them, saying, “Take heed: beware of the yeast of the Pharisees and the yeast of Herod.”"},{"v":16,"t":"They reasoned with one another, saying, “It’s because we have no bread.”"},{"v":17,"t":"Jesus, perceiving it, said to them, “Why do you reason that it’s because you have no bread? Don’t you perceive yet or understand? Is your heart still hardened?"},{"v":18,"t":"Having eyes, don’t you see? Having ears, don’t you hear? Don’t you remember?"},{"v":19,"t":"When I broke the five loaves among the five thousand, how many baskets full of broken pieces did you take up?” They told him, “Twelve.”"},{"v":20,"t":"“When the seven loaves fed the four thousand, how many baskets full of broken pieces did you take up?” They told him, “Seven.”"},{"v":21,"t":"He asked them, “Don’t you understand yet?”"},{"v":22,"t":"He came to Bethsaida. They brought a blind man to him and begged him to touch him."},{"v":23,"t":"He took hold of the blind man by the hand, and brought him out of the village. When he had spat on his eyes, and laid his hands on him, he asked him if he saw anything."},{"v":24,"t":"He looked up, and said, “I see men, but I see them like walking trees.”"},{"v":25,"t":"Then again he laid his hands on his eyes. He looked intently, and was restored, and saw everyone clearly."},{"v":26,"t":"He sent him away to his house, saying, “Don’t enter into the village, nor tell anyone in the village.”"},{"v":27,"t":"Jesus went out, with his disciples, into the villages of Caesarea Philippi. On the way he asked his disciples, “Who do men say that I am?”"},{"v":28,"t":"They told him, “John the Baptizer, and others say Elijah, but others, one of the prophets.”"},{"v":29,"t":"He said to them, “But who do you say that I am?” Peter answered, “You are the Christ.”"},{"v":30,"t":"He commanded them that they should tell no one about him."},{"v":31,"t":"He began to teach them that the Son of Man must suffer many things, and be rejected by the elders, the chief priests, and the scribes, and be killed, and after three days rise again."},{"v":32,"t":"He spoke to them openly. Peter took him and began to rebuke him."},{"v":33,"t":"But he, turning around and seeing his disciples, rebuked Peter, and said, “Get behind me, Satan! For you have in mind not the things of God, but the things of men.”"},{"v":34,"t":"He called the multitude to himself with his disciples and said to them, “Whoever wants to come after me, let him deny himself, and take up his cross, and follow me."},{"v":35,"t":"For whoever wants to save his life will lose it; and whoever will lose his life for my sake and the sake of the Good News will save it."},{"v":36,"t":"For what does it profit a man to gain the whole world and forfeit his life?"},{"v":37,"t":"For what will a man give in exchange for his life?"},{"v":38,"t":"For whoever will be ashamed of me and of my words in this adulterous and sinful generation, the Son of Man also will be ashamed of him when he comes in his Father’s glory with the holy angels.”"}]},"9":{"en":[{"v":1,"t":"He said to them, “Most certainly I tell you, there are some standing here who will in no way taste death until they see God’s Kingdom come with power.”"},{"v":2,"t":"After six days Jesus took with him Peter, James, and John, and brought them up onto a high mountain privately by themselves, and he was changed into another form in front of them."},{"v":3,"t":"His clothing became glistening, exceedingly white, like snow, such as no launderer on earth can whiten them."},{"v":4,"t":"Elijah and Moses appeared to them, and they were talking with Jesus."},{"v":5,"t":"Peter answered Jesus, “Rabbi, it is good for us to be here. Let’s make three tents: one for you, one for Moses, and one for Elijah.”"},{"v":6,"t":"For he didn’t know what to say, for they were very afraid."},{"v":7,"t":"A cloud came, overshadowing them, and a voice came out of the cloud, “This is my beloved Son. Listen to him.”"},{"v":8,"t":"Suddenly looking around, they saw no one with them any more, except Jesus only."},{"v":9,"t":"As they were coming down from the mountain, he commanded them that they should tell no one what things they had seen, until after the Son of Man had risen from the dead."},{"v":10,"t":"They kept this saying to themselves, questioning what the “rising from the dead” meant."},{"v":11,"t":"They asked him, saying, “Why do the scribes say that Elijah must come first?”"},{"v":12,"t":"He said to them, “Elijah indeed comes first, and restores all things. How is it written about the Son of Man, that he should suffer many things and be despised?"},{"v":13,"t":"But I tell you that Elijah has come, and they have also done to him whatever they wanted to, even as it is written about him.”"},{"v":14,"t":"Coming to the disciples, he saw a great multitude around them, and scribes questioning them."},{"v":15,"t":"Immediately all the multitude, when they saw him, were greatly amazed, and running to him, greeted him."},{"v":16,"t":"He asked the scribes, “What are you asking them?”"},{"v":17,"t":"One of the multitude answered, “Teacher, I brought to you my son, who has a mute spirit;"},{"v":18,"t":"and wherever it seizes him, it throws him down; and he foams at the mouth, grinds his teeth, and becomes rigid. I asked your disciples to cast it out, and they weren’t able.”"},{"v":19,"t":"He answered him, “Unbelieving generation, how long shall I be with you? How long shall I bear with you? Bring him to me.”"},{"v":20,"t":"They brought him to him, and when he saw him, immediately the spirit convulsed him and he fell on the ground, wallowing and foaming at the mouth."},{"v":21,"t":"He asked his father, “How long has it been since this has been happening to him?” He said, “From childhood."},{"v":22,"t":"Often it has cast him both into the fire and into the water to destroy him. But if you can do anything, have compassion on us and help us.”"},{"v":23,"t":"Jesus said to him, “If you can believe, all things are possible to him who believes.”"},{"v":24,"t":"Immediately the father of the child cried out with tears, “I believe. Help my unbelief!”"},{"v":25,"t":"When Jesus saw that a multitude came running together, he rebuked the unclean spirit, saying to him, “You mute and deaf spirit, I command you, come out of him, and never enter him again!”"},{"v":26,"t":"After crying out and convulsing him greatly, it came out of him. The boy became like one dead, so much that most of them said, “He is dead.”"},{"v":27,"t":"But Jesus took him by the hand and raised him up; and he arose."},{"v":28,"t":"When he had come into the house, his disciples asked him privately, “Why couldn’t we cast it out?”"},{"v":29,"t":"He said to them, “This kind can come out by nothing but by prayer and fasting.”"},{"v":30,"t":"They went out from there and passed through Galilee. He didn’t want anyone to know it,"},{"v":31,"t":"for he was teaching his disciples, and said to them, “The Son of Man is being handed over to the hands of men, and they will kill him; and when he is killed, on the third day he will rise again.”"},{"v":32,"t":"But they didn’t understand the saying, and were afraid to ask him."},{"v":33,"t":"He came to Capernaum, and when he was in the house he asked them, “What were you arguing among yourselves on the way?”"},{"v":34,"t":"But they were silent, for they had disputed with one another on the way about who was the greatest."},{"v":35,"t":"He sat down and called the twelve; and he said to them, “If any man wants to be first, he shall be last of all, and servant of all.”"},{"v":36,"t":"He took a little child and set him in the middle of them. Taking him in his arms, he said to them,"},{"v":37,"t":"“Whoever receives one such little child in my name receives me; and whoever receives me, doesn’t receive me, but him who sent me.”"},{"v":38,"t":"John said to him, “Teacher, we saw someone who doesn’t follow us casting out demons in your name; and we forbade him, because he doesn’t follow us.”"},{"v":39,"t":"But Jesus said, “Don’t forbid him, for there is no one who will do a mighty work in my name and be able quickly to speak evil of me."},{"v":40,"t":"For whoever is not against us is on our side."},{"v":41,"t":"For whoever will give you a cup of water to drink in my name because you are Christ’s, most certainly I tell you, he will in no way lose his reward."},{"v":42,"t":"“Whoever will cause one of these little ones who believe in me to stumble, it would be better for him if he were thrown into the sea with a millstone hung around his neck."},{"v":43,"t":"If your hand causes you to stumble, cut it off. It is better for you to enter into life maimed, rather than having your two hands to go into Gehenna, into the unquenchable fire,"},{"v":44,"t":"‘where their worm doesn’t die, and the fire is not quenched.’"},{"v":45,"t":"If your foot causes you to stumble, cut it off. It is better for you to enter into life lame, rather than having your two feet to be cast into Gehenna, into the fire that will never be quenched—"},{"v":46,"t":"‘where their worm doesn’t die, and the fire is not quenched.’"},{"v":47,"t":"If your eye causes you to stumble, throw it out. It is better for you to enter into God’s Kingdom with one eye, rather than having two eyes to be cast into the Gehenna of fire,"},{"v":48,"t":"‘where their worm doesn’t die, and the fire is not quenched.’"},{"v":49,"t":"For everyone will be salted with fire, and every sacrifice will be seasoned with salt."},{"v":50,"t":"Salt is good, but if the salt has lost its saltiness, with what will you season it? Have salt in yourselves, and be at peace with one another.”"}]},"10":{"en":[{"v":1,"t":"He arose from there and came into the borders of Judea and beyond the Jordan. Multitudes came together to him again. As he usually did, he was again teaching them."},{"v":2,"t":"Pharisees came to him testing him, and asked him, “Is it lawful for a man to divorce his wife?”"},{"v":3,"t":"He answered, “What did Moses command you?”"},{"v":4,"t":"They said, “Moses allowed a certificate of divorce to be written, and to divorce her.”"},{"v":5,"t":"But Jesus said to them, “For your hardness of heart, he wrote you this commandment."},{"v":6,"t":"But from the beginning of the creation, God made them male and female."},{"v":7,"t":"For this cause a man will leave his father and mother, and will join to his wife,"},{"v":8,"t":"and the two will become one flesh, so that they are no longer two, but one flesh."},{"v":9,"t":"What therefore God has joined together, let no man separate.”"},{"v":10,"t":"In the house, his disciples asked him again about the same matter."},{"v":11,"t":"He said to them, “Whoever divorces his wife and marries another commits adultery against her."},{"v":12,"t":"If a woman herself divorces her husband and marries another, she commits adultery.”"},{"v":13,"t":"They were bringing to him little children, that he should touch them, but the disciples rebuked those who were bringing them."},{"v":14,"t":"But when Jesus saw it, he was moved with indignation and said to them, “Allow the little children to come to me! Don’t forbid them, for God’s Kingdom belongs to such as these."},{"v":15,"t":"Most certainly I tell you, whoever will not receive God’s Kingdom like a little child, he will in no way enter into it.”"},{"v":16,"t":"He took them in his arms and blessed them, laying his hands on them."},{"v":17,"t":"As he was going out into the way, one ran to him, knelt before him, and asked him, “Good Teacher, what shall I do that I may inherit eternal life?”"},{"v":18,"t":"Jesus said to him, “Why do you call me good? No one is good except one—God."},{"v":19,"t":"You know the commandments: ‘Do not murder,’ ‘Do not commit adultery,’ ‘Do not steal,’ ‘Do not give false testimony,’ ‘Do not defraud,’ ‘Honor your father and mother.’”"},{"v":20,"t":"He said to him, “Teacher, I have observed all these things from my youth.”"},{"v":21,"t":"Jesus looking at him loved him, and said to him, “One thing you lack. Go, sell whatever you have and give to the poor, and you will have treasure in heaven; and come, follow me, taking up the cross.”"},{"v":22,"t":"But his face fell at that saying, and he went away sorrowful, for he was one who had great possessions."},{"v":23,"t":"Jesus looked around and said to his disciples, “How difficult it is for those who have riches to enter into God’s Kingdom!”"},{"v":24,"t":"The disciples were amazed at his words. But Jesus answered again, “Children, how hard it is for those who trust in riches to enter into God’s Kingdom!"},{"v":25,"t":"It is easier for a camel to go through a needle’s eye than for a rich man to enter into God’s Kingdom.”"},{"v":26,"t":"They were exceedingly astonished, saying to him, “Then who can be saved?”"},{"v":27,"t":"Jesus, looking at them, said, “With men it is impossible, but not with God, for all things are possible with God.”"},{"v":28,"t":"Peter began to tell him, “Behold, we have left all and have followed you.”"},{"v":29,"t":"Jesus said, “Most certainly I tell you, there is no one who has left house, or brothers, or sisters, or father, or mother, or wife, or children, or land, for my sake, and for the sake of the Good News,"},{"v":30,"t":"but he will receive one hundred times more now in this time: houses, brothers, sisters, mothers, children, and land, with persecutions; and in the age to come eternal life."},{"v":31,"t":"But many who are first will be last, and the last first.”"},{"v":32,"t":"They were on the way, going up to Jerusalem; and Jesus was going in front of them, and they were amazed; and those who followed were afraid. He again took the twelve, and began to tell them the things that were going to happen to him."},{"v":33,"t":"“Behold, we are going up to Jerusalem. The Son of Man will be delivered to the chief priests and the scribes. They will condemn him to death, and will deliver him to the Gentiles."},{"v":34,"t":"They will mock him, spit on him, scourge him, and kill him. On the third day he will rise again.”"},{"v":35,"t":"James and John, the sons of Zebedee, came near to him, saying, “Teacher, we want you to do for us whatever we will ask.”"},{"v":36,"t":"He said to them, “What do you want me to do for you?”"},{"v":37,"t":"They said to him, “Grant to us that we may sit, one at your right hand and one at your left hand, in your glory.”"},{"v":38,"t":"But Jesus said to them, “You don’t know what you are asking. Are you able to drink the cup that I drink, and to be baptized with the baptism that I am baptized with?”"},{"v":39,"t":"They said to him, “We are able.” Jesus said to them, “You shall indeed drink the cup that I drink, and you shall be baptized with the baptism that I am baptized with;"},{"v":40,"t":"but to sit at my right hand and at my left hand is not mine to give, but for whom it has been prepared.”"},{"v":41,"t":"When the ten heard it, they began to be indignant toward James and John."},{"v":42,"t":"Jesus summoned them and said to them, “You know that they who are recognized as rulers over the nations lord it over them, and their great ones exercise authority over them."},{"v":43,"t":"But it shall not be so among you, but whoever wants to become great among you shall be your servant."},{"v":44,"t":"Whoever of you wants to become first among you shall be bondservant of all."},{"v":45,"t":"For the Son of Man also came not to be served but to serve, and to give his life as a ransom for many.”"},{"v":46,"t":"They came to Jericho. As he went out from Jericho with his disciples and a great multitude, the son of Timaeus, Bartimaeus, a blind beggar, was sitting by the road."},{"v":47,"t":"When he heard that it was Jesus the Nazarene, he began to cry out and say, “Jesus, you son of David, have mercy on me!”"},{"v":48,"t":"Many rebuked him, that he should be quiet, but he cried out much more, “You son of David, have mercy on me!”"},{"v":49,"t":"Jesus stood still and said, “Call him.” They called the blind man, saying to him, “Cheer up! Get up. He is calling you!”"},{"v":50,"t":"He, casting away his cloak, sprang up, and came to Jesus."},{"v":51,"t":"Jesus asked him, “What do you want me to do for you?” The blind man said to him, “Rabboni, that I may see again.”"},{"v":52,"t":"Jesus said to him, “Go your way. Your faith has made you well.” Immediately he received his sight and followed Jesus on the way."}]},"11":{"en":[{"v":1,"t":"When they came near to Jerusalem, to Bethsphage and Bethany, at the Mount of Olives, he sent two of his disciples"},{"v":2,"t":"and said to them, “Go your way into the village that is opposite you. Immediately as you enter into it, you will find a young donkey tied, on which no one has sat. Untie him and bring him."},{"v":3,"t":"If anyone asks you, ‘Why are you doing this?’ say, ‘The Lord needs him;’ and immediately he will send him back here.”"},{"v":4,"t":"They went away, and found a young donkey tied at the door outside in the open street, and they untied him."},{"v":5,"t":"Some of those who stood there asked them, “What are you doing, untying the young donkey?”"},{"v":6,"t":"They said to them just as Jesus had said, and they let them go."},{"v":7,"t":"They brought the young donkey to Jesus and threw their garments on it, and Jesus sat on it."},{"v":8,"t":"Many spread their garments on the way, and others were cutting down branches from the trees and spreading them on the road."},{"v":9,"t":"Those who went in front and those who followed cried out, “Hosanna! Blessed is he who comes in the name of the Lord!"},{"v":10,"t":"Blessed is the kingdom of our father David that is coming in the name of the Lord! Hosanna in the highest!”"},{"v":11,"t":"Jesus entered into the temple in Jerusalem. When he had looked around at everything, it being now evening, he went out to Bethany with the twelve."},{"v":12,"t":"The next day, when they had come out from Bethany, he was hungry."},{"v":13,"t":"Seeing a fig tree afar off having leaves, he came to see if perhaps he might find anything on it. When he came to it, he found nothing but leaves, for it was not the season for figs."},{"v":14,"t":"Jesus told it, “May no one ever eat fruit from you again!” and his disciples heard it."},{"v":15,"t":"They came to Jerusalem, and Jesus entered into the temple and began to throw out those who sold and those who bought in the temple, and overthrew the money changers’ tables and the seats of those who sold the doves."},{"v":16,"t":"He would not allow anyone to carry a container through the temple."},{"v":17,"t":"He taught, saying to them, “Isn’t it written, ‘My house will be called a house of prayer for all the nations’? But you have made it a den of robbers!”"},{"v":18,"t":"The chief priests and the scribes heard it, and sought how they might destroy him. For they feared him, because all the multitude was astonished at his teaching."},{"v":19,"t":"When evening came, he went out of the city."},{"v":20,"t":"As they passed by in the morning, they saw the fig tree withered away from the roots."},{"v":21,"t":"Peter, remembering, said to him, “Rabbi, look! The fig tree which you cursed has withered away.”"},{"v":22,"t":"Jesus answered them, “Have faith in God."},{"v":23,"t":"For most certainly I tell you, whoever may tell this mountain, ‘Be taken up and cast into the sea,’ and doesn’t doubt in his heart, but believes that what he says is happening, he shall have whatever he says."},{"v":24,"t":"Therefore I tell you, all things whatever you pray and ask for, believe that you have received them, and you shall have them."},{"v":25,"t":"Whenever you stand praying, forgive, if you have anything against anyone; so that your Father, who is in heaven, may also forgive you your transgressions."},{"v":26,"t":"But if you do not forgive, neither will your Father in heaven forgive your transgressions.”"},{"v":27,"t":"They came again to Jerusalem, and as he was walking in the temple, the chief priests, the scribes, and the elders came to him,"},{"v":28,"t":"and they began saying to him, “By what authority do you do these things? Or who gave you this authority to do these things?”"},{"v":29,"t":"Jesus said to them, “I will ask you one question. Answer me, and I will tell you by what authority I do these things."},{"v":30,"t":"The baptism of John—was it from heaven, or from men? Answer me.”"},{"v":31,"t":"They reasoned with themselves, saying, “If we should say, ‘From heaven;’ he will say, ‘Why then did you not believe him?’"},{"v":32,"t":"If we should say, ‘From men’”—they feared the people, for all held John to really be a prophet."},{"v":33,"t":"They answered Jesus, “We don’t know.” Jesus said to them, “Neither will I tell you by what authority I do these things.”"}]},"12":{"en":[{"v":1,"t":"He began to speak to them in parables. “A man planted a vineyard, put a hedge around it, dug a pit for the wine press, built a tower, rented it out to a farmer, and went into another country."},{"v":2,"t":"When it was time, he sent a servant to the farmer to get from the farmer his share of the fruit of the vineyard."},{"v":3,"t":"They took him, beat him, and sent him away empty."},{"v":4,"t":"Again, he sent another servant to them; and they threw stones at him, wounded him in the head, and sent him away shamefully treated."},{"v":5,"t":"Again he sent another, and they killed him, and many others, beating some, and killing some."},{"v":6,"t":"Therefore still having one, his beloved son, he sent him last to them, saying, ‘They will respect my son.’"},{"v":7,"t":"But those farmers said among themselves, ‘This is the heir. Come, let’s kill him, and the inheritance will be ours.’"},{"v":8,"t":"They took him, killed him, and cast him out of the vineyard."},{"v":9,"t":"What therefore will the lord of the vineyard do? He will come and destroy the farmers, and will give the vineyard to others."},{"v":10,"t":"Haven’t you even read this Scripture: ‘The stone which the builders rejected was made the head of the corner."},{"v":11,"t":"This was from the Lord. It is marvelous in our eyes’?”"},{"v":12,"t":"They tried to seize him, but they feared the multitude; for they perceived that he spoke the parable against them. They left him and went away."},{"v":13,"t":"They sent some of the Pharisees and the Herodians to him, that they might trap him with words."},{"v":14,"t":"When they had come, they asked him, “Teacher, we know that you are honest, and don’t defer to anyone; for you aren’t partial to anyone, but truly teach the way of God. Is it lawful to pay taxes to Caesar, or not?"},{"v":15,"t":"Shall we give, or shall we not give?” But he, knowing their hypocrisy, said to them, “Why do you test me? Bring me a denarius, that I may see it.”"},{"v":16,"t":"They brought it. He said to them, “Whose is this image and inscription?” They said to him, “Caesar’s.”"},{"v":17,"t":"Jesus answered them, “Render to Caesar the things that are Caesar’s, and to God the things that are God’s.” They marveled greatly at him."},{"v":18,"t":"Some Sadducees, who say that there is no resurrection, came to him. They asked him, saying,"},{"v":19,"t":"“Teacher, Moses wrote to us, ‘If a man’s brother dies and leaves a wife behind him, and leaves no children, that his brother should take his wife and raise up offspring for his brother.’"},{"v":20,"t":"There were seven brothers. The first took a wife, and dying left no offspring."},{"v":21,"t":"The second took her, and died, leaving no children behind him. The third likewise;"},{"v":22,"t":"and the seven took her and left no children. Last of all the woman also died."},{"v":23,"t":"In the resurrection, when they rise, whose wife will she be of them? For the seven had her as a wife.”"},{"v":24,"t":"Jesus answered them, “Isn’t this because you are mistaken, not knowing the Scriptures nor the power of God?"},{"v":25,"t":"For when they will rise from the dead, they neither marry nor are given in marriage, but are like angels in heaven."},{"v":26,"t":"But about the dead, that they are raised, haven’t you read in the book of Moses about the Bush, how God spoke to him, saying, ‘I am the God of Abraham, the God of Isaac, and the God of Jacob’?"},{"v":27,"t":"He is not the God of the dead, but of the living. You are therefore badly mistaken.”"},{"v":28,"t":"One of the scribes came and heard them questioning together, and knowing that he had answered them well, asked him, “Which commandment is the greatest of all?”"},{"v":29,"t":"Jesus answered, “The greatest is: ‘Hear, Israel, the Lord our God, the Lord is one."},{"v":30,"t":"You shall love the Lord your God with all your heart, with all your soul, with all your mind, and with all your strength.’ This is the first commandment."},{"v":31,"t":"The second is like this: ‘You shall love your neighbor as yourself.’ There is no other commandment greater than these.”"},{"v":32,"t":"The scribe said to him, “Truly, teacher, you have said well that he is one, and there is none other but he;"},{"v":33,"t":"and to love him with all the heart, with all the understanding, all the soul, and with all the strength, and to love his neighbor as himself, is more important than all whole burnt offerings and sacrifices.”"},{"v":34,"t":"When Jesus saw that he answered wisely, he said to him, “You are not far from God’s Kingdom.” No one dared ask him any question after that."},{"v":35,"t":"Jesus responded, as he taught in the temple, “How is it that the scribes say that the Christ is the son of David?"},{"v":36,"t":"For David himself said in the Holy Spirit, ‘The Lord said to my Lord, “Sit at my right hand, until I make your enemies the footstool of your feet.”’"},{"v":37,"t":"Therefore David himself calls him Lord, so how can he be his son?” The common people heard him gladly."},{"v":38,"t":"In his teaching he said to them, “Beware of the scribes, who like to walk in long robes, and to get greetings in the marketplaces,"},{"v":39,"t":"and to get the best seats in the synagogues and the best places at feasts,"},{"v":40,"t":"those who devour widows’ houses, and for a pretense make long prayers. These will receive greater condemnation.”"},{"v":41,"t":"Jesus sat down opposite the treasury and saw how the multitude cast money into the treasury. Many who were rich cast in much."},{"v":42,"t":"A poor widow came and she cast in two small brass coins, which equal a quadrans coin."},{"v":43,"t":"He called his disciples to himself and said to them, “Most certainly I tell you, this poor widow gave more than all those who are giving into the treasury,"},{"v":44,"t":"for they all gave out of their abundance, but she, out of her poverty, gave all that she had to live on.”"}]},"13":{"en":[{"v":1,"t":"As he went out of the temple, one of his disciples said to him, “Teacher, see what kind of stones and what kind of buildings!”"},{"v":2,"t":"Jesus said to him, “Do you see these great buildings? There will not be left here one stone on another, which will not be thrown down.”"},{"v":3,"t":"As he sat on the Mount of Olives opposite the temple, Peter, James, John, and Andrew asked him privately,"},{"v":4,"t":"“Tell us, when will these things be? What is the sign that these things are all about to be fulfilled?”"},{"v":5,"t":"Jesus, answering, began to tell them, “Be careful that no one leads you astray."},{"v":6,"t":"For many will come in my name, saying, ‘I am he!’ and will lead many astray."},{"v":7,"t":"“When you hear of wars and rumors of wars, don’t be troubled. For those must happen, but the end is not yet."},{"v":8,"t":"For nation will rise against nation, and kingdom against kingdom. There will be earthquakes in various places. There will be famines and troubles. These things are the beginning of birth pains."},{"v":9,"t":"“But watch yourselves, for they will deliver you up to councils. You will be beaten in synagogues. You will stand before rulers and kings for my sake, for a testimony to them."},{"v":10,"t":"The Good News must first be preached to all the nations."},{"v":11,"t":"When they lead you away and deliver you up, don’t be anxious beforehand or premeditate what you will say, but say whatever will be given you in that hour. For it is not you who speak, but the Holy Spirit."},{"v":12,"t":"“Brother will deliver up brother to death, and the father his child. Children will rise up against parents and cause them to be put to death."},{"v":13,"t":"You will be hated by all men for my name’s sake, but he who endures to the end will be saved."},{"v":14,"t":"“But when you see the abomination of desolation, spoken of by Daniel the prophet, standing where it ought not” (let the reader understand), “then let those who are in Judea flee to the mountains,"},{"v":15,"t":"and let him who is on the housetop not go down, nor enter in, to take anything out of his house."},{"v":16,"t":"Let him who is in the field not return back to take his cloak."},{"v":17,"t":"But woe to those who are with child and to those who nurse babies in those days!"},{"v":18,"t":"Pray that your flight won’t be in the winter."},{"v":19,"t":"For in those days there will be oppression, such as there has not been the like from the beginning of the creation which God created until now, and never will be."},{"v":20,"t":"Unless the Lord had shortened the days, no flesh would have been saved; but for the sake of the chosen ones, whom he picked out, he shortened the days."},{"v":21,"t":"Then if anyone tells you, ‘Look, here is the Christ!’ or, ‘Look, there!’ don’t believe it."},{"v":22,"t":"For false christs and false prophets will arise and will show signs and wonders, that they may lead astray, if possible, even the chosen ones."},{"v":23,"t":"But you watch. “Behold, I have told you all things beforehand."},{"v":24,"t":"But in those days, after that oppression, the sun will be darkened, the moon will not give its light,"},{"v":25,"t":"the stars will be falling from the sky, and the powers that are in the heavens will be shaken."},{"v":26,"t":"Then they will see the Son of Man coming in clouds with great power and glory."},{"v":27,"t":"Then he will send out his angels, and will gather together his chosen ones from the four winds, from the ends of the earth to the ends of the sky."},{"v":28,"t":"“Now from the fig tree, learn this parable. When the branch has now become tender and produces its leaves, you know that the summer is near;"},{"v":29,"t":"even so you also, when you see these things coming to pass, know that it is near, at the doors."},{"v":30,"t":"Most certainly I say to you, this generation will not pass away until all these things happen."},{"v":31,"t":"Heaven and earth will pass away, but my words will not pass away."},{"v":32,"t":"“But of that day or that hour no one knows—not even the angels in heaven, nor the Son, but only the Father."},{"v":33,"t":"Watch, keep alert, and pray; for you don’t know when the time is."},{"v":34,"t":"“It is like a man traveling to another country, having left his house and given authority to his servants, and to each one his work, and also commanded the doorkeeper to keep watch."},{"v":35,"t":"Watch therefore, for you don’t know when the lord of the house is coming—whether at evening, or at midnight, or when the rooster crows, or in the morning;"},{"v":36,"t":"lest, coming suddenly, he might find you sleeping."},{"v":37,"t":"What I tell you, I tell all: Watch!”"}]},"14":{"en":[{"v":1,"t":"It was now two days before the Passover and the Feast of Unleavened Bread, and the chief priests and the scribes sought how they might seize him by deception and kill him."},{"v":2,"t":"For they said, “Not during the feast, because there might be a riot among the people.”"},{"v":3,"t":"While he was at Bethany, in the house of Simon the leper, as he sat at the table, a woman came having an alabaster jar of ointment of pure nard—very costly. She broke the jar and poured it over his head."},{"v":4,"t":"But there were some who were indignant among themselves, saying, “Why has this ointment been wasted?"},{"v":5,"t":"For this might have been sold for more than three hundred denarii and given to the poor.” So they grumbled against her."},{"v":6,"t":"But Jesus said, “Leave her alone. Why do you trouble her? She has done a good work for me."},{"v":7,"t":"For you always have the poor with you, and whenever you want to, you can do them good; but you will not always have me."},{"v":8,"t":"She has done what she could. She has anointed my body beforehand for the burying."},{"v":9,"t":"Most certainly I tell you, wherever this Good News may be preached throughout the whole world, that which this woman has done will also be spoken of for a memorial of her.”"},{"v":10,"t":"Judas Iscariot, who was one of the twelve, went away to the chief priests, that he might deliver him to them."},{"v":11,"t":"They, when they heard it, were glad, and promised to give him money. He sought how he might conveniently deliver him."},{"v":12,"t":"On the first day of unleavened bread, when they sacrificed the Passover, his disciples asked him, “Where do you want us to go and prepare that you may eat the Passover?”"},{"v":13,"t":"He sent two of his disciples and said to them, “Go into the city, and there a man carrying a pitcher of water will meet you. Follow him,"},{"v":14,"t":"and wherever he enters in, tell the master of the house, ‘The Teacher says, “Where is the guest room, where I may eat the Passover with my disciples?”’"},{"v":15,"t":"He will himself show you a large upper room furnished and ready. Get ready for us there.”"},{"v":16,"t":"His disciples went out, and came into the city, and found things as he had said to them, and they prepared the Passover."},{"v":17,"t":"When it was evening he came with the twelve."},{"v":18,"t":"As they sat and were eating, Jesus said, “Most certainly I tell you, one of you will betray me—he who eats with me.”"},{"v":19,"t":"They began to be sorrowful, and to ask him one by one, “Surely not I?” And another said, “Surely not I?”"},{"v":20,"t":"He answered them, “It is one of the twelve, he who dips with me in the dish."},{"v":21,"t":"For the Son of Man goes as it is written about him, but woe to that man by whom the Son of Man is betrayed! It would be better for that man if he had not been born.”"},{"v":22,"t":"As they were eating, Jesus took bread, and when he had blessed it, he broke it and gave to them, and said, “Take, eat. This is my body.”"},{"v":23,"t":"He took the cup, and when he had given thanks, he gave to them. They all drank of it."},{"v":24,"t":"He said to them, “This is my blood of the new covenant, which is poured out for many."},{"v":25,"t":"Most certainly I tell you, I will no more drink of the fruit of the vine until that day when I drink it anew in God’s Kingdom.”"},{"v":26,"t":"When they had sung a hymn, they went out to the Mount of Olives."},{"v":27,"t":"Jesus said to them, “All of you will be made to stumble because of me tonight, for it is written, ‘I will strike the shepherd, and the sheep will be scattered.’"},{"v":28,"t":"However, after I am raised up, I will go before you into Galilee.”"},{"v":29,"t":"But Peter said to him, “Although all will be offended, yet I will not.”"},{"v":30,"t":"Jesus said to him, “Most certainly I tell you that you today, even this night, before the rooster crows twice, you will deny me three times.”"},{"v":31,"t":"But he spoke all the more, “If I must die with you, I will not deny you.” They all said the same thing."},{"v":32,"t":"They came to a place which was named Gethsemane. He said to his disciples, “Sit here while I pray.”"},{"v":33,"t":"He took with him Peter, James, and John, and began to be greatly troubled and distressed."},{"v":34,"t":"He said to them, “My soul is exceedingly sorrowful, even to death. Stay here and watch.”"},{"v":35,"t":"He went forward a little, and fell on the ground, and prayed that if it were possible, the hour might pass away from him."},{"v":36,"t":"He said, “Abba, Father, all things are possible to you. Please remove this cup from me. However, not what I desire, but what you desire.”"},{"v":37,"t":"He came and found them sleeping, and said to Peter, “Simon, are you sleeping? Couldn’t you watch one hour?"},{"v":38,"t":"Watch and pray, that you may not enter into temptation. The spirit indeed is willing, but the flesh is weak.”"},{"v":39,"t":"Again he went away and prayed, saying the same words."},{"v":40,"t":"Again he returned and found them sleeping, for their eyes were very heavy; and they didn’t know what to answer him."},{"v":41,"t":"He came the third time and said to them, “Sleep on now, and take your rest. It is enough. The hour has come. Behold, the Son of Man is betrayed into the hands of sinners."},{"v":42,"t":"Arise! Let’s get going. Behold, he who betrays me is at hand.”"},{"v":43,"t":"Immediately, while he was still speaking, Judas, one of the twelve, came—and with him a multitude with swords and clubs, from the chief priests, the scribes, and the elders."},{"v":44,"t":"Now he who betrayed him had given them a sign, saying, “Whomever I will kiss, that is he. Seize him, and lead him away safely.”"},{"v":45,"t":"When he had come, immediately he came to him and said, “Rabbi! Rabbi!” and kissed him."},{"v":46,"t":"They laid their hands on him and seized him."},{"v":47,"t":"But a certain one of those who stood by drew his sword and struck the servant of the high priest, and cut off his ear."},{"v":48,"t":"Jesus answered them, “Have you come out, as against a robber, with swords and clubs to seize me?"},{"v":49,"t":"I was daily with you in the temple teaching, and you didn’t arrest me. But this is so that the Scriptures might be fulfilled.”"},{"v":50,"t":"They all left him, and fled."},{"v":51,"t":"A certain young man followed him, having a linen cloth thrown around himself over his naked body. The young men grabbed him,"},{"v":52,"t":"but he left the linen cloth and fled from them naked."},{"v":53,"t":"They led Jesus away to the high priest. All the chief priests, the elders, and the scribes came together with him."},{"v":54,"t":"Peter had followed him from a distance, until he came into the court of the high priest. He was sitting with the officers, and warming himself in the light of the fire."},{"v":55,"t":"Now the chief priests and the whole council sought witnesses against Jesus to put him to death, and found none."},{"v":56,"t":"For many gave false testimony against him, and their testimony didn’t agree with each other."},{"v":57,"t":"Some stood up and gave false testimony against him, saying,"},{"v":58,"t":"“We heard him say, ‘I will destroy this temple that is made with hands, and in three days I will build another made without hands.’”"},{"v":59,"t":"Even so, their testimony didn’t agree."},{"v":60,"t":"The high priest stood up in the middle, and asked Jesus, “Have you no answer? What is it which these testify against you?”"},{"v":61,"t":"But he stayed quiet, and answered nothing. Again the high priest asked him, “Are you the Christ, the Son of the Blessed?”"},{"v":62,"t":"Jesus said, “I am. You will see the Son of Man sitting at the right hand of Power, and coming with the clouds of the sky.”"},{"v":63,"t":"The high priest tore his clothes and said, “What further need have we of witnesses?"},{"v":64,"t":"You have heard the blasphemy! What do you think?” They all condemned him to be worthy of death."},{"v":65,"t":"Some began to spit on him, and to cover his face, and to beat him with fists, and to tell him, “Prophesy!” The officers struck him with the palms of their hands."},{"v":66,"t":"As Peter was in the courtyard below, one of the maids of the high priest came,"},{"v":67,"t":"and seeing Peter warming himself, she looked at him and said, “You were also with the Nazarene, Jesus!”"},{"v":68,"t":"But he denied it, saying, “I neither know nor understand what you are saying.” He went out on the porch, and the rooster crowed."},{"v":69,"t":"The maid saw him and began again to tell those who stood by, “This is one of them.”"},{"v":70,"t":"But he again denied it. After a little while again those who stood by said to Peter, “You truly are one of them, for you are a Galilean, and your speech shows it.”"},{"v":71,"t":"But he began to curse and to swear, “I don’t know this man of whom you speak!”"},{"v":72,"t":"The rooster crowed the second time. Peter remembered the words that Jesus said to him, “Before the rooster crows twice, you will deny me three times.” When he thought about that, he wept."}]},"15":{"en":[{"v":1,"t":"Immediately in the morning the chief priests, with the elders, scribes, and the whole council, held a consultation, bound Jesus, carried him away, and delivered him up to Pilate."},{"v":2,"t":"Pilate asked him, “Are you the King of the Jews?” He answered, “So you say.”"},{"v":3,"t":"The chief priests accused him of many things."},{"v":4,"t":"Pilate again asked him, “Have you no answer? See how many things they testify against you!”"},{"v":5,"t":"But Jesus made no further answer, so that Pilate marveled."},{"v":6,"t":"Now at the feast he used to release to them one prisoner, whomever they asked of him."},{"v":7,"t":"There was one called Barabbas, bound with his fellow insurgents, men who in the insurrection had committed murder."},{"v":8,"t":"The multitude, crying aloud, began to ask him to do as he always did for them."},{"v":9,"t":"Pilate answered them, saying, “Do you want me to release to you the King of the Jews?”"},{"v":10,"t":"For he perceived that for envy the chief priests had delivered him up."},{"v":11,"t":"But the chief priests stirred up the multitude, that he should release Barabbas to them instead."},{"v":12,"t":"Pilate again asked them, “What then should I do to him whom you call the King of the Jews?”"},{"v":13,"t":"They cried out again, “Crucify him!”"},{"v":14,"t":"Pilate said to them, “Why, what evil has he done?” But they cried out exceedingly, “Crucify him!”"},{"v":15,"t":"Pilate, wishing to please the multitude, released Barabbas to them, and handed over Jesus, when he had flogged him, to be crucified."},{"v":16,"t":"The soldiers led him away within the court, which is the Praetorium; and they called together the whole cohort."},{"v":17,"t":"They clothed him with purple; and weaving a crown of thorns, they put it on him."},{"v":18,"t":"They began to salute him, “Hail, King of the Jews!”"},{"v":19,"t":"They struck his head with a reed and spat on him, and bowing their knees, did homage to him."},{"v":20,"t":"When they had mocked him, they took the purple cloak off him, and put his own garments on him. They led him out to crucify him."},{"v":21,"t":"They compelled one passing by, coming from the country, Simon of Cyrene, the father of Alexander and Rufus, to go with them that he might bear his cross."},{"v":22,"t":"They brought him to the place called Golgotha, which is, being interpreted, “The place of a skull.”"},{"v":23,"t":"They offered him wine mixed with myrrh to drink, but he didn’t take it."},{"v":24,"t":"Crucifying him, they parted his garments among them, casting lots on them, what each should take."},{"v":25,"t":"It was the third hour when they crucified him."},{"v":26,"t":"The superscription of his accusation was written over him: “THE KING OF THE JEWS.”"},{"v":27,"t":"With him they crucified two robbers, one on his right hand, and one on his left."},{"v":28,"t":"The Scripture was fulfilled which says, “He was counted with transgressors.”"},{"v":29,"t":"Those who passed by blasphemed him, wagging their heads and saying, “Ha! You who destroy the temple and build it in three days,"},{"v":30,"t":"save yourself, and come down from the cross!”"},{"v":31,"t":"Likewise, also the chief priests mocking among themselves with the scribes said, “He saved others. He can’t save himself."},{"v":32,"t":"Let the Christ, the King of Israel, now come down from the cross, that we may see and believe him.” Those who were crucified with him also insulted him."},{"v":33,"t":"When the sixth hour had come, there was darkness over the whole land until the ninth hour."},{"v":34,"t":"At the ninth hour Jesus cried with a loud voice, saying, “Eloi, Eloi, lama sabachthani?” which is, being interpreted, “My God, my God, why have you forsaken me?”"},{"v":35,"t":"Some of those who stood by, when they heard it, said, “Behold, he is calling Elijah.”"},{"v":36,"t":"One ran, and filling a sponge full of vinegar, put it on a reed and gave it to him to drink, saying, “Let him be. Let’s see whether Elijah comes to take him down.”"},{"v":37,"t":"Jesus cried out with a loud voice, and gave up the spirit."},{"v":38,"t":"The veil of the temple was torn in two from the top to the bottom."},{"v":39,"t":"When the centurion, who stood by opposite him, saw that he cried out like this and breathed his last, he said, “Truly this man was the Son of God!”"},{"v":40,"t":"There were also women watching from afar, among whom were both Mary Magdalene and Mary the mother of James the less and of Joses, and Salome;"},{"v":41,"t":"who, when he was in Galilee, followed him and served him; and many other women who came up with him to Jerusalem."},{"v":42,"t":"When evening had now come, because it was the Preparation Day, that is, the day before the Sabbath,"},{"v":43,"t":"Joseph of Arimathaea, a prominent council member who also himself was looking for God’s Kingdom, came. He boldly went in to Pilate, and asked for Jesus’ body."},{"v":44,"t":"Pilate was surprised to hear that he was already dead; and summoning the centurion, he asked him whether he had been dead long."},{"v":45,"t":"When he found out from the centurion, he granted the body to Joseph."},{"v":46,"t":"He bought a linen cloth, and taking him down, wound him in the linen cloth and laid him in a tomb which had been cut out of a rock. He rolled a stone against the door of the tomb."},{"v":47,"t":"Mary Magdalene and Mary the mother of Joses, saw where he was laid."}]},"16":{"en":[{"v":1,"t":"When the Sabbath was past, Mary Magdalene, and Mary the mother of James, and Salome bought spices, that they might come and anoint him."},{"v":2,"t":"Very early on the first day of the week, they came to the tomb when the sun had risen."},{"v":3,"t":"They were saying among themselves, “Who will roll away the stone from the door of the tomb for us?”"},{"v":4,"t":"for it was very big. Looking up, they saw that the stone was rolled back."},{"v":5,"t":"Entering into the tomb, they saw a young man sitting on the right side, dressed in a white robe; and they were amazed."},{"v":6,"t":"He said to them, “Don’t be amazed. You seek Jesus, the Nazarene, who has been crucified. He has risen! He is not here. See the place where they laid him!"},{"v":7,"t":"But go, tell his disciples and Peter, ‘He goes before you into Galilee. There you will see him, as he said to you.’”"},{"v":8,"t":"They went out, and fled from the tomb, for trembling and astonishment had come on them. They said nothing to anyone; for they were afraid."},{"v":9,"t":"Now when he had risen early on the first day of the week, he appeared first to Mary Magdalene, from whom he had cast out seven demons."},{"v":10,"t":"She went and told those who had been with him, as they mourned and wept."},{"v":11,"t":"When they heard that he was alive and had been seen by her, they disbelieved."},{"v":12,"t":"After these things he was revealed in another form to two of them as they walked, on their way into the country."},{"v":13,"t":"They went away and told it to the rest. They didn’t believe them, either."},{"v":14,"t":"Afterward he was revealed to the eleven themselves as they sat at the table; and he rebuked them for their unbelief and hardness of heart, because they didn’t believe those who had seen him after he had risen."},{"v":15,"t":"He said to them, “Go into all the world and preach the Good News to the whole creation."},{"v":16,"t":"He who believes and is baptized will be saved; but he who disbelieves will be condemned."},{"v":17,"t":"These signs will accompany those who believe: in my name they will cast out demons; they will speak with new languages;"},{"v":18,"t":"they will take up serpents; and if they drink any deadly thing, it will in no way hurt them; they will lay hands on the sick, and they will recover.”"},{"v":19,"t":"So then the Lord, after he had spoken to them, was received up into heaven and sat down at the right hand of God."},{"v":20,"t":"They went out and preached everywhere, the Lord working with them and confirming the word by the signs that followed. Amen."}]}},"LUK":{"1":{"en":[{"v":1,"t":"Since many have undertaken to set in order a narrative concerning those matters which have been fulfilled among us,"},{"v":2,"t":"even as those who from the beginning were eyewitnesses and servants of the word delivered them to us,"},{"v":3,"t":"it seemed good to me also, having traced the course of all things accurately from the first, to write to you in order, most excellent Theophilus;"},{"v":4,"t":"that you might know the certainty concerning the things in which you were instructed."},{"v":5,"t":"There was in the days of Herod, the king of Judea, a certain priest named Zacharias, of the priestly division of Abijah. He had a wife of the daughters of Aaron, and her name was Elizabeth."},{"v":6,"t":"They were both righteous before God, walking blamelessly in all the commandments and ordinances of the Lord."},{"v":7,"t":"But they had no child, because Elizabeth was barren, and they both were well advanced in years."},{"v":8,"t":"Now while he executed the priest’s office before God in the order of his division"},{"v":9,"t":"according to the custom of the priest’s office, his lot was to enter into the temple of the Lord and burn incense."},{"v":10,"t":"The whole multitude of the people were praying outside at the hour of incense."},{"v":11,"t":"An angel of the Lord appeared to him, standing on the right side of the altar of incense."},{"v":12,"t":"Zacharias was troubled when he saw him, and fear fell upon him."},{"v":13,"t":"But the angel said to him, “Don’t be afraid, Zacharias, because your request has been heard. Your wife, Elizabeth, will bear you a son, and you shall call his name John."},{"v":14,"t":"You will have joy and gladness, and many will rejoice at his birth."},{"v":15,"t":"For he will be great in the sight of the Lord, and he will drink no wine nor strong drink. He will be filled with the Holy Spirit, even from his mother’s womb."},{"v":16,"t":"He will turn many of the children of Israel to the Lord their God."},{"v":17,"t":"He will go before him in the spirit and power of Elijah, ‘to turn the hearts of the fathers to the children,’ and the disobedient to the wisdom of the just; to prepare a people prepared for the Lord.”"},{"v":18,"t":"Zacharias said to the angel, “How can I be sure of this? For I am an old man, and my wife is well advanced in years.”"},{"v":19,"t":"The angel answered him, “I am Gabriel, who stands in the presence of God. I was sent to speak to you and to bring you this good news."},{"v":20,"t":"Behold, you will be silent and not able to speak until the day that these things will happen, because you didn’t believe my words, which will be fulfilled in their proper time.”"},{"v":21,"t":"The people were waiting for Zacharias, and they marveled that he delayed in the temple."},{"v":22,"t":"When he came out, he could not speak to them. They perceived that he had seen a vision in the temple. He continued making signs to them, and remained mute."},{"v":23,"t":"When the days of his service were fulfilled, he departed to his house."},{"v":24,"t":"After these days Elizabeth his wife conceived, and she hid herself five months, saying,"},{"v":25,"t":"“Thus has the Lord done to me in the days in which he looked at me, to take away my reproach among men.”"},{"v":26,"t":"Now in the sixth month, the angel Gabriel was sent from God to a city of Galilee named Nazareth,"},{"v":27,"t":"to a virgin pledged to be married to a man whose name was Joseph, of David’s house. The virgin’s name was Mary."},{"v":28,"t":"Having come in, the angel said to her, “Rejoice, you highly favored one! The Lord is with you. Blessed are you among women!”"},{"v":29,"t":"But when she saw him, she was greatly troubled at the saying, and considered what kind of salutation this might be."},{"v":30,"t":"The angel said to her, “Don’t be afraid, Mary, for you have found favor with God."},{"v":31,"t":"Behold, you will conceive in your womb and give birth to a son, and shall name him ‘Jesus.’"},{"v":32,"t":"He will be great and will be called the Son of the Most High. The Lord God will give him the throne of his father David,"},{"v":33,"t":"and he will reign over the house of Jacob forever. There will be no end to his Kingdom.”"},{"v":34,"t":"Mary said to the angel, “How can this be, seeing I am a virgin?”"},{"v":35,"t":"The angel answered her, “The Holy Spirit will come on you, and the power of the Most High will overshadow you. Therefore also the holy one who is born from you will be called the Son of God."},{"v":36,"t":"Behold, Elizabeth your relative also has conceived a son in her old age; and this is the sixth month with her who was called barren."},{"v":37,"t":"For nothing spoken by God is impossible.”"},{"v":38,"t":"Mary said, “Behold, the servant of the Lord; let it be done to me according to your word.” Then the angel departed from her."},{"v":39,"t":"Mary arose in those days and went into the hill country with haste, into a city of Judah,"},{"v":40,"t":"and entered into the house of Zacharias and greeted Elizabeth."},{"v":41,"t":"When Elizabeth heard Mary’s greeting, the baby leaped in her womb; and Elizabeth was filled with the Holy Spirit."},{"v":42,"t":"She called out with a loud voice and said, “Blessed are you among women, and blessed is the fruit of your womb!"},{"v":43,"t":"Why am I so favored, that the mother of my Lord should come to me?"},{"v":44,"t":"For behold, when the voice of your greeting came into my ears, the baby leaped in my womb for joy!"},{"v":45,"t":"Blessed is she who believed, for there will be a fulfillment of the things which have been spoken to her from the Lord!”"},{"v":46,"t":"Mary said, “My soul magnifies the Lord."},{"v":47,"t":"My spirit has rejoiced in God my Savior,"},{"v":48,"t":"for he has looked at the humble state of his servant. For behold, from now on, all generations will call me blessed."},{"v":49,"t":"For he who is mighty has done great things for me. Holy is his name."},{"v":50,"t":"His mercy is for generations and generations on those who fear him."},{"v":51,"t":"He has shown strength with his arm. He has scattered the proud in the imagination of their hearts."},{"v":52,"t":"He has put down princes from their thrones, and has exalted the lowly."},{"v":53,"t":"He has filled the hungry with good things. He has sent the rich away empty."},{"v":54,"t":"He has given help to Israel, his servant, that he might remember mercy,"},{"v":55,"t":"as he spoke to our fathers, to Abraham and his offspring forever.”"},{"v":56,"t":"Mary stayed with her about three months, and then returned to her house."},{"v":57,"t":"Now the time that Elizabeth should give birth was fulfilled, and she gave birth to a son."},{"v":58,"t":"Her neighbors and her relatives heard that the Lord had magnified his mercy toward her, and they rejoiced with her."},{"v":59,"t":"On the eighth day, they came to circumcise the child; and they would have called him Zacharias, after the name of his father."},{"v":60,"t":"His mother answered, “Not so; but he will be called John.”"},{"v":61,"t":"They said to her, “There is no one among your relatives who is called by this name.”"},{"v":62,"t":"They made signs to his father, what he would have him called."},{"v":63,"t":"He asked for a writing tablet, and wrote, “His name is John.” They all marveled."},{"v":64,"t":"His mouth was opened immediately and his tongue freed, and he spoke, blessing God."},{"v":65,"t":"Fear came on all who lived around them, and all these sayings were talked about throughout all the hill country of Judea."},{"v":66,"t":"All who heard them laid them up in their heart, saying, “What then will this child be?” The hand of the Lord was with him."},{"v":67,"t":"His father Zacharias was filled with the Holy Spirit, and prophesied, saying,"},{"v":68,"t":"“Blessed be the Lord, the God of Israel, for he has visited and redeemed his people;"},{"v":69,"t":"and has raised up a horn of salvation for us in the house of his servant David"},{"v":70,"t":"(as he spoke by the mouth of his holy prophets who have been from of old),"},{"v":71,"t":"salvation from our enemies and from the hand of all who hate us;"},{"v":72,"t":"to show mercy toward our fathers, to remember his holy covenant,"},{"v":73,"t":"the oath which he swore to Abraham our father,"},{"v":74,"t":"to grant to us that we, being delivered out of the hand of our enemies, should serve him without fear,"},{"v":75,"t":"in holiness and righteousness before him all the days of our life."},{"v":76,"t":"And you, child, will be called a prophet of the Most High; for you will go before the face of the Lord to prepare his ways,"},{"v":77,"t":"to give knowledge of salvation to his people by the remission of their sins,"},{"v":78,"t":"because of the tender mercy of our God, by which the dawn from on high will visit us,"},{"v":79,"t":"to shine on those who sit in darkness and the shadow of death; to guide our feet into the way of peace.”"},{"v":80,"t":"The child was growing and becoming strong in spirit, and was in the desert until the day of his public appearance to Israel."}]},"2":{"en":[{"v":1,"t":"Now in those days, a decree went out from Caesar Augustus that all the world should be enrolled."},{"v":2,"t":"This was the first enrollment made when Quirinius was governor of Syria."},{"v":3,"t":"All went to enroll themselves, everyone to his own city."},{"v":4,"t":"Joseph also went up from Galilee, out of the city of Nazareth, into Judea, to David’s city, which is called Bethlehem, because he was of the house and family of David,"},{"v":5,"t":"to enroll himself with Mary, who was pledged to be married to him as wife, being pregnant."},{"v":6,"t":"While they were there, the day had come for her to give birth."},{"v":7,"t":"She gave birth to her firstborn son. She wrapped him in bands of cloth and laid him in a feeding trough, because there was no room for them in the inn."},{"v":8,"t":"There were shepherds in the same country staying in the field, and keeping watch by night over their flock."},{"v":9,"t":"Behold, an angel of the Lord stood by them, and the glory of the Lord shone around them, and they were terrified."},{"v":10,"t":"The angel said to them, “Don’t be afraid, for behold, I bring you good news of great joy which will be to all the people."},{"v":11,"t":"For there is born to you today, in David’s city, a Savior, who is Christ the Lord."},{"v":12,"t":"This is the sign to you: you will find a baby wrapped in strips of cloth, lying in a feeding trough.”"},{"v":13,"t":"Suddenly, there was with the angel a multitude of the heavenly army praising God and saying,"},{"v":14,"t":"“Glory to God in the highest, on earth peace, good will toward men.”"},{"v":15,"t":"When the angels went away from them into the sky, the shepherds said to one another, “Let’s go to Bethlehem, now, and see this thing that has happened, which the Lord has made known to us.”"},{"v":16,"t":"They came with haste and found both Mary and Joseph, and the baby was lying in the feeding trough."},{"v":17,"t":"When they saw it, they publicized widely the saying which was spoken to them about this child."},{"v":18,"t":"All who heard it wondered at the things which were spoken to them by the shepherds."},{"v":19,"t":"But Mary kept all these sayings, pondering them in her heart."},{"v":20,"t":"The shepherds returned, glorifying and praising God for all the things that they had heard and seen, just as it was told them."},{"v":21,"t":"When eight days were fulfilled for the circumcision of the child, his name was called Jesus, which was given by the angel before he was conceived in the womb."},{"v":22,"t":"When the days of their purification according to the law of Moses were fulfilled, they brought him up to Jerusalem to present him to the Lord"},{"v":23,"t":"(as it is written in the law of the Lord, “Every male who opens the womb shall be called holy to the Lord”),"},{"v":24,"t":"and to offer a sacrifice according to that which is said in the law of the Lord, “A pair of turtledoves, or two young pigeons.”"},{"v":25,"t":"Behold, there was a man in Jerusalem whose name was Simeon. This man was righteous and devout, looking for the consolation of Israel, and the Holy Spirit was on him."},{"v":26,"t":"It had been revealed to him by the Holy Spirit that he should not see death before he had seen the Lord’s Christ."},{"v":27,"t":"He came in the Spirit into the temple. When the parents brought in the child, Jesus, that they might do concerning him according to the custom of the law,"},{"v":28,"t":"then he received him into his arms and blessed God, and said,"},{"v":29,"t":"“Now you are releasing your servant, Master, according to your word, in peace;"},{"v":30,"t":"for my eyes have seen your salvation,"},{"v":31,"t":"which you have prepared before the face of all peoples;"},{"v":32,"t":"a light for revelation to the nations, and the glory of your people Israel.”"},{"v":33,"t":"Joseph and his mother were marveling at the things which were spoken concerning him."},{"v":34,"t":"Simeon blessed them, and said to Mary, his mother, “Behold, this child is appointed for the falling and the rising of many in Israel, and for a sign which is spoken against."},{"v":35,"t":"Yes, a sword will pierce through your own soul, that the thoughts of many hearts may be revealed.”"},{"v":36,"t":"There was one Anna, a prophetess, the daughter of Phanuel, of the tribe of Asher (she was of a great age, having lived with a husband seven years from her virginity,"},{"v":37,"t":"and she had been a widow for about eighty-four years), who didn’t depart from the temple, worshiping with fastings and petitions night and day."},{"v":38,"t":"Coming up at that very hour, she gave thanks to the Lord, and spoke of him to all those who were looking for redemption in Jerusalem."},{"v":39,"t":"When they had accomplished all things that were according to the law of the Lord, they returned into Galilee, to their own city, Nazareth."},{"v":40,"t":"The child was growing, and was becoming strong in spirit, being filled with wisdom, and the grace of God was upon him."},{"v":41,"t":"His parents went every year to Jerusalem at the feast of the Passover."},{"v":42,"t":"When he was twelve years old, they went up to Jerusalem according to the custom of the feast;"},{"v":43,"t":"and when they had fulfilled the days, as they were returning, the boy Jesus stayed behind in Jerusalem. Joseph and his mother didn’t know it,"},{"v":44,"t":"but supposing him to be in the company, they went a day’s journey; and they looked for him among their relatives and acquaintances."},{"v":45,"t":"When they didn’t find him, they returned to Jerusalem, looking for him."},{"v":46,"t":"After three days they found him in the temple, sitting in the middle of the teachers, both listening to them and asking them questions."},{"v":47,"t":"All who heard him were amazed at his understanding and his answers."},{"v":48,"t":"When they saw him, they were astonished; and his mother said to him, “Son, why have you treated us this way? Behold, your father and I were anxiously looking for you.”"},{"v":49,"t":"He said to them, “Why were you looking for me? Didn’t you know that I must be in my Father’s house?”"},{"v":50,"t":"They didn’t understand the saying which he spoke to them."},{"v":51,"t":"And he went down with them and came to Nazareth. He was subject to them, and his mother kept all these sayings in her heart."},{"v":52,"t":"And Jesus increased in wisdom and stature, and in favor with God and men."}]},"3":{"en":[{"v":1,"t":"Now in the fifteenth year of the reign of Tiberius Caesar, Pontius Pilate being governor of Judea, and Herod being tetrarch of Galilee, and his brother Philip tetrarch of the region of Ituraea and Trachonitis, and Lysanias tetrarch of Abilene,"},{"v":2,"t":"during the high priesthood of Annas and Caiaphas, the word of God came to John, the son of Zacharias, in the wilderness."},{"v":3,"t":"He came into all the region around the Jordan, preaching the baptism of repentance for remission of sins."},{"v":4,"t":"As it is written in the book of the words of Isaiah the prophet, “The voice of one crying in the wilderness, ‘Make ready the way of the Lord. Make his paths straight."},{"v":5,"t":"Every valley will be filled. Every mountain and hill will be brought low. The crooked will become straight, and the rough ways smooth."},{"v":6,"t":"All flesh will see God’s salvation.’”"},{"v":7,"t":"He said therefore to the multitudes who went out to be baptized by him, “You offspring of vipers, who warned you to flee from the wrath to come?"},{"v":8,"t":"Therefore produce fruits worthy of repentance, and don’t begin to say among yourselves, ‘We have Abraham for our father;’ for I tell you that God is able to raise up children to Abraham from these stones!"},{"v":9,"t":"Even now the ax also lies at the root of the trees. Every tree therefore that doesn’t produce good fruit is cut down and thrown into the fire.”"},{"v":10,"t":"The multitudes asked him, “What then must we do?”"},{"v":11,"t":"He answered them, “He who has two coats, let him give to him who has none. He who has food, let him do likewise.”"},{"v":12,"t":"Tax collectors also came to be baptized, and they said to him, “Teacher, what must we do?”"},{"v":13,"t":"He said to them, “Collect no more than that which is appointed to you.”"},{"v":14,"t":"Soldiers also asked him, saying, “What about us? What must we do?” He said to them, “Extort from no one by violence, neither accuse anyone wrongfully. Be content with your wages.”"},{"v":15,"t":"As the people were in expectation, and all men reasoned in their hearts concerning John, whether perhaps he was the Christ,"},{"v":16,"t":"John answered them all, “I indeed baptize you with water, but he comes who is mightier than I, the strap of whose sandals I am not worthy to loosen. He will baptize you in the Holy Spirit and fire."},{"v":17,"t":"His winnowing fan is in his hand, and he will thoroughly cleanse his threshing floor, and will gather the wheat into his barn; but he will burn up the chaff with unquenchable fire.”"},{"v":18,"t":"Then with many other exhortations he preached good news to the people,"},{"v":19,"t":"but Herod the tetrarch, being reproved by him for Herodias, his brother’s wife, and for all the evil things which Herod had done,"},{"v":20,"t":"added this also to them all, that he shut up John in prison."},{"v":21,"t":"Now when all the people were baptized, Jesus also had been baptized and was praying. The sky was opened,"},{"v":22,"t":"and the Holy Spirit descended in a bodily form like a dove on him; and a voice came out of the sky, saying “You are my beloved Son. In you I am well pleased.”"},{"v":23,"t":"Jesus himself, when he began to teach, was about thirty years old, being the son (as was supposed) of Joseph, the son of Heli,"},{"v":24,"t":"the son of Matthat, the son of Levi, the son of Melchi, the son of Jannai, the son of Joseph,"},{"v":25,"t":"the son of Mattathias, the son of Amos, the son of Nahum, the son of Esli, the son of Naggai,"},{"v":26,"t":"the son of Maath, the son of Mattathias, the son of Semein, the son of Joseph, the son of Judah,"},{"v":27,"t":"the son of Joanan, the son of Rhesa, the son of Zerubbabel, the son of Shealtiel, the son of Neri,"},{"v":28,"t":"the son of Melchi, the son of Addi, the son of Cosam, the son of Elmodam, the son of Er,"},{"v":29,"t":"the son of Jose, the son of Eliezer, the son of Jorim, the son of Matthat, the son of Levi,"},{"v":30,"t":"the son of Simeon, the son of Judah, the son of Joseph, the son of Jonan, the son of Eliakim,"},{"v":31,"t":"the son of Melea, the son of Menan, the son of Mattatha, the son of Nathan, the son of David,"},{"v":32,"t":"the son of Jesse, the son of Obed, the son of Boaz, the son of Salmon, the son of Nahshon,"},{"v":33,"t":"the son of Amminadab, the son of Aram, the son of Hezron, the son of Perez, the son of Judah,"},{"v":34,"t":"the son of Jacob, the son of Isaac, the son of Abraham, the son of Terah, the son of Nahor,"},{"v":35,"t":"the son of Serug, the son of Reu, the son of Peleg, the son of Eber, the son of Shelah,"},{"v":36,"t":"the son of Cainan, the son of Arphaxad, the son of Shem, the son of Noah, the son of Lamech,"},{"v":37,"t":"the son of Methuselah, the son of Enoch, the son of Jared, the son of Mahalaleel, the son of Cainan,"},{"v":38,"t":"the son of Enos, the son of Seth, the son of Adam, the son of God."}]},"4":{"en":[{"v":1,"t":"Jesus, full of the Holy Spirit, returned from the Jordan and was led by the Spirit into the wilderness"},{"v":2,"t":"for forty days, being tempted by the devil. He ate nothing in those days. Afterward, when they were completed, he was hungry."},{"v":3,"t":"The devil said to him, “If you are the Son of God, command this stone to become bread.”"},{"v":4,"t":"Jesus answered him, saying, “It is written, ‘Man shall not live by bread alone, but by every word of God.’”"},{"v":5,"t":"The devil, leading him up on a high mountain, showed him all the kingdoms of the world in a moment of time."},{"v":6,"t":"The devil said to him, “I will give you all this authority and their glory, for it has been delivered to me, and I give it to whomever I want."},{"v":7,"t":"If you therefore will worship before me, it will all be yours.”"},{"v":8,"t":"Jesus answered him, “Get behind me, Satan! For it is written, ‘You shall worship the Lord your God, and you shall serve him only.’”"},{"v":9,"t":"He led him to Jerusalem and set him on the pinnacle of the temple, and said to him, “If you are the Son of God, cast yourself down from here,"},{"v":10,"t":"for it is written, ‘He will put his angels in charge of you, to guard you;’"},{"v":11,"t":"and, ‘On their hands they will bear you up, lest perhaps you dash your foot against a stone.’”"},{"v":12,"t":"Jesus answering, said to him, “It has been said, ‘You shall not tempt the Lord your God.’”"},{"v":13,"t":"When the devil had completed every temptation, he departed from him until another time."},{"v":14,"t":"Jesus returned in the power of the Spirit into Galilee, and news about him spread through all the surrounding area."},{"v":15,"t":"He taught in their synagogues, being glorified by all."},{"v":16,"t":"He came to Nazareth, where he had been brought up. He entered, as was his custom, into the synagogue on the Sabbath day, and stood up to read."},{"v":17,"t":"The book of the prophet Isaiah was handed to him. He opened the book, and found the place where it was written,"},{"v":18,"t":"“The Spirit of the Lord is on me, because he has anointed me to preach good news to the poor. He has sent me to heal the broken hearted, to proclaim release to the captives, recovering of sight to the blind, to deliver those who are crushed,"},{"v":19,"t":"and to proclaim the acceptable year of the Lord.”"},{"v":20,"t":"He closed the book, gave it back to the attendant, and sat down. The eyes of all in the synagogue were fastened on him."},{"v":21,"t":"He began to tell them, “Today, this Scripture has been fulfilled in your hearing.”"},{"v":22,"t":"All testified about him and wondered at the gracious words which proceeded out of his mouth; and they said, “Isn’t this Joseph’s son?”"},{"v":23,"t":"He said to them, “Doubtless you will tell me this proverb, ‘Physician, heal yourself! Whatever we have heard done at Capernaum, do also here in your hometown.’”"},{"v":24,"t":"He said, “Most certainly I tell you, no prophet is acceptable in his hometown."},{"v":25,"t":"But truly I tell you, there were many widows in Israel in the days of Elijah, when the sky was shut up three years and six months, when a great famine came over all the land."},{"v":26,"t":"Elijah was sent to none of them, except to Zarephath, in the land of Sidon, to a woman who was a widow."},{"v":27,"t":"There were many lepers in Israel in the time of Elisha the prophet, yet not one of them was cleansed, except Naaman, the Syrian.”"},{"v":28,"t":"They were all filled with wrath in the synagogue as they heard these things."},{"v":29,"t":"They rose up, threw him out of the city, and led him to the brow of the hill that their city was built on, that they might throw him off the cliff."},{"v":30,"t":"But he, passing through the middle of them, went his way."},{"v":31,"t":"He came down to Capernaum, a city of Galilee. He was teaching them on the Sabbath day,"},{"v":32,"t":"and they were astonished at his teaching, for his word was with authority."},{"v":33,"t":"In the synagogue there was a man who had a spirit of an unclean demon; and he cried out with a loud voice,"},{"v":34,"t":"saying, “Ah! what have we to do with you, Jesus of Nazareth? Have you come to destroy us? I know who you are: the Holy One of God!”"},{"v":35,"t":"Jesus rebuked him, saying, “Be silent and come out of him!” When the demon had thrown him down in the middle of them, he came out of him, having done him no harm."},{"v":36,"t":"Amazement came on all and they spoke together, one with another, saying, “What is this word? For with authority and power he commands the unclean spirits, and they come out!”"},{"v":37,"t":"News about him went out into every place of the surrounding region."},{"v":38,"t":"He rose up from the synagogue and entered into Simon’s house. Simon’s mother-in-law was afflicted with a great fever, and they begged him to help her."},{"v":39,"t":"He stood over her and rebuked the fever, and it left her. Immediately she rose up and served them."},{"v":40,"t":"When the sun was setting, all those who had any sick with various diseases brought them to him; and he laid his hands on every one of them, and healed them."},{"v":41,"t":"Demons also came out of many, crying out and saying, “You are the Christ, the Son of God!” Rebuking them, he didn’t allow them to speak, because they knew that he was the Christ."},{"v":42,"t":"When it was day, he departed and went into an uninhabited place and the multitudes looked for him, and came to him, and held on to him, so that he wouldn’t go away from them."},{"v":43,"t":"But he said to them, “I must preach the good news of God’s Kingdom to the other cities also. For this reason I have been sent.”"},{"v":44,"t":"He was preaching in the synagogues of Galilee."}]},"5":{"en":[{"v":1,"t":"Now while the multitude pressed on him and heard the word of God, he was standing by the lake of Gennesaret."},{"v":2,"t":"He saw two boats standing by the lake, but the fishermen had gone out of them and were washing their nets."},{"v":3,"t":"He entered into one of the boats, which was Simon’s, and asked him to put out a little from the land. He sat down and taught the multitudes from the boat."},{"v":4,"t":"When he had finished speaking, he said to Simon, “Put out into the deep and let down your nets for a catch.”"},{"v":5,"t":"Simon answered him, “Master, we worked all night and caught nothing; but at your word I will let down the net.”"},{"v":6,"t":"When they had done this, they caught a great multitude of fish, and their net was breaking."},{"v":7,"t":"They beckoned to their partners in the other boat, that they should come and help them. They came and filled both boats, so that they began to sink."},{"v":8,"t":"But Simon Peter, when he saw it, fell down at Jesus’ knees, saying, “Depart from me, for I am a sinful man, Lord.”"},{"v":9,"t":"For he was amazed, and all who were with him, at the catch of fish which they had caught;"},{"v":10,"t":"and so also were James and John, sons of Zebedee, who were partners with Simon. Jesus said to Simon, “Don’t be afraid. From now on you will be catching people alive.”"},{"v":11,"t":"When they had brought their boats to land, they left everything, and followed him."},{"v":12,"t":"While he was in one of the cities, behold, there was a man full of leprosy. When he saw Jesus, he fell on his face and begged him, saying, “Lord, if you want to, you can make me clean.”"},{"v":13,"t":"He stretched out his hand and touched him, saying, “I want to. Be made clean.” Immediately the leprosy left him."},{"v":14,"t":"He commanded him to tell no one, “But go your way and show yourself to the priest, and offer for your cleansing according to what Moses commanded, for a testimony to them.”"},{"v":15,"t":"But the report concerning him spread much more, and great multitudes came together to hear and to be healed by him of their infirmities."},{"v":16,"t":"But he withdrew himself into the desert and prayed."},{"v":17,"t":"On one of those days, he was teaching; and there were Pharisees and teachers of the law sitting by who had come out of every village of Galilee, Judea, and Jerusalem. The power of the Lord was with him to heal them."},{"v":18,"t":"Behold, men brought a paralyzed man on a cot, and they sought to bring him in to lay before Jesus."},{"v":19,"t":"Not finding a way to bring him in because of the multitude, they went up to the housetop and let him down through the tiles with his cot into the middle before Jesus."},{"v":20,"t":"Seeing their faith, he said to him, “Man, your sins are forgiven you.”"},{"v":21,"t":"The scribes and the Pharisees began to reason, saying, “Who is this who speaks blasphemies? Who can forgive sins, but God alone?”"},{"v":22,"t":"But Jesus, perceiving their thoughts, answered them, “Why are you reasoning so in your hearts?"},{"v":23,"t":"Which is easier to say, ‘Your sins are forgiven you,’ or to say, ‘Arise and walk’?"},{"v":24,"t":"But that you may know that the Son of Man has authority on earth to forgive sins,” he said to the paralyzed man, “I tell you, arise, take up your cot, and go to your house.”"},{"v":25,"t":"Immediately he rose up before them, and took up that which he was laying on, and departed to his house, glorifying God."},{"v":26,"t":"Amazement took hold on all, and they glorified God. They were filled with fear, saying, “We have seen strange things today.”"},{"v":27,"t":"After these things he went out and saw a tax collector named Levi sitting at the tax office, and said to him, “Follow me!”"},{"v":28,"t":"He left everything, and rose up and followed him."},{"v":29,"t":"Levi made a great feast for him in his house. There was a great crowd of tax collectors and others who were reclining with them."},{"v":30,"t":"Their scribes and the Pharisees murmured against his disciples, saying, “Why do you eat and drink with the tax collectors and sinners?”"},{"v":31,"t":"Jesus answered them, “Those who are healthy have no need for a physician, but those who are sick do."},{"v":32,"t":"I have not come to call the righteous, but sinners, to repentance.”"},{"v":33,"t":"They said to him, “Why do John’s disciples often fast and pray, likewise also the disciples of the Pharisees, but yours eat and drink?”"},{"v":34,"t":"He said to them, “Can you make the friends of the bridegroom fast while the bridegroom is with them?"},{"v":35,"t":"But the days will come when the bridegroom will be taken away from them. Then they will fast in those days.”"},{"v":36,"t":"He also told a parable to them. “No one puts a piece from a new garment on an old garment, or else he will tear the new, and also the piece from the new will not match the old."},{"v":37,"t":"No one puts new wine into old wineskins, or else the new wine will burst the skins, and it will be spilled and the skins will be destroyed."},{"v":38,"t":"But new wine must be put into fresh wineskins, and both are preserved."},{"v":39,"t":"No man having drunk old wine immediately desires new, for he says, ‘The old is better.’”"}]},"6":{"en":[{"v":1,"t":"Now on the second Sabbath after the first, he was going through the grain fields. His disciples plucked the heads of grain and ate, rubbing them in their hands."},{"v":2,"t":"But some of the Pharisees said to them, “Why do you do that which is not lawful to do on the Sabbath day?”"},{"v":3,"t":"Jesus, answering them, said, “Haven’t you read what David did when he was hungry, he and those who were with him,"},{"v":4,"t":"how he entered into God’s house, and took and ate the show bread, and gave also to those who were with him, which is not lawful to eat except for the priests alone?”"},{"v":5,"t":"He said to them, “The Son of Man is lord of the Sabbath.”"},{"v":6,"t":"It also happened on another Sabbath that he entered into the synagogue and taught. There was a man there, and his right hand was withered."},{"v":7,"t":"The scribes and the Pharisees watched him, to see whether he would heal on the Sabbath, that they might find an accusation against him."},{"v":8,"t":"But he knew their thoughts; and he said to the man who had the withered hand, “Rise up and stand in the middle.” He arose and stood."},{"v":9,"t":"Then Jesus said to them, “I will ask you something: Is it lawful on the Sabbath to do good, or to do harm? To save a life, or to kill?”"},{"v":10,"t":"He looked around at them all, and said to the man, “Stretch out your hand.” He did, and his hand was restored as sound as the other."},{"v":11,"t":"But they were filled with rage, and talked with one another about what they might do to Jesus."},{"v":12,"t":"In these days, he went out to the mountain to pray, and he continued all night in prayer to God."},{"v":13,"t":"When it was day, he called his disciples, and from them he chose twelve, whom he also named apostles:"},{"v":14,"t":"Simon, whom he also named Peter; Andrew, his brother; James; John; Philip; Bartholomew;"},{"v":15,"t":"Matthew; Thomas; James the son of Alphaeus; Simon who was called the Zealot;"},{"v":16,"t":"Judas the son of James; and Judas Iscariot, who also became a traitor."},{"v":17,"t":"He came down with them and stood on a level place, with a crowd of his disciples and a great number of the people from all Judea and Jerusalem and the sea coast of Tyre and Sidon, who came to hear him and to be healed of their diseases,"},{"v":18,"t":"as well as those who were troubled by unclean spirits; and they were being healed."},{"v":19,"t":"All the multitude sought to touch him, for power came out of him and healed them all."},{"v":20,"t":"He lifted up his eyes to his disciples, and said: “Blessed are you who are poor, for God’s Kingdom is yours."},{"v":21,"t":"Blessed are you who hunger now, for you will be filled. Blessed are you who weep now, for you will laugh."},{"v":22,"t":"Blessed are you when men hate you, and when they exclude and mock you, and throw out your name as evil, for the Son of Man’s sake."},{"v":23,"t":"Rejoice in that day and leap for joy, for behold, your reward is great in heaven, for their fathers did the same thing to the prophets."},{"v":24,"t":"“But woe to you who are rich! For you have received your consolation."},{"v":25,"t":"Woe to you, you who are full now, for you will be hungry. Woe to you who laugh now, for you will mourn and weep."},{"v":26,"t":"Woe, when men speak well of you, for their fathers did the same thing to the false prophets."},{"v":27,"t":"“But I tell you who hear: love your enemies, do good to those who hate you,"},{"v":28,"t":"bless those who curse you, and pray for those who mistreat you."},{"v":29,"t":"To him who strikes you on the cheek, offer also the other; and from him who takes away your cloak, don’t withhold your coat also."},{"v":30,"t":"Give to everyone who asks you, and don’t ask him who takes away your goods to give them back again."},{"v":31,"t":"“As you would like people to do to you, do exactly so to them."},{"v":32,"t":"“If you love those who love you, what credit is that to you? For even sinners love those who love them."},{"v":33,"t":"If you do good to those who do good to you, what credit is that to you? For even sinners do the same."},{"v":34,"t":"If you lend to those from whom you hope to receive, what credit is that to you? Even sinners lend to sinners, to receive back as much."},{"v":35,"t":"But love your enemies, and do good, and lend, expecting nothing back; and your reward will be great, and you will be children of the Most High; for he is kind toward the unthankful and evil."},{"v":36,"t":"“Therefore be merciful, even as your Father is also merciful."},{"v":37,"t":"Don’t judge, and you won’t be judged. Don’t condemn, and you won’t be condemned. Set free, and you will be set free."},{"v":38,"t":"“Give, and it will be given to you: good measure, pressed down, shaken together, and running over, will be given to you. For with the same measure you measure it will be measured back to you.”"},{"v":39,"t":"He spoke a parable to them. “Can the blind guide the blind? Won’t they both fall into a pit?"},{"v":40,"t":"A disciple is not above his teacher, but everyone when he is fully trained will be like his teacher."},{"v":41,"t":"Why do you see the speck of chaff that is in your brother’s eye, but don’t consider the beam that is in your own eye?"},{"v":42,"t":"Or how can you tell your brother, ‘Brother, let me remove the speck of chaff that is in your eye,’ when you yourself don’t see the beam that is in your own eye? You hypocrite! First remove the beam from your own eye, and then you can see clearly to remove the speck of chaff that is in your brother’s eye."},{"v":43,"t":"“For there is no good tree that produces rotten fruit, nor again a rotten tree that produces good fruit."},{"v":44,"t":"For each tree is known by its own fruit. For people don’t gather figs from thorns, nor do they gather grapes from a bramble bush."},{"v":45,"t":"The good man out of the good treasure of his heart brings out that which is good, and the evil man out of the evil treasure of his heart brings out that which is evil, for out of the abundance of the heart, his mouth speaks."},{"v":46,"t":"“Why do you call me, ‘Lord, Lord,’ and don’t do the things which I say?"},{"v":47,"t":"Everyone who comes to me, and hears my words and does them, I will show you who he is like."},{"v":48,"t":"He is like a man building a house, who dug and went deep and laid a foundation on the rock. When a flood arose, the stream broke against that house, and could not shake it, because it was founded on the rock."},{"v":49,"t":"But he who hears and doesn’t do, is like a man who built a house on the earth without a foundation, against which the stream broke, and immediately it fell; and the ruin of that house was great.”"}]},"7":{"en":[{"v":1,"t":"After he had finished speaking in the hearing of the people, he entered into Capernaum."},{"v":2,"t":"A certain centurion’s servant, who was dear to him, was sick and at the point of death."},{"v":3,"t":"When he heard about Jesus, he sent to him elders of the Jews, asking him to come and save his servant."},{"v":4,"t":"When they came to Jesus, they begged him earnestly, saying, “He is worthy for you to do this for him,"},{"v":5,"t":"for he loves our nation, and he built our synagogue for us.”"},{"v":6,"t":"Jesus went with them. When he was now not far from the house, the centurion sent friends to him, saying to him, “Lord, don’t trouble yourself, for I am not worthy for you to come under my roof."},{"v":7,"t":"Therefore I didn’t even think myself worthy to come to you; but say the word, and my servant will be healed."},{"v":8,"t":"For I also am a man placed under authority, having under myself soldiers. I tell this one, ‘Go!’ and he goes; and to another, ‘Come!’ and he comes; and to my servant, ‘Do this,’ and he does it.”"},{"v":9,"t":"When Jesus heard these things, he marveled at him, and turned and said to the multitude who followed him, “I tell you, I have not found such great faith, no, not in Israel.”"},{"v":10,"t":"Those who were sent, returning to the house, found that the servant who had been sick was well."},{"v":11,"t":"Soon afterwards, he went to a city called Nain. Many of his disciples, along with a great multitude, went with him."},{"v":12,"t":"Now when he came near to the gate of the city, behold, one who was dead was carried out, the only born son of his mother, and she was a widow. Many people of the city were with her."},{"v":13,"t":"When the Lord saw her, he had compassion on her and said to her, “Don’t cry.”"},{"v":14,"t":"He came near and touched the coffin, and the bearers stood still. He said, “Young man, I tell you, arise!”"},{"v":15,"t":"He who was dead sat up and began to speak. Then he gave him to his mother."},{"v":16,"t":"Fear took hold of all, and they glorified God, saying, “A great prophet has arisen among us!” and, “God has visited his people!”"},{"v":17,"t":"This report went out concerning him in the whole of Judea and in all the surrounding region."},{"v":18,"t":"The disciples of John told him about all these things."},{"v":19,"t":"John, calling to himself two of his disciples, sent them to Jesus, saying, “Are you the one who is coming, or should we look for another?”"},{"v":20,"t":"When the men had come to him, they said, “John the Baptizer has sent us to you, saying, ‘Are you he who comes, or should we look for another?’”"},{"v":21,"t":"In that hour he cured many of diseases and plagues and evil spirits; and to many who were blind he gave sight."},{"v":22,"t":"Jesus answered them, “Go and tell John the things which you have seen and heard: that the blind receive their sight, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised up, and the poor have good news preached to them."},{"v":23,"t":"Blessed is he who finds no occasion for stumbling in me.”"},{"v":24,"t":"When John’s messengers had departed, he began to tell the multitudes about John, “What did you go out into the wilderness to see? A reed shaken by the wind?"},{"v":25,"t":"But what did you go out to see? A man clothed in soft clothing? Behold, those who are gorgeously dressed and live delicately are in kings’ courts."},{"v":26,"t":"But what did you go out to see? A prophet? Yes, I tell you, and much more than a prophet."},{"v":27,"t":"This is he of whom it is written, ‘Behold, I send my messenger before your face, who will prepare your way before you.’"},{"v":28,"t":"“For I tell you, among those who are born of women there is not a greater prophet than John the Baptizer; yet he who is least in God’s Kingdom is greater than he.”"},{"v":29,"t":"When all the people and the tax collectors heard this, they declared God to be just, having been baptized with John’s baptism."},{"v":30,"t":"But the Pharisees and the lawyers rejected the counsel of God, not being baptized by him themselves."},{"v":31,"t":"“To what then should I compare the people of this generation? What are they like?"},{"v":32,"t":"They are like children who sit in the marketplace and call to one another, saying, ‘We piped to you, and you didn’t dance. We mourned, and you didn’t weep.’"},{"v":33,"t":"For John the Baptizer came neither eating bread nor drinking wine, and you say, ‘He has a demon.’"},{"v":34,"t":"The Son of Man has come eating and drinking, and you say, ‘Behold, a glutton and a drunkard, a friend of tax collectors and sinners!’"},{"v":35,"t":"Wisdom is justified by all her children.”"},{"v":36,"t":"One of the Pharisees invited him to eat with him. He entered into the Pharisee’s house and sat at the table."},{"v":37,"t":"Behold, a woman in the city who was a sinner, when she knew that he was reclining in the Pharisee’s house, brought an alabaster jar of ointment."},{"v":38,"t":"Standing behind at his feet weeping, she began to wet his feet with her tears, and she wiped them with the hair of her head, kissed his feet, and anointed them with the ointment."},{"v":39,"t":"Now when the Pharisee who had invited him saw it, he said to himself, “This man, if he were a prophet, would have perceived who and what kind of woman this is who touches him, that she is a sinner.”"},{"v":40,"t":"Jesus answered him, “Simon, I have something to tell you.” He said, “Teacher, say on.”"},{"v":41,"t":"“A certain lender had two debtors. The one owed five hundred denarii, and the other fifty."},{"v":42,"t":"When they couldn’t pay, he forgave them both. Which of them therefore will love him most?”"},{"v":43,"t":"Simon answered, “He, I suppose, to whom he forgave the most.” He said to him, “You have judged correctly.”"},{"v":44,"t":"Turning to the woman, he said to Simon, “Do you see this woman? I entered into your house, and you gave me no water for my feet, but she has wet my feet with her tears, and wiped them with the hair of her head."},{"v":45,"t":"You gave me no kiss, but she, since the time I came in, has not ceased to kiss my feet."},{"v":46,"t":"You didn’t anoint my head with oil, but she has anointed my feet with ointment."},{"v":47,"t":"Therefore I tell you, her sins, which are many, are forgiven, for she loved much. But one to whom little is forgiven, loves little.”"},{"v":48,"t":"He said to her, “Your sins are forgiven.”"},{"v":49,"t":"Those who sat at the table with him began to say to themselves, “Who is this who even forgives sins?”"},{"v":50,"t":"He said to the woman, “Your faith has saved you. Go in peace.”"}]},"8":{"en":[{"v":1,"t":"Soon afterwards, he went about through cities and villages, preaching and bringing the good news of God’s Kingdom. With him were the twelve,"},{"v":2,"t":"and certain women who had been healed of evil spirits and infirmities: Mary who was called Magdalene, from whom seven demons had gone out;"},{"v":3,"t":"and Joanna, the wife of Chuzas, Herod’s steward; Susanna; and many others who served them from their possessions."},{"v":4,"t":"When a great multitude came together and people from every city were coming to him, he spoke by a parable:"},{"v":5,"t":"“The farmer went out to sow his seed. As he sowed, some fell along the road, and it was trampled under foot, and the birds of the sky devoured it."},{"v":6,"t":"Other seed fell on the rock, and as soon as it grew, it withered away, because it had no moisture."},{"v":7,"t":"Other fell amid the thorns, and the thorns grew with it and choked it."},{"v":8,"t":"Other fell into the good ground and grew and produced one hundred times as much fruit.” As he said these things, he called out, “He who has ears to hear, let him hear!”"},{"v":9,"t":"Then his disciples asked him, “What does this parable mean?”"},{"v":10,"t":"He said, “To you it is given to know the mysteries of God’s Kingdom, but to the rest it is given in parables, that ‘seeing they may not see, and hearing they may not understand.’"},{"v":11,"t":"“Now the parable is this: The seed is the word of God."},{"v":12,"t":"Those along the road are those who hear; then the devil comes and takes away the word from their heart, that they may not believe and be saved."},{"v":13,"t":"Those on the rock are they who, when they hear, receive the word with joy; but these have no root. They believe for a while, then fall away in time of temptation."},{"v":14,"t":"What fell among the thorns, these are those who have heard, and as they go on their way they are choked with cares, riches, and pleasures of life; and they bring no fruit to maturity."},{"v":15,"t":"Those in the good ground, these are those who with an honest and good heart, having heard the word, hold it tightly, and produce fruit with perseverance."},{"v":16,"t":"“No one, when he has lit a lamp, covers it with a container or puts it under a bed; but puts it on a stand, that those who enter in may see the light."},{"v":17,"t":"For nothing is hidden that will not be revealed, nor anything secret that will not be known and come to light."},{"v":18,"t":"Be careful therefore how you hear. For whoever has, to him will be given; and whoever doesn’t have, from him will be taken away even that which he thinks he has.”"},{"v":19,"t":"His mother and brothers came to him, and they could not come near him for the crowd."},{"v":20,"t":"Some people told him, “Your mother and your brothers stand outside, desiring to see you.”"},{"v":21,"t":"But he answered them, “My mother and my brothers are these who hear the word of God and do it.”"},{"v":22,"t":"Now on one of those days, he entered into a boat, himself and his disciples, and he said to them, “Let’s go over to the other side of the lake.” So they launched out."},{"v":23,"t":"But as they sailed, he fell asleep. A wind storm came down on the lake, and they were taking on dangerous amounts of water."},{"v":24,"t":"They came to him and awoke him, saying, “Master, Master, we are dying!” He awoke and rebuked the wind and the raging of the water; then they ceased, and it was calm."},{"v":25,"t":"He said to them, “Where is your faith?” Being afraid, they marveled, saying to one another, “Who is this then, that he commands even the winds and the water, and they obey him?”"},{"v":26,"t":"Then they arrived at the country of the Gadarenes, which is opposite Galilee."},{"v":27,"t":"When Jesus stepped ashore, a certain man out of the city who had demons for a long time met him. He wore no clothes, and didn’t live in a house, but in the tombs."},{"v":28,"t":"When he saw Jesus, he cried out and fell down before him, and with a loud voice said, “What do I have to do with you, Jesus, you Son of the Most High God? I beg you, don’t torment me!”"},{"v":29,"t":"For Jesus was commanding the unclean spirit to come out of the man. For the unclean spirit had often seized the man. He was kept under guard and bound with chains and fetters. Breaking the bonds apart, he was driven by the demon into the desert."},{"v":30,"t":"Jesus asked him, “What is your name?” He said, “Legion,” for many demons had entered into him."},{"v":31,"t":"They begged him that he would not command them to go into the abyss."},{"v":32,"t":"Now there was there a herd of many pigs feeding on the mountain, and they begged him that he would allow them to enter into those. Then he allowed them."},{"v":33,"t":"The demons came out of the man and entered into the pigs, and the herd rushed down the steep bank into the lake and were drowned."},{"v":34,"t":"When those who fed them saw what had happened, they fled and told it in the city and in the country."},{"v":35,"t":"People went out to see what had happened. They came to Jesus and found the man from whom the demons had gone out, sitting at Jesus’ feet, clothed and in his right mind; and they were afraid."},{"v":36,"t":"Those who saw it told them how he who had been possessed by demons was healed."},{"v":37,"t":"All the people of the surrounding country of the Gadarenes asked him to depart from them, for they were very much afraid. Then he entered into the boat and returned."},{"v":38,"t":"But the man from whom the demons had gone out begged him that he might go with him, but Jesus sent him away, saying,"},{"v":39,"t":"“Return to your house, and declare what great things God has done for you.” He went his way, proclaiming throughout the whole city what great things Jesus had done for him."},{"v":40,"t":"When Jesus returned, the multitude welcomed him, for they were all waiting for him."},{"v":41,"t":"Behold, a man named Jairus came. He was a ruler of the synagogue. He fell down at Jesus’ feet and begged him to come into his house,"},{"v":42,"t":"for he had an only born daughter, about twelve years of age, and she was dying. But as he went, the multitudes pressed against him."},{"v":43,"t":"A woman who had a flow of blood for twelve years, who had spent all her living on physicians and could not be healed by any,"},{"v":44,"t":"came behind him and touched the fringe of his cloak. Immediately the flow of her blood stopped."},{"v":45,"t":"Jesus said, “Who touched me?” When all denied it, Peter and those with him said, “Master, the multitudes press and jostle you, and you say, ‘Who touched me?’”"},{"v":46,"t":"But Jesus said, “Someone did touch me, for I perceived that power has gone out of me.”"},{"v":47,"t":"When the woman saw that she was not hidden, she came trembling; and falling down before him declared to him in the presence of all the people the reason why she had touched him, and how she was healed immediately."},{"v":48,"t":"He said to her, “Daughter, cheer up. Your faith has made you well. Go in peace.”"},{"v":49,"t":"While he still spoke, one from the ruler of the synagogue’s house came, saying to him, “Your daughter is dead. Don’t trouble the Teacher.”"},{"v":50,"t":"But Jesus hearing it, answered him, “Don’t be afraid. Only believe, and she will be healed.”"},{"v":51,"t":"When he came to the house, he didn’t allow anyone to enter in, except Peter, John, James, the father of the child, and her mother."},{"v":52,"t":"All were weeping and mourning her, but he said, “Don’t weep. She isn’t dead, but sleeping.”"},{"v":53,"t":"They were ridiculing him, knowing that she was dead."},{"v":54,"t":"But he put them all outside, and taking her by the hand, he called, saying, “Child, arise!”"},{"v":55,"t":"Her spirit returned, and she rose up immediately. He commanded that something be given to her to eat."},{"v":56,"t":"Her parents were amazed, but he commanded them to tell no one what had been done."}]},"9":{"en":[{"v":1,"t":"He called the twelve together and gave them power and authority over all demons, and to cure diseases."},{"v":2,"t":"He sent them out to preach God’s Kingdom and to heal the sick."},{"v":3,"t":"He said to them, “Take nothing for your journey—no staffs, nor wallet, nor bread, nor money. Don’t have two tunics each."},{"v":4,"t":"Into whatever house you enter, stay there, and depart from there."},{"v":5,"t":"As many as don’t receive you, when you depart from that city, shake off even the dust from your feet for a testimony against them.”"},{"v":6,"t":"They departed and went throughout the villages, preaching the Good News and healing everywhere."},{"v":7,"t":"Now Herod the tetrarch heard of all that was done by him; and he was very perplexed, because it was said by some that John had risen from the dead,"},{"v":8,"t":"and by some that Elijah had appeared, and by others that one of the old prophets had risen again."},{"v":9,"t":"Herod said, “I beheaded John, but who is this about whom I hear such things?” He sought to see him."},{"v":10,"t":"The apostles, when they had returned, told him what things they had done. He took them and withdrew apart to a desert region of a city called Bethsaida."},{"v":11,"t":"But the multitudes, perceiving it, followed him. He welcomed them, spoke to them of God’s Kingdom, and he cured those who needed healing."},{"v":12,"t":"The day began to wear away; and the twelve came and said to him, “Send the multitude away, that they may go into the surrounding villages and farms and lodge and get food, for we are here in a deserted place.”"},{"v":13,"t":"But he said to them, “You give them something to eat.” They said, “We have no more than five loaves and two fish, unless we should go and buy food for all these people.”"},{"v":14,"t":"For they were about five thousand men. He said to his disciples, “Make them sit down in groups of about fifty each.”"},{"v":15,"t":"They did so, and made them all sit down."},{"v":16,"t":"He took the five loaves and the two fish, and looking up to the sky, he blessed them, broke them, and gave them to the disciples to set before the multitude."},{"v":17,"t":"They ate and were all filled. They gathered up twelve baskets of broken pieces that were left over."},{"v":18,"t":"As he was praying alone, the disciples were near him, and he asked them, “Who do the multitudes say that I am?”"},{"v":19,"t":"They answered, “‘John the Baptizer,’ but others say, ‘Elijah,’ and others, that one of the old prophets has risen again.”"},{"v":20,"t":"He said to them, “But who do you say that I am?” Peter answered, “The Christ of God.”"},{"v":21,"t":"But he warned them and commanded them to tell this to no one,"},{"v":22,"t":"saying, “The Son of Man must suffer many things, and be rejected by the elders, chief priests, and scribes, and be killed, and the third day be raised up.”"},{"v":23,"t":"He said to all, “If anyone desires to come after me, let him deny himself, take up his cross, and follow me."},{"v":24,"t":"For whoever desires to save his life will lose it, but whoever will lose his life for my sake will save it."},{"v":25,"t":"For what does it profit a man if he gains the whole world, and loses or forfeits his own self?"},{"v":26,"t":"For whoever will be ashamed of me and of my words, of him will the Son of Man be ashamed when he comes in his glory, and the glory of the Father, and of the holy angels."},{"v":27,"t":"But I tell you the truth: There are some of those who stand here who will in no way taste of death until they see God’s Kingdom.”"},{"v":28,"t":"About eight days after these sayings, he took with him Peter, John, and James, and went up onto the mountain to pray."},{"v":29,"t":"As he was praying, the appearance of his face was altered, and his clothing became white and dazzling."},{"v":30,"t":"Behold, two men were talking with him, who were Moses and Elijah,"},{"v":31,"t":"who appeared in glory and spoke of his departure, which he was about to accomplish at Jerusalem."},{"v":32,"t":"Now Peter and those who were with him were heavy with sleep, but when they were fully awake, they saw his glory, and the two men who stood with him."},{"v":33,"t":"As they were parting from him, Peter said to Jesus, “Master, it is good for us to be here. Let’s make three tents: one for you, one for Moses, and one for Elijah,” not knowing what he said."},{"v":34,"t":"While he said these things, a cloud came and overshadowed them, and they were afraid as they entered into the cloud."},{"v":35,"t":"A voice came out of the cloud, saying, “This is my beloved Son. Listen to him!”"},{"v":36,"t":"When the voice came, Jesus was found alone. They were silent, and told no one in those days any of the things which they had seen."},{"v":37,"t":"On the next day, when they had come down from the mountain, a great multitude met him."},{"v":38,"t":"Behold, a man from the crowd called out, saying, “Teacher, I beg you to look at my son, for he is my only born child."},{"v":39,"t":"Behold, a spirit takes him, he suddenly cries out, and it convulses him so that he foams; and it hardly departs from him, bruising him severely."},{"v":40,"t":"I begged your disciples to cast it out, and they couldn’t.”"},{"v":41,"t":"Jesus answered, “Faithless and perverse generation, how long shall I be with you and bear with you? Bring your son here.”"},{"v":42,"t":"While he was still coming, the demon threw him down and convulsed him violently. But Jesus rebuked the unclean spirit, healed the boy, and gave him back to his father."},{"v":43,"t":"They were all astonished at the majesty of God. But while all were marveling at all the things which Jesus did, he said to his disciples,"},{"v":44,"t":"“Let these words sink into your ears, for the Son of Man will be delivered up into the hands of men.”"},{"v":45,"t":"But they didn’t understand this saying. It was concealed from them, that they should not perceive it, and they were afraid to ask him about this saying."},{"v":46,"t":"An argument arose among them about which of them was the greatest."},{"v":47,"t":"Jesus, perceiving the reasoning of their hearts, took a little child, and set him by his side,"},{"v":48,"t":"and said to them, “Whoever receives this little child in my name receives me. Whoever receives me receives him who sent me. For whoever is least among you all, this one will be great.”"},{"v":49,"t":"John answered, “Master, we saw someone casting out demons in your name, and we forbade him, because he doesn’t follow with us.”"},{"v":50,"t":"Jesus said to him, “Don’t forbid him, for he who is not against us is for us.”"},{"v":51,"t":"It came to pass, when the days were near that he should be taken up, he intently set his face to go to Jerusalem"},{"v":52,"t":"and sent messengers before his face. They went and entered into a village of the Samaritans, so as to prepare for him."},{"v":53,"t":"They didn’t receive him, because he was traveling with his face set toward Jerusalem."},{"v":54,"t":"When his disciples, James and John, saw this, they said, “Lord, do you want us to command fire to come down from the sky and destroy them, just as Elijah did?”"},{"v":55,"t":"But he turned and rebuked them, “You don’t know of what kind of spirit you are."},{"v":56,"t":"For the Son of Man didn’t come to destroy men’s lives, but to save them.” They went to another village."},{"v":57,"t":"As they went on the way, a certain man said to him, “I want to follow you wherever you go, Lord.”"},{"v":58,"t":"Jesus said to him, “The foxes have holes and the birds of the sky have nests, but the Son of Man has no place to lay his head.”"},{"v":59,"t":"He said to another, “Follow me!” But he said, “Lord, allow me first to go and bury my father.”"},{"v":60,"t":"But Jesus said to him, “Leave the dead to bury their own dead, but you go and announce God’s Kingdom.”"},{"v":61,"t":"Another also said, “I want to follow you, Lord, but first allow me to say good-bye to those who are at my house.”"},{"v":62,"t":"But Jesus said to him, “No one, having put his hand to the plow and looking back, is fit for God’s Kingdom.”"}]},"10":{"en":[{"v":1,"t":"Now after these things, the Lord also appointed seventy others, and sent them two by two ahead of him into every city and place where he was about to come."},{"v":2,"t":"Then he said to them, “The harvest is indeed plentiful, but the laborers are few. Pray therefore to the Lord of the harvest, that he may send out laborers into his harvest."},{"v":3,"t":"Go your ways. Behold, I send you out as lambs among wolves."},{"v":4,"t":"Carry no purse, nor wallet, nor sandals. Greet no one on the way."},{"v":5,"t":"Into whatever house you enter, first say, ‘Peace be to this house.’"},{"v":6,"t":"If a son of peace is there, your peace will rest on him; but if not, it will return to you."},{"v":7,"t":"Remain in that same house, eating and drinking the things they give, for the laborer is worthy of his wages. Don’t go from house to house."},{"v":8,"t":"Into whatever city you enter and they receive you, eat the things that are set before you."},{"v":9,"t":"Heal the sick who are there and tell them, ‘God’s Kingdom has come near to you.’"},{"v":10,"t":"But into whatever city you enter and they don’t receive you, go out into its streets and say,"},{"v":11,"t":"‘Even the dust from your city that clings to us, we wipe off against you. Nevertheless know this, that God’s Kingdom has come near to you.’"},{"v":12,"t":"I tell you, it will be more tolerable in that day for Sodom than for that city."},{"v":13,"t":"“Woe to you, Chorazin! Woe to you, Bethsaida! For if the mighty works had been done in Tyre and Sidon which were done in you, they would have repented long ago, sitting in sackcloth and ashes."},{"v":14,"t":"But it will be more tolerable for Tyre and Sidon in the judgment than for you."},{"v":15,"t":"You, Capernaum, who are exalted to heaven, will be brought down to Hades."},{"v":16,"t":"Whoever listens to you listens to me, and whoever rejects you rejects me. Whoever rejects me rejects him who sent me.”"},{"v":17,"t":"The seventy returned with joy, saying, “Lord, even the demons are subject to us in your name!”"},{"v":18,"t":"He said to them, “I saw Satan having fallen like lightning from heaven."},{"v":19,"t":"Behold, I give you authority to tread on serpents and scorpions, and over all the power of the enemy. Nothing will in any way hurt you."},{"v":20,"t":"Nevertheless, don’t rejoice in this, that the spirits are subject to you, but rejoice that your names are written in heaven.”"},{"v":21,"t":"In that same hour, Jesus rejoiced in the Holy Spirit, and said, “I thank you, O Father, Lord of heaven and earth, that you have hidden these things from the wise and understanding, and revealed them to little children. Yes, Father, for so it was well-pleasing in your sight.”"},{"v":22,"t":"Turning to the disciples, he said, “All things have been delivered to me by my Father. No one knows who the Son is, except the Father, and who the Father is, except the Son, and he to whomever the Son desires to reveal him.”"},{"v":23,"t":"Turning to the disciples, he said privately, “Blessed are the eyes which see the things that you see,"},{"v":24,"t":"for I tell you that many prophets and kings desired to see the things which you see, and didn’t see them, and to hear the things which you hear, and didn’t hear them.”"},{"v":25,"t":"Behold, a certain lawyer stood up and tested him, saying, “Teacher, what shall I do to inherit eternal life?”"},{"v":26,"t":"He said to him, “What is written in the law? How do you read it?”"},{"v":27,"t":"He answered, “You shall love the Lord your God with all your heart, with all your soul, with all your strength, and with all your mind; and your neighbor as yourself.”"},{"v":28,"t":"He said to him, “You have answered correctly. Do this, and you will live.”"},{"v":29,"t":"But he, desiring to justify himself, asked Jesus, “Who is my neighbor?”"},{"v":30,"t":"Jesus answered, “A certain man was going down from Jerusalem to Jericho, and he fell among robbers, who both stripped him and beat him, and departed, leaving him half dead."},{"v":31,"t":"By chance a certain priest was going down that way. When he saw him, he passed by on the other side."},{"v":32,"t":"In the same way a Levite also, when he came to the place and saw him, passed by on the other side."},{"v":33,"t":"But a certain Samaritan, as he traveled, came where he was. When he saw him, he was moved with compassion,"},{"v":34,"t":"came to him, and bound up his wounds, pouring on oil and wine. He set him on his own animal, brought him to an inn, and took care of him."},{"v":35,"t":"On the next day, when he departed, he took out two denarii, gave them to the host, and said to him, ‘Take care of him. Whatever you spend beyond that, I will repay you when I return.’"},{"v":36,"t":"Now which of these three do you think seemed to be a neighbor to him who fell among the robbers?”"},{"v":37,"t":"He said, “He who showed mercy on him.” Then Jesus said to him, “Go and do likewise.”"},{"v":38,"t":"As they went on their way, he entered into a certain village, and a certain woman named Martha received him into her house."},{"v":39,"t":"She had a sister called Mary, who also sat at Jesus’ feet and heard his word."},{"v":40,"t":"But Martha was distracted with much serving, and she came up to him, and said, “Lord, don’t you care that my sister left me to serve alone? Ask her therefore to help me.”"},{"v":41,"t":"Jesus answered her, “Martha, Martha, you are anxious and troubled about many things,"},{"v":42,"t":"but one thing is needed. Mary has chosen the good part, which will not be taken away from her.”"}]},"11":{"en":[{"v":1,"t":"When he finished praying in a certain place, one of his disciples said to him, “Lord, teach us to pray, just as John also taught his disciples.”"},{"v":2,"t":"He said to them, “When you pray, say, ‘Our Father in heaven, may your name be kept holy. May your Kingdom come. May your will be done on earth, as it is in heaven."},{"v":3,"t":"Give us day by day our daily bread."},{"v":4,"t":"Forgive us our sins, for we ourselves also forgive everyone who is indebted to us. Bring us not into temptation, but deliver us from the evil one.’”"},{"v":5,"t":"He said to them, “Which of you, if you go to a friend at midnight and tell him, ‘Friend, lend me three loaves of bread,"},{"v":6,"t":"for a friend of mine has come to me from a journey, and I have nothing to set before him,’"},{"v":7,"t":"and he from within will answer and say, ‘Don’t bother me. The door is now shut, and my children are with me in bed. I can’t get up and give it to you’?"},{"v":8,"t":"I tell you, although he will not rise and give it to him because he is his friend, yet because of his persistence, he will get up and give him as many as he needs."},{"v":9,"t":"“I tell you, keep asking, and it will be given you. Keep seeking, and you will find. Keep knocking, and it will be opened to you."},{"v":10,"t":"For everyone who asks receives. He who seeks finds. To him who knocks it will be opened."},{"v":11,"t":"“Which of you fathers, if your son asks for bread, will give him a stone? Or if he asks for a fish, he won’t give him a snake instead of a fish, will he?"},{"v":12,"t":"Or if he asks for an egg, he won’t give him a scorpion, will he?"},{"v":13,"t":"If you then, being evil, know how to give good gifts to your children, how much more will your heavenly Father give the Holy Spirit to those who ask him?”"},{"v":14,"t":"He was casting out a demon, and it was mute. When the demon had gone out, the mute man spoke; and the multitudes marveled."},{"v":15,"t":"But some of them said, “He casts out demons by Beelzebul, the prince of the demons.”"},{"v":16,"t":"Others, testing him, sought from him a sign from heaven."},{"v":17,"t":"But he, knowing their thoughts, said to them, “Every kingdom divided against itself is brought to desolation. A house divided against itself falls."},{"v":18,"t":"If Satan also is divided against himself, how will his kingdom stand? For you say that I cast out demons by Beelzebul."},{"v":19,"t":"But if I cast out demons by Beelzebul, by whom do your children cast them out? Therefore they will be your judges."},{"v":20,"t":"But if I by God’s finger cast out demons, then God’s Kingdom has come to you."},{"v":21,"t":"“When the strong man, fully armed, guards his own dwelling, his goods are safe."},{"v":22,"t":"But when someone stronger attacks him and overcomes him, he takes from him his whole armor in which he trusted, and divides his plunder."},{"v":23,"t":"“He who is not with me is against me. He who doesn’t gather with me scatters."},{"v":24,"t":"The unclean spirit, when he has gone out of the man, passes through dry places, seeking rest; and finding none, he says, ‘I will turn back to my house from which I came out.’"},{"v":25,"t":"When he returns, he finds it swept and put in order."},{"v":26,"t":"Then he goes and takes seven other spirits more evil than himself, and they enter in and dwell there. The last state of that man becomes worse than the first.”"},{"v":27,"t":"It came to pass, as he said these things, a certain woman out of the multitude lifted up her voice and said to him, “Blessed is the womb that bore you, and the breasts which nursed you!”"},{"v":28,"t":"But he said, “On the contrary, blessed are those who hear the word of God, and keep it.”"},{"v":29,"t":"When the multitudes were gathering together to him, he began to say, “This is an evil generation. It seeks after a sign. No sign will be given to it but the sign of Jonah the prophet."},{"v":30,"t":"For even as Jonah became a sign to the Ninevites, so the Son of Man will also be to this generation."},{"v":31,"t":"The Queen of the South will rise up in the judgment with the men of this generation and will condemn them, for she came from the ends of the earth to hear the wisdom of Solomon; and behold, one greater than Solomon is here."},{"v":32,"t":"The men of Nineveh will stand up in the judgment with this generation, and will condemn it, for they repented at the preaching of Jonah; and behold, one greater than Jonah is here."},{"v":33,"t":"“No one, when he has lit a lamp, puts it in a cellar or under a basket, but on a stand, that those who come in may see the light."},{"v":34,"t":"The lamp of the body is the eye. Therefore when your eye is good, your whole body is also full of light; but when it is evil, your body also is full of darkness."},{"v":35,"t":"Therefore see whether the light that is in you isn’t darkness."},{"v":36,"t":"If therefore your whole body is full of light, having no part dark, it will be wholly full of light, as when the lamp with its bright shining gives you light.”"},{"v":37,"t":"Now as he spoke, a certain Pharisee asked him to dine with him. He went in and sat at the table."},{"v":38,"t":"When the Pharisee saw it, he marveled that he had not first washed himself before dinner."},{"v":39,"t":"The Lord said to him, “Now you Pharisees cleanse the outside of the cup and of the platter, but your inward part is full of extortion and wickedness."},{"v":40,"t":"You foolish ones, didn’t he who made the outside make the inside also?"},{"v":41,"t":"But give for gifts to the needy those things which are within, and behold, all things will be clean to you."},{"v":42,"t":"But woe to you Pharisees! For you tithe mint and rue and every herb, but you bypass justice and God’s love. You ought to have done these, and not to have left the other undone."},{"v":43,"t":"Woe to you Pharisees! For you love the best seats in the synagogues and the greetings in the marketplaces."},{"v":44,"t":"Woe to you, scribes and Pharisees, hypocrites! For you are like hidden graves, and the men who walk over them don’t know it.”"},{"v":45,"t":"One of the lawyers answered him, “Teacher, in saying this you insult us also.”"},{"v":46,"t":"He said, “Woe to you lawyers also! For you load men with burdens that are difficult to carry, and you yourselves won’t even lift one finger to help carry those burdens."},{"v":47,"t":"Woe to you! For you build the tombs of the prophets, and your fathers killed them."},{"v":48,"t":"So you testify and consent to the works of your fathers. For they killed them, and you build their tombs."},{"v":49,"t":"Therefore also the wisdom of God said, ‘I will send to them prophets and apostles; and some of them they will kill and persecute,"},{"v":50,"t":"that the blood of all the prophets, which was shed from the foundation of the world, may be required of this generation,"},{"v":51,"t":"from the blood of Abel to the blood of Zachariah, who perished between the altar and the sanctuary.’ Yes, I tell you, it will be required of this generation."},{"v":52,"t":"Woe to you lawyers! For you took away the key of knowledge. You didn’t enter in yourselves, and those who were entering in, you hindered.”"},{"v":53,"t":"As he said these things to them, the scribes and the Pharisees began to be terribly angry, and to draw many things out of him,"},{"v":54,"t":"lying in wait for him, and seeking to catch him in something he might say, that they might accuse him."}]},"12":{"en":[{"v":1,"t":"Meanwhile, when a multitude of many thousands had gathered together, so much so that they trampled on each other, he began to tell his disciples first of all, “Beware of the yeast of the Pharisees, which is hypocrisy."},{"v":2,"t":"But there is nothing covered up that will not be revealed, nor hidden that will not be known."},{"v":3,"t":"Therefore whatever you have said in the darkness will be heard in the light. What you have spoken in the ear in the inner rooms will be proclaimed on the housetops."},{"v":4,"t":"“I tell you, my friends, don’t be afraid of those who kill the body, and after that have no more that they can do."},{"v":5,"t":"But I will warn you whom you should fear. Fear him who after he has killed, has power to cast into Gehenna. Yes, I tell you, fear him."},{"v":6,"t":"“Aren’t five sparrows sold for two assaria coins? Not one of them is forgotten by God."},{"v":7,"t":"But the very hairs of your head are all counted. Therefore don’t be afraid. You are of more value than many sparrows."},{"v":8,"t":"“I tell you, everyone who confesses me before men, the Son of Man will also confess before the angels of God;"},{"v":9,"t":"but he who denies me in the presence of men will be denied in the presence of God’s angels."},{"v":10,"t":"Everyone who speaks a word against the Son of Man will be forgiven, but those who blaspheme against the Holy Spirit will not be forgiven."},{"v":11,"t":"When they bring you before the synagogues, the rulers, and the authorities, don’t be anxious how or what you will answer or what you will say;"},{"v":12,"t":"for the Holy Spirit will teach you in that same hour what you must say.”"},{"v":13,"t":"One of the multitude said to him, “Teacher, tell my brother to divide the inheritance with me.”"},{"v":14,"t":"But he said to him, “Man, who made me a judge or an arbitrator over you?”"},{"v":15,"t":"He said to them, “Beware! Keep yourselves from covetousness, for a man’s life doesn’t consist of the abundance of the things which he possesses.”"},{"v":16,"t":"He spoke a parable to them, saying, “The ground of a certain rich man produced abundantly."},{"v":17,"t":"He reasoned within himself, saying, ‘What will I do, because I don’t have room to store my crops?’"},{"v":18,"t":"He said, ‘This is what I will do. I will pull down my barns, build bigger ones, and there I will store all my grain and my goods."},{"v":19,"t":"I will tell my soul, “Soul, you have many goods laid up for many years. Take your ease, eat, drink, and be merry.”’"},{"v":20,"t":"“But God said to him, ‘You foolish one, tonight your soul is required of you. The things which you have prepared—whose will they be?’"},{"v":21,"t":"So is he who lays up treasure for himself, and is not rich toward God.”"},{"v":22,"t":"He said to his disciples, “Therefore I tell you, don’t be anxious for your life, what you will eat, nor yet for your body, what you will wear."},{"v":23,"t":"Life is more than food, and the body is more than clothing."},{"v":24,"t":"Consider the ravens: they don’t sow, they don’t reap, they have no warehouse or barn, and God feeds them. How much more valuable are you than birds!"},{"v":25,"t":"Which of you by being anxious can add a cubit to his height?"},{"v":26,"t":"If then you aren’t able to do even the least things, why are you anxious about the rest?"},{"v":27,"t":"Consider the lilies, how they grow. They don’t toil, neither do they spin; yet I tell you, even Solomon in all his glory was not arrayed like one of these."},{"v":28,"t":"But if this is how God clothes the grass in the field, which today exists and tomorrow is cast into the oven, how much more will he clothe you, O you of little faith?"},{"v":29,"t":"“Don’t seek what you will eat or what you will drink; neither be anxious."},{"v":30,"t":"For the nations of the world seek after all of these things, but your Father knows that you need these things."},{"v":31,"t":"But seek God’s Kingdom, and all these things will be added to you."},{"v":32,"t":"“Don’t be afraid, little flock, for it is your Father’s good pleasure to give you the Kingdom."},{"v":33,"t":"Sell what you have and give gifts to the needy. Make for yourselves purses which don’t grow old, a treasure in the heavens that doesn’t fail, where no thief approaches and no moth destroys."},{"v":34,"t":"For where your treasure is, there will your heart be also."},{"v":35,"t":"“Let your waist be dressed and your lamps burning."},{"v":36,"t":"Be like men watching for their lord when he returns from the wedding feast, that when he comes and knocks, they may immediately open to him."},{"v":37,"t":"Blessed are those servants whom the lord will find watching when he comes. Most certainly I tell you that he will dress himself, make them recline, and will come and serve them."},{"v":38,"t":"They will be blessed if he comes in the second or third watch and finds them so."},{"v":39,"t":"But know this, that if the master of the house had known in what hour the thief was coming, he would have watched and not allowed his house to be broken into."},{"v":40,"t":"Therefore be ready also, for the Son of Man is coming in an hour that you don’t expect him.”"},{"v":41,"t":"Peter said to him, “Lord, are you telling this parable to us, or to everybody?”"},{"v":42,"t":"The Lord said, “Who then is the faithful and wise steward, whom his lord will set over his household, to give them their portion of food at the right times?"},{"v":43,"t":"Blessed is that servant whom his lord will find doing so when he comes."},{"v":44,"t":"Truly I tell you that he will set him over all that he has."},{"v":45,"t":"But if that servant says in his heart, ‘My lord delays his coming,’ and begins to beat the menservants and the maidservants, and to eat and drink and to be drunken,"},{"v":46,"t":"then the lord of that servant will come in a day when he isn’t expecting him and in an hour that he doesn’t know, and will cut him in two, and place his portion with the unfaithful."},{"v":47,"t":"That servant who knew his lord’s will, and didn’t prepare nor do what he wanted, will be beaten with many stripes,"},{"v":48,"t":"but he who didn’t know, and did things worthy of stripes, will be beaten with few stripes. To whomever much is given, of him will much be required; and to whom much was entrusted, of him more will be asked."},{"v":49,"t":"“I came to throw fire on the earth. I wish it were already kindled."},{"v":50,"t":"But I have a baptism to be baptized with, and how distressed I am until it is accomplished!"},{"v":51,"t":"Do you think that I have come to give peace in the earth? I tell you, no, but rather division."},{"v":52,"t":"For from now on, there will be five in one house divided, three against two, and two against three."},{"v":53,"t":"They will be divided, father against son, and son against father; mother against daughter, and daughter against her mother; mother-in-law against her daughter-in-law, and daughter-in-law against her mother-in-law.”"},{"v":54,"t":"He said to the multitudes also, “When you see a cloud rising from the west, immediately you say, ‘A shower is coming,’ and so it happens."},{"v":55,"t":"When a south wind blows, you say, ‘There will be a scorching heat,’ and it happens."},{"v":56,"t":"You hypocrites! You know how to interpret the appearance of the earth and the sky, but how is it that you don’t interpret this time?"},{"v":57,"t":"“Why don’t you judge for yourselves what is right?"},{"v":58,"t":"For when you are going with your adversary before the magistrate, try diligently on the way to be released from him, lest perhaps he drag you to the judge, and the judge deliver you to the officer, and the officer throw you into prison."},{"v":59,"t":"I tell you, you will by no means get out of there until you have paid the very last penny.”"}]},"13":{"en":[{"v":1,"t":"Now there were some present at the same time who told him about the Galileans whose blood Pilate had mixed with their sacrifices."},{"v":2,"t":"Jesus answered them, “Do you think that these Galileans were worse sinners than all the other Galileans, because they suffered such things?"},{"v":3,"t":"I tell you, no, but unless you repent, you will all perish in the same way."},{"v":4,"t":"Or those eighteen on whom the tower in Siloam fell and killed them—do you think that they were worse offenders than all the men who dwell in Jerusalem?"},{"v":5,"t":"I tell you, no, but, unless you repent, you will all perish in the same way.”"},{"v":6,"t":"He spoke this parable. “A certain man had a fig tree planted in his vineyard, and he came seeking fruit on it and found none."},{"v":7,"t":"He said to the vine dresser, ‘Behold, these three years I have come looking for fruit on this fig tree, and found none. Cut it down! Why does it waste the soil?’"},{"v":8,"t":"He answered, ‘Lord, leave it alone this year also, until I dig around it and fertilize it."},{"v":9,"t":"If it bears fruit, fine; but if not, after that, you can cut it down.’”"},{"v":10,"t":"He was teaching in one of the synagogues on the Sabbath day."},{"v":11,"t":"Behold, there was a woman who had a spirit of infirmity eighteen years. She was bent over and could in no way straighten herself up."},{"v":12,"t":"When Jesus saw her, he called her and said to her, “Woman, you are freed from your infirmity.”"},{"v":13,"t":"He laid his hands on her, and immediately she stood up straight and glorified God."},{"v":14,"t":"The ruler of the synagogue, being indignant because Jesus had healed on the Sabbath, said to the multitude, “There are six days in which men ought to work. Therefore come on those days and be healed, and not on the Sabbath day!”"},{"v":15,"t":"Therefore the Lord answered him, “You hypocrites! Doesn’t each one of you free his ox or his donkey from the stall on the Sabbath and lead him away to water?"},{"v":16,"t":"Ought not this woman, being a daughter of Abraham whom Satan had bound eighteen long years, be freed from this bondage on the Sabbath day?”"},{"v":17,"t":"As he said these things, all his adversaries were disappointed; and all the multitude rejoiced for all the glorious things that were done by him."},{"v":18,"t":"He said, “What is God’s Kingdom like? To what shall I compare it?"},{"v":19,"t":"It is like a grain of mustard seed which a man took and put in his own garden. It grew and became a large tree, and the birds of the sky live in its branches.”"},{"v":20,"t":"Again he said, “To what shall I compare God’s Kingdom?"},{"v":21,"t":"It is like yeast, which a woman took and hid in three measures of flour, until it was all leavened.”"},{"v":22,"t":"He went on his way through cities and villages, teaching, and traveling on to Jerusalem."},{"v":23,"t":"One said to him, “Lord, are they few who are saved?” He said to them,"},{"v":24,"t":"“Strive to enter in by the narrow door, for many, I tell you, will seek to enter in and will not be able."},{"v":25,"t":"When once the master of the house has risen up and has shut the door, and you begin to stand outside and to knock at the door, saying, ‘Lord, Lord, open to us!’ then he will answer and tell you, ‘I don’t know you or where you come from.’"},{"v":26,"t":"Then you will begin to say, ‘We ate and drank in your presence, and you taught in our streets.’"},{"v":27,"t":"He will say, ‘I tell you, I don’t know where you come from. Depart from me, all you workers of iniquity.’"},{"v":28,"t":"There will be weeping and gnashing of teeth when you see Abraham, Isaac, Jacob, and all the prophets in God’s Kingdom, and yourselves being thrown outside."},{"v":29,"t":"They will come from the east, west, north, and south, and will sit down in God’s Kingdom."},{"v":30,"t":"Behold, there are some who are last who will be first, and there are some who are first who will be last.”"},{"v":31,"t":"On that same day, some Pharisees came, saying to him, “Get out of here and go away, for Herod wants to kill you.”"},{"v":32,"t":"He said to them, “Go and tell that fox, ‘Behold, I cast out demons and perform cures today and tomorrow, and the third day I complete my mission."},{"v":33,"t":"Nevertheless I must go on my way today and tomorrow and the next day, for it can’t be that a prophet would perish outside of Jerusalem.’"},{"v":34,"t":"“Jerusalem, Jerusalem, you who kills the prophets and stones those who are sent to her! How often I wanted to gather your children together, like a hen gathers her own brood under her wings, and you refused!"},{"v":35,"t":"Behold, your house is left to you desolate. I tell you, you will not see me until you say, ‘Blessed is he who comes in the name of the Lord!’”"}]},"14":{"en":[{"v":1,"t":"When he went into the house of one of the rulers of the Pharisees on a Sabbath to eat bread, they were watching him."},{"v":2,"t":"Behold, a certain man who had dropsy was in front of him."},{"v":3,"t":"Jesus, answering, spoke to the lawyers and Pharisees, saying, “Is it lawful to heal on the Sabbath?”"},{"v":4,"t":"But they were silent. He took him, and healed him, and let him go."},{"v":5,"t":"He answered them, “Which of you, if your son or an ox fell into a well, wouldn’t immediately pull him out on a Sabbath day?”"},{"v":6,"t":"They couldn’t answer him regarding these things."},{"v":7,"t":"He spoke a parable to those who were invited, when he noticed how they chose the best seats, and said to them,"},{"v":8,"t":"“When you are invited by anyone to a wedding feast, don’t sit in the best seat, since perhaps someone more honorable than you might be invited by him,"},{"v":9,"t":"and he who invited both of you would come and tell you, ‘Make room for this person.’ Then you would begin, with shame, to take the lowest place."},{"v":10,"t":"But when you are invited, go and sit in the lowest place, so that when he who invited you comes, he may tell you, ‘Friend, move up higher.’ Then you will be honored in the presence of all who sit at the table with you."},{"v":11,"t":"For everyone who exalts himself will be humbled, and whoever humbles himself will be exalted.”"},{"v":12,"t":"He also said to the one who had invited him, “When you make a dinner or a supper, don’t call your friends, nor your brothers, nor your kinsmen, nor rich neighbors, or perhaps they might also return the favor, and pay you back."},{"v":13,"t":"But when you make a feast, ask the poor, the maimed, the lame, or the blind;"},{"v":14,"t":"and you will be blessed, because they don’t have the resources to repay you. For you will be repaid in the resurrection of the righteous.”"},{"v":15,"t":"When one of those who sat at the table with him heard these things, he said to him, “Blessed is he who will feast in God’s Kingdom!”"},{"v":16,"t":"But he said to him, “A certain man made a great supper, and he invited many people."},{"v":17,"t":"He sent out his servant at supper time to tell those who were invited, ‘Come, for everything is ready now.’"},{"v":18,"t":"They all as one began to make excuses. “The first said to him, ‘I have bought a field, and I must go and see it. Please have me excused.’"},{"v":19,"t":"“Another said, ‘I have bought five yoke of oxen, and I must go try them out. Please have me excused.’"},{"v":20,"t":"“Another said, ‘I have married a wife, and therefore I can’t come.’"},{"v":21,"t":"“That servant came, and told his lord these things. Then the master of the house, being angry, said to his servant, ‘Go out quickly into the streets and lanes of the city, and bring in the poor, maimed, blind, and lame.’"},{"v":22,"t":"“The servant said, ‘Lord, it is done as you commanded, and there is still room.’"},{"v":23,"t":"“The lord said to the servant, ‘Go out into the highways and hedges, and compel them to come in, that my house may be filled."},{"v":24,"t":"For I tell you that none of those men who were invited will taste of my supper. For many are called, but few are chosen.’”"},{"v":25,"t":"Now great multitudes were going with him. He turned and said to them,"},{"v":26,"t":"“If anyone comes to me, and doesn’t disregard his own father, mother, wife, children, brothers, and sisters, yes, and his own life also, he can’t be my disciple."},{"v":27,"t":"Whoever doesn’t bear his own cross and come after me, can’t be my disciple."},{"v":28,"t":"For which of you, desiring to build a tower, doesn’t first sit down and count the cost, to see if he has enough to complete it?"},{"v":29,"t":"Or perhaps, when he has laid a foundation and isn’t able to finish, everyone who sees begins to mock him,"},{"v":30,"t":"saying, ‘This man began to build and wasn’t able to finish.’"},{"v":31,"t":"Or what king, as he goes to encounter another king in war, will not sit down first and consider whether he is able with ten thousand to meet him who comes against him with twenty thousand?"},{"v":32,"t":"Or else, while the other is yet a great way off, he sends an envoy and asks for conditions of peace."},{"v":33,"t":"So therefore, whoever of you who doesn’t renounce all that he has, he can’t be my disciple."},{"v":34,"t":"“Salt is good, but if the salt becomes flat and tasteless, with what do you season it?"},{"v":35,"t":"It is fit neither for the soil nor for the manure pile. It is thrown out. He who has ears to hear, let him hear.”"}]},"15":{"en":[{"v":1,"t":"Now all the tax collectors and sinners were coming close to him to hear him."},{"v":2,"t":"The Pharisees and the scribes murmured, saying, “This man welcomes sinners, and eats with them.”"},{"v":3,"t":"He told them this parable:"},{"v":4,"t":"“Which of you men, if you had one hundred sheep and lost one of them, wouldn’t leave the ninety-nine in the wilderness and go after the one that was lost, until he found it?"},{"v":5,"t":"When he has found it, he carries it on his shoulders, rejoicing."},{"v":6,"t":"When he comes home, he calls together his friends and his neighbors, saying to them, ‘Rejoice with me, for I have found my sheep which was lost!’"},{"v":7,"t":"I tell you that even so there will be more joy in heaven over one sinner who repents, than over ninety-nine righteous people who need no repentance."},{"v":8,"t":"“Or what woman, if she had ten drachma coins, if she lost one drachma coin, wouldn’t light a lamp, sweep the house, and seek diligently until she found it?"},{"v":9,"t":"When she has found it, she calls together her friends and neighbors, saying, ‘Rejoice with me, for I have found the drachma which I had lost!’"},{"v":10,"t":"Even so, I tell you, there is joy in the presence of the angels of God over one sinner repenting.”"},{"v":11,"t":"He said, “A certain man had two sons."},{"v":12,"t":"The younger of them said to his father, ‘Father, give me my share of your property.’ So he divided his livelihood between them."},{"v":13,"t":"Not many days after, the younger son gathered all of this together and traveled into a far country. There he wasted his property with riotous living."},{"v":14,"t":"When he had spent all of it, there arose a severe famine in that country, and he began to be in need."},{"v":15,"t":"He went and joined himself to one of the citizens of that country, and he sent him into his fields to feed pigs."},{"v":16,"t":"He wanted to fill his belly with the pods that the pigs ate, but no one gave him any."},{"v":17,"t":"But when he came to himself, he said, ‘How many hired servants of my father’s have bread enough to spare, and I’m dying with hunger!"},{"v":18,"t":"I will get up and go to my father, and will tell him, “Father, I have sinned against heaven and in your sight."},{"v":19,"t":"I am no more worthy to be called your son. Make me as one of your hired servants.”’"},{"v":20,"t":"“He arose and came to his father. But while he was still far off, his father saw him and was moved with compassion, and ran, fell on his neck, and kissed him."},{"v":21,"t":"The son said to him, ‘Father, I have sinned against heaven and in your sight. I am no longer worthy to be called your son.’"},{"v":22,"t":"“But the father said to his servants, ‘Bring out the best robe and put it on him. Put a ring on his hand and sandals on his feet."},{"v":23,"t":"Bring the fattened calf, kill it, and let’s eat and celebrate;"},{"v":24,"t":"for this, my son, was dead and is alive again. He was lost and is found.’ Then they began to celebrate."},{"v":25,"t":"“Now his elder son was in the field. As he came near to the house, he heard music and dancing."},{"v":26,"t":"He called one of the servants to him and asked what was going on."},{"v":27,"t":"He said to him, ‘Your brother has come, and your father has killed the fattened calf, because he has received him back safe and healthy.’"},{"v":28,"t":"But he was angry and would not go in. Therefore his father came out and begged him."},{"v":29,"t":"But he answered his father, ‘Behold, these many years I have served you, and I never disobeyed a commandment of yours, but you never gave me a goat, that I might celebrate with my friends."},{"v":30,"t":"But when this your son came, who has devoured your living with prostitutes, you killed the fattened calf for him.’"},{"v":31,"t":"“He said to him, ‘Son, you are always with me, and all that is mine is yours."},{"v":32,"t":"But it was appropriate to celebrate and be glad, for this, your brother, was dead, and is alive again. He was lost, and is found.’”"}]},"16":{"en":[{"v":1,"t":"He also said to his disciples, “There was a certain rich man who had a manager. An accusation was made to him that this man was wasting his possessions."},{"v":2,"t":"He called him, and said to him, ‘What is this that I hear about you? Give an accounting of your management, for you can no longer be manager.’"},{"v":3,"t":"“The manager said within himself, ‘What will I do, seeing that my lord is taking away the management position from me? I don’t have strength to dig. I am ashamed to beg."},{"v":4,"t":"I know what I will do, so that when I am removed from management, they may receive me into their houses.’"},{"v":5,"t":"Calling each one of his lord’s debtors to him, he said to the first, ‘How much do you owe to my lord?’"},{"v":6,"t":"He said, ‘A hundred batos of oil.’ He said to him, ‘Take your bill, and sit down quickly and write fifty.’"},{"v":7,"t":"Then he said to another, ‘How much do you owe?’ He said, ‘A hundred cors of wheat.’ He said to him, ‘Take your bill, and write eighty.’"},{"v":8,"t":"“His lord commended the dishonest manager because he had done wisely, for the children of this world are, in their own generation, wiser than the children of the light."},{"v":9,"t":"I tell you, make for yourselves friends by means of unrighteous mammon, so that when you fail, they may receive you into the eternal tents."},{"v":10,"t":"He who is faithful in a very little is faithful also in much. He who is dishonest in a very little is also dishonest in much."},{"v":11,"t":"If therefore you have not been faithful in the unrighteous mammon, who will commit to your trust the true riches?"},{"v":12,"t":"If you have not been faithful in that which is another’s, who will give you that which is your own?"},{"v":13,"t":"No servant can serve two masters, for either he will hate the one and love the other; or else he will hold to one and despise the other. You aren’t able to serve God and Mammon.”"},{"v":14,"t":"The Pharisees, who were lovers of money, also heard all these things, and they scoffed at him."},{"v":15,"t":"He said to them, “You are those who justify yourselves in the sight of men, but God knows your hearts. For that which is exalted among men is an abomination in the sight of God."},{"v":16,"t":"“The law and the prophets were until John. From that time the Good News of God’s Kingdom is preached, and everyone is forcing his way into it."},{"v":17,"t":"But it is easier for heaven and earth to pass away than for one tiny stroke of a pen in the law to fall."},{"v":18,"t":"“Everyone who divorces his wife and marries another commits adultery. He who marries one who is divorced from a husband commits adultery."},{"v":19,"t":"“Now there was a certain rich man, and he was clothed in purple and fine linen, living in luxury every day."},{"v":20,"t":"A certain beggar, named Lazarus, was taken to his gate, full of sores,"},{"v":21,"t":"and desiring to be fed with the crumbs that fell from the rich man’s table. Yes, even the dogs came and licked his sores."},{"v":22,"t":"The beggar died, and he was carried away by the angels to Abraham’s bosom. The rich man also died and was buried."},{"v":23,"t":"In Hades, he lifted up his eyes, being in torment, and saw Abraham far off, and Lazarus at his bosom."},{"v":24,"t":"He cried and said, ‘Father Abraham, have mercy on me, and send Lazarus, that he may dip the tip of his finger in water and cool my tongue! For I am in anguish in this flame.’"},{"v":25,"t":"“But Abraham said, ‘Son, remember that you, in your lifetime, received your good things, and Lazarus, in the same way, bad things. But here he is now comforted and you are in anguish."},{"v":26,"t":"Besides all this, between us and you there is a great gulf fixed, that those who want to pass from here to you are not able, and that no one may cross over from there to us.’"},{"v":27,"t":"“He said, ‘I ask you therefore, father, that you would send him to my father’s house—"},{"v":28,"t":"for I have five brothers—that he may testify to them, so they won’t also come into this place of torment.’"},{"v":29,"t":"“But Abraham said to him, ‘They have Moses and the prophets. Let them listen to them.’"},{"v":30,"t":"“He said, ‘No, father Abraham, but if one goes to them from the dead, they will repent.’"},{"v":31,"t":"“He said to him, ‘If they don’t listen to Moses and the prophets, neither will they be persuaded if one rises from the dead.’”"}]},"17":{"en":[{"v":1,"t":"He said to the disciples, “It is impossible that no occasions of stumbling should come, but woe to him through whom they come!"},{"v":2,"t":"It would be better for him if a millstone were hung around his neck, and he were thrown into the sea, rather than that he should cause one of these little ones to stumble."},{"v":3,"t":"Be careful. If your brother sins against you, rebuke him. If he repents, forgive him."},{"v":4,"t":"If he sins against you seven times in the day, and seven times returns, saying, ‘I repent,’ you shall forgive him.”"},{"v":5,"t":"The apostles said to the Lord, “Increase our faith.”"},{"v":6,"t":"The Lord said, “If you had faith like a grain of mustard seed, you would tell this sycamore tree, ‘Be uprooted and be planted in the sea,’ and it would obey you."},{"v":7,"t":"But who is there among you, having a servant plowing or keeping sheep, that will say when he comes in from the field, ‘Come immediately and sit down at the table’?"},{"v":8,"t":"Wouldn’t he rather tell him, ‘Prepare my supper, clothe yourself properly, and serve me while I eat and drink. Afterward you shall eat and drink’?"},{"v":9,"t":"Does he thank that servant because he did the things that were commanded? I think not."},{"v":10,"t":"Even so you also, when you have done all the things that are commanded you, say, ‘We are unworthy servants. We have done our duty.’”"},{"v":11,"t":"As he was on his way to Jerusalem, he was passing along the borders of Samaria and Galilee."},{"v":12,"t":"As he entered into a certain village, ten men who were lepers met him, who stood at a distance."},{"v":13,"t":"They lifted up their voices, saying, “Jesus, Master, have mercy on us!”"},{"v":14,"t":"When he saw them, he said to them, “Go and show yourselves to the priests.” As they went, they were cleansed."},{"v":15,"t":"One of them, when he saw that he was healed, turned back, glorifying God with a loud voice."},{"v":16,"t":"He fell on his face at Jesus’ feet, giving him thanks; and he was a Samaritan."},{"v":17,"t":"Jesus answered, “Weren’t the ten cleansed? But where are the nine?"},{"v":18,"t":"Were there none found who returned to give glory to God, except this foreigner?”"},{"v":19,"t":"Then he said to him, “Get up, and go your way. Your faith has healed you.”"},{"v":20,"t":"Being asked by the Pharisees when God’s Kingdom would come, he answered them, “God’s Kingdom doesn’t come with observation;"},{"v":21,"t":"neither will they say, ‘Look, here!’ or, ‘Look, there!’ for behold, God’s Kingdom is within you.”"},{"v":22,"t":"He said to the disciples, “The days will come when you will desire to see one of the days of the Son of Man, and you will not see it."},{"v":23,"t":"They will tell you, ‘Look, here!’ or ‘Look, there!’ Don’t go away or follow after them,"},{"v":24,"t":"for as the lightning, when it flashes out of one part under the sky, shines to another part under the sky, so will the Son of Man be in his day."},{"v":25,"t":"But first, he must suffer many things and be rejected by this generation."},{"v":26,"t":"As it was in the days of Noah, even so it will also be in the days of the Son of Man."},{"v":27,"t":"They ate, they drank, they married, and they were given in marriage until the day that Noah entered into the ship, and the flood came and destroyed them all."},{"v":28,"t":"Likewise, even as it was in the days of Lot: they ate, they drank, they bought, they sold, they planted, they built;"},{"v":29,"t":"but in the day that Lot went out from Sodom, it rained fire and sulfur from the sky and destroyed them all."},{"v":30,"t":"It will be the same way in the day that the Son of Man is revealed."},{"v":31,"t":"In that day, he who will be on the housetop and his goods in the house, let him not go down to take them away. Let him who is in the field likewise not turn back."},{"v":32,"t":"Remember Lot’s wife!"},{"v":33,"t":"Whoever seeks to save his life loses it, but whoever loses his life preserves it."},{"v":34,"t":"I tell you, in that night there will be two people in one bed. One will be taken and the other will be left."},{"v":35,"t":"There will be two grinding grain together. One will be taken and the other will be left.”"},{"v":37,"t":"They, answering, asked him, “Where, Lord?” He said to them, “Where the body is, there the vultures will also be gathered together.”"}]},"18":{"en":[{"v":1,"t":"He also spoke a parable to them that they must always pray and not give up,"},{"v":2,"t":"saying, “There was a judge in a certain city who didn’t fear God and didn’t respect man."},{"v":3,"t":"A widow was in that city, and she often came to him, saying, ‘Defend me from my adversary!’"},{"v":4,"t":"He wouldn’t for a while; but afterward he said to himself, ‘Though I neither fear God nor respect man,"},{"v":5,"t":"yet because this widow bothers me, I will defend her, or else she will wear me out by her continual coming.’”"},{"v":6,"t":"The Lord said, “Listen to what the unrighteous judge says."},{"v":7,"t":"Won’t God avenge his chosen ones who are crying out to him day and night, and yet he exercises patience with them?"},{"v":8,"t":"I tell you that he will avenge them quickly. Nevertheless, when the Son of Man comes, will he find faith on the earth?”"},{"v":9,"t":"He also spoke this parable to certain people who were convinced of their own righteousness, and who despised all others:"},{"v":10,"t":"“Two men went up into the temple to pray; one was a Pharisee, and the other was a tax collector."},{"v":11,"t":"The Pharisee stood and prayed by himself like this: ‘God, I thank you that I am not like the rest of men: extortionists, unrighteous, adulterers, or even like this tax collector."},{"v":12,"t":"I fast twice a week. I give tithes of all that I get.’"},{"v":13,"t":"But the tax collector, standing far away, wouldn’t even lift up his eyes to heaven, but beat his chest, saying, ‘God, be merciful to me, a sinner!’"},{"v":14,"t":"I tell you, this man went down to his house justified rather than the other; for everyone who exalts himself will be humbled, but he who humbles himself will be exalted.”"},{"v":15,"t":"They were also bringing their babies to him, that he might touch them. But when the disciples saw it, they rebuked them."},{"v":16,"t":"Jesus summoned them, saying, “Allow the little children to come to me, and don’t hinder them, for God’s Kingdom belongs to such as these."},{"v":17,"t":"Most certainly, I tell you, whoever doesn’t receive God’s Kingdom like a little child, he will in no way enter into it.”"},{"v":18,"t":"A certain ruler asked him, saying, “Good Teacher, what shall I do to inherit eternal life?”"},{"v":19,"t":"Jesus asked him, “Why do you call me good? No one is good, except one: God."},{"v":20,"t":"You know the commandments: ‘Don’t commit adultery,’ ‘Don’t murder,’ ‘Don’t steal,’ ‘Don’t give false testimony,’ ‘Honor your father and your mother.’”"},{"v":21,"t":"He said, “I have observed all these things from my youth up.”"},{"v":22,"t":"When Jesus heard these things, he said to him, “You still lack one thing. Sell all that you have and distribute it to the poor. Then you will have treasure in heaven; then come, follow me.”"},{"v":23,"t":"But when he heard these things, he became very sad, for he was very rich."},{"v":24,"t":"Jesus, seeing that he became very sad, said, “How hard it is for those who have riches to enter into God’s Kingdom!"},{"v":25,"t":"For it is easier for a camel to enter in through a needle’s eye than for a rich man to enter into God’s Kingdom.”"},{"v":26,"t":"Those who heard it said, “Then who can be saved?”"},{"v":27,"t":"But he said, “The things which are impossible with men are possible with God.”"},{"v":28,"t":"Peter said, “Look, we have left everything and followed you.”"},{"v":29,"t":"He said to them, “Most certainly I tell you, there is no one who has left house, or wife, or brothers, or parents, or children, for God’s Kingdom’s sake,"},{"v":30,"t":"who will not receive many times more in this time, and in the world to come, eternal life.”"},{"v":31,"t":"He took the twelve aside and said to them, “Behold, we are going up to Jerusalem, and all the things that are written through the prophets concerning the Son of Man will be completed."},{"v":32,"t":"For he will be delivered up to the Gentiles, will be mocked, treated shamefully, and spit on."},{"v":33,"t":"They will scourge and kill him. On the third day, he will rise again.”"},{"v":34,"t":"They understood none of these things. This saying was hidden from them, and they didn’t understand the things that were said."},{"v":35,"t":"As he came near Jericho, a certain blind man sat by the road, begging."},{"v":36,"t":"Hearing a multitude going by, he asked what this meant."},{"v":37,"t":"They told him that Jesus of Nazareth was passing by."},{"v":38,"t":"He cried out, “Jesus, you son of David, have mercy on me!”"},{"v":39,"t":"Those who led the way rebuked him, that he should be quiet; but he cried out all the more, “You son of David, have mercy on me!”"},{"v":40,"t":"Standing still, Jesus commanded him to be brought to him. When he had come near, he asked him,"},{"v":41,"t":"“What do you want me to do?” He said, “Lord, that I may see again.”"},{"v":42,"t":"Jesus said to him, “Receive your sight. Your faith has healed you.”"},{"v":43,"t":"Immediately he received his sight and followed him, glorifying God. All the people, when they saw it, praised God."}]},"19":{"en":[{"v":1,"t":"He entered and was passing through Jericho."},{"v":2,"t":"There was a man named Zacchaeus. He was a chief tax collector, and he was rich."},{"v":3,"t":"He was trying to see who Jesus was, and couldn’t because of the crowd, because he was short."},{"v":4,"t":"He ran on ahead and climbed up into a sycamore tree to see him, for he was going to pass that way."},{"v":5,"t":"When Jesus came to the place, he looked up and saw him, and said to him, “Zacchaeus, hurry and come down, for today I must stay at your house.”"},{"v":6,"t":"He hurried, came down, and received him joyfully."},{"v":7,"t":"When they saw it, they all murmured, saying, “He has gone in to lodge with a man who is a sinner.”"},{"v":8,"t":"Zacchaeus stood and said to the Lord, “Behold, Lord, half of my goods I give to the poor. If I have wrongfully exacted anything of anyone, I restore four times as much.”"},{"v":9,"t":"Jesus said to him, “Today, salvation has come to this house, because he also is a son of Abraham."},{"v":10,"t":"For the Son of Man came to seek and to save that which was lost.”"},{"v":11,"t":"As they heard these things, he went on and told a parable, because he was near Jerusalem, and they supposed that God’s Kingdom would be revealed immediately."},{"v":12,"t":"He said therefore, “A certain nobleman went into a far country to receive for himself a kingdom and to return."},{"v":13,"t":"He called ten servants of his and gave them ten mina coins, and told them, ‘Conduct business until I come.’"},{"v":14,"t":"But his citizens hated him, and sent an envoy after him, saying, ‘We don’t want this man to reign over us.’"},{"v":15,"t":"“When he had come back again, having received the kingdom, he commanded these servants, to whom he had given the money, to be called to him, that he might know what they had gained by conducting business."},{"v":16,"t":"The first came before him, saying, ‘Lord, your mina has made ten more minas.’"},{"v":17,"t":"“He said to him, ‘Well done, you good servant! Because you were found faithful with very little, you shall have authority over ten cities.’"},{"v":18,"t":"“The second came, saying, ‘Your mina, Lord, has made five minas.’"},{"v":19,"t":"“So he said to him, ‘And you are to be over five cities.’"},{"v":20,"t":"Another came, saying, ‘Lord, behold, your mina, which I kept laid away in a handkerchief,"},{"v":21,"t":"for I feared you, because you are an exacting man. You take up that which you didn’t lay down, and reap that which you didn’t sow.’"},{"v":22,"t":"“He said to him, ‘Out of your own mouth I will judge you, you wicked servant! You knew that I am an exacting man, taking up that which I didn’t lay down and reaping that which I didn’t sow."},{"v":23,"t":"Then why didn’t you deposit my money in the bank, and at my coming, I might have earned interest on it?’"},{"v":24,"t":"He said to those who stood by, ‘Take the mina away from him and give it to him who has the ten minas.’"},{"v":25,"t":"“They said to him, ‘Lord, he has ten minas!’"},{"v":26,"t":"‘For I tell you that to everyone who has, will more be given; but from him who doesn’t have, even that which he has will be taken away from him."},{"v":27,"t":"But bring those enemies of mine who didn’t want me to reign over them here, and kill them before me.’”"},{"v":28,"t":"Having said these things, he went on ahead, going up to Jerusalem."},{"v":29,"t":"When he came near to Bethsphage and Bethany, at the mountain that is called Olivet, he sent two of his disciples,"},{"v":30,"t":"saying, “Go your way into the village on the other side, in which, as you enter, you will find a colt tied, which no man has ever sat upon. Untie it and bring it."},{"v":31,"t":"If anyone asks you, ‘Why are you untying it?’ say to him: ‘The Lord needs it.’”"},{"v":32,"t":"Those who were sent went away and found things just as he had told them."},{"v":33,"t":"As they were untying the colt, its owners said to them, “Why are you untying the colt?”"},{"v":34,"t":"They said, “The Lord needs it.”"},{"v":35,"t":"Then they brought it to Jesus. They threw their cloaks on the colt and sat Jesus on them."},{"v":36,"t":"As he went, they spread their cloaks on the road."},{"v":37,"t":"As he was now getting near, at the descent of the Mount of Olives, the whole multitude of the disciples began to rejoice and praise God with a loud voice for all the mighty works which they had seen,"},{"v":38,"t":"saying, “Blessed is the King who comes in the name of the Lord! Peace in heaven, and glory in the highest!”"},{"v":39,"t":"Some of the Pharisees from the multitude said to him, “Teacher, rebuke your disciples!”"},{"v":40,"t":"He answered them, “I tell you that if these were silent, the stones would cry out.”"},{"v":41,"t":"When he came near, he saw the city and wept over it,"},{"v":42,"t":"saying, “If you, even you, had known today the things which belong to your peace! But now, they are hidden from your eyes."},{"v":43,"t":"For the days will come on you when your enemies will throw up a barricade against you, surround you, hem you in on every side,"},{"v":44,"t":"and will dash you and your children within you to the ground. They will not leave in you one stone on another, because you didn’t know the time of your visitation.”"},{"v":45,"t":"He entered into the temple and began to drive out those who bought and sold in it,"},{"v":46,"t":"saying to them, “It is written, ‘My house is a house of prayer,’ but you have made it a ‘den of robbers’!”"},{"v":47,"t":"He was teaching daily in the temple, but the chief priests, the scribes, and the leading men among the people sought to destroy him."},{"v":48,"t":"They couldn’t find what they might do, for all the people hung on to every word that he said."}]},"20":{"en":[{"v":1,"t":"On one of those days, as he was teaching the people in the temple and preaching the Good News, the priests and scribes came to him with the elders."},{"v":2,"t":"They asked him, “Tell us: by what authority do you do these things? Or who is giving you this authority?”"},{"v":3,"t":"He answered them, “I also will ask you one question. Tell me:"},{"v":4,"t":"the baptism of John, was it from heaven, or from men?”"},{"v":5,"t":"They reasoned with themselves, saying, “If we say, ‘From heaven,’ he will say, ‘Why didn’t you believe him?’"},{"v":6,"t":"But if we say, ‘From men,’ all the people will stone us, for they are persuaded that John was a prophet.”"},{"v":7,"t":"They answered that they didn’t know where it was from."},{"v":8,"t":"Jesus said to them, “Neither will I tell you by what authority I do these things.”"},{"v":9,"t":"He began to tell the people this parable: “A man planted a vineyard and rented it out to some farmers, and went into another country for a long time."},{"v":10,"t":"At the proper season, he sent a servant to the farmers to collect his share of the fruit of the vineyard. But the farmers beat him and sent him away empty."},{"v":11,"t":"He sent yet another servant, and they also beat him and treated him shamefully, and sent him away empty."},{"v":12,"t":"He sent yet a third, and they also wounded him and threw him out."},{"v":13,"t":"The lord of the vineyard said, ‘What shall I do? I will send my beloved son. It may be that seeing him, they will respect him.’"},{"v":14,"t":"“But when the farmers saw him, they reasoned among themselves, saying, ‘This is the heir. Come, let’s kill him, that the inheritance may be ours.’"},{"v":15,"t":"Then they threw him out of the vineyard and killed him. What therefore will the lord of the vineyard do to them?"},{"v":16,"t":"He will come and destroy these farmers, and will give the vineyard to others.” When they heard that, they said, “May that never be!”"},{"v":17,"t":"But he looked at them and said, “Then what is this that is written, ‘The stone which the builders rejected was made the chief cornerstone’?"},{"v":18,"t":"Everyone who falls on that stone will be broken to pieces, but it will crush whomever it falls on to dust.”"},{"v":19,"t":"The chief priests and the scribes sought to lay hands on him that very hour, but they feared the people—for they knew he had spoken this parable against them."},{"v":20,"t":"They watched him and sent out spies, who pretended to be righteous, that they might trap him in something he said, so as to deliver him up to the power and authority of the governor."},{"v":21,"t":"They asked him, “Teacher, we know that you say and teach what is right, and aren’t partial to anyone, but truly teach the way of God."},{"v":22,"t":"Is it lawful for us to pay taxes to Caesar, or not?”"},{"v":23,"t":"But he perceived their craftiness, and said to them, “Why do you test me?"},{"v":24,"t":"Show me a denarius. Whose image and inscription are on it?” They answered, “Caesar’s.”"},{"v":25,"t":"He said to them, “Then give to Caesar the things that are Caesar’s, and to God the things that are God’s.”"},{"v":26,"t":"They weren’t able to trap him in his words before the people. They marveled at his answer and were silent."},{"v":27,"t":"Some of the Sadducees came to him, those who deny that there is a resurrection."},{"v":28,"t":"They asked him, “Teacher, Moses wrote to us that if a man’s brother dies having a wife, and he is childless, his brother should take the wife and raise up children for his brother."},{"v":29,"t":"There were therefore seven brothers. The first took a wife, and died childless."},{"v":30,"t":"The second took her as wife, and he died childless."},{"v":31,"t":"The third took her, and likewise the seven all left no children, and died."},{"v":32,"t":"Afterward the woman also died."},{"v":33,"t":"Therefore in the resurrection whose wife of them will she be? For the seven had her as a wife.”"},{"v":34,"t":"Jesus said to them, “The children of this age marry and are given in marriage."},{"v":35,"t":"But those who are considered worthy to attain to that age and the resurrection from the dead neither marry nor are given in marriage."},{"v":36,"t":"For they can’t die any more, for they are like the angels and are children of God, being children of the resurrection."},{"v":37,"t":"But that the dead are raised, even Moses showed at the bush, when he called the Lord ‘The God of Abraham, the God of Isaac, and the God of Jacob.’"},{"v":38,"t":"Now he is not the God of the dead, but of the living, for all are alive to him.”"},{"v":39,"t":"Some of the scribes answered, “Teacher, you speak well.”"},{"v":40,"t":"They didn’t dare to ask him any more questions."},{"v":41,"t":"He said to them, “Why do they say that the Christ is David’s son?"},{"v":42,"t":"David himself says in the book of Psalms, ‘The Lord said to my Lord, “Sit at my right hand,"},{"v":43,"t":"until I make your enemies the footstool of your feet.”’"},{"v":44,"t":"“David therefore calls him Lord, so how is he his son?”"},{"v":45,"t":"In the hearing of all the people, he said to his disciples,"},{"v":46,"t":"“Beware of those scribes who like to walk in long robes, and love greetings in the marketplaces, the best seats in the synagogues, and the best places at feasts;"},{"v":47,"t":"who devour widows’ houses, and for a pretense make long prayers. These will receive greater condemnation.”"}]},"21":{"en":[{"v":1,"t":"He looked up and saw the rich people who were putting their gifts into the treasury."},{"v":2,"t":"He saw a certain poor widow casting in two small brass coins."},{"v":3,"t":"He said, “Truly I tell you, this poor widow put in more than all of them,"},{"v":4,"t":"for all these put in gifts for God from their abundance, but she, out of her poverty, put in all that she had to live on.”"},{"v":5,"t":"As some were talking about the temple and how it was decorated with beautiful stones and gifts, he said,"},{"v":6,"t":"“As for these things which you see, the days will come in which there will not be left here one stone on another that will not be thrown down.”"},{"v":7,"t":"They asked him, “Teacher, so when will these things be? What is the sign that these things are about to happen?”"},{"v":8,"t":"He said, “Watch out that you don’t get led astray, for many will come in my name, saying, ‘I am he,’ and, ‘The time is at hand.’ Therefore don’t follow them."},{"v":9,"t":"When you hear of wars and disturbances, don’t be terrified, for these things must happen first, but the end won’t come immediately.”"},{"v":10,"t":"Then he said to them, “Nation will rise against nation, and kingdom against kingdom."},{"v":11,"t":"There will be great earthquakes, famines, and plagues in various places. There will be terrors and great signs from heaven."},{"v":12,"t":"But before all these things, they will lay their hands on you and will persecute you, delivering you up to synagogues and prisons, bringing you before kings and governors for my name’s sake."},{"v":13,"t":"It will turn out as a testimony for you."},{"v":14,"t":"Settle it therefore in your hearts not to meditate beforehand how to answer,"},{"v":15,"t":"for I will give you a mouth and wisdom which all your adversaries will not be able to withstand or to contradict."},{"v":16,"t":"You will be handed over even by parents, brothers, relatives, and friends. They will cause some of you to be put to death."},{"v":17,"t":"You will be hated by all men for my name’s sake."},{"v":18,"t":"And not a hair of your head will perish."},{"v":19,"t":"“By your endurance you will win your lives."},{"v":20,"t":"“But when you see Jerusalem surrounded by armies, then know that its desolation is at hand."},{"v":21,"t":"Then let those who are in Judea flee to the mountains. Let those who are in the middle of her depart. Let those who are in the country not enter therein."},{"v":22,"t":"For these are days of vengeance, that all things which are written may be fulfilled."},{"v":23,"t":"Woe to those who are pregnant and to those who nurse infants in those days! For there will be great distress in the land and wrath to this people."},{"v":24,"t":"They will fall by the edge of the sword, and will be led captive into all the nations. Jerusalem will be trampled down by the Gentiles until the times of the Gentiles are fulfilled."},{"v":25,"t":"“There will be signs in the sun, moon, and stars; and on the earth anxiety of nations, in perplexity for the roaring of the sea and the waves;"},{"v":26,"t":"men fainting for fear and for expectation of the things which are coming on the world, for the powers of the heavens will be shaken."},{"v":27,"t":"Then they will see the Son of Man coming in a cloud with power and great glory."},{"v":28,"t":"But when these things begin to happen, look up and lift up your heads, because your redemption is near.”"},{"v":29,"t":"He told them a parable. “See the fig tree and all the trees."},{"v":30,"t":"When they are already budding, you see it and know by your own selves that the summer is already near."},{"v":31,"t":"Even so you also, when you see these things happening, know that God’s Kingdom is near."},{"v":32,"t":"Most certainly I tell you, this generation will not pass away until all things are accomplished."},{"v":33,"t":"Heaven and earth will pass away, but my words will by no means pass away."},{"v":34,"t":"“So be careful, or your hearts will be loaded down with carousing, drunkenness, and cares of this life, and that day will come on you suddenly."},{"v":35,"t":"For it will come like a snare on all those who dwell on the surface of all the earth."},{"v":36,"t":"Therefore be watchful all the time, praying that you may be counted worthy to escape all these things that will happen, and to stand before the Son of Man.”"},{"v":37,"t":"Every day Jesus was teaching in the temple, and every night he would go out and spend the night on the mountain that is called Olivet."},{"v":38,"t":"All the people came early in the morning to him in the temple to hear him."}]},"22":{"en":[{"v":1,"t":"Now the feast of unleavened bread, which is called the Passover, was approaching."},{"v":2,"t":"The chief priests and the scribes sought how they might put him to death, for they feared the people."},{"v":3,"t":"Satan entered into Judas, who was also called Iscariot, who was counted with the twelve."},{"v":4,"t":"He went away and talked with the chief priests and captains about how he might deliver him to them."},{"v":5,"t":"They were glad, and agreed to give him money."},{"v":6,"t":"He consented and sought an opportunity to deliver him to them in the absence of the multitude."},{"v":7,"t":"The day of unleavened bread came, on which the Passover must be sacrificed."},{"v":8,"t":"Jesus sent Peter and John, saying, “Go and prepare the Passover for us, that we may eat.”"},{"v":9,"t":"They said to him, “Where do you want us to prepare?”"},{"v":10,"t":"He said to them, “Behold, when you have entered into the city, a man carrying a pitcher of water will meet you. Follow him into the house which he enters."},{"v":11,"t":"Tell the master of the house, ‘The Teacher says to you, “Where is the guest room, where I may eat the Passover with my disciples?”’"},{"v":12,"t":"He will show you a large, furnished upper room. Make preparations there.”"},{"v":13,"t":"They went, found things as Jesus had told them, and they prepared the Passover."},{"v":14,"t":"When the hour had come, he sat down with the twelve apostles."},{"v":15,"t":"He said to them, “I have earnestly desired to eat this Passover with you before I suffer,"},{"v":16,"t":"for I tell you, I will no longer by any means eat of it until it is fulfilled in God’s Kingdom.”"},{"v":17,"t":"He received a cup, and when he had given thanks, he said, “Take this and share it among yourselves,"},{"v":18,"t":"for I tell you, I will not drink at all again from the fruit of the vine, until God’s Kingdom comes.”"},{"v":19,"t":"He took bread, and when he had given thanks, he broke and gave it to them, saying, “This is my body which is given for you. Do this in memory of me.”"},{"v":20,"t":"Likewise, he took the cup after supper, saying, “This cup is the new covenant in my blood, which is poured out for you."},{"v":21,"t":"But behold, the hand of him who betrays me is with me on the table."},{"v":22,"t":"The Son of Man indeed goes as it has been determined, but woe to that man through whom he is betrayed!”"},{"v":23,"t":"They began to question among themselves which of them it was who would do this thing."},{"v":24,"t":"A dispute also arose among them, which of them was considered to be greatest."},{"v":25,"t":"He said to them, “The kings of the nations lord it over them, and those who have authority over them are called ‘benefactors.’"},{"v":26,"t":"But not so with you. Rather, the one who is greater among you, let him become as the younger, and one who is governing, as one who serves."},{"v":27,"t":"For who is greater, one who sits at the table, or one who serves? Isn’t it he who sits at the table? But I am among you as one who serves."},{"v":28,"t":"“But you are those who have continued with me in my trials."},{"v":29,"t":"I confer on you a kingdom, even as my Father conferred on me,"},{"v":30,"t":"that you may eat and drink at my table in my Kingdom. You will sit on thrones, judging the twelve tribes of Israel.”"},{"v":31,"t":"The Lord said, “Simon, Simon, behold, Satan asked to have all of you, that he might sift you as wheat,"},{"v":32,"t":"but I prayed for you, that your faith wouldn’t fail. You, when once you have turned again, establish your brothers.”"},{"v":33,"t":"He said to him, “Lord, I am ready to go with you both to prison and to death!”"},{"v":34,"t":"He said, “I tell you, Peter, the rooster will by no means crow today until you deny that you know me three times.”"},{"v":35,"t":"He said to them, “When I sent you out without purse, bag, and sandals, did you lack anything?” They said, “Nothing.”"},{"v":36,"t":"Then he said to them, “But now, whoever has a purse, let him take it, and likewise a bag. Whoever has none, let him sell his cloak, and buy a sword."},{"v":37,"t":"For I tell you that this which is written must still be fulfilled in me: ‘He was counted with transgressors.’ For that which concerns me is being fulfilled.”"},{"v":38,"t":"They said, “Lord, behold, here are two swords.” He said to them, “That is enough.”"},{"v":39,"t":"He came out and went, as his custom was, to the Mount of Olives. His disciples also followed him."},{"v":40,"t":"When he was at the place, he said to them, “Pray that you don’t enter into temptation.”"},{"v":41,"t":"He was withdrawn from them about a stone’s throw, and he knelt down and prayed,"},{"v":42,"t":"saying, “Father, if you are willing, remove this cup from me. Nevertheless, not my will, but yours, be done.”"},{"v":43,"t":"An angel from heaven appeared to him, strengthening him."},{"v":44,"t":"Being in agony, he prayed more earnestly. His sweat became like great drops of blood falling down on the ground."},{"v":45,"t":"When he rose up from his prayer, he came to the disciples and found them sleeping because of grief,"},{"v":46,"t":"and said to them, “Why do you sleep? Rise and pray that you may not enter into temptation.”"},{"v":47,"t":"While he was still speaking, a crowd appeared. He who was called Judas, one of the twelve, was leading them. He came near to Jesus to kiss him."},{"v":48,"t":"But Jesus said to him, “Judas, do you betray the Son of Man with a kiss?”"},{"v":49,"t":"When those who were around him saw what was about to happen, they said to him, “Lord, shall we strike with the sword?”"},{"v":50,"t":"A certain one of them struck the servant of the high priest, and cut off his right ear."},{"v":51,"t":"But Jesus answered, “Let me at least do this”—and he touched his ear and healed him."},{"v":52,"t":"Jesus said to the chief priests, captains of the temple, and elders, who had come against him, “Have you come out as against a robber, with swords and clubs?"},{"v":53,"t":"When I was with you in the temple daily, you didn’t stretch out your hands against me. But this is your hour, and the power of darkness.”"},{"v":54,"t":"They seized him and led him away, and brought him into the high priest’s house. But Peter followed from a distance."},{"v":55,"t":"When they had kindled a fire in the middle of the courtyard and had sat down together, Peter sat among them."},{"v":56,"t":"A certain servant girl saw him as he sat in the light, and looking intently at him, said, “This man also was with him.”"},{"v":57,"t":"He denied Jesus, saying, “Woman, I don’t know him.”"},{"v":58,"t":"After a little while someone else saw him and said, “You also are one of them!” But Peter answered, “Man, I am not!”"},{"v":59,"t":"After about one hour passed, another confidently affirmed, saying, “Truly this man also was with him, for he is a Galilean!”"},{"v":60,"t":"But Peter said, “Man, I don’t know what you are talking about!” Immediately, while he was still speaking, a rooster crowed."},{"v":61,"t":"The Lord turned and looked at Peter. Then Peter remembered the Lord’s word, how he said to him, “Before the rooster crows you will deny me three times.”"},{"v":62,"t":"He went out, and wept bitterly."},{"v":63,"t":"The men who held Jesus mocked him and beat him."},{"v":64,"t":"Having blindfolded him, they struck him on the face and asked him, “Prophesy! Who is the one who struck you?”"},{"v":65,"t":"They spoke many other things against him, insulting him."},{"v":66,"t":"As soon as it was day, the assembly of the elders of the people were gathered together, both chief priests and scribes, and they led him away into their council, saying,"},{"v":67,"t":"“If you are the Christ, tell us.” But he said to them, “If I tell you, you won’t believe,"},{"v":68,"t":"and if I ask, you will in no way answer me or let me go."},{"v":69,"t":"From now on, the Son of Man will be seated at the right hand of the power of God.”"},{"v":70,"t":"They all said, “Are you then the Son of God?” He said to them, “You say it, because I am.”"},{"v":71,"t":"They said, “Why do we need any more witness? For we ourselves have heard from his own mouth!”"}]},"23":{"en":[{"v":1,"t":"The whole company of them rose up and brought him before Pilate."},{"v":2,"t":"They began to accuse him, saying, “We found this man perverting the nation, forbidding paying taxes to Caesar, and saying that he himself is Christ, a king.”"},{"v":3,"t":"Pilate asked him, “Are you the King of the Jews?” He answered him, “So you say.”"},{"v":4,"t":"Pilate said to the chief priests and the multitudes, “I find no basis for a charge against this man.”"},{"v":5,"t":"But they insisted, saying, “He stirs up the people, teaching throughout all Judea, beginning from Galilee even to this place.”"},{"v":6,"t":"But when Pilate heard Galilee mentioned, he asked if the man was a Galilean."},{"v":7,"t":"When he found out that he was in Herod’s jurisdiction, he sent him to Herod, who was also in Jerusalem during those days."},{"v":8,"t":"Now when Herod saw Jesus, he was exceedingly glad, for he had wanted to see him for a long time, because he had heard many things about him. He hoped to see some miracle done by him."},{"v":9,"t":"He questioned him with many words, but he gave no answers."},{"v":10,"t":"The chief priests and the scribes stood, vehemently accusing him."},{"v":11,"t":"Herod with his soldiers humiliated him and mocked him. Dressing him in luxurious clothing, they sent him back to Pilate."},{"v":12,"t":"Herod and Pilate became friends with each other that very day, for before that they were enemies with each other."},{"v":13,"t":"Pilate called together the chief priests, the rulers, and the people,"},{"v":14,"t":"and said to them, “You brought this man to me as one that perverts the people, and behold, having examined him before you, I found no basis for a charge against this man concerning those things of which you accuse him."},{"v":15,"t":"Neither has Herod, for I sent you to him, and see, nothing worthy of death has been done by him."},{"v":16,"t":"I will therefore chastise him and release him.”"},{"v":17,"t":"Now he had to release one prisoner to them at the feast."},{"v":18,"t":"But they all cried out together, saying, “Away with this man! Release to us Barabbas!”—"},{"v":19,"t":"one who was thrown into prison for a certain revolt in the city, and for murder."},{"v":20,"t":"Then Pilate spoke to them again, wanting to release Jesus,"},{"v":21,"t":"but they shouted, saying, “Crucify! Crucify him!”"},{"v":22,"t":"He said to them the third time, “Why? What evil has this man done? I have found no capital crime in him. I will therefore chastise him and release him.”"},{"v":23,"t":"But they were urgent with loud voices, asking that he might be crucified. Their voices and the voices of the chief priests prevailed."},{"v":24,"t":"Pilate decreed that what they asked for should be done."},{"v":25,"t":"He released him who had been thrown into prison for insurrection and murder, for whom they asked, but he delivered Jesus up to their will."},{"v":26,"t":"When they led him away, they grabbed one Simon of Cyrene, coming from the country, and laid the cross on him to carry it after Jesus."},{"v":27,"t":"A great multitude of the people followed him, including women who also mourned and lamented him."},{"v":28,"t":"But Jesus, turning to them, said, “Daughters of Jerusalem, don’t weep for me, but weep for yourselves and for your children."},{"v":29,"t":"For behold, the days are coming in which they will say, ‘Blessed are the barren, the wombs that never bore, and the breasts that never nursed.’"},{"v":30,"t":"Then they will begin to tell the mountains, ‘Fall on us!’ and tell the hills, ‘Cover us.’"},{"v":31,"t":"For if they do these things in the green tree, what will be done in the dry?”"},{"v":32,"t":"There were also others, two criminals, led with him to be put to death."},{"v":33,"t":"When they came to the place that is called “The Skull”, they crucified him there with the criminals, one on the right and the other on the left."},{"v":34,"t":"Jesus said, “Father, forgive them, for they don’t know what they are doing.” Dividing his garments among them, they cast lots."},{"v":35,"t":"The people stood watching. The rulers with them also scoffed at him, saying, “He saved others. Let him save himself, if this is the Christ of God, his chosen one!”"},{"v":36,"t":"The soldiers also mocked him, coming to him and offering him vinegar,"},{"v":37,"t":"and saying, “If you are the King of the Jews, save yourself!”"},{"v":38,"t":"An inscription was also written over him in letters of Greek, Latin, and Hebrew: “THIS IS THE KING OF THE JEWS.”"},{"v":39,"t":"One of the criminals who was hanged insulted him, saying, “If you are the Christ, save yourself and us!”"},{"v":40,"t":"But the other answered, and rebuking him said, “Don’t you even fear God, seeing you are under the same condemnation?"},{"v":41,"t":"And we indeed justly, for we receive the due reward for our deeds, but this man has done nothing wrong.”"},{"v":42,"t":"He said to Jesus, “Lord, remember me when you come into your Kingdom.”"},{"v":43,"t":"Jesus said to him, “Assuredly I tell you, today you will be with me in Paradise.”"},{"v":44,"t":"It was now about the sixth hour, and darkness came over the whole land until the ninth hour."},{"v":45,"t":"The sun was darkened, and the veil of the temple was torn in two."},{"v":46,"t":"Jesus, crying with a loud voice, said, “Father, into your hands I commit my spirit!” Having said this, he breathed his last."},{"v":47,"t":"When the centurion saw what was done, he glorified God, saying, “Certainly this was a righteous man.”"},{"v":48,"t":"All the multitudes that came together to see this, when they saw the things that were done, returned home beating their chests."},{"v":49,"t":"All his acquaintances and the women who followed with him from Galilee stood at a distance, watching these things."},{"v":50,"t":"Behold, there was a man named Joseph, who was a member of the council, a good and righteous man"},{"v":51,"t":"(he had not consented to their counsel and deed), from Arimathaea, a city of the Jews, who was also waiting for God’s Kingdom."},{"v":52,"t":"This man went to Pilate, and asked for Jesus’ body."},{"v":53,"t":"He took it down and wrapped it in a linen cloth, and laid him in a tomb that was cut in stone, where no one had ever been laid."},{"v":54,"t":"It was the day of the Preparation, and the Sabbath was drawing near."},{"v":55,"t":"The women who had come with him out of Galilee followed after, and saw the tomb and how his body was laid."},{"v":56,"t":"They returned and prepared spices and ointments. On the Sabbath they rested according to the commandment."}]},"24":{"en":[{"v":1,"t":"But on the first day of the week, at early dawn, they and some others came to the tomb, bringing the spices which they had prepared."},{"v":2,"t":"They found the stone rolled away from the tomb."},{"v":3,"t":"They entered in, and didn’t find the Lord Jesus’ body."},{"v":4,"t":"While they were greatly perplexed about this, behold, two men stood by them in dazzling clothing."},{"v":5,"t":"Becoming terrified, they bowed their faces down to the earth. The men said to them, “Why do you seek the living among the dead?"},{"v":6,"t":"He isn’t here, but is risen. Remember what he told you when he was still in Galilee,"},{"v":7,"t":"saying that the Son of Man must be delivered up into the hands of sinful men and be crucified, and the third day rise again?”"},{"v":8,"t":"They remembered his words,"},{"v":9,"t":"returned from the tomb, and told all these things to the eleven and to all the rest."},{"v":10,"t":"Now they were Mary Magdalene, Joanna, and Mary the mother of James. The other women with them told these things to the apostles."},{"v":11,"t":"These words seemed to them to be nonsense, and they didn’t believe them."},{"v":12,"t":"But Peter got up and ran to the tomb. Stooping and looking in, he saw the strips of linen lying by themselves, and he departed to his home, wondering what had happened."},{"v":13,"t":"Behold, two of them were going that very day to a village named Emmaus, which was sixty stadia from Jerusalem."},{"v":14,"t":"They talked with each other about all of these things which had happened."},{"v":15,"t":"While they talked and questioned together, Jesus himself came near, and went with them."},{"v":16,"t":"But their eyes were kept from recognizing him."},{"v":17,"t":"He said to them, “What are you talking about as you walk, and are sad?”"},{"v":18,"t":"One of them, named Cleopas, answered him, “Are you the only stranger in Jerusalem who doesn’t know the things which have happened there in these days?”"},{"v":19,"t":"He said to them, “What things?” They said to him, “The things concerning Jesus the Nazarene, who was a prophet mighty in deed and word before God and all the people;"},{"v":20,"t":"and how the chief priests and our rulers delivered him up to be condemned to death, and crucified him."},{"v":21,"t":"But we were hoping that it was he who would redeem Israel. Yes, and besides all this, it is now the third day since these things happened."},{"v":22,"t":"Also, certain women of our company amazed us, having arrived early at the tomb;"},{"v":23,"t":"and when they didn’t find his body, they came saying that they had also seen a vision of angels, who said that he was alive."},{"v":24,"t":"Some of us went to the tomb and found it just like the women had said, but they didn’t see him.”"},{"v":25,"t":"He said to them, “Foolish people, and slow of heart to believe in all that the prophets have spoken!"},{"v":26,"t":"Didn’t the Christ have to suffer these things and to enter into his glory?”"},{"v":27,"t":"Beginning from Moses and from all the prophets, he explained to them in all the Scriptures the things concerning himself."},{"v":28,"t":"They came near to the village where they were going, and he acted like he would go further."},{"v":29,"t":"They urged him, saying, “Stay with us, for it is almost evening, and the day is almost over.” He went in to stay with them."},{"v":30,"t":"When he had sat down at the table with them, he took the bread and gave thanks. Breaking it, he gave it to them."},{"v":31,"t":"Their eyes were opened and they recognized him; then he vanished out of their sight."},{"v":32,"t":"They said to one another, “Weren’t our hearts burning within us while he spoke to us along the way, and while he opened the Scriptures to us?”"},{"v":33,"t":"They rose up that very hour, returned to Jerusalem, and found the eleven gathered together, and those who were with them,"},{"v":34,"t":"saying, “The Lord is risen indeed, and has appeared to Simon!”"},{"v":35,"t":"They related the things that happened along the way, and how he was recognized by them in the breaking of the bread."},{"v":36,"t":"As they said these things, Jesus himself stood among them, and said to them, “Peace be to you.”"},{"v":37,"t":"But they were terrified and filled with fear, and supposed that they had seen a spirit."},{"v":38,"t":"He said to them, “Why are you troubled? Why do doubts arise in your hearts?"},{"v":39,"t":"See my hands and my feet, that it is truly me. Touch me and see, for a spirit doesn’t have flesh and bones, as you see that I have.”"},{"v":40,"t":"When he had said this, he showed them his hands and his feet."},{"v":41,"t":"While they still didn’t believe for joy, and wondered, he said to them, “Do you have anything here to eat?”"},{"v":42,"t":"They gave him a piece of a broiled fish and some honeycomb."},{"v":43,"t":"He took them, and ate in front of them."},{"v":44,"t":"He said to them, “This is what I told you while I was still with you, that all things which are written in the law of Moses, the prophets, and the psalms concerning me must be fulfilled.”"},{"v":45,"t":"Then he opened their minds, that they might understand the Scriptures."},{"v":46,"t":"He said to them, “Thus it is written, and thus it was necessary for the Christ to suffer and to rise from the dead the third day,"},{"v":47,"t":"and that repentance and remission of sins should be preached in his name to all the nations, beginning at Jerusalem."},{"v":48,"t":"You are witnesses of these things."},{"v":49,"t":"Behold, I send out the promise of my Father on you. But wait in the city of Jerusalem until you are clothed with power from on high.”"},{"v":50,"t":"He led them out as far as Bethany, and he lifted up his hands and blessed them."},{"v":51,"t":"While he blessed them, he withdrew from them and was carried up into heaven."},{"v":52,"t":"They worshiped him and returned to Jerusalem with great joy,"},{"v":53,"t":"and were continually in the temple, praising and blessing God. Amen."}]}},"JHN":{"1":{"en":[{"v":1,"t":"In the beginning was the Word, and the Word was with God, and the Word was God."},{"v":2,"t":"The same was in the beginning with God."},{"v":3,"t":"All things were made through him. Without him, nothing was made that has been made."},{"v":4,"t":"In him was life, and the life was the light of men."},{"v":5,"t":"The light shines in the darkness, and the darkness hasn’t overcome it."},{"v":6,"t":"There came a man sent from God, whose name was John."},{"v":7,"t":"The same came as a witness, that he might testify about the light, that all might believe through him."},{"v":8,"t":"He was not the light, but was sent that he might testify about the light."},{"v":9,"t":"The true light that enlightens everyone was coming into the world."},{"v":10,"t":"He was in the world, and the world was made through him, and the world didn’t recognize him."},{"v":11,"t":"He came to his own, and those who were his own didn’t receive him."},{"v":12,"t":"But as many as received him, to them he gave the right to become God’s children, to those who believe in his name:"},{"v":13,"t":"who were born, not of blood, nor of the will of the flesh, nor of the will of man, but of God."},{"v":14,"t":"The Word became flesh and lived among us. We saw his glory, such glory as of the only born Son of the Father, full of grace and truth."},{"v":15,"t":"John testified about him. He cried out, saying, “This was he of whom I said, ‘He who comes after me has surpassed me, for he was before me.’”"},{"v":16,"t":"From his fullness we all received grace upon grace."},{"v":17,"t":"For the law was given through Moses. Grace and truth were realized through Jesus Christ."},{"v":18,"t":"No one has seen God at any time. The only born Son, who is in the bosom of the Father, has declared him."},{"v":19,"t":"This is John’s testimony, when the Jews sent priests and Levites from Jerusalem to ask him, “Who are you?”"},{"v":20,"t":"He declared, and didn’t deny, but he declared, “I am not the Christ.”"},{"v":21,"t":"They asked him, “What then? Are you Elijah?” He said, “I am not.” “Are you the prophet?” He answered, “No.”"},{"v":22,"t":"They said therefore to him, “Who are you? Give us an answer to take back to those who sent us. What do you say about yourself?”"},{"v":23,"t":"He said, “I am the voice of one crying in the wilderness, ‘Make straight the way of the Lord,’ as Isaiah the prophet said.”"},{"v":24,"t":"The ones who had been sent were from the Pharisees."},{"v":25,"t":"They asked him, “Why then do you baptize if you are not the Christ, nor Elijah, nor the prophet?”"},{"v":26,"t":"John answered them, “I baptize in water, but among you stands one whom you don’t know."},{"v":27,"t":"He is the one who comes after me, who is preferred before me, whose sandal strap I’m not worthy to loosen.”"},{"v":28,"t":"These things were done in Bethany beyond the Jordan, where John was baptizing."},{"v":29,"t":"The next day, he saw Jesus coming to him, and said, “Behold, the Lamb of God, who takes away the sin of the world!"},{"v":30,"t":"This is he of whom I said, ‘After me comes a man who is preferred before me, for he was before me.’"},{"v":31,"t":"I didn’t know him, but for this reason I came baptizing in water, that he would be revealed to Israel.”"},{"v":32,"t":"John testified, saying, “I have seen the Spirit descending like a dove out of heaven, and it remained on him."},{"v":33,"t":"I didn’t recognize him, but he who sent me to baptize in water said to me, ‘On whomever you will see the Spirit descending and remaining on him is he who baptizes in the Holy Spirit.’"},{"v":34,"t":"I have seen and have testified that this is the Son of God.”"},{"v":35,"t":"Again, the next day, John was standing with two of his disciples,"},{"v":36,"t":"and he looked at Jesus as he walked, and said, “Behold, the Lamb of God!”"},{"v":37,"t":"The two disciples heard him speak, and they followed Jesus."},{"v":38,"t":"Jesus turned and saw them following, and said to them, “What are you looking for?” They said to him, “Rabbi” (which is to say, being interpreted, Teacher), “where are you staying?”"},{"v":39,"t":"He said to them, “Come and see.” They came and saw where he was staying, and they stayed with him that day. It was about the tenth hour."},{"v":40,"t":"One of the two who heard John and followed him was Andrew, Simon Peter’s brother."},{"v":41,"t":"He first found his own brother, Simon, and said to him, “We have found the Messiah!” (which is, being interpreted, Christ)."},{"v":42,"t":"He brought him to Jesus. Jesus looked at him and said, “You are Simon the son of Jonah. You shall be called Cephas” (which is by interpretation, Peter)."},{"v":43,"t":"On the next day, he was determined to go out into Galilee, and he found Philip. Jesus said to him, “Follow me.”"},{"v":44,"t":"Now Philip was from Bethsaida, the city of Andrew and Peter."},{"v":45,"t":"Philip found Nathanael, and said to him, “We have found him of whom Moses in the law and also the prophets, wrote: Jesus of Nazareth, the son of Joseph.”"},{"v":46,"t":"Nathanael said to him, “Can any good thing come out of Nazareth?” Philip said to him, “Come and see.”"},{"v":47,"t":"Jesus saw Nathanael coming to him, and said about him, “Behold, an Israelite indeed, in whom is no deceit!”"},{"v":48,"t":"Nathanael said to him, “How do you know me?” Jesus answered him, “Before Philip called you, when you were under the fig tree, I saw you.”"},{"v":49,"t":"Nathanael answered him, “Rabbi, you are the Son of God! You are King of Israel!”"},{"v":50,"t":"Jesus answered him, “Because I told you, ‘I saw you underneath the fig tree,’ do you believe? You will see greater things than these!”"},{"v":51,"t":"He said to him, “Most certainly, I tell you all, hereafter you will see heaven opened, and the angels of God ascending and descending on the Son of Man.”"}]},"2":{"en":[{"v":1,"t":"The third day, there was a wedding in Cana of Galilee. Jesus’ mother was there."},{"v":2,"t":"Jesus also was invited, with his disciples, to the wedding."},{"v":3,"t":"When the wine ran out, Jesus’ mother said to him, “They have no wine.”"},{"v":4,"t":"Jesus said to her, “Woman, what does that have to do with you and me? My hour has not yet come.”"},{"v":5,"t":"His mother said to the servants, “Whatever he says to you, do it.”"},{"v":6,"t":"Now there were six water pots of stone set there after the Jews’ way of purifying, containing two or three metretes apiece."},{"v":7,"t":"Jesus said to them, “Fill the water pots with water.” So they filled them up to the brim."},{"v":8,"t":"He said to them, “Now draw some out, and take it to the ruler of the feast.” So they took it."},{"v":9,"t":"When the ruler of the feast tasted the water now become wine, and didn’t know where it came from (but the servants who had drawn the water knew), the ruler of the feast called the bridegroom"},{"v":10,"t":"and said to him, “Everyone serves the good wine first, and when the guests have drunk freely, then that which is worse. You have kept the good wine until now!”"},{"v":11,"t":"This beginning of his signs Jesus did in Cana of Galilee, and revealed his glory; and his disciples believed in him."},{"v":12,"t":"After this, he went down to Capernaum, he, and his mother, his brothers, and his disciples; and they stayed there a few days."},{"v":13,"t":"The Passover of the Jews was at hand, and Jesus went up to Jerusalem."},{"v":14,"t":"He found in the temple those who sold oxen, sheep, and doves, and the changers of money sitting."},{"v":15,"t":"He made a whip of cords and drove all out of the temple, both the sheep and the oxen; and he poured out the changers’ money and overthrew their tables."},{"v":16,"t":"To those who sold the doves, he said, “Take these things out of here! Don’t make my Father’s house a marketplace!”"},{"v":17,"t":"His disciples remembered that it was written, “Zeal for your house will eat me up.”"},{"v":18,"t":"The Jews therefore answered him, “What sign do you show us, seeing that you do these things?”"},{"v":19,"t":"Jesus answered them, “Destroy this temple, and in three days I will raise it up.”"},{"v":20,"t":"The Jews therefore said, “It took forty-six years to build this temple! Will you raise it up in three days?”"},{"v":21,"t":"But he spoke of the temple of his body."},{"v":22,"t":"When therefore he was raised from the dead, his disciples remembered that he said this, and they believed the Scripture and the word which Jesus had said."},{"v":23,"t":"Now when he was in Jerusalem at the Passover, during the feast, many believed in his name, observing his signs which he did."},{"v":24,"t":"But Jesus didn’t entrust himself to them, because he knew everyone,"},{"v":25,"t":"and because he didn’t need for anyone to testify concerning man; for he himself knew what was in man."}]},"3":{"en":[{"v":1,"t":"Now there was a man of the Pharisees named Nicodemus, a ruler of the Jews."},{"v":2,"t":"He came to Jesus by night and said to him, “Rabbi, we know that you are a teacher come from God, for no one can do these signs that you do, unless God is with him.”"},{"v":3,"t":"Jesus answered him, “Most certainly I tell you, unless one is born anew, he can’t see God’s Kingdom.”"},{"v":4,"t":"Nicodemus said to him, “How can a man be born when he is old? Can he enter a second time into his mother’s womb and be born?”"},{"v":5,"t":"Jesus answered, “Most certainly I tell you, unless one is born of water and Spirit, he can’t enter into God’s Kingdom."},{"v":6,"t":"That which is born of the flesh is flesh. That which is born of the Spirit is spirit."},{"v":7,"t":"Don’t marvel that I said to you, ‘You must be born anew.’"},{"v":8,"t":"The wind blows where it wants to, and you hear its sound, but don’t know where it comes from and where it is going. So is everyone who is born of the Spirit.”"},{"v":9,"t":"Nicodemus answered him, “How can these things be?”"},{"v":10,"t":"Jesus answered him, “Are you the teacher of Israel, and don’t understand these things?"},{"v":11,"t":"Most certainly I tell you, we speak that which we know and testify of that which we have seen, and you don’t receive our witness."},{"v":12,"t":"If I told you earthly things and you don’t believe, how will you believe if I tell you heavenly things?"},{"v":13,"t":"No one has ascended into heaven but he who descended out of heaven, the Son of Man, who is in heaven."},{"v":14,"t":"As Moses lifted up the serpent in the wilderness, even so must the Son of Man be lifted up,"},{"v":15,"t":"that whoever believes in him should not perish, but have eternal life."},{"v":16,"t":"For God so loved the world, that he gave his only born Son, that whoever believes in him should not perish, but have eternal life."},{"v":17,"t":"For God didn’t send his Son into the world to judge the world, but that the world should be saved through him."},{"v":18,"t":"He who believes in him is not judged. He who doesn’t believe has been judged already, because he has not believed in the name of the only born Son of God."},{"v":19,"t":"This is the judgment, that the light has come into the world, and men loved the darkness rather than the light, for their works were evil."},{"v":20,"t":"For everyone who does evil hates the light and doesn’t come to the light, lest his works would be exposed."},{"v":21,"t":"But he who does the truth comes to the light, that his works may be revealed, that they have been done in God.”"},{"v":22,"t":"After these things, Jesus came with his disciples into the land of Judea. He stayed there with them and baptized."},{"v":23,"t":"John also was baptizing in Enon near Salim, because there was much water there. They came and were baptized;"},{"v":24,"t":"for John was not yet thrown into prison."},{"v":25,"t":"Therefore a dispute arose on the part of John’s disciples with some Jews about purification."},{"v":26,"t":"They came to John and said to him, “Rabbi, he who was with you beyond the Jordan, to whom you have testified, behold, he baptizes, and everyone is coming to him.”"},{"v":27,"t":"John answered, “A man can receive nothing unless it has been given him from heaven."},{"v":28,"t":"You yourselves testify that I said, ‘I am not the Christ,’ but, ‘I have been sent before him.’"},{"v":29,"t":"He who has the bride is the bridegroom; but the friend of the bridegroom, who stands and hears him, rejoices greatly because of the bridegroom’s voice. Therefore my joy is made full."},{"v":30,"t":"He must increase, but I must decrease."},{"v":31,"t":"“He who comes from above is above all. He who is from the earth belongs to the earth and speaks of the earth. He who comes from heaven is above all."},{"v":32,"t":"What he has seen and heard, of that he testifies; and no one receives his witness."},{"v":33,"t":"He who has received his witness has set his seal to this, that God is true."},{"v":34,"t":"For he whom God has sent speaks the words of God; for God gives the Spirit without measure."},{"v":35,"t":"The Father loves the Son, and has given all things into his hand."},{"v":36,"t":"One who believes in the Son has eternal life, but one who disobeys the Son won’t see life, but the wrath of God remains on him.”"}]},"4":{"en":[{"v":1,"t":"Therefore when the Lord knew that the Pharisees had heard that Jesus was making and baptizing more disciples than John"},{"v":2,"t":"(although Jesus himself didn’t baptize, but his disciples),"},{"v":3,"t":"he left Judea and departed into Galilee."},{"v":4,"t":"He needed to pass through Samaria."},{"v":5,"t":"So he came to a city of Samaria called Sychar, near the parcel of ground that Jacob gave to his son Joseph."},{"v":6,"t":"Jacob’s well was there. Jesus therefore, being tired from his journey, sat down by the well. It was about the sixth hour."},{"v":7,"t":"A woman of Samaria came to draw water. Jesus said to her, “Give me a drink.”"},{"v":8,"t":"For his disciples had gone away into the city to buy food."},{"v":9,"t":"The Samaritan woman therefore said to him, “How is it that you, being a Jew, ask for a drink from me, a Samaritan woman?” (For Jews have no dealings with Samaritans.)"},{"v":10,"t":"Jesus answered her, “If you knew the gift of God, and who it is who says to you, ‘Give me a drink,’ you would have asked him, and he would have given you living water.”"},{"v":11,"t":"The woman said to him, “Sir, you have nothing to draw with, and the well is deep. So where do you get that living water?"},{"v":12,"t":"Are you greater than our father Jacob, who gave us the well and drank from it himself, as did his children and his livestock?”"},{"v":13,"t":"Jesus answered her, “Everyone who drinks of this water will thirst again,"},{"v":14,"t":"but whoever drinks of the water that I will give him will never thirst again; but the water that I will give him will become in him a well of water springing up to eternal life.”"},{"v":15,"t":"The woman said to him, “Sir, give me this water, so that I don’t get thirsty, neither come all the way here to draw.”"},{"v":16,"t":"Jesus said to her, “Go, call your husband, and come here.”"},{"v":17,"t":"The woman answered, “I have no husband.” Jesus said to her, “You said well, ‘I have no husband,’"},{"v":18,"t":"for you have had five husbands; and he whom you now have is not your husband. This you have said truly.”"},{"v":19,"t":"The woman said to him, “Sir, I perceive that you are a prophet."},{"v":20,"t":"Our fathers worshiped in this mountain, and you Jews say that in Jerusalem is the place where people ought to worship.”"},{"v":21,"t":"Jesus said to her, “Woman, believe me, the hour is coming when neither in this mountain nor in Jerusalem will you worship the Father."},{"v":22,"t":"You worship that which you don’t know. We worship that which we know; for salvation is from the Jews."},{"v":23,"t":"But the hour comes, and now is, when the true worshipers will worship the Father in spirit and truth, for the Father seeks such to be his worshipers."},{"v":24,"t":"God is spirit, and those who worship him must worship in spirit and truth.”"},{"v":25,"t":"The woman said to him, “I know that Messiah is coming, he who is called Christ. When he has come, he will declare to us all things.”"},{"v":26,"t":"Jesus said to her, “I am he, the one who speaks to you.”"},{"v":27,"t":"Just then, his disciples came. They marveled that he was speaking with a woman; yet no one said, “What are you looking for?” or, “Why do you speak with her?”"},{"v":28,"t":"So the woman left her water pot, went away into the city, and said to the people,"},{"v":29,"t":"“Come, see a man who told me everything that I have done. Can this be the Christ?”"},{"v":30,"t":"They went out of the city, and were coming to him."},{"v":31,"t":"In the meanwhile, the disciples urged him, saying, “Rabbi, eat.”"},{"v":32,"t":"But he said to them, “I have food to eat that you don’t know about.”"},{"v":33,"t":"The disciples therefore said to one another, “Has anyone brought him something to eat?”"},{"v":34,"t":"Jesus said to them, “My food is to do the will of him who sent me and to accomplish his work."},{"v":35,"t":"Don’t you say, ‘There are yet four months until the harvest’? Behold, I tell you, lift up your eyes and look at the fields, that they are white for harvest already."},{"v":36,"t":"He who reaps receives wages and gathers fruit to eternal life, that both he who sows and he who reaps may rejoice together."},{"v":37,"t":"For in this the saying is true, ‘One sows, and another reaps.’"},{"v":38,"t":"I sent you to reap that for which you haven’t labored. Others have labored, and you have entered into their labor.”"},{"v":39,"t":"From that city many of the Samaritans believed in him because of the word of the woman, who testified, “He told me everything that I have done.”"},{"v":40,"t":"So when the Samaritans came to him, they begged him to stay with them. He stayed there two days."},{"v":41,"t":"Many more believed because of his word."},{"v":42,"t":"They said to the woman, “Now we believe, not because of your speaking; for we have heard for ourselves, and know that this is indeed the Christ, the Savior of the world.”"},{"v":43,"t":"After the two days he went out from there and went into Galilee."},{"v":44,"t":"For Jesus himself testified that a prophet has no honor in his own country."},{"v":45,"t":"So when he came into Galilee, the Galileans received him, having seen all the things that he did in Jerusalem at the feast, for they also went to the feast."},{"v":46,"t":"Jesus came therefore again to Cana of Galilee, where he made the water into wine. There was a certain nobleman whose son was sick at Capernaum."},{"v":47,"t":"When he heard that Jesus had come out of Judea into Galilee, he went to him and begged him that he would come down and heal his son, for he was at the point of death."},{"v":48,"t":"Jesus therefore said to him, “Unless you see signs and wonders, you will in no way believe.”"},{"v":49,"t":"The nobleman said to him, “Sir, come down before my child dies.”"},{"v":50,"t":"Jesus said to him, “Go your way. Your son lives.” The man believed the word that Jesus spoke to him, and he went his way."},{"v":51,"t":"As he was going down, his servants met him and reported, saying “Your child lives!”"},{"v":52,"t":"So he inquired of them the hour when he began to get better. They said therefore to him, “Yesterday at the seventh hour, the fever left him.”"},{"v":53,"t":"So the father knew that it was at that hour in which Jesus said to him, “Your son lives.” He believed, as did his whole house."},{"v":54,"t":"This is again the second sign that Jesus did, having come out of Judea into Galilee."}]},"5":{"en":[{"v":1,"t":"After these things, there was a feast of the Jews, and Jesus went up to Jerusalem."},{"v":2,"t":"Now in Jerusalem by the sheep gate, there is a pool, which is called in Hebrew, “Bethesda”, having five porches."},{"v":3,"t":"In these lay a great multitude of those who were sick, blind, lame, or paralyzed, waiting for the moving of the water;"},{"v":4,"t":"for an angel went down at certain times into the pool and stirred up the water. Whoever stepped in first after the stirring of the water was healed of whatever disease he had."},{"v":5,"t":"A certain man was there who had been sick for thirty-eight years."},{"v":6,"t":"When Jesus saw him lying there, and knew that he had been sick for a long time, he asked him, “Do you want to be made well?”"},{"v":7,"t":"The sick man answered him, “Sir, I have no one to put me into the pool when the water is stirred up, but while I’m coming, another steps down before me.”"},{"v":8,"t":"Jesus said to him, “Arise, take up your mat, and walk.”"},{"v":9,"t":"Immediately, the man was made well, and took up his mat and walked. Now that day was a Sabbath."},{"v":10,"t":"So the Jews said to him who was cured, “It is the Sabbath. It is not lawful for you to carry the mat.”"},{"v":11,"t":"He answered them, “He who made me well said to me, ‘Take up your mat and walk.’ ”"},{"v":12,"t":"Then they asked him, “Who is the man who said to you, ‘Take up your mat and walk’?”"},{"v":13,"t":"But he who was healed didn’t know who it was, for Jesus had withdrawn, a crowd being in the place."},{"v":14,"t":"Afterward Jesus found him in the temple and said to him, “Behold, you are made well. Sin no more, so that nothing worse happens to you.”"},{"v":15,"t":"The man went away, and told the Jews that it was Jesus who had made him well."},{"v":16,"t":"For this cause the Jews persecuted Jesus and sought to kill him, because he did these things on the Sabbath."},{"v":17,"t":"But Jesus answered them, “My Father is still working, so I am working, too.”"},{"v":18,"t":"For this cause therefore the Jews sought all the more to kill him, because he not only broke the Sabbath, but also called God his own Father, making himself equal with God."},{"v":19,"t":"Jesus therefore answered them, “Most certainly, I tell you, the Son can do nothing of himself, but what he sees the Father doing. For whatever things he does, these the Son also does likewise."},{"v":20,"t":"For the Father has affection for the Son, and shows him all things that he himself does. He will show him greater works than these, that you may marvel."},{"v":21,"t":"For as the Father raises the dead and gives them life, even so the Son also gives life to whom he desires."},{"v":22,"t":"For the Father judges no one, but he has given all judgment to the Son,"},{"v":23,"t":"that all may honor the Son, even as they honor the Father. He who doesn’t honor the Son doesn’t honor the Father who sent him."},{"v":24,"t":"“Most certainly I tell you, he who hears my word and believes him who sent me has eternal life, and doesn’t come into judgment, but has passed out of death into life."},{"v":25,"t":"Most certainly I tell you, the hour comes, and now is, when the dead will hear the Son of God’s voice; and those who hear will live."},{"v":26,"t":"For as the Father has life in himself, even so he gave to the Son also to have life in himself."},{"v":27,"t":"He also gave him authority to execute judgment, because he is a son of man."},{"v":28,"t":"Don’t marvel at this, for the hour comes in which all who are in the tombs will hear his voice"},{"v":29,"t":"and will come out; those who have done good, to the resurrection of life; and those who have done evil, to the resurrection of judgment."},{"v":30,"t":"I can of myself do nothing. As I hear, I judge; and my judgment is righteous, because I don’t seek my own will, but the will of my Father who sent me."},{"v":31,"t":"“If I testify about myself, my witness is not valid."},{"v":32,"t":"It is another who testifies about me. I know that the testimony which he testifies about me is true."},{"v":33,"t":"You have sent to John, and he has testified to the truth."},{"v":34,"t":"But the testimony which I receive is not from man. However, I say these things that you may be saved."},{"v":35,"t":"He was the burning and shining lamp, and you were willing to rejoice for a while in his light."},{"v":36,"t":"But the testimony which I have is greater than that of John; for the works which the Father gave me to accomplish, the very works that I do, testify about me, that the Father has sent me."},{"v":37,"t":"The Father himself, who sent me, has testified about me. You have neither heard his voice at any time, nor seen his form."},{"v":38,"t":"You don’t have his word living in you, because you don’t believe him whom he sent."},{"v":39,"t":"“You search the Scriptures, because you think that in them you have eternal life; and these are they which testify about me."},{"v":40,"t":"Yet you will not come to me, that you may have life."},{"v":41,"t":"I don’t receive glory from men."},{"v":42,"t":"But I know you, that you don’t have God’s love in yourselves."},{"v":43,"t":"I have come in my Father’s name, and you don’t receive me. If another comes in his own name, you will receive him."},{"v":44,"t":"How can you believe, who receive glory from one another, and you don’t seek the glory that comes from the only God?"},{"v":45,"t":"“Don’t think that I will accuse you to the Father. There is one who accuses you, even Moses, on whom you have set your hope."},{"v":46,"t":"For if you believed Moses, you would believe me; for he wrote about me."},{"v":47,"t":"But if you don’t believe his writings, how will you believe my words?”"}]},"6":{"en":[{"v":1,"t":"After these things, Jesus went away to the other side of the sea of Galilee, which is also called the Sea of Tiberias."},{"v":2,"t":"A great multitude followed him, because they saw his signs which he did on those who were sick."},{"v":3,"t":"Jesus went up into the mountain, and he sat there with his disciples."},{"v":4,"t":"Now the Passover, the feast of the Jews, was at hand."},{"v":5,"t":"Jesus therefore, lifting up his eyes and seeing that a great multitude was coming to him, said to Philip, “Where are we to buy bread, that these may eat?”"},{"v":6,"t":"He said this to test him, for he himself knew what he would do."},{"v":7,"t":"Philip answered him, “Two hundred denarii worth of bread is not sufficient for them, that every one of them may receive a little.”"},{"v":8,"t":"One of his disciples, Andrew, Simon Peter’s brother, said to him,"},{"v":9,"t":"“There is a boy here who has five barley loaves and two fish, but what are these among so many?”"},{"v":10,"t":"Jesus said, “Have the people sit down.” Now there was much grass in that place. So the men sat down, in number about five thousand."},{"v":11,"t":"Jesus took the loaves, and having given thanks, he distributed to the disciples, and the disciples to those who were sitting down, likewise also of the fish as much as they desired."},{"v":12,"t":"When they were filled, he said to his disciples, “Gather up the broken pieces which are left over, that nothing be lost.”"},{"v":13,"t":"So they gathered them up, and filled twelve baskets with broken pieces from the five barley loaves, which were left over by those who had eaten."},{"v":14,"t":"When therefore the people saw the sign which Jesus did, they said, “This is truly the prophet who comes into the world.”"},{"v":15,"t":"Jesus therefore, perceiving that they were about to come and take him by force to make him king, withdrew again to the mountain by himself."},{"v":16,"t":"When evening came, his disciples went down to the sea."},{"v":17,"t":"They entered into the boat, and were going over the sea to Capernaum. It was now dark, and Jesus had not come to them."},{"v":18,"t":"The sea was tossed by a great wind blowing."},{"v":19,"t":"When therefore they had rowed about twenty-five or thirty stadia, they saw Jesus walking on the sea and drawing near to the boat; and they were afraid."},{"v":20,"t":"But he said to them, “It is I. Don’t be afraid.”"},{"v":21,"t":"They were willing therefore to receive him into the boat. Immediately the boat was at the land where they were going."},{"v":22,"t":"On the next day, the multitude that stood on the other side of the sea saw that there was no other boat there, except the one in which his disciples had embarked, and that Jesus hadn’t entered with his disciples into the boat, but his disciples had gone away alone."},{"v":23,"t":"However, boats from Tiberias came near to the place where they ate the bread after the Lord had given thanks."},{"v":24,"t":"When the multitude therefore saw that Jesus wasn’t there, nor his disciples, they themselves got into the boats and came to Capernaum, seeking Jesus."},{"v":25,"t":"When they found him on the other side of the sea, they asked him, “Rabbi, when did you come here?”"},{"v":26,"t":"Jesus answered them, “Most certainly I tell you, you seek me, not because you saw signs, but because you ate of the loaves and were filled."},{"v":27,"t":"Don’t work for the food which perishes, but for the food which remains to eternal life, which the Son of Man will give to you. For God the Father has sealed him.”"},{"v":28,"t":"They said therefore to him, “What must we do, that we may work the works of God?”"},{"v":29,"t":"Jesus answered them, “This is the work of God, that you believe in him whom he has sent.”"},{"v":30,"t":"They said therefore to him, “What then do you do for a sign, that we may see and believe you? What work do you do?"},{"v":31,"t":"Our fathers ate the manna in the wilderness. As it is written, ‘He gave them bread out of heaven to eat.’”"},{"v":32,"t":"Jesus therefore said to them, “Most certainly, I tell you, it wasn’t Moses who gave you the bread out of heaven, but my Father gives you the true bread out of heaven."},{"v":33,"t":"For the bread of God is that which comes down out of heaven and gives life to the world.”"},{"v":34,"t":"They said therefore to him, “Lord, always give us this bread.”"},{"v":35,"t":"Jesus said to them, “I am the bread of life. Whoever comes to me will not be hungry, and whoever believes in me will never be thirsty."},{"v":36,"t":"But I told you that you have seen me, and yet you don’t believe."},{"v":37,"t":"All those whom the Father gives me will come to me. He who comes to me I will in no way throw out."},{"v":38,"t":"For I have come down from heaven, not to do my own will, but the will of him who sent me."},{"v":39,"t":"This is the will of my Father who sent me, that of all he has given to me I should lose nothing, but should raise him up at the last day."},{"v":40,"t":"This is the will of the one who sent me, that everyone who sees the Son and believes in him should have eternal life; and I will raise him up at the last day.”"},{"v":41,"t":"The Jews therefore murmured concerning him, because he said, “I am the bread which came down out of heaven.”"},{"v":42,"t":"They said, “Isn’t this Jesus, the son of Joseph, whose father and mother we know? How then does he say, ‘I have come down out of heaven’?”"},{"v":43,"t":"Therefore Jesus answered them, “Don’t murmur among yourselves."},{"v":44,"t":"No one can come to me unless the Father who sent me draws him; and I will raise him up in the last day."},{"v":45,"t":"It is written in the prophets, ‘They will all be taught by God.’ Therefore everyone who hears from the Father and has learned, comes to me."},{"v":46,"t":"Not that anyone has seen the Father, except he who is from God. He has seen the Father."},{"v":47,"t":"Most certainly, I tell you, he who believes in me has eternal life."},{"v":48,"t":"I am the bread of life."},{"v":49,"t":"Your fathers ate the manna in the wilderness and they died."},{"v":50,"t":"This is the bread which comes down out of heaven, that anyone may eat of it and not die."},{"v":51,"t":"I am the living bread which came down out of heaven. If anyone eats of this bread, he will live forever. Yes, the bread which I will give for the life of the world is my flesh.”"},{"v":52,"t":"The Jews therefore contended with one another, saying, “How can this man give us his flesh to eat?”"},{"v":53,"t":"Jesus therefore said to them, “Most certainly I tell you, unless you eat the flesh of the Son of Man and drink his blood, you don’t have life in yourselves."},{"v":54,"t":"He who eats my flesh and drinks my blood has eternal life, and I will raise him up at the last day."},{"v":55,"t":"For my flesh is food indeed, and my blood is drink indeed."},{"v":56,"t":"He who eats my flesh and drinks my blood lives in me, and I in him."},{"v":57,"t":"As the living Father sent me, and I live because of the Father, so he who feeds on me will also live because of me."},{"v":58,"t":"This is the bread which came down out of heaven—not as our fathers ate the manna and died. He who eats this bread will live forever.”"},{"v":59,"t":"He said these things in the synagogue, as he taught in Capernaum."},{"v":60,"t":"Therefore many of his disciples, when they heard this, said, “This is a hard saying! Who can listen to it?”"},{"v":61,"t":"But Jesus knowing in himself that his disciples murmured at this, said to them, “Does this cause you to stumble?"},{"v":62,"t":"Then what if you would see the Son of Man ascending to where he was before?"},{"v":63,"t":"It is the spirit who gives life. The flesh profits nothing. The words that I speak to you are spirit, and are life."},{"v":64,"t":"But there are some of you who don’t believe.” For Jesus knew from the beginning who they were who didn’t believe, and who it was who would betray him."},{"v":65,"t":"He said, “For this cause I have said to you that no one can come to me, unless it is given to him by my Father.”"},{"v":66,"t":"At this, many of his disciples went back and walked no more with him."},{"v":67,"t":"Jesus said therefore to the twelve, “You don’t also want to go away, do you?”"},{"v":68,"t":"Simon Peter answered him, “Lord, to whom would we go? You have the words of eternal life."},{"v":69,"t":"We have come to believe and know that you are the Christ, the Son of the living God.”"},{"v":70,"t":"Jesus answered them, “Didn’t I choose you, the twelve, and one of you is a devil?”"},{"v":71,"t":"Now he spoke of Judas, the son of Simon Iscariot, for it was he who would betray him, being one of the twelve."}]},"7":{"en":[{"v":1,"t":"After these things, Jesus was walking in Galilee, for he wouldn’t walk in Judea, because the Jews sought to kill him."},{"v":2,"t":"Now the feast of the Jews, the Feast of Booths, was at hand."},{"v":3,"t":"His brothers therefore said to him, “Depart from here and go into Judea, that your disciples also may see your works which you do."},{"v":4,"t":"For no one does anything in secret while he seeks to be known openly. If you do these things, reveal yourself to the world.”"},{"v":5,"t":"For even his brothers didn’t believe in him."},{"v":6,"t":"Jesus therefore said to them, “My time has not yet come, but your time is always ready."},{"v":7,"t":"The world can’t hate you, but it hates me, because I testify about it, that its works are evil."},{"v":8,"t":"You go up to the feast. I am not yet going up to this feast, because my time is not yet fulfilled.”"},{"v":9,"t":"Having said these things to them, he stayed in Galilee."},{"v":10,"t":"But when his brothers had gone up to the feast, then he also went up, not publicly, but as it were in secret."},{"v":11,"t":"The Jews therefore sought him at the feast, and said, “Where is he?”"},{"v":12,"t":"There was much murmuring among the multitudes concerning him. Some said, “He is a good man.” Others said, “Not so, but he leads the multitude astray.”"},{"v":13,"t":"Yet no one spoke openly of him for fear of the Jews."},{"v":14,"t":"But when it was now the middle of the feast, Jesus went up into the temple and taught."},{"v":15,"t":"The Jews therefore marveled, saying, “How does this man know letters, having never been educated?”"},{"v":16,"t":"Jesus therefore answered them, “My teaching is not mine, but his who sent me."},{"v":17,"t":"If anyone desires to do his will, he will know about the teaching, whether it is from God or if I am speaking from myself."},{"v":18,"t":"He who speaks from himself seeks his own glory, but he who seeks the glory of him who sent him is true, and no unrighteousness is in him."},{"v":19,"t":"Didn’t Moses give you the law, and yet none of you keeps the law? Why do you seek to kill me?”"},{"v":20,"t":"The multitude answered, “You have a demon! Who seeks to kill you?”"},{"v":21,"t":"Jesus answered them, “I did one work and you all marvel because of it."},{"v":22,"t":"Moses has given you circumcision (not that it is of Moses, but of the fathers), and on the Sabbath you circumcise a boy."},{"v":23,"t":"If a boy receives circumcision on the Sabbath, that the law of Moses may not be broken, are you angry with me because I made a man completely healthy on the Sabbath?"},{"v":24,"t":"Don’t judge according to appearance, but judge righteous judgment.”"},{"v":25,"t":"Therefore some of them of Jerusalem said, “Isn’t this he whom they seek to kill?"},{"v":26,"t":"Behold, he speaks openly, and they say nothing to him. Can it be that the rulers indeed know that this is truly the Christ?"},{"v":27,"t":"However, we know where this man comes from, but when the Christ comes, no one will know where he comes from.”"},{"v":28,"t":"Jesus therefore cried out in the temple, teaching and saying, “You both know me, and know where I am from. I have not come of myself, but he who sent me is true, whom you don’t know."},{"v":29,"t":"I know him, because I am from him, and he sent me.”"},{"v":30,"t":"They sought therefore to take him; but no one laid a hand on him, because his hour had not yet come."},{"v":31,"t":"But of the multitude, many believed in him. They said, “When the Christ comes, he won’t do more signs than those which this man has done, will he?”"},{"v":32,"t":"The Pharisees heard the multitude murmuring these things concerning him, and the chief priests and the Pharisees sent officers to arrest him."},{"v":33,"t":"Then Jesus said, “I will be with you a little while longer, then I go to him who sent me."},{"v":34,"t":"You will seek me and won’t find me. You can’t come where I am.”"},{"v":35,"t":"The Jews therefore said among themselves, “Where will this man go that we won’t find him? Will he go to the Dispersion among the Greeks and teach the Greeks?"},{"v":36,"t":"What is this word that he said, ‘You will seek me, and won’t find me;’ and ‘Where I am, you can’t come’?”"},{"v":37,"t":"Now on the last and greatest day of the feast, Jesus stood and cried out, “If anyone is thirsty, let him come to me and drink!"},{"v":38,"t":"He who believes in me, as the Scripture has said, from within him will flow rivers of living water.”"},{"v":39,"t":"But he said this about the Spirit, which those believing in him were to receive. For the Holy Spirit was not yet given, because Jesus wasn’t yet glorified."},{"v":40,"t":"Many of the multitude therefore, when they heard these words, said, “This is truly the prophet.”"},{"v":41,"t":"Others said, “This is the Christ.” But some said, “What, does the Christ come out of Galilee?"},{"v":42,"t":"Hasn’t the Scripture said that the Christ comes of the offspring of David, and from Bethlehem, the village where David was?”"},{"v":43,"t":"So a division arose in the multitude because of him."},{"v":44,"t":"Some of them would have arrested him, but no one laid hands on him."},{"v":45,"t":"The officers therefore came to the chief priests and Pharisees; and they said to them, “Why didn’t you bring him?”"},{"v":46,"t":"The officers answered, “No man ever spoke like this man!”"},{"v":47,"t":"The Pharisees therefore answered them, “You aren’t also led astray, are you?"},{"v":48,"t":"Have any of the rulers or any of the Pharisees believed in him?"},{"v":49,"t":"But this multitude that doesn’t know the law is cursed.”"},{"v":50,"t":"Nicodemus (he who came to him by night, being one of them) said to them,"},{"v":51,"t":"“Does our law judge a man unless it first hears from him personally and knows what he does?”"},{"v":52,"t":"They answered him, “Are you also from Galilee? Search and see that no prophet has arisen out of Galilee.”"},{"v":53,"t":"Everyone went to his own house,"}]},"8":{"en":[{"v":1,"t":"but Jesus went to the Mount of Olives."},{"v":2,"t":"Now very early in the morning, he came again into the temple, and all the people came to him. He sat down and taught them."},{"v":3,"t":"The scribes and the Pharisees brought a woman taken in adultery. Having set her in the middle,"},{"v":4,"t":"they told him, “Teacher, we found this woman in adultery, in the very act."},{"v":5,"t":"Now in our law, Moses commanded us to stone such women. What then do you say about her?”"},{"v":6,"t":"They said this testing him, that they might have something to accuse him of. But Jesus stooped down and wrote on the ground with his finger."},{"v":7,"t":"But when they continued asking him, he looked up and said to them, “He who is without sin among you, let him throw the first stone at her.”"},{"v":8,"t":"Again he stooped down and wrote on the ground with his finger."},{"v":9,"t":"They, when they heard it, being convicted by their conscience, went out one by one, beginning from the oldest, even to the last. Jesus was left alone with the woman where she was, in the middle."},{"v":10,"t":"Jesus, standing up, saw her and said, “Woman, where are your accusers? Did no one condemn you?”"},{"v":11,"t":"She said, “No one, Lord.” Jesus said, “Neither do I condemn you. Go your way. From now on, sin no more.”"},{"v":12,"t":"Again, therefore, Jesus spoke to them, saying, “I am the light of the world. He who follows me will not walk in the darkness, but will have the light of life.”"},{"v":13,"t":"The Pharisees therefore said to him, “You testify about yourself. Your testimony is not valid.”"},{"v":14,"t":"Jesus answered them, “Even if I testify about myself, my testimony is true, for I know where I came from, and where I am going; but you don’t know where I came from, or where I am going."},{"v":15,"t":"You judge according to the flesh. I judge no one."},{"v":16,"t":"Even if I do judge, my judgment is true, for I am not alone, but I am with the Father who sent me."},{"v":17,"t":"It’s also written in your law that the testimony of two people is valid."},{"v":18,"t":"I am one who testifies about myself, and the Father who sent me testifies about me.”"},{"v":19,"t":"They said therefore to him, “Where is your Father?” Jesus answered, “You know neither me nor my Father. If you knew me, you would know my Father also.”"},{"v":20,"t":"Jesus spoke these words in the treasury, as he taught in the temple. Yet no one arrested him, because his hour had not yet come."},{"v":21,"t":"Jesus said therefore again to them, “I am going away, and you will seek me, and you will die in your sins. Where I go, you can’t come.”"},{"v":22,"t":"The Jews therefore said, “Will he kill himself, because he says, ‘Where I am going, you can’t come’?”"},{"v":23,"t":"He said to them, “You are from beneath. I am from above. You are of this world. I am not of this world."},{"v":24,"t":"I said therefore to you that you will die in your sins; for unless you believe that I am he, you will die in your sins.”"},{"v":25,"t":"They said therefore to him, “Who are you?” Jesus said to them, “Just what I have been saying to you from the beginning."},{"v":26,"t":"I have many things to speak and to judge concerning you. However, he who sent me is true; and the things which I heard from him, these I say to the world.”"},{"v":27,"t":"They didn’t understand that he spoke to them about the Father."},{"v":28,"t":"Jesus therefore said to them, “When you have lifted up the Son of Man, then you will know that I am he, and I do nothing of myself, but as my Father taught me, I say these things."},{"v":29,"t":"He who sent me is with me. The Father hasn’t left me alone, for I always do the things that are pleasing to him.”"},{"v":30,"t":"As he spoke these things, many believed in him."},{"v":31,"t":"Jesus therefore said to those Jews who had believed him, “If you remain in my word, then you are truly my disciples."},{"v":32,"t":"You will know the truth, and the truth will make you free.”"},{"v":33,"t":"They answered him, “We are Abraham’s offspring, and have never been in bondage to anyone. How do you say, ‘You will be made free’?”"},{"v":34,"t":"Jesus answered them, “Most certainly I tell you, everyone who commits sin is the bondservant of sin."},{"v":35,"t":"A bondservant doesn’t live in the house forever. A son remains forever."},{"v":36,"t":"If therefore the Son makes you free, you will be free indeed."},{"v":37,"t":"I know that you are Abraham’s offspring, yet you seek to kill me, because my word finds no place in you."},{"v":38,"t":"I say the things which I have seen with my Father; and you also do the things which you have seen with your father.”"},{"v":39,"t":"They answered him, “Our father is Abraham.” Jesus said to them, “If you were Abraham’s children, you would do the works of Abraham."},{"v":40,"t":"But now you seek to kill me, a man who has told you the truth which I heard from God. Abraham didn’t do this."},{"v":41,"t":"You do the works of your father.” They said to him, “We were not born of sexual immorality. We have one Father, God.”"},{"v":42,"t":"Therefore Jesus said to them, “If God were your father, you would love me, for I came out and have come from God. For I haven’t come of myself, but he sent me."},{"v":43,"t":"Why don’t you understand my speech? Because you can’t hear my word."},{"v":44,"t":"You are of your father the devil, and you want to do the desires of your father. He was a murderer from the beginning, and doesn’t stand in the truth, because there is no truth in him. When he speaks a lie, he speaks on his own; for he is a liar, and the father of lies."},{"v":45,"t":"But because I tell the truth, you don’t believe me."},{"v":46,"t":"Which of you convicts me of sin? If I tell the truth, why do you not believe me?"},{"v":47,"t":"He who is of God hears the words of God. For this cause you don’t hear, because you are not of God.”"},{"v":48,"t":"Then the Jews answered him, “Don’t we say well that you are a Samaritan, and have a demon?”"},{"v":49,"t":"Jesus answered, “I don’t have a demon, but I honor my Father and you dishonor me."},{"v":50,"t":"But I don’t seek my own glory. There is one who seeks and judges."},{"v":51,"t":"Most certainly, I tell you, if a person keeps my word, he will never see death.”"},{"v":52,"t":"Then the Jews said to him, “Now we know that you have a demon. Abraham died, as did the prophets; and you say, ‘If a man keeps my word, he will never taste of death.’"},{"v":53,"t":"Are you greater than our father Abraham, who died? The prophets died. Who do you make yourself out to be?”"},{"v":54,"t":"Jesus answered, “If I glorify myself, my glory is nothing. It is my Father who glorifies me, of whom you say that he is our God."},{"v":55,"t":"You have not known him, but I know him. If I said, ‘I don’t know him,’ I would be like you, a liar. But I know him and keep his word."},{"v":56,"t":"Your father Abraham rejoiced to see my day. He saw it and was glad.”"},{"v":57,"t":"The Jews therefore said to him, “You are not yet fifty years old! Have you seen Abraham?”"},{"v":58,"t":"Jesus said to them, “Most certainly, I tell you, before Abraham came into existence, I AM.”"},{"v":59,"t":"Therefore they took up stones to throw at him, but Jesus hid himself and went out of the temple, having gone through the middle of them, and so passed by."}]},"9":{"en":[{"v":1,"t":"As he passed by, he saw a man blind from birth."},{"v":2,"t":"His disciples asked him, “Rabbi, who sinned, this man or his parents, that he was born blind?”"},{"v":3,"t":"Jesus answered, “This man didn’t sin, nor did his parents, but that the works of God might be revealed in him."},{"v":4,"t":"I must work the works of him who sent me while it is day. The night is coming, when no one can work."},{"v":5,"t":"While I am in the world, I am the light of the world.”"},{"v":6,"t":"When he had said this, he spat on the ground, made mud with the saliva, anointed the blind man’s eyes with the mud,"},{"v":7,"t":"and said to him, “Go, wash in the pool of Siloam” (which means “Sent”). So he went away, washed, and came back seeing."},{"v":8,"t":"Therefore the neighbors and those who saw that he was blind before said, “Isn’t this he who sat and begged?”"},{"v":9,"t":"Others were saying, “It is he.” Still others were saying, “He looks like him.” He said, “I am he.”"},{"v":10,"t":"They therefore were asking him, “How were your eyes opened?”"},{"v":11,"t":"He answered, “A man called Jesus made mud, anointed my eyes, and said to me, ‘Go to the pool of Siloam and wash.’ So I went away and washed, and I received sight.”"},{"v":12,"t":"Then they asked him, “Where is he?” He said, “I don’t know.”"},{"v":13,"t":"They brought him who had been blind to the Pharisees."},{"v":14,"t":"It was a Sabbath when Jesus made the mud and opened his eyes."},{"v":15,"t":"Again therefore the Pharisees also asked him how he received his sight. He said to them, “He put mud on my eyes, I washed, and I see.”"},{"v":16,"t":"Some therefore of the Pharisees said, “This man is not from God, because he doesn’t keep the Sabbath.” Others said, “How can a man who is a sinner do such signs?” So there was division among them."},{"v":17,"t":"Therefore they asked the blind man again, “What do you say about him, because he opened your eyes?” He said, “He is a prophet.”"},{"v":18,"t":"The Jews therefore didn’t believe concerning him, that he had been blind and had received his sight, until they called the parents of him who had received his sight,"},{"v":19,"t":"and asked them, “Is this your son, whom you say was born blind? How then does he now see?”"},{"v":20,"t":"His parents answered them, “We know that this is our son, and that he was born blind;"},{"v":21,"t":"but how he now sees, we don’t know; or who opened his eyes, we don’t know. He is of age. Ask him. He will speak for himself.”"},{"v":22,"t":"His parents said these things because they feared the Jews; for the Jews had already agreed that if any man would confess him as Christ, he would be put out of the synagogue."},{"v":23,"t":"Therefore his parents said, “He is of age. Ask him.”"},{"v":24,"t":"So they called the man who was blind a second time, and said to him, “Give glory to God. We know that this man is a sinner.”"},{"v":25,"t":"He therefore answered, “I don’t know if he is a sinner. One thing I do know: that though I was blind, now I see.”"},{"v":26,"t":"They said to him again, “What did he do to you? How did he open your eyes?”"},{"v":27,"t":"He answered them, “I told you already, and you didn’t listen. Why do you want to hear it again? You don’t also want to become his disciples, do you?”"},{"v":28,"t":"They insulted him and said, “You are his disciple, but we are disciples of Moses."},{"v":29,"t":"We know that God has spoken to Moses. But as for this man, we don’t know where he comes from.”"},{"v":30,"t":"The man answered them, “How amazing! You don’t know where he comes from, yet he opened my eyes."},{"v":31,"t":"We know that God doesn’t listen to sinners, but if anyone is a worshiper of God and does his will, he listens to him."},{"v":32,"t":"Since the world began it has never been heard of that anyone opened the eyes of someone born blind."},{"v":33,"t":"If this man were not from God, he could do nothing.”"},{"v":34,"t":"They answered him, “You were altogether born in sins, and do you teach us?” Then they threw him out."},{"v":35,"t":"Jesus heard that they had thrown him out, and finding him, he said, “Do you believe in the Son of God?”"},{"v":36,"t":"He answered, “Who is he, Lord, that I may believe in him?”"},{"v":37,"t":"Jesus said to him, “You have both seen him, and it is he who speaks with you.”"},{"v":38,"t":"He said, “Lord, I believe!” and he worshiped him."},{"v":39,"t":"Jesus said, “I came into this world for judgment, that those who don’t see may see; and that those who see may become blind.”"},{"v":40,"t":"Those of the Pharisees who were with him heard these things, and said to him, “Are we also blind?”"},{"v":41,"t":"Jesus said to them, “If you were blind, you would have no sin; but now you say, ‘We see.’ Therefore your sin remains."}]},"10":{"en":[{"v":1,"t":"“Most certainly, I tell you, one who doesn’t enter by the door into the sheep fold, but climbs up some other way, is a thief and a robber."},{"v":2,"t":"But one who enters in by the door is the shepherd of the sheep."},{"v":3,"t":"The gatekeeper opens the gate for him, and the sheep listen to his voice. He calls his own sheep by name and leads them out."},{"v":4,"t":"Whenever he brings out his own sheep, he goes before them; and the sheep follow him, for they know his voice."},{"v":5,"t":"They will by no means follow a stranger, but will flee from him; for they don’t know the voice of strangers.”"},{"v":6,"t":"Jesus spoke this parable to them, but they didn’t understand what he was telling them."},{"v":7,"t":"Jesus therefore said to them again, “Most certainly, I tell you, I am the sheep’s door."},{"v":8,"t":"All who came before me are thieves and robbers, but the sheep didn’t listen to them."},{"v":9,"t":"I am the door. If anyone enters in by me, he will be saved, and will go in and go out and will find pasture."},{"v":10,"t":"The thief only comes to steal, kill, and destroy. I came that they may have life, and may have it abundantly."},{"v":11,"t":"“I am the good shepherd. The good shepherd lays down his life for the sheep."},{"v":12,"t":"He who is a hired hand, and not a shepherd, who doesn’t own the sheep, sees the wolf coming, leaves the sheep, and flees. The wolf snatches the sheep and scatters them."},{"v":13,"t":"The hired hand flees because he is a hired hand and doesn’t care for the sheep."},{"v":14,"t":"I am the good shepherd. I know my own, and I’m known by my own;"},{"v":15,"t":"even as the Father knows me, and I know the Father. I lay down my life for the sheep."},{"v":16,"t":"I have other sheep which are not of this fold. I must bring them also, and they will hear my voice. They will become one flock with one shepherd."},{"v":17,"t":"Therefore the Father loves me, because I lay down my life, that I may take it again."},{"v":18,"t":"No one takes it away from me, but I lay it down by myself. I have power to lay it down, and I have power to take it again. I received this commandment from my Father.”"},{"v":19,"t":"Therefore a division arose again among the Jews because of these words."},{"v":20,"t":"Many of them said, “He has a demon and is insane! Why do you listen to him?”"},{"v":21,"t":"Others said, “These are not the sayings of one possessed by a demon. It isn’t possible for a demon to open the eyes of the blind, is it?”"},{"v":22,"t":"It was the Feast of the Dedication at Jerusalem."},{"v":23,"t":"It was winter, and Jesus was walking in the temple, in Solomon’s porch."},{"v":24,"t":"The Jews therefore came around him and said to him, “How long will you hold us in suspense? If you are the Christ, tell us plainly.”"},{"v":25,"t":"Jesus answered them, “I told you, and you don’t believe. The works that I do in my Father’s name, these testify about me."},{"v":26,"t":"But you don’t believe, because you are not of my sheep, as I told you."},{"v":27,"t":"My sheep hear my voice, and I know them, and they follow me."},{"v":28,"t":"I give eternal life to them. They will never perish, and no one will snatch them out of my hand."},{"v":29,"t":"My Father who has given them to me is greater than all. No one is able to snatch them out of my Father’s hand."},{"v":30,"t":"I and the Father are one.”"},{"v":31,"t":"Therefore the Jews took up stones again to stone him."},{"v":32,"t":"Jesus answered them, “I have shown you many good works from my Father. For which of those works do you stone me?”"},{"v":33,"t":"The Jews answered him, “We don’t stone you for a good work, but for blasphemy, because you, being a man, make yourself God.”"},{"v":34,"t":"Jesus answered them, “Isn’t it written in your law, ‘I said, you are gods’?"},{"v":35,"t":"If he called them gods, to whom the word of God came (and the Scripture can’t be broken),"},{"v":36,"t":"do you say of him whom the Father sanctified and sent into the world, ‘You blaspheme,’ because I said, ‘I am the Son of God’?"},{"v":37,"t":"If I don’t do the works of my Father, don’t believe me."},{"v":38,"t":"But if I do them, though you don’t believe me, believe the works, that you may know and believe that the Father is in me, and I in the Father.”"},{"v":39,"t":"They sought again to seize him, and he went out of their hand."},{"v":40,"t":"He went away again beyond the Jordan into the place where John was baptizing at first, and he stayed there."},{"v":41,"t":"Many came to him. They said, “John indeed did no sign, but everything that John said about this man is true.”"},{"v":42,"t":"Many believed in him there."}]},"11":{"en":[{"v":1,"t":"Now a certain man was sick, Lazarus from Bethany, of the village of Mary and her sister, Martha."},{"v":2,"t":"It was that Mary who had anointed the Lord with ointment and wiped his feet with her hair, whose brother Lazarus was sick."},{"v":3,"t":"The sisters therefore sent to him, saying, “Lord, behold, he for whom you have great affection is sick.”"},{"v":4,"t":"But when Jesus heard it, he said, “This sickness is not to death, but for the glory of God, that God’s Son may be glorified by it.”"},{"v":5,"t":"Now Jesus loved Martha, and her sister, and Lazarus."},{"v":6,"t":"When therefore he heard that he was sick, he stayed two days in the place where he was."},{"v":7,"t":"Then after this he said to the disciples, “Let’s go into Judea again.”"},{"v":8,"t":"The disciples asked him, “Rabbi, the Jews were just trying to stone you. Are you going there again?”"},{"v":9,"t":"Jesus answered, “Aren’t there twelve hours of daylight? If a man walks in the day, he doesn’t stumble, because he sees the light of this world."},{"v":10,"t":"But if a man walks in the night, he stumbles, because the light isn’t in him.”"},{"v":11,"t":"He said these things, and after that, he said to them, “Our friend Lazarus has fallen asleep, but I am going so that I may awake him out of sleep.”"},{"v":12,"t":"The disciples therefore said, “Lord, if he has fallen asleep, he will recover.”"},{"v":13,"t":"Now Jesus had spoken of his death, but they thought that he spoke of taking rest in sleep."},{"v":14,"t":"So Jesus said to them plainly then, “Lazarus is dead."},{"v":15,"t":"I am glad for your sakes that I was not there, so that you may believe. Nevertheless, let’s go to him.”"},{"v":16,"t":"Thomas therefore, who is called Didymus, said to his fellow disciples, “Let’s also go, that we may die with him.”"},{"v":17,"t":"So when Jesus came, he found that he had been in the tomb four days already."},{"v":18,"t":"Now Bethany was near Jerusalem, about fifteen stadia away."},{"v":19,"t":"Many of the Jews had joined the women around Martha and Mary, to console them concerning their brother."},{"v":20,"t":"Then when Martha heard that Jesus was coming, she went and met him, but Mary stayed in the house."},{"v":21,"t":"Therefore Martha said to Jesus, “Lord, if you would have been here, my brother wouldn’t have died."},{"v":22,"t":"Even now I know that whatever you ask of God, God will give you.”"},{"v":23,"t":"Jesus said to her, “Your brother will rise again.”"},{"v":24,"t":"Martha said to him, “I know that he will rise again in the resurrection at the last day.”"},{"v":25,"t":"Jesus said to her, “I am the resurrection and the life. He who believes in me will still live, even if he dies."},{"v":26,"t":"Whoever lives and believes in me will never die. Do you believe this?”"},{"v":27,"t":"She said to him, “Yes, Lord. I have come to believe that you are the Christ, God’s Son, he who comes into the world.”"},{"v":28,"t":"When she had said this, she went away and called Mary, her sister, secretly, saying, “The Teacher is here and is calling you.”"},{"v":29,"t":"When she heard this, she arose quickly and went to him."},{"v":30,"t":"Now Jesus had not yet come into the village, but was in the place where Martha met him."},{"v":31,"t":"Then the Jews who were with her in the house and were consoling her, when they saw Mary, that she rose up quickly and went out, followed her, saying, “She is going to the tomb to weep there.”"},{"v":32,"t":"Therefore when Mary came to where Jesus was and saw him, she fell down at his feet, saying to him, “Lord, if you would have been here, my brother wouldn’t have died.”"},{"v":33,"t":"When Jesus therefore saw her weeping, and the Jews weeping who came with her, he groaned in the spirit and was troubled,"},{"v":34,"t":"and said, “Where have you laid him?” They told him, “Lord, come and see.”"},{"v":35,"t":"Jesus wept."},{"v":36,"t":"The Jews therefore said, “See how much affection he had for him!”"},{"v":37,"t":"Some of them said, “Couldn’t this man, who opened the eyes of him who was blind, have also kept this man from dying?”"},{"v":38,"t":"Jesus therefore, again groaning in himself, came to the tomb. Now it was a cave, and a stone lay against it."},{"v":39,"t":"Jesus said, “Take away the stone.” Martha, the sister of him who was dead, said to him, “Lord, by this time there is a stench, for he has been dead four days.”"},{"v":40,"t":"Jesus said to her, “Didn’t I tell you that if you believed, you would see God’s glory?”"},{"v":41,"t":"So they took away the stone from the place where the dead man was lying. Jesus lifted up his eyes and said, “Father, I thank you that you listened to me."},{"v":42,"t":"I know that you always listen to me, but because of the multitude standing around I said this, that they may believe that you sent me.”"},{"v":43,"t":"When he had said this, he cried with a loud voice, “Lazarus, come out!”"},{"v":44,"t":"He who was dead came out, bound hand and foot with wrappings, and his face was wrapped around with a cloth. Jesus said to them, “Free him, and let him go.”"},{"v":45,"t":"Therefore many of the Jews who came to Mary and saw what Jesus did believed in him."},{"v":46,"t":"But some of them went away to the Pharisees and told them the things which Jesus had done."},{"v":47,"t":"The chief priests therefore and the Pharisees gathered a council, and said, “What are we doing? For this man does many signs."},{"v":48,"t":"If we leave him alone like this, everyone will believe in him, and the Romans will come and take away both our place and our nation.”"},{"v":49,"t":"But a certain one of them, Caiaphas, being high priest that year, said to them, “You know nothing at all,"},{"v":50,"t":"nor do you consider that it is advantageous for us that one man should die for the people, and that the whole nation not perish.”"},{"v":51,"t":"Now he didn’t say this of himself, but being high priest that year, he prophesied that Jesus would die for the nation,"},{"v":52,"t":"and not for the nation only, but that he might also gather together into one the children of God who are scattered abroad."},{"v":53,"t":"So from that day forward they took counsel that they might put him to death."},{"v":54,"t":"Jesus therefore walked no more openly among the Jews, but departed from there into the country near the wilderness, to a city called Ephraim. He stayed there with his disciples."},{"v":55,"t":"Now the Passover of the Jews was at hand. Many went up from the country to Jerusalem before the Passover, to purify themselves."},{"v":56,"t":"Then they sought for Jesus and spoke with one another as they stood in the temple, “What do you think—that he isn’t coming to the feast at all?”"},{"v":57,"t":"Now the chief priests and the Pharisees had commanded that if anyone knew where he was, he should report it, that they might seize him."}]},"12":{"en":[{"v":1,"t":"Then, six days before the Passover, Jesus came to Bethany, where Lazarus was, who had been dead, whom he raised from the dead."},{"v":2,"t":"So they made him a supper there. Martha served, but Lazarus was one of those who sat at the table with him."},{"v":3,"t":"Therefore Mary took a pound of ointment of pure nard, very precious, and anointed Jesus’ feet and wiped his feet with her hair. The house was filled with the fragrance of the ointment."},{"v":4,"t":"Then Judas Iscariot, Simon’s son, one of his disciples, who would betray him, said,"},{"v":5,"t":"“Why wasn’t this ointment sold for three hundred denarii and given to the poor?”"},{"v":6,"t":"Now he said this, not because he cared for the poor, but because he was a thief, and having the money box, used to steal what was put into it."},{"v":7,"t":"But Jesus said, “Leave her alone. She has kept this for the day of my burial."},{"v":8,"t":"For you always have the poor with you, but you don’t always have me.”"},{"v":9,"t":"A large crowd therefore of the Jews learned that he was there; and they came, not for Jesus’ sake only, but that they might see Lazarus also, whom he had raised from the dead."},{"v":10,"t":"But the chief priests conspired to put Lazarus to death also,"},{"v":11,"t":"because on account of him many of the Jews went away and believed in Jesus."},{"v":12,"t":"On the next day a great multitude had come to the feast. When they heard that Jesus was coming to Jerusalem,"},{"v":13,"t":"they took the branches of the palm trees and went out to meet him, and cried out, “Hosanna! Blessed is he who comes in the name of the Lord, the King of Israel!”"},{"v":14,"t":"Jesus, having found a young donkey, sat on it. As it is written,"},{"v":15,"t":"“Don’t be afraid, daughter of Zion. Behold, your King comes, sitting on a donkey’s colt.”"},{"v":16,"t":"His disciples didn’t understand these things at first, but when Jesus was glorified, then they remembered that these things were written about him, and that they had done these things to him."},{"v":17,"t":"The multitude therefore that was with him when he called Lazarus out of the tomb and raised him from the dead was testifying about it."},{"v":18,"t":"For this cause also the multitude went and met him, because they heard that he had done this sign."},{"v":19,"t":"The Pharisees therefore said among themselves, “See how you accomplish nothing. Behold, the world has gone after him.”"},{"v":20,"t":"Now there were certain Greeks among those who went up to worship at the feast."},{"v":21,"t":"Therefore, these came to Philip, who was from Bethsaida of Galilee, and asked him, saying, “Sir, we want to see Jesus.”"},{"v":22,"t":"Philip came and told Andrew, and in turn, Andrew came with Philip, and they told Jesus."},{"v":23,"t":"Jesus answered them, “The time has come for the Son of Man to be glorified."},{"v":24,"t":"Most certainly I tell you, unless a grain of wheat falls into the earth and dies, it remains by itself alone. But if it dies, it bears much fruit."},{"v":25,"t":"He who loves his life will lose it. He who hates his life in this world will keep it to eternal life."},{"v":26,"t":"If anyone serves me, let him follow me. Where I am, there my servant will also be. If anyone serves me, the Father will honor him."},{"v":27,"t":"“Now my soul is troubled. What shall I say? ‘Father, save me from this time’? But I came to this time for this cause."},{"v":28,"t":"Father, glorify your name!” Then a voice came out of the sky, saying, “I have both glorified it and will glorify it again.”"},{"v":29,"t":"Therefore the multitude who stood by and heard it said that it had thundered. Others said, “An angel has spoken to him.”"},{"v":30,"t":"Jesus answered, “This voice hasn’t come for my sake, but for your sakes."},{"v":31,"t":"Now is the judgment of this world. Now the prince of this world will be cast out."},{"v":32,"t":"And I, if I am lifted up from the earth, will draw all people to myself.”"},{"v":33,"t":"But he said this, signifying by what kind of death he should die."},{"v":34,"t":"The multitude answered him, “We have heard out of the law that the Christ remains forever. How do you say, ‘The Son of Man must be lifted up’? Who is this Son of Man?”"},{"v":35,"t":"Jesus therefore said to them, “Yet a little while the light is with you. Walk while you have the light, that darkness doesn’t overtake you. He who walks in the darkness doesn’t know where he is going."},{"v":36,"t":"While you have the light, believe in the light, that you may become children of light.” Jesus said these things, and he departed and hid himself from them."},{"v":37,"t":"But though he had done so many signs before them, yet they didn’t believe in him,"},{"v":38,"t":"that the word of Isaiah the prophet might be fulfilled, which he spoke: “Lord, who has believed our report? To whom has the arm of the Lord been revealed?”"},{"v":39,"t":"For this cause they couldn’t believe, for Isaiah said again:"},{"v":40,"t":"“He has blinded their eyes and he hardened their heart, lest they should see with their eyes, and perceive with their heart, and would turn, and I would heal them.”"},{"v":41,"t":"Isaiah said these things when he saw his glory, and spoke of him."},{"v":42,"t":"Nevertheless, even many of the rulers believed in him, but because of the Pharisees they didn’t confess it, so that they wouldn’t be put out of the synagogue,"},{"v":43,"t":"for they loved men’s praise more than God’s praise."},{"v":44,"t":"Jesus cried out and said, “Whoever believes in me, believes not in me, but in him who sent me."},{"v":45,"t":"He who sees me sees him who sent me."},{"v":46,"t":"I have come as a light into the world, that whoever believes in me may not remain in the darkness."},{"v":47,"t":"If anyone listens to my sayings and doesn’t believe, I don’t judge him. For I came not to judge the world, but to save the world."},{"v":48,"t":"He who rejects me, and doesn’t receive my sayings, has one who judges him. The word that I spoke will judge him in the last day."},{"v":49,"t":"For I spoke not from myself, but the Father who sent me gave me a commandment, what I should say and what I should speak."},{"v":50,"t":"I know that his commandment is eternal life. The things therefore which I speak, even as the Father has said to me, so I speak.”"}]},"13":{"en":[{"v":1,"t":"Now before the feast of the Passover, Jesus, knowing that his time had come that he would depart from this world to the Father, having loved his own who were in the world, he loved them to the end."},{"v":2,"t":"During supper, the devil having already put into the heart of Judas Iscariot, Simon’s son, to betray him,"},{"v":3,"t":"Jesus, knowing that the Father had given all things into his hands, and that he came from God and was going to God,"},{"v":4,"t":"arose from supper, and laid aside his outer garments. He took a towel and wrapped a towel around his waist."},{"v":5,"t":"Then he poured water into the basin, and began to wash the disciples’ feet and to wipe them with the towel that was wrapped around him."},{"v":6,"t":"Then he came to Simon Peter. He said to him, “Lord, do you wash my feet?”"},{"v":7,"t":"Jesus answered him, “You don’t know what I am doing now, but you will understand later.”"},{"v":8,"t":"Peter said to him, “You will never wash my feet!” Jesus answered him, “If I don’t wash you, you have no part with me.”"},{"v":9,"t":"Simon Peter said to him, “Lord, not my feet only, but also my hands and my head!”"},{"v":10,"t":"Jesus said to him, “Someone who has bathed only needs to have his feet washed, but is completely clean. You are clean, but not all of you.”"},{"v":11,"t":"For he knew him who would betray him; therefore he said, “You are not all clean.”"},{"v":12,"t":"So when he had washed their feet, put his outer garment back on, and sat down again, he said to them, “Do you know what I have done to you?"},{"v":13,"t":"You call me, ‘Teacher’ and ‘Lord.’ You say so correctly, for so I am."},{"v":14,"t":"If I then, the Lord and the Teacher, have washed your feet, you also ought to wash one another’s feet."},{"v":15,"t":"For I have given you an example, that you should also do as I have done to you."},{"v":16,"t":"Most certainly I tell you, a servant is not greater than his lord, neither is one who is sent greater than he who sent him."},{"v":17,"t":"If you know these things, blessed are you if you do them."},{"v":18,"t":"I don’t speak concerning all of you. I know whom I have chosen; but that the Scripture may be fulfilled, ‘He who eats bread with me has lifted up his heel against me.’"},{"v":19,"t":"From now on, I tell you before it happens, that when it happens, you may believe that I am he."},{"v":20,"t":"Most certainly I tell you, he who receives whomever I send, receives me; and he who receives me, receives him who sent me.”"},{"v":21,"t":"When Jesus had said this, he was troubled in spirit, and testified, “Most certainly I tell you that one of you will betray me.”"},{"v":22,"t":"The disciples looked at one another, perplexed about whom he spoke."},{"v":23,"t":"One of his disciples, whom Jesus loved, was at the table, leaning against Jesus’ chest."},{"v":24,"t":"Simon Peter therefore beckoned to him, and said to him, “Tell us who it is of whom he speaks.”"},{"v":25,"t":"He, leaning back, as he was, on Jesus’ chest, asked him, “Lord, who is it?”"},{"v":26,"t":"Jesus therefore answered, “It is he to whom I will give this piece of bread when I have dipped it.” So when he had dipped the piece of bread, he gave it to Judas, the son of Simon Iscariot."},{"v":27,"t":"After the piece of bread, then Satan entered into him. Then Jesus said to him, “What you do, do quickly.”"},{"v":28,"t":"Now nobody at the table knew why he said this to him."},{"v":29,"t":"For some thought, because Judas had the money box, that Jesus said to him, “Buy what things we need for the feast,” or that he should give something to the poor."},{"v":30,"t":"Therefore having received that morsel, he went out immediately. It was night."},{"v":31,"t":"When he had gone out, Jesus said, “Now the Son of Man has been glorified, and God has been glorified in him."},{"v":32,"t":"If God has been glorified in him, God will also glorify him in himself, and he will glorify him immediately."},{"v":33,"t":"Little children, I will be with you a little while longer. You will seek me, and as I said to the Jews, ‘Where I am going, you can’t come,’ so now I tell you."},{"v":34,"t":"A new commandment I give to you, that you love one another. Just as I have loved you, you also love one another."},{"v":35,"t":"By this everyone will know that you are my disciples, if you have love for one another.”"},{"v":36,"t":"Simon Peter said to him, “Lord, where are you going?” Jesus answered, “Where I am going, you can’t follow now, but you will follow afterwards.”"},{"v":37,"t":"Peter said to him, “Lord, why can’t I follow you now? I will lay down my life for you.”"},{"v":38,"t":"Jesus answered him, “Will you lay down your life for me? Most certainly I tell you, the rooster won’t crow until you have denied me three times."}]},"14":{"en":[{"v":1,"t":"“Don’t let your heart be troubled. Believe in God. Believe also in me."},{"v":2,"t":"In my Father’s house are many homes. If it weren’t so, I would have told you. I am going to prepare a place for you."},{"v":3,"t":"If I go and prepare a place for you, I will come again and will receive you to myself; that where I am, you may be there also."},{"v":4,"t":"You know where I go, and you know the way.”"},{"v":5,"t":"Thomas said to him, “Lord, we don’t know where you are going. How can we know the way?”"},{"v":6,"t":"Jesus said to him, “I am the way, the truth, and the life. No one comes to the Father, except through me."},{"v":7,"t":"If you had known me, you would have known my Father also. From now on, you know him and have seen him.”"},{"v":8,"t":"Philip said to him, “Lord, show us the Father, and that will be enough for us.”"},{"v":9,"t":"Jesus said to him, “Have I been with you such a long time, and do you not know me, Philip? He who has seen me has seen the Father. How do you say, ‘Show us the Father’?"},{"v":10,"t":"Don’t you believe that I am in the Father, and the Father in me? The words that I tell you, I speak not from myself; but the Father who lives in me does his works."},{"v":11,"t":"Believe me that I am in the Father, and the Father in me; or else believe me for the very works’ sake."},{"v":12,"t":"Most certainly I tell you, he who believes in me, the works that I do, he will do also; and he will do greater works than these, because I am going to my Father."},{"v":13,"t":"Whatever you will ask in my name, I will do it, that the Father may be glorified in the Son."},{"v":14,"t":"If you will ask anything in my name, I will do it."},{"v":15,"t":"If you love me, keep my commandments."},{"v":16,"t":"I will pray to the Father, and he will give you another Counselor, that he may be with you forever:"},{"v":17,"t":"the Spirit of truth, whom the world can’t receive, for it doesn’t see him and doesn’t know him. You know him, for he lives with you and will be in you."},{"v":18,"t":"I will not leave you orphans. I will come to you."},{"v":19,"t":"Yet a little while, and the world will see me no more; but you will see me. Because I live, you will live also."},{"v":20,"t":"In that day you will know that I am in my Father, and you in me, and I in you."},{"v":21,"t":"One who has my commandments and keeps them, that person is one who loves me. One who loves me will be loved by my Father, and I will love him, and will reveal myself to him.”"},{"v":22,"t":"Judas (not Iscariot) said to him, “Lord, what has happened that you are about to reveal yourself to us, and not to the world?”"},{"v":23,"t":"Jesus answered him, “If a man loves me, he will keep my word. My Father will love him, and we will come to him and make our home with him."},{"v":24,"t":"He who doesn’t love me doesn’t keep my words. The word which you hear isn’t mine, but the Father’s who sent me."},{"v":25,"t":"“I have said these things to you while still living with you."},{"v":26,"t":"But the Counselor, the Holy Spirit, whom the Father will send in my name, will teach you all things, and will remind you of all that I said to you."},{"v":27,"t":"Peace I leave with you. My peace I give to you; not as the world gives, I give to you. Don’t let your heart be troubled, neither let it be fearful."},{"v":28,"t":"You heard how I told you, ‘I am going away, and I will come back to you.’ If you loved me, you would have rejoiced because I said ‘I am going to my Father;’ for the Father is greater than I."},{"v":29,"t":"Now I have told you before it happens so that when it happens, you may believe."},{"v":30,"t":"I will no more speak much with you, for the prince of the world comes, and he has nothing in me."},{"v":31,"t":"But that the world may know that I love the Father, and as the Father commanded me, even so I do. Arise, let’s go from here."}]},"15":{"en":[{"v":1,"t":"“I am the true vine, and my Father is the farmer."},{"v":2,"t":"Every branch in me that doesn’t bear fruit, he takes away. Every branch that bears fruit, he prunes, that it may bear more fruit."},{"v":3,"t":"You are already pruned clean because of the word which I have spoken to you."},{"v":4,"t":"Remain in me, and I in you. As the branch can’t bear fruit by itself unless it remains in the vine, so neither can you, unless you remain in me."},{"v":5,"t":"I am the vine. You are the branches. He who remains in me and I in him bears much fruit, for apart from me you can do nothing."},{"v":6,"t":"If a man doesn’t remain in me, he is thrown out as a branch and is withered; and they gather them, throw them into the fire, and they are burned."},{"v":7,"t":"If you remain in me, and my words remain in you, you will ask whatever you desire, and it will be done for you."},{"v":8,"t":"“In this my Father is glorified, that you bear much fruit; and so you will be my disciples."},{"v":9,"t":"Even as the Father has loved me, I also have loved you. Remain in my love."},{"v":10,"t":"If you keep my commandments, you will remain in my love, even as I have kept my Father’s commandments and remain in his love."},{"v":11,"t":"I have spoken these things to you, that my joy may remain in you, and that your joy may be made full."},{"v":12,"t":"“This is my commandment, that you love one another, even as I have loved you."},{"v":13,"t":"Greater love has no one than this, that someone lay down his life for his friends."},{"v":14,"t":"You are my friends if you do whatever I command you."},{"v":15,"t":"No longer do I call you servants, for the servant doesn’t know what his lord does. But I have called you friends, for everything that I heard from my Father, I have made known to you."},{"v":16,"t":"You didn’t choose me, but I chose you and appointed you, that you should go and bear fruit, and that your fruit should remain; that whatever you will ask of the Father in my name, he may give it to you."},{"v":17,"t":"“I command these things to you, that you may love one another."},{"v":18,"t":"If the world hates you, you know that it has hated me before it hated you."},{"v":19,"t":"If you were of the world, the world would love its own. But because you are not of the world, since I chose you out of the world, therefore the world hates you."},{"v":20,"t":"Remember the word that I said to you: ‘A servant is not greater than his lord.’ If they persecuted me, they will also persecute you. If they kept my word, they will also keep yours."},{"v":21,"t":"But they will do all these things to you for my name’s sake, because they don’t know him who sent me."},{"v":22,"t":"If I had not come and spoken to them, they would not have had sin; but now they have no excuse for their sin."},{"v":23,"t":"He who hates me, hates my Father also."},{"v":24,"t":"If I hadn’t done among them the works which no one else did, they wouldn’t have had sin. But now they have seen and also hated both me and my Father."},{"v":25,"t":"But this happened so that the word may be fulfilled which was written in their law, ‘They hated me without a cause.’"},{"v":26,"t":"“When the Counselor has come, whom I will send to you from the Father, the Spirit of truth, who proceeds from the Father, he will testify about me."},{"v":27,"t":"You will also testify, because you have been with me from the beginning."}]},"16":{"en":[{"v":1,"t":"“I have said these things to you so that you wouldn’t be caused to stumble."},{"v":2,"t":"They will put you out of the synagogues. Yes, the time is coming that whoever kills you will think that he offers service to God."},{"v":3,"t":"They will do these things because they have not known the Father nor me."},{"v":4,"t":"But I have told you these things so that when the time comes, you may remember that I told you about them. I didn’t tell you these things from the beginning, because I was with you."},{"v":5,"t":"But now I am going to him who sent me, and none of you asks me, ‘Where are you going?’"},{"v":6,"t":"But because I have told you these things, sorrow has filled your heart."},{"v":7,"t":"Nevertheless I tell you the truth: It is to your advantage that I go away; for if I don’t go away, the Counselor won’t come to you. But if I go, I will send him to you."},{"v":8,"t":"When he has come, he will convict the world about sin, about righteousness, and about judgment;"},{"v":9,"t":"about sin, because they don’t believe in me;"},{"v":10,"t":"about righteousness, because I am going to my Father, and you won’t see me any more;"},{"v":11,"t":"about judgment, because the prince of this world has been judged."},{"v":12,"t":"“I still have many things to tell you, but you can’t bear them now."},{"v":13,"t":"However, when he, the Spirit of truth, has come, he will guide you into all truth, for he will not speak from himself; but whatever he hears, he will speak. He will declare to you things that are coming."},{"v":14,"t":"He will glorify me, for he will take from what is mine and will declare it to you."},{"v":15,"t":"All things that the Father has are mine; therefore I said that he takes of mine and will declare it to you."},{"v":16,"t":"“A little while, and you will not see me. Again a little while, and you will see me.”"},{"v":17,"t":"Some of his disciples therefore said to one another, “What is this that he says to us, ‘A little while, and you won’t see me, and again a little while, and you will see me;’ and, ‘Because I go to the Father’?”"},{"v":18,"t":"They said therefore, “What is this that he says, ‘A little while’? We don’t know what he is saying.”"},{"v":19,"t":"Therefore Jesus perceived that they wanted to ask him, and he said to them, “Do you inquire among yourselves concerning this, that I said, ‘A little while, and you won’t see me, and again a little while, and you will see me’?"},{"v":20,"t":"Most certainly I tell you that you will weep and lament, but the world will rejoice. You will be sorrowful, but your sorrow will be turned into joy."},{"v":21,"t":"A woman, when she gives birth, has sorrow because her time has come. But when she has delivered the child, she doesn’t remember the anguish any more, for the joy that a human being is born into the world."},{"v":22,"t":"Therefore you now have sorrow, but I will see you again, and your heart will rejoice, and no one will take your joy away from you."},{"v":23,"t":"“In that day you will ask me no questions. Most certainly I tell you, whatever you may ask of the Father in my name, he will give it to you."},{"v":24,"t":"Until now, you have asked nothing in my name. Ask, and you will receive, that your joy may be made full."},{"v":25,"t":"“I have spoken these things to you in figures of speech. But the time is coming when I will no more speak to you in figures of speech, but will tell you plainly about the Father."},{"v":26,"t":"In that day you will ask in my name; and I don’t say to you that I will pray to the Father for you,"},{"v":27,"t":"for the Father himself loves you, because you have loved me, and have believed that I came from God."},{"v":28,"t":"I came from the Father and have come into the world. Again, I leave the world and go to the Father.”"},{"v":29,"t":"His disciples said to him, “Behold, now you are speaking plainly, and using no figures of speech."},{"v":30,"t":"Now we know that you know all things, and don’t need for anyone to question you. By this we believe that you came from God.”"},{"v":31,"t":"Jesus answered them, “Do you now believe?"},{"v":32,"t":"Behold, the time is coming, yes, and has now come, that you will be scattered, everyone to his own place, and you will leave me alone. Yet I am not alone, because the Father is with me."},{"v":33,"t":"I have told you these things, that in me you may have peace. In the world you have trouble; but cheer up! I have overcome the world.”"}]},"17":{"en":[{"v":1,"t":"Jesus said these things, then lifting up his eyes to heaven, he said, “Father, the time has come. Glorify your Son, that your Son may also glorify you;"},{"v":2,"t":"even as you gave him authority over all flesh, so he will give eternal life to all whom you have given him."},{"v":3,"t":"This is eternal life, that they should know you, the only true God, and him whom you sent, Jesus Christ."},{"v":4,"t":"I glorified you on the earth. I have accomplished the work which you have given me to do."},{"v":5,"t":"Now, Father, glorify me with your own self with the glory which I had with you before the world existed."},{"v":6,"t":"“I revealed your name to the people whom you have given me out of the world. They were yours, and you have given them to me. They have kept your word."},{"v":7,"t":"Now they have known that all things whatever you have given me are from you,"},{"v":8,"t":"for the words which you have given me I have given to them; and they received them, and knew for sure that I came from you. They have believed that you sent me."},{"v":9,"t":"I pray for them. I don’t pray for the world, but for those whom you have given me, for they are yours."},{"v":10,"t":"All things that are mine are yours, and yours are mine, and I am glorified in them."},{"v":11,"t":"I am no more in the world, but these are in the world, and I am coming to you. Holy Father, keep them through your name which you have given me, that they may be one, even as we are."},{"v":12,"t":"While I was with them in the world, I kept them in your name. I have kept those whom you have given me. None of them is lost except the son of destruction, that the Scripture might be fulfilled."},{"v":13,"t":"But now I come to you, and I say these things in the world, that they may have my joy made full in themselves."},{"v":14,"t":"I have given them your word. The world hated them because they are not of the world, even as I am not of the world."},{"v":15,"t":"I pray not that you would take them from the world, but that you would keep them from the evil one."},{"v":16,"t":"They are not of the world, even as I am not of the world."},{"v":17,"t":"Sanctify them in your truth. Your word is truth."},{"v":18,"t":"As you sent me into the world, even so I have sent them into the world."},{"v":19,"t":"For their sakes I sanctify myself, that they themselves also may be sanctified in truth."},{"v":20,"t":"“Not for these only do I pray, but for those also who will believe in me through their word,"},{"v":21,"t":"that they may all be one; even as you, Father, are in me, and I in you, that they also may be one in us; that the world may believe that you sent me."},{"v":22,"t":"The glory which you have given me, I have given to them, that they may be one, even as we are one,"},{"v":23,"t":"I in them, and you in me, that they may be perfected into one, that the world may know that you sent me and loved them, even as you loved me."},{"v":24,"t":"Father, I desire that they also whom you have given me be with me where I am, that they may see my glory which you have given me, for you loved me before the foundation of the world."},{"v":25,"t":"Righteous Father, the world hasn’t known you, but I knew you; and these knew that you sent me."},{"v":26,"t":"I made known to them your name, and will make it known; that the love with which you loved me may be in them, and I in them.”"}]},"18":{"en":[{"v":1,"t":"When Jesus had spoken these words, he went out with his disciples over the brook Kidron, where there was a garden, into which he and his disciples entered."},{"v":2,"t":"Now Judas, who betrayed him, also knew the place, for Jesus often met there with his disciples."},{"v":3,"t":"Judas then, having taken a detachment of soldiers and officers from the chief priests and the Pharisees, came there with lanterns, torches, and weapons."},{"v":4,"t":"Jesus therefore, knowing all the things that were happening to him, went out and said to them, “Who are you looking for?”"},{"v":5,"t":"They answered him, “Jesus of Nazareth.” Jesus said to them, “I am he.” Judas also, who betrayed him, was standing with them."},{"v":6,"t":"When therefore he said to them, “I am he,” they went backward and fell to the ground."},{"v":7,"t":"Again therefore he asked them, “Who are you looking for?” They said, “Jesus of Nazareth.”"},{"v":8,"t":"Jesus answered, “I told you that I am he. If therefore you seek me, let these go their way,”"},{"v":9,"t":"that the word might be fulfilled which he spoke, “Of those whom you have given me, I have lost none.”"},{"v":10,"t":"Simon Peter therefore, having a sword, drew it, struck the high priest’s servant, and cut off his right ear. The servant’s name was Malchus."},{"v":11,"t":"Jesus therefore said to Peter, “Put the sword into its sheath. The cup which the Father has given me, shall I not surely drink it?”"},{"v":12,"t":"So the detachment, the commanding officer, and the officers of the Jews seized Jesus and bound him,"},{"v":13,"t":"and led him to Annas first, for he was father-in-law to Caiaphas, who was high priest that year."},{"v":14,"t":"Now it was Caiaphas who advised the Jews that it was expedient that one man should perish for the people."},{"v":15,"t":"Simon Peter followed Jesus, as did another disciple. Now that disciple was known to the high priest, and entered in with Jesus into the court of the high priest;"},{"v":16,"t":"but Peter was standing at the door outside. So the other disciple, who was known to the high priest, went out and spoke to her who kept the door, and brought in Peter."},{"v":17,"t":"Then the maid who kept the door said to Peter, “Are you also one of this man’s disciples?” He said, “I am not.”"},{"v":18,"t":"Now the servants and the officers were standing there, having made a fire of coals, for it was cold. They were warming themselves. Peter was with them, standing and warming himself."},{"v":19,"t":"The high priest therefore asked Jesus about his disciples and about his teaching."},{"v":20,"t":"Jesus answered him, “I spoke openly to the world. I always taught in synagogues and in the temple, where the Jews always meet. I said nothing in secret."},{"v":21,"t":"Why do you ask me? Ask those who have heard me what I said to them. Behold, they know the things which I said.”"},{"v":22,"t":"When he had said this, one of the officers standing by slapped Jesus with his hand, saying, “Do you answer the high priest like that?”"},{"v":23,"t":"Jesus answered him, “If I have spoken evil, testify of the evil; but if well, why do you beat me?”"},{"v":24,"t":"Annas sent him bound to Caiaphas, the high priest."},{"v":25,"t":"Now Simon Peter was standing and warming himself. They said therefore to him, “You aren’t also one of his disciples, are you?” He denied it and said, “I am not.”"},{"v":26,"t":"One of the servants of the high priest, being a relative of him whose ear Peter had cut off, said, “Didn’t I see you in the garden with him?”"},{"v":27,"t":"Peter therefore denied it again, and immediately the rooster crowed."},{"v":28,"t":"They led Jesus therefore from Caiaphas into the Praetorium. It was early, and they themselves didn’t enter into the Praetorium, that they might not be defiled, but might eat the Passover."},{"v":29,"t":"Pilate therefore went out to them and said, “What accusation do you bring against this man?”"},{"v":30,"t":"They answered him, “If this man weren’t an evildoer, we wouldn’t have delivered him up to you.”"},{"v":31,"t":"Pilate therefore said to them, “Take him yourselves, and judge him according to your law.” Therefore the Jews said to him, “It is illegal for us to put anyone to death,”"},{"v":32,"t":"that the word of Jesus might be fulfilled, which he spoke, signifying by what kind of death he should die."},{"v":33,"t":"Pilate therefore entered again into the Praetorium, called Jesus, and said to him, “Are you the King of the Jews?”"},{"v":34,"t":"Jesus answered him, “Do you say this by yourself, or did others tell you about me?”"},{"v":35,"t":"Pilate answered, “I’m not a Jew, am I? Your own nation and the chief priests delivered you to me. What have you done?”"},{"v":36,"t":"Jesus answered, “My Kingdom is not of this world. If my Kingdom were of this world, then my servants would fight, that I wouldn’t be delivered to the Jews. But now my Kingdom is not from here.”"},{"v":37,"t":"Pilate therefore said to him, “Are you a king then?” Jesus answered, “You say that I am a king. For this reason I have been born, and for this reason I have come into the world, that I should testify to the truth. Everyone who is of the truth listens to my voice.”"},{"v":38,"t":"Pilate said to him, “What is truth?” When he had said this, he went out again to the Jews, and said to them, “I find no basis for a charge against him."},{"v":39,"t":"But you have a custom that I should release someone to you at the Passover. Therefore, do you want me to release to you the King of the Jews?”"},{"v":40,"t":"Then they all shouted again, saying, “Not this man, but Barabbas!” Now Barabbas was a robber."}]},"19":{"en":[{"v":1,"t":"So Pilate then took Jesus and flogged him."},{"v":2,"t":"The soldiers twisted thorns into a crown and put it on his head, and dressed him in a purple garment."},{"v":3,"t":"They kept saying, “Hail, King of the Jews!” and they kept slapping him."},{"v":4,"t":"Then Pilate went out again, and said to them, “Behold, I bring him out to you, that you may know that I find no basis for a charge against him.”"},{"v":5,"t":"Jesus therefore came out, wearing the crown of thorns and the purple garment. Pilate said to them, “Behold, the man!”"},{"v":6,"t":"When therefore the chief priests and the officers saw him, they shouted, saying, “Crucify! Crucify!” Pilate said to them, “Take him yourselves and crucify him, for I find no basis for a charge against him.”"},{"v":7,"t":"The Jews answered him, “We have a law, and by our law he ought to die, because he made himself the Son of God.”"},{"v":8,"t":"When therefore Pilate heard this saying, he was more afraid."},{"v":9,"t":"He entered into the Praetorium again, and said to Jesus, “Where are you from?” But Jesus gave him no answer."},{"v":10,"t":"Pilate therefore said to him, “Aren’t you speaking to me? Don’t you know that I have power to release you and have power to crucify you?”"},{"v":11,"t":"Jesus answered, “You would have no power at all against me, unless it were given to you from above. Therefore he who delivered me to you has greater sin.”"},{"v":12,"t":"At this, Pilate was seeking to release him, but the Jews cried out, saying, “If you release this man, you aren’t Caesar’s friend! Everyone who makes himself a king speaks against Caesar!”"},{"v":13,"t":"When Pilate therefore heard these words, he brought Jesus out and sat down on the judgment seat at a place called “The Pavement”, but in Hebrew, “Gabbatha.”"},{"v":14,"t":"Now it was the Preparation Day of the Passover, at about the sixth hour. He said to the Jews, “Behold, your King!”"},{"v":15,"t":"They cried out, “Away with him! Away with him! Crucify him!” Pilate said to them, “Shall I crucify your King?” The chief priests answered, “We have no king but Caesar!”"},{"v":16,"t":"So then he delivered him to them to be crucified. So they took Jesus and led him away."},{"v":17,"t":"He went out, bearing his cross, to the place called “The Place of a Skull”, which is called in Hebrew, “Golgotha”,"},{"v":18,"t":"where they crucified him, and with him two others, on either side one, and Jesus in the middle."},{"v":19,"t":"Pilate wrote a title also, and put it on the cross. There was written, “JESUS OF NAZARETH, THE KING OF THE JEWS.”"},{"v":20,"t":"Therefore many of the Jews read this title, for the place where Jesus was crucified was near the city; and it was written in Hebrew, in Latin, and in Greek."},{"v":21,"t":"The chief priests of the Jews therefore said to Pilate, “Don’t write, ‘The King of the Jews,’ but, ‘he said, “I am King of the Jews.”’”"},{"v":22,"t":"Pilate answered, “What I have written, I have written.”"},{"v":23,"t":"Then the soldiers, when they had crucified Jesus, took his garments and made four parts, to every soldier a part; and also the tunic. Now the tunic was without seam, woven from the top throughout."},{"v":24,"t":"Then they said to one another, “Let’s not tear it, but cast lots for it to decide whose it will be,” that the Scripture might be fulfilled, which says, “They parted my garments among them. They cast lots for my clothing.” Therefore the soldiers did these things."},{"v":25,"t":"But standing by Jesus’ cross were his mother, his mother’s sister, Mary the wife of Clopas, and Mary Magdalene."},{"v":26,"t":"Therefore when Jesus saw his mother, and the disciple whom he loved standing there, he said to his mother, “Woman, behold, your son!”"},{"v":27,"t":"Then he said to the disciple, “Behold, your mother!” From that hour, the disciple took her to his own home."},{"v":28,"t":"After this, Jesus, seeing that all things were now finished, that the Scripture might be fulfilled, said, “I am thirsty!”"},{"v":29,"t":"Now a vessel full of vinegar was set there; so they put a sponge full of the vinegar on hyssop, and held it at his mouth."},{"v":30,"t":"When Jesus therefore had received the vinegar, he said, “It is finished!” Then he bowed his head and gave up his spirit."},{"v":31,"t":"Therefore the Jews, because it was the Preparation Day, so that the bodies wouldn’t remain on the cross on the Sabbath (for that Sabbath was a special one), asked of Pilate that their legs might be broken and that they might be taken away."},{"v":32,"t":"Therefore the soldiers came and broke the legs of the first and of the other who was crucified with him;"},{"v":33,"t":"but when they came to Jesus and saw that he was already dead, they didn’t break his legs."},{"v":34,"t":"However, one of the soldiers pierced his side with a spear, and immediately blood and water came out."},{"v":35,"t":"He who has seen has testified, and his testimony is true. He knows that he tells the truth, that you may believe."},{"v":36,"t":"For these things happened that the Scripture might be fulfilled, “A bone of him will not be broken.”"},{"v":37,"t":"Again another Scripture says, “They will look on him whom they pierced.”"},{"v":38,"t":"After these things, Joseph of Arimathaea, being a disciple of Jesus, but secretly for fear of the Jews, asked of Pilate that he might take away Jesus’ body. Pilate gave him permission. He came therefore and took away his body."},{"v":39,"t":"Nicodemus, who at first came to Jesus by night, also came bringing a mixture of myrrh and aloes, about a hundred Roman pounds."},{"v":40,"t":"So they took Jesus’ body, and bound it in linen cloths with the spices, as the custom of the Jews is to bury."},{"v":41,"t":"Now in the place where he was crucified there was a garden. In the garden was a new tomb in which no man had ever yet been laid."},{"v":42,"t":"Then, because of the Jews’ Preparation Day (for the tomb was near at hand), they laid Jesus there."}]},"20":{"en":[{"v":1,"t":"Now on the first day of the week, Mary Magdalene went early, while it was still dark, to the tomb, and saw that the stone had been taken away from the tomb."},{"v":2,"t":"Therefore she ran and came to Simon Peter and to the other disciple whom Jesus loved, and said to them, “They have taken away the Lord out of the tomb, and we don’t know where they have laid him!”"},{"v":3,"t":"Therefore Peter and the other disciple went out, and they went toward the tomb."},{"v":4,"t":"They both ran together. The other disciple outran Peter and came to the tomb first."},{"v":5,"t":"Stooping and looking in, he saw the linen cloths lying there; yet he didn’t enter in."},{"v":6,"t":"Then Simon Peter came, following him, and entered into the tomb. He saw the linen cloths lying,"},{"v":7,"t":"and the cloth that had been on his head, not lying with the linen cloths, but rolled up in a place by itself."},{"v":8,"t":"So then the other disciple who came first to the tomb also entered in, and he saw and believed."},{"v":9,"t":"For as yet they didn’t know the Scripture, that he must rise from the dead."},{"v":10,"t":"So the disciples went away again to their own homes."},{"v":11,"t":"But Mary was standing outside at the tomb weeping. So as she wept, she stooped and looked into the tomb,"},{"v":12,"t":"and she saw two angels in white sitting, one at the head and one at the feet, where the body of Jesus had lain."},{"v":13,"t":"They asked her, “Woman, why are you weeping?” She said to them, “Because they have taken away my Lord, and I don’t know where they have laid him.”"},{"v":14,"t":"When she had said this, she turned around and saw Jesus standing, and didn’t know that it was Jesus."},{"v":15,"t":"Jesus said to her, “Woman, why are you weeping? Who are you looking for?” She, supposing him to be the gardener, said to him, “Sir, if you have carried him away, tell me where you have laid him, and I will take him away.”"},{"v":16,"t":"Jesus said to her, “Mary.” She turned and said to him, “Rabboni!” which is to say, “Teacher!”"},{"v":17,"t":"Jesus said to her, “Don’t hold me, for I haven’t yet ascended to my Father; but go to my brothers and tell them, ‘I am ascending to my Father and your Father, to my God and your God.’”"},{"v":18,"t":"Mary Magdalene came and told the disciples that she had seen the Lord, and that he had said these things to her."},{"v":19,"t":"When therefore it was evening on that day, the first day of the week, and when the doors were locked where the disciples were assembled, for fear of the Jews, Jesus came and stood in the middle and said to them, “Peace be to you.”"},{"v":20,"t":"When he had said this, he showed them his hands and his side. The disciples therefore were glad when they saw the Lord."},{"v":21,"t":"Jesus therefore said to them again, “Peace be to you. As the Father has sent me, even so I send you.”"},{"v":22,"t":"When he had said this, he breathed on them, and said to them, “Receive the Holy Spirit!"},{"v":23,"t":"If you forgive anyone’s sins, they have been forgiven them. If you retain anyone’s sins, they have been retained.”"},{"v":24,"t":"But Thomas, one of the twelve, called Didymus, wasn’t with them when Jesus came."},{"v":25,"t":"The other disciples therefore said to him, “We have seen the Lord!” But he said to them, “Unless I see in his hands the print of the nails, put my finger into the print of the nails, and put my hand into his side, I will not believe.”"},{"v":26,"t":"After eight days, again his disciples were inside and Thomas was with them. Jesus came, the doors being locked, and stood in the middle, and said, “Peace be to you.”"},{"v":27,"t":"Then he said to Thomas, “Reach here your finger, and see my hands. Reach here your hand, and put it into my side. Don’t be unbelieving, but believing.”"},{"v":28,"t":"Thomas answered him, “My Lord and my God!”"},{"v":29,"t":"Jesus said to him, “Because you have seen me, you have believed. Blessed are those who have not seen and have believed.”"},{"v":30,"t":"Therefore Jesus did many other signs in the presence of his disciples, which are not written in this book;"},{"v":31,"t":"but these are written that you may believe that Jesus is the Christ, the Son of God, and that believing you may have life in his name."}]},"21":{"en":[{"v":1,"t":"After these things, Jesus revealed himself again to the disciples at the sea of Tiberias. He revealed himself this way."},{"v":2,"t":"Simon Peter, Thomas called Didymus, Nathanael of Cana in Galilee, and the sons of Zebedee, and two others of his disciples were together."},{"v":3,"t":"Simon Peter said to them, “I’m going fishing.” They told him, “We are also coming with you.” They immediately went out and entered into the boat. That night, they caught nothing."},{"v":4,"t":"But when day had already come, Jesus stood on the beach; yet the disciples didn’t know that it was Jesus."},{"v":5,"t":"Jesus therefore said to them, “Children, have you anything to eat?” They answered him, “No.”"},{"v":6,"t":"He said to them, “Cast the net on the right side of the boat, and you will find some.” They cast it therefore, and now they weren’t able to draw it in for the multitude of fish."},{"v":7,"t":"That disciple therefore whom Jesus loved said to Peter, “It’s the Lord!” So when Simon Peter heard that it was the Lord, he wrapped his coat around himself (for he was naked), and threw himself into the sea."},{"v":8,"t":"But the other disciples came in the little boat (for they were not far from the land, but about two hundred cubits away), dragging the net full of fish."},{"v":9,"t":"So when they got out on the land, they saw a fire of coals there, with fish and bread laid on it."},{"v":10,"t":"Jesus said to them, “Bring some of the fish which you have just caught.”"},{"v":11,"t":"Simon Peter went up, and drew the net to land, full of one hundred fifty-three great fish. Even though there were so many, the net wasn’t torn."},{"v":12,"t":"Jesus said to them, “Come and eat breakfast!” None of the disciples dared inquire of him, “Who are you?” knowing that it was the Lord."},{"v":13,"t":"Then Jesus came and took the bread, gave it to them, and the fish likewise."},{"v":14,"t":"This is now the third time that Jesus was revealed to his disciples after he had risen from the dead."},{"v":15,"t":"So when they had eaten their breakfast, Jesus said to Simon Peter, “Simon, son of Jonah, do you love me more than these?” He said to him, “Yes, Lord; you know that I have affection for you.” He said to him, “Feed my lambs.”"},{"v":16,"t":"He said to him again a second time, “Simon, son of Jonah, do you love me?” He said to him, “Yes, Lord; you know that I have affection for you.” He said to him, “Tend my sheep.”"},{"v":17,"t":"He said to him the third time, “Simon, son of Jonah, do you have affection for me?” Peter was grieved because he asked him the third time, “Do you have affection for me?” He said to him, “Lord, you know everything. You know that I have affection for you.” Jesus said to him, “Feed my sheep."},{"v":18,"t":"Most certainly I tell you, when you were young, you dressed yourself and walked where you wanted to. But when you are old, you will stretch out your hands, and another will dress you and carry you where you don’t want to go.”"},{"v":19,"t":"Now he said this, signifying by what kind of death he would glorify God. When he had said this, he said to him, “Follow me.”"},{"v":20,"t":"Then Peter, turning around, saw a disciple following. This was the disciple whom Jesus loved, the one who had also leaned on Jesus’ chest at the supper and asked, “Lord, who is going to betray you?”"},{"v":21,"t":"Peter, seeing him, said to Jesus, “Lord, what about this man?”"},{"v":22,"t":"Jesus said to him, “If I desire that he stay until I come, what is that to you? You follow me.”"},{"v":23,"t":"This saying therefore went out among the brothers that this disciple wouldn’t die. Yet Jesus didn’t say to him that he wouldn’t die, but, “If I desire that he stay until I come, what is that to you?”"},{"v":24,"t":"This is the disciple who testifies about these things, and wrote these things. We know that his witness is true."},{"v":25,"t":"There are also many other things which Jesus did, which if they would all be written, I suppose that even the world itself wouldn’t have room for the books that would be written."}]}},"ACT":{"1":{"en":[{"v":1,"t":"The first book I wrote, Theophilus, concerned all that Jesus began both to do and to teach,"},{"v":2,"t":"until the day in which he was received up, after he had given commandment through the Holy Spirit to the apostles whom he had chosen."},{"v":3,"t":"To these he also showed himself alive after he suffered, by many proofs, appearing to them over a period of forty days and speaking about God’s Kingdom."},{"v":4,"t":"Being assembled together with them, he commanded them, “Don’t depart from Jerusalem, but wait for the promise of the Father, which you heard from me."},{"v":5,"t":"For John indeed baptized in water, but you will be baptized in the Holy Spirit not many days from now.”"},{"v":6,"t":"Therefore, when they had come together, they asked him, “Lord, are you now restoring the kingdom to Israel?”"},{"v":7,"t":"He said to them, “It isn’t for you to know times or seasons which the Father has set within his own authority."},{"v":8,"t":"But you will receive power when the Holy Spirit has come upon you. You will be witnesses to me in Jerusalem, in all Judea and Samaria, and to the uttermost parts of the earth.”"},{"v":9,"t":"When he had said these things, as they were looking, he was taken up, and a cloud received him out of their sight."},{"v":10,"t":"While they were looking steadfastly into the sky as he went, behold, two men stood by them in white clothing,"},{"v":11,"t":"who also said, “You men of Galilee, why do you stand looking into the sky? This Jesus, who was received up from you into the sky, will come back in the same way as you saw him going into the sky.”"},{"v":12,"t":"Then they returned to Jerusalem from the mountain called Olivet, which is near Jerusalem, a Sabbath day’s journey away."},{"v":13,"t":"When they had come in, they went up into the upper room where they were staying, that is Peter, John, James, Andrew, Philip, Thomas, Bartholomew, Matthew, James the son of Alphaeus, Simon the Zealot, and Judas the son of James."},{"v":14,"t":"All these with one accord continued steadfastly in prayer and supplication, along with the women and Mary the mother of Jesus, and with his brothers."},{"v":15,"t":"In these days, Peter stood up in the middle of the disciples (and the number of names was about one hundred twenty), and said,"},{"v":16,"t":"“Brothers, it was necessary that this Scripture should be fulfilled, which the Holy Spirit spoke before by the mouth of David concerning Judas, who was guide to those who took Jesus."},{"v":17,"t":"For he was counted with us, and received his portion in this ministry."},{"v":18,"t":"Now this man obtained a field with the reward for his wickedness; and falling headlong, his body burst open and all his intestines gushed out."},{"v":19,"t":"It became known to everyone who lived in Jerusalem that in their language that field was called ‘Akeldama,’ that is, ‘The field of blood.’"},{"v":20,"t":"For it is written in the book of Psalms, ‘Let his habitation be made desolate. Let no one dwell in it;’ and, ‘Let another take his office.’"},{"v":21,"t":"“Of the men therefore who have accompanied us all the time that the Lord Jesus went in and out among us,"},{"v":22,"t":"beginning from the baptism of John to the day that he was received up from us, of these one must become a witness with us of his resurrection.”"},{"v":23,"t":"They put forward two: Joseph called Barsabbas, who was also called Justus, and Matthias."},{"v":24,"t":"They prayed and said, “You, Lord, who know the hearts of all men, show which one of these two you have chosen"},{"v":25,"t":"to take part in this ministry and apostleship from which Judas fell away, that he might go to his own place.”"},{"v":26,"t":"They drew lots for them, and the lot fell on Matthias; and he was counted with the eleven apostles."}]},"2":{"en":[{"v":1,"t":"Now when the day of Pentecost had come, they were all with one accord in one place."},{"v":2,"t":"Suddenly there came from the sky a sound like the rushing of a mighty wind, and it filled all the house where they were sitting."},{"v":3,"t":"Tongues like fire appeared and were distributed to them, and one sat on each of them."},{"v":4,"t":"They were all filled with the Holy Spirit and began to speak with other languages, as the Spirit gave them the ability to speak."},{"v":5,"t":"Now there were dwelling in Jerusalem Jews, devout men, from every nation under the sky."},{"v":6,"t":"When this sound was heard, the multitude came together and were bewildered, because everyone heard them speaking in his own language."},{"v":7,"t":"They were all amazed and marveled, saying to one another, “Behold, aren’t all these who speak Galileans?"},{"v":8,"t":"How do we hear, everyone in our own native language?"},{"v":9,"t":"Parthians, Medes, Elamites, and people from Mesopotamia, Judea, Cappadocia, Pontus, Asia,"},{"v":10,"t":"Phrygia, Pamphylia, Egypt, the parts of Libya around Cyrene, visitors from Rome, both Jews and proselytes,"},{"v":11,"t":"Cretans and Arabians—we hear them speaking in our languages the mighty works of God!”"},{"v":12,"t":"They were all amazed and were perplexed, saying to one another, “What does this mean?”"},{"v":13,"t":"Others, mocking, said, “They are filled with new wine.”"},{"v":14,"t":"But Peter, standing up with the eleven, lifted up his voice and spoke out to them, “You men of Judea and all you who dwell at Jerusalem, let this be known to you, and listen to my words."},{"v":15,"t":"For these aren’t drunken, as you suppose, seeing it is only the third hour of the day."},{"v":16,"t":"But this is what has been spoken through the prophet Joel:"},{"v":17,"t":"‘It will be in the last days, says God, that I will pour out my Spirit on all flesh. Your sons and your daughters will prophesy. Your young men will see visions. Your old men will dream dreams."},{"v":18,"t":"Yes, and on my servants and on my handmaidens in those days, I will pour out my Spirit, and they will prophesy."},{"v":19,"t":"I will show wonders in the sky above, and signs on the earth beneath: blood, and fire, and billows of smoke."},{"v":20,"t":"The sun will be turned into darkness, and the moon into blood, before the great and glorious day of the Lord comes."},{"v":21,"t":"It will be that whoever will call on the name of the Lord will be saved.’"},{"v":22,"t":"“Men of Israel, hear these words! Jesus of Nazareth, a man approved by God to you by mighty works and wonders and signs which God did by him among you, even as you yourselves know,"},{"v":23,"t":"him, being delivered up by the determined counsel and foreknowledge of God, you have taken by the hand of lawless men, crucified and killed;"},{"v":24,"t":"whom God raised up, having freed him from the agony of death, because it was not possible that he should be held by it."},{"v":25,"t":"For David says concerning him, ‘I saw the Lord always before my face, for he is on my right hand, that I should not be moved."},{"v":26,"t":"Therefore my heart was glad, and my tongue rejoiced. Moreover my flesh also will dwell in hope,"},{"v":27,"t":"because you will not leave my soul in Hades, neither will you allow your Holy One to see decay."},{"v":28,"t":"You made known to me the ways of life. You will make me full of gladness with your presence.’"},{"v":29,"t":"“Brothers, I may tell you freely of the patriarch David, that he both died and was buried, and his tomb is with us to this day."},{"v":30,"t":"Therefore, being a prophet, and knowing that God had sworn with an oath to him that of the fruit of his body, according to the flesh, he would raise up the Christ to sit on his throne,"},{"v":31,"t":"he foreseeing this, spoke about the resurrection of the Christ, that his soul wasn’t left in Hades, and his flesh didn’t see decay."},{"v":32,"t":"This Jesus God raised up, to which we all are witnesses."},{"v":33,"t":"Being therefore exalted by the right hand of God, and having received from the Father the promise of the Holy Spirit, he has poured out this which you now see and hear."},{"v":34,"t":"For David didn’t ascend into the heavens, but he says himself, ‘The Lord said to my Lord, “Sit by my right hand"},{"v":35,"t":"until I make your enemies a footstool for your feet.”’"},{"v":36,"t":"“Let all the house of Israel therefore know certainly that God has made him both Lord and Christ, this Jesus whom you crucified.”"},{"v":37,"t":"Now when they heard this, they were cut to the heart, and said to Peter and the rest of the apostles, “Brothers, what shall we do?”"},{"v":38,"t":"Peter said to them, “Repent and be baptized, every one of you, in the name of Jesus Christ for the forgiveness of sins, and you will receive the gift of the Holy Spirit."},{"v":39,"t":"For the promise is to you and to your children, and to all who are far off, even as many as the Lord our God will call to himself.”"},{"v":40,"t":"With many other words he testified and exhorted them, saying, “Save yourselves from this crooked generation!”"},{"v":41,"t":"Then those who gladly received his word were baptized. There were added that day about three thousand souls."},{"v":42,"t":"They continued steadfastly in the apostles’ teaching and fellowship, in the breaking of bread, and prayer."},{"v":43,"t":"Fear came on every soul, and many wonders and signs were done through the apostles."},{"v":44,"t":"All who believed were together, and had all things in common."},{"v":45,"t":"They sold their possessions and goods, and distributed them to all, according as anyone had need."},{"v":46,"t":"Day by day, continuing steadfastly with one accord in the temple, and breaking bread at home, they took their food with gladness and singleness of heart,"},{"v":47,"t":"praising God and having favor with all the people. The Lord added to the assembly day by day those who were being saved."}]},"3":{"en":[{"v":1,"t":"Peter and John were going up into the temple at the hour of prayer, the ninth hour."},{"v":2,"t":"A certain man who was lame from his mother’s womb was being carried, whom they laid daily at the door of the temple which is called Beautiful, to ask gifts for the needy of those who entered into the temple."},{"v":3,"t":"Seeing Peter and John about to go into the temple, he asked to receive gifts for the needy."},{"v":4,"t":"Peter, fastening his eyes on him, with John, said, “Look at us.”"},{"v":5,"t":"He listened to them, expecting to receive something from them."},{"v":6,"t":"But Peter said, “I have no silver or gold, but what I have, that I give you. In the name of Jesus Christ of Nazareth, get up and walk!”"},{"v":7,"t":"He took him by the right hand and raised him up. Immediately his feet and his ankle bones received strength."},{"v":8,"t":"Leaping up, he stood and began to walk. He entered with them into the temple, walking, leaping, and praising God."},{"v":9,"t":"All the people saw him walking and praising God."},{"v":10,"t":"They recognized him, that it was he who used to sit begging for gifts for the needy at the Beautiful Gate of the temple. They were filled with wonder and amazement at what had happened to him."},{"v":11,"t":"As the lame man who was healed held on to Peter and John, all the people ran together to them in the porch that is called Solomon’s, greatly wondering."},{"v":12,"t":"When Peter saw it, he responded to the people, “You men of Israel, why do you marvel at this man? Why do you fasten your eyes on us, as though by our own power or godliness we had made him walk?"},{"v":13,"t":"The God of Abraham, Isaac, and Jacob, the God of our fathers, has glorified his Servant Jesus, whom you delivered up and denied in the presence of Pilate, when he had determined to release him."},{"v":14,"t":"But you denied the Holy and Righteous One and asked for a murderer to be granted to you,"},{"v":15,"t":"and killed the Prince of life, whom God raised from the dead, to which we are witnesses."},{"v":16,"t":"By faith in his name, his name has made this man strong, whom you see and know. Yes, the faith which is through him has given him this perfect soundness in the presence of you all."},{"v":17,"t":"“Now, brothers, I know that you did this in ignorance, as did also your rulers."},{"v":18,"t":"But the things which God announced by the mouth of all his prophets, that Christ should suffer, he thus fulfilled."},{"v":19,"t":"“Repent therefore, and turn again, that your sins may be blotted out, so that there may come times of refreshing from the presence of the Lord,"},{"v":20,"t":"and that he may send Christ Jesus, who was ordained for you before,"},{"v":21,"t":"whom heaven must receive until the times of restoration of all things, which God spoke long ago by the mouth of his holy prophets."},{"v":22,"t":"For Moses indeed said to the fathers, ‘The Lord God will raise up a prophet for you from among your brothers, like me. You shall listen to him in all things whatever he says to you."},{"v":23,"t":"It will be that every soul that will not listen to that prophet will be utterly destroyed from among the people.’"},{"v":24,"t":"Yes, and all the prophets from Samuel and those who followed after, as many as have spoken, also told of these days."},{"v":25,"t":"You are the children of the prophets, and of the covenant which God made with our fathers, saying to Abraham, ‘All the families of the earth will be blessed through your offspring.’"},{"v":26,"t":"God, having raised up his servant Jesus, sent him to you first to bless you, in turning away every one of you from your wickedness.”"}]},"4":{"en":[{"v":1,"t":"As they spoke to the people, the priests and the captain of the temple and the Sadducees came to them,"},{"v":2,"t":"being upset because they taught the people and proclaimed in Jesus the resurrection from the dead."},{"v":3,"t":"They laid hands on them, and put them in custody until the next day, for it was now evening."},{"v":4,"t":"But many of those who heard the word believed, and the number of the men came to be about five thousand."},{"v":5,"t":"In the morning, their rulers, elders, and scribes were gathered together in Jerusalem."},{"v":6,"t":"Annas the high priest was there, with Caiaphas, John, Alexander, and as many as were relatives of the high priest."},{"v":7,"t":"When they had stood Peter and John in the middle of them, they inquired, “By what power, or in what name, have you done this?”"},{"v":8,"t":"Then Peter, filled with the Holy Spirit, said to them, “You rulers of the people and elders of Israel,"},{"v":9,"t":"if we are examined today concerning a good deed done to a crippled man, by what means this man has been healed,"},{"v":10,"t":"may it be known to you all, and to all the people of Israel, that in the name of Jesus Christ of Nazareth, whom you crucified, whom God raised from the dead, this man stands here before you whole in him."},{"v":11,"t":"He is ‘the stone which was regarded as worthless by you, the builders, which has become the head of the corner.’"},{"v":12,"t":"There is salvation in no one else, for there is no other name under heaven that is given among men, by which we must be saved!”"},{"v":13,"t":"Now when they saw the boldness of Peter and John, and had perceived that they were unlearned and ignorant men, they marveled. They recognized that they had been with Jesus."},{"v":14,"t":"Seeing the man who was healed standing with them, they could say nothing against it."},{"v":15,"t":"But when they had commanded them to go aside out of the council, they conferred among themselves,"},{"v":16,"t":"saying, “What shall we do to these men? Because indeed a notable miracle has been done through them, as can be plainly seen by all who dwell in Jerusalem, and we can’t deny it."},{"v":17,"t":"But so that this spreads no further among the people, let’s threaten them, that from now on they don’t speak to anyone in this name.”"},{"v":18,"t":"They called them, and commanded them not to speak at all nor teach in the name of Jesus."},{"v":19,"t":"But Peter and John answered them, “Whether it is right in the sight of God to listen to you rather than to God, judge for yourselves,"},{"v":20,"t":"for we can’t help telling the things which we saw and heard.”"},{"v":21,"t":"When they had further threatened them, they let them go, finding no way to punish them, because of the people; for everyone glorified God for that which was done."},{"v":22,"t":"For the man on whom this miracle of healing was performed was more than forty years old."},{"v":23,"t":"Being let go, they came to their own company and reported all that the chief priests and the elders had said to them."},{"v":24,"t":"When they heard it, they lifted up their voice to God with one accord and said, “O Lord, you are God, who made the heaven, the earth, the sea, and all that is in them;"},{"v":25,"t":"who by the mouth of your servant David, said, ‘Why do the nations rage, and the peoples plot a vain thing?"},{"v":26,"t":"The kings of the earth take a stand, and the rulers plot together, against the Lord, and against his Christ.’"},{"v":27,"t":"“For truly, both Herod and Pontius Pilate, with the Gentiles and the people of Israel, were gathered together against your holy servant Jesus, whom you anointed,"},{"v":28,"t":"to do whatever your hand and your counsel foreordained to happen."},{"v":29,"t":"Now, Lord, look at their threats, and grant to your servants to speak your word with all boldness,"},{"v":30,"t":"while you stretch out your hand to heal; and that signs and wonders may be done through the name of your holy Servant Jesus.”"},{"v":31,"t":"When they had prayed, the place was shaken where they were gathered together. They were all filled with the Holy Spirit, and they spoke the word of God with boldness."},{"v":32,"t":"The multitude of those who believed were of one heart and soul. Not one of them claimed that anything of the things which he possessed was his own, but they had all things in common."},{"v":33,"t":"With great power, the apostles gave their testimony of the resurrection of the Lord Jesus. Great grace was on them all."},{"v":34,"t":"For neither was there among them any who lacked, for as many as were owners of lands or houses sold them, and brought the proceeds of the things that were sold,"},{"v":35,"t":"and laid them at the apostles’ feet; and distribution was made to each, according as anyone had need."},{"v":36,"t":"Joses, who by the apostles was also called Barnabas (which is, being interpreted, Son of Encouragement), a Levite, a man of Cyprus by race,"},{"v":37,"t":"having a field, sold it and brought the money and laid it at the apostles’ feet."}]},"5":{"en":[{"v":1,"t":"But a certain man named Ananias, with Sapphira his wife, sold a possession,"},{"v":2,"t":"and kept back part of the price, his wife also being aware of it, then brought a certain part and laid it at the apostles’ feet."},{"v":3,"t":"But Peter said, “Ananias, why has Satan filled your heart to lie to the Holy Spirit and to keep back part of the price of the land?"},{"v":4,"t":"While you kept it, didn’t it remain your own? After it was sold, wasn’t it in your power? How is it that you have conceived this thing in your heart? You haven’t lied to men, but to God.”"},{"v":5,"t":"Ananias, hearing these words, fell down and died. Great fear came on all who heard these things."},{"v":6,"t":"The young men arose and wrapped him up, and they carried him out and buried him."},{"v":7,"t":"About three hours later, his wife, not knowing what had happened, came in."},{"v":8,"t":"Peter answered her, “Tell me whether you sold the land for so much.” She said, “Yes, for so much.”"},{"v":9,"t":"But Peter asked her, “How is it that you have agreed together to tempt the Spirit of the Lord? Behold, the feet of those who have buried your husband are at the door, and they will carry you out.”"},{"v":10,"t":"She fell down immediately at his feet and died. The young men came in and found her dead, and they carried her out and buried her by her husband."},{"v":11,"t":"Great fear came on the whole assembly, and on all who heard these things."},{"v":12,"t":"By the hands of the apostles many signs and wonders were done among the people. They were all with one accord in Solomon’s porch."},{"v":13,"t":"None of the rest dared to join them; however, the people honored them."},{"v":14,"t":"More believers were added to the Lord, multitudes of both men and women."},{"v":15,"t":"They even carried out the sick into the streets and laid them on cots and mattresses, so that as Peter came by, at least his shadow might overshadow some of them."},{"v":16,"t":"The multitude also came together from the cities around Jerusalem, bringing sick people and those who were tormented by unclean spirits; and they were all healed."},{"v":17,"t":"But the high priest rose up, and all those who were with him (which is the sect of the Sadducees), and they were filled with jealousy"},{"v":18,"t":"and laid hands on the apostles, then put them in public custody."},{"v":19,"t":"But an angel of the Lord opened the prison doors by night, and brought them out and said,"},{"v":20,"t":"“Go stand and speak in the temple to the people all the words of this life.”"},{"v":21,"t":"When they heard this, they entered into the temple about daybreak and taught. But the high priest and those who were with him came and called the council together, with all the senate of the children of Israel, and sent to the prison to have them brought."},{"v":22,"t":"But the officers who came didn’t find them in the prison. They returned and reported,"},{"v":23,"t":"“We found the prison shut and locked, and the guards standing before the doors, but when we opened them, we found no one inside!”"},{"v":24,"t":"Now when the high priest, the captain of the temple, and the chief priests heard these words, they were very perplexed about them and what might become of this."},{"v":25,"t":"One came and told them, “Behold, the men whom you put in prison are in the temple, standing and teaching the people.”"},{"v":26,"t":"Then the captain went with the officers, and brought them without violence, for they were afraid that the people might stone them."},{"v":27,"t":"When they had brought them, they set them before the council. The high priest questioned them,"},{"v":28,"t":"saying, “Didn’t we strictly command you not to teach in this name? Behold, you have filled Jerusalem with your teaching, and intend to bring this man’s blood on us.”"},{"v":29,"t":"But Peter and the apostles answered, “We must obey God rather than men."},{"v":30,"t":"The God of our fathers raised up Jesus, whom you killed, hanging him on a tree."},{"v":31,"t":"God exalted him with his right hand to be a Prince and a Savior, to give repentance to Israel, and remission of sins."},{"v":32,"t":"We are his witnesses of these things; and so also is the Holy Spirit, whom God has given to those who obey him.”"},{"v":33,"t":"But they, when they heard this, were cut to the heart, and were determined to kill them."},{"v":34,"t":"But one stood up in the council, a Pharisee named Gamaliel, a teacher of the law, honored by all the people, and commanded to put the apostles out for a little while."},{"v":35,"t":"He said to them, “You men of Israel, be careful concerning these men, what you are about to do."},{"v":36,"t":"For before these days Theudas rose up, making himself out to be somebody; to whom a number of men, about four hundred, joined themselves. He was slain; and all, as many as obeyed him, were dispersed and came to nothing."},{"v":37,"t":"After this man, Judas of Galilee rose up in the days of the enrollment, and drew away some people after him. He also perished, and all, as many as obeyed him, were scattered abroad."},{"v":38,"t":"Now I tell you, withdraw from these men and leave them alone. For if this counsel or this work is of men, it will be overthrown."},{"v":39,"t":"But if it is of God, you will not be able to overthrow it, and you would be found even to be fighting against God!”"},{"v":40,"t":"They agreed with him. Summoning the apostles, they beat them and commanded them not to speak in the name of Jesus, and let them go."},{"v":41,"t":"They therefore departed from the presence of the council, rejoicing that they were counted worthy to suffer dishonor for Jesus’ name."},{"v":42,"t":"Every day, in the temple and at home, they never stopped teaching and preaching Jesus, the Christ."}]},"6":{"en":[{"v":1,"t":"Now in those days, when the number of the disciples was multiplying, a complaint arose from the Hellenists against the Hebrews, because their widows were neglected in the daily service."},{"v":2,"t":"The twelve summoned the multitude of the disciples and said, “It is not appropriate for us to forsake the word of God and serve tables."},{"v":3,"t":"Therefore, select from among you, brothers, seven men of good report, full of the Holy Spirit and of wisdom, whom we may appoint over this business."},{"v":4,"t":"But we will continue steadfastly in prayer and in the ministry of the word.”"},{"v":5,"t":"These words pleased the whole multitude. They chose Stephen, a man full of faith and of the Holy Spirit, Philip, Prochorus, Nicanor, Timon, Parmenas, and Nicolaus, a proselyte of Antioch,"},{"v":6,"t":"whom they set before the apostles. When they had prayed, they laid their hands on them."},{"v":7,"t":"The word of God increased and the number of the disciples greatly multiplied in Jerusalem. A great company of the priests were obedient to the faith."},{"v":8,"t":"Stephen, full of faith and power, performed great wonders and signs among the people."},{"v":9,"t":"But some of those who were of the synagogue called “The Libertines”, and of the Cyrenians, of the Alexandrians, and of those of Cilicia and Asia arose, disputing with Stephen."},{"v":10,"t":"They weren’t able to withstand the wisdom and the Spirit by which he spoke."},{"v":11,"t":"Then they secretly induced men to say, “We have heard him speak blasphemous words against Moses and God.”"},{"v":12,"t":"They stirred up the people, the elders, and the scribes, and came against him and seized him, then brought him in to the council,"},{"v":13,"t":"and set up false witnesses who said, “This man never stops speaking blasphemous words against this holy place and the law."},{"v":14,"t":"For we have heard him say that this Jesus of Nazareth will destroy this place, and will change the customs which Moses delivered to us.”"},{"v":15,"t":"All who sat in the council, fastening their eyes on him, saw his face like it was the face of an angel."}]},"7":{"en":[{"v":1,"t":"The high priest said, “Are these things so?”"},{"v":2,"t":"He said, “Brothers and fathers, listen. The God of glory appeared to our father Abraham when he was in Mesopotamia, before he lived in Haran,"},{"v":3,"t":"and said to him, ‘Get out of your land and away from your relatives, and come into a land which I will show you.’"},{"v":4,"t":"Then he came out of the land of the Chaldaeans and lived in Haran. From there, when his father was dead, God moved him into this land where you are now living."},{"v":5,"t":"He gave him no inheritance in it, no, not so much as to set his foot on. He promised that he would give it to him for a possession, and to his offspring after him, when he still had no child."},{"v":6,"t":"God spoke in this way: that his offspring would live as aliens in a strange land, and that they would be enslaved and mistreated for four hundred years."},{"v":7,"t":"‘I will judge the nation to which they will be in bondage,’ said God, ‘and after that they will come out and serve me in this place.’"},{"v":8,"t":"He gave him the covenant of circumcision. So Abraham became the father of Isaac, and circumcised him the eighth day. Isaac became the father of Jacob, and Jacob became the father of the twelve patriarchs."},{"v":9,"t":"“The patriarchs, moved with jealousy against Joseph, sold him into Egypt. God was with him"},{"v":10,"t":"and delivered him out of all his afflictions, and gave him favor and wisdom before Pharaoh, king of Egypt. He made him governor over Egypt and all his house."},{"v":11,"t":"Now a famine came over all the land of Egypt and Canaan, and great affliction. Our fathers found no food."},{"v":12,"t":"But when Jacob heard that there was grain in Egypt, he sent out our fathers the first time."},{"v":13,"t":"On the second time Joseph was made known to his brothers, and Joseph’s family was revealed to Pharaoh."},{"v":14,"t":"Joseph sent and summoned Jacob his father and all his relatives, seventy-five souls."},{"v":15,"t":"Jacob went down into Egypt and he died, himself and our fathers;"},{"v":16,"t":"and they were brought back to Shechem and laid in the tomb that Abraham bought for a price in silver from the children of Hamor of Shechem."},{"v":17,"t":"“But as the time of the promise came close which God had sworn to Abraham, the people grew and multiplied in Egypt,"},{"v":18,"t":"until there arose a different king who didn’t know Joseph."},{"v":19,"t":"The same took advantage of our race and mistreated our fathers, and forced them to abandon their babies, so that they wouldn’t stay alive."},{"v":20,"t":"At that time Moses was born, and was exceedingly handsome to God. He was nourished three months in his father’s house."},{"v":21,"t":"When he was abandoned, Pharaoh’s daughter took him up and reared him as her own son."},{"v":22,"t":"Moses was instructed in all the wisdom of the Egyptians. He was mighty in his words and works."},{"v":23,"t":"But when he was forty years old, it came into his heart to visit his brothers, the children of Israel."},{"v":24,"t":"Seeing one of them suffer wrong, he defended him and avenged him who was oppressed, striking the Egyptian."},{"v":25,"t":"He supposed that his brothers understood that God, by his hand, was giving them deliverance; but they didn’t understand."},{"v":26,"t":"“The day following, he appeared to them as they fought, and urged them to be at peace again, saying, ‘Sirs, you are brothers. Why do you wrong one another?’"},{"v":27,"t":"But he who did his neighbor wrong pushed him away, saying, ‘Who made you a ruler and a judge over us?"},{"v":28,"t":"Do you want to kill me as you killed the Egyptian yesterday?’"},{"v":29,"t":"Moses fled at this saying, and became a stranger in the land of Midian, where he became the father of two sons."},{"v":30,"t":"“When forty years were fulfilled, an angel of the Lord appeared to him in the wilderness of Mount Sinai, in a flame of fire in a bush."},{"v":31,"t":"When Moses saw it, he wondered at the sight. As he came close to see, the voice of the Lord came to him,"},{"v":32,"t":"‘I am the God of your fathers: the God of Abraham, the God of Isaac, and the God of Jacob.’ Moses trembled and dared not look."},{"v":33,"t":"The Lord said to him, ‘Take off your sandals, for the place where you stand is holy ground."},{"v":34,"t":"I have surely seen the affliction of my people who are in Egypt, and have heard their groaning. I have come down to deliver them. Now come, I will send you into Egypt.’"},{"v":35,"t":"“This Moses whom they refused, saying, ‘Who made you a ruler and a judge?’—God has sent him as both a ruler and a deliverer by the hand of the angel who appeared to him in the bush."},{"v":36,"t":"This man led them out, having worked wonders and signs in Egypt, in the Red Sea, and in the wilderness for forty years."},{"v":37,"t":"This is that Moses who said to the children of Israel, ‘The Lord our God will raise up a prophet for you from among your brothers, like me.’"},{"v":38,"t":"This is he who was in the assembly in the wilderness with the angel that spoke to him on Mount Sinai, and with our fathers, who received living revelations to give to us,"},{"v":39,"t":"to whom our fathers wouldn’t be obedient, but rejected him and turned back in their hearts to Egypt,"},{"v":40,"t":"saying to Aaron, ‘Make us gods that will go before us, for as for this Moses who led us out of the land of Egypt, we don’t know what has become of him.’"},{"v":41,"t":"They made a calf in those days, and brought a sacrifice to the idol, and rejoiced in the works of their hands."},{"v":42,"t":"But God turned away and gave them up to serve the army of the sky, as it is written in the book of the prophets, ‘Did you offer to me slain animals and sacrifices forty years in the wilderness, O house of Israel?"},{"v":43,"t":"You took up the tabernacle of Moloch, the star of your god Rephan, the figures which you made to worship, so I will carry you away beyond Babylon.’"},{"v":44,"t":"“Our fathers had the tabernacle of the testimony in the wilderness, even as he who spoke to Moses commanded him to make it according to the pattern that he had seen;"},{"v":45,"t":"which also our fathers, in their turn, brought in with Joshua when they entered into the possession of the nations whom God drove out before the face of our fathers to the days of David,"},{"v":46,"t":"who found favor in the sight of God, and asked to find a habitation for the God of Jacob."},{"v":47,"t":"But Solomon built him a house."},{"v":48,"t":"However, the Most High doesn’t dwell in temples made with hands, as the prophet says,"},{"v":49,"t":"‘heaven is my throne, and the earth a footstool for my feet. What kind of house will you build me?’ says the Lord. ‘Or what is the place of my rest?"},{"v":50,"t":"Didn’t my hand make all these things?’"},{"v":51,"t":"“You stiff-necked and uncircumcised in heart and ears, you always resist the Holy Spirit! As your fathers did, so you do."},{"v":52,"t":"Which of the prophets didn’t your fathers persecute? They killed those who foretold the coming of the Righteous One, of whom you have now become betrayers and murderers."},{"v":53,"t":"You received the law as it was ordained by angels, and didn’t keep it!”"},{"v":54,"t":"Now when they heard these things, they were cut to the heart, and they gnashed at him with their teeth."},{"v":55,"t":"But he, being full of the Holy Spirit, looked up steadfastly into heaven and saw the glory of God, and Jesus standing on the right hand of God,"},{"v":56,"t":"and said, “Behold, I see the heavens opened and the Son of Man standing at the right hand of God!”"},{"v":57,"t":"But they cried out with a loud voice and stopped their ears, then rushed at him with one accord."},{"v":58,"t":"They threw him out of the city and stoned him. The witnesses placed their garments at the feet of a young man named Saul."},{"v":59,"t":"They stoned Stephen as he called out, saying, “Lord Jesus, receive my spirit!”"},{"v":60,"t":"He kneeled down and cried with a loud voice, “Lord, don’t hold this sin against them!” When he had said this, he fell asleep."}]},"8":{"en":[{"v":1,"t":"Saul was consenting to his death. A great persecution arose against the assembly which was in Jerusalem in that day. They were all scattered abroad throughout the regions of Judea and Samaria, except for the apostles."},{"v":2,"t":"Devout men buried Stephen and lamented greatly over him."},{"v":3,"t":"But Saul ravaged the assembly, entering into every house and dragged both men and women off to prison."},{"v":4,"t":"Therefore those who were scattered abroad went around preaching the word."},{"v":5,"t":"Philip went down to the city of Samaria and proclaimed to them the Christ."},{"v":6,"t":"The multitudes listened with one accord to the things that were spoken by Philip when they heard and saw the signs which he did."},{"v":7,"t":"For unclean spirits came out of many of those who had them. They came out, crying with a loud voice. Many who had been paralyzed and lame were healed."},{"v":8,"t":"There was great joy in that city."},{"v":9,"t":"But there was a certain man, Simon by name, who used to practice sorcery in the city and amazed the people of Samaria, making himself out to be some great one,"},{"v":10,"t":"to whom they all listened, from the least to the greatest, saying, “This man is that great power of God.”"},{"v":11,"t":"They listened to him because for a long time he had amazed them with his sorceries."},{"v":12,"t":"But when they believed Philip preaching good news concerning God’s Kingdom and the name of Jesus Christ, they were baptized, both men and women."},{"v":13,"t":"Simon himself also believed. Being baptized, he continued with Philip. Seeing signs and great miracles occurring, he was amazed."},{"v":14,"t":"Now when the apostles who were at Jerusalem heard that Samaria had received the word of God, they sent Peter and John to them,"},{"v":15,"t":"who, when they had come down, prayed for them, that they might receive the Holy Spirit;"},{"v":16,"t":"for as yet he had fallen on none of them. They had only been baptized in the name of Christ Jesus."},{"v":17,"t":"Then they laid their hands on them, and they received the Holy Spirit."},{"v":18,"t":"Now when Simon saw that the Holy Spirit was given through the laying on of the apostles’ hands, he offered them money,"},{"v":19,"t":"saying, “Give me also this power, that whomever I lay my hands on may receive the Holy Spirit.”"},{"v":20,"t":"But Peter said to him, “May your silver perish with you, because you thought you could obtain the gift of God with money!"},{"v":21,"t":"You have neither part nor lot in this matter, for your heart isn’t right before God."},{"v":22,"t":"Repent therefore of this, your wickedness, and ask God if perhaps the thought of your heart may be forgiven you."},{"v":23,"t":"For I see that you are in the poison of bitterness and in the bondage of iniquity.”"},{"v":24,"t":"Simon answered, “Pray for me to the Lord, that none of the things which you have spoken happen to me.”"},{"v":25,"t":"They therefore, when they had testified and spoken the word of the Lord, returned to Jerusalem, and preached the Good News to many villages of the Samaritans."},{"v":26,"t":"Then an angel of the Lord spoke to Philip, saying, “Arise, and go toward the south to the way that goes down from Jerusalem to Gaza. This is a desert.”"},{"v":27,"t":"He arose and went; and behold, there was a man of Ethiopia, a eunuch of great authority under Candace, queen of the Ethiopians, who was over all her treasure, who had come to Jerusalem to worship."},{"v":28,"t":"He was returning and sitting in his chariot, and was reading the prophet Isaiah."},{"v":29,"t":"The Spirit said to Philip, “Go near, and join yourself to this chariot.”"},{"v":30,"t":"Philip ran to him, and heard him reading Isaiah the prophet, and said, “Do you understand what you are reading?”"},{"v":31,"t":"He said, “How can I, unless someone explains it to me?” He begged Philip to come up and sit with him."},{"v":32,"t":"Now the passage of the Scripture which he was reading was this, “He was led as a sheep to the slaughter. As a lamb before his shearer is silent, so he doesn’t open his mouth."},{"v":33,"t":"In his humiliation, his judgment was taken away. Who will declare His generation? For his life is taken from the earth.”"},{"v":34,"t":"The eunuch answered Philip, “Who is the prophet talking about? About himself, or about someone else?”"},{"v":35,"t":"Philip opened his mouth, and beginning from this Scripture, preached to him about Jesus."},{"v":36,"t":"As they went on the way, they came to some water; and the eunuch said, “Behold, here is water. What is keeping me from being baptized?”"},{"v":38,"t":"He commanded the chariot to stand still, and they both went down into the water, both Philip and the eunuch, and he baptized him."},{"v":39,"t":"When they came up out of the water, the Spirit of the Lord caught Philip away, and the eunuch didn’t see him any more, for he went on his way rejoicing."},{"v":40,"t":"But Philip was found at Azotus. Passing through, he preached the Good News to all the cities until he came to Caesarea."}]},"9":{"en":[{"v":1,"t":"But Saul, still breathing threats and slaughter against the disciples of the Lord, went to the high priest"},{"v":2,"t":"and asked for letters from him to the synagogues of Damascus, that if he found any who were of the Way, whether men or women, he might bring them bound to Jerusalem."},{"v":3,"t":"As he traveled, he got close to Damascus, and suddenly a light from the sky shone around him."},{"v":4,"t":"He fell on the earth, and heard a voice saying to him, “Saul, Saul, why do you persecute me?”"},{"v":5,"t":"He said, “Who are you, Lord?” The Lord said, “I am Jesus, whom you are persecuting."},{"v":6,"t":"But rise up and enter into the city, then you will be told what you must do.”"},{"v":7,"t":"The men who traveled with him stood speechless, hearing the sound, but seeing no one."},{"v":8,"t":"Saul arose from the ground, and when his eyes were opened, he saw no one. They led him by the hand and brought him into Damascus."},{"v":9,"t":"He was without sight for three days, and neither ate nor drank."},{"v":10,"t":"Now there was a certain disciple at Damascus named Ananias. The Lord said to him in a vision, “Ananias!” He said, “Behold, it’s me, Lord.”"},{"v":11,"t":"The Lord said to him, “Arise and go to the street which is called Straight, and inquire in the house of Judah for one named Saul, a man of Tarsus. For behold, he is praying,"},{"v":12,"t":"and in a vision he has seen a man named Ananias coming in and laying his hands on him, that he might receive his sight.”"},{"v":13,"t":"But Ananias answered, “Lord, I have heard from many about this man, how much evil he did to your saints at Jerusalem."},{"v":14,"t":"Here he has authority from the chief priests to bind all who call on your name.”"},{"v":15,"t":"But the Lord said to him, “Go your way, for he is my chosen vessel to bear my name before the nations and kings, and the children of Israel."},{"v":16,"t":"For I will show him how many things he must suffer for my name’s sake.”"},{"v":17,"t":"Ananias departed and entered into the house. Laying his hands on him, he said, “Brother Saul, the Lord, who appeared to you on the road by which you came, has sent me that you may receive your sight and be filled with the Holy Spirit.”"},{"v":18,"t":"Immediately something like scales fell from his eyes, and he received his sight. He arose and was baptized."},{"v":19,"t":"He took food and was strengthened. Saul stayed several days with the disciples who were at Damascus."},{"v":20,"t":"Immediately in the synagogues he proclaimed the Christ, that he is the Son of God."},{"v":21,"t":"All who heard him were amazed, and said, “Isn’t this he who in Jerusalem made havoc of those who called on this name? And he had come here intending to bring them bound before the chief priests!”"},{"v":22,"t":"But Saul increased more in strength, and confounded the Jews who lived at Damascus, proving that this is the Christ."},{"v":23,"t":"When many days were fulfilled, the Jews conspired together to kill him,"},{"v":24,"t":"but their plot became known to Saul. They watched the gates both day and night that they might kill him,"},{"v":25,"t":"but his disciples took him by night and let him down through the wall, lowering him in a basket."},{"v":26,"t":"When Saul had come to Jerusalem, he tried to join himself to the disciples; but they were all afraid of him, not believing that he was a disciple."},{"v":27,"t":"But Barnabas took him and brought him to the apostles, and declared to them how he had seen the Lord on the way, and that he had spoken to him, and how at Damascus he had preached boldly in the name of Jesus."},{"v":28,"t":"He was with them entering into Jerusalem,"},{"v":29,"t":"preaching boldly in the name of the Lord Jesus. He spoke and disputed against the Hellenists, but they were seeking to kill him."},{"v":30,"t":"When the brothers knew it, they brought him down to Caesarea and sent him off to Tarsus."},{"v":31,"t":"So the assemblies throughout all Judea, Galilee, and Samaria had peace and were built up. They were multiplied, walking in the fear of the Lord and in the comfort of the Holy Spirit."},{"v":32,"t":"As Peter went throughout all those parts, he came down also to the saints who lived at Lydda."},{"v":33,"t":"There he found a certain man named Aeneas, who had been bedridden for eight years because he was paralyzed."},{"v":34,"t":"Peter said to him, “Aeneas, Jesus Christ heals you. Get up and make your bed!” Immediately he arose."},{"v":35,"t":"All who lived at Lydda and in Sharon saw him, and they turned to the Lord."},{"v":36,"t":"Now there was at Joppa a certain disciple named Tabitha, which when translated means Dorcas. This woman was full of good works and acts of mercy which she did."},{"v":37,"t":"In those days, she became sick and died. When they had washed her, they laid her in an upper room."},{"v":38,"t":"As Lydda was near Joppa, the disciples, hearing that Peter was there, sent two men to him, imploring him not to delay in coming to them."},{"v":39,"t":"Peter got up and went with them. When he had come, they brought him into the upper room. All the widows stood by him weeping, and showing the tunics and other garments which Dorcas had made while she was with them."},{"v":40,"t":"Peter sent them all out, and knelt down and prayed. Turning to the body, he said, “Tabitha, get up!” She opened her eyes, and when she saw Peter, she sat up."},{"v":41,"t":"He gave her his hand and raised her up. Calling the saints and widows, he presented her alive."},{"v":42,"t":"This became known throughout all Joppa, and many believed in the Lord."},{"v":43,"t":"He stayed many days in Joppa with a tanner named Simon."}]},"10":{"en":[{"v":1,"t":"Now there was a certain man in Caesarea, Cornelius by name, a centurion of what was called the Italian Regiment,"},{"v":2,"t":"a devout man, and one who feared God with all his house, who gave gifts for the needy generously to the people, and always prayed to God."},{"v":3,"t":"At about the ninth hour of the day, he clearly saw in a vision an angel of God coming to him and saying to him, “Cornelius!”"},{"v":4,"t":"He, fastening his eyes on him and being frightened, said, “What is it, Lord?” He said to him, “Your prayers and your gifts to the needy have gone up for a memorial before God."},{"v":5,"t":"Now send men to Joppa, and get Simon, who is also called Peter."},{"v":6,"t":"He is staying with a tanner named Simon, whose house is by the seaside."},{"v":7,"t":"When the angel who spoke to him had departed, Cornelius called two of his household servants and a devout soldier of those who waited on him continually."},{"v":8,"t":"Having explained everything to them, he sent them to Joppa."},{"v":9,"t":"Now on the next day as they were on their journey and got close to the city, Peter went up on the housetop to pray at about noon."},{"v":10,"t":"He became hungry and desired to eat, but while they were preparing, he fell into a trance."},{"v":11,"t":"He saw heaven opened and a certain container descending to him, like a great sheet let down by four corners on the earth,"},{"v":12,"t":"in which were all kinds of four-footed animals of the earth, wild animals, reptiles, and birds of the sky."},{"v":13,"t":"A voice came to him, “Rise, Peter, kill and eat!”"},{"v":14,"t":"But Peter said, “Not so, Lord; for I have never eaten anything that is common or unclean.”"},{"v":15,"t":"A voice came to him again the second time, “What God has cleansed, you must not call unclean.”"},{"v":16,"t":"This was done three times, and immediately the thing was received up into heaven."},{"v":17,"t":"Now while Peter was very perplexed in himself what the vision which he had seen might mean, behold, the men who were sent by Cornelius, having made inquiry for Simon’s house, stood before the gate,"},{"v":18,"t":"and called and asked whether Simon, who was also called Peter, was lodging there."},{"v":19,"t":"While Peter was pondering the vision, the Spirit said to him, “Behold, three men seek you."},{"v":20,"t":"But arise, get down, and go with them, doubting nothing; for I have sent them.”"},{"v":21,"t":"Peter went down to the men, and said, “Behold, I am he whom you seek. Why have you come?”"},{"v":22,"t":"They said, “Cornelius, a centurion, a righteous man and one who fears God, and well spoken of by all the nation of the Jews, was directed by a holy angel to invite you to his house, and to listen to what you say.”"},{"v":23,"t":"So he called them in and provided a place to stay. On the next day Peter arose and went out with them, and some of the brothers from Joppa accompanied him."},{"v":24,"t":"On the next day they entered into Caesarea. Cornelius was waiting for them, having called together his relatives and his near friends."},{"v":25,"t":"When Peter entered, Cornelius met him, fell down at his feet, and worshiped him."},{"v":26,"t":"But Peter raised him up, saying, “Stand up! I myself am also a man.”"},{"v":27,"t":"As he talked with him, he went in and found many gathered together."},{"v":28,"t":"He said to them, “You yourselves know how it is an unlawful thing for a man who is a Jew to join himself or come to one of another nation, but God has shown me that I shouldn’t call any man unholy or unclean."},{"v":29,"t":"Therefore I also came without complaint when I was sent for. I ask therefore, why did you send for me?”"},{"v":30,"t":"Cornelius said, “Four days ago, I was fasting until this hour; and at the ninth hour, I prayed in my house, and behold, a man stood before me in bright clothing"},{"v":31,"t":"and said, ‘Cornelius, your prayer is heard, and your gifts to the needy are remembered in the sight of God."},{"v":32,"t":"Send therefore to Joppa and summon Simon, who is also called Peter. He is staying in the house of a tanner named Simon, by the seaside. When he comes, he will speak to you.’"},{"v":33,"t":"Therefore I sent to you at once, and it was good of you to come. Now therefore we are all here present in the sight of God to hear all things that have been commanded you by God.”"},{"v":34,"t":"Peter opened his mouth and said, “Truly I perceive that God doesn’t show favoritism;"},{"v":35,"t":"but in every nation he who fears him and works righteousness is acceptable to him."},{"v":36,"t":"The word which he sent to the children of Israel, preaching good news of peace by Jesus Christ—he is Lord of all—"},{"v":37,"t":"you yourselves know what happened, which was proclaimed throughout all Judea, beginning from Galilee, after the baptism which John preached;"},{"v":38,"t":"how God anointed Jesus of Nazareth with the Holy Spirit and with power, who went about doing good and healing all who were oppressed by the devil, for God was with him."},{"v":39,"t":"We are witnesses of everything he did both in the country of the Jews and in Jerusalem; whom they also killed, hanging him on a tree."},{"v":40,"t":"God raised him up the third day and gave him to be revealed,"},{"v":41,"t":"not to all the people, but to witnesses who were chosen before by God, to us, who ate and drank with him after he rose from the dead."},{"v":42,"t":"He commanded us to preach to the people and to testify that this is he who is appointed by God as the Judge of the living and the dead."},{"v":43,"t":"All the prophets testify about him, that through his name everyone who believes in him will receive remission of sins.”"},{"v":44,"t":"While Peter was still speaking these words, the Holy Spirit fell on all those who heard the word."},{"v":45,"t":"They of the circumcision who believed were amazed, as many as came with Peter, because the gift of the Holy Spirit was also poured out on the Gentiles."},{"v":46,"t":"For they heard them speaking in other languages and magnifying God. Then Peter answered,"},{"v":47,"t":"“Can anyone forbid these people from being baptized with water? They have received the Holy Spirit just like us.”"},{"v":48,"t":"He commanded them to be baptized in the name of Jesus Christ. Then they asked him to stay some days."}]},"11":{"en":[{"v":1,"t":"Now the apostles and the brothers who were in Judea heard that the Gentiles had also received the word of God."},{"v":2,"t":"When Peter had come up to Jerusalem, those who were of the circumcision contended with him,"},{"v":3,"t":"saying, “You went in to uncircumcised men and ate with them!”"},{"v":4,"t":"But Peter began, and explained to them in order, saying,"},{"v":5,"t":"“I was in the city of Joppa praying, and in a trance I saw a vision: a certain container descending, like it was a great sheet let down from heaven by four corners. It came as far as me."},{"v":6,"t":"When I had looked intently at it, I considered, and saw the four-footed animals of the earth, wild animals, creeping things, and birds of the sky."},{"v":7,"t":"I also heard a voice saying to me, ‘Rise, Peter, kill and eat!’"},{"v":8,"t":"But I said, ‘Not so, Lord, for nothing unholy or unclean has ever entered into my mouth.’"},{"v":9,"t":"But a voice answered me the second time out of heaven, ‘What God has cleansed, don’t you call unclean.’"},{"v":10,"t":"This was done three times, and all were drawn up again into heaven."},{"v":11,"t":"Behold, immediately three men stood before the house where I was, having been sent from Caesarea to me."},{"v":12,"t":"The Spirit told me to go with them without discriminating. These six brothers also accompanied me, and we entered into the man’s house."},{"v":13,"t":"He told us how he had seen the angel standing in his house and saying to him, ‘Send to Joppa and get Simon, who is called Peter,"},{"v":14,"t":"who will speak to you words by which you will be saved, you and all your house.’"},{"v":15,"t":"As I began to speak, the Holy Spirit fell on them, even as on us at the beginning."},{"v":16,"t":"I remembered the word of the Lord, how he said, ‘John indeed baptized in water, but you will be baptized in the Holy Spirit.’"},{"v":17,"t":"If then God gave to them the same gift as us when we believed in the Lord Jesus Christ, who was I, that I could withstand God?”"},{"v":18,"t":"When they heard these things, they held their peace and glorified God, saying, “Then God has also granted to the Gentiles repentance to life!”"},{"v":19,"t":"They therefore who were scattered abroad by the oppression that arose about Stephen traveled as far as Phoenicia, Cyprus, and Antioch, speaking the word to no one except to Jews only."},{"v":20,"t":"But there were some of them, men of Cyprus and Cyrene, who, when they had come to Antioch, spoke to the Hellenists, preaching the Lord Jesus."},{"v":21,"t":"The hand of the Lord was with them, and a great number believed and turned to the Lord."},{"v":22,"t":"The report concerning them came to the ears of the assembly which was in Jerusalem. They sent out Barnabas to go as far as Antioch,"},{"v":23,"t":"who, when he had come, and had seen the grace of God, was glad. He exhorted them all, that with purpose of heart they should remain near to the Lord."},{"v":24,"t":"For he was a good man, and full of the Holy Spirit and of faith, and many people were added to the Lord."},{"v":25,"t":"Barnabas went out to Tarsus to look for Saul."},{"v":26,"t":"When he had found him, he brought him to Antioch. For a whole year they were gathered together with the assembly, and taught many people. The disciples were first called Christians in Antioch."},{"v":27,"t":"Now in these days, prophets came down from Jerusalem to Antioch."},{"v":28,"t":"One of them named Agabus stood up and indicated by the Spirit that there should be a great famine all over the world, which also happened in the days of Claudius."},{"v":29,"t":"As any of the disciples had plenty, each determined to send relief to the brothers who lived in Judea;"},{"v":30,"t":"which they also did, sending it to the elders by the hands of Barnabas and Saul."}]},"12":{"en":[{"v":1,"t":"Now about that time, King Herod stretched out his hands to oppress some of the assembly."},{"v":2,"t":"He killed James, the brother of John, with the sword."},{"v":3,"t":"When he saw that it pleased the Jews, he proceeded to seize Peter also. This was during the days of unleavened bread."},{"v":4,"t":"When he had arrested him, he put him in prison and delivered him to four squads of four soldiers each to guard him, intending to bring him out to the people after the Passover."},{"v":5,"t":"Peter therefore was kept in the prison, but constant prayer was made by the assembly to God for him."},{"v":6,"t":"The same night when Herod was about to bring him out, Peter was sleeping between two soldiers, bound with two chains. Guards in front of the door kept the prison."},{"v":7,"t":"And behold, an angel of the Lord stood by him, and a light shone in the cell. He struck Peter on the side and woke him up, saying, “Stand up quickly!” His chains fell off his hands."},{"v":8,"t":"The angel said to him, “Get dressed and put on your sandals.” He did so. He said to him, “Put on your cloak and follow me.”"},{"v":9,"t":"And he went out and followed him. He didn’t know that what was being done by the angel was real, but thought he saw a vision."},{"v":10,"t":"When they were past the first and the second guard, they came to the iron gate that leads into the city, which opened to them by itself. They went out and went down one street, and immediately the angel departed from him."},{"v":11,"t":"When Peter had come to himself, he said, “Now I truly know that the Lord has sent out his angel and delivered me out of the hand of Herod, and from everything the Jewish people were expecting.”"},{"v":12,"t":"Thinking about that, he came to the house of Mary, the mother of John who was called Mark, where many were gathered together and were praying."},{"v":13,"t":"When Peter knocked at the door of the gate, a servant girl named Rhoda came to answer."},{"v":14,"t":"When she recognized Peter’s voice, she didn’t open the gate for joy, but ran in and reported that Peter was standing in front of the gate."},{"v":15,"t":"They said to her, “You are crazy!” But she insisted that it was so. They said, “It is his angel.”"},{"v":16,"t":"But Peter continued knocking. When they had opened, they saw him and were amazed."},{"v":17,"t":"But he, beckoning to them with his hand to be silent, declared to them how the Lord had brought him out of the prison. He said, “Tell these things to James and to the brothers.” Then he departed and went to another place."},{"v":18,"t":"Now as soon as it was day, there was no small stir among the soldiers about what had become of Peter."},{"v":19,"t":"When Herod had sought for him and didn’t find him, he examined the guards, then commanded that they should be put to death. He went down from Judea to Caesarea, and stayed there."},{"v":20,"t":"Now Herod was very angry with the people of Tyre and Sidon. They came with one accord to him and, having made Blastus, the king’s personal aide, their friend, they asked for peace, because their country depended on the king’s country for food."},{"v":21,"t":"On an appointed day, Herod dressed himself in royal clothing, sat on the throne, and gave a speech to them."},{"v":22,"t":"The people shouted, “The voice of a god, and not of a man!”"},{"v":23,"t":"Immediately an angel of the Lord struck him, because he didn’t give God the glory. Then he was eaten by worms and died."},{"v":24,"t":"But the word of God grew and multiplied."},{"v":25,"t":"Barnabas and Saul returned to Jerusalem when they had fulfilled their service, also taking with them John who was called Mark."}]},"13":{"en":[{"v":1,"t":"Now in the assembly that was at Antioch there were some prophets and teachers: Barnabas, Simeon who was called Niger, Lucius of Cyrene, Manaen the foster brother of Herod the tetrarch, and Saul."},{"v":2,"t":"As they served the Lord and fasted, the Holy Spirit said, “Separate Barnabas and Saul for me, for the work to which I have called them.”"},{"v":3,"t":"Then, when they had fasted and prayed and laid their hands on them, they sent them away."},{"v":4,"t":"So, being sent out by the Holy Spirit, they went down to Seleucia. From there they sailed to Cyprus."},{"v":5,"t":"When they were at Salamis, they proclaimed God’s word in the Jewish synagogues. They also had John as their attendant."},{"v":6,"t":"When they had gone through the island to Paphos, they found a certain sorcerer, a false prophet, a Jew whose name was Bar Jesus,"},{"v":7,"t":"who was with the proconsul, Sergius Paulus, a man of understanding. This man summoned Barnabas and Saul, and sought to hear the word of God."},{"v":8,"t":"But Elymas the sorcerer (for so is his name by interpretation) withstood them, seeking to turn the proconsul away from the faith."},{"v":9,"t":"But Saul, who is also called Paul, filled with the Holy Spirit, fastened his eyes on him"},{"v":10,"t":"and said, “You son of the devil, full of all deceit and all cunning, you enemy of all righteousness, will you not cease to pervert the right ways of the Lord?"},{"v":11,"t":"Now, behold, the hand of the Lord is on you, and you will be blind, not seeing the sun for a season!” Immediately a mist and darkness fell on him. He went around seeking someone to lead him by the hand."},{"v":12,"t":"Then the proconsul, when he saw what was done, believed, being astonished at the teaching of the Lord."},{"v":13,"t":"Now Paul and his company set sail from Paphos and came to Perga in Pamphylia. John departed from them and returned to Jerusalem."},{"v":14,"t":"But they, passing on from Perga, came to Antioch of Pisidia. They went into the synagogue on the Sabbath day and sat down."},{"v":15,"t":"After the reading of the law and the prophets, the rulers of the synagogue sent to them, saying, “Brothers, if you have any word of exhortation for the people, speak.”"},{"v":16,"t":"Paul stood up, and gesturing with his hand said, “Men of Israel, and you who fear God, listen."},{"v":17,"t":"The God of this people chose our fathers, and exalted the people when they stayed as aliens in the land of Egypt, and with an uplifted arm, he led them out of it."},{"v":18,"t":"For a period of about forty years he put up with them in the wilderness."},{"v":19,"t":"When he had destroyed seven nations in the land of Canaan, he gave them their land for an inheritance for about four hundred fifty years."},{"v":20,"t":"After these things, he gave them judges until Samuel the prophet."},{"v":21,"t":"Afterward they asked for a king, and God gave to them Saul the son of Kish, a man of the tribe of Benjamin, for forty years."},{"v":22,"t":"When he had removed him, he raised up David to be their king, to whom he also testified, ‘I have found David the son of Jesse, a man after my heart, who will do all my will.’"},{"v":23,"t":"From this man’s offspring, God has brought salvation to Israel according to his promise,"},{"v":24,"t":"before his coming, when John had first preached the baptism of repentance to Israel."},{"v":25,"t":"As John was fulfilling his course, he said, ‘What do you suppose that I am? I am not he. But behold, one comes after me, the sandals of whose feet I am not worthy to untie.’"},{"v":26,"t":"“Brothers, children of the stock of Abraham, and those among you who fear God, the word of this salvation is sent out to you."},{"v":27,"t":"For those who dwell in Jerusalem, and their rulers, because they didn’t know him, nor the voices of the prophets which are read every Sabbath, fulfilled them by condemning him."},{"v":28,"t":"Though they found no cause for death, they still asked Pilate to have him killed."},{"v":29,"t":"When they had fulfilled all things that were written about him, they took him down from the tree and laid him in a tomb."},{"v":30,"t":"But God raised him from the dead,"},{"v":31,"t":"and he was seen for many days by those who came up with him from Galilee to Jerusalem, who are his witnesses to the people."},{"v":32,"t":"We bring you good news of the promise made to the fathers,"},{"v":33,"t":"that God has fulfilled this to us, their children, in that he raised up Jesus. As it is also written in the second psalm, ‘You are my Son. Today I have become your father.’"},{"v":34,"t":"“Concerning that he raised him up from the dead, now no more to return to corruption, he has spoken thus: ‘I will give you the holy and sure blessings of David.’"},{"v":35,"t":"Therefore he says also in another psalm, ‘You will not allow your Holy One to see decay.’"},{"v":36,"t":"For David, after he had in his own generation served the counsel of God, fell asleep, was laid with his fathers, and saw decay."},{"v":37,"t":"But he whom God raised up saw no decay."},{"v":38,"t":"Be it known to you therefore, brothers, that through this man is proclaimed to you remission of sins;"},{"v":39,"t":"and by him everyone who believes is justified from all things, from which you could not be justified by the law of Moses."},{"v":40,"t":"Beware therefore, lest that come on you which is spoken in the prophets:"},{"v":41,"t":"‘Behold, you scoffers! Wonder and perish, for I work a work in your days, a work which you will in no way believe, if one declares it to you.’”"},{"v":42,"t":"So when the Jews went out of the synagogue, the Gentiles begged that these words might be preached to them the next Sabbath."},{"v":43,"t":"Now when the synagogue broke up, many of the Jews and of the devout proselytes followed Paul and Barnabas; who, speaking to them, urged them to continue in the grace of God."},{"v":44,"t":"The next Sabbath, almost the whole city was gathered together to hear the word of God."},{"v":45,"t":"But when the Jews saw the multitudes, they were filled with jealousy, and contradicted the things which were spoken by Paul, and blasphemed."},{"v":46,"t":"Paul and Barnabas spoke out boldly, and said, “It was necessary that God’s word should be spoken to you first. Since indeed you thrust it from yourselves, and judge yourselves unworthy of eternal life, behold, we turn to the Gentiles."},{"v":47,"t":"For so has the Lord commanded us, saying, ‘I have set you as a light for the Gentiles, that you should bring salvation to the uttermost parts of the earth.’”"},{"v":48,"t":"As the Gentiles heard this, they were glad and glorified the word of God. As many as were appointed to eternal life believed."},{"v":49,"t":"The Lord’s word was spread abroad throughout all the region."},{"v":50,"t":"But the Jews stirred up the devout and prominent women and the chief men of the city, and stirred up a persecution against Paul and Barnabas, and threw them out of their borders."},{"v":51,"t":"But they shook off the dust of their feet against them, and came to Iconium."},{"v":52,"t":"The disciples were filled with joy and with the Holy Spirit."}]},"14":{"en":[{"v":1,"t":"In Iconium, they entered together into the synagogue of the Jews, and so spoke that a great multitude both of Jews and of Greeks believed."},{"v":2,"t":"But the disbelieving Jews stirred up and embittered the souls of the Gentiles against the brothers."},{"v":3,"t":"Therefore they stayed there a long time, speaking boldly in the Lord, who testified to the word of his grace, granting signs and wonders to be done by their hands."},{"v":4,"t":"But the multitude of the city was divided. Part sided with the Jews and part with the apostles."},{"v":5,"t":"When some of both the Gentiles and the Jews, with their rulers, made a violent attempt to mistreat and stone them,"},{"v":6,"t":"they became aware of it and fled to the cities of Lycaonia, Lystra, Derbe, and the surrounding region."},{"v":7,"t":"There they preached the Good News."},{"v":8,"t":"At Lystra a certain man sat, impotent in his feet, a cripple from his mother’s womb, who never had walked."},{"v":9,"t":"He was listening to Paul speaking, who, fastening eyes on him and seeing that he had faith to be made whole,"},{"v":10,"t":"said with a loud voice, “Stand upright on your feet!” He leaped up and walked."},{"v":11,"t":"When the multitude saw what Paul had done, they lifted up their voice, saying in the language of Lycaonia, “The gods have come down to us in the likeness of men!”"},{"v":12,"t":"They called Barnabas “Jupiter”, and Paul “Mercury”, because he was the chief speaker."},{"v":13,"t":"The priest of Jupiter, whose temple was in front of their city, brought oxen and garlands to the gates, and would have made a sacrifice along with the multitudes."},{"v":14,"t":"But when the apostles, Barnabas and Paul, heard of it, they tore their clothes and sprang into the multitude, crying out,"},{"v":15,"t":"“Men, why are you doing these things? We also are men of the same nature as you, and bring you good news, that you should turn from these vain things to the living God, who made the sky, the earth, the sea, and all that is in them;"},{"v":16,"t":"who in the generations gone by allowed all the nations to walk in their own ways."},{"v":17,"t":"Yet he didn’t leave himself without witness, in that he did good and gave you rains from the sky and fruitful seasons, filling our hearts with food and gladness.”"},{"v":18,"t":"Even saying these things, they hardly stopped the multitudes from making a sacrifice to them."},{"v":19,"t":"But some Jews from Antioch and Iconium came there, and having persuaded the multitudes, they stoned Paul and dragged him out of the city, supposing that he was dead."},{"v":20,"t":"But as the disciples stood around him, he rose up, and entered into the city. On the next day he went out with Barnabas to Derbe."},{"v":21,"t":"When they had preached the Good News to that city and had made many disciples, they returned to Lystra, Iconium, and Antioch,"},{"v":22,"t":"strengthening the souls of the disciples, exhorting them to continue in the faith, and that through many afflictions we must enter into God’s Kingdom."},{"v":23,"t":"When they had appointed elders for them in every assembly, and had prayed with fasting, they commended them to the Lord on whom they had believed."},{"v":24,"t":"They passed through Pisidia and came to Pamphylia."},{"v":25,"t":"When they had spoken the word in Perga, they went down to Attalia."},{"v":26,"t":"From there they sailed to Antioch, from where they had been committed to the grace of God for the work which they had fulfilled."},{"v":27,"t":"When they had arrived and had gathered the assembly together, they reported all the things that God had done with them, and that he had opened a door of faith to the nations."},{"v":28,"t":"They stayed there with the disciples for a long time."}]},"15":{"en":[{"v":1,"t":"Some men came down from Judea and taught the brothers, “Unless you are circumcised after the custom of Moses, you can’t be saved.”"},{"v":2,"t":"Therefore when Paul and Barnabas had no small discord and discussion with them, they appointed Paul, Barnabas, and some others of them to go up to Jerusalem to the apostles and elders about this question."},{"v":3,"t":"They, being sent on their way by the assembly, passed through both Phoenicia and Samaria, declaring the conversion of the Gentiles. They caused great joy to all the brothers."},{"v":4,"t":"When they had come to Jerusalem, they were received by the assembly and the apostles and the elders, and they reported everything that God had done with them."},{"v":5,"t":"But some of the sect of the Pharisees who believed rose up, saying, “It is necessary to circumcise them, and to command them to keep the law of Moses.”"},{"v":6,"t":"The apostles and the elders were gathered together to see about this matter."},{"v":7,"t":"When there had been much discussion, Peter rose up and said to them, “Brothers, you know that a good while ago God made a choice among you that by my mouth the nations should hear the word of the Good News and believe."},{"v":8,"t":"God, who knows the heart, testified about them, giving them the Holy Spirit, just like he did to us."},{"v":9,"t":"He made no distinction between us and them, cleansing their hearts by faith."},{"v":10,"t":"Now therefore why do you tempt God, that you should put a yoke on the neck of the disciples which neither our fathers nor we were able to bear?"},{"v":11,"t":"But we believe that we are saved through the grace of the Lord Jesus, just as they are.”"},{"v":12,"t":"All the multitude kept silence, and they listened to Barnabas and Paul reporting what signs and wonders God had done among the nations through them."},{"v":13,"t":"After they were silent, James answered, “Brothers, listen to me."},{"v":14,"t":"Simeon has reported how God first visited the nations to take out of them a people for his name."},{"v":15,"t":"This agrees with the words of the prophets. As it is written,"},{"v":16,"t":"‘After these things I will return. I will again build the tabernacle of David, which has fallen. I will again build its ruins. I will set it up"},{"v":17,"t":"that the rest of men may seek after the Lord: all the Gentiles who are called by my name, says the Lord, who does all these things.’"},{"v":18,"t":"“All of God’s works are known to him from eternity."},{"v":19,"t":"Therefore my judgment is that we don’t trouble those from among the Gentiles who turn to God,"},{"v":20,"t":"but that we write to them that they abstain from the pollution of idols, from sexual immorality, from what is strangled, and from blood."},{"v":21,"t":"For Moses from generations of old has in every city those who preach him, being read in the synagogues every Sabbath.”"},{"v":22,"t":"Then it seemed good to the apostles and the elders, with the whole assembly, to choose men out of their company, and send them to Antioch with Paul and Barnabas: Judas called Barsabbas, and Silas, chief men among the brothers."},{"v":23,"t":"They wrote these things by their hand: “The apostles, the elders, and the brothers, to the brothers who are of the Gentiles in Antioch, Syria, and Cilicia: greetings."},{"v":24,"t":"Because we have heard that some who went out from us have troubled you with words, unsettling your souls, saying, ‘You must be circumcised and keep the law,’ to whom we gave no commandment;"},{"v":25,"t":"it seemed good to us, having come to one accord, to choose out men and send them to you with our beloved Barnabas and Paul,"},{"v":26,"t":"men who have risked their lives for the name of our Lord Jesus Christ."},{"v":27,"t":"We have sent therefore Judas and Silas, who themselves will also tell you the same things by word of mouth."},{"v":28,"t":"For it seemed good to the Holy Spirit, and to us, to lay no greater burden on you than these necessary things:"},{"v":29,"t":"that you abstain from things sacrificed to idols, from blood, from things strangled, and from sexual immorality, from which if you keep yourselves, it will be well with you. Farewell.”"},{"v":30,"t":"So, when they were sent off, they came to Antioch. Having gathered the multitude together, they delivered the letter."},{"v":31,"t":"When they had read it, they rejoiced over the encouragement."},{"v":32,"t":"Judas and Silas, also being prophets themselves, encouraged the brothers with many words and strengthened them."},{"v":33,"t":"After they had spent some time there, they were dismissed in peace from the brothers to the apostles."},{"v":35,"t":"But Paul and Barnabas stayed in Antioch, teaching and preaching the word of the Lord, with many others also."},{"v":36,"t":"After some days Paul said to Barnabas, “Let’s return now and visit our brothers in every city in which we proclaimed the word of the Lord, to see how they are doing.”"},{"v":37,"t":"Barnabas planned to take John, who was called Mark, with them also."},{"v":38,"t":"But Paul didn’t think that it was a good idea to take with them someone who had withdrawn from them in Pamphylia, and didn’t go with them to do the work."},{"v":39,"t":"Then the contention grew so sharp that they separated from each other. Barnabas took Mark with him and sailed away to Cyprus,"},{"v":40,"t":"but Paul chose Silas and went out, being commended by the brothers to the grace of God."},{"v":41,"t":"He went through Syria and Cilicia, strengthening the assemblies."}]},"16":{"en":[{"v":1,"t":"He came to Derbe and Lystra; and behold, a certain disciple was there, named Timothy, the son of a Jewess who believed, but his father was a Greek."},{"v":2,"t":"The brothers who were at Lystra and Iconium gave a good testimony about him."},{"v":3,"t":"Paul wanted to have him go out with him, and he took and circumcised him because of the Jews who were in those parts, for they all knew that his father was a Greek."},{"v":4,"t":"As they went on their way through the cities, they delivered the decrees to them to keep which had been ordained by the apostles and elders who were at Jerusalem."},{"v":5,"t":"So the assemblies were strengthened in the faith, and increased in number daily."},{"v":6,"t":"When they had gone through the region of Phrygia and Galatia, they were forbidden by the Holy Spirit to speak the word in Asia."},{"v":7,"t":"When they had come opposite Mysia, they tried to go into Bithynia, but the Spirit didn’t allow them."},{"v":8,"t":"Passing by Mysia, they came down to Troas."},{"v":9,"t":"A vision appeared to Paul in the night. There was a man of Macedonia standing, begging him and saying, “Come over into Macedonia and help us.”"},{"v":10,"t":"When he had seen the vision, immediately we sought to go out to Macedonia, concluding that the Lord had called us to preach the Good News to them."},{"v":11,"t":"Setting sail therefore from Troas, we made a straight course to Samothrace, and the day following to Neapolis;"},{"v":12,"t":"and from there to Philippi, which is a city of Macedonia, the foremost of the district, a Roman colony. We were staying some days in this city."},{"v":13,"t":"On the Sabbath day we went outside of the city by a riverside, where we supposed there was a place of prayer, and we sat down and spoke to the women who had come together."},{"v":14,"t":"A certain woman named Lydia, a seller of purple, of the city of Thyatira, one who worshiped God, heard us. The Lord opened her heart to listen to the things which were spoken by Paul."},{"v":15,"t":"When she and her household were baptized, she begged us, saying, “If you have judged me to be faithful to the Lord, come into my house and stay.” So she persuaded us."},{"v":16,"t":"As we were going to prayer, a certain girl having a spirit of divination met us, who brought her masters much gain by fortune telling."},{"v":17,"t":"Following Paul and us, she cried out, “These men are servants of the Most High God, who proclaim to us a way of salvation!”"},{"v":18,"t":"She was doing this for many days. But Paul, becoming greatly annoyed, turned and said to the spirit, “I command you in the name of Jesus Christ to come out of her!” It came out that very hour."},{"v":19,"t":"But when her masters saw that the hope of their gain was gone, they seized Paul and Silas and dragged them into the marketplace before the rulers."},{"v":20,"t":"When they had brought them to the magistrates, they said, “These men, being Jews, are agitating our city"},{"v":21,"t":"and advocate customs which it is not lawful for us to accept or to observe, being Romans.”"},{"v":22,"t":"The multitude rose up together against them and the magistrates tore their clothes from them, then commanded them to be beaten with rods."},{"v":23,"t":"When they had laid many stripes on them, they threw them into prison, charging the jailer to keep them safely."},{"v":24,"t":"Having received such a command, he threw them into the inner prison and secured their feet in the stocks."},{"v":25,"t":"But about midnight Paul and Silas were praying and singing hymns to God, and the prisoners were listening to them."},{"v":26,"t":"Suddenly there was a great earthquake, so that the foundations of the prison were shaken; and immediately all the doors were opened, and everyone’s bonds were loosened."},{"v":27,"t":"The jailer, being roused out of sleep and seeing the prison doors open, drew his sword and was about to kill himself, supposing that the prisoners had escaped."},{"v":28,"t":"But Paul cried with a loud voice, saying, “Don’t harm yourself, for we are all here!”"},{"v":29,"t":"He called for lights, sprang in, fell down trembling before Paul and Silas,"},{"v":30,"t":"brought them out, and said, “Sirs, what must I do to be saved?”"},{"v":31,"t":"They said, “Believe in the Lord Jesus Christ, and you will be saved, you and your household.”"},{"v":32,"t":"They spoke the word of the Lord to him, and to all who were in his house."},{"v":33,"t":"He took them the same hour of the night and washed their stripes, and was immediately baptized, he and all his household."},{"v":34,"t":"He brought them up into his house and set food before them, and rejoiced greatly with all his household, having believed in God."},{"v":35,"t":"But when it was day, the magistrates sent the sergeants, saying, “Let those men go.”"},{"v":36,"t":"The jailer reported these words to Paul, saying, “The magistrates have sent to let you go; now therefore come out and go in peace.”"},{"v":37,"t":"But Paul said to them, “They have beaten us publicly without a trial, men who are Romans, and have cast us into prison! Do they now release us secretly? No, most certainly, but let them come themselves and bring us out!”"},{"v":38,"t":"The sergeants reported these words to the magistrates, and they were afraid when they heard that they were Romans,"},{"v":39,"t":"and they came and begged them. When they had brought them out, they asked them to depart from the city."},{"v":40,"t":"They went out of the prison and entered into Lydia’s house. When they had seen the brothers, they encouraged them, then departed."}]},"17":{"en":[{"v":1,"t":"Now when they had passed through Amphipolis and Apollonia, they came to Thessalonica, where there was a Jewish synagogue."},{"v":2,"t":"Paul, as was his custom, went in to them; and for three Sabbath days reasoned with them from the Scriptures,"},{"v":3,"t":"explaining and demonstrating that the Christ had to suffer and rise again from the dead, and saying, “This Jesus, whom I proclaim to you, is the Christ.”"},{"v":4,"t":"Some of them were persuaded and joined Paul and Silas: of the devout Greeks a great multitude, and not a few of the chief women."},{"v":5,"t":"But the unpersuaded Jews took along some wicked men from the marketplace and gathering a crowd, set the city in an uproar. Assaulting the house of Jason, they sought to bring them out to the people."},{"v":6,"t":"When they didn’t find them, they dragged Jason and certain brothers before the rulers of the city, crying, “These who have turned the world upside down have come here also,"},{"v":7,"t":"whom Jason has received. These all act contrary to the decrees of Caesar, saying that there is another king, Jesus!”"},{"v":8,"t":"The multitude and the rulers of the city were troubled when they heard these things."},{"v":9,"t":"When they had taken security from Jason and the rest, they let them go."},{"v":10,"t":"The brothers immediately sent Paul and Silas away by night to Beroea. When they arrived, they went into the Jewish synagogue."},{"v":11,"t":"Now these were more noble than those in Thessalonica, in that they received the word with all readiness of mind, examining the Scriptures daily to see whether these things were so."},{"v":12,"t":"Many of them therefore believed; also of the prominent Greek women, and not a few men."},{"v":13,"t":"But when the Jews of Thessalonica had knowledge that the word of God was proclaimed by Paul at Beroea also, they came there likewise, agitating the multitudes."},{"v":14,"t":"Then the brothers immediately sent out Paul to go as far as to the sea, and Silas and Timothy still stayed there."},{"v":15,"t":"But those who escorted Paul brought him as far as Athens. Receiving a commandment to Silas and Timothy that they should come to him very quickly, they departed."},{"v":16,"t":"Now while Paul waited for them at Athens, his spirit was provoked within him as he saw the city full of idols."},{"v":17,"t":"So he reasoned in the synagogue with the Jews and the devout persons, and in the marketplace every day with those who met him."},{"v":18,"t":"Some of the Epicurean and Stoic philosophers also were conversing with him. Some said, “What does this babbler want to say?” Others said, “He seems to be advocating foreign deities,” because he preached Jesus and the resurrection."},{"v":19,"t":"They took hold of him and brought him to the Areopagus, saying, “May we know what this new teaching is, which you are speaking about?"},{"v":20,"t":"For you bring certain strange things to our ears. We want to know therefore what these things mean.”"},{"v":21,"t":"Now all the Athenians and the strangers living there spent their time in nothing else, but either to tell or to hear some new thing."},{"v":22,"t":"Paul stood in the middle of the Areopagus and said, “You men of Athens, I perceive that you are very religious in all things."},{"v":23,"t":"For as I passed along and observed the objects of your worship, I also found an altar with this inscription: ‘TO AN UNKNOWN GOD.’ What therefore you worship in ignorance, I announce to you."},{"v":24,"t":"The God who made the world and all things in it, he, being Lord of heaven and earth, doesn’t dwell in temples made with hands."},{"v":25,"t":"He isn’t served by men’s hands, as though he needed anything, seeing he himself gives to all life and breath and all things."},{"v":26,"t":"He made from one blood every nation of men to dwell on all the surface of the earth, having determined appointed seasons and the boundaries of their dwellings,"},{"v":27,"t":"that they should seek the Lord, if perhaps they might reach out for him and find him, though he is not far from each one of us."},{"v":28,"t":"‘For in him we live, move, and have our being.’ As some of your own poets have said, ‘For we are also his offspring.’"},{"v":29,"t":"Being then the offspring of God, we ought not to think that the Divine Nature is like gold, or silver, or stone, engraved by art and design of man."},{"v":30,"t":"The times of ignorance therefore God overlooked. But now he commands that all people everywhere should repent,"},{"v":31,"t":"because he has appointed a day in which he will judge the world in righteousness by the man whom he has ordained; of which he has given assurance to all men, in that he has raised him from the dead.”"},{"v":32,"t":"Now when they heard of the resurrection of the dead, some mocked; but others said, “We want to hear you again concerning this.”"},{"v":33,"t":"Thus Paul went out from among them."},{"v":34,"t":"But certain men joined with him and believed, including Dionysius the Areopagite, and a woman named Damaris, and others with them."}]},"18":{"en":[{"v":1,"t":"After these things Paul departed from Athens and came to Corinth."},{"v":2,"t":"He found a certain Jew named Aquila, a man of Pontus by race, who had recently come from Italy with his wife Priscilla, because Claudius had commanded all the Jews to depart from Rome. He came to them,"},{"v":3,"t":"and because he practiced the same trade, he lived with them and worked, for by trade they were tent makers."},{"v":4,"t":"He reasoned in the synagogue every Sabbath and persuaded Jews and Greeks."},{"v":5,"t":"When Silas and Timothy came down from Macedonia, Paul was compelled by the Spirit, testifying to the Jews that Jesus was the Christ."},{"v":6,"t":"When they opposed him and blasphemed, he shook out his clothing and said to them, “Your blood be on your own heads! I am clean. From now on, I will go to the Gentiles!”"},{"v":7,"t":"He departed there and went into the house of a certain man named Justus, one who worshiped God, whose house was next door to the synagogue."},{"v":8,"t":"Crispus, the ruler of the synagogue, believed in the Lord with all his house. Many of the Corinthians, when they heard, believed and were baptized."},{"v":9,"t":"The Lord said to Paul in the night by a vision, “Don’t be afraid, but speak and don’t be silent;"},{"v":10,"t":"for I am with you, and no one will attack you to harm you, for I have many people in this city.”"},{"v":11,"t":"He lived there a year and six months, teaching the word of God among them."},{"v":12,"t":"But when Gallio was proconsul of Achaia, the Jews with one accord rose up against Paul and brought him before the judgment seat,"},{"v":13,"t":"saying, “This man persuades men to worship God contrary to the law.”"},{"v":14,"t":"But when Paul was about to open his mouth, Gallio said to the Jews, “If indeed it were a matter of wrong or of wicked crime, you Jews, it would be reasonable that I should bear with you;"},{"v":15,"t":"but if they are questions about words and names and your own law, look to it yourselves. For I don’t want to be a judge of these matters.”"},{"v":16,"t":"So he drove them from the judgment seat."},{"v":17,"t":"Then all the Greeks seized Sosthenes, the ruler of the synagogue, and beat him before the judgment seat. Gallio didn’t care about any of these things."},{"v":18,"t":"Paul, having stayed after this many more days, took his leave of the brothers, and sailed from there for Syria, together with Priscilla and Aquila. He shaved his head in Cenchreae, for he had a vow."},{"v":19,"t":"He came to Ephesus, and he left them there; but he himself entered into the synagogue and reasoned with the Jews."},{"v":20,"t":"When they asked him to stay with them a longer time, he declined;"},{"v":21,"t":"but taking his leave of them, he said, “I must by all means keep this coming feast in Jerusalem, but I will return again to you if God wills.” Then he set sail from Ephesus."},{"v":22,"t":"When he had landed at Caesarea, he went up and greeted the assembly, and went down to Antioch."},{"v":23,"t":"Having spent some time there, he departed and went through the region of Galatia and Phrygia, in order, establishing all the disciples."},{"v":24,"t":"Now a certain Jew named Apollos, an Alexandrian by race, an eloquent man, came to Ephesus. He was mighty in the Scriptures."},{"v":25,"t":"This man had been instructed in the way of the Lord; and being fervent in spirit, he spoke and taught accurately the things concerning Jesus, although he knew only the baptism of John."},{"v":26,"t":"He began to speak boldly in the synagogue. But when Priscilla and Aquila heard him, they took him aside, and explained to him the way of God more accurately."},{"v":27,"t":"When he had determined to pass over into Achaia, the brothers encouraged him; and wrote to the disciples to receive him. When he had come, he greatly helped those who had believed through grace;"},{"v":28,"t":"for he powerfully refuted the Jews, publicly showing by the Scriptures that Jesus was the Christ."}]},"19":{"en":[{"v":1,"t":"While Apollos was at Corinth, Paul, having passed through the upper country, came to Ephesus and found certain disciples."},{"v":2,"t":"He said to them, “Did you receive the Holy Spirit when you believed?” They said to him, “No, we haven’t even heard that there is a Holy Spirit.”"},{"v":3,"t":"He said, “Into what then were you baptized?” They said, “Into John’s baptism.”"},{"v":4,"t":"Paul said, “John indeed baptized with the baptism of repentance, saying to the people that they should believe in the one who would come after him, that is, in Christ Jesus.”"},{"v":5,"t":"When they heard this, they were baptized in the name of the Lord Jesus."},{"v":6,"t":"When Paul had laid his hands on them, the Holy Spirit came on them and they spoke with other languages and prophesied."},{"v":7,"t":"They were about twelve men in all."},{"v":8,"t":"He entered into the synagogue and spoke boldly for a period of three months, reasoning and persuading about the things concerning God’s Kingdom."},{"v":9,"t":"But when some were hardened and disobedient, speaking evil of the Way before the multitude, he departed from them and separated the disciples, reasoning daily in the school of Tyrannus."},{"v":10,"t":"This continued for two years, so that all those who lived in Asia heard the word of the Lord Jesus, both Jews and Greeks."},{"v":11,"t":"God worked special miracles by the hands of Paul,"},{"v":12,"t":"so that even handkerchiefs or aprons were carried away from his body to the sick, and the diseases departed from them, and the evil spirits went out."},{"v":13,"t":"But some of the itinerant Jews, exorcists, took on themselves to invoke over those who had the evil spirits the name of the Lord Jesus, saying, “We adjure you by Jesus whom Paul preaches.”"},{"v":14,"t":"There were seven sons of one Sceva, a Jewish chief priest, who did this."},{"v":15,"t":"The evil spirit answered, “Jesus I know, and Paul I know, but who are you?”"},{"v":16,"t":"The man in whom the evil spirit was leaped on them, overpowered them, and prevailed against them, so that they fled out of that house naked and wounded."},{"v":17,"t":"This became known to all, both Jews and Greeks, who lived at Ephesus. Fear fell on them all, and the name of the Lord Jesus was magnified."},{"v":18,"t":"Many also of those who had believed came, confessing and declaring their deeds."},{"v":19,"t":"Many of those who practiced magical arts brought their books together and burned them in the sight of all. They counted their price, and found it to be fifty thousand pieces of silver."},{"v":20,"t":"So the word of the Lord was growing and becoming mighty."},{"v":21,"t":"Now after these things had ended, Paul determined in the Spirit, when he had passed through Macedonia and Achaia, to go to Jerusalem, saying, “After I have been there, I must also see Rome.”"},{"v":22,"t":"Having sent into Macedonia two of those who served him, Timothy and Erastus, he himself stayed in Asia for a while."},{"v":23,"t":"About that time there arose no small disturbance concerning the Way."},{"v":24,"t":"For a certain man named Demetrius, a silversmith who made silver shrines of Artemis, brought no little business to the craftsmen,"},{"v":25,"t":"whom he gathered together with the workmen of like occupation, and said, “Sirs, you know that by this business we have our wealth."},{"v":26,"t":"You see and hear that not at Ephesus alone, but almost throughout all Asia, this Paul has persuaded and turned away many people, saying that they are no gods that are made with hands."},{"v":27,"t":"Not only is there danger that this our trade come into disrepute, but also that the temple of the great goddess Artemis will be counted as nothing and her majesty destroyed, whom all Asia and the world worships.”"},{"v":28,"t":"When they heard this they were filled with anger, and cried out, saying, “Great is Artemis of the Ephesians!”"},{"v":29,"t":"The whole city was filled with confusion, and they rushed with one accord into the theater, having seized Gaius and Aristarchus, men of Macedonia, Paul’s companions in travel."},{"v":30,"t":"When Paul wanted to enter in to the people, the disciples didn’t allow him."},{"v":31,"t":"Certain also of the Asiarchs, being his friends, sent to him and begged him not to venture into the theater."},{"v":32,"t":"Some therefore cried one thing, and some another, for the assembly was in confusion. Most of them didn’t know why they had come together."},{"v":33,"t":"They brought Alexander out of the multitude, the Jews putting him forward. Alexander beckoned with his hand, and would have made a defense to the people."},{"v":34,"t":"But when they perceived that he was a Jew, all with one voice for a time of about two hours cried out, “Great is Artemis of the Ephesians!”"},{"v":35,"t":"When the town clerk had quieted the multitude, he said, “You men of Ephesus, what man is there who doesn’t know that the city of the Ephesians is temple keeper of the great goddess Artemis, and of the image which fell down from Zeus?"},{"v":36,"t":"Seeing then that these things can’t be denied, you ought to be quiet and to do nothing rash."},{"v":37,"t":"For you have brought these men here, who are neither robbers of temples nor blasphemers of your goddess."},{"v":38,"t":"If therefore Demetrius and the craftsmen who are with him have a matter against anyone, the courts are open and there are proconsuls. Let them press charges against one another."},{"v":39,"t":"But if you seek anything about other matters, it will be settled in the regular assembly."},{"v":40,"t":"For indeed we are in danger of being accused concerning today’s riot, there being no cause. Concerning it, we wouldn’t be able to give an account of this commotion.”"}]},"20":{"en":[{"v":1,"t":"After the uproar had ceased, Paul sent for the disciples, took leave of them, and departed to go into Macedonia."},{"v":2,"t":"When he had gone through those parts and had encouraged them with many words, he came into Greece."},{"v":3,"t":"When he had spent three months there, and a plot was made against him by Jews as he was about to set sail for Syria, he determined to return through Macedonia."},{"v":4,"t":"These accompanied him as far as Asia: Sopater of Beroea, Aristarchus and Secundus of the Thessalonians, Gaius of Derbe, Timothy, and Tychicus and Trophimus of Asia."},{"v":5,"t":"But these had gone ahead, and were waiting for us at Troas."},{"v":6,"t":"We sailed away from Philippi after the days of Unleavened Bread, and came to them at Troas in five days, where we stayed seven days."},{"v":7,"t":"On the first day of the week, when the disciples were gathered together to break bread, Paul talked with them, intending to depart on the next day; and continued his speech until midnight."},{"v":8,"t":"There were many lights in the upper room where we were gathered together."},{"v":9,"t":"A certain young man named Eutychus sat in the window, weighed down with deep sleep. As Paul spoke still longer, being weighed down by his sleep, he fell down from the third floor and was taken up dead."},{"v":10,"t":"Paul went down and fell upon him, and embracing him said, “Don’t be troubled, for his life is in him.”"},{"v":11,"t":"When he had gone up, had broken bread and eaten, and had talked with them a long while, even until break of day, he departed."},{"v":12,"t":"They brought the boy in alive, and were greatly comforted."},{"v":13,"t":"But we, going ahead to the ship, set sail for Assos, intending to take Paul aboard there; for he had so arranged, intending himself to go by land."},{"v":14,"t":"When he met us at Assos, we took him aboard and came to Mitylene."},{"v":15,"t":"Sailing from there, we came the following day opposite Chios. The next day we touched at Samos and stayed at Trogyllium, and the day after we came to Miletus."},{"v":16,"t":"For Paul had determined to sail past Ephesus, that he might not have to spend time in Asia; for he was hastening, if it were possible for him, to be in Jerusalem on the day of Pentecost."},{"v":17,"t":"From Miletus he sent to Ephesus and called to himself the elders of the assembly."},{"v":18,"t":"When they had come to him, he said to them, “You yourselves know, from the first day that I set foot in Asia, how I was with you all the time,"},{"v":19,"t":"serving the Lord with all humility, with many tears, and with trials which happened to me by the plots of the Jews;"},{"v":20,"t":"how I didn’t shrink from declaring to you anything that was profitable, teaching you publicly and from house to house,"},{"v":21,"t":"testifying both to Jews and to Greeks repentance toward God and faith toward our Lord Jesus."},{"v":22,"t":"Now, behold, I go bound by the Spirit to Jerusalem, not knowing what will happen to me there;"},{"v":23,"t":"except that the Holy Spirit testifies in every city, saying that bonds and afflictions wait for me."},{"v":24,"t":"But these things don’t count; nor do I hold my life dear to myself, so that I may finish my race with joy, and the ministry which I received from the Lord Jesus, to fully testify to the Good News of the grace of God."},{"v":25,"t":"“Now, behold, I know that you all, among whom I went about preaching God’s Kingdom, will see my face no more."},{"v":26,"t":"Therefore I testify to you today that I am clean from the blood of all men,"},{"v":27,"t":"for I didn’t shrink from declaring to you the whole counsel of God."},{"v":28,"t":"Take heed, therefore, to yourselves and to all the flock, in which the Holy Spirit has made you overseers, to shepherd the assembly of the Lord and God which he purchased with his own blood."},{"v":29,"t":"For I know that after my departure, vicious wolves will enter in among you, not sparing the flock."},{"v":30,"t":"Men will arise from among your own selves, speaking perverse things, to draw away the disciples after them."},{"v":31,"t":"Therefore watch, remembering that for a period of three years I didn’t cease to admonish everyone night and day with tears."},{"v":32,"t":"Now, brothers, I entrust you to God and to the word of his grace, which is able to build up and to give you the inheritance among all those who are sanctified."},{"v":33,"t":"I coveted no one’s silver, gold, or clothing."},{"v":34,"t":"You yourselves know that these hands served my necessities, and those who were with me."},{"v":35,"t":"In all things I gave you an example, that so laboring you ought to help the weak, and to remember the words of the Lord Jesus, that he himself said, ‘It is more blessed to give than to receive.’ ”"},{"v":36,"t":"When he had spoken these things, he knelt down and prayed with them all."},{"v":37,"t":"They all wept freely, and fell on Paul’s neck and kissed him,"},{"v":38,"t":"sorrowing most of all because of the word which he had spoken, that they should see his face no more. Then they accompanied him to the ship."}]},"21":{"en":[{"v":1,"t":"When we had departed from them and had set sail, we came with a straight course to Cos, and the next day to Rhodes, and from there to Patara."},{"v":2,"t":"Having found a ship crossing over to Phoenicia, we went aboard and set sail."},{"v":3,"t":"When we had come in sight of Cyprus, leaving it on the left hand, we sailed to Syria and landed at Tyre, for the ship was there to unload her cargo."},{"v":4,"t":"Having found disciples, we stayed there seven days. These said to Paul through the Spirit that he should not go up to Jerusalem."},{"v":5,"t":"When those days were over, we departed and went on our journey. They all, with wives and children, brought us on our way until we were out of the city. Kneeling down on the beach, we prayed."},{"v":6,"t":"After saying goodbye to each other, we went on board the ship, and they returned home again."},{"v":7,"t":"When we had finished the voyage from Tyre, we arrived at Ptolemais. We greeted the brothers and stayed with them one day."},{"v":8,"t":"On the next day, we who were Paul’s companions departed and came to Caesarea. We entered into the house of Philip the evangelist, who was one of the seven, and stayed with him."},{"v":9,"t":"Now this man had four virgin daughters who prophesied."},{"v":10,"t":"As we stayed there some days, a certain prophet named Agabus came down from Judea."},{"v":11,"t":"Coming to us and taking Paul’s belt, he bound his own feet and hands, and said, “The Holy Spirit says: ‘So the Jews at Jerusalem will bind the man who owns this belt, and will deliver him into the hands of the Gentiles.’”"},{"v":12,"t":"When we heard these things, both we and the people of that place begged him not to go up to Jerusalem."},{"v":13,"t":"Then Paul answered, “What are you doing, weeping and breaking my heart? For I am ready not only to be bound, but also to die at Jerusalem for the name of the Lord Jesus.”"},{"v":14,"t":"When he would not be persuaded, we ceased, saying, “The Lord’s will be done.”"},{"v":15,"t":"After these days we took up our baggage and went up to Jerusalem."},{"v":16,"t":"Some of the disciples from Caesarea also went with us, bringing one Mnason of Cyprus, an early disciple, with whom we would stay."},{"v":17,"t":"When we had come to Jerusalem, the brothers received us gladly."},{"v":18,"t":"The day following, Paul went in with us to James; and all the elders were present."},{"v":19,"t":"When he had greeted them, he reported one by one the things which God had worked among the Gentiles through his ministry."},{"v":20,"t":"They, when they heard it, glorified God. They said to him, “You see, brother, how many thousands there are among the Jews of those who have believed, and they are all zealous for the law."},{"v":21,"t":"They have been informed about you, that you teach all the Jews who are among the Gentiles to forsake Moses, telling them not to circumcise their children and not to walk after the customs."},{"v":22,"t":"What then? The assembly must certainly meet, for they will hear that you have come."},{"v":23,"t":"Therefore do what we tell you. We have four men who have taken a vow."},{"v":24,"t":"Take them and purify yourself with them, and pay their expenses for them, that they may shave their heads. Then all will know that there is no truth in the things that they have been informed about you, but that you yourself also walk keeping the law."},{"v":25,"t":"But concerning the Gentiles who believe, we have written our decision that they should observe no such thing, except that they should keep themselves from food offered to idols, from blood, from strangled things, and from sexual immorality.”"},{"v":26,"t":"Then Paul took the men, and the next day purified himself and went with them into the temple, declaring the fulfillment of the days of purification, until the offering was offered for every one of them."},{"v":27,"t":"When the seven days were almost completed, the Jews from Asia, when they saw him in the temple, stirred up all the multitude and laid hands on him,"},{"v":28,"t":"crying out, “Men of Israel, help! This is the man who teaches all men everywhere against the people, and the law, and this place. Moreover, he also brought Greeks into the temple and has defiled this holy place!”"},{"v":29,"t":"For they had seen Trophimus the Ephesian, with him in the city, and they supposed that Paul had brought him into the temple."},{"v":30,"t":"All the city was moved and the people ran together. They seized Paul and dragged him out of the temple. Immediately the doors were shut."},{"v":31,"t":"As they were trying to kill him, news came up to the commanding officer of the regiment that all Jerusalem was in an uproar."},{"v":32,"t":"Immediately he took soldiers and centurions and ran down to them. They, when they saw the chief captain and the soldiers, stopped beating Paul."},{"v":33,"t":"Then the commanding officer came near, arrested him, commanded him to be bound with two chains, and inquired who he was and what he had done."},{"v":34,"t":"Some shouted one thing and some another, among the crowd. When he couldn’t find out the truth because of the noise, he commanded him to be brought into the barracks."},{"v":35,"t":"When he came to the stairs, he was carried by the soldiers because of the violence of the crowd;"},{"v":36,"t":"for the multitude of the people followed after, crying out, “Away with him!”"},{"v":37,"t":"As Paul was about to be brought into the barracks, he asked the commanding officer, “May I speak to you?” He said, “Do you know Greek?"},{"v":38,"t":"Aren’t you then the Egyptian who before these days stirred up to sedition and led out into the wilderness the four thousand men of the Assassins?”"},{"v":39,"t":"But Paul said, “I am a Jew from Tarsus in Cilicia, a citizen of no insignificant city. I beg you, allow me to speak to the people.”"},{"v":40,"t":"When he had given him permission, Paul, standing on the stairs, beckoned with his hand to the people. When there was a great silence, he spoke to them in the Hebrew language, saying,"}]},"22":{"en":[{"v":1,"t":"“Brothers and fathers, listen to the defense which I now make to you.”"},{"v":2,"t":"When they heard that he spoke to them in the Hebrew language, they were even more quiet. He said,"},{"v":3,"t":"“I am indeed a Jew, born in Tarsus of Cilicia, but brought up in this city at the feet of Gamaliel, instructed according to the strict tradition of the law of our fathers, being zealous for God, even as you all are today."},{"v":4,"t":"I persecuted this Way to the death, binding and delivering into prisons both men and women,"},{"v":5,"t":"as also the high priest and all the council of the elders testify, from whom also I received letters to the brothers, and traveled to Damascus to bring them also who were there to Jerusalem in bonds to be punished."},{"v":6,"t":"“As I made my journey and came close to Damascus, about noon suddenly a great light shone around me from the sky."},{"v":7,"t":"I fell to the ground and heard a voice saying to me, ‘Saul, Saul, why are you persecuting me?’"},{"v":8,"t":"I answered, ‘Who are you, Lord?’ He said to me, ‘I am Jesus of Nazareth, whom you persecute.’"},{"v":9,"t":"“Those who were with me indeed saw the light and were afraid, but they didn’t understand the voice of him who spoke to me."},{"v":10,"t":"I said, ‘What shall I do, Lord?’ The Lord said to me, ‘Arise, and go into Damascus. There you will be told about all things which are appointed for you to do.’"},{"v":11,"t":"When I couldn’t see for the glory of that light, being led by the hand of those who were with me, I came into Damascus."},{"v":12,"t":"“One Ananias, a devout man according to the law, well reported of by all the Jews who lived in Damascus,"},{"v":13,"t":"came to me, and standing by me said to me, ‘Brother Saul, receive your sight!’ In that very hour I looked up at him."},{"v":14,"t":"He said, ‘The God of our fathers has appointed you to know his will, and to see the Righteous One, and to hear a voice from his mouth."},{"v":15,"t":"For you will be a witness for him to all men of what you have seen and heard."},{"v":16,"t":"Now why do you wait? Arise, be baptized, and wash away your sins, calling on the name of the Lord.’"},{"v":17,"t":"“When I had returned to Jerusalem and while I prayed in the temple, I fell into a trance"},{"v":18,"t":"and saw him saying to me, ‘Hurry and get out of Jerusalem quickly, because they will not receive testimony concerning me from you.’"},{"v":19,"t":"I said, ‘Lord, they themselves know that I imprisoned and beat in every synagogue those who believed in you."},{"v":20,"t":"When the blood of Stephen, your witness, was shed, I also was standing by, consenting to his death, and guarding the cloaks of those who killed him.’"},{"v":21,"t":"“He said to me, ‘Depart, for I will send you out far from here to the Gentiles.’ ”"},{"v":22,"t":"They listened to him until he said that; then they lifted up their voice and said, “Rid the earth of this fellow, for he isn’t fit to live!”"},{"v":23,"t":"As they cried out, threw off their cloaks, and threw dust into the air,"},{"v":24,"t":"the commanding officer commanded him to be brought into the barracks, ordering him to be examined by scourging, that he might know for what crime they shouted against him like that."},{"v":25,"t":"When they had tied him up with straps, Paul asked the centurion who stood by, “Is it lawful for you to scourge a man who is a Roman, and not found guilty?”"},{"v":26,"t":"When the centurion heard it, he went to the commanding officer and told him, “Watch what you are about to do, for this man is a Roman!”"},{"v":27,"t":"The commanding officer came and asked him, “Tell me, are you a Roman?” He said, “Yes.”"},{"v":28,"t":"The commanding officer answered, “I bought my citizenship for a great price.” Paul said, “But I was born a Roman.”"},{"v":29,"t":"Immediately those who were about to examine him departed from him, and the commanding officer also was afraid when he realized that he was a Roman, because he had bound him."},{"v":30,"t":"But on the next day, desiring to know the truth about why he was accused by the Jews, he freed him from the bonds and commanded the chief priests and all the council to come together, and brought Paul down and set him before them."}]},"23":{"en":[{"v":1,"t":"Paul, looking steadfastly at the council, said, “Brothers, I have lived before God in all good conscience until today.”"},{"v":2,"t":"The high priest, Ananias, commanded those who stood by him to strike him on the mouth."},{"v":3,"t":"Then Paul said to him, “God will strike you, you whitewashed wall! Do you sit to judge me according to the law, and command me to be struck contrary to the law?”"},{"v":4,"t":"Those who stood by said, “Do you malign God’s high priest?”"},{"v":5,"t":"Paul said, “I didn’t know, brothers, that he was high priest. For it is written, ‘You shall not speak evil of a ruler of your people.’”"},{"v":6,"t":"But when Paul perceived that the one part were Sadducees and the other Pharisees, he cried out in the council, “Men and brothers, I am a Pharisee, a son of Pharisees. Concerning the hope and resurrection of the dead I am being judged!”"},{"v":7,"t":"When he had said this, an argument arose between the Pharisees and Sadducees, and the crowd was divided."},{"v":8,"t":"For the Sadducees say that there is no resurrection, nor angel, nor spirit; but the Pharisees confess all of these."},{"v":9,"t":"A great clamor arose, and some of the scribes of the Pharisees’ part stood up, and contended, saying, “We find no evil in this man. But if a spirit or angel has spoken to him, let’s not fight against God!”"},{"v":10,"t":"When a great argument arose, the commanding officer, fearing that Paul would be torn in pieces by them, commanded the soldiers to go down and take him by force from among them and bring him into the barracks."},{"v":11,"t":"The following night, the Lord stood by him and said, “Cheer up, Paul, for as you have testified about me at Jerusalem, so you must testify also at Rome.”"},{"v":12,"t":"When it was day, some of the Jews banded together and bound themselves under a curse, saying that they would neither eat nor drink until they had killed Paul."},{"v":13,"t":"There were more than forty people who had made this conspiracy."},{"v":14,"t":"They came to the chief priests and the elders, and said, “We have bound ourselves under a great curse to taste nothing until we have killed Paul."},{"v":15,"t":"Now therefore, you with the council inform the commanding officer that he should bring him down to you tomorrow, as though you were going to judge his case more exactly. We are ready to kill him before he comes near.”"},{"v":16,"t":"But Paul’s sister’s son heard they were lying in wait, and he came and entered into the barracks and told Paul."},{"v":17,"t":"Paul summoned one of the centurions and said, “Bring this young man to the commanding officer, for he has something to tell him.”"},{"v":18,"t":"So he took him and brought him to the commanding officer and said, “Paul, the prisoner, summoned me and asked me to bring this young man to you. He has something to tell you.”"},{"v":19,"t":"The commanding officer took him by the hand, and going aside, asked him privately, “What is it that you have to tell me?”"},{"v":20,"t":"He said, “The Jews have agreed to ask you to bring Paul down to the council tomorrow, as though intending to inquire somewhat more accurately concerning him."},{"v":21,"t":"Therefore don’t yield to them, for more than forty men lie in wait for him, who have bound themselves under a curse to neither eat nor drink until they have killed him. Now they are ready, looking for the promise from you.”"},{"v":22,"t":"So the commanding officer let the young man go, charging him, “Tell no one that you have revealed these things to me.”"},{"v":23,"t":"He called to himself two of the centurions, and said, “Prepare two hundred soldiers to go as far as Caesarea, with seventy horsemen and two hundred men armed with spears, at the third hour of the night.”"},{"v":24,"t":"He asked them to provide mounts, that they might set Paul on one, and bring him safely to Felix the governor."},{"v":25,"t":"He wrote a letter like this:"},{"v":26,"t":"“Claudius Lysias to the most excellent governor Felix: Greetings."},{"v":27,"t":"“This man was seized by the Jews, and was about to be killed by them when I came with the soldiers and rescued him, having learned that he was a Roman."},{"v":28,"t":"Desiring to know the cause why they accused him, I brought him down to their council."},{"v":29,"t":"I found him to be accused about questions of their law, but not to be charged with anything worthy of death or of imprisonment."},{"v":30,"t":"When I was told that the Jews lay in wait for the man, I sent him to you immediately, charging his accusers also to bring their accusations against him before you. Farewell.”"},{"v":31,"t":"So the soldiers, carrying out their orders, took Paul and brought him by night to Antipatris."},{"v":32,"t":"But on the next day they left the horsemen to go with him, and returned to the barracks."},{"v":33,"t":"When they came to Caesarea and delivered the letter to the governor, they also presented Paul to him."},{"v":34,"t":"When the governor had read it, he asked what province he was from. When he understood that he was from Cilicia, he said,"},{"v":35,"t":"“I will hear you fully when your accusers also arrive.” He commanded that he be kept in Herod’s palace."}]},"24":{"en":[{"v":1,"t":"After five days, the high priest, Ananias, came down with certain elders and an orator, one Tertullus. They informed the governor against Paul."},{"v":2,"t":"When he was called, Tertullus began to accuse him, saying, “Seeing that by you we enjoy much peace, and that prosperity is coming to this nation by your foresight,"},{"v":3,"t":"we accept it in all ways and in all places, most excellent Felix, with all thankfulness."},{"v":4,"t":"But that I don’t delay you, I entreat you to bear with us and hear a few words."},{"v":5,"t":"For we have found this man to be a plague, an instigator of insurrections among all the Jews throughout the world, and a ringleader of the sect of the Nazarenes."},{"v":6,"t":"He even tried to profane the temple, and we arrested him."},{"v":8,"t":"By examining him yourself you may ascertain all these things of which we accuse him.”"},{"v":9,"t":"The Jews also joined in the attack, affirming that these things were so."},{"v":10,"t":"When the governor had beckoned to him to speak, Paul answered, “Because I know that you have been a judge of this nation for many years, I cheerfully make my defense,"},{"v":11,"t":"seeing that you can verify that it is not more than twelve days since I went up to worship at Jerusalem."},{"v":12,"t":"In the temple they didn’t find me disputing with anyone or stirring up a crowd, either in the synagogues or in the city."},{"v":13,"t":"Nor can they prove to you the things of which they now accuse me."},{"v":14,"t":"But this I confess to you, that according to the Way, which they call a sect, so I serve the God of our fathers, believing all things which are according to the law, and which are written in the prophets;"},{"v":15,"t":"having hope toward God, which these also themselves look for, that there will be a resurrection of the dead, both of the just and unjust."},{"v":16,"t":"In this I also practice always having a conscience void of offense toward God and men."},{"v":17,"t":"Now after some years, I came to bring gifts for the needy to my nation, and offerings;"},{"v":18,"t":"amid which certain Jews from Asia found me purified in the temple, not with a mob, nor with turmoil."},{"v":19,"t":"They ought to have been here before you and to make accusation if they had anything against me."},{"v":20,"t":"Or else let these men themselves say what injustice they found in me when I stood before the council,"},{"v":21,"t":"unless it is for this one thing that I cried standing among them, ‘Concerning the resurrection of the dead I am being judged before you today!’”"},{"v":22,"t":"But Felix, having more exact knowledge concerning the Way, deferred them, saying, “When Lysias, the commanding officer, comes down, I will decide your case.”"},{"v":23,"t":"He ordered the centurion that Paul should be kept in custody and should have some privileges, and not to forbid any of his friends to serve him or to visit him."},{"v":24,"t":"After some days, Felix came with Drusilla his wife, who was a Jewess, and sent for Paul and heard him concerning the faith in Christ Jesus."},{"v":25,"t":"As he reasoned about righteousness, self-control, and the judgment to come, Felix was terrified, and answered, “Go your way for this time, and when it is convenient for me, I will summon you.”"},{"v":26,"t":"Meanwhile, he also hoped that money would be given to him by Paul, that he might release him. Therefore also he sent for him more often and talked with him."},{"v":27,"t":"But when two years were fulfilled, Felix was succeeded by Porcius Festus, and desiring to gain favor with the Jews, Felix left Paul in bonds."}]},"25":{"en":[{"v":1,"t":"Festus therefore, having come into the province, after three days went up to Jerusalem from Caesarea."},{"v":2,"t":"Then the high priest and the principal men of the Jews informed him against Paul, and they begged him,"},{"v":3,"t":"asking a favor against him, that he would summon him to Jerusalem, plotting to kill him on the way."},{"v":4,"t":"However Festus answered that Paul should be kept in custody at Caesarea, and that he himself was about to depart shortly."},{"v":5,"t":"“Let them therefore”, he said, “that are in power among you go down with me, and if there is anything wrong in the man, let them accuse him.”"},{"v":6,"t":"When he had stayed among them more than ten days, he went down to Caesarea, and on the next day he sat on the judgment seat, and commanded Paul to be brought."},{"v":7,"t":"When he had come, the Jews who had come down from Jerusalem stood around him, bringing against him many and grievous charges which they could not prove,"},{"v":8,"t":"while he said in his defense, “Neither against the law of the Jews, nor against the temple, nor against Caesar, have I sinned at all.”"},{"v":9,"t":"But Festus, desiring to gain favor with the Jews, answered Paul and said, “Are you willing to go up to Jerusalem and be judged by me there concerning these things?”"},{"v":10,"t":"But Paul said, “I am standing before Caesar’s judgment seat, where I ought to be tried. I have done no wrong to the Jews, as you also know very well."},{"v":11,"t":"For if I have done wrong and have committed anything worthy of death, I don’t refuse to die; but if none of those things is true that they accuse me of, no one can give me up to them. I appeal to Caesar!”"},{"v":12,"t":"Then Festus, when he had conferred with the council, answered, “You have appealed to Caesar. To Caesar you shall go.”"},{"v":13,"t":"Now when some days had passed, King Agrippa and Bernice arrived at Caesarea and greeted Festus."},{"v":14,"t":"As he stayed there many days, Festus laid Paul’s case before the king, saying, “There is a certain man left a prisoner by Felix;"},{"v":15,"t":"about whom, when I was at Jerusalem, the chief priests and the elders of the Jews informed me, asking for a sentence against him."},{"v":16,"t":"I answered them that it is not the custom of the Romans to give up any man to destruction before the accused has met the accusers face to face and has had opportunity to make his defense concerning the matter laid against him."},{"v":17,"t":"When therefore they had come together here, I didn’t delay, but on the next day sat on the judgment seat and commanded the man to be brought."},{"v":18,"t":"When the accusers stood up, they brought no charges against him of such things as I supposed;"},{"v":19,"t":"but had certain questions against him about their own religion and about one Jesus, who was dead, whom Paul affirmed to be alive."},{"v":20,"t":"Being perplexed how to inquire concerning these things, I asked whether he was willing to go to Jerusalem and there be judged concerning these matters."},{"v":21,"t":"But when Paul had appealed to be kept for the decision of the emperor, I commanded him to be kept until I could send him to Caesar.”"},{"v":22,"t":"Agrippa said to Festus, “I also would like to hear the man myself.” “Tomorrow,” he said, “you shall hear him.”"},{"v":23,"t":"So on the next day, when Agrippa and Bernice had come with great pomp, and they had entered into the place of hearing with the commanding officers and the principal men of the city, at the command of Festus, Paul was brought in."},{"v":24,"t":"Festus said, “King Agrippa, and all men who are here present with us, you see this man about whom all the multitude of the Jews petitioned me, both at Jerusalem and here, crying that he ought not to live any longer."},{"v":25,"t":"But when I found that he had committed nothing worthy of death, and as he himself appealed to the emperor, I determined to send him,"},{"v":26,"t":"of whom I have no certain thing to write to my lord. Therefore I have brought him out before you, and especially before you, King Agrippa, that, after examination I may have something to write."},{"v":27,"t":"For it seems to me unreasonable, in sending a prisoner, not to also specify the charges against him.”"}]},"26":{"en":[{"v":1,"t":"Agrippa said to Paul, “You may speak for yourself.” Then Paul stretched out his hand, and made his defense."},{"v":2,"t":"“I think myself happy, King Agrippa, that I am to make my defense before you today concerning all the things that I am accused by the Jews,"},{"v":3,"t":"especially because you are expert in all customs and questions which are among the Jews. Therefore I beg you to hear me patiently."},{"v":4,"t":"“Indeed, all the Jews know my way of life from my youth up, which was from the beginning among my own nation and at Jerusalem;"},{"v":5,"t":"having known me from the first, if they are willing to testify, that after the strictest sect of our religion I lived a Pharisee."},{"v":6,"t":"Now I stand here to be judged for the hope of the promise made by God to our fathers,"},{"v":7,"t":"which our twelve tribes, earnestly serving night and day, hope to attain. Concerning this hope I am accused by the Jews, King Agrippa!"},{"v":8,"t":"Why is it judged incredible with you if God does raise the dead?"},{"v":9,"t":"“I myself most certainly thought that I ought to do many things contrary to the name of Jesus of Nazareth."},{"v":10,"t":"I also did this in Jerusalem. I both shut up many of the saints in prisons, having received authority from the chief priests; and when they were put to death I gave my vote against them."},{"v":11,"t":"Punishing them often in all the synagogues, I tried to make them blaspheme. Being exceedingly enraged against them, I persecuted them even to foreign cities."},{"v":12,"t":"“Whereupon as I traveled to Damascus with the authority and commission from the chief priests,"},{"v":13,"t":"at noon, O king, I saw on the way a light from the sky, brighter than the sun, shining around me and those who traveled with me."},{"v":14,"t":"When we had all fallen to the earth, I heard a voice saying to me in the Hebrew language, ‘Saul, Saul, why are you persecuting me? It is hard for you to kick against the goads.’"},{"v":15,"t":"“I said, ‘Who are you, Lord?’ “He said, ‘I am Jesus, whom you are persecuting."},{"v":16,"t":"But arise, and stand on your feet, for I have appeared to you for this purpose: to appoint you a servant and a witness both of the things which you have seen and of the things which I will reveal to you;"},{"v":17,"t":"delivering you from the people and from the Gentiles, to whom I send you,"},{"v":18,"t":"to open their eyes, that they may turn from darkness to light and from the power of Satan to God, that they may receive remission of sins and an inheritance among those who are sanctified by faith in me.’"},{"v":19,"t":"“Therefore, King Agrippa, I was not disobedient to the heavenly vision,"},{"v":20,"t":"but declared first to them of Damascus, at Jerusalem, and throughout all the country of Judea, and also to the Gentiles, that they should repent and turn to God, doing works worthy of repentance."},{"v":21,"t":"For this reason the Jews seized me in the temple and tried to kill me."},{"v":22,"t":"Having therefore obtained the help that is from God, I stand to this day testifying both to small and great, saying nothing but what the prophets and Moses said would happen,"},{"v":23,"t":"how the Christ must suffer, and how, by the resurrection of the dead, he would be first to proclaim light both to these people and to the Gentiles.”"},{"v":24,"t":"As he thus made his defense, Festus said with a loud voice, “Paul, you are crazy! Your great learning is driving you insane!”"},{"v":25,"t":"But he said, “I am not crazy, most excellent Festus, but boldly declare words of truth and reasonableness."},{"v":26,"t":"For the king knows of these things, to whom also I speak freely. For I am persuaded that none of these things is hidden from him, for this has not been done in a corner."},{"v":27,"t":"King Agrippa, do you believe the prophets? I know that you believe.”"},{"v":28,"t":"Agrippa said to Paul, “With a little persuasion are you trying to make me a Christian?”"},{"v":29,"t":"Paul said, “I pray to God, that whether with little or with much, not only you, but also all that hear me today, might become such as I am, except for these bonds.”"},{"v":30,"t":"The king rose up with the governor and Bernice, and those who sat with them."},{"v":31,"t":"When they had withdrawn, they spoke to one another, saying, “This man does nothing worthy of death or of bonds.”"},{"v":32,"t":"Agrippa said to Festus, “This man might have been set free if he had not appealed to Caesar.”"}]},"27":{"en":[{"v":1,"t":"When it was determined that we should sail for Italy, they delivered Paul and certain other prisoners to a centurion named Julius, of the Augustan band."},{"v":2,"t":"Embarking in a ship of Adramyttium, which was about to sail to places on the coast of Asia, we put to sea, Aristarchus, a Macedonian of Thessalonica being with us."},{"v":3,"t":"The next day, we touched at Sidon. Julius treated Paul kindly and gave him permission to go to his friends and refresh himself."},{"v":4,"t":"Putting to sea from there, we sailed under the lee of Cyprus, because the winds were contrary."},{"v":5,"t":"When we had sailed across the sea which is off Cilicia and Pamphylia, we came to Myra, a city of Lycia."},{"v":6,"t":"There the centurion found a ship of Alexandria sailing for Italy, and he put us on board."},{"v":7,"t":"When we had sailed slowly many days, and had come with difficulty opposite Cnidus, the wind not allowing us further, we sailed under the lee of Crete, opposite Salmone."},{"v":8,"t":"With difficulty sailing along it we came to a certain place called Fair Havens, near the city of Lasea."},{"v":9,"t":"When much time had passed and the voyage was now dangerous because the Fast had now already gone by, Paul admonished them"},{"v":10,"t":"and said to them, “Sirs, I perceive that the voyage will be with injury and much loss, not only of the cargo and the ship, but also of our lives.”"},{"v":11,"t":"But the centurion gave more heed to the master and to the owner of the ship than to those things which were spoken by Paul."},{"v":12,"t":"Because the haven was not suitable to winter in, the majority advised going to sea from there, if by any means they could reach Phoenix and winter there, which is a port of Crete, looking southwest and northwest."},{"v":13,"t":"When the south wind blew softly, supposing that they had obtained their purpose, they weighed anchor and sailed along Crete, close to shore."},{"v":14,"t":"But before long, a stormy wind beat down from shore, which is called Euroclydon."},{"v":15,"t":"When the ship was caught and couldn’t face the wind, we gave way to it and were driven along."},{"v":16,"t":"Running under the lee of a small island called Clauda, we were able, with difficulty, to secure the boat."},{"v":17,"t":"After they had hoisted it up, they used cables to help reinforce the ship. Fearing that they would run aground on the Syrtis sand bars, they lowered the sea anchor, and so were driven along."},{"v":18,"t":"As we labored exceedingly with the storm, the next day they began to throw things overboard."},{"v":19,"t":"On the third day, they threw out the ship’s tackle with their own hands."},{"v":20,"t":"When neither sun nor stars shone on us for many days, and no small storm pressed on us, all hope that we would be saved was now taken away."},{"v":21,"t":"When they had been long without food, Paul stood up in the middle of them and said, “Sirs, you should have listened to me, and not have set sail from Crete and have gotten this injury and loss."},{"v":22,"t":"Now I exhort you to cheer up, for there will be no loss of life among you, but only of the ship."},{"v":23,"t":"For there stood by me this night an angel, belonging to the God whose I am and whom I serve,"},{"v":24,"t":"saying, ‘Don’t be afraid, Paul. You must stand before Caesar. Behold, God has granted you all those who sail with you.’"},{"v":25,"t":"Therefore, sirs, cheer up! For I believe God, that it will be just as it has been spoken to me."},{"v":26,"t":"But we must run aground on a certain island.”"},{"v":27,"t":"But when the fourteenth night had come, as we were driven back and forth in the Adriatic Sea, about midnight the sailors surmised that they were drawing near to some land."},{"v":28,"t":"They took soundings and found twenty fathoms. After a little while, they took soundings again, and found fifteen fathoms."},{"v":29,"t":"Fearing that we would run aground on rocky ground, they let go four anchors from the stern, and wished for daylight."},{"v":30,"t":"As the sailors were trying to flee out of the ship and had lowered the boat into the sea, pretending that they would lay out anchors from the bow,"},{"v":31,"t":"Paul said to the centurion and to the soldiers, “Unless these stay in the ship, you can’t be saved.”"},{"v":32,"t":"Then the soldiers cut away the ropes of the boat and let it fall off."},{"v":33,"t":"While the day was coming on, Paul begged them all to take some food, saying, “Today is the fourteenth day that you wait and continue fasting, having taken nothing."},{"v":34,"t":"Therefore I beg you to take some food, for this is for your safety; for not a hair will perish from any of your heads.”"},{"v":35,"t":"When he had said this and had taken bread, he gave thanks to God in the presence of all; then he broke it and began to eat."},{"v":36,"t":"Then they all cheered up, and they also took food."},{"v":37,"t":"In all, we were two hundred seventy-six souls on the ship."},{"v":38,"t":"When they had eaten enough, they lightened the ship, throwing out the wheat into the sea."},{"v":39,"t":"When it was day, they didn’t recognize the land, but they noticed a certain bay with a beach, and they decided to try to drive the ship onto it."},{"v":40,"t":"Casting off the anchors, they left them in the sea, at the same time untying the rudder ropes. Hoisting up the foresail to the wind, they made for the beach."},{"v":41,"t":"But coming to a place where two seas met, they ran the vessel aground. The bow struck and remained immovable, but the stern began to break up by the violence of the waves."},{"v":42,"t":"The soldiers’ counsel was to kill the prisoners, so that none of them would swim out and escape."},{"v":43,"t":"But the centurion, desiring to save Paul, stopped them from their purpose, and commanded that those who could swim should throw themselves overboard first to go toward the land;"},{"v":44,"t":"and the rest should follow, some on planks and some on other things from the ship. So they all escaped safely to the land."}]},"28":{"en":[{"v":1,"t":"When we had escaped, then they learned that the island was called Malta."},{"v":2,"t":"The natives showed us uncommon kindness; for they kindled a fire and received us all, because of the present rain and because of the cold."},{"v":3,"t":"But when Paul had gathered a bundle of sticks and laid them on the fire, a viper came out because of the heat and fastened on his hand."},{"v":4,"t":"When the natives saw the creature hanging from his hand, they said to one another, “No doubt this man is a murderer, whom, though he has escaped from the sea, yet Justice has not allowed to live.”"},{"v":5,"t":"However he shook off the creature into the fire, and wasn’t harmed."},{"v":6,"t":"But they expected that he would have swollen or fallen down dead suddenly, but when they watched for a long time and saw nothing bad happen to him, they changed their minds and said that he was a god."},{"v":7,"t":"Now in the neighborhood of that place were lands belonging to the chief man of the island, named Publius, who received us and courteously entertained us for three days."},{"v":8,"t":"The father of Publius lay sick of fever and dysentery. Paul entered in to him, prayed, and laying his hands on him, healed him."},{"v":9,"t":"Then when this was done, the rest also who had diseases in the island came and were cured."},{"v":10,"t":"They also honored us with many honors; and when we sailed, they put on board the things that we needed."},{"v":11,"t":"After three months, we set sail in a ship of Alexandria which had wintered in the island, whose figurehead was “The Twin Brothers.”"},{"v":12,"t":"Touching at Syracuse, we stayed there three days."},{"v":13,"t":"From there we circled around and arrived at Rhegium. After one day, a south wind sprang up, and on the second day we came to Puteoli,"},{"v":14,"t":"where we found brothers, and were entreated to stay with them for seven days. So we came to Rome."},{"v":15,"t":"From there the brothers, when they heard of us, came to meet us as far as The Market of Appius and The Three Taverns. When Paul saw them, he thanked God and took courage."},{"v":16,"t":"When we entered into Rome, the centurion delivered the prisoners to the captain of the guard, but Paul was allowed to stay by himself with the soldier who guarded him."},{"v":17,"t":"After three days Paul called together those who were the leaders of the Jews. When they had come together, he said to them, “I, brothers, though I had done nothing against the people or the customs of our fathers, still was delivered prisoner from Jerusalem into the hands of the Romans,"},{"v":18,"t":"who, when they had examined me, desired to set me free, because there was no cause of death in me."},{"v":19,"t":"But when the Jews spoke against it, I was constrained to appeal to Caesar, not that I had anything about which to accuse my nation."},{"v":20,"t":"For this cause therefore I asked to see you and to speak with you. For because of the hope of Israel I am bound with this chain.”"},{"v":21,"t":"They said to him, “We neither received letters from Judea concerning you, nor did any of the brothers come here and report or speak any evil of you."},{"v":22,"t":"But we desire to hear from you what you think. For, as concerning this sect, it is known to us that everywhere it is spoken against.”"},{"v":23,"t":"When they had appointed him a day, many people came to him at his lodging. He explained to them, testifying about God’s Kingdom, and persuading them concerning Jesus, both from the law of Moses and from the prophets, from morning until evening."},{"v":24,"t":"Some believed the things which were spoken, and some disbelieved."},{"v":25,"t":"When they didn’t agree among themselves, they departed after Paul had spoken one message: “The Holy Spirit spoke rightly through Isaiah the prophet to our fathers,"},{"v":26,"t":"saying, ‘Go to this people and say, in hearing, you will hear, but will in no way understand. In seeing, you will see, but will in no way perceive."},{"v":27,"t":"For this people’s heart has grown callous. Their ears are dull of hearing. Their eyes they have closed. Lest they should see with their eyes, hear with their ears, understand with their heart, and would turn again, then I would heal them.’"},{"v":28,"t":"“Be it known therefore to you that the salvation of God is sent to the nations, and they will listen.”"},{"v":29,"t":"When he had said these words, the Jews departed, having a great dispute among themselves."},{"v":30,"t":"Paul stayed two whole years in his own rented house and received all who were coming to him,"},{"v":31,"t":"preaching God’s Kingdom and teaching the things concerning the Lord Jesus Christ with all boldness, without hindrance."}]}},"ROM":{"1":{"en":[{"v":1,"t":"Paul, a servant of Jesus Christ, called to be an apostle, set apart for the Good News of God,"},{"v":2,"t":"which he promised before through his prophets in the holy Scriptures,"},{"v":3,"t":"concerning his Son, who was born of the offspring of David according to the flesh,"},{"v":4,"t":"who was declared to be the Son of God with power according to the Spirit of holiness, by the resurrection from the dead, Jesus Christ our Lord,"},{"v":5,"t":"through whom we received grace and apostleship for obedience of faith among all the nations for his name’s sake;"},{"v":6,"t":"among whom you are also called to belong to Jesus Christ;"},{"v":7,"t":"to all who are in Rome, beloved of God, called to be saints: Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":8,"t":"First, I thank my God through Jesus Christ for all of you, that your faith is proclaimed throughout the whole world."},{"v":9,"t":"For God is my witness, whom I serve in my spirit in the Good News of his Son, how unceasingly I make mention of you always in my prayers,"},{"v":10,"t":"requesting, if by any means now at last I may be prospered by the will of God to come to you."},{"v":11,"t":"For I long to see you, that I may impart to you some spiritual gift, to the end that you may be established;"},{"v":12,"t":"that is, that I with you may be encouraged in you, each of us by the other’s faith, both yours and mine."},{"v":13,"t":"Now I don’t desire to have you unaware, brothers, that I often planned to come to you (and was hindered so far), that I might have some fruit among you also, even as among the rest of the Gentiles."},{"v":14,"t":"I am debtor both to Greeks and to foreigners, both to the wise and to the foolish."},{"v":15,"t":"So as much as is in me, I am eager to preach the Good News to you also who are in Rome."},{"v":16,"t":"For I am not ashamed of the Good News of Christ, because it is the power of God for salvation for everyone who believes, for the Jew first, and also for the Greek."},{"v":17,"t":"For in it is revealed God’s righteousness from faith to faith. As it is written, “But the righteous shall live by faith.”"},{"v":18,"t":"For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men who suppress the truth in unrighteousness,"},{"v":19,"t":"because that which is known of God is revealed in them, for God revealed it to them."},{"v":20,"t":"For the invisible things of him since the creation of the world are clearly seen, being perceived through the things that are made, even his everlasting power and divinity, that they may be without excuse."},{"v":21,"t":"Because knowing God, they didn’t glorify him as God, and didn’t give thanks, but became vain in their reasoning, and their senseless heart was darkened."},{"v":22,"t":"Professing themselves to be wise, they became fools,"},{"v":23,"t":"and traded the glory of the incorruptible God for the likeness of an image of corruptible man, and of birds, four-footed animals, and creeping things."},{"v":24,"t":"Therefore God also gave them up in the lusts of their hearts to uncleanness, that their bodies should be dishonored among themselves;"},{"v":25,"t":"who exchanged the truth of God for a lie, and worshiped and served the creature rather than the Creator, who is blessed forever. Amen."},{"v":26,"t":"For this reason, God gave them up to vile passions. For their women changed the natural function into that which is against nature."},{"v":27,"t":"Likewise also the men, leaving the natural function of the woman, burned in their lust toward one another, men doing what is inappropriate with men, and receiving in themselves the due penalty of their error."},{"v":28,"t":"Even as they refused to have God in their knowledge, God gave them up to a reprobate mind, to do those things which are not fitting;"},{"v":29,"t":"being filled with all unrighteousness, sexual immorality, wickedness, covetousness, malice; full of envy, murder, strife, deceit, evil habits, secret slanderers,"},{"v":30,"t":"backbiters, hateful to God, insolent, arrogant, boastful, inventors of evil things, disobedient to parents,"},{"v":31,"t":"without understanding, covenant breakers, without natural affection, unforgiving, unmerciful;"},{"v":32,"t":"who, knowing the ordinance of God, that those who practice such things are worthy of death, not only do the same, but also approve of those who practice them."}]},"2":{"en":[{"v":1,"t":"Therefore you are without excuse, O man, whoever you are who judge. For in that which you judge another, you condemn yourself. For you who judge practice the same things."},{"v":2,"t":"We know that the judgment of God is according to truth against those who practice such things."},{"v":3,"t":"Do you think this, O man who judges those who practice such things, and do the same, that you will escape the judgment of God?"},{"v":4,"t":"Or do you despise the riches of his goodness, forbearance, and patience, not knowing that the goodness of God leads you to repentance?"},{"v":5,"t":"But according to your hardness and unrepentant heart you are treasuring up for yourself wrath in the day of wrath, revelation, and of the righteous judgment of God,"},{"v":6,"t":"who “will pay back to everyone according to their works:”"},{"v":7,"t":"to those who by perseverance in well-doing seek for glory, honor, and incorruptibility, eternal life;"},{"v":8,"t":"but to those who are self-seeking and don’t obey the truth, but obey unrighteousness, will be wrath, indignation,"},{"v":9,"t":"oppression, and anguish on every soul of man who does evil, to the Jew first, and also to the Greek."},{"v":10,"t":"But glory, honor, and peace go to every man who does good, to the Jew first, and also to the Greek."},{"v":11,"t":"For there is no partiality with God."},{"v":12,"t":"For as many as have sinned without the law will also perish without the law. As many as have sinned under the law will be judged by the law."},{"v":13,"t":"For it isn’t the hearers of the law who are righteous before God, but the doers of the law will be justified"},{"v":14,"t":"(for when Gentiles who don’t have the law do by nature the things of the law, these, not having the law, are a law to themselves,"},{"v":15,"t":"in that they show the work of the law written in their hearts, their conscience testifying with them, and their thoughts among themselves accusing or else excusing them)"},{"v":16,"t":"in the day when God will judge the secrets of men, according to my Good News, by Jesus Christ."},{"v":17,"t":"Indeed you bear the name of a Jew, rest on the law, glory in God,"},{"v":18,"t":"know his will, and approve the things that are excellent, being instructed out of the law,"},{"v":19,"t":"and are confident that you yourself are a guide of the blind, a light to those who are in darkness,"},{"v":20,"t":"a corrector of the foolish, a teacher of babies, having in the law the form of knowledge and of the truth."},{"v":21,"t":"You therefore who teach another, don’t you teach yourself? You who preach that a man shouldn’t steal, do you steal?"},{"v":22,"t":"You who say a man shouldn’t commit adultery, do you commit adultery? You who abhor idols, do you rob temples?"},{"v":23,"t":"You who glory in the law, do you dishonor God by disobeying the law?"},{"v":24,"t":"For “the name of God is blasphemed among the Gentiles because of you,” just as it is written."},{"v":25,"t":"For circumcision indeed profits, if you are a doer of the law, but if you are a transgressor of the law, your circumcision has become uncircumcision."},{"v":26,"t":"If therefore the uncircumcised keep the ordinances of the law, won’t his uncircumcision be accounted as circumcision?"},{"v":27,"t":"Won’t those who are physically uncircumcised, but fulfill the law, judge you, who with the letter and circumcision are a transgressor of the law?"},{"v":28,"t":"For he is not a Jew who is one outwardly, neither is that circumcision which is outward in the flesh;"},{"v":29,"t":"but he is a Jew who is one inwardly, and circumcision is that of the heart, in the spirit, not in the letter; whose praise is not from men, but from God."}]},"3":{"en":[{"v":1,"t":"Then what advantage does the Jew have? Or what is the profit of circumcision?"},{"v":2,"t":"Much in every way! Because first of all, they were entrusted with the revelations of God."},{"v":3,"t":"For what if some were without faith? Will their lack of faith nullify the faithfulness of God?"},{"v":4,"t":"May it never be! Yes, let God be found true, but every man a liar. As it is written, “that you might be justified in your words, and might prevail when you come into judgment.”"},{"v":5,"t":"But if our unrighteousness commends the righteousness of God, what will we say? Is God unrighteous who inflicts wrath? I speak like men do."},{"v":6,"t":"May it never be! For then how will God judge the world?"},{"v":7,"t":"For if the truth of God through my lie abounded to his glory, why am I also still judged as a sinner?"},{"v":8,"t":"Why not (as we are slanderously reported, and as some affirm that we say), “Let’s do evil, that good may come?” Those who say so are justly condemned."},{"v":9,"t":"What then? Are we better than they? No, in no way. For we previously warned both Jews and Greeks that they are all under sin."},{"v":10,"t":"As it is written, “There is no one righteous; no, not one."},{"v":11,"t":"There is no one who understands. There is no one who seeks after God."},{"v":12,"t":"They have all turned away. They have together become unprofitable. There is no one who does good, no, not so much as one.”"},{"v":13,"t":"“Their throat is an open tomb. With their tongues they have used deceit.” “The poison of vipers is under their lips.”"},{"v":14,"t":"“Their mouth is full of cursing and bitterness.”"},{"v":15,"t":"“Their feet are swift to shed blood."},{"v":16,"t":"Destruction and misery are in their ways."},{"v":17,"t":"The way of peace, they haven’t known.”"},{"v":18,"t":"“There is no fear of God before their eyes.”"},{"v":19,"t":"Now we know that whatever things the law says, it speaks to those who are under the law, that every mouth may be closed, and all the world may be brought under the judgment of God."},{"v":20,"t":"Because by the works of the law, no flesh will be justified in his sight; for through the law comes the knowledge of sin."},{"v":21,"t":"But now apart from the law, a righteousness of God has been revealed, being testified by the law and the prophets;"},{"v":22,"t":"even the righteousness of God through faith in Jesus Christ to all and on all those who believe. For there is no distinction,"},{"v":23,"t":"for all have sinned, and fall short of the glory of God;"},{"v":24,"t":"being justified freely by his grace through the redemption that is in Christ Jesus,"},{"v":25,"t":"whom God sent to be an atoning sacrifice through faith in his blood, for a demonstration of his righteousness through the passing over of prior sins, in God’s forbearance;"},{"v":26,"t":"to demonstrate his righteousness at this present time, that he might himself be just and the justifier of him who has faith in Jesus."},{"v":27,"t":"Where then is the boasting? It is excluded. By what kind of law? Of works? No, but by a law of faith."},{"v":28,"t":"We maintain therefore that a man is justified by faith apart from the works of the law."},{"v":29,"t":"Or is God the God of Jews only? Isn’t he the God of Gentiles also? Yes, of Gentiles also,"},{"v":30,"t":"since indeed there is one God who will justify the circumcised by faith and the uncircumcised through faith."},{"v":31,"t":"Do we then nullify the law through faith? May it never be! No, we establish the law."}]},"4":{"en":[{"v":1,"t":"What then will we say that Abraham, our forefather, has found according to the flesh?"},{"v":2,"t":"For if Abraham was justified by works, he has something to boast about, but not toward God."},{"v":3,"t":"For what does the Scripture say? “Abraham believed God, and it was accounted to him for righteousness.”"},{"v":4,"t":"Now to him who works, the reward is not counted as grace, but as something owed."},{"v":5,"t":"But to him who doesn’t work, but believes in him who justifies the ungodly, his faith is accounted for righteousness."},{"v":6,"t":"Even as David also pronounces blessing on the man to whom God counts righteousness apart from works:"},{"v":7,"t":"“Blessed are they whose iniquities are forgiven, whose sins are covered."},{"v":8,"t":"Blessed is the man whom the Lord will by no means charge with sin.”"},{"v":9,"t":"Is this blessing then pronounced only on the circumcised, or on the uncircumcised also? For we say that faith was accounted to Abraham for righteousness."},{"v":10,"t":"How then was it counted? When he was in circumcision, or in uncircumcision? Not in circumcision, but in uncircumcision."},{"v":11,"t":"He received the sign of circumcision, a seal of the righteousness of the faith which he had while he was in uncircumcision, that he might be the father of all those who believe, though they might be in uncircumcision, that righteousness might also be accounted to them."},{"v":12,"t":"He is the father of circumcision to those who not only are of the circumcision, but who also walk in the steps of that faith of our father Abraham, which he had in uncircumcision."},{"v":13,"t":"For the promise to Abraham and to his offspring that he would be heir of the world wasn’t through the law, but through the righteousness of faith."},{"v":14,"t":"For if those who are of the law are heirs, faith is made void, and the promise is made of no effect."},{"v":15,"t":"For the law produces wrath; for where there is no law, neither is there disobedience."},{"v":16,"t":"For this cause it is of faith, that it may be according to grace, to the end that the promise may be sure to all the offspring, not to that only which is of the law, but to that also which is of the faith of Abraham, who is the father of us all."},{"v":17,"t":"As it is written, “I have made you a father of many nations.” This is in the presence of him whom he believed: God, who gives life to the dead, and calls the things that are not, as though they were."},{"v":18,"t":"Against hope, Abraham in hope believed, to the end that he might become a father of many nations, according to that which had been spoken, “So will your offspring be.”"},{"v":19,"t":"Without being weakened in faith, he didn’t consider his own body, already having been worn out, (he being about a hundred years old), and the deadness of Sarah’s womb."},{"v":20,"t":"Yet, looking to the promise of God, he didn’t waver through unbelief, but grew strong through faith, giving glory to God,"},{"v":21,"t":"and being fully assured that what he had promised, he was also able to perform."},{"v":22,"t":"Therefore it also was “credited to him for righteousness.”"},{"v":23,"t":"Now it was not written that it was accounted to him for his sake alone,"},{"v":24,"t":"but for our sake also, to whom it will be accounted, who believe in him who raised Jesus our Lord from the dead,"},{"v":25,"t":"who was delivered up for our trespasses, and was raised for our justification."}]},"5":{"en":[{"v":1,"t":"Being therefore justified by faith, we have peace with God through our Lord Jesus Christ;"},{"v":2,"t":"through whom we also have our access by faith into this grace in which we stand. We rejoice in hope of the glory of God."},{"v":3,"t":"Not only this, but we also rejoice in our sufferings, knowing that suffering produces perseverance;"},{"v":4,"t":"and perseverance, proven character; and proven character, hope;"},{"v":5,"t":"and hope doesn’t disappoint us, because God’s love has been poured into our hearts through the Holy Spirit who was given to us."},{"v":6,"t":"For while we were yet weak, at the right time Christ died for the ungodly."},{"v":7,"t":"For one will hardly die for a righteous man. Yet perhaps for a good person someone would even dare to die."},{"v":8,"t":"But God commends his own love toward us, in that while we were yet sinners, Christ died for us."},{"v":9,"t":"Much more then, being now justified by his blood, we will be saved from God’s wrath through him."},{"v":10,"t":"For if while we were enemies, we were reconciled to God through the death of his Son, much more, being reconciled, we will be saved by his life."},{"v":11,"t":"Not only so, but we also rejoice in God through our Lord Jesus Christ, through whom we have now received the reconciliation."},{"v":12,"t":"Therefore, as sin entered into the world through one man, and death through sin, so death passed to all men because all sinned."},{"v":13,"t":"For until the law, sin was in the world; but sin is not charged when there is no law."},{"v":14,"t":"Nevertheless death reigned from Adam until Moses, even over those whose sins weren’t like Adam’s disobedience, who is a foreshadowing of him who was to come."},{"v":15,"t":"But the free gift isn’t like the trespass. For if by the trespass of the one the many died, much more did the grace of God and the gift by the grace of the one man, Jesus Christ, abound to the many."},{"v":16,"t":"The gift is not as through one who sinned; for the judgment came by one to condemnation, but the free gift followed many trespasses to justification."},{"v":17,"t":"For if by the trespass of the one, death reigned through the one; so much more will those who receive the abundance of grace and of the gift of righteousness reign in life through the one, Jesus Christ."},{"v":18,"t":"So then as through one trespass, all men were condemned; even so through one act of righteousness, all men were justified to life."},{"v":19,"t":"For as through the one man’s disobedience many were made sinners, even so through the obedience of the one, many will be made righteous."},{"v":20,"t":"The law came in that the trespass might abound; but where sin abounded, grace abounded more exceedingly,"},{"v":21,"t":"that as sin reigned in death, even so grace might reign through righteousness to eternal life through Jesus Christ our Lord."}]},"6":{"en":[{"v":1,"t":"What shall we say then? Shall we continue in sin, that grace may abound?"},{"v":2,"t":"May it never be! We who died to sin, how could we live in it any longer?"},{"v":3,"t":"Or don’t you know that all of us who were baptized into Christ Jesus were baptized into his death?"},{"v":4,"t":"We were buried therefore with him through baptism into death, that just as Christ was raised from the dead through the glory of the Father, so we also might walk in newness of life."},{"v":5,"t":"For if we have become united with him in the likeness of his death, we will also be part of his resurrection;"},{"v":6,"t":"knowing this, that our old man was crucified with him, that the body of sin might be done away with, so that we would no longer be in bondage to sin."},{"v":7,"t":"For he who has died has been freed from sin."},{"v":8,"t":"But if we died with Christ, we believe that we will also live with him,"},{"v":9,"t":"knowing that Christ, being raised from the dead, dies no more. Death no longer has dominion over him!"},{"v":10,"t":"For the death that he died, he died to sin one time; but the life that he lives, he lives to God."},{"v":11,"t":"Thus consider yourselves also to be dead to sin, but alive to God in Christ Jesus our Lord."},{"v":12,"t":"Therefore don’t let sin reign in your mortal body, that you should obey it in its lusts."},{"v":13,"t":"Also, do not present your members to sin as instruments of unrighteousness, but present yourselves to God as alive from the dead, and your members as instruments of righteousness to God."},{"v":14,"t":"For sin will not have dominion over you, for you are not under law, but under grace."},{"v":15,"t":"What then? Shall we sin because we are not under law but under grace? May it never be!"},{"v":16,"t":"Don’t you know that when you present yourselves as servants and obey someone, you are the servants of whomever you obey, whether of sin to death, or of obedience to righteousness?"},{"v":17,"t":"But thanks be to God that, whereas you were bondservants of sin, you became obedient from the heart to that form of teaching to which you were delivered."},{"v":18,"t":"Being made free from sin, you became bondservants of righteousness."},{"v":19,"t":"I speak in human terms because of the weakness of your flesh; for as you presented your members as servants to uncleanness and to wickedness upon wickedness, even so now present your members as servants to righteousness for sanctification."},{"v":20,"t":"For when you were servants of sin, you were free from righteousness."},{"v":21,"t":"What fruit then did you have at that time in the things of which you are now ashamed? For the end of those things is death."},{"v":22,"t":"But now, being made free from sin and having become servants of God, you have your fruit of sanctification and the result of eternal life."},{"v":23,"t":"For the wages of sin is death, but the free gift of God is eternal life in Christ Jesus our Lord."}]},"7":{"en":[{"v":1,"t":"Or don’t you know, brothers (for I speak to men who know the law), that the law has dominion over a man for as long as he lives?"},{"v":2,"t":"For the woman that has a husband is bound by law to the husband while he lives, but if the husband dies, she is discharged from the law of the husband."},{"v":3,"t":"So then if, while the husband lives, she is joined to another man, she would be called an adulteress. But if the husband dies, she is free from the law, so that she is no adulteress, though she is joined to another man."},{"v":4,"t":"Therefore, my brothers, you also were made dead to the law through the body of Christ, that you would be joined to another, to him who was raised from the dead, that we might produce fruit to God."},{"v":5,"t":"For when we were in the flesh, the sinful passions which were through the law worked in our members to bring out fruit to death."},{"v":6,"t":"But now we have been discharged from the law, having died to that in which we were held; so that we serve in newness of the spirit, and not in oldness of the letter."},{"v":7,"t":"What shall we say then? Is the law sin? May it never be! However, I wouldn’t have known sin except through the law. For I wouldn’t have known coveting unless the law had said, “You shall not covet.”"},{"v":8,"t":"But sin, finding occasion through the commandment, produced in me all kinds of coveting. For apart from the law, sin is dead."},{"v":9,"t":"I was alive apart from the law once, but when the commandment came, sin revived and I died."},{"v":10,"t":"The commandment which was for life, this I found to be for death;"},{"v":11,"t":"for sin, finding occasion through the commandment, deceived me, and through it killed me."},{"v":12,"t":"Therefore the law indeed is holy, and the commandment holy, righteous, and good."},{"v":13,"t":"Did then that which is good become death to me? May it never be! But sin, that it might be shown to be sin, was producing death in me through that which is good; that through the commandment sin might become exceedingly sinful."},{"v":14,"t":"For we know that the law is spiritual, but I am fleshly, sold under sin."},{"v":15,"t":"For I don’t understand what I am doing. For I don’t practice what I desire to do; but what I hate, that I do."},{"v":16,"t":"But if what I don’t desire, that I do, I consent to the law that it is good."},{"v":17,"t":"So now it is no more I that do it, but sin which dwells in me."},{"v":18,"t":"For I know that in me, that is, in my flesh, dwells no good thing. For desire is present with me, but I don’t find it doing that which is good."},{"v":19,"t":"For the good which I desire, I don’t do; but the evil which I don’t desire, that I practice."},{"v":20,"t":"But if what I don’t desire, that I do, it is no more I that do it, but sin which dwells in me."},{"v":21,"t":"I find then the law that, while I desire to do good, evil is present."},{"v":22,"t":"For I delight in God’s law after the inward person,"},{"v":23,"t":"but I see a different law in my members, warring against the law of my mind, and bringing me into captivity under the law of sin which is in my members."},{"v":24,"t":"What a wretched man I am! Who will deliver me out of the body of this death?"},{"v":25,"t":"I thank God through Jesus Christ, our Lord! So then with the mind, I myself serve God’s law, but with the flesh, sin’s law."}]},"8":{"en":[{"v":1,"t":"There is therefore now no condemnation to those who are in Christ Jesus, who don’t walk according to the flesh, but according to the Spirit."},{"v":2,"t":"For the law of the Spirit of life in Christ Jesus made me free from the law of sin and of death."},{"v":3,"t":"For what the law couldn’t do, in that it was weak through the flesh, God did, sending his own Son in the likeness of sinful flesh and for sin, he condemned sin in the flesh,"},{"v":4,"t":"that the ordinance of the law might be fulfilled in us who don’t walk according to the flesh, but according to the Spirit."},{"v":5,"t":"For those who live according to the flesh set their minds on the things of the flesh, but those who live according to the Spirit, the things of the Spirit."},{"v":6,"t":"For the mind of the flesh is death, but the mind of the Spirit is life and peace;"},{"v":7,"t":"because the mind of the flesh is hostile toward God, for it is not subject to God’s law, neither indeed can it be."},{"v":8,"t":"Those who are in the flesh can’t please God."},{"v":9,"t":"But you are not in the flesh but in the Spirit, if it is so that the Spirit of God dwells in you. But if any man doesn’t have the Spirit of Christ, he is not his."},{"v":10,"t":"If Christ is in you, the body is dead because of sin, but the spirit is alive because of righteousness."},{"v":11,"t":"But if the Spirit of him who raised up Jesus from the dead dwells in you, he who raised up Christ Jesus from the dead will also give life to your mortal bodies through his Spirit who dwells in you."},{"v":12,"t":"So then, brothers, we are debtors, not to the flesh, to live after the flesh."},{"v":13,"t":"For if you live after the flesh, you must die; but if by the Spirit you put to death the deeds of the body, you will live."},{"v":14,"t":"For as many as are led by the Spirit of God, these are children of God."},{"v":15,"t":"For you didn’t receive the spirit of bondage again to fear, but you received the Spirit of adoption, by whom we cry, “Abba! Father!”"},{"v":16,"t":"The Spirit himself testifies with our spirit that we are children of God;"},{"v":17,"t":"and if children, then heirs—heirs of God and joint heirs with Christ, if indeed we suffer with him, that we may also be glorified with him."},{"v":18,"t":"For I consider that the sufferings of this present time are not worthy to be compared with the glory which will be revealed toward us."},{"v":19,"t":"For the creation waits with eager expectation for the children of God to be revealed."},{"v":20,"t":"For the creation was subjected to vanity, not of its own will, but because of him who subjected it, in hope"},{"v":21,"t":"that the creation itself also will be delivered from the bondage of decay into the liberty of the glory of the children of God."},{"v":22,"t":"For we know that the whole creation groans and travails in pain together until now."},{"v":23,"t":"Not only so, but ourselves also, who have the first fruits of the Spirit, even we ourselves groan within ourselves, waiting for adoption, the redemption of our body."},{"v":24,"t":"For we were saved in hope, but hope that is seen is not hope. For who hopes for that which he sees?"},{"v":25,"t":"But if we hope for that which we don’t see, we wait for it with patience."},{"v":26,"t":"In the same way, the Spirit also helps our weaknesses, for we don’t know how to pray as we ought. But the Spirit himself makes intercession for us with groanings which can’t be uttered."},{"v":27,"t":"He who searches the hearts knows what is on the Spirit’s mind, because he makes intercession for the saints according to God."},{"v":28,"t":"We know that all things work together for good for those who love God, for those who are called according to his purpose."},{"v":29,"t":"For whom he foreknew, he also predestined to be conformed to the image of his Son, that he might be the firstborn among many brothers."},{"v":30,"t":"Whom he predestined, those he also called. Whom he called, those he also justified. Whom he justified, those he also glorified."},{"v":31,"t":"What then shall we say about these things? If God is for us, who can be against us?"},{"v":32,"t":"He who didn’t spare his own Son, but delivered him up for us all, how would he not also with him freely give us all things?"},{"v":33,"t":"Who could bring a charge against God’s chosen ones? It is God who justifies."},{"v":34,"t":"Who is he who condemns? It is Christ who died, yes rather, who was raised from the dead, who is at the right hand of God, who also makes intercession for us."},{"v":35,"t":"Who shall separate us from the love of Christ? Could oppression, or anguish, or persecution, or famine, or nakedness, or peril, or sword?"},{"v":36,"t":"Even as it is written, “For your sake we are killed all day long. We were accounted as sheep for the slaughter.”"},{"v":37,"t":"No, in all these things we are more than conquerors through him who loved us."},{"v":38,"t":"For I am persuaded that neither death, nor life, nor angels, nor principalities, nor things present, nor things to come, nor powers,"},{"v":39,"t":"nor height, nor depth, nor any other created thing will be able to separate us from God’s love which is in Christ Jesus our Lord."}]},"9":{"en":[{"v":1,"t":"I tell the truth in Christ. I am not lying, my conscience testifying with me in the Holy Spirit"},{"v":2,"t":"that I have great sorrow and unceasing pain in my heart."},{"v":3,"t":"For I could wish that I myself were accursed from Christ for my brothers’ sake, my relatives according to the flesh"},{"v":4,"t":"who are Israelites; whose is the adoption, the glory, the covenants, the giving of the law, the service, and the promises;"},{"v":5,"t":"of whom are the fathers, and from whom is Christ as concerning the flesh, who is over all, God, blessed forever. Amen."},{"v":6,"t":"But it is not as though the word of God has come to nothing. For they are not all Israel that are of Israel."},{"v":7,"t":"Neither, because they are Abraham’s offspring, are they all children. But, “your offspring will be accounted as from Isaac.”"},{"v":8,"t":"That is, it is not the children of the flesh who are children of God, but the children of the promise are counted as heirs."},{"v":9,"t":"For this is a word of promise: “At the appointed time I will come, and Sarah will have a son.”"},{"v":10,"t":"Not only so, but Rebekah also conceived by one, by our father Isaac."},{"v":11,"t":"For being not yet born, neither having done anything good or bad, that the purpose of God according to election might stand, not of works, but of him who calls,"},{"v":12,"t":"it was said to her, “The elder will serve the younger.”"},{"v":13,"t":"Even as it is written, “Jacob I loved, but Esau I hated.”"},{"v":14,"t":"What shall we say then? Is there unrighteousness with God? May it never be!"},{"v":15,"t":"For he said to Moses, “I will have mercy on whom I have mercy, and I will have compassion on whom I have compassion.”"},{"v":16,"t":"So then it is not of him who wills, nor of him who runs, but of God who has mercy."},{"v":17,"t":"For the Scripture says to Pharaoh, “For this very purpose I caused you to be raised up, that I might show in you my power, and that my name might be proclaimed in all the earth.”"},{"v":18,"t":"So then, he has mercy on whom he desires, and he hardens whom he desires."},{"v":19,"t":"You will say then to me, “Why does he still find fault? For who withstands his will?”"},{"v":20,"t":"But indeed, O man, who are you to reply against God? Will the thing formed ask him who formed it, “Why did you make me like this?”"},{"v":21,"t":"Or hasn’t the potter a right over the clay, from the same lump to make one part a vessel for honor, and another for dishonor?"},{"v":22,"t":"What if God, willing to show his wrath and to make his power known, endured with much patience vessels of wrath prepared for destruction,"},{"v":23,"t":"and that he might make known the riches of his glory on vessels of mercy, which he prepared beforehand for glory—"},{"v":24,"t":"us, whom he also called, not from the Jews only, but also from the Gentiles?"},{"v":25,"t":"As he says also in Hosea, “I will call them ‘my people,’ which were not my people; and her ‘beloved,’ who was not beloved.”"},{"v":26,"t":"“It will be that in the place where it was said to them, ‘You are not my people,’ there they will be called ‘children of the living God.’”"},{"v":27,"t":"Isaiah cries concerning Israel, “If the number of the children of Israel are as the sand of the sea, it is the remnant who will be saved;"},{"v":28,"t":"for he will finish the work and cut it short in righteousness, because the Lord will make a short work upon the earth.”"},{"v":29,"t":"As Isaiah has said before, “Unless the Lord of Armies had left us a seed, we would have become like Sodom, and would have been made like Gomorrah.”"},{"v":30,"t":"What shall we say then? That the Gentiles, who didn’t follow after righteousness, attained to righteousness, even the righteousness which is of faith;"},{"v":31,"t":"but Israel, following after a law of righteousness, didn’t arrive at the law of righteousness."},{"v":32,"t":"Why? Because they didn’t seek it by faith, but as it were by works of the law. They stumbled over the stumbling stone,"},{"v":33,"t":"even as it is written, “Behold, I lay in Zion a stumbling stone and a rock of offense; and no one who believes in him will be disappointed.”"}]},"10":{"en":[{"v":1,"t":"Brothers, my heart’s desire and my prayer to God is for Israel, that they may be saved."},{"v":2,"t":"For I testify about them that they have a zeal for God, but not according to knowledge."},{"v":3,"t":"For being ignorant of God’s righteousness, and seeking to establish their own righteousness, they didn’t subject themselves to the righteousness of God."},{"v":4,"t":"For Christ is the fulfillment of the law for righteousness to everyone who believes."},{"v":5,"t":"For Moses writes about the righteousness of the law, “The one who does them will live by them.”"},{"v":6,"t":"But the righteousness which is of faith says this, “Don’t say in your heart, ‘Who will ascend into heaven?’ (that is, to bring Christ down);"},{"v":7,"t":"or, ‘Who will descend into the abyss?’ (that is, to bring Christ up from the dead.)”"},{"v":8,"t":"But what does it say? “The word is near you, in your mouth and in your heart;” that is, the word of faith which we preach:"},{"v":9,"t":"that if you will confess with your mouth that Jesus is Lord and believe in your heart that God raised him from the dead, you will be saved."},{"v":10,"t":"For with the heart one believes resulting in righteousness; and with the mouth confession is made resulting in salvation."},{"v":11,"t":"For the Scripture says, “Whoever believes in him will not be disappointed.”"},{"v":12,"t":"For there is no distinction between Jew and Greek; for the same Lord is Lord of all, and is rich to all who call on him."},{"v":13,"t":"For, “Whoever will call on the name of the Lord will be saved.”"},{"v":14,"t":"How then will they call on him in whom they have not believed? How will they believe in him whom they have not heard? How will they hear without a preacher?"},{"v":15,"t":"And how will they preach unless they are sent? As it is written: “How beautiful are the feet of those who preach the Good News of peace, who bring glad tidings of good things!”"},{"v":16,"t":"But they didn’t all listen to the glad news. For Isaiah says, “Lord, who has believed our report?”"},{"v":17,"t":"So faith comes by hearing, and hearing by the word of God."},{"v":18,"t":"But I say, didn’t they hear? Yes, most certainly, “Their sound went out into all the earth, their words to the ends of the world.”"},{"v":19,"t":"But I ask, didn’t Israel know? First Moses says, “I will provoke you to jealousy with that which is no nation. I will make you angry with a nation void of understanding.”"},{"v":20,"t":"Isaiah is very bold and says, “I was found by those who didn’t seek me. I was revealed to those who didn’t ask for me.”"},{"v":21,"t":"But about Israel he says, “All day long I stretched out my hands to a disobedient and contrary people.”"}]},"11":{"en":[{"v":1,"t":"I ask then, did God reject his people? May it never be! For I also am an Israelite, a descendant of Abraham, of the tribe of Benjamin."},{"v":2,"t":"God didn’t reject his people, whom he foreknew. Or don’t you know what the Scripture says about Elijah? How he pleads with God against Israel:"},{"v":3,"t":"“Lord, they have killed your prophets. They have broken down your altars. I am left alone, and they seek my life.”"},{"v":4,"t":"But how does God answer him? “I have reserved for myself seven thousand men who have not bowed the knee to Baal.”"},{"v":5,"t":"Even so too at this present time also there is a remnant according to the election of grace."},{"v":6,"t":"And if by grace, then it is no longer of works; otherwise grace is no longer grace. But if it is of works, it is no longer grace; otherwise work is no longer work."},{"v":7,"t":"What then? That which Israel seeks for, that he didn’t obtain, but the chosen ones obtained it, and the rest were hardened."},{"v":8,"t":"According as it is written, “God gave them a spirit of stupor, eyes that they should not see, and ears that they should not hear, to this very day.”"},{"v":9,"t":"David says, “Let their table be made a snare, a trap, a stumbling block, and a retribution to them."},{"v":10,"t":"Let their eyes be darkened, that they may not see. Always keep their backs bent.”"},{"v":11,"t":"I ask then, did they stumble that they might fall? May it never be! But by their fall salvation has come to the Gentiles, to provoke them to jealousy."},{"v":12,"t":"Now if their fall is the riches of the world, and their loss the riches of the Gentiles, how much more their fullness!"},{"v":13,"t":"For I speak to you who are Gentiles. Since then as I am an apostle to Gentiles, I glorify my ministry,"},{"v":14,"t":"if by any means I may provoke to jealousy those who are my flesh, and may save some of them."},{"v":15,"t":"For if the rejection of them is the reconciling of the world, what would their acceptance be, but life from the dead?"},{"v":16,"t":"If the first fruit is holy, so is the lump. If the root is holy, so are the branches."},{"v":17,"t":"But if some of the branches were broken off, and you, being a wild olive, were grafted in among them and became partaker with them of the root and of the richness of the olive tree,"},{"v":18,"t":"don’t boast over the branches. But if you boast, remember that it is not you who support the root, but the root supports you."},{"v":19,"t":"You will say then, “Branches were broken off, that I might be grafted in.”"},{"v":20,"t":"True; by their unbelief they were broken off, and you stand by your faith. Don’t be conceited, but fear;"},{"v":21,"t":"for if God didn’t spare the natural branches, neither will he spare you."},{"v":22,"t":"See then the goodness and severity of God. Toward those who fell, severity; but toward you, goodness, if you continue in his goodness; otherwise you also will be cut off."},{"v":23,"t":"They also, if they don’t continue in their unbelief, will be grafted in, for God is able to graft them in again."},{"v":24,"t":"For if you were cut out of that which is by nature a wild olive tree, and were grafted contrary to nature into a good olive tree, how much more will these, which are the natural branches, be grafted into their own olive tree?"},{"v":25,"t":"For I don’t desire you to be ignorant, brothers, of this mystery, so that you won’t be wise in your own conceits, that a partial hardening has happened to Israel, until the fullness of the Gentiles has come in,"},{"v":26,"t":"and so all Israel will be saved. Even as it is written, “There will come out of Zion the Deliverer, and he will turn away ungodliness from Jacob."},{"v":27,"t":"This is my covenant with them, when I will take away their sins.”"},{"v":28,"t":"Concerning the Good News, they are enemies for your sake. But concerning the election, they are beloved for the fathers’ sake."},{"v":29,"t":"For the gifts and the calling of God are irrevocable."},{"v":30,"t":"For as you in time past were disobedient to God, but now have obtained mercy by their disobedience,"},{"v":31,"t":"even so these also have now been disobedient, that by the mercy shown to you they may also obtain mercy."},{"v":32,"t":"For God has bound all to disobedience, that he might have mercy on all."},{"v":33,"t":"Oh the depth of the riches both of the wisdom and the knowledge of God! How unsearchable are his judgments, and his ways past tracing out!"},{"v":34,"t":"“For who has known the mind of the Lord? Or who has been his counselor?”"},{"v":35,"t":"“Or who has first given to him, and it will be repaid to him again?”"},{"v":36,"t":"For of him and through him and to him are all things. To him be the glory for ever! Amen."}]},"12":{"en":[{"v":1,"t":"Therefore I urge you, brothers, by the mercies of God, to present your bodies a living sacrifice, holy, acceptable to God, which is your spiritual service."},{"v":2,"t":"Don’t be conformed to this world, but be transformed by the renewing of your mind, so that you may prove what is the good, well-pleasing, and perfect will of God."},{"v":3,"t":"For I say through the grace that was given me, to everyone who is among you, not to think of yourself more highly than you ought to think; but to think reasonably, as God has apportioned to each person a measure of faith."},{"v":4,"t":"For even as we have many members in one body, and all the members don’t have the same function,"},{"v":5,"t":"so we, who are many, are one body in Christ, and individually members of one another,"},{"v":6,"t":"having gifts differing according to the grace that was given to us: if prophecy, let’s prophesy according to the proportion of our faith;"},{"v":7,"t":"or service, let’s give ourselves to service; or he who teaches, to his teaching;"},{"v":8,"t":"or he who exhorts, to his exhorting; he who gives, let him do it with generosity; he who rules, with diligence; he who shows mercy, with cheerfulness."},{"v":9,"t":"Let love be without hypocrisy. Abhor that which is evil. Cling to that which is good."},{"v":10,"t":"In love of the brothers be tenderly affectionate to one another; in honor prefer one another,"},{"v":11,"t":"not lagging in diligence, fervent in spirit, serving the Lord,"},{"v":12,"t":"rejoicing in hope, enduring in troubles, continuing steadfastly in prayer,"},{"v":13,"t":"contributing to the needs of the saints, and given to hospitality."},{"v":14,"t":"Bless those who persecute you; bless, and don’t curse."},{"v":15,"t":"Rejoice with those who rejoice. Weep with those who weep."},{"v":16,"t":"Be of the same mind one toward another. Don’t set your mind on high things, but associate with the humble. Don’t be wise in your own conceits."},{"v":17,"t":"Repay no one evil for evil. Respect what is honorable in the sight of all men."},{"v":18,"t":"If it is possible, as much as it is up to you, be at peace with all men."},{"v":19,"t":"Don’t seek revenge yourselves, beloved, but give place to God’s wrath. For it is written, “Vengeance belongs to me; I will repay, says the Lord.”"},{"v":20,"t":"Therefore “If your enemy is hungry, feed him. If he is thirsty, give him a drink; for in doing so, you will heap coals of fire on his head.”"},{"v":21,"t":"Don’t be overcome by evil, but overcome evil with good."}]},"13":{"en":[{"v":1,"t":"Let every soul be in subjection to the higher authorities, for there is no authority except from God, and those who exist are ordained by God."},{"v":2,"t":"Therefore he who resists the authority withstands the ordinance of God; and those who withstand will receive to themselves judgment."},{"v":3,"t":"For rulers are not a terror to the good work, but to the evil. Do you desire to have no fear of the authority? Do that which is good, and you will have praise from the authority,"},{"v":4,"t":"for he is a servant of God to you for good. But if you do that which is evil, be afraid, for he doesn’t bear the sword in vain; for he is a servant of God, an avenger for wrath to him who does evil."},{"v":5,"t":"Therefore you need to be in subjection, not only because of the wrath, but also for conscience’ sake."},{"v":6,"t":"For this reason you also pay taxes, for they are servants of God’s service, continually doing this very thing."},{"v":7,"t":"Therefore give everyone what you owe: if you owe taxes, pay taxes; if customs, then customs; if respect, then respect; if honor, then honor."},{"v":8,"t":"Owe no one anything, except to love one another; for he who loves his neighbor has fulfilled the law."},{"v":9,"t":"For the commandments, “You shall not commit adultery,” “You shall not murder,” “You shall not steal,” “You shall not covet,” and whatever other commandments there are, are all summed up in this saying, namely, “You shall love your neighbor as yourself.”"},{"v":10,"t":"Love doesn’t harm a neighbor. Love therefore is the fulfillment of the law."},{"v":11,"t":"Do this, knowing the time, that it is already time for you to awaken out of sleep, for salvation is now nearer to us than when we first believed."},{"v":12,"t":"The night is far gone, and the day is near. Let’s therefore throw off the deeds of darkness, and let’s put on the armor of light."},{"v":13,"t":"Let’s walk properly, as in the day; not in reveling and drunkenness, not in sexual promiscuity and lustful acts, and not in strife and jealousy."},{"v":14,"t":"But put on the Lord Jesus Christ, and make no provision for the flesh, for its lusts."}]},"14":{"en":[{"v":1,"t":"Now accept one who is weak in faith, but not for disputes over opinions."},{"v":2,"t":"One man has faith to eat all things, but he who is weak eats only vegetables."},{"v":3,"t":"Don’t let him who eats despise him who doesn’t eat. Don’t let him who doesn’t eat judge him who eats, for God has accepted him."},{"v":4,"t":"Who are you who judge another’s servant? To his own lord he stands or falls. Yes, he will be made to stand, for God has power to make him stand."},{"v":5,"t":"One man esteems one day as more important. Another esteems every day alike. Let each man be fully assured in his own mind."},{"v":6,"t":"He who observes the day, observes it to the Lord; and he who does not observe the day, to the Lord he does not observe it. He who eats, eats to the Lord, for he gives God thanks. He who doesn’t eat, to the Lord he doesn’t eat, and gives God thanks."},{"v":7,"t":"For none of us lives to himself, and none dies to himself."},{"v":8,"t":"For if we live, we live to the Lord. Or if we die, we die to the Lord. If therefore we live or die, we are the Lord’s."},{"v":9,"t":"For to this end Christ died, rose, and lived again, that he might be Lord of both the dead and the living."},{"v":10,"t":"But you, why do you judge your brother? Or you again, why do you despise your brother? For we will all stand before the judgment seat of Christ."},{"v":11,"t":"For it is written, “‘As I live,’ says the Lord, ‘to me every knee will bow. Every tongue will confess to God.’”"},{"v":12,"t":"So then each one of us will give account of himself to God."},{"v":13,"t":"Therefore let’s not judge one another any more, but judge this rather, that no man put a stumbling block in his brother’s way, or an occasion for falling."},{"v":14,"t":"I know and am persuaded in the Lord Jesus that nothing is unclean of itself; except that to him who considers anything to be unclean, to him it is unclean."},{"v":15,"t":"Yet if because of food your brother is grieved, you walk no longer in love. Don’t destroy with your food him for whom Christ died."},{"v":16,"t":"Then don’t let your good be slandered,"},{"v":17,"t":"for God’s Kingdom is not eating and drinking, but righteousness, peace, and joy in the Holy Spirit."},{"v":18,"t":"For he who serves Christ in these things is acceptable to God and approved by men."},{"v":19,"t":"So then, let’s follow after things which make for peace, and things by which we may build one another up."},{"v":20,"t":"Don’t overthrow God’s work for food’s sake. All things indeed are clean, however it is evil for that man who creates a stumbling block by eating."},{"v":21,"t":"It is good to not eat meat, drink wine, nor do anything by which your brother stumbles, is offended, or is made weak."},{"v":22,"t":"Do you have faith? Have it to yourself before God. Happy is he who doesn’t judge himself in that which he approves."},{"v":23,"t":"But he who doubts is condemned if he eats, because it isn’t of faith; and whatever is not of faith is sin."}]},"15":{"en":[{"v":1,"t":"Now we who are strong ought to bear the weaknesses of the weak, and not to please ourselves."},{"v":2,"t":"Let each one of us please his neighbor for that which is good, to be building him up."},{"v":3,"t":"For even Christ didn’t please himself. But, as it is written, “The reproaches of those who reproached you fell on me.”"},{"v":4,"t":"For whatever things were written before were written for our learning, that through perseverance and through encouragement of the Scriptures we might have hope."},{"v":5,"t":"Now the God of perseverance and of encouragement grant you to be of the same mind with one another according to Christ Jesus,"},{"v":6,"t":"that with one accord you may with one mouth glorify the God and Father of our Lord Jesus Christ."},{"v":7,"t":"Therefore accept one another, even as Christ also accepted you, to the glory of God."},{"v":8,"t":"Now I say that Christ has been made a servant of the circumcision for the truth of God, that he might confirm the promises given to the fathers,"},{"v":9,"t":"and that the Gentiles might glorify God for his mercy. As it is written, “Therefore I will give praise to you among the Gentiles and sing to your name.”"},{"v":10,"t":"Again he says, “Rejoice, you Gentiles, with his people.”"},{"v":11,"t":"Again, “Praise the Lord, all you Gentiles! Let all the peoples praise him.”"},{"v":12,"t":"Again, Isaiah says, “There will be the root of Jesse, he who arises to rule over the Gentiles; in him the Gentiles will hope.”"},{"v":13,"t":"Now may the God of hope fill you with all joy and peace in believing, that you may abound in hope in the power of the Holy Spirit."},{"v":14,"t":"I myself am also persuaded about you, my brothers, that you yourselves are full of goodness, filled with all knowledge, able also to admonish others."},{"v":15,"t":"But I write the more boldly to you in part as reminding you, because of the grace that was given to me by God,"},{"v":16,"t":"that I should be a servant of Christ Jesus to the Gentiles, serving as a priest of the Good News of God, that the offering up of the Gentiles might be made acceptable, sanctified by the Holy Spirit."},{"v":17,"t":"I have therefore my boasting in Christ Jesus in things pertaining to God."},{"v":18,"t":"For I will not dare to speak of any things except those which Christ worked through me for the obedience of the Gentiles, by word and deed,"},{"v":19,"t":"in the power of signs and wonders, in the power of God’s Spirit; so that from Jerusalem and around as far as to Illyricum, I have fully preached the Good News of Christ;"},{"v":20,"t":"yes, making it my aim to preach the Good News, not where Christ was already named, that I might not build on another’s foundation."},{"v":21,"t":"But, as it is written, “They will see, to whom no news of him came. They who haven’t heard will understand.”"},{"v":22,"t":"Therefore also I was hindered these many times from coming to you,"},{"v":23,"t":"but now, no longer having any place in these regions, and having these many years a longing to come to you,"},{"v":24,"t":"whenever I travel to Spain, I will come to you. For I hope to see you on my journey, and to be helped on my way there by you, if first I may enjoy your company for a while."},{"v":25,"t":"But now, I say, I am going to Jerusalem, serving the saints."},{"v":26,"t":"For it has been the good pleasure of Macedonia and Achaia to make a certain contribution for the poor among the saints who are at Jerusalem."},{"v":27,"t":"Yes, it has been their good pleasure, and they are their debtors. For if the Gentiles have been made partakers of their spiritual things, they owe it to them also to serve them in material things."},{"v":28,"t":"When therefore I have accomplished this, and have sealed to them this fruit, I will go on by way of you to Spain."},{"v":29,"t":"I know that when I come to you, I will come in the fullness of the blessing of the Good News of Christ."},{"v":30,"t":"Now I beg you, brothers, by our Lord Jesus Christ and by the love of the Spirit, that you strive together with me in your prayers to God for me,"},{"v":31,"t":"that I may be delivered from those who are disobedient in Judea, and that my service which I have for Jerusalem may be acceptable to the saints,"},{"v":32,"t":"that I may come to you in joy through the will of God, and together with you, find rest."},{"v":33,"t":"Now the God of peace be with you all. Amen."}]},"16":{"en":[{"v":1,"t":"I commend to you Phoebe, our sister, who is a servant of the assembly that is at Cenchreae,"},{"v":2,"t":"that you receive her in the Lord in a way worthy of the saints, and that you assist her in whatever matter she may need from you, for she herself also has been a helper of many, and of my own self."},{"v":3,"t":"Greet Prisca and Aquila, my fellow workers in Christ Jesus,"},{"v":4,"t":"who risked their own necks for my life, to whom not only I give thanks, but also all the assemblies of the Gentiles."},{"v":5,"t":"Greet the assembly that is in their house. Greet Epaenetus, my beloved, who is the first fruits of Achaia to Christ."},{"v":6,"t":"Greet Mary, who labored much for us."},{"v":7,"t":"Greet Andronicus and Junia, my relatives and my fellow prisoners, who are notable among the apostles, who were also in Christ before me."},{"v":8,"t":"Greet Amplias, my beloved in the Lord."},{"v":9,"t":"Greet Urbanus, our fellow worker in Christ, and Stachys, my beloved."},{"v":10,"t":"Greet Apelles, the approved in Christ. Greet those who are of the household of Aristobulus."},{"v":11,"t":"Greet Herodion, my kinsman. Greet them of the household of Narcissus, who are in the Lord."},{"v":12,"t":"Greet Tryphaena and Tryphosa, who labor in the Lord. Greet Persis, the beloved, who labored much in the Lord."},{"v":13,"t":"Greet Rufus, the chosen in the Lord, and his mother and mine."},{"v":14,"t":"Greet Asyncritus, Phlegon, Hermes, Patrobas, Hermas, and the brothers who are with them."},{"v":15,"t":"Greet Philologus and Julia, Nereus and his sister, and Olympas, and all the saints who are with them."},{"v":16,"t":"Greet one another with a holy kiss. The assemblies of Christ greet you."},{"v":17,"t":"Now I beg you, brothers, look out for those who are causing the divisions and occasions of stumbling, contrary to the doctrine which you learned, and turn away from them."},{"v":18,"t":"For those who are such don’t serve our Lord Jesus Christ, but their own belly; and by their smooth and flattering speech they deceive the hearts of the innocent."},{"v":19,"t":"For your obedience has become known to all. I rejoice therefore over you. But I desire to have you wise in that which is good, but innocent in that which is evil."},{"v":20,"t":"And the God of peace will quickly crush Satan under your feet. The grace of our Lord Jesus Christ be with you."},{"v":21,"t":"Timothy, my fellow worker, greets you, as do Lucius, Jason, and Sosipater, my relatives."},{"v":22,"t":"I, Tertius, who write the letter, greet you in the Lord."},{"v":23,"t":"Gaius, my host and host of the whole assembly, greets you. Erastus, the treasurer of the city, greets you, as does Quartus, the brother."},{"v":24,"t":"The grace of our Lord Jesus Christ be with you all! Amen."}]}},"1CO":{"1":{"en":[{"v":1,"t":"Paul, called to be an apostle of Jesus Christ through the will of God, and our brother Sosthenes,"},{"v":2,"t":"to the assembly of God which is at Corinth—those who are sanctified in Christ Jesus, called saints, with all who call on the name of our Lord Jesus Christ in every place, both theirs and ours:"},{"v":3,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":4,"t":"I always thank my God concerning you for the grace of God which was given you in Christ Jesus,"},{"v":5,"t":"that in everything you were enriched in him, in all speech and all knowledge—"},{"v":6,"t":"even as the testimony of Christ was confirmed in you—"},{"v":7,"t":"so that you come behind in no gift, waiting for the revelation of our Lord Jesus Christ,"},{"v":8,"t":"who will also confirm you until the end, blameless in the day of our Lord Jesus Christ."},{"v":9,"t":"God is faithful, through whom you were called into the fellowship of his Son, Jesus Christ our Lord."},{"v":10,"t":"Now I beg you, brothers, through the name of our Lord, Jesus Christ, that you all speak the same thing, and that there be no divisions among you, but that you be perfected together in the same mind and in the same judgment."},{"v":11,"t":"For it has been reported to me concerning you, my brothers, by those who are from Chloe’s household, that there are contentions among you."},{"v":12,"t":"Now I mean this, that each one of you says, “I follow Paul,” “I follow Apollos,” “I follow Cephas,” and, “I follow Christ.”"},{"v":13,"t":"Is Christ divided? Was Paul crucified for you? Or were you baptized into the name of Paul?"},{"v":14,"t":"I thank God that I baptized none of you except Crispus and Gaius,"},{"v":15,"t":"so that no one should say that I had baptized you into my own name."},{"v":16,"t":"(I also baptized the household of Stephanas; besides them, I don’t know whether I baptized any other.)"},{"v":17,"t":"For Christ sent me not to baptize, but to preach the Good News—not in wisdom of words, so that the cross of Christ wouldn’t be made void."},{"v":18,"t":"For the word of the cross is foolishness to those who are dying, but to us who are being saved it is the power of God."},{"v":19,"t":"For it is written, “I will destroy the wisdom of the wise. I will bring the discernment of the discerning to nothing.”"},{"v":20,"t":"Where is the wise? Where is the scribe? Where is the debater of this age? Hasn’t God made foolish the wisdom of this world?"},{"v":21,"t":"For seeing that in the wisdom of God, the world through its wisdom didn’t know God, it was God’s good pleasure through the foolishness of the preaching to save those who believe."},{"v":22,"t":"For Jews ask for signs, Greeks seek after wisdom,"},{"v":23,"t":"but we preach Christ crucified, a stumbling block to Jews and foolishness to Greeks,"},{"v":24,"t":"but to those who are called, both Jews and Greeks, Christ is the power of God and the wisdom of God;"},{"v":25,"t":"because the foolishness of God is wiser than men, and the weakness of God is stronger than men."},{"v":26,"t":"For you see your calling, brothers, that not many are wise according to the flesh, not many mighty, and not many noble;"},{"v":27,"t":"but God chose the foolish things of the world that he might put to shame those who are wise. God chose the weak things of the world that he might put to shame the things that are strong."},{"v":28,"t":"God chose the lowly things of the world, and the things that are despised, and the things that don’t exist, that he might bring to nothing the things that exist,"},{"v":29,"t":"that no flesh should boast before God."},{"v":30,"t":"Because of him, you are in Christ Jesus, who was made to us wisdom from God, and righteousness and sanctification, and redemption,"},{"v":31,"t":"that, as it is written, “He who boasts, let him boast in the Lord.”"}]},"2":{"en":[{"v":1,"t":"When I came to you, brothers, I didn’t come with excellence of speech or of wisdom, proclaiming to you the testimony of God."},{"v":2,"t":"For I determined not to know anything among you except Jesus Christ and him crucified."},{"v":3,"t":"I was with you in weakness, in fear, and in much trembling."},{"v":4,"t":"My speech and my preaching were not in persuasive words of human wisdom, but in demonstration of the Spirit and of power,"},{"v":5,"t":"that your faith wouldn’t stand in the wisdom of men, but in the power of God."},{"v":6,"t":"We speak wisdom, however, among those who are full grown, yet a wisdom not of this world nor of the rulers of this world who are coming to nothing."},{"v":7,"t":"But we speak God’s wisdom in a mystery, the wisdom that has been hidden, which God foreordained before the worlds for our glory,"},{"v":8,"t":"which none of the rulers of this world has known. For had they known it, they wouldn’t have crucified the Lord of glory."},{"v":9,"t":"But as it is written, “Things which an eye didn’t see, and an ear didn’t hear, which didn’t enter into the heart of man, these God has prepared for those who love him.”"},{"v":10,"t":"But to us, God revealed them through the Spirit. For the Spirit searches all things, yes, the deep things of God."},{"v":11,"t":"For who among men knows the things of a man except the spirit of the man which is in him? Even so, no one knows the things of God except God’s Spirit."},{"v":12,"t":"But we received not the spirit of the world, but the Spirit which is from God, that we might know the things that were freely given to us by God."},{"v":13,"t":"We also speak these things, not in words which man’s wisdom teaches but which the Holy Spirit teaches, comparing spiritual things with spiritual things."},{"v":14,"t":"Now the natural man doesn’t receive the things of God’s Spirit, for they are foolishness to him; and he can’t know them, because they are spiritually discerned."},{"v":15,"t":"But he who is spiritual discerns all things, and he himself is to be judged by no one."},{"v":16,"t":"“For who has known the mind of the Lord that he should instruct him?” But we have Christ’s mind."}]},"3":{"en":[{"v":1,"t":"Brothers, I couldn’t speak to you as to spiritual, but as to fleshly, as to babies in Christ."},{"v":2,"t":"I fed you with milk, not with solid food, for you weren’t yet ready. Indeed, you aren’t ready even now,"},{"v":3,"t":"for you are still fleshly. For insofar as there is jealousy, strife, and factions among you, aren’t you fleshly, and don’t you walk in the ways of men?"},{"v":4,"t":"For when one says, “I follow Paul,” and another, “I follow Apollos,” aren’t you fleshly?"},{"v":5,"t":"Who then is Apollos, and who is Paul, but servants through whom you believed, and each as the Lord gave to him?"},{"v":6,"t":"I planted. Apollos watered. But God gave the increase."},{"v":7,"t":"So then neither he who plants is anything, nor he who waters, but God who gives the increase."},{"v":8,"t":"Now he who plants and he who waters are the same, but each will receive his own reward according to his own labor."},{"v":9,"t":"For we are God’s fellow workers. You are God’s farming, God’s building."},{"v":10,"t":"According to the grace of God which was given to me, as a wise master builder I laid a foundation, and another builds on it. But let each man be careful how he builds on it."},{"v":11,"t":"For no one can lay any other foundation than that which has been laid, which is Jesus Christ."},{"v":12,"t":"But if anyone builds on the foundation with gold, silver, costly stones, wood, hay, or straw,"},{"v":13,"t":"each man’s work will be revealed. For the Day will declare it, because it is revealed in fire; and the fire itself will test what sort of work each man’s work is."},{"v":14,"t":"If any man’s work remains which he built on it, he will receive a reward."},{"v":15,"t":"If any man’s work is burned, he will suffer loss, but he himself will be saved, but as through fire."},{"v":16,"t":"Don’t you know that you are God’s temple and that God’s Spirit lives in you?"},{"v":17,"t":"If anyone destroys God’s temple, God will destroy him; for God’s temple is holy, which you are."},{"v":18,"t":"Let no one deceive himself. If anyone thinks that he is wise among you in this world, let him become a fool that he may become wise."},{"v":19,"t":"For the wisdom of this world is foolishness with God. For it is written, “He has taken the wise in their craftiness.”"},{"v":20,"t":"And again, “The Lord knows the reasoning of the wise, that it is worthless.”"},{"v":21,"t":"Therefore let no one boast in men. For all things are yours,"},{"v":22,"t":"whether Paul, or Apollos, or Cephas, or the world, or life, or death, or things present, or things to come. All are yours,"},{"v":23,"t":"and you are Christ’s, and Christ is God’s."}]},"4":{"en":[{"v":1,"t":"So let a man think of us as Christ’s servants and stewards of God’s mysteries."},{"v":2,"t":"Here, moreover, it is required of stewards that they be found faithful."},{"v":3,"t":"But with me it is a very small thing that I should be judged by you, or by a human court. Yes, I don’t even judge my own self."},{"v":4,"t":"For I know nothing against myself. Yet I am not justified by this, but he who judges me is the Lord."},{"v":5,"t":"Therefore judge nothing before the time, until the Lord comes, who will both bring to light the hidden things of darkness and reveal the counsels of the hearts. Then each man will get his praise from God."},{"v":6,"t":"Now these things, brothers, I have in a figure transferred to myself and Apollos for your sakes, that in us you might learn not to think beyond the things which are written, that none of you be puffed up against one another."},{"v":7,"t":"For who makes you different? And what do you have that you didn’t receive? But if you did receive it, why do you boast as if you had not received it?"},{"v":8,"t":"You are already filled. You have already become rich. You have come to reign without us. Yes, and I wish that you did reign, that we also might reign with you!"},{"v":9,"t":"For I think that God has displayed us, the apostles, last of all, like men sentenced to death. For we are made a spectacle to the world, both to angels and men."},{"v":10,"t":"We are fools for Christ’s sake, but you are wise in Christ. We are weak, but you are strong. You have honor, but we have dishonor."},{"v":11,"t":"Even to this present hour we hunger, thirst, are naked, are beaten, and have no certain dwelling place."},{"v":12,"t":"We toil, working with our own hands. When people curse us, we bless. Being persecuted, we endure."},{"v":13,"t":"Being defamed, we entreat. We are made as the filth of the world, the dirt wiped off by all, even until now."},{"v":14,"t":"I don’t write these things to shame you, but to admonish you as my beloved children."},{"v":15,"t":"For though you have ten thousand tutors in Christ, you don’t have many fathers. For in Christ Jesus, I became your father through the Good News."},{"v":16,"t":"I beg you therefore, be imitators of me."},{"v":17,"t":"Because of this I have sent Timothy to you, who is my beloved and faithful child in the Lord, who will remind you of my ways which are in Christ, even as I teach everywhere in every assembly."},{"v":18,"t":"Now some are puffed up, as though I were not coming to you."},{"v":19,"t":"But I will come to you shortly, if the Lord is willing. And I will know, not the word of those who are puffed up, but the power."},{"v":20,"t":"For God’s Kingdom is not in word, but in power."},{"v":21,"t":"What do you want? Shall I come to you with a rod, or in love and a spirit of gentleness?"}]},"5":{"en":[{"v":1,"t":"It is actually reported that there is sexual immorality among you, and such sexual immorality as is not even named among the Gentiles, that one has his father’s wife."},{"v":2,"t":"You are arrogant, and didn’t mourn instead, that he who had done this deed might be removed from among you."},{"v":3,"t":"For I most certainly, as being absent in body but present in spirit, have already, as though I were present, judged him who has done this thing."},{"v":4,"t":"In the name of our Lord Jesus Christ, when you are gathered together with my spirit with the power of our Lord Jesus Christ,"},{"v":5,"t":"you are to deliver such a one to Satan for the destruction of the flesh, that the spirit may be saved in the day of the Lord Jesus."},{"v":6,"t":"Your boasting is not good. Don’t you know that a little yeast leavens the whole lump?"},{"v":7,"t":"Purge out the old yeast, that you may be a new lump, even as you are unleavened. For indeed Christ, our Passover, has been sacrificed in our place."},{"v":8,"t":"Therefore let’s keep the feast, not with old yeast, neither with the yeast of malice and wickedness, but with the unleavened bread of sincerity and truth."},{"v":9,"t":"I wrote to you in my letter to have no company with sexual sinners;"},{"v":10,"t":"yet not at all meaning with the sexual sinners of this world, or with the covetous and extortionists, or with idolaters, for then you would have to leave the world."},{"v":11,"t":"But as it is, I wrote to you not to associate with anyone who is called a brother who is a sexual sinner, or covetous, or an idolater, or a slanderer, or a drunkard, or an extortionist. Don’t even eat with such a person."},{"v":12,"t":"For what do I have to do with also judging those who are outside? Don’t you judge those who are within?"},{"v":13,"t":"But those who are outside, God judges. “Put away the wicked man from among yourselves.”"}]},"6":{"en":[{"v":1,"t":"Dare any of you, having a matter against his neighbor, go to law before the unrighteous, and not before the saints?"},{"v":2,"t":"Don’t you know that the saints will judge the world? And if the world is judged by you, are you unworthy to judge the smallest matters?"},{"v":3,"t":"Don’t you know that we will judge angels? How much more, things that pertain to this life?"},{"v":4,"t":"If then you have to judge things pertaining to this life, do you set them to judge who are of no account in the assembly?"},{"v":5,"t":"I say this to move you to shame. Isn’t there even one wise man among you who would be able to decide between his brothers?"},{"v":6,"t":"But brother goes to law with brother, and that before unbelievers!"},{"v":7,"t":"Therefore it is already altogether a defect in you that you have lawsuits one with another. Why not rather be wronged? Why not rather be defrauded?"},{"v":8,"t":"No, but you yourselves do wrong and defraud, and that against your brothers."},{"v":9,"t":"Or don’t you know that the unrighteous will not inherit God’s Kingdom? Don’t be deceived. Neither the sexually immoral, nor idolaters, nor adulterers, nor male prostitutes, nor homosexuals,"},{"v":10,"t":"nor thieves, nor covetous, nor drunkards, nor slanderers, nor extortionists, will inherit God’s Kingdom."},{"v":11,"t":"Some of you were such, but you were washed. You were sanctified. You were justified in the name of the Lord Jesus, and in the Spirit of our God."},{"v":12,"t":"“All things are lawful for me,” but not all things are expedient. “All things are lawful for me,” but I will not be brought under the power of anything."},{"v":13,"t":"“Foods for the belly, and the belly for foods,” but God will bring to nothing both it and them. But the body is not for sexual immorality, but for the Lord, and the Lord for the body."},{"v":14,"t":"Now God raised up the Lord, and will also raise us up by his power."},{"v":15,"t":"Don’t you know that your bodies are members of Christ? Shall I then take the members of Christ and make them members of a prostitute? May it never be!"},{"v":16,"t":"Or don’t you know that he who is joined to a prostitute is one body? For, “The two”, he says, “will become one flesh.”"},{"v":17,"t":"But he who is joined to the Lord is one spirit."},{"v":18,"t":"Flee sexual immorality! “Every sin that a man does is outside the body,” but he who commits sexual immorality sins against his own body."},{"v":19,"t":"Or don’t you know that your body is a temple of the Holy Spirit who is in you, whom you have from God? You are not your own,"},{"v":20,"t":"for you were bought with a price. Therefore glorify God in your body and in your spirit, which are God’s."}]},"7":{"en":[{"v":1,"t":"Now concerning the things about which you wrote to me: it is good for a man not to touch a woman."},{"v":2,"t":"But, because of sexual immoralities, let each man have his own wife, and let each woman have her own husband."},{"v":3,"t":"Let the husband give his wife the affection owed her, and likewise also the wife her husband."},{"v":4,"t":"The wife doesn’t have authority over her own body, but the husband does. Likewise also the husband doesn’t have authority over his own body, but the wife does."},{"v":5,"t":"Don’t deprive one another, unless it is by consent for a season, that you may give yourselves to fasting and prayer, and may be together again, that Satan doesn’t tempt you because of your lack of self-control."},{"v":6,"t":"But this I say by way of concession, not of commandment."},{"v":7,"t":"Yet I wish that all men were like me. However, each man has his own gift from God, one of this kind, and another of that kind."},{"v":8,"t":"But I say to the unmarried and to widows, it is good for them if they remain even as I am."},{"v":9,"t":"But if they don’t have self-control, let them marry. For it’s better to marry than to burn with passion."},{"v":10,"t":"But to the married I command—not I, but the Lord—that the wife not leave her husband"},{"v":11,"t":"(but if she departs, let her remain unmarried, or else be reconciled to her husband), and that the husband not leave his wife."},{"v":12,"t":"But to the rest I—not the Lord—say, if any brother has an unbelieving wife, and she is content to live with him, let him not leave her."},{"v":13,"t":"The woman who has an unbelieving husband, and he is content to live with her, let her not leave her husband."},{"v":14,"t":"For the unbelieving husband is sanctified in the wife, and the unbelieving wife is sanctified in the husband. Otherwise your children would be unclean, but now they are holy."},{"v":15,"t":"Yet if the unbeliever departs, let there be separation. The brother or the sister is not under bondage in such cases, but God has called us in peace."},{"v":16,"t":"For how do you know, wife, whether you will save your husband? Or how do you know, husband, whether you will save your wife?"},{"v":17,"t":"Only, as the Lord has distributed to each man, as God has called each, so let him walk. So I command in all the assemblies."},{"v":18,"t":"Was anyone called having been circumcised? Let him not become uncircumcised. Has anyone been called in uncircumcision? Let him not be circumcised."},{"v":19,"t":"Circumcision is nothing, and uncircumcision is nothing, but what matters is keeping God’s commandments."},{"v":20,"t":"Let each man stay in that calling in which he was called."},{"v":21,"t":"Were you called being a bondservant? Don’t let that bother you, but if you get an opportunity to become free, use it."},{"v":22,"t":"For he who was called in the Lord being a bondservant is the Lord’s free man. Likewise he who was called being free is Christ’s bondservant."},{"v":23,"t":"You were bought with a price. Don’t become bondservants of men."},{"v":24,"t":"Brothers, let each man, in whatever condition he was called, stay in that condition with God."},{"v":25,"t":"Now concerning virgins, I have no commandment from the Lord, but I give my judgment as one who has obtained mercy from the Lord to be trustworthy."},{"v":26,"t":"Therefore I think that because of the distress that is on us, it’s good for a man to remain as he is."},{"v":27,"t":"Are you bound to a wife? Don’t seek to be freed. Are you free from a wife? Don’t seek a wife."},{"v":28,"t":"But if you marry, you have not sinned. If a virgin marries, she has not sinned. Yet such will have oppression in the flesh, and I want to spare you."},{"v":29,"t":"But I say this, brothers: the time is short. From now on, both those who have wives may be as though they had none;"},{"v":30,"t":"and those who weep, as though they didn’t weep; and those who rejoice, as though they didn’t rejoice; and those who buy, as though they didn’t possess;"},{"v":31,"t":"and those who use the world, as not using it to the fullest. For the mode of this world passes away."},{"v":32,"t":"But I desire to have you to be free from cares. He who is unmarried is concerned for the things of the Lord, how he may please the Lord;"},{"v":33,"t":"but he who is married is concerned about the things of the world, how he may please his wife."},{"v":34,"t":"There is also a difference between a wife and a virgin. The unmarried woman cares about the things of the Lord, that she may be holy both in body and in spirit. But she who is married cares about the things of the world—how she may please her husband."},{"v":35,"t":"This I say for your own benefit, not that I may ensnare you, but for that which is appropriate, and that you may attend to the Lord without distraction."},{"v":36,"t":"But if any man thinks that he is behaving inappropriately toward his virgin, if she is past the flower of her age, and if need so requires, let him do what he desires. He doesn’t sin. Let them marry."},{"v":37,"t":"But he who stands steadfast in his heart, having no urgency, but has power over his own will, and has determined in his own heart to keep his own virgin, does well."},{"v":38,"t":"So then both he who gives his own virgin in marriage does well, and he who doesn’t give her in marriage does better."},{"v":39,"t":"A wife is bound by law for as long as her husband lives; but if the husband is dead, she is free to be married to whomever she desires, only in the Lord."},{"v":40,"t":"But she is happier if she stays as she is, in my judgment, and I think that I also have God’s Spirit."}]},"8":{"en":[{"v":1,"t":"Now concerning things sacrificed to idols: We know that we all have knowledge. Knowledge puffs up, but love builds up."},{"v":2,"t":"But if anyone thinks that he knows anything, he doesn’t yet know as he ought to know."},{"v":3,"t":"But anyone who loves God is known by him."},{"v":4,"t":"Therefore concerning the eating of things sacrificed to idols, we know that no idol is anything in the world, and that there is no other God but one."},{"v":5,"t":"For though there are things that are called “gods”, whether in the heavens or on earth—as there are many “gods” and many “lords”—"},{"v":6,"t":"yet to us there is one God, the Father, of whom are all things, and we for him; and one Lord, Jesus Christ, through whom are all things, and we live through him."},{"v":7,"t":"However, that knowledge isn’t in all men. But some, with consciousness of an idol until now, eat as of a thing sacrificed to an idol, and their conscience, being weak, is defiled."},{"v":8,"t":"But food will not commend us to God. For neither, if we don’t eat are we the worse, nor if we eat are we the better."},{"v":9,"t":"But be careful that by no means does this liberty of yours become a stumbling block to the weak."},{"v":10,"t":"For if a man sees you who have knowledge sitting in an idol’s temple, won’t his conscience, if he is weak, be emboldened to eat things sacrificed to idols?"},{"v":11,"t":"And through your knowledge, he who is weak perishes, the brother for whose sake Christ died."},{"v":12,"t":"Thus, sinning against the brothers, and wounding their conscience when it is weak, you sin against Christ."},{"v":13,"t":"Therefore, if food causes my brother to stumble, I will eat no meat forever more, that I don’t cause my brother to stumble."}]},"9":{"en":[{"v":1,"t":"Am I not free? Am I not an apostle? Haven’t I seen Jesus Christ, our Lord? Aren’t you my work in the Lord?"},{"v":2,"t":"If to others I am not an apostle, yet at least I am to you; for you are the seal of my apostleship in the Lord."},{"v":3,"t":"My defense to those who examine me is this:"},{"v":4,"t":"Have we no right to eat and to drink?"},{"v":5,"t":"Have we no right to take along a wife who is a believer, even as the rest of the apostles, and the brothers of the Lord, and Cephas?"},{"v":6,"t":"Or have only Barnabas and I no right to not work?"},{"v":7,"t":"What soldier ever serves at his own expense? Who plants a vineyard, and doesn’t eat of its fruit? Or who feeds a flock, and doesn’t drink from the flock’s milk?"},{"v":8,"t":"Do I speak these things according to the ways of men? Or doesn’t the law also say the same thing?"},{"v":9,"t":"For it is written in the law of Moses, “You shall not muzzle an ox while it treads out the grain.” Is it for the oxen that God cares,"},{"v":10,"t":"or does he say it assuredly for our sake? Yes, it was written for our sake, because he who plows ought to plow in hope, and he who threshes in hope should partake of his hope."},{"v":11,"t":"If we sowed to you spiritual things, is it a great thing if we reap your fleshly things?"},{"v":12,"t":"If others partake of this right over you, don’t we yet more? Nevertheless we didn’t use this right, but we bear all things, that we may cause no hindrance to the Good News of Christ."},{"v":13,"t":"Don’t you know that those who serve around sacred things eat from the things of the temple, and those who wait on the altar have their portion with the altar?"},{"v":14,"t":"Even so the Lord ordained that those who proclaim the Good News should live from the Good News."},{"v":15,"t":"But I have used none of these things, and I don’t write these things that it may be done so in my case; for I would rather die, than that anyone should make my boasting void."},{"v":16,"t":"For if I preach the Good News, I have nothing to boast about, for necessity is laid on me; but woe is to me if I don’t preach the Good News."},{"v":17,"t":"For if I do this of my own will, I have a reward. But if not of my own will, I have a stewardship entrusted to me."},{"v":18,"t":"What then is my reward? That when I preach the Good News, I may present the Good News of Christ without charge, so as not to abuse my authority in the Good News."},{"v":19,"t":"For though I was free from all, I brought myself under bondage to all, that I might gain the more."},{"v":20,"t":"To the Jews I became as a Jew, that I might gain Jews; to those who are under the law, as under the law, that I might gain those who are under the law;"},{"v":21,"t":"to those who are without law, as without law (not being without law toward God, but under law toward Christ), that I might win those who are without law."},{"v":22,"t":"To the weak I became as weak, that I might gain the weak. I have become all things to all men, that I may by all means save some."},{"v":23,"t":"Now I do this for the sake of the Good News, that I may be a joint partaker of it."},{"v":24,"t":"Don’t you know that those who run in a race all run, but one receives the prize? Run like that, so that you may win."},{"v":25,"t":"Every man who strives in the games exercises self-control in all things. Now they do it to receive a corruptible crown, but we an incorruptible."},{"v":26,"t":"I therefore run like that, not aimlessly. I fight like that, not beating the air,"},{"v":27,"t":"but I beat my body and bring it into submission, lest by any means, after I have preached to others, I myself should be disqualified."}]},"10":{"en":[{"v":1,"t":"Now I would not have you ignorant, brothers, that our fathers were all under the cloud, and all passed through the sea;"},{"v":2,"t":"and were all baptized into Moses in the cloud and in the sea;"},{"v":3,"t":"and all ate the same spiritual food;"},{"v":4,"t":"and all drank the same spiritual drink. For they drank of a spiritual rock that followed them, and the rock was Christ."},{"v":5,"t":"However with most of them, God was not well pleased, for they were overthrown in the wilderness."},{"v":6,"t":"Now these things were our examples, to the intent we should not lust after evil things as they also lusted."},{"v":7,"t":"Don’t be idolaters, as some of them were. As it is written, “The people sat down to eat and drink, and rose up to play.”"},{"v":8,"t":"Let’s not commit sexual immorality, as some of them committed, and in one day twenty-three thousand fell."},{"v":9,"t":"Let’s not test Christ, as some of them tested, and perished by the serpents."},{"v":10,"t":"Don’t grumble, as some of them also grumbled, and perished by the destroyer."},{"v":11,"t":"Now all these things happened to them by way of example, and they were written for our admonition, on whom the ends of the ages have come."},{"v":12,"t":"Therefore let him who thinks he stands be careful that he doesn’t fall."},{"v":13,"t":"No temptation has taken you except what is common to man. God is faithful, who will not allow you to be tempted above what you are able, but will with the temptation also make the way of escape, that you may be able to endure it."},{"v":14,"t":"Therefore, my beloved, flee from idolatry."},{"v":15,"t":"I speak as to wise men. Judge what I say."},{"v":16,"t":"The cup of blessing which we bless, isn’t it a sharing of the blood of Christ? The bread which we break, isn’t it a sharing of the body of Christ?"},{"v":17,"t":"Because there is one loaf of bread, we, who are many, are one body; for we all partake of the one loaf of bread."},{"v":18,"t":"Consider Israel according to the flesh. Don’t those who eat the sacrifices participate in the altar?"},{"v":19,"t":"What am I saying then? That a thing sacrificed to idols is anything, or that an idol is anything?"},{"v":20,"t":"But I say that the things which the Gentiles sacrifice, they sacrifice to demons and not to God, and I don’t desire that you would have fellowship with demons."},{"v":21,"t":"You can’t both drink the cup of the Lord and the cup of demons. You can’t both partake of the table of the Lord and of the table of demons."},{"v":22,"t":"Or do we provoke the Lord to jealousy? Are we stronger than he?"},{"v":23,"t":"“All things are lawful for me,” but not all things are profitable. “All things are lawful for me,” but not all things build up."},{"v":24,"t":"Let no one seek his own, but each one his neighbor’s good."},{"v":25,"t":"Whatever is sold in the butcher shop, eat, asking no question for the sake of conscience,"},{"v":26,"t":"for “the earth is the Lord’s, and its fullness.”"},{"v":27,"t":"But if one of those who don’t believe invites you to a meal, and you are inclined to go, eat whatever is set before you, asking no questions for the sake of conscience."},{"v":28,"t":"But if anyone says to you, “This was offered to idols,” don’t eat it for the sake of the one who told you, and for the sake of conscience. For “the earth is the Lord’s, with all its fullness.”"},{"v":29,"t":"Conscience, I say, not your own, but the other’s conscience. For why is my liberty judged by another conscience?"},{"v":30,"t":"If I partake with thankfulness, why am I denounced for something I give thanks for?"},{"v":31,"t":"Whether therefore you eat or drink, or whatever you do, do all to the glory of God."},{"v":32,"t":"Give no occasion for stumbling, whether to Jews, to Greeks, or to the assembly of God;"},{"v":33,"t":"even as I also please all men in all things, not seeking my own profit, but the profit of the many, that they may be saved."}]},"11":{"en":[{"v":1,"t":"Be imitators of me, even as I also am of Christ."},{"v":2,"t":"Now I praise you, brothers, that you remember me in all things, and hold firm the traditions, even as I delivered them to you."},{"v":3,"t":"But I would have you know that the head of every man is Christ, and the head of the woman is man, and the head of Christ is God."},{"v":4,"t":"Every man praying or prophesying, having his head covered, dishonors his head."},{"v":5,"t":"But every woman praying or prophesying with her head uncovered dishonors her head. For it is one and the same thing as if she were shaved."},{"v":6,"t":"For if a woman is not covered, let her hair also be cut off. But if it is shameful for a woman to have her hair cut off or be shaved, let her be covered."},{"v":7,"t":"For a man indeed ought not to have his head covered, because he is the image and glory of God, but the woman is the glory of the man."},{"v":8,"t":"For man is not from woman, but woman from man;"},{"v":9,"t":"for man wasn’t created for the woman, but woman for the man."},{"v":10,"t":"For this cause the woman ought to have authority over her own head, because of the angels."},{"v":11,"t":"Nevertheless, neither is the woman independent of the man, nor the man independent of the woman, in the Lord."},{"v":12,"t":"For as woman came from man, so a man also comes through a woman; but all things are from God."},{"v":13,"t":"Judge for yourselves. Is it appropriate that a woman pray to God unveiled?"},{"v":14,"t":"Doesn’t even nature itself teach you that if a man has long hair, it is a dishonor to him?"},{"v":15,"t":"But if a woman has long hair, it is a glory to her, for her hair is given to her for a covering."},{"v":16,"t":"But if any man seems to be contentious, we have no such custom, neither do God’s assemblies."},{"v":17,"t":"But in giving you this command I don’t praise you, because you come together not for the better but for the worse."},{"v":18,"t":"For first of all, when you come together in the assembly, I hear that divisions exist among you, and I partly believe it."},{"v":19,"t":"For there also must be factions among you, that those who are approved may be revealed among you."},{"v":20,"t":"When therefore you assemble yourselves together, it is not the Lord’s supper that you eat."},{"v":21,"t":"For in your eating each one takes his own supper first. One is hungry, and another is drunken."},{"v":22,"t":"What, don’t you have houses to eat and to drink in? Or do you despise God’s assembly and put them to shame who don’t have enough? What shall I tell you? Shall I praise you? In this I don’t praise you."},{"v":23,"t":"For I received from the Lord that which also I delivered to you, that the Lord Jesus on the night in which he was betrayed took bread."},{"v":24,"t":"When he had given thanks, he broke it and said, “Take, eat. This is my body, which is broken for you. Do this in memory of me.”"},{"v":25,"t":"In the same way he also took the cup after supper, saying, “This cup is the new covenant in my blood. Do this, as often as you drink, in memory of me.”"},{"v":26,"t":"For as often as you eat this bread and drink this cup, you proclaim the Lord’s death until he comes."},{"v":27,"t":"Therefore whoever eats this bread or drinks the Lord’s cup in a way unworthy of the Lord will be guilty of the body and the blood of the Lord."},{"v":28,"t":"But let a man examine himself, and so let him eat of the bread and drink of the cup."},{"v":29,"t":"For he who eats and drinks in an unworthy way eats and drinks judgment to himself if he doesn’t discern the Lord’s body."},{"v":30,"t":"For this cause many among you are weak and sickly, and not a few sleep."},{"v":31,"t":"For if we discerned ourselves, we wouldn’t be judged."},{"v":32,"t":"But when we are judged, we are disciplined by the Lord, that we may not be condemned with the world."},{"v":33,"t":"Therefore, my brothers, when you come together to eat, wait for one another."},{"v":34,"t":"But if anyone is hungry, let him eat at home, lest your coming together be for judgment. The rest I will set in order whenever I come."}]},"12":{"en":[{"v":1,"t":"Now concerning spiritual things, brothers, I don’t want you to be ignorant."},{"v":2,"t":"You know that when you were heathen, you were led away to those mute idols, however you might be led."},{"v":3,"t":"Therefore I make known to you that no man speaking by God’s Spirit says, “Jesus is accursed.” No one can say, “Jesus is Lord,” but by the Holy Spirit."},{"v":4,"t":"Now there are various kinds of gifts, but the same Spirit."},{"v":5,"t":"There are various kinds of service, and the same Lord."},{"v":6,"t":"There are various kinds of workings, but the same God who works all things in all."},{"v":7,"t":"But to each one is given the manifestation of the Spirit for the profit of all."},{"v":8,"t":"For to one is given through the Spirit the word of wisdom, and to another the word of knowledge according to the same Spirit,"},{"v":9,"t":"to another faith by the same Spirit, and to another gifts of healings by the same Spirit,"},{"v":10,"t":"and to another workings of miracles, and to another prophecy, and to another discerning of spirits, to another different kinds of languages, and to another the interpretation of languages."},{"v":11,"t":"But the one and the same Spirit produces all of these, distributing to each one separately as he desires."},{"v":12,"t":"For as the body is one and has many members, and all the members of the body, being many, are one body; so also is Christ."},{"v":13,"t":"For in one Spirit we were all baptized into one body, whether Jews or Greeks, whether bond or free; and were all given to drink into one Spirit."},{"v":14,"t":"For the body is not one member, but many."},{"v":15,"t":"If the foot would say, “Because I’m not the hand, I’m not part of the body,” it is not therefore not part of the body."},{"v":16,"t":"If the ear would say, “Because I’m not the eye, I’m not part of the body,” it’s not therefore not part of the body."},{"v":17,"t":"If the whole body were an eye, where would the hearing be? If the whole were hearing, where would the smelling be?"},{"v":18,"t":"But now God has set the members, each one of them, in the body, just as he desired."},{"v":19,"t":"If they were all one member, where would the body be?"},{"v":20,"t":"But now they are many members, but one body."},{"v":21,"t":"The eye can’t tell the hand, “I have no need for you,” or again the head to the feet, “I have no need for you.”"},{"v":22,"t":"No, much rather, those members of the body which seem to be weaker are necessary."},{"v":23,"t":"Those parts of the body which we think to be less honorable, on those we bestow more abundant honor; and our unpresentable parts have more abundant modesty,"},{"v":24,"t":"while our presentable parts have no such need. But God composed the body together, giving more abundant honor to the inferior part,"},{"v":25,"t":"that there should be no division in the body, but that the members should have the same care for one another."},{"v":26,"t":"When one member suffers, all the members suffer with it. When one member is honored, all the members rejoice with it."},{"v":27,"t":"Now you are the body of Christ, and members individually."},{"v":28,"t":"God has set some in the assembly: first apostles, second prophets, third teachers, then miracle workers, then gifts of healings, helps, governments, and various kinds of languages."},{"v":29,"t":"Are all apostles? Are all prophets? Are all teachers? Are all miracle workers?"},{"v":30,"t":"Do all have gifts of healings? Do all speak with various languages? Do all interpret?"},{"v":31,"t":"But earnestly desire the best gifts. Moreover, I show a most excellent way to you."}]},"13":{"en":[{"v":1,"t":"If I speak with the languages of men and of angels, but don’t have love, I have become sounding brass or a clanging cymbal."},{"v":2,"t":"If I have the gift of prophecy, and know all mysteries and all knowledge, and if I have all faith, so as to remove mountains, but don’t have love, I am nothing."},{"v":3,"t":"If I give away all my goods to feed the poor, and if I give my body to be burned, but don’t have love, it profits me nothing."},{"v":4,"t":"Love is patient and is kind. Love doesn’t envy. Love doesn’t brag, is not proud,"},{"v":5,"t":"doesn’t behave itself inappropriately, doesn’t seek its own way, is not provoked, takes no account of evil;"},{"v":6,"t":"doesn’t rejoice in unrighteousness, but rejoices with the truth;"},{"v":7,"t":"bears all things, believes all things, hopes all things, and endures all things."},{"v":8,"t":"Love never fails. But where there are prophecies, they will be done away with. Where there are various languages, they will cease. Where there is knowledge, it will be done away with."},{"v":9,"t":"For we know in part and we prophesy in part;"},{"v":10,"t":"but when that which is complete has come, then that which is partial will be done away with."},{"v":11,"t":"When I was a child, I spoke as a child, I felt as a child, I thought as a child. Now that I have become a man, I have put away childish things."},{"v":12,"t":"For now we see in a mirror, dimly, but then face to face. Now I know in part, but then I will know fully, even as I was also fully known."},{"v":13,"t":"But now faith, hope, and love remain—these three. The greatest of these is love."}]},"14":{"en":[{"v":1,"t":"Follow after love and earnestly desire spiritual gifts, but especially that you may prophesy."},{"v":2,"t":"For he who speaks in another language speaks not to men, but to God, for no one understands, but in the Spirit he speaks mysteries."},{"v":3,"t":"But he who prophesies speaks to men for their edification, exhortation, and consolation."},{"v":4,"t":"He who speaks in another language edifies himself, but he who prophesies edifies the assembly."},{"v":5,"t":"Now I desire to have you all speak with other languages, but even more that you would prophesy. For he is greater who prophesies than he who speaks with other languages, unless he interprets, that the assembly may be built up."},{"v":6,"t":"But now, brothers, if I come to you speaking with other languages, what would I profit you unless I speak to you either by way of revelation, or of knowledge, or of prophesying, or of teaching?"},{"v":7,"t":"Even lifeless things that make a sound, whether pipe or harp, if they didn’t give a distinction in the sounds, how would it be known what is piped or harped?"},{"v":8,"t":"For if the trumpet gave an uncertain sound, who would prepare himself for war?"},{"v":9,"t":"So also you, unless you uttered by the tongue words easy to understand, how would it be known what is spoken? For you would be speaking into the air."},{"v":10,"t":"There are, it may be, so many kinds of languages in the world, and none of them is without meaning."},{"v":11,"t":"If then I don’t know the meaning of the language, I would be to him who speaks a foreigner, and he who speaks would be a foreigner to me."},{"v":12,"t":"So also you, since you are zealous for spiritual gifts, seek that you may abound to the building up of the assembly."},{"v":13,"t":"Therefore let him who speaks in another language pray that he may interpret."},{"v":14,"t":"For if I pray in another language, my spirit prays, but my understanding is unfruitful."},{"v":15,"t":"What should I do? I will pray with the spirit, and I will pray with the understanding also. I will sing with the spirit, and I will sing with the understanding also."},{"v":16,"t":"Otherwise, if you bless with the spirit, how will he who fills the place of the unlearned say the “Amen” at your giving of thanks, seeing he doesn’t know what you say?"},{"v":17,"t":"For you most certainly give thanks well, but the other person is not built up."},{"v":18,"t":"I thank my God, I speak with other languages more than you all."},{"v":19,"t":"However, in the assembly I would rather speak five words with my understanding, that I might instruct others also, than ten thousand words in another language."},{"v":20,"t":"Brothers, don’t be children in thoughts, yet in malice be babies, but in thoughts be mature."},{"v":21,"t":"In the law it is written, “By men of strange languages and by the lips of strangers I will speak to this people. They won’t even listen to me that way, says the Lord.”"},{"v":22,"t":"Therefore other languages are for a sign, not to those who believe, but to the unbelieving; but prophesying is for a sign, not to the unbelieving, but to those who believe."},{"v":23,"t":"If therefore the whole assembly is assembled together and all speak with other languages, and unlearned or unbelieving people come in, won’t they say that you are crazy?"},{"v":24,"t":"But if all prophesy, and someone unbelieving or unlearned comes in, he is reproved by all, and he is judged by all."},{"v":25,"t":"And thus the secrets of his heart are revealed. So he will fall down on his face and worship God, declaring that God is among you indeed."},{"v":26,"t":"What is it then, brothers? When you come together, each one of you has a psalm, has a teaching, has a revelation, has another language, or has an interpretation. Let all things be done to build each other up."},{"v":27,"t":"If any man speaks in another language, let there be two, or at the most three, and in turn; and let one interpret."},{"v":28,"t":"But if there is no interpreter, let him keep silent in the assembly, and let him speak to himself and to God."},{"v":29,"t":"Let two or three of the prophets speak, and let the others discern."},{"v":30,"t":"But if a revelation is made to another sitting by, let the first keep silent."},{"v":31,"t":"For you all can prophesy one by one, that all may learn and all may be exhorted."},{"v":32,"t":"The spirits of the prophets are subject to the prophets,"},{"v":33,"t":"for God is not a God of confusion but of peace, as in all the assemblies of the saints."},{"v":34,"t":"Let the wives be quiet in the assemblies, for it has not been permitted for them to be talking except in submission, as the law also says,"},{"v":35,"t":"if they desire to learn anything. “Let them ask their own husbands at home, for it is shameful for a wife to be talking in the assembly.”"},{"v":36,"t":"What!? Was it from you that the word of God went out? Or did it come to you alone?"},{"v":37,"t":"If any man thinks himself to be a prophet or spiritual, let him recognize the things which I write to you, that they are the commandment of the Lord."},{"v":38,"t":"But if anyone is ignorant, let him be ignorant."},{"v":39,"t":"Therefore, brothers, desire earnestly to prophesy, and don’t forbid speaking with other languages."},{"v":40,"t":"Let all things be done decently and in order."}]},"15":{"en":[{"v":1,"t":"Now I declare to you, brothers, the Good News which I preached to you, which also you received, in which you also stand,"},{"v":2,"t":"by which also you are saved, if you hold firmly the word which I preached to you—unless you believed in vain."},{"v":3,"t":"For I delivered to you first of all that which I also received: that Christ died for our sins according to the Scriptures,"},{"v":4,"t":"that he was buried, that he was raised on the third day according to the Scriptures,"},{"v":5,"t":"and that he appeared to Cephas, then to the twelve."},{"v":6,"t":"Then he appeared to over five hundred brothers at once, most of whom remain until now, but some have also fallen asleep."},{"v":7,"t":"Then he appeared to James, then to all the apostles,"},{"v":8,"t":"and last of all, as to the child born at the wrong time, he appeared to me also."},{"v":9,"t":"For I am the least of the apostles, who is not worthy to be called an apostle, because I persecuted the assembly of God."},{"v":10,"t":"But by the grace of God I am what I am. His grace which was given to me was not futile, but I worked more than all of them; yet not I, but the grace of God which was with me."},{"v":11,"t":"Whether then it is I or they, so we preach, and so you believed."},{"v":12,"t":"Now if Christ is preached, that he has been raised from the dead, how do some among you say that there is no resurrection of the dead?"},{"v":13,"t":"But if there is no resurrection of the dead, neither has Christ been raised."},{"v":14,"t":"If Christ has not been raised, then our preaching is in vain and your faith also is in vain."},{"v":15,"t":"Yes, we are also found false witnesses of God, because we testified about God that he raised up Christ, whom he didn’t raise up if it is true that the dead are not raised."},{"v":16,"t":"For if the dead aren’t raised, neither has Christ been raised."},{"v":17,"t":"If Christ has not been raised, your faith is vain; you are still in your sins."},{"v":18,"t":"Then they also who are fallen asleep in Christ have perished."},{"v":19,"t":"If we have only hoped in Christ in this life, we are of all men most pitiable."},{"v":20,"t":"But now Christ has been raised from the dead. He became the first fruit of those who are asleep."},{"v":21,"t":"For since death came by man, the resurrection of the dead also came by man."},{"v":22,"t":"For as in Adam all die, so also in Christ all will be made alive."},{"v":23,"t":"But each in his own order: Christ the first fruits, then those who are Christ’s at his coming."},{"v":24,"t":"Then the end comes, when he will deliver up the Kingdom to God the Father, when he will have abolished all rule and all authority and power."},{"v":25,"t":"For he must reign until he has put all his enemies under his feet."},{"v":26,"t":"The last enemy that will be abolished is death."},{"v":27,"t":"For, “He put all things in subjection under his feet.” But when he says, “All things are put in subjection”, it is evident that he is excepted who subjected all things to him."},{"v":28,"t":"When all things have been subjected to him, then the Son will also himself be subjected to him who subjected all things to him, that God may be all in all."},{"v":29,"t":"Or else what will they do who are baptized for the dead? If the dead aren’t raised at all, why then are they baptized for the dead?"},{"v":30,"t":"Why do we also stand in jeopardy every hour?"},{"v":31,"t":"I affirm, by the boasting in you which I have in Christ Jesus our Lord, I die daily."},{"v":32,"t":"If I fought with animals at Ephesus for human purposes, what does it profit me? If the dead are not raised, then “let’s eat and drink, for tomorrow we die.”"},{"v":33,"t":"Don’t be deceived! “Evil companionships corrupt good morals.”"},{"v":34,"t":"Wake up righteously and don’t sin, for some have no knowledge of God. I say this to your shame."},{"v":35,"t":"But someone will say, “How are the dead raised?” and, “With what kind of body do they come?”"},{"v":36,"t":"You foolish one, that which you yourself sow is not made alive unless it dies."},{"v":37,"t":"That which you sow, you don’t sow the body that will be, but a bare grain, maybe of wheat, or of some other kind."},{"v":38,"t":"But God gives it a body even as it pleased him, and to each seed a body of its own."},{"v":39,"t":"All flesh is not the same flesh, but there is one flesh of men, another flesh of animals, another of fish, and another of birds."},{"v":40,"t":"There are also celestial bodies and terrestrial bodies; but the glory of the celestial differs from that of the terrestrial."},{"v":41,"t":"There is one glory of the sun, another glory of the moon, and another glory of the stars; for one star differs from another star in glory."},{"v":42,"t":"So also is the resurrection of the dead. The body is sown perishable; it is raised imperishable."},{"v":43,"t":"It is sown in dishonor; it is raised in glory. It is sown in weakness; it is raised in power."},{"v":44,"t":"It is sown a natural body; it is raised a spiritual body. There is a natural body and there is also a spiritual body."},{"v":45,"t":"So also it is written, “The first man Adam became a living soul.” The last Adam became a life-giving spirit."},{"v":46,"t":"However, that which is spiritual isn’t first, but that which is natural, then that which is spiritual."},{"v":47,"t":"The first man is of the earth, made of dust. The second man is the Lord from heaven."},{"v":48,"t":"As is the one made of dust, such are those who are also made of dust; and as is the heavenly, such are they also that are heavenly."},{"v":49,"t":"As we have borne the image of those made of dust, let’s also bear the image of the heavenly."},{"v":50,"t":"Now I say this, brothers, that flesh and blood can’t inherit God’s Kingdom; neither does the perishable inherit imperishable."},{"v":51,"t":"Behold, I tell you a mystery. We will not all sleep, but we will all be changed,"},{"v":52,"t":"in a moment, in the twinkling of an eye, at the last trumpet. For the trumpet will sound and the dead will be raised incorruptible, and we will be changed."},{"v":53,"t":"For this perishable body must become imperishable, and this mortal must put on immortality."},{"v":54,"t":"But when this perishable body will have become imperishable, and this mortal will have put on immortality, then what is written will happen: “Death is swallowed up in victory.”"},{"v":55,"t":"“Death, where is your sting? Hades, where is your victory?”"},{"v":56,"t":"The sting of death is sin, and the power of sin is the law."},{"v":57,"t":"But thanks be to God, who gives us the victory through our Lord Jesus Christ."},{"v":58,"t":"Therefore, my beloved brothers, be steadfast, immovable, always abounding in the Lord’s work, because you know that your labor is not in vain in the Lord."}]},"16":{"en":[{"v":1,"t":"Now concerning the collection for the saints: as I commanded the assemblies of Galatia, you do likewise."},{"v":2,"t":"On the first day of every week, let each one of you save as he may prosper, that no collections are made when I come."},{"v":3,"t":"When I arrive, I will send whoever you approve with letters to carry your gracious gift to Jerusalem."},{"v":4,"t":"If it is appropriate for me to go also, they will go with me."},{"v":5,"t":"I will come to you when I have passed through Macedonia, for I am passing through Macedonia."},{"v":6,"t":"But with you it may be that I will stay with you, or even winter with you, that you may send me on my journey wherever I go."},{"v":7,"t":"For I do not wish to see you now in passing, but I hope to stay a while with you, if the Lord permits."},{"v":8,"t":"But I will stay at Ephesus until Pentecost,"},{"v":9,"t":"for a great and effective door has opened to me, and there are many adversaries."},{"v":10,"t":"Now if Timothy comes, see that he is with you without fear, for he does the work of the Lord, as I also do."},{"v":11,"t":"Therefore let no one despise him. But set him forward on his journey in peace, that he may come to me; for I expect him with the brothers."},{"v":12,"t":"Now concerning Apollos the brother, I strongly urged him to come to you with the brothers, but it was not at all his desire to come now; but he will come when he has an opportunity."},{"v":13,"t":"Watch! Stand firm in the faith! Be courageous! Be strong!"},{"v":14,"t":"Let all that you do be done in love."},{"v":15,"t":"Now I beg you, brothers—you know the house of Stephanas, that it is the first fruits of Achaia, and that they have set themselves to serve the saints—"},{"v":16,"t":"that you also be in subjection to such, and to everyone who helps in the work and labors."},{"v":17,"t":"I rejoice at the coming of Stephanas, Fortunatus, and Achaicus; for that which was lacking on your part, they supplied."},{"v":18,"t":"For they refreshed my spirit and yours. Therefore acknowledge those who are like that."},{"v":19,"t":"The assemblies of Asia greet you. Aquila and Priscilla greet you warmly in the Lord, together with the assembly that is in their house."},{"v":20,"t":"All the brothers greet you. Greet one another with a holy kiss."},{"v":21,"t":"This greeting is by me, Paul, with my own hand."},{"v":22,"t":"If any man doesn’t love the Lord Jesus Christ, let him be cursed. Come, Lord!"},{"v":23,"t":"The grace of the Lord Jesus Christ be with you."},{"v":24,"t":"My love to all of you in Christ Jesus. Amen."}]}},"2CO":{"1":{"en":[{"v":1,"t":"Paul, an apostle of Christ Jesus through the will of God, and Timothy our brother, to the assembly of God which is at Corinth, with all the saints who are in the whole of Achaia:"},{"v":2,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"Blessed be the God and Father of our Lord Jesus Christ, the Father of mercies and God of all comfort,"},{"v":4,"t":"who comforts us in all our affliction, that we may be able to comfort those who are in any affliction, through the comfort with which we ourselves are comforted by God."},{"v":5,"t":"For as the sufferings of Christ abound to us, even so our comfort also abounds through Christ."},{"v":6,"t":"But if we are afflicted, it is for your comfort and salvation. If we are comforted, it is for your comfort, which produces in you the patient enduring of the same sufferings which we also suffer."},{"v":7,"t":"Our hope for you is steadfast, knowing that, since you are partakers of the sufferings, so you are also of the comfort."},{"v":8,"t":"For we don’t desire to have you uninformed, brothers, concerning our affliction which happened to us in Asia: that we were weighed down exceedingly, beyond our power, so much that we despaired even of life."},{"v":9,"t":"Yes, we ourselves have had the sentence of death within ourselves, that we should not trust in ourselves, but in God who raises the dead,"},{"v":10,"t":"who delivered us out of so great a death, and does deliver, on whom we have set our hope that he will also still deliver us,"},{"v":11,"t":"you also helping together on our behalf by your supplication; that, for the gift given to us by means of many, thanks may be given by many persons on your behalf."},{"v":12,"t":"For our boasting is this: the testimony of our conscience that in holiness and sincerity of God, not in fleshly wisdom but in the grace of God, we behaved ourselves in the world, and more abundantly toward you."},{"v":13,"t":"For we write no other things to you than what you read or even acknowledge, and I hope you will acknowledge to the end—"},{"v":14,"t":"as also you acknowledged us in part—that we are your boasting, even as you also are ours, in the day of our Lord Jesus."},{"v":15,"t":"In this confidence, I was determined to come first to you, that you might have a second benefit,"},{"v":16,"t":"and by you to pass into Macedonia, and again from Macedonia to come to you, and to be sent forward by you on my journey to Judea."},{"v":17,"t":"When I therefore planned this, did I show fickleness? Or the things that I plan, do I plan according to the flesh, that with me there should be the “Yes, yes” and the “No, no?”"},{"v":18,"t":"But as God is faithful, our word toward you was not “Yes and no.”"},{"v":19,"t":"For the Son of God, Jesus Christ, who was preached among you by us—by me, Silvanus, and Timothy—was not “Yes and no,” but in him is “Yes.”"},{"v":20,"t":"For however many are the promises of God, in him is the “Yes.” Therefore also through him is the “Amen”, to the glory of God through us."},{"v":21,"t":"Now he who establishes us with you in Christ and anointed us is God,"},{"v":22,"t":"who also sealed us and gave us the down payment of the Spirit in our hearts."},{"v":23,"t":"But I call God for a witness to my soul, that to spare you, I didn’t come to Corinth."},{"v":24,"t":"We don’t control your faith, but are fellow workers with you for your joy. For you stand firm in faith."}]},"2":{"en":[{"v":1,"t":"But I determined this for myself, that I would not come to you again in sorrow."},{"v":2,"t":"For if I make you grieve, then who will make me glad but he who is made to grieve by me?"},{"v":3,"t":"And I wrote this very thing to you, so that when I came, I wouldn’t have sorrow from them of whom I ought to rejoice; having confidence in you all that my joy would be shared by all of you."},{"v":4,"t":"For out of much affliction and anguish of heart I wrote to you with many tears, not that you should be made to grieve, but that you might know the love that I have so abundantly for you."},{"v":5,"t":"But if any has caused sorrow, he has caused sorrow not to me, but in part (that I not press too heavily) to you all."},{"v":6,"t":"This punishment which was inflicted by the many is sufficient for such a one;"},{"v":7,"t":"so that, on the contrary, you should rather forgive him and comfort him, lest by any means such a one should be swallowed up with his excessive sorrow."},{"v":8,"t":"Therefore I beg you to confirm your love toward him."},{"v":9,"t":"For to this end I also wrote, that I might know the proof of you, whether you are obedient in all things."},{"v":10,"t":"Now I also forgive whomever you forgive anything. For if indeed I have forgiven anything, I have forgiven that one for your sakes in the presence of Christ,"},{"v":11,"t":"that no advantage may be gained over us by Satan, for we are not ignorant of his schemes."},{"v":12,"t":"Now when I came to Troas for the Good News of Christ, and when a door was opened to me in the Lord,"},{"v":13,"t":"I had no relief for my spirit, because I didn’t find Titus my brother, but taking my leave of them, I went out into Macedonia."},{"v":14,"t":"Now thanks be to God who always leads us in triumph in Christ, and reveals through us the sweet aroma of his knowledge in every place."},{"v":15,"t":"For we are a sweet aroma of Christ to God in those who are saved and in those who perish:"},{"v":16,"t":"to the one a stench from death to death, to the other a sweet aroma from life to life. Who is sufficient for these things?"},{"v":17,"t":"For we are not as so many, peddling the word of God. But as of sincerity, but as of God, in the sight of God, we speak in Christ."}]},"3":{"en":[{"v":1,"t":"Are we beginning again to commend ourselves? Or do we need, as do some, letters of commendation to you or from you?"},{"v":2,"t":"You are our letter, written in our hearts, known and read by all men,"},{"v":3,"t":"being revealed that you are a letter of Christ, served by us, written not with ink, but with the Spirit of the living God; not in tablets of stone, but in tablets that are hearts of flesh."},{"v":4,"t":"Such confidence we have through Christ toward God,"},{"v":5,"t":"not that we are sufficient of ourselves to account anything as from ourselves; but our sufficiency is from God,"},{"v":6,"t":"who also made us sufficient as servants of a new covenant, not of the letter but of the Spirit. For the letter kills, but the Spirit gives life."},{"v":7,"t":"But if the service of death, written engraved on stones, came with glory, so that the children of Israel could not look steadfastly on the face of Moses for the glory of his face, which was passing away,"},{"v":8,"t":"won’t service of the Spirit be with much more glory?"},{"v":9,"t":"For if the service of condemnation has glory, the service of righteousness exceeds much more in glory."},{"v":10,"t":"For most certainly that which has been made glorious has not been made glorious in this respect, by reason of the glory that surpasses."},{"v":11,"t":"For if that which passes away was with glory, much more that which remains is in glory."},{"v":12,"t":"Having therefore such a hope, we use great boldness of speech,"},{"v":13,"t":"and not as Moses, who put a veil on his face so that the children of Israel wouldn’t look steadfastly on the end of that which was passing away."},{"v":14,"t":"But their minds were hardened, for until this very day at the reading of the old covenant the same veil remains, because in Christ it passes away."},{"v":15,"t":"But to this day, when Moses is read, a veil lies on their heart."},{"v":16,"t":"But whenever someone turns to the Lord, the veil is taken away."},{"v":17,"t":"Now the Lord is the Spirit; and where the Spirit of the Lord is, there is liberty."},{"v":18,"t":"But we all, with unveiled face seeing the glory of the Lord as in a mirror, are transformed into the same image from glory to glory, even as from the Lord, the Spirit."}]},"4":{"en":[{"v":1,"t":"Therefore, seeing we have this ministry, even as we obtained mercy, we don’t faint."},{"v":2,"t":"But we have renounced the hidden things of shame, not walking in craftiness nor handling the word of God deceitfully, but by the manifestation of the truth commending ourselves to every man’s conscience in the sight of God."},{"v":3,"t":"Even if our Good News is veiled, it is veiled in those who are dying,"},{"v":4,"t":"in whom the god of this world has blinded the minds of the unbelieving, that the light of the Good News of the glory of Christ, who is the image of God, should not dawn on them."},{"v":5,"t":"For we don’t preach ourselves, but Christ Jesus as Lord, and ourselves as your servants for Jesus’ sake,"},{"v":6,"t":"seeing it is God who said, “Light will shine out of darkness,” who has shone in our hearts to give the light of the knowledge of the glory of God in the face of Jesus Christ."},{"v":7,"t":"But we have this treasure in clay vessels, that the exceeding greatness of the power may be of God and not from ourselves."},{"v":8,"t":"We are pressed on every side, yet not crushed; perplexed, yet not to despair;"},{"v":9,"t":"pursued, yet not forsaken; struck down, yet not destroyed;"},{"v":10,"t":"always carrying in the body the putting to death of the Lord Jesus, that the life of Jesus may also be revealed in our body."},{"v":11,"t":"For we who live are always delivered to death for Jesus’ sake, that the life also of Jesus may be revealed in our mortal flesh."},{"v":12,"t":"So then death works in us, but life in you."},{"v":13,"t":"But having the same spirit of faith, according to that which is written, “I believed, and therefore I spoke.” We also believe, and therefore we also speak,"},{"v":14,"t":"knowing that he who raised the Lord Jesus will raise us also with Jesus, and will present us with you."},{"v":15,"t":"For all things are for your sakes, that the grace, being multiplied through the many, may cause the thanksgiving to abound to the glory of God."},{"v":16,"t":"Therefore we don’t faint, but though our outward person is decaying, yet our inward person is renewed day by day."},{"v":17,"t":"For our light affliction, which is for the moment, works for us more and more exceedingly an eternal weight of glory,"},{"v":18,"t":"while we don’t look at the things which are seen, but at the things which are not seen. For the things which are seen are temporal, but the things which are not seen are eternal."}]},"5":{"en":[{"v":1,"t":"For we know that if the earthly house of our tent is dissolved, we have a building from God, a house not made with hands, eternal, in the heavens."},{"v":2,"t":"For most certainly in this we groan, longing to be clothed with our habitation which is from heaven,"},{"v":3,"t":"if indeed being clothed, we will not be found naked."},{"v":4,"t":"For indeed we who are in this tent do groan, being burdened, not that we desire to be unclothed, but that we desire to be clothed, that what is mortal may be swallowed up by life."},{"v":5,"t":"Now he who made us for this very thing is God, who also gave to us the down payment of the Spirit."},{"v":6,"t":"Therefore we are always confident and know that while we are at home in the body, we are absent from the Lord;"},{"v":7,"t":"for we walk by faith, not by sight."},{"v":8,"t":"We are courageous, I say, and are willing rather to be absent from the body and to be at home with the Lord."},{"v":9,"t":"Therefore also we make it our aim, whether at home or absent, to be well pleasing to him."},{"v":10,"t":"For we must all be revealed before the judgment seat of Christ that each one may receive the things in the body according to what he has done, whether good or bad."},{"v":11,"t":"Knowing therefore the fear of the Lord, we persuade men, but we are revealed to God, and I hope that we are revealed also in your consciences."},{"v":12,"t":"For we are not commending ourselves to you again, but speak as giving you occasion of boasting on our behalf, that you may have something to answer those who boast in appearance and not in heart."},{"v":13,"t":"For if we are beside ourselves, it is for God. Or if we are of sober mind, it is for you."},{"v":14,"t":"For the love of Christ compels us; because we judge thus: that one died for all, therefore all died."},{"v":15,"t":"He died for all, that those who live should no longer live to themselves, but to him who for their sakes died and rose again."},{"v":16,"t":"Therefore we know no one according to the flesh from now on. Even though we have known Christ according to the flesh, yet now we know him so no more."},{"v":17,"t":"Therefore if anyone is in Christ, he is a new creation. The old things have passed away. Behold, all things have become new."},{"v":18,"t":"But all things are of God, who reconciled us to himself through Jesus Christ, and gave to us the ministry of reconciliation;"},{"v":19,"t":"namely, that God was in Christ reconciling the world to himself, not reckoning to them their trespasses, and having committed to us the word of reconciliation."},{"v":20,"t":"We are therefore ambassadors on behalf of Christ, as though God were entreating by us: we beg you on behalf of Christ, be reconciled to God."},{"v":21,"t":"For him who knew no sin he made to be sin on our behalf, so that in him we might become the righteousness of God."}]},"6":{"en":[{"v":1,"t":"Working together, we entreat also that you do not receive the grace of God in vain."},{"v":2,"t":"For he says, “At an acceptable time I listened to you. In a day of salvation I helped you.” Behold, now is the acceptable time. Behold, now is the day of salvation."},{"v":3,"t":"We give no occasion of stumbling in anything, that our service may not be blamed,"},{"v":4,"t":"but in everything commending ourselves as servants of God: in great endurance, in afflictions, in hardships, in distresses,"},{"v":5,"t":"in beatings, in imprisonments, in riots, in labors, in watchings, in fastings,"},{"v":6,"t":"in pureness, in knowledge, in perseverance, in kindness, in the Holy Spirit, in sincere love,"},{"v":7,"t":"in the word of truth, in the power of God, by the armor of righteousness on the right hand and on the left,"},{"v":8,"t":"by glory and dishonor, by evil report and good report, as deceivers and yet true,"},{"v":9,"t":"as unknown and yet well known, as dying and behold—we live, as punished and not killed,"},{"v":10,"t":"as sorrowful yet always rejoicing, as poor yet making many rich, as having nothing and yet possessing all things."},{"v":11,"t":"Our mouth is open to you, Corinthians. Our heart is enlarged."},{"v":12,"t":"You are not restricted by us, but you are restricted by your own affections."},{"v":13,"t":"Now in return—I speak as to my children—you also open your hearts."},{"v":14,"t":"Don’t be unequally yoked with unbelievers, for what fellowship do righteousness and iniquity have? Or what fellowship does light have with darkness?"},{"v":15,"t":"What agreement does Christ have with Belial? Or what portion does a believer have with an unbeliever?"},{"v":16,"t":"What agreement does a temple of God have with idols? For you are a temple of the living God. Even as God said, “I will dwell in them and walk in them. I will be their God and they will be my people.”"},{"v":17,"t":"Therefore “‘Come out from among them, and be separate,’ says the Lord. ‘Touch no unclean thing. I will receive you."},{"v":18,"t":"I will be to you a Father. You will be to me sons and daughters,’ says the Lord Almighty.”"}]},"7":{"en":[{"v":1,"t":"Having therefore these promises, beloved, let’s cleanse ourselves from all defilement of flesh and spirit, perfecting holiness in the fear of God."},{"v":2,"t":"Open your hearts to us. We wronged no one. We corrupted no one. We took advantage of no one."},{"v":3,"t":"I say this not to condemn you, for I have said before that you are in our hearts to die together and live together."},{"v":4,"t":"Great is my boldness of speech toward you. Great is my boasting on your behalf. I am filled with comfort. I overflow with joy in all our affliction."},{"v":5,"t":"For even when we had come into Macedonia, our flesh had no relief, but we were afflicted on every side. Fightings were outside. Fear was inside."},{"v":6,"t":"Nevertheless, he who comforts the lowly, God, comforted us by the coming of Titus,"},{"v":7,"t":"and not by his coming only, but also by the comfort with which he was comforted in you while he told us of your longing, your mourning, and your zeal for me, so that I rejoiced still more."},{"v":8,"t":"For though I grieved you with my letter, I do not regret it, though I did regret it. For I see that my letter made you grieve, though just for a while."},{"v":9,"t":"I now rejoice, not that you were grieved, but that you were grieved to repentance. For you were grieved in a godly way, that you might suffer loss by us in nothing."},{"v":10,"t":"For godly sorrow produces repentance leading to salvation, which brings no regret. But the sorrow of the world produces death."},{"v":11,"t":"For behold, this same thing, that you were grieved in a godly way, what earnest care it worked in you. Yes, what defense, indignation, fear, longing, zeal, and vindication! In everything you demonstrated yourselves to be pure in the matter."},{"v":12,"t":"So although I wrote to you, I wrote not for his cause that did the wrong, nor for his cause that suffered the wrong, but that your earnest care for us might be revealed in you in the sight of God."},{"v":13,"t":"Therefore we have been comforted. In our comfort we rejoiced the more exceedingly for the joy of Titus, because his spirit has been refreshed by you all."},{"v":14,"t":"For if in anything I have boasted to him on your behalf, I was not disappointed. But as we spoke all things to you in truth, so our glorying also which I made before Titus was found to be truth."},{"v":15,"t":"His affection is more abundantly toward you, while he remembers all of your obedience, how with fear and trembling you received him."},{"v":16,"t":"I rejoice that in everything I am confident concerning you."}]},"8":{"en":[{"v":1,"t":"Moreover, brothers, we make known to you the grace of God which has been given in the assemblies of Macedonia,"},{"v":2,"t":"how in a severe ordeal of affliction, the abundance of their joy and their deep poverty abounded to the riches of their generosity."},{"v":3,"t":"For according to their power, I testify, yes and beyond their power, they gave of their own accord,"},{"v":4,"t":"begging us with much entreaty to receive this grace and the fellowship in the service to the saints."},{"v":5,"t":"This was not as we had expected, but first they gave their own selves to the Lord, and to us through the will of God."},{"v":6,"t":"So we urged Titus, that as he had made a beginning before, so he would also complete in you this grace."},{"v":7,"t":"But as you abound in everything—in faith, utterance, knowledge, all earnestness, and in your love to us—see that you also abound in this grace."},{"v":8,"t":"I speak not by way of commandment, but as proving through the earnestness of others the sincerity also of your love."},{"v":9,"t":"For you know the grace of our Lord Jesus Christ, that though he was rich, yet for your sakes he became poor, that you through his poverty might become rich."},{"v":10,"t":"I give advice in this: it is expedient for you who were the first to start a year ago, not only to do, but also to be willing."},{"v":11,"t":"But now complete the doing also, that as there was the readiness to be willing, so there may be the completion also out of your ability."},{"v":12,"t":"For if the readiness is there, it is acceptable according to what you have, not according to what you don’t have."},{"v":13,"t":"For this is not that others may be eased and you distressed,"},{"v":14,"t":"but for equality. Your abundance at this present time supplies their lack, that their abundance also may become a supply for your lack, that there may be equality."},{"v":15,"t":"As it is written, “He who gathered much had nothing left over, and he who gathered little had no lack.”"},{"v":16,"t":"But thanks be to God, who puts the same earnest care for you into the heart of Titus."},{"v":17,"t":"For he indeed accepted our exhortation, but being himself very earnest, he went out to you of his own accord."},{"v":18,"t":"We have sent together with him the brother whose praise in the Good News is known throughout all the assemblies."},{"v":19,"t":"Not only so, but he was also appointed by the assemblies to travel with us in this grace, which is served by us to the glory of the Lord himself, and to show our readiness."},{"v":20,"t":"We are avoiding this, that any man should blame us concerning this abundance which is administered by us."},{"v":21,"t":"Having regard for honorable things, not only in the sight of the Lord, but also in the sight of men."},{"v":22,"t":"We have sent with them our brother whom we have many times proved earnest in many things, but now much more earnest, by reason of the great confidence which he has in you."},{"v":23,"t":"As for Titus, he is my partner and fellow worker for you. As for our brothers, they are the apostles of the assemblies, the glory of Christ."},{"v":24,"t":"Therefore show the proof of your love to them before the assemblies, and of our boasting on your behalf."}]},"9":{"en":[{"v":1,"t":"It is indeed unnecessary for me to write to you concerning the service to the saints,"},{"v":2,"t":"for I know your readiness, of which I boast on your behalf to those of Macedonia, that Achaia has been prepared for the past year. Your zeal has stirred up very many of them."},{"v":3,"t":"But I have sent the brothers so that our boasting on your behalf may not be in vain in this respect, that, just as I said, you may be prepared,"},{"v":4,"t":"lest by any means, if anyone from Macedonia comes there with me and finds you unprepared, we (to say nothing of you) would be disappointed in this confident boasting."},{"v":5,"t":"I thought it necessary therefore to entreat the brothers that they would go before to you and arrange ahead of time the generous gift that you promised before, that the same might be ready as a matter of generosity, and not of greediness."},{"v":6,"t":"Remember this: he who sows sparingly will also reap sparingly. He who sows bountifully will also reap bountifully."},{"v":7,"t":"Let each man give according as he has determined in his heart, not grudgingly or under compulsion, for God loves a cheerful giver."},{"v":8,"t":"And God is able to make all grace abound to you, that you, always having all sufficiency in everything, may abound to every good work."},{"v":9,"t":"As it is written, “He has scattered abroad. He has given to the poor. His righteousness remains forever.”"},{"v":10,"t":"Now may he who supplies seed to the sower and bread for food, supply and multiply your seed for sowing, and increase the fruits of your righteousness,"},{"v":11,"t":"you being enriched in everything for all generosity, which produces thanksgiving to God through us."},{"v":12,"t":"For this service of giving that you perform not only makes up for lack among the saints, but abounds also through much giving of thanks to God,"},{"v":13,"t":"seeing that through the proof given by this service, they glorify God for the obedience of your confession to the Good News of Christ and for the generosity of your contribution to them and to all,"},{"v":14,"t":"while they themselves also, with supplication on your behalf, yearn for you by reason of the exceeding grace of God in you."},{"v":15,"t":"Now thanks be to God for his unspeakable gift!"}]},"10":{"en":[{"v":1,"t":"Now I Paul, myself, entreat you by the humility and gentleness of Christ, I who in your presence am lowly among you, but being absent am bold toward you."},{"v":2,"t":"Yes, I beg you that I may not, when present, show courage with the confidence with which I intend to be bold against some, who consider us to be walking according to the flesh."},{"v":3,"t":"For though we walk in the flesh, we don’t wage war according to the flesh;"},{"v":4,"t":"for the weapons of our warfare are not of the flesh, but mighty before God to the throwing down of strongholds,"},{"v":5,"t":"throwing down imaginations and every high thing that is exalted against the knowledge of God and bringing every thought into captivity to the obedience of Christ,"},{"v":6,"t":"and being in readiness to avenge all disobedience when your obedience is made full."},{"v":7,"t":"Do you look at things only as they appear in front of your face? If anyone trusts in himself that he is Christ’s, let him consider this again with himself, that even as he is Christ’s, so we also are Christ’s."},{"v":8,"t":"For even if I boast somewhat abundantly concerning our authority, which the Lord gave for building you up and not for casting you down, I will not be ashamed,"},{"v":9,"t":"that I may not seem as if I desire to terrify you by my letters."},{"v":10,"t":"For, “His letters”, they say, “are weighty and strong, but his bodily presence is weak, and his speech is despised.”"},{"v":11,"t":"Let such a person consider this, that what we are in word by letters when we are absent, such are we also in deed when we are present."},{"v":12,"t":"For we are not bold to number or compare ourselves with some of those who commend themselves. But they themselves, measuring themselves by themselves, and comparing themselves with themselves, are without understanding."},{"v":13,"t":"But we will not boast beyond proper limits, but within the boundaries with which God appointed to us, which reach even to you."},{"v":14,"t":"For we don’t stretch ourselves too much, as though we didn’t reach to you. For we came even as far as to you with the Good News of Christ,"},{"v":15,"t":"not boasting beyond proper limits in other men’s labors, but having hope that as your faith grows, we will be abundantly enlarged by you in our sphere of influence,"},{"v":16,"t":"so as to preach the Good News even to the parts beyond you, not to boast in what someone else has already done."},{"v":17,"t":"But “he who boasts, let him boast in the Lord.”"},{"v":18,"t":"For it isn’t he who commends himself who is approved, but whom the Lord commends."}]},"11":{"en":[{"v":1,"t":"I wish that you would bear with me in a little foolishness, but indeed you do bear with me."},{"v":2,"t":"For I am jealous over you with a godly jealousy. For I promised you in marriage to one husband, that I might present you as a pure virgin to Christ."},{"v":3,"t":"But I am afraid that somehow, as the serpent deceived Eve in his craftiness, so your minds might be corrupted from the simplicity that is in Christ."},{"v":4,"t":"For if he who comes preaches another Jesus whom we didn’t preach, or if you receive a different spirit which you didn’t receive, or a different “good news” which you didn’t accept, you put up with that well enough."},{"v":5,"t":"For I reckon that I am not at all behind the very best apostles."},{"v":6,"t":"But though I am unskilled in speech, yet I am not unskilled in knowledge. No, in every way we have been revealed to you in all things."},{"v":7,"t":"Or did I commit a sin in humbling myself that you might be exalted, because I preached to you God’s Good News free of charge?"},{"v":8,"t":"I robbed other assemblies, taking wages from them that I might serve you."},{"v":9,"t":"When I was present with you and was in need, I wasn’t a burden on anyone, for the brothers, when they came from Macedonia, supplied the measure of my need. In everything I kept myself from being burdensome to you, and I will continue to do so."},{"v":10,"t":"As the truth of Christ is in me, no one will stop me from this boasting in the regions of Achaia."},{"v":11,"t":"Why? Because I don’t love you? God knows."},{"v":12,"t":"But what I do, that I will continue to do, that I may cut off opportunity from those who desire an opportunity, that in which they boast, they may be recognized just like us."},{"v":13,"t":"For such men are false apostles, deceitful workers, masquerading as Christ’s apostles."},{"v":14,"t":"And no wonder, for even Satan masquerades as an angel of light."},{"v":15,"t":"It is no great thing therefore if his servants also masquerade as servants of righteousness, whose end will be according to their works."},{"v":16,"t":"I say again, let no one think me foolish. But if so, yet receive me as foolish, that I also may boast a little."},{"v":17,"t":"That which I speak, I don’t speak according to the Lord, but as in foolishness, in this confidence of boasting."},{"v":18,"t":"Seeing that many boast after the flesh, I will also boast."},{"v":19,"t":"For you bear with the foolish gladly, being wise."},{"v":20,"t":"For you bear with a man if he brings you into bondage, if he devours you, if he takes you captive, if he exalts himself, or if he strikes you on the face."},{"v":21,"t":"To my shame, I speak as though we had been weak. Yet in whatever way anyone is bold (I speak in foolishness), I am bold also."},{"v":22,"t":"Are they Hebrews? So am I. Are they Israelites? So am I. Are they the offspring of Abraham? So am I."},{"v":23,"t":"Are they servants of Christ? (I speak as one beside himself.) I am more so: in labors more abundantly, in prisons more abundantly, in stripes above measure, and in deaths often."},{"v":24,"t":"Five times I received forty stripes minus one from the Jews."},{"v":25,"t":"Three times I was beaten with rods. Once I was stoned. Three times I suffered shipwreck. I have been a night and a day in the deep."},{"v":26,"t":"I have been in travels often, perils of rivers, perils of robbers, perils from my countrymen, perils from the Gentiles, perils in the city, perils in the wilderness, perils in the sea, perils among false brothers;"},{"v":27,"t":"in labor and travail, in watchings often, in hunger and thirst, in fastings often, and in cold and nakedness."},{"v":28,"t":"Besides those things that are outside, there is that which presses on me daily: anxiety for all the assemblies."},{"v":29,"t":"Who is weak, and I am not weak? Who is caused to stumble, and I don’t burn with indignation?"},{"v":30,"t":"If I must boast, I will boast of the things that concern my weakness."},{"v":31,"t":"The God and Father of the Lord Jesus Christ, he who is blessed forever more, knows that I don’t lie."},{"v":32,"t":"In Damascus the governor under King Aretas guarded the Damascenes’ city, desiring to arrest me."},{"v":33,"t":"I was let down in a basket through a window by the wall, and escaped his hands."}]},"12":{"en":[{"v":1,"t":"It is doubtless not profitable for me to boast, but I will come to visions and revelations of the Lord."},{"v":2,"t":"I know a man in Christ who was caught up into the third heaven fourteen years ago—whether in the body, I don’t know, or whether out of the body, I don’t know; God knows."},{"v":3,"t":"I know such a man (whether in the body, or outside of the body, I don’t know; God knows),"},{"v":4,"t":"how he was caught up into Paradise and heard unspeakable words, which it is not lawful for a man to utter."},{"v":5,"t":"On behalf of such a one I will boast, but on my own behalf I will not boast, except in my weaknesses."},{"v":6,"t":"For if I would desire to boast, I will not be foolish; for I will speak the truth. But I refrain, so that no man may think more of me than that which he sees in me or hears from me."},{"v":7,"t":"By reason of the exceeding greatness of the revelations, that I should not be exalted excessively, a thorn in the flesh was given to me: a messenger of Satan to torment me, that I should not be exalted excessively."},{"v":8,"t":"Concerning this thing, I begged the Lord three times that it might depart from me."},{"v":9,"t":"He has said to me, “My grace is sufficient for you, for my power is made perfect in weakness.” Most gladly therefore I will rather glory in my weaknesses, that the power of Christ may rest on me."},{"v":10,"t":"Therefore I take pleasure in weaknesses, in injuries, in necessities, in persecutions, and in distresses, for Christ’s sake. For when I am weak, then am I strong."},{"v":11,"t":"I have become foolish in boasting. You compelled me, for I ought to have been commended by you, for I am in no way inferior to the very best apostles, though I am nothing."},{"v":12,"t":"Truly the signs of an apostle were worked among you in all perseverance, in signs and wonders and mighty works."},{"v":13,"t":"For what is there in which you were made inferior to the rest of the assemblies, unless it is that I myself was not a burden to you? Forgive me this wrong!"},{"v":14,"t":"Behold, this is the third time I am ready to come to you, and I will not be a burden to you; for I seek not your possessions, but you. For the children ought not to save up for the parents, but the parents for the children."},{"v":15,"t":"I will most gladly spend and be spent for your souls. If I love you more abundantly, am I loved the less?"},{"v":16,"t":"Even so, I myself didn’t burden you. But you might say that being crafty, I caught you with deception."},{"v":17,"t":"Did I take advantage of you by anyone of those whom I have sent to you?"},{"v":18,"t":"I exhorted Titus, and I sent the brother with him. Did Titus take any advantage of you? Didn’t we walk in the same spirit? Didn’t we walk in the same steps?"},{"v":19,"t":"Again, do you think that we are excusing ourselves to you? In the sight of God we speak in Christ. But all things, beloved, are for your edifying."},{"v":20,"t":"For I am afraid that perhaps when I come, I might find you not the way I want to, and that I might be found by you as you don’t desire, that perhaps there would be strife, jealousy, outbursts of anger, factions, slander, whisperings, proud thoughts, or riots,"},{"v":21,"t":"that again when I come my God would humble me before you, and I would mourn for many of those who have sinned before now, and not repented of the uncleanness, sexual immorality, and lustfulness which they committed."}]},"13":{"en":[{"v":1,"t":"This is the third time I am coming to you. “At the mouth of two or three witnesses shall every word be established.”"},{"v":2,"t":"I have warned previously, and I warn again, as when I was present the second time, so now, being absent, I write to those who have sinned before now and to all the rest that if I come again, I will not spare,"},{"v":3,"t":"seeing that you seek a proof of Christ who speaks in me who is not weak, but is powerful in you."},{"v":4,"t":"For he was crucified through weakness, yet he lives through the power of God. For we also are weak in him, but we will live with him through the power of God toward you."},{"v":5,"t":"Examine your own selves, whether you are in the faith. Test your own selves. Or don’t you know about your own selves, that Jesus Christ is in you?—unless indeed you are disqualified."},{"v":6,"t":"But I hope that you will know that we aren’t disqualified."},{"v":7,"t":"Now I pray to God that you do no evil; not that we may appear approved, but that you may do that which is honorable, though we may seem to have failed."},{"v":8,"t":"For we can do nothing against the truth, but for the truth."},{"v":9,"t":"For we rejoice when we are weak and you are strong. We also pray for this: your becoming perfect."},{"v":10,"t":"For this cause I write these things while absent, that I may not deal sharply when present, according to the authority which the Lord gave me for building up and not for tearing down."},{"v":11,"t":"Finally, brothers, rejoice! Be perfected. Be comforted. Be of the same mind. Live in peace, and the God of love and peace will be with you."},{"v":12,"t":"Greet one another with a holy kiss."},{"v":13,"t":"All the saints greet you."}]}},"GAL":{"1":{"en":[{"v":1,"t":"Paul, an apostle—not from men, nor through man, but through Jesus Christ, and God the Father, who raised him from the dead—"},{"v":2,"t":"and all the brothers who are with me, to the assemblies of Galatia:"},{"v":3,"t":"Grace to you and peace from God the Father and our Lord Jesus Christ,"},{"v":4,"t":"who gave himself for our sins, that he might deliver us out of this present evil age, according to the will of our God and Father—"},{"v":5,"t":"to whom be the glory forever and ever. Amen."},{"v":6,"t":"I marvel that you are so quickly deserting him who called you in the grace of Christ to a different “good news”,"},{"v":7,"t":"but there isn’t another “good news.” Only there are some who trouble you and want to pervert the Good News of Christ."},{"v":8,"t":"But even though we, or an angel from heaven, should preach to you any “good news” other than that which we preached to you, let him be cursed."},{"v":9,"t":"As we have said before, so I now say again: if any man preaches to you any “good news” other than that which you received, let him be cursed."},{"v":10,"t":"For am I now seeking the favor of men, or of God? Or am I striving to please men? For if I were still pleasing men, I wouldn’t be a servant of Christ."},{"v":11,"t":"But I make known to you, brothers, concerning the Good News which was preached by me, that it is not according to man."},{"v":12,"t":"For I didn’t receive it from man, nor was I taught it, but it came to me through revelation of Jesus Christ."},{"v":13,"t":"For you have heard of my way of living in time past in the Jews’ religion, how that beyond measure I persecuted the assembly of God and ravaged it."},{"v":14,"t":"I advanced in the Jews’ religion beyond many of my own age among my countrymen, being more exceedingly zealous for the traditions of my fathers."},{"v":15,"t":"But when it was the good pleasure of God, who separated me from my mother’s womb and called me through his grace,"},{"v":16,"t":"to reveal his Son in me, that I might preach him among the Gentiles, I didn’t immediately confer with flesh and blood,"},{"v":17,"t":"nor did I go up to Jerusalem to those who were apostles before me, but I went away into Arabia. Then I returned to Damascus."},{"v":18,"t":"Then after three years I went up to Jerusalem to visit Peter, and stayed with him fifteen days."},{"v":19,"t":"But of the other apostles I saw no one except James, the Lord’s brother."},{"v":20,"t":"Now about the things which I write to you, behold, before God, I’m not lying."},{"v":21,"t":"Then I came to the regions of Syria and Cilicia."},{"v":22,"t":"I was still unknown by face to the assemblies of Judea which were in Christ,"},{"v":23,"t":"but they only heard, “He who once persecuted us now preaches the faith that he once tried to destroy.”"},{"v":24,"t":"So they glorified God in me."}]},"2":{"en":[{"v":1,"t":"Then after a period of fourteen years I went up again to Jerusalem with Barnabas, taking Titus also with me."},{"v":2,"t":"I went up by revelation, and I laid before them the Good News which I preach among the Gentiles, but privately before those who were respected, for fear that I might be running, or had run, in vain."},{"v":3,"t":"But not even Titus, who was with me, being a Greek, was compelled to be circumcised."},{"v":4,"t":"This was because of the false brothers secretly brought in, who stole in to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage,"},{"v":5,"t":"to whom we gave no place in the way of subjection, not for an hour, that the truth of the Good News might continue with you."},{"v":6,"t":"But from those who were reputed to be important—whatever they were, it makes no difference to me; God doesn’t show partiality to man—they, I say, who were respected imparted nothing to me,"},{"v":7,"t":"but to the contrary, when they saw that I had been entrusted with the Good News for the uncircumcised, even as Peter with the Good News for the circumcised—"},{"v":8,"t":"for he who worked through Peter in the apostleship with the circumcised also worked through me with the Gentiles—"},{"v":9,"t":"and when they perceived the grace that was given to me, James and Cephas and John, those who were reputed to be pillars, gave to Barnabas and me the right hand of fellowship, that we should go to the Gentiles, and they to the circumcision."},{"v":10,"t":"They only asked us to remember the poor—which very thing I was also zealous to do."},{"v":11,"t":"But when Peter came to Antioch, I resisted him to his face, because he stood condemned."},{"v":12,"t":"For before some people came from James, he ate with the Gentiles. But when they came, he drew back and separated himself, fearing those who were of the circumcision."},{"v":13,"t":"And the rest of the Jews joined him in his hypocrisy, so that even Barnabas was carried away with their hypocrisy."},{"v":14,"t":"But when I saw that they didn’t walk uprightly according to the truth of the Good News, I said to Peter before them all, “If you, being a Jew, live as the Gentiles do, and not as the Jews do, why do you compel the Gentiles to live as the Jews do?"},{"v":15,"t":"“We, being Jews by nature and not Gentile sinners,"},{"v":16,"t":"yet knowing that a man is not justified by the works of the law but through faith in Jesus Christ, even we believed in Christ Jesus, that we might be justified by faith in Christ and not by the works of the law, because no flesh will be justified by the works of the law."},{"v":17,"t":"But if while we sought to be justified in Christ, we ourselves also were found sinners, is Christ a servant of sin? Certainly not!"},{"v":18,"t":"For if I build up again those things which I destroyed, I prove myself a law-breaker."},{"v":19,"t":"For I through the law died to the law, that I might live to God."},{"v":20,"t":"I have been crucified with Christ, and it is no longer I who live, but Christ lives in me. That life which I now live in the flesh, I live by faith in the Son of God, who loved me and gave himself up for me."},{"v":21,"t":"I don’t reject the grace of God. For if righteousness is through the law, then Christ died for nothing!”"}]},"3":{"en":[{"v":1,"t":"Foolish Galatians, who has bewitched you not to obey the truth, before whose eyes Jesus Christ was openly portrayed among you as crucified?"},{"v":2,"t":"I just want to learn this from you: Did you receive the Spirit by the works of the law, or by hearing of faith?"},{"v":3,"t":"Are you so foolish? Having begun in the Spirit, are you now completed in the flesh?"},{"v":4,"t":"Did you suffer so many things in vain, if it is indeed in vain?"},{"v":5,"t":"He therefore who supplies the Spirit to you and does miracles among you, does he do it by the works of the law, or by hearing of faith?"},{"v":6,"t":"Even so, Abraham “believed God, and it was counted to him for righteousness.”"},{"v":7,"t":"Know therefore that those who are of faith are children of Abraham."},{"v":8,"t":"The Scripture, foreseeing that God would justify the Gentiles by faith, preached the Good News beforehand to Abraham, saying, “In you all the nations will be blessed.”"},{"v":9,"t":"So then, those who are of faith are blessed with the faithful Abraham."},{"v":10,"t":"For as many as are of the works of the law are under a curse. For it is written, “Cursed is everyone who doesn’t continue in all things that are written in the book of the law, to do them.”"},{"v":11,"t":"Now that no man is justified by the law before God is evident, for, “The righteous will live by faith.”"},{"v":12,"t":"The law is not of faith, but, “The man who does them will live by them.”"},{"v":13,"t":"Christ redeemed us from the curse of the law, having become a curse for us. For it is written, “Cursed is everyone who hangs on a tree,”"},{"v":14,"t":"that the blessing of Abraham might come on the Gentiles through Christ Jesus, that we might receive the promise of the Spirit through faith."},{"v":15,"t":"Brothers, speaking of human terms, though it is only a man’s covenant, yet when it has been confirmed, no one makes it void or adds to it."},{"v":16,"t":"Now the promises were spoken to Abraham and to his offspring. He doesn’t say, “To descendants”, as of many, but as of one, “To your offspring”, which is Christ."},{"v":17,"t":"Now I say this: A covenant confirmed beforehand by God in Christ, the law, which came four hundred thirty years after, does not annul, so as to make the promise of no effect."},{"v":18,"t":"For if the inheritance is of the law, it is no more of promise; but God has granted it to Abraham by promise."},{"v":19,"t":"Then why is there the law? It was added because of transgressions, until the offspring should come to whom the promise has been made. It was ordained through angels by the hand of a mediator."},{"v":20,"t":"Now a mediator is not between one, but God is one."},{"v":21,"t":"Is the law then against the promises of God? Certainly not! For if there had been a law given which could make alive, most certainly righteousness would have been of the law."},{"v":22,"t":"But the Scripture imprisoned all things under sin, that the promise by faith in Jesus Christ might be given to those who believe."},{"v":23,"t":"But before faith came, we were kept in custody under the law, confined for the faith which should afterwards be revealed."},{"v":24,"t":"So that the law has become our tutor to bring us to Christ, that we might be justified by faith."},{"v":25,"t":"But now that faith has come, we are no longer under a tutor."},{"v":26,"t":"For you are all children of God, through faith in Christ Jesus."},{"v":27,"t":"For as many of you as were baptized into Christ have put on Christ."},{"v":28,"t":"There is neither Jew nor Greek, there is neither slave nor free man, there is neither male nor female; for you are all one in Christ Jesus."},{"v":29,"t":"If you are Christ’s, then you are Abraham’s offspring and heirs according to promise."}]},"4":{"en":[{"v":1,"t":"But I say that so long as the heir is a child, he is no different from a bondservant, though he is lord of all,"},{"v":2,"t":"but is under guardians and stewards until the day appointed by the father."},{"v":3,"t":"So we also, when we were children, were held in bondage under the elemental principles of the world."},{"v":4,"t":"But when the fullness of the time came, God sent out his Son, born to a woman, born under the law,"},{"v":5,"t":"that he might redeem those who were under the law, that we might receive the adoption as children."},{"v":6,"t":"And because you are children, God sent out the Spirit of his Son into your hearts, crying, “Abba, Father!”"},{"v":7,"t":"So you are no longer a bondservant, but a son; and if a son, then an heir of God through Christ."},{"v":8,"t":"However at that time, not knowing God, you were in bondage to those who by nature are not gods."},{"v":9,"t":"But now that you have come to know God, or rather to be known by God, why do you turn back again to the weak and miserable elemental principles, to which you desire to be in bondage all over again?"},{"v":10,"t":"You observe days, months, seasons, and years."},{"v":11,"t":"I am afraid for you, that I might have wasted my labor for you."},{"v":12,"t":"I beg you, brothers, become as I am, for I also have become as you are. You did me no wrong,"},{"v":13,"t":"but you know that because of weakness in the flesh I preached the Good News to you the first time."},{"v":14,"t":"That which was a temptation to you in my flesh, you didn’t despise nor reject; but you received me as an angel of God, even as Christ Jesus."},{"v":15,"t":"What was the blessing you enjoyed? For I testify to you that, if possible, you would have plucked out your eyes and given them to me."},{"v":16,"t":"So then, have I become your enemy by telling you the truth?"},{"v":17,"t":"They zealously seek you in no good way. No, they desire to alienate you, that you may seek them."},{"v":18,"t":"But it is always good to be zealous in a good cause, and not only when I am present with you."},{"v":19,"t":"My little children, of whom I am again in travail until Christ is formed in you—"},{"v":20,"t":"but I could wish to be present with you now, and to change my tone, for I am perplexed about you."},{"v":21,"t":"Tell me, you that desire to be under the law, don’t you listen to the law?"},{"v":22,"t":"For it is written that Abraham had two sons, one by the servant, and one by the free woman."},{"v":23,"t":"However, the son by the servant was born according to the flesh, but the son by the free woman was born through promise."},{"v":24,"t":"These things contain an allegory, for these are two covenants. One is from Mount Sinai, bearing children to bondage, which is Hagar."},{"v":25,"t":"For this Hagar is Mount Sinai in Arabia, and answers to the Jerusalem that exists now, for she is in bondage with her children."},{"v":26,"t":"But the Jerusalem that is above is free, which is the mother of us all."},{"v":27,"t":"For it is written, “Rejoice, you barren who don’t bear. Break out and shout, you who don’t travail. For the desolate women have more children than her who has a husband.”"},{"v":28,"t":"Now we, brothers, as Isaac was, are children of promise."},{"v":29,"t":"But as then, he who was born according to the flesh persecuted him who was born according to the Spirit, so also it is now."},{"v":30,"t":"However, what does the Scripture say? “Throw out the servant and her son, for the son of the servant will not inherit with the son of the free woman.”"},{"v":31,"t":"So then, brothers, we are not children of a servant, but of the free woman."}]},"5":{"en":[{"v":1,"t":"Stand firm therefore in the liberty by which Christ has made us free, and don’t be entangled again with a yoke of bondage."},{"v":2,"t":"Behold, I, Paul, tell you that if you receive circumcision, Christ will profit you nothing."},{"v":3,"t":"Yes, I testify again to every man who receives circumcision that he is a debtor to do the whole law."},{"v":4,"t":"You are alienated from Christ, you who desire to be justified by the law. You have fallen away from grace."},{"v":5,"t":"For we through the Spirit, by faith wait for the hope of righteousness."},{"v":6,"t":"For in Christ Jesus neither circumcision nor uncircumcision amounts to anything, but faith working through love."},{"v":7,"t":"You were running well! Who interfered with you that you should not obey the truth?"},{"v":8,"t":"This persuasion is not from him who calls you."},{"v":9,"t":"A little yeast grows through the whole lump."},{"v":10,"t":"I have confidence toward you in the Lord that you will think no other way. But he who troubles you will bear his judgment, whoever he is."},{"v":11,"t":"But I, brothers, if I still preach circumcision, why am I still persecuted? Then the stumbling block of the cross has been removed."},{"v":12,"t":"I wish that those who disturb you would cut themselves off."},{"v":13,"t":"For you, brothers, were called for freedom. Only don’t use your freedom as an opportunity for the flesh, but through love be servants to one another."},{"v":14,"t":"For the whole law is fulfilled in one word, in this: “You shall love your neighbor as yourself.”"},{"v":15,"t":"But if you bite and devour one another, be careful that you don’t consume one another."},{"v":16,"t":"But I say, walk by the Spirit, and you won’t fulfill the lust of the flesh."},{"v":17,"t":"For the flesh lusts against the Spirit, and the Spirit against the flesh; and these are contrary to one another, that you may not do the things that you desire."},{"v":18,"t":"But if you are led by the Spirit, you are not under the law."},{"v":19,"t":"Now the deeds of the flesh are obvious, which are: adultery, sexual immorality, uncleanness, lustfulness,"},{"v":20,"t":"idolatry, sorcery, hatred, strife, jealousies, outbursts of anger, rivalries, divisions, heresies,"},{"v":21,"t":"envy, murders, drunkenness, orgies, and things like these; of which I forewarn you, even as I also forewarned you, that those who practice such things will not inherit God’s Kingdom."},{"v":22,"t":"But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faith,"},{"v":23,"t":"gentleness, and self-control. Against such things there is no law."},{"v":24,"t":"Those who belong to Christ have crucified the flesh with its passions and lusts."},{"v":25,"t":"If we live by the Spirit, let’s also walk by the Spirit."},{"v":26,"t":"Let’s not become conceited, provoking one another, and envying one another."}]},"6":{"en":[{"v":1,"t":"Brothers, even if a man is caught in some fault, you who are spiritual must restore such a one in a spirit of gentleness, looking to yourself so that you also aren’t tempted."},{"v":2,"t":"Bear one another’s burdens, and so fulfill the law of Christ."},{"v":3,"t":"For if a man thinks himself to be something when he is nothing, he deceives himself."},{"v":4,"t":"But let each man examine his own work, and then he will have reason to boast in himself, and not in someone else."},{"v":5,"t":"For each man will bear his own burden."},{"v":6,"t":"But let him who is taught in the word share all good things with him who teaches."},{"v":7,"t":"Don’t be deceived. God is not mocked, for whatever a man sows, that he will also reap."},{"v":8,"t":"For he who sows to his own flesh will from the flesh reap corruption. But he who sows to the Spirit will from the Spirit reap eternal life."},{"v":9,"t":"Let’s not be weary in doing good, for we will reap in due season if we don’t give up."},{"v":10,"t":"So then, as we have opportunity, let’s do what is good toward all men, and especially toward those who are of the household of the faith."},{"v":11,"t":"See with what large letters I write to you with my own hand."},{"v":12,"t":"As many as desire to make a good impression in the flesh compel you to be circumcised, just so they may not be persecuted for the cross of Christ."},{"v":13,"t":"For even they who receive circumcision don’t keep the law themselves, but they desire to have you circumcised, so that they may boast in your flesh."},{"v":14,"t":"But far be it from me to boast except in the cross of our Lord Jesus Christ, through which the world has been crucified to me, and I to the world."},{"v":15,"t":"For in Christ Jesus neither is circumcision anything, nor uncircumcision, but a new creation."},{"v":16,"t":"As many as walk by this rule, peace and mercy be on them, and on God’s Israel."},{"v":17,"t":"From now on, let no one cause me any trouble, for I bear the marks of the Lord Jesus branded on my body."},{"v":18,"t":"The grace of our Lord Jesus Christ be with your spirit, brothers. Amen."}]}},"EPH":{"1":{"en":[{"v":1,"t":"Paul, an apostle of Christ Jesus through the will of God, to the saints who are at Ephesus, and the faithful in Christ Jesus:"},{"v":2,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"Blessed be the God and Father of our Lord Jesus Christ, who has blessed us with every spiritual blessing in the heavenly places in Christ,"},{"v":4,"t":"even as he chose us in him before the foundation of the world, that we would be holy and without defect before him in love,"},{"v":5,"t":"having predestined us for adoption as children through Jesus Christ to himself, according to the good pleasure of his desire,"},{"v":6,"t":"to the praise of the glory of his grace, by which he freely gave us favor in the Beloved."},{"v":7,"t":"In him we have our redemption through his blood, the forgiveness of our trespasses, according to the riches of his grace"},{"v":8,"t":"which he made to abound toward us in all wisdom and prudence,"},{"v":9,"t":"making known to us the mystery of his will, according to his good pleasure which he purposed in him"},{"v":10,"t":"to an administration of the fullness of the times, to sum up all things in Christ, the things in the heavens and the things on the earth, in him."},{"v":11,"t":"We were also assigned an inheritance in him, having been foreordained according to the purpose of him who does all things after the counsel of his will,"},{"v":12,"t":"to the end that we should be to the praise of his glory, we who had before hoped in Christ."},{"v":13,"t":"In him you also, having heard the word of the truth, the Good News of your salvation—in whom, having also believed, you were sealed with the promised Holy Spirit,"},{"v":14,"t":"who is a pledge of our inheritance, to the redemption of God’s own possession, to the praise of his glory."},{"v":15,"t":"For this cause I also, having heard of the faith in the Lord Jesus which is among you and the love which you have toward all the saints,"},{"v":16,"t":"don’t cease to give thanks for you, making mention of you in my prayers,"},{"v":17,"t":"that the God of our Lord Jesus Christ, the Father of glory, may give to you a spirit of wisdom and revelation in the knowledge of him,"},{"v":18,"t":"having the eyes of your hearts enlightened, that you may know what is the hope of his calling, and what are the riches of the glory of his inheritance in the saints,"},{"v":19,"t":"and what is the exceeding greatness of his power toward us who believe, according to that working of the strength of his might"},{"v":20,"t":"which he worked in Christ when he raised him from the dead and made him to sit at his right hand in the heavenly places,"},{"v":21,"t":"far above all rule, authority, power, dominion, and every name that is named, not only in this age, but also in that which is to come."},{"v":22,"t":"He put all things in subjection under his feet, and gave him to be head over all things for the assembly,"},{"v":23,"t":"which is his body, the fullness of him who fills all in all."}]},"2":{"en":[{"v":1,"t":"You were made alive when you were dead in transgressions and sins,"},{"v":2,"t":"in which you once walked according to the course of this world, according to the prince of the power of the air, the spirit who now works in the children of disobedience."},{"v":3,"t":"We also all once lived among them in the lusts of our flesh, doing the desires of the flesh and of the mind, and were by nature children of wrath, even as the rest."},{"v":4,"t":"But God, being rich in mercy, for his great love with which he loved us,"},{"v":5,"t":"even when we were dead through our trespasses, made us alive together with Christ—by grace you have been saved—"},{"v":6,"t":"and raised us up with him, and made us to sit with him in the heavenly places in Christ Jesus,"},{"v":7,"t":"that in the ages to come he might show the exceeding riches of his grace in kindness toward us in Christ Jesus;"},{"v":8,"t":"for by grace you have been saved through faith, and that not of yourselves; it is the gift of God,"},{"v":9,"t":"not of works, that no one would boast."},{"v":10,"t":"For we are his workmanship, created in Christ Jesus for good works, which God prepared before that we would walk in them."},{"v":11,"t":"Therefore remember that once you, the Gentiles in the flesh, who are called “uncircumcision” by that which is called “circumcision” (in the flesh, made by hands),"},{"v":12,"t":"that you were at that time separate from Christ, alienated from the commonwealth of Israel, and strangers from the covenants of the promise, having no hope and without God in the world."},{"v":13,"t":"But now in Christ Jesus you who once were far off are made near in the blood of Christ."},{"v":14,"t":"For he is our peace, who made both one, and broke down the middle wall of separation,"},{"v":15,"t":"having abolished in his flesh the hostility, the law of commandments contained in ordinances, that he might create in himself one new man of the two, making peace,"},{"v":16,"t":"and might reconcile them both in one body to God through the cross, having killed the hostility through it."},{"v":17,"t":"He came and preached peace to you who were far off and to those who were near."},{"v":18,"t":"For through him we both have our access in one Spirit to the Father."},{"v":19,"t":"So then you are no longer strangers and foreigners, but you are fellow citizens with the saints and of the household of God,"},{"v":20,"t":"being built on the foundation of the apostles and prophets, Christ Jesus himself being the chief cornerstone;"},{"v":21,"t":"in whom the whole building, fitted together, grows into a holy temple in the Lord;"},{"v":22,"t":"in whom you also are built together for a habitation of God in the Spirit."}]},"3":{"en":[{"v":1,"t":"For this cause I, Paul, am the prisoner of Christ Jesus on behalf of you Gentiles,"},{"v":2,"t":"if it is so that you have heard of the administration of that grace of God which was given me toward you,"},{"v":3,"t":"how that by revelation the mystery was made known to me, as I wrote before in few words,"},{"v":4,"t":"by which, when you read, you can perceive my understanding in the mystery of Christ,"},{"v":5,"t":"which in other generations was not made known to the children of men, as it has now been revealed to his holy apostles and prophets in the Spirit,"},{"v":6,"t":"that the Gentiles are fellow heirs and fellow members of the body, and fellow partakers of his promise in Christ Jesus through the Good News,"},{"v":7,"t":"of which I was made a servant according to the gift of that grace of God which was given me according to the working of his power."},{"v":8,"t":"To me, the very least of all saints, was this grace given, to preach to the Gentiles the unsearchable riches of Christ,"},{"v":9,"t":"and to make all men see what is the administration of the mystery which for ages has been hidden in God, who created all things through Jesus Christ,"},{"v":10,"t":"to the intent that now through the assembly the manifold wisdom of God might be made known to the principalities and the powers in the heavenly places,"},{"v":11,"t":"according to the eternal purpose which he accomplished in Christ Jesus our Lord."},{"v":12,"t":"In him we have boldness and access in confidence through our faith in him."},{"v":13,"t":"Therefore I ask that you may not lose heart at my troubles for you, which are your glory."},{"v":14,"t":"For this cause, I bow my knees to the Father of our Lord Jesus Christ,"},{"v":15,"t":"from whom every family in heaven and on earth is named,"},{"v":16,"t":"that he would grant you, according to the riches of his glory, that you may be strengthened with power through his Spirit in the inner person,"},{"v":17,"t":"that Christ may dwell in your hearts through faith, to the end that you, being rooted and grounded in love,"},{"v":18,"t":"may be strengthened to comprehend with all the saints what is the width and length and height and depth,"},{"v":19,"t":"and to know Christ’s love which surpasses knowledge, that you may be filled with all the fullness of God."},{"v":20,"t":"Now to him who is able to do exceedingly abundantly above all that we ask or think, according to the power that works in us,"},{"v":21,"t":"to him be the glory in the assembly and in Christ Jesus to all generations, forever and ever. Amen."}]},"4":{"en":[{"v":1,"t":"I therefore, the prisoner in the Lord, beg you to walk worthily of the calling with which you were called,"},{"v":2,"t":"with all lowliness and humility, with patience, bearing with one another in love,"},{"v":3,"t":"being eager to keep the unity of the Spirit in the bond of peace."},{"v":4,"t":"There is one body and one Spirit, even as you also were called in one hope of your calling,"},{"v":5,"t":"one Lord, one faith, one baptism,"},{"v":6,"t":"one God and Father of all, who is over all and through all and in us all."},{"v":7,"t":"But to each one of us, the grace was given according to the measure of the gift of Christ."},{"v":8,"t":"Therefore he says, “When he ascended on high, he led captivity captive, and gave gifts to people.”"},{"v":9,"t":"Now this, “He ascended”, what is it but that he also first descended into the lower parts of the earth?"},{"v":10,"t":"He who descended is the one who also ascended far above all the heavens, that he might fill all things."},{"v":11,"t":"He gave some to be apostles; and some, prophets; and some, evangelists; and some, shepherds and teachers;"},{"v":12,"t":"for the perfecting of the saints, to the work of serving, to the building up of the body of Christ,"},{"v":13,"t":"until we all attain to the unity of the faith and of the knowledge of the Son of God, to a full grown man, to the measure of the stature of the fullness of Christ,"},{"v":14,"t":"that we may no longer be children, tossed back and forth and carried about with every wind of doctrine, by the trickery of men, in craftiness, after the wiles of error;"},{"v":15,"t":"but speaking truth in love, we may grow up in all things into him who is the head, Christ,"},{"v":16,"t":"from whom all the body, being fitted and knit together through that which every joint supplies, according to the working in measure of each individual part, makes the body increase to the building up of itself in love."},{"v":17,"t":"This I say therefore, and testify in the Lord, that you no longer walk as the rest of the Gentiles also walk, in the futility of their mind,"},{"v":18,"t":"being darkened in their understanding, alienated from the life of God because of the ignorance that is in them, because of the hardening of their hearts."},{"v":19,"t":"They, having become callous, gave themselves up to lust, to work all uncleanness with greediness."},{"v":20,"t":"But you didn’t learn Christ that way,"},{"v":21,"t":"if indeed you heard him and were taught in him, even as truth is in Jesus:"},{"v":22,"t":"that you put away, as concerning your former way of life, the old man that grows corrupt after the lusts of deceit,"},{"v":23,"t":"and that you be renewed in the spirit of your mind,"},{"v":24,"t":"and put on the new man, who in the likeness of God has been created in righteousness and holiness of truth."},{"v":25,"t":"Therefore, putting away falsehood, speak truth each one with his neighbor, for we are members of one another."},{"v":26,"t":"“Be angry, and don’t sin.” Don’t let the sun go down on your wrath,"},{"v":27,"t":"and don’t give place to the devil."},{"v":28,"t":"Let him who stole steal no more; but rather let him labor, producing with his hands something that is good, that he may have something to give to him who has need."},{"v":29,"t":"Let no corrupt speech proceed out of your mouth, but only what is good for building others up as the need may be, that it may give grace to those who hear."},{"v":30,"t":"Don’t grieve the Holy Spirit of God, in whom you were sealed for the day of redemption."},{"v":31,"t":"Let all bitterness, wrath, anger, outcry, and slander be put away from you, with all malice."},{"v":32,"t":"And be kind to one another, tender hearted, forgiving each other, just as God also in Christ forgave you."}]},"5":{"en":[{"v":1,"t":"Be therefore imitators of God, as beloved children."},{"v":2,"t":"Walk in love, even as Christ also loved us and gave himself up for us, an offering and a sacrifice to God for a sweet-smelling fragrance."},{"v":3,"t":"But sexual immorality, and all uncleanness or covetousness, let it not even be mentioned among you, as becomes saints;"},{"v":4,"t":"nor filthiness, nor foolish talking, nor jesting, which are not appropriate, but rather giving of thanks."},{"v":5,"t":"Know this for sure, that no sexually immoral person, nor unclean person, nor covetous man (who is an idolater), has any inheritance in the Kingdom of Christ and God."},{"v":6,"t":"Let no one deceive you with empty words, for because of these things the wrath of God comes on the children of disobedience."},{"v":7,"t":"Therefore don’t be partakers with them."},{"v":8,"t":"For you were once darkness, but are now light in the Lord. Walk as children of light,"},{"v":9,"t":"for the fruit of the Spirit is in all goodness and righteousness and truth,"},{"v":10,"t":"proving what is well pleasing to the Lord."},{"v":11,"t":"Have no fellowship with the unfruitful deeds of darkness, but rather even reprove them."},{"v":12,"t":"For it is a shame even to speak of the things which are done by them in secret."},{"v":13,"t":"But all things, when they are reproved, are revealed by the light, for everything that reveals is light."},{"v":14,"t":"Therefore he says, “Awake, you who sleep, and arise from the dead, and Christ will shine on you.”"},{"v":15,"t":"Therefore watch carefully how you walk, not as unwise, but as wise,"},{"v":16,"t":"redeeming the time, because the days are evil."},{"v":17,"t":"Therefore, don’t be foolish, but understand what the will of the Lord is."},{"v":18,"t":"Don’t be drunken with wine, in which is dissipation, but be filled with the Spirit,"},{"v":19,"t":"speaking to one another in psalms, hymns, and spiritual songs; singing and making melody in your heart to the Lord;"},{"v":20,"t":"giving thanks always concerning all things in the name of our Lord Jesus Christ to God, even the Father;"},{"v":21,"t":"subjecting yourselves to one another in the fear of Christ."},{"v":22,"t":"Wives, be subject to your own husbands, as to the Lord."},{"v":23,"t":"For the husband is the head of the wife, as Christ also is the head of the assembly, being himself the savior of the body."},{"v":24,"t":"But as the assembly is subject to Christ, so let the wives also be to their own husbands in everything."},{"v":25,"t":"Husbands, love your wives, even as Christ also loved the assembly and gave himself up for her,"},{"v":26,"t":"that he might sanctify her, having cleansed her by the washing of water with the word,"},{"v":27,"t":"that he might present the assembly to himself gloriously, not having spot or wrinkle or any such thing, but that she should be holy and without defect."},{"v":28,"t":"Even so husbands also ought to love their own wives as their own bodies. He who loves his own wife loves himself."},{"v":29,"t":"For no man ever hated his own flesh, but nourishes and cherishes it, even as the Lord also does the assembly,"},{"v":30,"t":"because we are members of his body, of his flesh and bones."},{"v":31,"t":"“For this cause a man will leave his father and mother and will be joined to his wife. Then the two will become one flesh.”"},{"v":32,"t":"This mystery is great, but I speak concerning Christ and the assembly."},{"v":33,"t":"Nevertheless each of you must also love his own wife even as himself; and let the wife see that she respects her husband."}]},"6":{"en":[{"v":1,"t":"Children, obey your parents in the Lord, for this is right."},{"v":2,"t":"“Honor your father and mother,” which is the first commandment with a promise:"},{"v":3,"t":"“that it may be well with you, and you may live long on the earth.”"},{"v":4,"t":"You fathers, don’t provoke your children to wrath, but nurture them in the discipline and instruction of the Lord."},{"v":5,"t":"Servants, be obedient to those who according to the flesh are your masters, with fear and trembling, in singleness of your heart, as to Christ,"},{"v":6,"t":"not in the way of service only when eyes are on you, as men pleasers, but as servants of Christ, doing the will of God from the heart,"},{"v":7,"t":"with good will doing service as to the Lord and not to men,"},{"v":8,"t":"knowing that whatever good thing each one does, he will receive the same good again from the Lord, whether he is bound or free."},{"v":9,"t":"You masters, do the same things to them, and give up threatening, knowing that he who is both their Master and yours is in heaven, and there is no partiality with him."},{"v":10,"t":"Finally, be strong in the Lord and in the strength of his might."},{"v":11,"t":"Put on the whole armor of God, that you may be able to stand against the wiles of the devil."},{"v":12,"t":"For our wrestling is not against flesh and blood, but against the principalities, against the powers, against the world’s rulers of the darkness of this age, and against the spiritual forces of wickedness in the heavenly places."},{"v":13,"t":"Therefore put on the whole armor of God, that you may be able to withstand in the evil day, and having done all, to stand."},{"v":14,"t":"Stand therefore, having the utility belt of truth buckled around your waist, and having put on the breastplate of righteousness,"},{"v":15,"t":"and having fitted your feet with the preparation of the Good News of peace,"},{"v":16,"t":"above all, taking up the shield of faith, with which you will be able to quench all the fiery darts of the evil one."},{"v":17,"t":"And take the helmet of salvation, and the sword of the Spirit, which is the word of God;"},{"v":18,"t":"with all prayer and requests, praying at all times in the Spirit, and being watchful to this end in all perseverance and requests for all the saints."},{"v":19,"t":"Pray for me, that utterance may be given to me in opening my mouth, to make known with boldness the mystery of the Good News,"},{"v":20,"t":"for which I am an ambassador in chains; that in it I may speak boldly, as I ought to speak."},{"v":21,"t":"But that you also may know my affairs, how I am doing, Tychicus, the beloved brother and faithful servant in the Lord, will make known to you all things."},{"v":22,"t":"I have sent him to you for this very purpose, that you may know our state and that he may comfort your hearts."},{"v":23,"t":"Peace be to the brothers, and love with faith, from God the Father and the Lord Jesus Christ."},{"v":24,"t":"Grace be with all those who love our Lord Jesus Christ with incorruptible love. Amen."}]}},"PHP":{"1":{"en":[{"v":1,"t":"Paul and Timothy, servants of Jesus Christ, to all the saints in Christ Jesus who are at Philippi, with the overseers and servants:"},{"v":2,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"I thank my God whenever I remember you,"},{"v":4,"t":"always in every request of mine on behalf of you all, making my requests with joy,"},{"v":5,"t":"for your partnership in furtherance of the Good News from the first day until now;"},{"v":6,"t":"being confident of this very thing, that he who began a good work in you will complete it until the day of Jesus Christ."},{"v":7,"t":"It is even right for me to think this way on behalf of all of you, because I have you in my heart, because both in my bonds and in the defense and confirmation of the Good News, you all are partakers with me of grace."},{"v":8,"t":"For God is my witness, how I long after all of you in the tender mercies of Christ Jesus."},{"v":9,"t":"This I pray, that your love may abound yet more and more in knowledge and all discernment,"},{"v":10,"t":"so that you may approve the things that are excellent, that you may be sincere and without offense to the day of Christ,"},{"v":11,"t":"being filled with the fruits of righteousness which are through Jesus Christ, to the glory and praise of God."},{"v":12,"t":"Now I desire to have you know, brothers, that the things which happened to me have turned out rather to the progress of the Good News,"},{"v":13,"t":"so that it became evident to the whole palace guard, and to all the rest, that my bonds are in Christ,"},{"v":14,"t":"and that most of the brothers in the Lord, being confident through my bonds, are more abundantly bold to speak the word of God without fear."},{"v":15,"t":"Some indeed preach Christ even out of envy and strife, and some also out of good will."},{"v":16,"t":"The former insincerely preach Christ from selfish ambition, thinking that they add affliction to my chains;"},{"v":17,"t":"but the latter out of love, knowing that I am appointed for the defense of the Good News."},{"v":18,"t":"What does it matter? Only that in every way, whether in pretense or in truth, Christ is proclaimed. I rejoice in this, yes, and will rejoice."},{"v":19,"t":"For I know that this will turn out to my salvation through your prayers and the supply of the Spirit of Jesus Christ,"},{"v":20,"t":"according to my earnest expectation and hope, that I will in no way be disappointed, but with all boldness, as always, now also Christ will be magnified in my body, whether by life or by death."},{"v":21,"t":"For to me to live is Christ, and to die is gain."},{"v":22,"t":"But if I live on in the flesh, this will bring fruit from my work; yet I don’t know what I will choose."},{"v":23,"t":"But I am hard pressed between the two, having the desire to depart and be with Christ, which is far better."},{"v":24,"t":"Yet to remain in the flesh is more needful for your sake."},{"v":25,"t":"Having this confidence, I know that I will remain, yes, and remain with you all for your progress and joy in the faith,"},{"v":26,"t":"that your boasting may abound in Christ Jesus in me through my presence with you again."},{"v":27,"t":"Only let your way of life be worthy of the Good News of Christ, that whether I come and see you or am absent, I may hear of your state, that you stand firm in one spirit, with one soul striving for the faith of the Good News;"},{"v":28,"t":"and in nothing frightened by the adversaries, which is for them a proof of destruction, but to you of salvation, and that from God."},{"v":29,"t":"Because it has been granted to you on behalf of Christ, not only to believe in him, but also to suffer on his behalf,"},{"v":30,"t":"having the same conflict which you saw in me and now hear is in me."}]},"2":{"en":[{"v":1,"t":"If therefore there is any exhortation in Christ, if any consolation of love, if any fellowship of the Spirit, if any tender mercies and compassion,"},{"v":2,"t":"make my joy full by being like-minded, having the same love, being of one accord, of one mind;"},{"v":3,"t":"doing nothing through rivalry or through conceit, but in humility, each counting others better than himself;"},{"v":4,"t":"each of you not just looking to his own things, but each of you also to the things of others."},{"v":5,"t":"Have this in your mind, which was also in Christ Jesus,"},{"v":6,"t":"who, existing in the form of God, didn’t consider equality with God a thing to be grasped,"},{"v":7,"t":"but emptied himself, taking the form of a servant, being made in the likeness of men."},{"v":8,"t":"And being found in human form, he humbled himself, becoming obedient to the point of death, yes, the death of the cross."},{"v":9,"t":"Therefore God also highly exalted him, and gave to him the name which is above every name,"},{"v":10,"t":"that at the name of Jesus every knee should bow, of those in heaven, those on earth, and those under the earth,"},{"v":11,"t":"and that every tongue should confess that Jesus Christ is Lord, to the glory of God the Father."},{"v":12,"t":"So then, my beloved, even as you have always obeyed, not only in my presence, but now much more in my absence, work out your own salvation with fear and trembling."},{"v":13,"t":"For it is God who works in you both to will and to work for his good pleasure."},{"v":14,"t":"Do all things without complaining and arguing,"},{"v":15,"t":"that you may become blameless and harmless, children of God without defect in the middle of a crooked and perverse generation, among whom you are seen as lights in the world,"},{"v":16,"t":"holding up the word of life, that I may have something to boast in the day of Christ that I didn’t run in vain nor labor in vain."},{"v":17,"t":"Yes, and if I am poured out on the sacrifice and service of your faith, I am glad and rejoice with you all."},{"v":18,"t":"In the same way, you also should be glad and rejoice with me."},{"v":19,"t":"But I hope in the Lord Jesus to send Timothy to you soon, that I also may be cheered up when I know how you are doing."},{"v":20,"t":"For I have no one else like-minded, who will truly care about you."},{"v":21,"t":"For they all seek their own, not the things of Jesus Christ."},{"v":22,"t":"But you know that he has proved himself. As a child serves a father, so he served with me in furtherance of the Good News."},{"v":23,"t":"Therefore I hope to send him at once, as soon as I see how it will go with me."},{"v":24,"t":"But I trust in the Lord that I myself also will come shortly."},{"v":25,"t":"But I thought it necessary to send to you Epaphroditus, my brother, fellow worker, fellow soldier, and your apostle and servant of my need,"},{"v":26,"t":"since he longed for you all, and was very troubled because you had heard that he was sick."},{"v":27,"t":"For indeed he was sick nearly to death, but God had mercy on him, and not on him only, but on me also, that I might not have sorrow on sorrow."},{"v":28,"t":"I have sent him therefore the more diligently, that when you see him again, you may rejoice, and that I may be the less sorrowful."},{"v":29,"t":"Receive him therefore in the Lord with all joy, and hold such people in honor,"},{"v":30,"t":"because for the work of Christ he came near to death, risking his life to supply that which was lacking in your service toward me."}]},"3":{"en":[{"v":1,"t":"Finally, my brothers, rejoice in the Lord! To write the same things to you, to me indeed is not tiresome, but for you it is safe."},{"v":2,"t":"Beware of the dogs; beware of the evil workers; beware of the false circumcision."},{"v":3,"t":"For we are the circumcision, who worship God in the Spirit, and rejoice in Christ Jesus, and have no confidence in the flesh;"},{"v":4,"t":"though I myself might have confidence even in the flesh. If any other man thinks that he has confidence in the flesh, I yet more:"},{"v":5,"t":"circumcised the eighth day, of the stock of Israel, of the tribe of Benjamin, a Hebrew of Hebrews; concerning the law, a Pharisee;"},{"v":6,"t":"concerning zeal, persecuting the assembly; concerning the righteousness which is in the law, found blameless."},{"v":7,"t":"However, I consider those things that were gain to me as a loss for Christ."},{"v":8,"t":"Yes most certainly, and I count all things to be a loss for the excellency of the knowledge of Christ Jesus, my Lord, for whom I suffered the loss of all things, and count them nothing but refuse, that I may gain Christ"},{"v":9,"t":"and be found in him, not having a righteousness of my own, that which is of the law, but that which is through faith in Christ, the righteousness which is from God by faith,"},{"v":10,"t":"that I may know him and the power of his resurrection, and the fellowship of his sufferings, becoming conformed to his death,"},{"v":11,"t":"if by any means I may attain to the resurrection from the dead."},{"v":12,"t":"Not that I have already obtained, or am already made perfect; but I press on, that I may take hold of that for which also I was taken hold of by Christ Jesus."},{"v":13,"t":"Brothers, I don’t regard myself as yet having taken hold, but one thing I do: forgetting the things which are behind and stretching forward to the things which are before,"},{"v":14,"t":"I press on toward the goal for the prize of the high calling of God in Christ Jesus."},{"v":15,"t":"Let us therefore, as many as are perfect, think this way. If in anything you think otherwise, God will also reveal that to you."},{"v":16,"t":"Nevertheless, to the extent that we have already attained, let’s walk by the same rule. Let’s be of the same mind."},{"v":17,"t":"Brothers, be imitators together of me, and note those who walk this way, even as you have us for an example."},{"v":18,"t":"For many walk, of whom I told you often, and now tell you even weeping, as the enemies of the cross of Christ,"},{"v":19,"t":"whose end is destruction, whose god is the belly, and whose glory is in their shame, who think about earthly things."},{"v":20,"t":"For our citizenship is in heaven, from where we also wait for a Savior, the Lord Jesus Christ,"},{"v":21,"t":"who will change the body of our humiliation to be conformed to the body of his glory, according to the working by which he is able even to subject all things to himself."}]},"4":{"en":[{"v":1,"t":"Therefore, my brothers, beloved and longed for, my joy and crown, stand firm in the Lord in this way, my beloved."},{"v":2,"t":"I exhort Euodia, and I exhort Syntyche, to think the same way in the Lord."},{"v":3,"t":"Yes, I beg you also, true partner, help these women, for they labored with me in the Good News with Clement also, and the rest of my fellow workers, whose names are in the book of life."},{"v":4,"t":"Rejoice in the Lord always! Again I will say, “Rejoice!”"},{"v":5,"t":"Let your gentleness be known to all men. The Lord is at hand."},{"v":6,"t":"In nothing be anxious, but in everything, by prayer and petition with thanksgiving, let your requests be made known to God."},{"v":7,"t":"And the peace of God, which surpasses all understanding, will guard your hearts and your thoughts in Christ Jesus."},{"v":8,"t":"Finally, brothers, whatever things are true, whatever things are honorable, whatever things are just, whatever things are pure, whatever things are lovely, whatever things are of good report: if there is any virtue and if there is anything worthy of praise, think about these things."},{"v":9,"t":"Do the things which you learned, received, heard, and saw in me, and the God of peace will be with you."},{"v":10,"t":"But I rejoice in the Lord greatly that now at length you have revived your thought for me; in which you did indeed take thought, but you lacked opportunity."},{"v":11,"t":"Not that I speak because of lack, for I have learned in whatever state I am, to be content in it."},{"v":12,"t":"I know how to be humbled, and I also know how to abound. In any and all circumstances I have learned the secret both to be filled and to be hungry, both to abound and to be in need."},{"v":13,"t":"I can do all things through Christ who strengthens me."},{"v":14,"t":"However you did well that you shared in my affliction."},{"v":15,"t":"You yourselves also know, you Philippians, that in the beginning of the Good News, when I departed from Macedonia, no assembly shared with me in the matter of giving and receiving but you only."},{"v":16,"t":"For even in Thessalonica you sent once and again to my need."},{"v":17,"t":"Not that I seek for the gift, but I seek for the fruit that increases to your account."},{"v":18,"t":"But I have all things and abound. I am filled, having received from Epaphroditus the things that came from you, a sweet-smelling fragrance, an acceptable and well-pleasing sacrifice to God."},{"v":19,"t":"My God will supply every need of yours according to his riches in glory in Christ Jesus."},{"v":20,"t":"Now to our God and Father be the glory forever and ever! Amen."},{"v":21,"t":"Greet every saint in Christ Jesus. The brothers who are with me greet you."},{"v":22,"t":"All the saints greet you, especially those who are of Caesar’s household."},{"v":23,"t":"The grace of the Lord Jesus Christ be with you all. Amen."}]}},"COL":{"1":{"en":[{"v":1,"t":"Paul, an apostle of Christ Jesus through the will of God, and Timothy our brother,"},{"v":2,"t":"to the saints and faithful brothers in Christ at Colossae: Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"We give thanks to God the Father of our Lord Jesus Christ, praying always for you,"},{"v":4,"t":"having heard of your faith in Christ Jesus and of the love which you have toward all the saints,"},{"v":5,"t":"because of the hope which is laid up for you in the heavens, of which you heard before in the word of the truth of the Good News"},{"v":6,"t":"which has come to you, even as it is in all the world and is bearing fruit and growing, as it does in you also, since the day you heard and knew the grace of God in truth,"},{"v":7,"t":"even as you learned from Epaphras our beloved fellow servant, who is a faithful servant of Christ on your behalf,"},{"v":8,"t":"who also declared to us your love in the Spirit."},{"v":9,"t":"For this cause, we also, since the day we heard this, don’t cease praying and making requests for you, that you may be filled with the knowledge of his will in all spiritual wisdom and understanding,"},{"v":10,"t":"that you may walk worthily of the Lord, to please him in all respects, bearing fruit in every good work and increasing in the knowledge of God,"},{"v":11,"t":"strengthened with all power, according to the might of his glory, for all endurance and perseverance with joy,"},{"v":12,"t":"giving thanks to the Father, who made us fit to be partakers of the inheritance of the saints in light,"},{"v":13,"t":"who delivered us out of the power of darkness, and translated us into the Kingdom of the Son of his love,"},{"v":14,"t":"in whom we have our redemption, the forgiveness of our sins."},{"v":15,"t":"He is the image of the invisible God, the firstborn of all creation."},{"v":16,"t":"For by him all things were created in the heavens and on the earth, visible things and invisible things, whether thrones or dominions or principalities or powers. All things have been created through him and for him."},{"v":17,"t":"He is before all things, and in him all things are held together."},{"v":18,"t":"He is the head of the body, the assembly, who is the beginning, the firstborn from the dead, that in all things he might have the preeminence."},{"v":19,"t":"For all the fullness was pleased to dwell in him,"},{"v":20,"t":"and through him to reconcile all things to himself by him, whether things on the earth or things in the heavens, having made peace through the blood of his cross."},{"v":21,"t":"You, being in past times alienated and enemies in your mind in your evil deeds,"},{"v":22,"t":"yet now he has reconciled in the body of his flesh through death, to present you holy and without defect and blameless before him,"},{"v":23,"t":"if it is so that you continue in the faith, grounded and steadfast, and not moved away from the hope of the Good News which you heard, which was proclaimed in all creation under heaven, of which I, Paul, was made a servant."},{"v":24,"t":"Now I rejoice in my sufferings for your sake, and fill up on my part that which is lacking of the afflictions of Christ in my flesh for his body’s sake, which is the assembly,"},{"v":25,"t":"of which I was made a servant according to the stewardship of God which was given me toward you to fulfill the word of God,"},{"v":26,"t":"the mystery which has been hidden for ages and generations. But now it has been revealed to his saints,"},{"v":27,"t":"to whom God was pleased to make known what are the riches of the glory of this mystery among the Gentiles, which is Christ in you, the hope of glory."},{"v":28,"t":"We proclaim him, admonishing every man and teaching every man in all wisdom, that we may present every man perfect in Christ Jesus;"},{"v":29,"t":"for which I also labor, striving according to his working, which works in me mightily."}]},"2":{"en":[{"v":1,"t":"For I desire to have you know how greatly I struggle for you and for those at Laodicea, and for as many as have not seen my face in the flesh;"},{"v":2,"t":"that their hearts may be comforted, they being knit together in love, and gaining all riches of the full assurance of understanding, that they may know the mystery of God, both of the Father and of Christ,"},{"v":3,"t":"in whom all the treasures of wisdom and knowledge are hidden."},{"v":4,"t":"Now I say this that no one may delude you with persuasiveness of speech."},{"v":5,"t":"For though I am absent in the flesh, yet I am with you in the spirit, rejoicing and seeing your order, and the steadfastness of your faith in Christ."},{"v":6,"t":"As therefore you received Christ Jesus the Lord, walk in him,"},{"v":7,"t":"rooted and built up in him and established in the faith, even as you were taught, abounding in it in thanksgiving."},{"v":8,"t":"Be careful that you don’t let anyone rob you through his philosophy and vain deceit, after the tradition of men, after the elemental spirits of the world, and not after Christ."},{"v":9,"t":"For in him all the fullness of the Deity dwells bodily,"},{"v":10,"t":"and in him you are made full, who is the head of all principality and power."},{"v":11,"t":"In him you were also circumcised with a circumcision not made with hands, in the putting off of the body of the sins of the flesh, in the circumcision of Christ,"},{"v":12,"t":"having been buried with him in baptism, in which you were also raised with him through faith in the working of God, who raised him from the dead."},{"v":13,"t":"You were dead through your trespasses and the uncircumcision of your flesh. He made you alive together with him, having forgiven us all our trespasses,"},{"v":14,"t":"wiping out the handwriting in ordinances which was against us. He has taken it out of the way, nailing it to the cross."},{"v":15,"t":"Having stripped the principalities and the powers, he made a show of them openly, triumphing over them in it."},{"v":16,"t":"Let no one therefore judge you in eating or drinking, or with respect to a feast day or a new moon or a Sabbath day,"},{"v":17,"t":"which are a shadow of the things to come; but the body is Christ’s."},{"v":18,"t":"Let no one rob you of your prize by self-abasement and worshiping of the angels, dwelling in the things which he has not seen, vainly puffed up by his fleshly mind,"},{"v":19,"t":"and not holding firmly to the Head, from whom all the body, being supplied and knit together through the joints and ligaments, grows with God’s growth."},{"v":20,"t":"If you died with Christ from the elemental spirits of the world, why, as though living in the world, do you subject yourselves to ordinances,"},{"v":21,"t":"“Don’t handle, nor taste, nor touch”"},{"v":22,"t":"(all of which perish with use), according to the precepts and doctrines of men?"},{"v":23,"t":"These things indeed appear like wisdom in self-imposed worship, humility, and severity to the body, but aren’t of any value against the indulgence of the flesh."}]},"3":{"en":[{"v":1,"t":"If then you were raised together with Christ, seek the things that are above, where Christ is, seated on the right hand of God."},{"v":2,"t":"Set your mind on the things that are above, not on the things that are on the earth."},{"v":3,"t":"For you died, and your life is hidden with Christ in God."},{"v":4,"t":"When Christ, our life, is revealed, then you will also be revealed with him in glory."},{"v":5,"t":"Put to death therefore your members which are on the earth: sexual immorality, uncleanness, depraved passion, evil desire, and covetousness, which is idolatry."},{"v":6,"t":"For these things’ sake the wrath of God comes on the children of disobedience."},{"v":7,"t":"You also once walked in those, when you lived in them,"},{"v":8,"t":"but now you must put them all away: anger, wrath, malice, slander, and shameful speaking out of your mouth."},{"v":9,"t":"Don’t lie to one another, seeing that you have put off the old man with his doings,"},{"v":10,"t":"and have put on the new man, who is being renewed in knowledge after the image of his Creator,"},{"v":11,"t":"where there can’t be Greek and Jew, circumcision and uncircumcision, barbarian, Scythian, bondservant, or free person; but Christ is all, and in all."},{"v":12,"t":"Put on therefore, as God’s chosen ones, holy and beloved, a heart of compassion, kindness, lowliness, humility, and perseverance;"},{"v":13,"t":"bearing with one another, and forgiving each other, if any man has a complaint against any; even as Christ forgave you, so you also do."},{"v":14,"t":"Above all these things, walk in love, which is the bond of perfection."},{"v":15,"t":"And let the peace of God rule in your hearts, to which also you were called in one body, and be thankful."},{"v":16,"t":"Let the word of Christ dwell in you richly; in all wisdom teaching and admonishing one another with psalms, hymns, and spiritual songs, singing with grace in your heart to the Lord."},{"v":17,"t":"Whatever you do, in word or in deed, do all in the name of the Lord Jesus, giving thanks to God the Father through him."},{"v":18,"t":"Wives, be in subjection to your husbands, as is fitting in the Lord."},{"v":19,"t":"Husbands, love your wives, and don’t be bitter against them."},{"v":20,"t":"Children, obey your parents in all things, for this pleases the Lord."},{"v":21,"t":"Fathers, don’t provoke your children, so that they won’t be discouraged."},{"v":22,"t":"Servants, obey in all things those who are your masters according to the flesh, not just when they are looking, as men pleasers, but in singleness of heart, fearing God."},{"v":23,"t":"And whatever you do, work heartily, as for the Lord and not for men,"},{"v":24,"t":"knowing that from the Lord you will receive the reward of the inheritance; for you serve the Lord Christ."},{"v":25,"t":"But he who does wrong will receive again for the wrong that he has done, and there is no partiality."}]},"4":{"en":[{"v":1,"t":"Masters, give to your servants that which is just and equal, knowing that you also have a Master in heaven."},{"v":2,"t":"Continue steadfastly in prayer, watching in it with thanksgiving,"},{"v":3,"t":"praying together for us also, that God may open to us a door for the word, to speak the mystery of Christ, for which I am also in bonds,"},{"v":4,"t":"that I may reveal it as I ought to speak."},{"v":5,"t":"Walk in wisdom toward those who are outside, redeeming the time."},{"v":6,"t":"Let your speech always be with grace, seasoned with salt, that you may know how you ought to answer each one."},{"v":7,"t":"All my affairs will be made known to you by Tychicus, the beloved brother, faithful servant, and fellow bondservant in the Lord."},{"v":8,"t":"I am sending him to you for this very purpose, that he may know your circumstances and comfort your hearts,"},{"v":9,"t":"together with Onesimus, the faithful and beloved brother, who is one of you. They will make known to you everything that is going on here."},{"v":10,"t":"Aristarchus, my fellow prisoner, greets you, and Mark the cousin of Barnabas (concerning whom you received instructions, “if he comes to you, receive him”),"},{"v":11,"t":"and Jesus who is called Justus. These are my only fellow workers for God’s Kingdom who are of the circumcision, men who have been a comfort to me."},{"v":12,"t":"Epaphras, who is one of you, a servant of Christ, salutes you, always striving for you in his prayers, that you may stand perfect and complete in all the will of God."},{"v":13,"t":"For I testify about him that he has great zeal for you, and for those in Laodicea, and for those in Hierapolis."},{"v":14,"t":"Luke the beloved physician and Demas greet you."},{"v":15,"t":"Greet the brothers who are in Laodicea, with Nymphas and the assembly that is in his house."},{"v":16,"t":"When this letter has been read among you, cause it to be read also in the assembly of the Laodiceans, and that you also read the letter from Laodicea."},{"v":17,"t":"Tell Archippus, “Take heed to the ministry which you have received in the Lord, that you fulfill it.”"},{"v":18,"t":"I, Paul, write this greeting with my own hand. Remember my chains. Grace be with you. Amen."}]}},"1TH":{"1":{"en":[{"v":1,"t":"Paul, Silvanus, and Timothy, to the assembly of the Thessalonians in God the Father and the Lord Jesus Christ: Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":2,"t":"We always give thanks to God for all of you, mentioning you in our prayers,"},{"v":3,"t":"remembering without ceasing your work of faith and labor of love and perseverance of hope in our Lord Jesus Christ, before our God and Father."},{"v":4,"t":"We know, brothers loved by God, that you are chosen,"},{"v":5,"t":"and that our Good News came to you not in word only, but also in power, and in the Holy Spirit and with much assurance. You know what kind of men we showed ourselves to be among you for your sake."},{"v":6,"t":"You became imitators of us and of the Lord, having received the word in much affliction, with joy of the Holy Spirit,"},{"v":7,"t":"so that you became an example to all who believe in Macedonia and in Achaia."},{"v":8,"t":"For from you the word of the Lord has been declared, not only in Macedonia and Achaia, but also in every place your faith toward God has gone out, so that we need not to say anything."},{"v":9,"t":"For they themselves report concerning us what kind of a reception we had from you, and how you turned to God from idols to serve a living and true God,"},{"v":10,"t":"and to wait for his Son from heaven, whom he raised from the dead: Jesus, who delivers us from the wrath to come."}]},"2":{"en":[{"v":1,"t":"For you yourselves know, brothers, our visit to you wasn’t in vain,"},{"v":2,"t":"but having suffered before and been shamefully treated, as you know, at Philippi, we grew bold in our God to tell you the Good News of God in much conflict."},{"v":3,"t":"For our exhortation is not of error, nor of uncleanness, nor in deception."},{"v":4,"t":"But even as we have been approved by God to be entrusted with the Good News, so we speak—not as pleasing men, but God, who tests our hearts."},{"v":5,"t":"For neither were we at any time found using words of flattery, as you know, nor a cloak of covetousness (God is witness),"},{"v":6,"t":"nor seeking glory from men (neither from you nor from others), when we might have claimed authority as apostles of Christ."},{"v":7,"t":"But we were gentle among you, like a nursing mother cherishes her own children."},{"v":8,"t":"Even so, affectionately longing for you, we were well pleased to impart to you not the Good News of God only, but also our own souls, because you had become very dear to us."},{"v":9,"t":"For you remember, brothers, our labor and travail; for working night and day, that we might not burden any of you, we preached to you the Good News of God."},{"v":10,"t":"You are witnesses with God how holy, righteously, and blamelessly we behaved ourselves toward you who believe."},{"v":11,"t":"As you know, we exhorted, comforted, and implored every one of you, as a father does his own children,"},{"v":12,"t":"to the end that you should walk worthily of God, who calls you into his own Kingdom and glory."},{"v":13,"t":"For this cause we also thank God without ceasing that when you received from us the word of the message of God, you accepted it not as the word of men, but as it is in truth, God’s word, which also works in you who believe."},{"v":14,"t":"For you, brothers, became imitators of the assemblies of God which are in Judea in Christ Jesus; for you also suffered the same things from your own countrymen, even as they did from the Jews"},{"v":15,"t":"who killed both the Lord Jesus and their own prophets, and drove us out, and don’t please God, and are contrary to all men,"},{"v":16,"t":"forbidding us to speak to the Gentiles that they may be saved, to fill up their sins always. But wrath has come on them to the uttermost."},{"v":17,"t":"But we, brothers, being bereaved of you for a short season in presence, not in heart, tried even harder to see your face with great desire,"},{"v":18,"t":"because we wanted to come to you—indeed, I, Paul, once and again—but Satan hindered us."},{"v":19,"t":"For what is our hope, or joy, or crown of rejoicing? Isn’t it even you, before our Lord Jesus at his coming?"},{"v":20,"t":"For you are our glory and our joy."}]},"3":{"en":[{"v":1,"t":"Therefore when we couldn’t stand it any longer, we thought it good to be left behind at Athens alone,"},{"v":2,"t":"and sent Timothy, our brother and God’s servant in the Good News of Christ, to establish you and to comfort you concerning your faith,"},{"v":3,"t":"that no one would be moved by these afflictions. For you know that we are appointed to this task."},{"v":4,"t":"For most certainly, when we were with you, we told you beforehand that we are to suffer affliction, even as it happened, and you know."},{"v":5,"t":"For this cause I also, when I couldn’t stand it any longer, sent that I might know your faith, for fear that by any means the tempter had tempted you, and our labor would have been in vain."},{"v":6,"t":"But Timothy has just now come to us from you, and brought us glad news of your faith and love, and that you have good memories of us always, longing to see us, even as we also long to see you."},{"v":7,"t":"For this cause, brothers, we were comforted over you in all our distress and affliction through your faith."},{"v":8,"t":"For now we live, if you stand fast in the Lord."},{"v":9,"t":"For what thanksgiving can we render again to God for you, for all the joy with which we rejoice for your sakes before our God,"},{"v":10,"t":"night and day praying exceedingly that we may see your face and may perfect that which is lacking in your faith?"},{"v":11,"t":"Now may our God and Father himself, and our Lord Jesus Christ, direct our way to you."},{"v":12,"t":"May the Lord make you to increase and abound in love toward one another and toward all men, even as we also do toward you,"},{"v":13,"t":"to the end he may establish your hearts blameless in holiness before our God and Father at the coming of our Lord Jesus with all his saints."}]},"4":{"en":[{"v":1,"t":"Finally then, brothers, we beg and exhort you in the Lord Jesus, that as you received from us how you ought to walk and to please God, that you abound more and more."},{"v":2,"t":"For you know what instructions we gave you through the Lord Jesus."},{"v":3,"t":"For this is the will of God: your sanctification, that you abstain from sexual immorality,"},{"v":4,"t":"that each one of you know how to control his own body in sanctification and honor,"},{"v":5,"t":"not in the passion of lust, even as the Gentiles who don’t know God,"},{"v":6,"t":"that no one should take advantage of and wrong a brother or sister in this matter; because the Lord is an avenger in all these things, as also we forewarned you and testified."},{"v":7,"t":"For God called us not for uncleanness, but in sanctification."},{"v":8,"t":"Therefore he who rejects this doesn’t reject man, but God, who has also given his Holy Spirit to you."},{"v":9,"t":"But concerning brotherly love, you have no need that one write to you. For you yourselves are taught by God to love one another,"},{"v":10,"t":"for indeed you do it toward all the brothers who are in all Macedonia. But we exhort you, brothers, that you abound more and more;"},{"v":11,"t":"and that you make it your ambition to lead a quiet life, and to do your own business, and to work with your own hands, even as we instructed you,"},{"v":12,"t":"that you may walk properly toward those who are outside, and may have need of nothing."},{"v":13,"t":"But we don’t want you to be ignorant, brothers, concerning those who have fallen asleep, so that you don’t grieve like the rest, who have no hope."},{"v":14,"t":"For if we believe that Jesus died and rose again, even so God will bring with him those who have fallen asleep in Jesus."},{"v":15,"t":"For this we tell you by the word of the Lord, that we who are alive, who are left until the coming of the Lord, will in no way precede those who have fallen asleep."},{"v":16,"t":"For the Lord himself will descend from heaven with a shout, with the voice of the archangel and with God’s trumpet. The dead in Christ will rise first,"},{"v":17,"t":"then we who are alive, who are left, will be caught up together with them in the clouds to meet the Lord in the air. So we will be with the Lord forever."},{"v":18,"t":"Therefore comfort one another with these words."}]},"5":{"en":[{"v":1,"t":"But concerning the times and the seasons, brothers, you have no need that anything be written to you."},{"v":2,"t":"For you yourselves know well that the day of the Lord comes like a thief in the night."},{"v":3,"t":"For when they are saying, “Peace and safety,” then sudden destruction will come on them, like birth pains on a pregnant woman. Then they will in no way escape."},{"v":4,"t":"But you, brothers, aren’t in darkness, that the day should overtake you like a thief."},{"v":5,"t":"You are all children of light and children of the day. We don’t belong to the night, nor to darkness,"},{"v":6,"t":"so then let’s not sleep, as the rest do, but let’s watch and be sober."},{"v":7,"t":"For those who sleep, sleep in the night; and those who are drunk are drunk in the night."},{"v":8,"t":"But since we belong to the day, let’s be sober, putting on the breastplate of faith and love, and for a helmet, the hope of salvation."},{"v":9,"t":"For God didn’t appoint us to wrath, but to the obtaining of salvation through our Lord Jesus Christ,"},{"v":10,"t":"who died for us, that, whether we wake or sleep, we should live together with him."},{"v":11,"t":"Therefore exhort one another, and build each other up, even as you also do."},{"v":12,"t":"But we beg you, brothers, to know those who labor among you, and are over you in the Lord and admonish you,"},{"v":13,"t":"and to respect and honor them in love for their work’s sake. Be at peace among yourselves."},{"v":14,"t":"We exhort you, brothers: Admonish the disorderly; encourage the faint-hearted; support the weak; be patient toward all."},{"v":15,"t":"See that no one returns evil for evil to anyone, but always follow after that which is good for one another and for all."},{"v":16,"t":"Always rejoice."},{"v":17,"t":"Pray without ceasing."},{"v":18,"t":"In everything give thanks, for this is the will of God in Christ Jesus toward you."},{"v":19,"t":"Don’t quench the Spirit."},{"v":20,"t":"Don’t despise prophecies."},{"v":21,"t":"Test all things, and hold firmly that which is good."},{"v":22,"t":"Abstain from every form of evil."},{"v":23,"t":"May the God of peace himself sanctify you completely. May your whole spirit, soul, and body be preserved blameless at the coming of our Lord Jesus Christ."},{"v":24,"t":"He who calls you is faithful, who will also do it."},{"v":25,"t":"Brothers, pray for us."},{"v":26,"t":"Greet all the brothers with a holy kiss."},{"v":27,"t":"I solemnly command you by the Lord that this letter be read to all the holy brothers."},{"v":28,"t":"The grace of our Lord Jesus Christ be with you. Amen."}]}},"2TH":{"1":{"en":[{"v":1,"t":"Paul, Silvanus, and Timothy, to the assembly of the Thessalonians in God our Father and the Lord Jesus Christ:"},{"v":2,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"We are bound to always give thanks to God for you, brothers, even as it is appropriate, because your faith grows exceedingly, and the love of each and every one of you toward one another abounds,"},{"v":4,"t":"so that we ourselves boast about you in the assemblies of God for your perseverance and faith in all your persecutions and in the afflictions which you endure."},{"v":5,"t":"This is an obvious sign of the righteous judgment of God, to the end that you may be counted worthy of God’s Kingdom, for which you also suffer."},{"v":6,"t":"For it is a righteous thing with God to repay affliction to those who afflict you,"},{"v":7,"t":"and to give relief to you who are afflicted with us when the Lord Jesus is revealed from heaven with his mighty angels in flaming fire,"},{"v":8,"t":"punishing those who don’t know God, and to those who don’t obey the Good News of our Lord Jesus,"},{"v":9,"t":"who will pay the penalty: eternal destruction from the face of the Lord and from the glory of his might,"},{"v":10,"t":"when he comes in that day to be glorified in his saints and to be admired among all those who have believed, because our testimony to you was believed."},{"v":11,"t":"To this end we also pray always for you that our God may count you worthy of your calling, and fulfill every desire of goodness and work of faith with power,"},{"v":12,"t":"that the name of our Lord Jesus may be glorified in you, and you in him, according to the grace of our God and the Lord Jesus Christ."}]},"2":{"en":[{"v":1,"t":"Now, brothers, concerning the coming of our Lord Jesus Christ and our gathering together to him, we ask you"},{"v":2,"t":"not to be quickly shaken in your mind or troubled, either by spirit or by word or by letter as if from us, saying that the day of Christ has already come."},{"v":3,"t":"Let no one deceive you in any way. For it will not be unless the rebellion comes first, and the man of sin is revealed, the son of destruction."},{"v":4,"t":"He opposes and exalts himself against all that is called God or that is worshiped, so that he sits as God in the temple of God, setting himself up as God."},{"v":5,"t":"Don’t you remember that when I was still with you, I told you these things?"},{"v":6,"t":"Now you know what is restraining him, to the end that he may be revealed in his own season."},{"v":7,"t":"For the mystery of lawlessness already works. Only there is one who restrains now, until he is taken out of the way."},{"v":8,"t":"Then the lawless one will be revealed, whom the Lord will kill with the breath of his mouth and destroy by the manifestation of his coming;"},{"v":9,"t":"even he whose coming is according to the working of Satan with all power and signs and lying wonders,"},{"v":10,"t":"and with all deception of wickedness for those who are being lost, because they didn’t receive the love of the truth, that they might be saved."},{"v":11,"t":"Because of this, God sends them a powerful delusion, that they should believe a lie,"},{"v":12,"t":"that they all might be judged who didn’t believe the truth, but had pleasure in unrighteousness."},{"v":13,"t":"But we are bound to always give thanks to God for you, brothers loved by the Lord, because God chose you from the beginning for salvation through sanctification of the Spirit and belief in the truth,"},{"v":14,"t":"to which he called you through our Good News, for the obtaining of the glory of our Lord Jesus Christ."},{"v":15,"t":"So then, brothers, stand firm and hold the traditions which you were taught by us, whether by word or by letter."},{"v":16,"t":"Now our Lord Jesus Christ himself, and God our Father, who loved us and gave us eternal comfort and good hope through grace,"},{"v":17,"t":"comfort your hearts and establish you in every good work and word."}]},"3":{"en":[{"v":1,"t":"Finally, brothers, pray for us, that the word of the Lord may spread rapidly and be glorified, even as also with you,"},{"v":2,"t":"and that we may be delivered from unreasonable and evil men; for not all have faith."},{"v":3,"t":"But the Lord is faithful, who will establish you and guard you from the evil one."},{"v":4,"t":"We have confidence in the Lord concerning you, that you both do and will do the things we command."},{"v":5,"t":"May the Lord direct your hearts into God’s love and into the perseverance of Christ."},{"v":6,"t":"Now we command you, brothers, in the name of our Lord Jesus Christ, that you withdraw yourselves from every brother who walks in rebellion and not after the tradition which they received from us."},{"v":7,"t":"For you know how you ought to imitate us. For we didn’t behave ourselves rebelliously among you,"},{"v":8,"t":"neither did we eat bread from anyone’s hand without paying for it, but in labor and travail worked night and day, that we might not burden any of you."},{"v":9,"t":"This was not because we don’t have the right, but to make ourselves an example to you, that you should imitate us."},{"v":10,"t":"For even when we were with you, we commanded you this: “If anyone is not willing to work, don’t let him eat.”"},{"v":11,"t":"For we hear of some who walk among you in rebellion, who don’t work at all, but are busybodies."},{"v":12,"t":"Now those who are that way, we command and exhort in the Lord Jesus Christ, that they work with quietness and eat their own bread."},{"v":13,"t":"But you, brothers, don’t be weary in doing what is right."},{"v":14,"t":"If any man doesn’t obey our word in this letter, note that man and have no company with him, to the end that he may be ashamed."},{"v":15,"t":"Don’t count him as an enemy, but admonish him as a brother."},{"v":16,"t":"Now may the Lord of peace himself give you peace at all times in all ways. The Lord be with you all."},{"v":17,"t":"I, Paul, write this greeting with my own hand, which is the sign in every letter. This is how I write."},{"v":18,"t":"The grace of our Lord Jesus Christ be with you all. Amen."}]}},"1TI":{"1":{"en":[{"v":1,"t":"Paul, an apostle of Jesus Christ according to the commandment of God our Savior and the Lord Jesus Christ our hope,"},{"v":2,"t":"to Timothy, my true child in faith: Grace, mercy, and peace from God our Father and Christ Jesus our Lord."},{"v":3,"t":"As I urged you when I was going into Macedonia, stay at Ephesus that you might command certain men not to teach a different doctrine,"},{"v":4,"t":"and not to pay attention to myths and endless genealogies, which cause disputes rather than God’s stewardship, which is in faith."},{"v":5,"t":"But the goal of this command is love from a pure heart, a good conscience, and sincere faith,"},{"v":6,"t":"from which things some, having missed the mark, have turned away to vain talking,"},{"v":7,"t":"desiring to be teachers of the law, though they understand neither what they say nor about what they strongly affirm."},{"v":8,"t":"But we know that the law is good if a person uses it lawfully,"},{"v":9,"t":"as knowing this, that law is not made for a righteous person, but for the lawless and insubordinate, for the ungodly and sinners, for the unholy and profane, for murderers of fathers and murderers of mothers, for manslayers,"},{"v":10,"t":"for the sexually immoral, for homosexuals, for slave-traders, for liars, for perjurers, and for any other thing contrary to the sound doctrine,"},{"v":11,"t":"according to the Good News of the glory of the blessed God, which was committed to my trust."},{"v":12,"t":"I thank him who enabled me, Christ Jesus our Lord, because he counted me faithful, appointing me to service,"},{"v":13,"t":"although I used to be a blasphemer, a persecutor, and insolent. However, I obtained mercy because I did it ignorantly in unbelief."},{"v":14,"t":"The grace of our Lord abounded exceedingly with faith and love which is in Christ Jesus."},{"v":15,"t":"The saying is faithful and worthy of all acceptance, that Christ Jesus came into the world to save sinners, of whom I am chief."},{"v":16,"t":"However, for this cause I obtained mercy, that in me first, Jesus Christ might display all his patience for an example of those who were going to believe in him for eternal life."},{"v":17,"t":"Now to the King eternal, immortal, invisible, to God who alone is wise, be honor and glory forever and ever. Amen."},{"v":18,"t":"I commit this instruction to you, my child Timothy, according to the prophecies which were given to you before, that by them you may wage the good warfare,"},{"v":19,"t":"holding faith and a good conscience, which some having thrust away made a shipwreck concerning the faith,"},{"v":20,"t":"of whom are Hymenaeus and Alexander, whom I delivered to Satan that they might be taught not to blaspheme."}]},"2":{"en":[{"v":1,"t":"I exhort therefore, first of all, that petitions, prayers, intercessions, and givings of thanks be made for all men,"},{"v":2,"t":"for kings and all who are in high places, that we may lead a tranquil and quiet life in all godliness and reverence."},{"v":3,"t":"For this is good and acceptable in the sight of God our Savior,"},{"v":4,"t":"who desires all people to be saved and come to full knowledge of the truth."},{"v":5,"t":"For there is one God and one mediator between God and men, the man Christ Jesus,"},{"v":6,"t":"who gave himself as a ransom for all, the testimony at the proper time,"},{"v":7,"t":"to which I was appointed a preacher and an apostle—I am telling the truth in Christ, not lying—a teacher of the Gentiles in faith and truth."},{"v":8,"t":"I desire therefore that the men in every place pray, lifting up holy hands without anger and doubting."},{"v":9,"t":"In the same way, that women also adorn themselves in decent clothing, with modesty and propriety, not with braided hair, gold, pearls, or expensive clothing,"},{"v":10,"t":"but with good works, which is appropriate for women professing godliness."},{"v":11,"t":"Let a woman learn in quietness with full submission."},{"v":12,"t":"But I don’t permit a woman to teach, nor to exercise authority over a man, but to be in quietness."},{"v":13,"t":"For Adam was formed first, then Eve."},{"v":14,"t":"Adam wasn’t deceived, but the woman, being deceived, has fallen into disobedience;"},{"v":15,"t":"but she will be saved through her childbearing, if they continue in faith, love, and holiness with sobriety."}]},"3":{"en":[{"v":1,"t":"This is a faithful saying: someone who seeks to be an overseer desires a good work."},{"v":2,"t":"The overseer therefore must be without reproach, the husband of one wife, temperate, sensible, modest, hospitable, good at teaching;"},{"v":3,"t":"not a drinker, not violent, not greedy for money, but gentle, not quarrelsome, not covetous;"},{"v":4,"t":"one who rules his own house well, having children in subjection with all reverence;"},{"v":5,"t":"(for how could someone who doesn’t know how to rule his own house take care of God’s assembly?)"},{"v":6,"t":"not a new convert, lest being puffed up he fall into the same condemnation as the devil."},{"v":7,"t":"Moreover he must have good testimony from those who are outside, to avoid falling into reproach and the snare of the devil."},{"v":8,"t":"Servants, in the same way, must be reverent, not double-tongued, not addicted to much wine, not greedy for money,"},{"v":9,"t":"holding the mystery of the faith in a pure conscience."},{"v":10,"t":"Let them also first be tested; then let them serve if they are blameless."},{"v":11,"t":"Their wives in the same way must be reverent, not slanderers, temperate, and faithful in all things."},{"v":12,"t":"Let servants be husbands of one wife, ruling their children and their own houses well."},{"v":13,"t":"For those who have served well gain for themselves a good standing and great boldness in the faith which is in Christ Jesus."},{"v":14,"t":"These things I write to you, hoping to come to you shortly,"},{"v":15,"t":"but if I wait long, that you may know how men ought to behave themselves in God’s house, which is the assembly of the living God, the pillar and ground of the truth."},{"v":16,"t":"Without controversy, the mystery of godliness is great: God was revealed in the flesh, justified in the spirit, seen by angels, preached among the nations, believed on in the world, and received up in glory."}]},"4":{"en":[{"v":1,"t":"But the Spirit says expressly that in later times some will fall away from the faith, paying attention to seducing spirits and doctrines of demons,"},{"v":2,"t":"through the hypocrisy of men who speak lies, branded in their own conscience as with a hot iron,"},{"v":3,"t":"forbidding marriage and commanding to abstain from foods which God created to be received with thanksgiving by those who believe and know the truth."},{"v":4,"t":"For every creature of God is good, and nothing is to be rejected if it is received with thanksgiving."},{"v":5,"t":"For it is sanctified through the word of God and prayer."},{"v":6,"t":"If you instruct the brothers of these things, you will be a good servant of Christ Jesus, nourished in the words of the faith and of the good doctrine which you have followed."},{"v":7,"t":"But refuse profane and old wives’ fables. Exercise yourself toward godliness."},{"v":8,"t":"For bodily exercise has some value, but godliness has value in all things, having the promise of the life which is now and of that which is to come."},{"v":9,"t":"This saying is faithful and worthy of all acceptance."},{"v":10,"t":"For to this end we both labor and suffer reproach, because we have set our trust in the living God, who is the Savior of all men, especially of those who believe."},{"v":11,"t":"Command and teach these things."},{"v":12,"t":"Let no man despise your youth; but be an example to those who believe, in word, in your way of life, in love, in spirit, in faith, and in purity."},{"v":13,"t":"Until I come, pay attention to reading, to exhortation, and to teaching."},{"v":14,"t":"Don’t neglect the gift that is in you, which was given to you by prophecy with the laying on of the hands of the elders."},{"v":15,"t":"Be diligent in these things. Give yourself wholly to them, that your progress may be revealed to all."},{"v":16,"t":"Pay attention to yourself and to your teaching. Continue in these things, for in doing this you will save both yourself and those who hear you."}]},"5":{"en":[{"v":1,"t":"Don’t rebuke an older man, but exhort him as a father; the younger men as brothers;"},{"v":2,"t":"the elder women as mothers; the younger as sisters, in all purity."},{"v":3,"t":"Honor widows who are widows indeed."},{"v":4,"t":"But if any widow has children or grandchildren, let them learn first to show piety toward their own family and to repay their parents, for this is acceptable in the sight of God."},{"v":5,"t":"Now she who is a widow indeed and desolate, has her hope set on God and continues in petitions and prayers night and day."},{"v":6,"t":"But she who gives herself to pleasure is dead while she lives."},{"v":7,"t":"Also command these things, that they may be without reproach."},{"v":8,"t":"But if anyone doesn’t provide for his own, and especially his own household, he has denied the faith and is worse than an unbeliever."},{"v":9,"t":"Let no one be enrolled as a widow under sixty years old, having been the wife of one man,"},{"v":10,"t":"being approved by good works, if she has brought up children, if she has been hospitable to strangers, if she has washed the saints’ feet, if she has relieved the afflicted, and if she has diligently followed every good work."},{"v":11,"t":"But refuse younger widows, for when they have grown wanton against Christ, they desire to marry,"},{"v":12,"t":"having condemnation, because they have rejected their first pledge."},{"v":13,"t":"Besides, they also learn to be idle, going about from house to house. Not only idle, but also gossips and busybodies, saying things which they ought not."},{"v":14,"t":"I desire therefore that the younger widows marry, bear children, rule the household, and give no occasion to the adversary for insulting."},{"v":15,"t":"For already some have turned away after Satan."},{"v":16,"t":"If any man or woman who believes has widows, let them relieve them, and don’t let the assembly be burdened, that it might relieve those who are widows indeed."},{"v":17,"t":"Let the elders who rule well be counted worthy of double honor, especially those who labor in the word and in teaching."},{"v":18,"t":"For the Scripture says, “You shall not muzzle the ox when it treads out the grain.” And, “The laborer is worthy of his wages.”"},{"v":19,"t":"Don’t receive an accusation against an elder except at the word of two or three witnesses."},{"v":20,"t":"Those who sin, reprove in the sight of all, that the rest also may be in fear."},{"v":21,"t":"I command you in the sight of God, and the Lord Jesus Christ, and the chosen angels, that you observe these things without prejudice, doing nothing by partiality."},{"v":22,"t":"Lay hands hastily on no one. Don’t be a participant in other people’s sins. Keep yourself pure."},{"v":23,"t":"Be no longer a drinker of water only, but use a little wine for your stomach’s sake and your frequent infirmities."},{"v":24,"t":"Some men’s sins are evident, preceding them to judgment, and some also follow later."},{"v":25,"t":"In the same way also there are good works that are obvious, and those that are otherwise can’t be hidden."}]},"6":{"en":[{"v":1,"t":"Let as many as are bondservants under the yoke count their own masters worthy of all honor, that the name of God and the doctrine not be blasphemed."},{"v":2,"t":"Those who have believing masters, let them not despise them because they are brothers, but rather let them serve them, because those who partake of the benefit are believing and beloved. Teach and exhort these things."},{"v":3,"t":"If anyone teaches a different doctrine and doesn’t consent to sound words, the words of our Lord Jesus Christ, and to the doctrine which is according to godliness,"},{"v":4,"t":"he is conceited, knowing nothing, but obsessed with arguments, disputes, and word battles, from which come envy, strife, insulting, evil suspicions,"},{"v":5,"t":"constant friction of people of corrupt minds and destitute of the truth, who suppose that godliness is a means of gain. Withdraw yourself from such."},{"v":6,"t":"But godliness with contentment is great gain."},{"v":7,"t":"For we brought nothing into the world, and we certainly can’t carry anything out."},{"v":8,"t":"But having food and clothing, we will be content with that."},{"v":9,"t":"But those who are determined to be rich fall into a temptation, a snare, and many foolish and harmful lusts, such as drown men in ruin and destruction."},{"v":10,"t":"For the love of money is a root of all kinds of evil. Some have been led astray from the faith in their greed, and have pierced themselves through with many sorrows."},{"v":11,"t":"But you, man of God, flee these things, and follow after righteousness, godliness, faith, love, perseverance, and gentleness."},{"v":12,"t":"Fight the good fight of faith. Take hold of the eternal life to which you were called, and you confessed the good confession in the sight of many witnesses."},{"v":13,"t":"I command you before God who gives life to all things, and before Christ Jesus who before Pontius Pilate testified the good confession,"},{"v":14,"t":"that you keep the commandment without spot, blameless until the appearing of our Lord Jesus Christ,"},{"v":15,"t":"which at the right time he will show, who is the blessed and only Ruler, the King of kings and Lord of lords."},{"v":16,"t":"He alone has immortality, dwelling in unapproachable light, whom no man has seen nor can see, to whom be honor and eternal power. Amen."},{"v":17,"t":"Charge those who are rich in this present age that they not be arrogant, nor have their hope set on the uncertainty of riches, but on the living God, who richly provides us with everything to enjoy;"},{"v":18,"t":"that they do good, that they be rich in good works, that they be ready to distribute, willing to share;"},{"v":19,"t":"laying up in store for themselves a good foundation against the time to come, that they may lay hold of eternal life."},{"v":20,"t":"Timothy, guard that which is committed to you, turning away from the empty chatter and oppositions of what is falsely called knowledge,"},{"v":21,"t":"which some profess, and thus have wandered from the faith. Grace be with you. Amen."}]}},"2TI":{"1":{"en":[{"v":1,"t":"Paul, an apostle of Jesus Christ through the will of God, according to the promise of the life which is in Christ Jesus,"},{"v":2,"t":"to Timothy, my beloved child: Grace, mercy, and peace, from God the Father and Christ Jesus our Lord."},{"v":3,"t":"I thank God, whom I serve as my forefathers did, with a pure conscience. How unceasing is my memory of you in my petitions, night and day"},{"v":4,"t":"longing to see you, remembering your tears, that I may be filled with joy;"},{"v":5,"t":"having been reminded of the sincere faith that is in you, which lived first in your grandmother Lois and your mother Eunice and, I am persuaded, in you also."},{"v":6,"t":"For this cause, I remind you that you should stir up the gift of God which is in you through the laying on of my hands."},{"v":7,"t":"For God didn’t give us a spirit of fear, but of power, love, and self-control."},{"v":8,"t":"Therefore don’t be ashamed of the testimony of our Lord, nor of me his prisoner; but endure hardship for the Good News according to the power of God,"},{"v":9,"t":"who saved us and called us with a holy calling, not according to our works, but according to his own purpose and grace, which was given to us in Christ Jesus before times eternal,"},{"v":10,"t":"but has now been revealed by the appearing of our Savior, Christ Jesus, who abolished death, and brought life and immortality to light through the Good News."},{"v":11,"t":"For this I was appointed as a preacher, an apostle, and a teacher of the Gentiles."},{"v":12,"t":"For this cause I also suffer these things. Yet I am not ashamed, for I know him whom I have believed, and I am persuaded that he is able to guard that which I have committed to him against that day."},{"v":13,"t":"Hold the pattern of sound words which you have heard from me, in faith and love which is in Christ Jesus."},{"v":14,"t":"That good thing which was committed to you, guard through the Holy Spirit who dwells in us."},{"v":15,"t":"This you know, that all who are in Asia turned away from me, of whom are Phygelus and Hermogenes."},{"v":16,"t":"May the Lord grant mercy to the house of Onesiphorus, for he often refreshed me, and was not ashamed of my chain,"},{"v":17,"t":"but when he was in Rome, he sought me diligently and found me"},{"v":18,"t":"(the Lord grant to him to find the Lord’s mercy in that day); and in how many things he served at Ephesus, you know very well."}]},"2":{"en":[{"v":1,"t":"You therefore, my child, be strengthened in the grace that is in Christ Jesus."},{"v":2,"t":"The things which you have heard from me among many witnesses, commit the same things to faithful men who will be able to teach others also."},{"v":3,"t":"You therefore must endure hardship as a good soldier of Christ Jesus."},{"v":4,"t":"No soldier on duty entangles himself in the affairs of life, that he may please him who enrolled him as a soldier."},{"v":5,"t":"Also, if anyone competes in athletics, he isn’t crowned unless he has competed by the rules."},{"v":6,"t":"The farmer who labors must be the first to get a share of the crops."},{"v":7,"t":"Consider what I say, and may the Lord give you understanding in all things."},{"v":8,"t":"Remember Jesus Christ, risen from the dead, of the offspring of David, according to my Good News,"},{"v":9,"t":"in which I suffer hardship to the point of chains as a criminal. But God’s word isn’t chained."},{"v":10,"t":"Therefore I endure all things for the chosen ones’ sake, that they also may obtain the salvation which is in Christ Jesus with eternal glory."},{"v":11,"t":"This saying is trustworthy: “For if we died with him, we will also live with him."},{"v":12,"t":"If we endure, we will also reign with him. If we deny him, he also will deny us."},{"v":13,"t":"If we are faithless, he remains faithful; for he can’t deny himself.”"},{"v":14,"t":"Remind them of these things, charging them in the sight of the Lord that they don’t argue about words to no profit, to the subverting of those who hear."},{"v":15,"t":"Give diligence to present yourself approved by God, a workman who doesn’t need to be ashamed, properly handling the Word of Truth."},{"v":16,"t":"But shun empty chatter, for it will go further in ungodliness,"},{"v":17,"t":"and those words will consume like gangrene, of whom is Hymenaeus and Philetus:"},{"v":18,"t":"men who have erred concerning the truth, saying that the resurrection is already past, and overthrowing the faith of some."},{"v":19,"t":"However, God’s firm foundation stands, having this seal: “The Lord knows those who are his,” and, “Let every one who names the name of the Lord depart from unrighteousness.”"},{"v":20,"t":"Now in a large house there are not only vessels of gold and of silver, but also of wood and of clay. Some are for honor and some for dishonor."},{"v":21,"t":"If anyone therefore purges himself from these, he will be a vessel for honor, sanctified, and suitable for the master’s use, prepared for every good work."},{"v":22,"t":"Flee from youthful lusts; but pursue righteousness, faith, love, and peace with those who call on the Lord out of a pure heart."},{"v":23,"t":"But refuse foolish and ignorant questionings, knowing that they generate strife."},{"v":24,"t":"The Lord’s servant must not quarrel, but be gentle toward all, able to teach, patient,"},{"v":25,"t":"in gentleness correcting those who oppose him. Perhaps God may give them repentance leading to a full knowledge of the truth,"},{"v":26,"t":"and they may recover themselves out of the devil’s snare, having been taken captive by him to do his will."}]},"3":{"en":[{"v":1,"t":"But know this: that in the last days, grievous times will come."},{"v":2,"t":"For men will be lovers of self, lovers of money, boastful, arrogant, blasphemers, disobedient to parents, unthankful, unholy,"},{"v":3,"t":"without natural affection, unforgiving, slanderers, without self-control, fierce, not lovers of good,"},{"v":4,"t":"traitors, headstrong, conceited, lovers of pleasure rather than lovers of God,"},{"v":5,"t":"holding a form of godliness but having denied its power. Turn away from these, also."},{"v":6,"t":"For some of these are people who creep into houses and take captive gullible women loaded down with sins, led away by various lusts,"},{"v":7,"t":"always learning and never able to come to the knowledge of the truth."},{"v":8,"t":"Even as Jannes and Jambres opposed Moses, so these also oppose the truth, men corrupted in mind, who concerning the faith are rejected."},{"v":9,"t":"But they will proceed no further. For their folly will be evident to all men, as theirs also came to be."},{"v":10,"t":"But you followed my teaching, conduct, purpose, faith, patience, love, steadfastness,"},{"v":11,"t":"persecutions, and sufferings—those things that happened to me at Antioch, Iconium, and Lystra. I endured those persecutions. The Lord delivered me out of them all."},{"v":12,"t":"Yes, and all who desire to live godly in Christ Jesus will suffer persecution."},{"v":13,"t":"But evil men and impostors will grow worse and worse, deceiving and being deceived."},{"v":14,"t":"But you remain in the things which you have learned and have been assured of, knowing from whom you have learned them."},{"v":15,"t":"From infancy, you have known the holy Scriptures which are able to make you wise for salvation through faith which is in Christ Jesus."},{"v":16,"t":"Every Scripture is God-breathed and profitable for teaching, for reproof, for correction, and for instruction in righteousness,"},{"v":17,"t":"that each person who belongs to God may be complete, thoroughly equipped for every good work."}]},"4":{"en":[{"v":1,"t":"I command you therefore before God and the Lord Jesus Christ, who will judge the living and the dead at his appearing and his Kingdom:"},{"v":2,"t":"preach the word; be urgent in season and out of season; reprove, rebuke, and exhort with all patience and teaching."},{"v":3,"t":"For the time will come when they will not listen to the sound doctrine, but having itching ears, will heap up for themselves teachers after their own lusts,"},{"v":4,"t":"and will turn away their ears from the truth, and turn away to fables."},{"v":5,"t":"But you be sober in all things, suffer hardship, do the work of an evangelist, and fulfill your ministry."},{"v":6,"t":"For I am already being offered, and the time of my departure has come."},{"v":7,"t":"I have fought the good fight. I have finished the course. I have kept the faith."},{"v":8,"t":"From now on, the crown of righteousness is stored up for me, which the Lord, the righteous judge, will give to me on that day; and not to me only, but also to all those who have loved his appearing."},{"v":9,"t":"Be diligent to come to me soon,"},{"v":10,"t":"for Demas left me, having loved this present world, and went to Thessalonica; Crescens to Galatia; and Titus to Dalmatia."},{"v":11,"t":"Only Luke is with me. Take Mark and bring him with you, for he is useful to me for service."},{"v":12,"t":"But I sent Tychicus to Ephesus."},{"v":13,"t":"Bring the cloak that I left at Troas with Carpus when you come—and the books, especially the parchments."},{"v":14,"t":"Alexander the coppersmith did much evil to me. The Lord will repay him according to his deeds."},{"v":15,"t":"Beware of him, for he greatly opposed our words."},{"v":16,"t":"At my first defense, no one came to help me, but all left me. May it not be held against them."},{"v":17,"t":"But the Lord stood by me and strengthened me, that through me the message might be fully proclaimed, and that all the Gentiles might hear. So I was delivered out of the mouth of the lion."},{"v":18,"t":"And the Lord will deliver me from every evil work and will preserve me for his heavenly Kingdom. To him be the glory forever and ever. Amen."},{"v":19,"t":"Greet Prisca and Aquila, and the house of Onesiphorus."},{"v":20,"t":"Erastus remained at Corinth, but I left Trophimus at Miletus sick."},{"v":21,"t":"Be diligent to come before winter. Eubulus salutes you, as do Pudens, Linus, Claudia, and all the brothers."},{"v":22,"t":"The Lord Jesus Christ be with your spirit. Grace be with you. Amen."}]}},"TIT":{"1":{"en":[{"v":1,"t":"Paul, a servant of God and an apostle of Jesus Christ, according to the faith of God’s chosen ones and the knowledge of the truth which is according to godliness,"},{"v":2,"t":"in hope of eternal life, which God, who can’t lie, promised before time began;"},{"v":3,"t":"but in his own time revealed his word in the message with which I was entrusted according to the commandment of God our Savior,"},{"v":4,"t":"to Titus, my true child according to a common faith: Grace, mercy, and peace from God the Father and the Lord Jesus Christ our Savior."},{"v":5,"t":"I left you in Crete for this reason, that you would set in order the things that were lacking and appoint elders in every city, as I directed you—"},{"v":6,"t":"if anyone is blameless, the husband of one wife, having children who believe, who are not accused of loose or unruly behavior."},{"v":7,"t":"For the overseer must be blameless, as God’s steward, not self-pleasing, not easily angered, not given to wine, not violent, not greedy for dishonest gain;"},{"v":8,"t":"but given to hospitality, a lover of good, sober minded, fair, holy, self-controlled,"},{"v":9,"t":"holding to the faithful word which is according to the teaching, that he may be able to exhort in the sound doctrine, and to convict those who contradict him."},{"v":10,"t":"For there are also many unruly men, vain talkers and deceivers, especially those of the circumcision,"},{"v":11,"t":"whose mouths must be stopped: men who overthrow whole houses, teaching things which they ought not, for dishonest gain’s sake."},{"v":12,"t":"One of them, a prophet of their own, said, “Cretans are always liars, evil beasts, and idle gluttons.”"},{"v":13,"t":"This testimony is true. For this cause, reprove them sharply, that they may be sound in the faith,"},{"v":14,"t":"not paying attention to Jewish fables and commandments of men who turn away from the truth."},{"v":15,"t":"To the pure, all things are pure, but to those who are defiled and unbelieving, nothing is pure; but both their mind and their conscience are defiled."},{"v":16,"t":"They profess that they know God, but by their deeds they deny him, being abominable, disobedient, and unfit for any good work."}]},"2":{"en":[{"v":1,"t":"But say the things which fit sound doctrine,"},{"v":2,"t":"that older men should be temperate, sensible, sober minded, sound in faith, in love, and in perseverance,"},{"v":3,"t":"and that older women likewise be reverent in behavior, not slanderers nor enslaved to much wine, teachers of that which is good,"},{"v":4,"t":"that they may train the young wives to love their husbands, to love their children,"},{"v":5,"t":"to be sober minded, chaste, workers at home, kind, being in subjection to their own husbands, that God’s word may not be blasphemed."},{"v":6,"t":"Likewise, exhort the younger men to be sober minded."},{"v":7,"t":"In all things show yourself an example of good works. In your teaching, show integrity, seriousness, incorruptibility,"},{"v":8,"t":"and soundness of speech that can’t be condemned, that he who opposes you may be ashamed, having no evil thing to say about us."},{"v":9,"t":"Exhort servants to be in subjection to their own masters and to be well-pleasing in all things, not contradicting,"},{"v":10,"t":"not stealing, but showing all good fidelity, that they may adorn the doctrine of God, our Savior, in all things."},{"v":11,"t":"For the grace of God has appeared, bringing salvation to all men,"},{"v":12,"t":"instructing us to the intent that, denying ungodliness and worldly lusts, we would live soberly, righteously, and godly in this present age;"},{"v":13,"t":"looking for the blessed hope and appearing of the glory of our great God and Savior, Jesus Christ,"},{"v":14,"t":"who gave himself for us, that he might redeem us from all iniquity and purify for himself a people for his own possession, zealous for good works."},{"v":15,"t":"Say these things and exhort and reprove with all authority. Let no one despise you."}]},"3":{"en":[{"v":1,"t":"Remind them to be in subjection to rulers and to authorities, to be obedient, to be ready for every good work,"},{"v":2,"t":"to speak evil of no one, not to be contentious, to be gentle, showing all humility toward all men."},{"v":3,"t":"For we were also once foolish, disobedient, deceived, serving various lusts and pleasures, living in malice and envy, hateful, and hating one another."},{"v":4,"t":"But when the kindness of God our Savior and his love toward mankind appeared,"},{"v":5,"t":"not by works of righteousness which we did ourselves, but according to his mercy, he saved us through the washing of regeneration and renewing by the Holy Spirit,"},{"v":6,"t":"whom he poured out on us richly through Jesus Christ our Savior;"},{"v":7,"t":"that being justified by his grace, we might be made heirs according to the hope of eternal life."},{"v":8,"t":"This saying is faithful, and concerning these things I desire that you insist confidently, so that those who have believed God may be careful to maintain good works. These things are good and profitable to men;"},{"v":9,"t":"but shun foolish questionings, genealogies, strife, and disputes about the law; for they are unprofitable and vain."},{"v":10,"t":"Avoid a factious man after a first and second warning,"},{"v":11,"t":"knowing that such a one is perverted and sinful, being self-condemned."},{"v":12,"t":"When I send Artemas to you, or Tychicus, be diligent to come to me to Nicopolis, for I have determined to winter there."},{"v":13,"t":"Send Zenas the lawyer and Apollos on their journey speedily, that nothing may be lacking for them."},{"v":14,"t":"Let our people also learn to maintain good works to meet necessary needs, that they may not be unfruitful."},{"v":15,"t":"All who are with me greet you. Greet those who love us in faith. Grace be with you all. Amen."}]}},"PHM":{"1":{"en":[{"v":1,"t":"Paul, a prisoner of Christ Jesus, and Timothy our brother, to Philemon, our beloved fellow worker,"},{"v":2,"t":"to the beloved Apphia, to Archippus our fellow soldier, and to the assembly in your house:"},{"v":3,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":4,"t":"I thank my God always, making mention of you in my prayers,"},{"v":5,"t":"hearing of your love and of the faith which you have toward the Lord Jesus and toward all the saints,"},{"v":6,"t":"that the fellowship of your faith may become effective in the knowledge of every good thing which is in us in Christ Jesus."},{"v":7,"t":"For we have much joy and comfort in your love, because the hearts of the saints have been refreshed through you, brother."},{"v":8,"t":"Therefore though I have all boldness in Christ to command you that which is appropriate,"},{"v":9,"t":"yet for love’s sake I rather appeal to you, being such a one as Paul, the aged, but also a prisoner of Jesus Christ."},{"v":10,"t":"I appeal to you for my child Onesimus, whom I have become the father of in my chains,"},{"v":11,"t":"who once was useless to you, but now is useful to you and to me."},{"v":12,"t":"I am sending him back. Therefore receive him, that is, my own heart,"},{"v":13,"t":"whom I desired to keep with me, that on your behalf he might serve me in my chains for the Good News."},{"v":14,"t":"But I was willing to do nothing without your consent, that your goodness would not be as of necessity, but of free will."},{"v":15,"t":"For perhaps he was therefore separated from you for a while that you would have him forever,"},{"v":16,"t":"no longer as a slave, but more than a slave, a beloved brother—especially to me, but how much rather to you, both in the flesh and in the Lord."},{"v":17,"t":"If then you count me a partner, receive him as you would receive me."},{"v":18,"t":"But if he has wronged you at all or owes you anything, put that to my account."},{"v":19,"t":"I, Paul, write this with my own hand: I will repay it (not to mention to you that you owe to me even your own self besides)."},{"v":20,"t":"Yes, brother, let me have joy from you in the Lord. Refresh my heart in the Lord."},{"v":21,"t":"Having confidence in your obedience, I write to you, knowing that you will do even beyond what I say."},{"v":22,"t":"Also, prepare a guest room for me, for I hope that through your prayers I will be restored to you."},{"v":23,"t":"Epaphras, my fellow prisoner in Christ Jesus, greets you,"},{"v":24,"t":"as do Mark, Aristarchus, Demas, and Luke, my fellow workers."},{"v":25,"t":"The grace of our Lord Jesus Christ be with your spirit. Amen."}]}},"HEB":{"1":{"en":[{"v":1,"t":"God, having in the past spoken to the fathers through the prophets at many times and in various ways,"},{"v":2,"t":"has at the end of these days spoken to us by his Son, whom he appointed heir of all things, through whom also he made the worlds."},{"v":3,"t":"His Son is the radiance of his glory, the very image of his substance, and upholding all things by the word of his power, who, when he had by himself purified us of our sins, sat down on the right hand of the Majesty on high,"},{"v":4,"t":"having become as much better than the angels as the more excellent name he has inherited is better than theirs."},{"v":5,"t":"For to which of the angels did he say at any time, “You are my Son. Today I have become your father?” and again, “I will be to him a Father, and he will be to me a Son?”"},{"v":6,"t":"When he again brings in the firstborn into the world he says, “Let all the angels of God worship him.”"},{"v":7,"t":"Of the angels he says, “He makes his angels winds, and his servants a flame of fire.”"},{"v":8,"t":"But of the Son he says, “Your throne, O God, is forever and ever. The scepter of uprightness is the scepter of your Kingdom."},{"v":9,"t":"You have loved righteousness and hated iniquity; therefore God, your God, has anointed you with the oil of gladness above your fellows.”"},{"v":10,"t":"And, “You, Lord, in the beginning, laid the foundation of the earth. The heavens are the works of your hands."},{"v":11,"t":"They will perish, but you continue. They all will grow old like a garment does."},{"v":12,"t":"You will roll them up like a mantle, and they will be changed; but you are the same. Your years won’t fail.”"},{"v":13,"t":"But which of the angels has he told at any time, “Sit at my right hand, until I make your enemies the footstool of your feet?”"},{"v":14,"t":"Aren’t they all serving spirits, sent out to do service for the sake of those who will inherit salvation?"}]},"2":{"en":[{"v":1,"t":"Therefore we ought to pay greater attention to the things that were heard, lest perhaps we drift away."},{"v":2,"t":"For if the word spoken through angels proved steadfast, and every transgression and disobedience received a just penalty,"},{"v":3,"t":"how will we escape if we neglect so great a salvation—which at the first having been spoken through the Lord, was confirmed to us by those who heard,"},{"v":4,"t":"God also testifying with them, both by signs and wonders, by various works of power, and by gifts of the Holy Spirit, according to his own will?"},{"v":5,"t":"For he didn’t subject the world to come, of which we speak, to angels."},{"v":6,"t":"But one has somewhere testified, saying, “What is man, that you think of him? Or the son of man, that you care for him?"},{"v":7,"t":"You made him a little lower than the angels. You crowned him with glory and honor."},{"v":8,"t":"You have put all things in subjection under his feet.” For in that he subjected all things to him, he left nothing that is not subject to him. But now we don’t yet see all things subjected to him."},{"v":9,"t":"But we see him who has been made a little lower than the angels, Jesus, because of the suffering of death crowned with glory and honor, that by the grace of God he should taste of death for everyone."},{"v":10,"t":"For it became him, for whom are all things and through whom are all things, in bringing many children to glory, to make the author of their salvation perfect through sufferings."},{"v":11,"t":"For both he who sanctifies and those who are sanctified are all from one, for which cause he is not ashamed to call them brothers,"},{"v":12,"t":"saying, “I will declare your name to my brothers. Among the congregation I will sing your praise.”"},{"v":13,"t":"Again, “I will put my trust in him.” Again, “Behold, here I am with the children whom God has given me.”"},{"v":14,"t":"Since then the children have shared in flesh and blood, he also himself in the same way partook of the same, that through death he might bring to nothing him who had the power of death, that is, the devil,"},{"v":15,"t":"and might deliver all of them who through fear of death were all their lifetime subject to bondage."},{"v":16,"t":"For most certainly, he doesn’t give help to angels, but he gives help to the offspring of Abraham."},{"v":17,"t":"Therefore he was obligated in all things to be made like his brothers, that he might become a merciful and faithful high priest in things pertaining to God, to make atonement for the sins of the people."},{"v":18,"t":"For in that he himself has suffered being tempted, he is able to help those who are tempted."}]},"3":{"en":[{"v":1,"t":"Therefore, holy brothers, partakers of a heavenly calling, consider the Apostle and High Priest of our confession: Jesus,"},{"v":2,"t":"who was faithful to him who appointed him, as also Moses was in all his house."},{"v":3,"t":"For he has been counted worthy of more glory than Moses, because he who built the house has more honor than the house."},{"v":4,"t":"For every house is built by someone; but he who built all things is God."},{"v":5,"t":"Moses indeed was faithful in all his house as a servant, for a testimony of those things which were afterward to be spoken,"},{"v":6,"t":"but Christ is faithful as a Son over his house. We are his house, if we hold fast our confidence and the glorying of our hope firm to the end."},{"v":7,"t":"Therefore, even as the Holy Spirit says, “Today if you will hear his voice,"},{"v":8,"t":"don’t harden your hearts as in the rebellion, in the day of the trial in the wilderness,"},{"v":9,"t":"where your fathers tested me and tried me, and saw my deeds for forty years."},{"v":10,"t":"Therefore I was displeased with that generation, and said, ‘They always err in their heart, but they didn’t know my ways.’"},{"v":11,"t":"As I swore in my wrath, ‘They will not enter into my rest.’”"},{"v":12,"t":"Beware, brothers, lest perhaps there might be in any one of you an evil heart of unbelief, in falling away from the living God;"},{"v":13,"t":"but exhort one another day by day, so long as it is called “today”, lest any one of you be hardened by the deceitfulness of sin."},{"v":14,"t":"For we have become partakers of Christ, if we hold the beginning of our confidence firm to the end,"},{"v":15,"t":"while it is said, “Today if you will hear his voice, don’t harden your hearts, as in the rebellion.”"},{"v":16,"t":"For who, when they heard, rebelled? Wasn’t it all those who came out of Egypt led by Moses?"},{"v":17,"t":"With whom was he displeased forty years? Wasn’t it with those who sinned, whose bodies fell in the wilderness?"},{"v":18,"t":"To whom did he swear that they wouldn’t enter into his rest, but to those who were disobedient?"},{"v":19,"t":"We see that they weren’t able to enter in because of unbelief."}]},"4":{"en":[{"v":1,"t":"Let’s fear therefore, lest perhaps anyone of you should seem to have come short of a promise of entering into his rest."},{"v":2,"t":"For indeed we have had good news preached to us, even as they also did, but the word they heard didn’t profit them, because it wasn’t mixed with faith by those who heard."},{"v":3,"t":"For we who have believed do enter into that rest, even as he has said, “As I swore in my wrath, they will not enter into my rest;” although the works were finished from the foundation of the world."},{"v":4,"t":"For he has said this somewhere about the seventh day, “God rested on the seventh day from all his works;”"},{"v":5,"t":"and in this place again, “They will not enter into my rest.”"},{"v":6,"t":"Seeing therefore it remains that some should enter into it, and they to whom the good news was preached before failed to enter in because of disobedience,"},{"v":7,"t":"he again defines a certain day, “today”, saying through David so long a time afterward (just as has been said), “Today if you will hear his voice, don’t harden your hearts.”"},{"v":8,"t":"For if Joshua had given them rest, he would not have spoken afterward of another day."},{"v":9,"t":"There remains therefore a Sabbath rest for the people of God."},{"v":10,"t":"For he who has entered into his rest has himself also rested from his works, as God did from his."},{"v":11,"t":"Let’s therefore give diligence to enter into that rest, lest anyone fall after the same example of disobedience."},{"v":12,"t":"For the word of God is living and active, and sharper than any two-edged sword, piercing even to the dividing of soul and spirit, of both joints and marrow, and is able to discern the thoughts and intentions of the heart."},{"v":13,"t":"There is no creature that is hidden from his sight, but all things are naked and laid open before the eyes of him to whom we must give an account."},{"v":14,"t":"Having then a great high priest who has passed through the heavens, Jesus, the Son of God, let’s hold tightly to our confession."},{"v":15,"t":"For we don’t have a high priest who can’t be touched with the feeling of our infirmities, but one who has been in all points tempted like we are, yet without sin."},{"v":16,"t":"Let’s therefore draw near with boldness to the throne of grace, that we may receive mercy and may find grace for help in time of need."}]},"5":{"en":[{"v":1,"t":"For every high priest, being taken from among men, is appointed for men in things pertaining to God, that he may offer both gifts and sacrifices for sins."},{"v":2,"t":"The high priest can deal gently with those who are ignorant and going astray, because he himself is also surrounded with weakness."},{"v":3,"t":"Because of this, he must offer sacrifices for sins for the people, as well as for himself."},{"v":4,"t":"Nobody takes this honor on himself, but he is called by God, just like Aaron was."},{"v":5,"t":"So also Christ didn’t glorify himself to be made a high priest, but it was he who said to him, “You are my Son. Today I have become your father.”"},{"v":6,"t":"As he says also in another place, “You are a priest forever, after the order of Melchizedek.”"},{"v":7,"t":"He, in the days of his flesh, having offered up prayers and petitions with strong crying and tears to him who was able to save him from death, and having been heard for his godly fear,"},{"v":8,"t":"though he was a Son, yet learned obedience by the things which he suffered."},{"v":9,"t":"Having been made perfect, he became to all of those who obey him the author of eternal salvation,"},{"v":10,"t":"named by God a high priest after the order of Melchizedek."},{"v":11,"t":"About him we have many words to say, and hard to interpret, seeing you have become dull of hearing."},{"v":12,"t":"For although by this time you should be teachers, you again need to have someone teach you the rudiments of the first principles of the revelations of God. You have come to need milk, and not solid food."},{"v":13,"t":"For everyone who lives on milk is not experienced in the word of righteousness, for he is a baby."},{"v":14,"t":"But solid food is for those who are full grown, who by reason of use have their senses exercised to discern good and evil."}]},"6":{"en":[{"v":1,"t":"Therefore leaving the teaching of the first principles of Christ, let’s press on to perfection—not laying again a foundation of repentance from dead works, of faith toward God,"},{"v":2,"t":"of the teaching of baptisms, of laying on of hands, of resurrection of the dead, and of eternal judgment."},{"v":3,"t":"This will we do, if God permits."},{"v":4,"t":"For concerning those who were once enlightened and tasted of the heavenly gift, and were made partakers of the Holy Spirit,"},{"v":5,"t":"and tasted the good word of God and the powers of the age to come,"},{"v":6,"t":"and then fell away, it is impossible to renew them again to repentance; seeing they crucify the Son of God for themselves again, and put him to open shame."},{"v":7,"t":"For the land which has drunk the rain that comes often on it and produces a crop suitable for them for whose sake it is also tilled, receives blessing from God;"},{"v":8,"t":"but if it bears thorns and thistles, it is rejected and near being cursed, whose end is to be burned."},{"v":9,"t":"But, beloved, we are persuaded of better things for you, and things that accompany salvation, even though we speak like this."},{"v":10,"t":"For God is not unrighteous, so as to forget your work and the labor of love which you showed toward his name, in that you served the saints, and still do serve them."},{"v":11,"t":"We desire that each one of you may show the same diligence to the fullness of hope even to the end,"},{"v":12,"t":"that you won’t be sluggish, but imitators of those who through faith and perseverance inherited the promises."},{"v":13,"t":"For when God made a promise to Abraham, since he could swear by no one greater, he swore by himself,"},{"v":14,"t":"saying, “Surely blessing I will bless you, and multiplying I will multiply you.”"},{"v":15,"t":"Thus, having patiently endured, he obtained the promise."},{"v":16,"t":"For men indeed swear by a greater one, and in every dispute of theirs the oath is final for confirmation."},{"v":17,"t":"In this way God, being determined to show more abundantly to the heirs of the promise the immutability of his counsel, interposed with an oath,"},{"v":18,"t":"that by two immutable things, in which it is impossible for God to lie, we may have a strong encouragement, who have fled for refuge to take hold of the hope set before us."},{"v":19,"t":"This hope we have as an anchor of the soul, a hope both sure and steadfast and entering into that which is within the veil,"},{"v":20,"t":"where as a forerunner Jesus entered for us, having become a high priest forever after the order of Melchizedek."}]},"7":{"en":[{"v":1,"t":"For this Melchizedek, king of Salem, priest of God Most High, who met Abraham returning from the slaughter of the kings and blessed him,"},{"v":2,"t":"to whom also Abraham divided a tenth part of all (being first, by interpretation, “king of righteousness”, and then also “king of Salem”, which means “king of peace”,"},{"v":3,"t":"without father, without mother, without genealogy, having neither beginning of days nor end of life, but made like the Son of God), remains a priest continually."},{"v":4,"t":"Now consider how great this man was, to whom even Abraham the patriarch gave a tenth out of the best plunder."},{"v":5,"t":"They indeed of the sons of Levi who receive the priest’s office have a commandment to take tithes from the people according to the law, that is, of their brothers, though these have come out of the body of Abraham,"},{"v":6,"t":"but he whose genealogy is not counted from them has accepted tithes from Abraham, and has blessed him who has the promises."},{"v":7,"t":"But without any dispute the lesser is blessed by the greater."},{"v":8,"t":"Here people who die receive tithes, but there one receives tithes of whom it is testified that he lives."},{"v":9,"t":"We can say that through Abraham even Levi, who receives tithes, has paid tithes,"},{"v":10,"t":"for he was yet in the body of his father when Melchizedek met him."},{"v":11,"t":"Now if perfection was through the Levitical priesthood (for under it the people have received the law), what further need was there for another priest to arise after the order of Melchizedek, and not be called after the order of Aaron?"},{"v":12,"t":"For the priesthood being changed, there is of necessity a change made also in the law."},{"v":13,"t":"For he of whom these things are said belongs to another tribe, from which no one has officiated at the altar."},{"v":14,"t":"For it is evident that our Lord has sprung out of Judah, about which tribe Moses spoke nothing concerning priesthood."},{"v":15,"t":"This is yet more abundantly evident, if after the likeness of Melchizedek there arises another priest,"},{"v":16,"t":"who has been made, not after the law of a fleshly commandment, but after the power of an endless life;"},{"v":17,"t":"for it is testified, “You are a priest forever, according to the order of Melchizedek.”"},{"v":18,"t":"For there is an annulling of a foregoing commandment because of its weakness and uselessness"},{"v":19,"t":"(for the law made nothing perfect), and a bringing in of a better hope, through which we draw near to God."},{"v":20,"t":"Inasmuch as he was not made priest without the taking of an oath"},{"v":21,"t":"(for they indeed have been made priests without an oath), but he with an oath by him that says of him, “The Lord swore and will not change his mind, ‘You are a priest forever, according to the order of Melchizedek.’”"},{"v":22,"t":"By so much, Jesus has become the guarantee of a better covenant."},{"v":23,"t":"Many, indeed, have been made priests, because they are hindered from continuing by death."},{"v":24,"t":"But he, because he lives forever, has his priesthood unchangeable."},{"v":25,"t":"Therefore he is also able to save to the uttermost those who draw near to God through him, seeing that he lives forever to make intercession for them."},{"v":26,"t":"For such a high priest was fitting for us: holy, guiltless, undefiled, separated from sinners, and made higher than the heavens;"},{"v":27,"t":"who doesn’t need, like those high priests, to offer up sacrifices daily, first for his own sins, and then for the sins of the people. For he did this once for all, when he offered up himself."},{"v":28,"t":"For the law appoints men as high priests who have weakness, but the word of the oath, which came after the law, appoints a Son forever who has been perfected."}]},"8":{"en":[{"v":1,"t":"Now in the things which we are saying, the main point is this: we have such a high priest, who sat down on the right hand of the throne of the Majesty in the heavens,"},{"v":2,"t":"a servant of the sanctuary and of the true tabernacle which the Lord pitched, not man."},{"v":3,"t":"For every high priest is appointed to offer both gifts and sacrifices. Therefore it is necessary that this high priest also have something to offer."},{"v":4,"t":"For if he were on earth, he would not be a priest at all, seeing there are priests who offer the gifts according to the law,"},{"v":5,"t":"who serve a copy and shadow of the heavenly things, even as Moses was warned by God when he was about to make the tabernacle, for he said, “See, you shall make everything according to the pattern that was shown to you on the mountain.”"},{"v":6,"t":"But now he has obtained a more excellent ministry, by as much as he is also the mediator of a better covenant, which on better promises has been given as law."},{"v":7,"t":"For if that first covenant had been faultless, then no place would have been sought for a second."},{"v":8,"t":"For finding fault with them, he said, “Behold, the days are coming”, says the Lord, “that I will make a new covenant with the house of Israel and with the house of Judah;"},{"v":9,"t":"not according to the covenant that I made with their fathers in the day that I took them by the hand to lead them out of the land of Egypt; for they didn’t continue in my covenant, and I disregarded them,” says the Lord."},{"v":10,"t":"“For this is the covenant that I will make with the house of Israel after those days,” says the Lord: “I will put my laws into their mind; I will also write them on their heart. I will be their God, and they will be my people."},{"v":11,"t":"They will not teach every man his fellow citizen and every man his brother, saying, ‘Know the Lord,’ for all will know me, from their least to their greatest."},{"v":12,"t":"For I will be merciful to their unrighteousness. I will remember their sins and lawless deeds no more.”"},{"v":13,"t":"In that he says, “A new covenant”, he has made the first obsolete. But that which is becoming obsolete and grows aged is near to vanishing away."}]},"9":{"en":[{"v":1,"t":"Now indeed even the first covenant had ordinances of divine service and an earthly sanctuary."},{"v":2,"t":"For a tabernacle was prepared. In the first part were the lamp stand, the table, and the show bread, which is called the Holy Place."},{"v":3,"t":"After the second veil was the tabernacle which is called the Holy of Holies,"},{"v":4,"t":"having a golden altar of incense and the ark of the covenant overlaid on all sides with gold, in which was a golden pot holding the manna, Aaron’s rod that budded, and the tablets of the covenant;"},{"v":5,"t":"and above it cherubim of glory overshadowing the mercy seat, of which things we can’t speak now in detail."},{"v":6,"t":"Now these things having been thus prepared, the priests go in continually into the first tabernacle, accomplishing the services,"},{"v":7,"t":"but into the second the high priest alone, once in the year, not without blood, which he offers for himself and for the errors of the people."},{"v":8,"t":"The Holy Spirit is indicating this, that the way into the Holy Place wasn’t yet revealed while the first tabernacle was still standing."},{"v":9,"t":"This is a symbol of the present age, where gifts and sacrifices are offered that are incapable, concerning the conscience, of making the worshiper perfect,"},{"v":10,"t":"being only (with foods and drinks and various washings) fleshly ordinances, imposed until a time of reformation."},{"v":11,"t":"But Christ having come as a high priest of the coming good things, through the greater and more perfect tabernacle, not made with hands, that is to say, not of this creation,"},{"v":12,"t":"nor yet through the blood of goats and calves, but through his own blood, entered in once for all into the Holy Place, having obtained eternal redemption."},{"v":13,"t":"For if the blood of goats and bulls, and the ashes of a heifer sprinkling those who have been defiled, sanctify to the cleanness of the flesh,"},{"v":14,"t":"how much more will the blood of Christ, who through the eternal Spirit offered himself without defect to God, cleanse your conscience from dead works to serve the living God?"},{"v":15,"t":"For this reason he is the mediator of a new covenant, since a death has occurred for the redemption of the transgressions that were under the first covenant, that those who have been called may receive the promise of the eternal inheritance."},{"v":16,"t":"For where a last will and testament is, there must of necessity be the death of him who made it."},{"v":17,"t":"For a will is in force where there has been death, for it is never in force while he who made it lives."},{"v":18,"t":"Therefore even the first covenant has not been dedicated without blood."},{"v":19,"t":"For when every commandment had been spoken by Moses to all the people according to the law, he took the blood of the calves and the goats, with water and scarlet wool and hyssop, and sprinkled both the book itself and all the people,"},{"v":20,"t":"saying, “This is the blood of the covenant which God has commanded you.”"},{"v":21,"t":"He sprinkled the tabernacle and all the vessels of the ministry in the same way with the blood."},{"v":22,"t":"According to the law, nearly everything is cleansed with blood, and apart from shedding of blood there is no remission."},{"v":23,"t":"It was necessary therefore that the copies of the things in the heavens should be cleansed with these, but the heavenly things themselves with better sacrifices than these."},{"v":24,"t":"For Christ hasn’t entered into holy places made with hands, which are representations of the true, but into heaven itself, now to appear in the presence of God for us;"},{"v":25,"t":"nor yet that he should offer himself often, as the high priest enters into the holy place year by year with blood not his own,"},{"v":26,"t":"or else he must have suffered often since the foundation of the world. But now once at the end of the ages, he has been revealed to put away sin by the sacrifice of himself."},{"v":27,"t":"Inasmuch as it is appointed for men to die once, and after this, judgment,"},{"v":28,"t":"so Christ also, having been offered once to bear the sins of many, will appear a second time, not to deal with sin, but to save those who are eagerly waiting for him."}]},"10":{"en":[{"v":1,"t":"For the law, having a shadow of the good to come, not the very image of the things, can never with the same sacrifices year by year, which they offer continually, make perfect those who draw near."},{"v":2,"t":"Or else wouldn’t they have ceased to be offered, because the worshipers, having been once cleansed, would have had no more consciousness of sins?"},{"v":3,"t":"But in those sacrifices there is a yearly reminder of sins."},{"v":4,"t":"For it is impossible that the blood of bulls and goats should take away sins."},{"v":5,"t":"Therefore when he comes into the world, he says, “You didn’t desire sacrifice and offering, but you prepared a body for me."},{"v":6,"t":"You had no pleasure in whole burnt offerings and sacrifices for sin."},{"v":7,"t":"Then I said, ‘Behold, I have come (in the scroll of the book it is written of me) to do your will, O God.’”"},{"v":8,"t":"Previously saying, “Sacrifices and offerings and whole burnt offerings and sacrifices for sin you didn’t desire, neither had pleasure in them” (those which are offered according to the law),"},{"v":9,"t":"then he has said, “Behold, I have come to do your will.” He takes away the first, that he may establish the second,"},{"v":10,"t":"by which will we have been sanctified through the offering of the body of Jesus Christ once for all."},{"v":11,"t":"Every priest indeed stands day by day serving and offering often the same sacrifices, which can never take away sins,"},{"v":12,"t":"but he, when he had offered one sacrifice for sins forever, sat down on the right hand of God,"},{"v":13,"t":"from that time waiting until his enemies are made the footstool of his feet."},{"v":14,"t":"For by one offering he has perfected forever those who are being sanctified."},{"v":15,"t":"The Holy Spirit also testifies to us, for after saying,"},{"v":16,"t":"“This is the covenant that I will make with them after those days,” says the Lord, “I will put my laws on their heart, I will also write them on their mind;” then he says,"},{"v":17,"t":"“I will remember their sins and their iniquities no more.”"},{"v":18,"t":"Now where remission of these is, there is no more offering for sin."},{"v":19,"t":"Having therefore, brothers, boldness to enter into the holy place by the blood of Jesus,"},{"v":20,"t":"by the way which he dedicated for us, a new and living way, through the veil, that is to say, his flesh,"},{"v":21,"t":"and having a great priest over God’s house,"},{"v":22,"t":"let’s draw near with a true heart in fullness of faith, having our hearts sprinkled from an evil conscience and having our body washed with pure water,"},{"v":23,"t":"let’s hold fast the confession of our hope without wavering; for he who promised is faithful."},{"v":24,"t":"Let’s consider how to provoke one another to love and good works,"},{"v":25,"t":"not forsaking our own assembling together, as the custom of some is, but exhorting one another, and so much the more as you see the Day approaching."},{"v":26,"t":"For if we sin willfully after we have received the knowledge of the truth, there remains no more a sacrifice for sins,"},{"v":27,"t":"but a certain fearful expectation of judgment, and a fierceness of fire which will devour the adversaries."},{"v":28,"t":"A man who disregards Moses’ law dies without compassion on the word of two or three witnesses."},{"v":29,"t":"How much worse punishment do you think he will be judged worthy of who has trodden under foot the Son of God, and has counted the blood of the covenant with which he was sanctified an unholy thing, and has insulted the Spirit of grace?"},{"v":30,"t":"For we know him who said, “Vengeance belongs to me. I will repay,” says the Lord. Again, “The Lord will judge his people.”"},{"v":31,"t":"It is a fearful thing to fall into the hands of the living God."},{"v":32,"t":"But remember the former days, in which, after you were enlightened, you endured a great struggle with sufferings:"},{"v":33,"t":"partly, being exposed to both reproaches and oppressions, and partly, becoming partakers with those who were treated so."},{"v":34,"t":"For you both had compassion on me in my chains and joyfully accepted the plundering of your possessions, knowing that you have for yourselves a better possession and an enduring one in the heavens."},{"v":35,"t":"Therefore don’t throw away your boldness, which has a great reward."},{"v":36,"t":"For you need endurance so that, having done the will of God, you may receive the promise."},{"v":37,"t":"“In a very little while, he who comes will come and will not wait."},{"v":38,"t":"But the righteous one will live by faith. If he shrinks back, my soul has no pleasure in him.”"},{"v":39,"t":"But we are not of those who shrink back to destruction, but of those who have faith to the saving of the soul."}]},"11":{"en":[{"v":1,"t":"Now faith is assurance of things hoped for, proof of things not seen."},{"v":2,"t":"For by this, the elders obtained approval."},{"v":3,"t":"By faith we understand that the universe has been framed by the word of God, so that what is seen has not been made out of things which are visible."},{"v":4,"t":"By faith Abel offered to God a more excellent sacrifice than Cain, through which he had testimony given to him that he was righteous, God testifying with respect to his gifts; and through it he, being dead, still speaks."},{"v":5,"t":"By faith Enoch was taken away, so that he wouldn’t see death, and he was not found, because God translated him. For he has had testimony given to him that before his translation he had been well pleasing to God."},{"v":6,"t":"Without faith it is impossible to be well pleasing to him, for he who comes to God must believe that he exists, and that he is a rewarder of those who seek him."},{"v":7,"t":"By faith Noah, being warned about things not yet seen, moved with godly fear, prepared a ship for the saving of his house, through which he condemned the world and became heir of the righteousness which is according to faith."},{"v":8,"t":"By faith Abraham, when he was called, obeyed to go out to the place which he was to receive for an inheritance. He went out, not knowing where he went."},{"v":9,"t":"By faith he lived as an alien in the land of promise, as in a land not his own, dwelling in tents with Isaac and Jacob, the heirs with him of the same promise."},{"v":10,"t":"For he was looking for the city which has foundations, whose builder and maker is God."},{"v":11,"t":"By faith even Sarah herself received power to conceive, and she bore a child when she was past age, since she counted him faithful who had promised."},{"v":12,"t":"Therefore as many as the stars of the sky in multitude, and as innumerable as the sand which is by the sea shore, were fathered by one man, and him as good as dead."},{"v":13,"t":"These all died in faith, not having received the promises, but having seen them and embraced them from afar, and having confessed that they were strangers and pilgrims on the earth."},{"v":14,"t":"For those who say such things make it clear that they are seeking a country of their own."},{"v":15,"t":"If indeed they had been thinking of that country from which they went out, they would have had enough time to return."},{"v":16,"t":"But now they desire a better country, that is, a heavenly one. Therefore God is not ashamed of them, to be called their God, for he has prepared a city for them."},{"v":17,"t":"By faith, Abraham, being tested, offered up Isaac. Yes, he who had gladly received the promises was offering up his only born son,"},{"v":18,"t":"to whom it was said, “Your offspring will be accounted as from Isaac,”"},{"v":19,"t":"concluding that God is able to raise up even from the dead. Figuratively speaking, he also did receive him back from the dead."},{"v":20,"t":"By faith Isaac blessed Jacob and Esau, even concerning things to come."},{"v":21,"t":"By faith Jacob, when he was dying, blessed each of the sons of Joseph, and worshiped, leaning on the top of his staff."},{"v":22,"t":"By faith Joseph, when his end was near, made mention of the departure of the children of Israel, and gave instructions concerning his bones."},{"v":23,"t":"By faith Moses, when he was born, was hidden for three months by his parents, because they saw that he was a beautiful child; and they were not afraid of the king’s commandment."},{"v":24,"t":"By faith Moses, when he had grown up, refused to be called the son of Pharaoh’s daughter,"},{"v":25,"t":"choosing rather to share ill treatment with God’s people than to enjoy the pleasures of sin for a time,"},{"v":26,"t":"considering the reproach of Christ greater riches than the treasures of Egypt; for he looked to the reward."},{"v":27,"t":"By faith he left Egypt, not fearing the wrath of the king; for he endured, as seeing him who is invisible."},{"v":28,"t":"By faith he kept the Passover and the sprinkling of the blood, that the destroyer of the firstborn should not touch them."},{"v":29,"t":"By faith they passed through the Red Sea as on dry land. When the Egyptians tried to do so, they were swallowed up."},{"v":30,"t":"By faith the walls of Jericho fell down after they had been encircled for seven days."},{"v":31,"t":"By faith Rahab the prostitute didn’t perish with those who were disobedient, having received the spies in peace."},{"v":32,"t":"What more shall I say? For the time would fail me if I told of Gideon, Barak, Samson, Jephthah, David, Samuel, and the prophets—"},{"v":33,"t":"who through faith subdued kingdoms, worked out righteousness, obtained promises, stopped the mouths of lions,"},{"v":34,"t":"quenched the power of fire, escaped the edge of the sword, from weakness were made strong, grew mighty in war, and caused foreign armies to flee."},{"v":35,"t":"Women received their dead by resurrection. Others were tortured, not accepting their deliverance, that they might obtain a better resurrection."},{"v":36,"t":"Others were tried by mocking and scourging, yes, moreover by bonds and imprisonment."},{"v":37,"t":"They were stoned. They were sawn apart. They were tempted. They were slain with the sword. They went around in sheep skins and in goat skins; being destitute, afflicted, ill-treated—"},{"v":38,"t":"of whom the world was not worthy—wandering in deserts, mountains, caves, and the holes of the earth."},{"v":39,"t":"These all, having been commended for their faith, didn’t receive the promise,"},{"v":40,"t":"God having provided some better thing concerning us, so that apart from us they should not be made perfect."}]},"12":{"en":[{"v":1,"t":"Therefore let’s also, seeing we are surrounded by so great a cloud of witnesses, lay aside every weight and the sin which so easily entangles us, and let’s run with perseverance the race that is set before us,"},{"v":2,"t":"looking to Jesus, the author and perfecter of faith, who for the joy that was set before him endured the cross, despising its shame, and has sat down at the right hand of the throne of God."},{"v":3,"t":"For consider him who has endured such contradiction of sinners against himself, that you don’t grow weary, fainting in your souls."},{"v":4,"t":"You have not yet resisted to blood, striving against sin."},{"v":5,"t":"You have forgotten the exhortation which reasons with you as with children, “My son, don’t take lightly the chastening of the Lord, nor faint when you are reproved by him;"},{"v":6,"t":"for whom the Lord loves, he disciplines, and chastises every son whom he receives.”"},{"v":7,"t":"It is for discipline that you endure. God deals with you as with children, for what son is there whom his father doesn’t discipline?"},{"v":8,"t":"But if you are without discipline, of which all have been made partakers, then you are illegitimate, and not children."},{"v":9,"t":"Furthermore, we had the fathers of our flesh to chasten us, and we paid them respect. Shall we not much rather be in subjection to the Father of spirits and live?"},{"v":10,"t":"For they indeed for a few days disciplined us as seemed good to them, but he for our profit, that we may be partakers of his holiness."},{"v":11,"t":"All chastening seems for the present to be not joyous but grievous; yet afterward it yields the peaceful fruit of righteousness to those who have been trained by it."},{"v":12,"t":"Therefore lift up the hands that hang down and the feeble knees,"},{"v":13,"t":"and make straight paths for your feet, so what is lame may not be dislocated, but rather be healed."},{"v":14,"t":"Follow after peace with all men, and the sanctification without which no man will see the Lord,"},{"v":15,"t":"looking carefully lest there be any man who falls short of the grace of God, lest any root of bitterness springing up trouble you and many be defiled by it,"},{"v":16,"t":"lest there be any sexually immoral person or profane person, like Esau, who sold his birthright for one meal."},{"v":17,"t":"For you know that even when he afterward desired to inherit the blessing, he was rejected, for he found no place for a change of mind though he sought it diligently with tears."},{"v":18,"t":"For you have not come to a mountain that might be touched and that burned with fire, and to blackness, darkness, storm,"},{"v":19,"t":"the sound of a trumpet, and the voice of words; which those who heard it begged that not one more word should be spoken to them,"},{"v":20,"t":"for they could not stand that which was commanded, “If even an animal touches the mountain, it shall be stoned”."},{"v":21,"t":"So fearful was the appearance that Moses said, “I am terrified and trembling.”"},{"v":22,"t":"But you have come to Mount Zion and to the city of the living God, the heavenly Jerusalem, and to innumerable multitudes of angels,"},{"v":23,"t":"to the festal gathering and assembly of the firstborn who are enrolled in heaven, to God the Judge of all, to the spirits of just men made perfect,"},{"v":24,"t":"to Jesus, the mediator of a new covenant, and to the blood of sprinkling that speaks better than that of Abel."},{"v":25,"t":"See that you don’t refuse him who speaks. For if they didn’t escape when they refused him who warned on the earth, how much more will we not escape who turn away from him who warns from heaven,"},{"v":26,"t":"whose voice shook the earth then, but now he has promised, saying, “Yet once more I will shake not only the earth, but also the heavens.”"},{"v":27,"t":"This phrase, “Yet once more” signifies the removing of those things that are shaken, as of things that have been made, that those things which are not shaken may remain."},{"v":28,"t":"Therefore, receiving a Kingdom that can’t be shaken, let’s have grace, through which we serve God acceptably, with reverence and awe,"},{"v":29,"t":"for our God is a consuming fire."}]},"13":{"en":[{"v":1,"t":"Let brotherly love continue."},{"v":2,"t":"Don’t forget to show hospitality to strangers, for in doing so, some have entertained angels without knowing it."},{"v":3,"t":"Remember those who are in bonds, as bound with them, and those who are ill-treated, since you are also in the body."},{"v":4,"t":"Let marriage be held in honor among all, and let the bed be undefiled; but God will judge the sexually immoral and adulterers."},{"v":5,"t":"Be free from the love of money, content with such things as you have, for he has said, “I will in no way leave you, neither will I in any way forsake you.”"},{"v":6,"t":"So that with good courage we say, “The Lord is my helper. I will not fear. What can man do to me?”"},{"v":7,"t":"Remember your leaders, men who spoke to you the word of God, and considering the results of their conduct, imitate their faith."},{"v":8,"t":"Jesus Christ is the same yesterday, today, and forever."},{"v":9,"t":"Don’t be carried away by various and strange teachings, for it is good that the heart be established by grace, not by foods, through which those who were so occupied were not benefited."},{"v":10,"t":"We have an altar from which those who serve the holy tabernacle have no right to eat."},{"v":11,"t":"For the bodies of those animals, whose blood is brought into the holy place by the high priest as an offering for sin, are burned outside of the camp."},{"v":12,"t":"Therefore Jesus also, that he might sanctify the people through his own blood, suffered outside of the gate."},{"v":13,"t":"Let’s therefore go out to him outside of the camp, bearing his reproach."},{"v":14,"t":"For we don’t have here an enduring city, but we seek that which is to come."},{"v":15,"t":"Through him, then, let’s offer up a sacrifice of praise to God continually, that is, the fruit of lips which proclaim allegiance to his name."},{"v":16,"t":"But don’t forget to be doing good and sharing, for with such sacrifices God is well pleased."},{"v":17,"t":"Obey your leaders and submit to them, for they watch on behalf of your souls, as those who will give account, that they may do this with joy and not with groaning, for that would be unprofitable for you."},{"v":18,"t":"Pray for us, for we are persuaded that we have a good conscience, desiring to live honorably in all things."},{"v":19,"t":"I strongly urge you to do this, that I may be restored to you sooner."},{"v":20,"t":"Now may the God of peace, who brought again from the dead the great shepherd of the sheep with the blood of an eternal covenant, our Lord Jesus,"},{"v":21,"t":"make you complete in every good work to do his will, working in you that which is well pleasing in his sight, through Jesus Christ, to whom be the glory forever and ever. Amen."},{"v":22,"t":"But I exhort you, brothers, endure the word of exhortation, for I have written to you in few words."},{"v":23,"t":"Know that our brother Timothy has been freed, with whom, if he comes shortly, I will see you."},{"v":24,"t":"Greet all of your leaders and all the saints. The Italians greet you."},{"v":25,"t":"Grace be with you all. Amen."}]}},"JAS":{"1":{"en":[{"v":1,"t":"James, a servant of God and of the Lord Jesus Christ, to the twelve tribes which are in the Dispersion: Greetings."},{"v":2,"t":"Count it all joy, my brothers, when you fall into various temptations,"},{"v":3,"t":"knowing that the testing of your faith produces endurance."},{"v":4,"t":"Let endurance have its perfect work, that you may be perfect and complete, lacking in nothing."},{"v":5,"t":"But if any of you lacks wisdom, let him ask of God, who gives to all liberally and without reproach, and it will be given to him."},{"v":6,"t":"But let him ask in faith, without any doubting, for he who doubts is like a wave of the sea, driven by the wind and tossed."},{"v":7,"t":"For that man shouldn’t think that he will receive anything from the Lord."},{"v":8,"t":"He is a double-minded man, unstable in all his ways."},{"v":9,"t":"Let the brother in humble circumstances glory in his high position;"},{"v":10,"t":"and the rich, in that he is made humble, because like the flower in the grass, he will pass away."},{"v":11,"t":"For the sun arises with the scorching wind and withers the grass; and the flower in it falls, and the beauty of its appearance perishes. So the rich man will also fade away in his pursuits."},{"v":12,"t":"Blessed is a person who endures temptation, for when he has been approved, he will receive the crown of life which the Lord promised to those who love him."},{"v":13,"t":"Let no man say when he is tempted, “I am tempted by God,” for God can’t be tempted by evil, and he himself tempts no one."},{"v":14,"t":"But each one is tempted when he is drawn away by his own lust and enticed."},{"v":15,"t":"Then the lust, when it has conceived, bears sin. The sin, when it is full grown, produces death."},{"v":16,"t":"Don’t be deceived, my beloved brothers."},{"v":17,"t":"Every good gift and every perfect gift is from above, coming down from the Father of lights, with whom can be no variation nor turning shadow."},{"v":18,"t":"Of his own will he gave birth to us by the word of truth, that we should be a kind of first fruits of his creatures."},{"v":19,"t":"So, then, my beloved brothers, let every man be swift to hear, slow to speak, and slow to anger;"},{"v":20,"t":"for the anger of man doesn’t produce the righteousness of God."},{"v":21,"t":"Therefore, putting away all filthiness and overflowing of wickedness, receive with humility the implanted word, which is able to save your souls."},{"v":22,"t":"But be doers of the word, and not only hearers, deluding your own selves."},{"v":23,"t":"For if anyone is a hearer of the word and not a doer, he is like a man looking at his natural face in a mirror;"},{"v":24,"t":"for he sees himself, and goes away, and immediately forgets what kind of man he was."},{"v":25,"t":"But he who looks into the perfect law of freedom and continues, not being a hearer who forgets but a doer of the work, this man will be blessed in what he does."},{"v":26,"t":"If anyone among you thinks himself to be religious while he doesn’t bridle his tongue, but deceives his heart, this man’s religion is worthless."},{"v":27,"t":"Pure religion and undefiled before our God and Father is this: to visit the fatherless and widows in their affliction, and to keep oneself unstained by the world."}]},"2":{"en":[{"v":1,"t":"My brothers, don’t hold the faith of our glorious Lord Jesus Christ with partiality."},{"v":2,"t":"For if a man with a gold ring, in fine clothing, comes into your synagogue, and a poor man in filthy clothing also comes in,"},{"v":3,"t":"and you pay special attention to him who wears the fine clothing and say, “Sit here in a good place;” and you tell the poor man, “Stand there,” or “Sit by my footstool”"},{"v":4,"t":"haven’t you shown partiality among yourselves, and become judges with evil thoughts?"},{"v":5,"t":"Listen, my beloved brothers. Didn’t God choose those who are poor in this world to be rich in faith and heirs of the Kingdom which he promised to those who love him?"},{"v":6,"t":"But you have dishonored the poor man. Don’t the rich oppress you and personally drag you before the courts?"},{"v":7,"t":"Don’t they blaspheme the honorable name by which you are called?"},{"v":8,"t":"However, if you fulfill the royal law according to the Scripture, “You shall love your neighbor as yourself,” you do well."},{"v":9,"t":"But if you show partiality, you commit sin, being convicted by the law as transgressors."},{"v":10,"t":"For whoever keeps the whole law, and yet stumbles in one point, he has become guilty of all."},{"v":11,"t":"For he who said, “Do not commit adultery,” also said, “Do not commit murder.” Now if you do not commit adultery but do murder, you have become a transgressor of the law."},{"v":12,"t":"So speak and so do as men who are to be judged by the law of freedom."},{"v":13,"t":"For judgment is without mercy to him who has shown no mercy. Mercy triumphs over judgment."},{"v":14,"t":"What good is it, my brothers, if a man says he has faith, but has no works? Can faith save him?"},{"v":15,"t":"And if a brother or sister is naked and in lack of daily food,"},{"v":16,"t":"and one of you tells them, “Go in peace. Be warmed and filled;” yet you didn’t give them the things the body needs, what good is it?"},{"v":17,"t":"Even so faith, if it has no works, is dead in itself."},{"v":18,"t":"Yes, a man will say, “You have faith, and I have works.” Show me your faith without works, and I will show you my faith by my works."},{"v":19,"t":"You believe that God is one. You do well. The demons also believe—and shudder."},{"v":20,"t":"But do you want to know, vain man, that faith apart from works is dead?"},{"v":21,"t":"Wasn’t Abraham our father justified by works, in that he offered up Isaac his son on the altar?"},{"v":22,"t":"You see that faith worked with his works, and by works faith was perfected."},{"v":23,"t":"So the Scripture was fulfilled which says, “Abraham believed God, and it was accounted to him as righteousness,” and he was called the friend of God."},{"v":24,"t":"You see then that by works a man is justified, and not only by faith."},{"v":25,"t":"In the same way, wasn’t Rahab the prostitute also justified by works when she received the messengers and sent them out another way?"},{"v":26,"t":"For as the body apart from the spirit is dead, even so faith apart from works is dead."}]},"3":{"en":[{"v":1,"t":"Let not many of you be teachers, my brothers, knowing that we will receive heavier judgment."},{"v":2,"t":"For we all stumble in many things. Anyone who doesn’t stumble in word is a perfect person, able to bridle the whole body also."},{"v":3,"t":"Indeed, we put bits into the horses’ mouths so that they may obey us, and we guide their whole body."},{"v":4,"t":"Behold, the ships also, though they are so big and are driven by fierce winds, are yet guided by a very small rudder, wherever the pilot desires."},{"v":5,"t":"So the tongue is also a little member, and boasts great things. See how a small fire can spread to a large forest!"},{"v":6,"t":"And the tongue is a fire. The world of iniquity among our members is the tongue, which defiles the whole body, and sets on fire the course of nature, and is set on fire by Gehenna."},{"v":7,"t":"For every kind of animal, bird, creeping thing, and sea creature is tamed, and has been tamed by mankind;"},{"v":8,"t":"but nobody can tame the tongue. It is a restless evil, full of deadly poison."},{"v":9,"t":"With it we bless our God and Father, and with it we curse men who are made in the image of God."},{"v":10,"t":"Out of the same mouth comes blessing and cursing. My brothers, these things ought not to be so."},{"v":11,"t":"Does a spring send out from the same opening fresh and bitter water?"},{"v":12,"t":"Can a fig tree, my brothers, yield olives, or a vine figs? Thus no spring yields both salt water and fresh water."},{"v":13,"t":"Who is wise and understanding among you? Let him show by his good conduct that his deeds are done in gentleness of wisdom."},{"v":14,"t":"But if you have bitter jealousy and selfish ambition in your heart, don’t boast and don’t lie against the truth."},{"v":15,"t":"This wisdom is not that which comes down from above, but is earthly, sensual, and demonic."},{"v":16,"t":"For where jealousy and selfish ambition are, there is confusion and every evil deed."},{"v":17,"t":"But the wisdom that is from above is first pure, then peaceful, gentle, reasonable, full of mercy and good fruits, without partiality, and without hypocrisy."},{"v":18,"t":"Now the fruit of righteousness is sown in peace by those who make peace."}]},"4":{"en":[{"v":1,"t":"Where do wars and fightings among you come from? Don’t they come from your pleasures that war in your members?"},{"v":2,"t":"You lust, and don’t have. You murder and covet, and can’t obtain. You fight and make war. You don’t have, because you don’t ask."},{"v":3,"t":"You ask, and don’t receive, because you ask with wrong motives, so that you may spend it on your pleasures."},{"v":4,"t":"You adulterers and adulteresses, don’t you know that friendship with the world is hostility toward God? Whoever therefore wants to be a friend of the world makes himself an enemy of God."},{"v":5,"t":"Or do you think that the Scripture says in vain, “The Spirit who lives in us yearns jealously”?"},{"v":6,"t":"But he gives more grace. Therefore it says, “God resists the proud, but gives grace to the humble.”"},{"v":7,"t":"Be subject therefore to God. Resist the devil, and he will flee from you."},{"v":8,"t":"Draw near to God, and he will draw near to you. Cleanse your hands, you sinners. Purify your hearts, you double-minded."},{"v":9,"t":"Lament, mourn, and weep. Let your laughter be turned to mourning and your joy to gloom."},{"v":10,"t":"Humble yourselves in the sight of the Lord, and he will exalt you."},{"v":11,"t":"Don’t speak against one another, brothers. He who speaks against a brother and judges his brother, speaks against the law and judges the law. But if you judge the law, you are not a doer of the law but a judge."},{"v":12,"t":"Only one is the lawgiver, who is able to save and to destroy. But who are you to judge another?"},{"v":13,"t":"Come now, you who say, “Today or tomorrow let’s go into this city and spend a year there, trade, and make a profit.”"},{"v":14,"t":"Yet you don’t know what your life will be like tomorrow. For what is your life? For you are a vapor that appears for a little time and then vanishes away."},{"v":15,"t":"For you ought to say, “If the Lord wills, we will both live, and do this or that.”"},{"v":16,"t":"But now you glory in your boasting. All such boasting is evil."},{"v":17,"t":"To him therefore who knows to do good and doesn’t do it, to him it is sin."}]},"5":{"en":[{"v":1,"t":"Come now, you rich, weep and howl for your miseries that are coming on you."},{"v":2,"t":"Your riches are corrupted and your garments are moth-eaten."},{"v":3,"t":"Your gold and your silver are corroded, and their corrosion will be for a testimony against you and will eat your flesh like fire. You have laid up your treasure in the last days."},{"v":4,"t":"Behold, the wages of the laborers who mowed your fields, which you have kept back by fraud, cry out; and the cries of those who reaped have entered into the ears of the Lord of Armies."},{"v":5,"t":"You have lived in luxury on the earth, and taken your pleasure. You have nourished your hearts as in a day of slaughter."},{"v":6,"t":"You have condemned and you have murdered the righteous one. He doesn’t resist you."},{"v":7,"t":"Be patient therefore, brothers, until the coming of the Lord. Behold, the farmer waits for the precious fruit of the earth, being patient over it, until it receives the early and late rain."},{"v":8,"t":"You also be patient. Establish your hearts, for the coming of the Lord is at hand."},{"v":9,"t":"Don’t grumble, brothers, against one another, so that you won’t be judged. Behold, the judge stands at the door."},{"v":10,"t":"Take, brothers, for an example of suffering and of perseverance, the prophets who spoke in the name of the Lord."},{"v":11,"t":"Behold, we call them blessed who endured. You have heard of the perseverance of Job and have seen the Lord in the outcome, and how the Lord is full of compassion and mercy."},{"v":12,"t":"But above all things, my brothers, don’t swear—not by heaven, or by the earth, or by any other oath; but let your “yes” be “yes”, and your “no”, “no”, so that you don’t fall into hypocrisy."},{"v":13,"t":"Is any among you suffering? Let him pray. Is any cheerful? Let him sing praises."},{"v":14,"t":"Is any among you sick? Let him call for the elders of the assembly, and let them pray over him, anointing him with oil in the name of the Lord;"},{"v":15,"t":"and the prayer of faith will heal him who is sick, and the Lord will raise him up. If he has committed sins, he will be forgiven."},{"v":16,"t":"Confess your sins to one another and pray for one another, that you may be healed. The insistent prayer of a righteous person is powerfully effective."},{"v":17,"t":"Elijah was a man with a nature like ours, and he prayed earnestly that it might not rain, and it didn’t rain on the earth for three years and six months."},{"v":18,"t":"He prayed again, and the sky gave rain, and the earth produced its fruit."},{"v":19,"t":"Brothers, if any among you wanders from the truth and someone turns him back,"},{"v":20,"t":"let him know that he who turns a sinner from the error of his way will save a soul from death and will cover a multitude of sins."}]}},"1PE":{"1":{"en":[{"v":1,"t":"Peter, an apostle of Jesus Christ, to the chosen ones who are living as foreigners in the Dispersion in Pontus, Galatia, Cappadocia, Asia, and Bithynia,"},{"v":2,"t":"according to the foreknowledge of God the Father, in sanctification of the Spirit, that you may obey Jesus Christ and be sprinkled with his blood: Grace to you and peace be multiplied."},{"v":3,"t":"Blessed be the God and Father of our Lord Jesus Christ, who according to his great mercy caused us to be born again to a living hope through the resurrection of Jesus Christ from the dead,"},{"v":4,"t":"to an incorruptible and undefiled inheritance that doesn’t fade away, reserved in Heaven for you,"},{"v":5,"t":"who by the power of God are guarded through faith for a salvation ready to be revealed in the last time."},{"v":6,"t":"In this you greatly rejoice, though now for a little while, if need be, you have been grieved in various trials,"},{"v":7,"t":"that the proof of your faith, which is more precious than gold that perishes, even though it is tested by fire, may be found to result in praise, glory, and honor at the revelation of Jesus Christ—"},{"v":8,"t":"whom, not having known, you love. In him, though now you don’t see him, yet believing, you rejoice greatly with joy that is unspeakable and full of glory,"},{"v":9,"t":"receiving the result of your faith, the salvation of your souls."},{"v":10,"t":"Concerning this salvation, the prophets sought and searched diligently. They prophesied of the grace that would come to you,"},{"v":11,"t":"searching for who or what kind of time the Spirit of Christ which was in them pointed to when he predicted the sufferings of Christ and the glories that would follow them."},{"v":12,"t":"To them it was revealed that they served not themselves, but you, in these things, which now have been announced to you through those who preached the Good News to you by the Holy Spirit sent out from heaven; which things angels desire to look into."},{"v":13,"t":"Therefore prepare your minds for action. Be sober, and set your hope fully on the grace that will be brought to you at the revelation of Jesus Christ—"},{"v":14,"t":"as children of obedience, not conforming yourselves according to your former lusts as in your ignorance,"},{"v":15,"t":"but just as he who called you is holy, you yourselves also be holy in all of your behavior,"},{"v":16,"t":"because it is written, “You shall be holy, for I am holy.”"},{"v":17,"t":"If you call on him as Father, who without respect of persons judges according to each man’s work, pass the time of your living as foreigners here in reverent fear,"},{"v":18,"t":"knowing that you were redeemed, not with corruptible things like silver or gold, from the useless way of life handed down from your fathers,"},{"v":19,"t":"but with precious blood, as of a lamb without blemish or spot, the blood of Christ,"},{"v":20,"t":"who was foreknown indeed before the foundation of the world, but was revealed in this last age for your sake,"},{"v":21,"t":"who through him are believers in God, who raised him from the dead and gave him glory, so that your faith and hope might be in God."},{"v":22,"t":"Seeing you have purified your souls in your obedience to the truth through the Spirit in sincere brotherly affection, love one another from the heart fervently,"},{"v":23,"t":"having been born again, not of corruptible seed, but of incorruptible, through the word of God, which lives and remains forever."},{"v":24,"t":"For, “All flesh is like grass, and all of man’s glory like the flower in the grass. The grass withers, and its flower falls;"},{"v":25,"t":"but the Lord’s word endures forever.” This is the word of Good News which was preached to you."}]},"2":{"en":[{"v":1,"t":"Putting away therefore all wickedness, all deceit, hypocrisies, envies, and all evil speaking,"},{"v":2,"t":"as newborn babies, long for the pure spiritual milk, that with it you may grow,"},{"v":3,"t":"if indeed you have tasted that the Lord is gracious."},{"v":4,"t":"Come to him, a living stone, rejected indeed by men, but chosen by God, precious."},{"v":5,"t":"You also as living stones are built up as a spiritual house, to be a holy priesthood, to offer up spiritual sacrifices, acceptable to God through Jesus Christ."},{"v":6,"t":"Because it is contained in Scripture, “Behold, I lay in Zion a chief cornerstone, chosen and precious. He who believes in him will not be disappointed.”"},{"v":7,"t":"For you who believe therefore is the honor, but for those who are disobedient, “The stone which the builders rejected has become the chief cornerstone,”"},{"v":8,"t":"and, “a stumbling stone and a rock of offense.” For they stumble at the word, being disobedient, to which also they were appointed."},{"v":9,"t":"But you are a chosen race, a royal priesthood, a holy nation, a people for God’s own possession, that you may proclaim the excellence of him who called you out of darkness into his marvelous light."},{"v":10,"t":"In the past, you were not a people, but now are God’s people, who had not obtained mercy, but now have obtained mercy."},{"v":11,"t":"Beloved, I beg you as foreigners and pilgrims to abstain from fleshly lusts which war against the soul,"},{"v":12,"t":"having good behavior among the nations, so in that of which they speak against you as evildoers, they may see your good works and glorify God in the day of visitation."},{"v":13,"t":"Therefore subject yourselves to every ordinance of man for the Lord’s sake: whether to the king, as supreme,"},{"v":14,"t":"or to governors, as sent by him for vengeance on evildoers and for praise to those who do well."},{"v":15,"t":"For this is the will of God, that by well-doing you should put to silence the ignorance of foolish men."},{"v":16,"t":"Live as free people, yet not using your freedom for a cloak of wickedness, but as bondservants of God."},{"v":17,"t":"Honor all men. Love the brotherhood. Fear God. Honor the king."},{"v":18,"t":"Servants, be in subjection to your masters with all respect, not only to the good and gentle, but also to the wicked."},{"v":19,"t":"For it is commendable if someone endures pain, suffering unjustly, because of conscience toward God."},{"v":20,"t":"For what glory is it if, when you sin, you patiently endure beating? But if when you do well, you patiently endure suffering, this is commendable with God."},{"v":21,"t":"For you were called to this, because Christ also suffered for us, leaving you an example, that you should follow his steps,"},{"v":22,"t":"who didn’t sin, “neither was deceit found in his mouth.”"},{"v":23,"t":"When he was cursed, he didn’t curse back. When he suffered, he didn’t threaten, but committed himself to him who judges righteously."},{"v":24,"t":"He himself bore our sins in his body on the tree, that we, having died to sins, might live to righteousness. You were healed by his wounds."},{"v":25,"t":"For you were going astray like sheep; but now you have returned to the Shepherd and Overseer of your souls."}]},"3":{"en":[{"v":1,"t":"In the same way, wives, be in subjection to your own husbands, so that, even if any don’t obey the Word, they may be won by the behavior of their wives without a word,"},{"v":2,"t":"seeing your pure behavior in fear."},{"v":3,"t":"Let your beauty come not from the outward adorning of braiding your hair, and of wearing gold ornaments or of putting on fine clothing,"},{"v":4,"t":"but from the hidden person of the heart, in the incorruptible adornment of a gentle and quiet spirit, which is very precious in God’s sight."},{"v":5,"t":"For this is how in the past the holy women who hoped in God also adorned themselves, being in subjection to their own husbands."},{"v":6,"t":"So Sarah obeyed Abraham, calling him lord, whose children you now are if you do well and are not put in fear by any terror."},{"v":7,"t":"You husbands, in the same way, live with your wives according to knowledge, giving honor to the woman as to the weaker vessel, as also being joint heirs of the grace of life, that your prayers may not be hindered."},{"v":8,"t":"Finally, all of you be like-minded, compassionate, loving as brothers, tenderhearted, courteous,"},{"v":9,"t":"not rendering evil for evil or insult for insult; but instead blessing, knowing that you were called to this, that you may inherit a blessing."},{"v":10,"t":"For, “He who would love life and see good days, let him keep his tongue from evil and his lips from speaking deceit."},{"v":11,"t":"Let him turn away from evil and do good. Let him seek peace and pursue it."},{"v":12,"t":"For the eyes of the Lord are on the righteous, and his ears open to their prayer; but the face of the Lord is against those who do evil.”"},{"v":13,"t":"Now who will harm you if you become imitators of that which is good?"},{"v":14,"t":"But even if you should suffer for righteousness’ sake, you are blessed. “Don’t fear what they fear, neither be troubled.”"},{"v":15,"t":"But sanctify the Lord God in your hearts. Always be ready to give an answer to everyone who asks you a reason concerning the hope that is in you, with humility and fear,"},{"v":16,"t":"having a good conscience. Thus, while you are spoken against as evildoers, they may be disappointed who curse your good way of life in Christ."},{"v":17,"t":"For it is better, if it is God’s will, that you suffer for doing what is right than for doing evil."},{"v":18,"t":"Because Christ also suffered for sins once, the righteous for the unrighteous, that he might bring you to God, being put to death in the flesh, but made alive in the Spirit,"},{"v":19,"t":"in whom he also went and preached to the spirits in prison,"},{"v":20,"t":"who before were disobedient when God waited patiently in the days of Noah while the ship was being built. In it, few, that is, eight souls, were saved through water."},{"v":21,"t":"This is a symbol of baptism, which now saves you—not the putting away of the filth of the flesh, but the answer of a good conscience toward God—through the resurrection of Jesus Christ,"},{"v":22,"t":"who is at the right hand of God, having gone into heaven, angels and authorities and powers being made subject to him."}]},"4":{"en":[{"v":1,"t":"Therefore, since Christ suffered for us in the flesh, arm yourselves also with the same mind; for he who has suffered in the flesh has ceased from sin,"},{"v":2,"t":"that you no longer should live the rest of your time in the flesh for the lusts of men, but for the will of God."},{"v":3,"t":"For we have spent enough of our past time doing the desire of the Gentiles, and having walked in lewdness, lusts, drunken binges, orgies, carousings, and abominable idolatries."},{"v":4,"t":"They think it is strange that you don’t run with them into the same excess of riot, speaking evil of you."},{"v":5,"t":"They will give account to him who is ready to judge the living and the dead."},{"v":6,"t":"For to this end the Good News was preached even to the dead, that they might be judged indeed as men in the flesh, but live as to God in the spirit."},{"v":7,"t":"But the end of all things is near. Therefore be of sound mind, self-controlled, and sober in prayer."},{"v":8,"t":"And above all things be earnest in your love among yourselves, for love covers a multitude of sins."},{"v":9,"t":"Be hospitable to one another without grumbling."},{"v":10,"t":"As each has received a gift, employ it in serving one another, as good managers of the grace of God in its various forms."},{"v":11,"t":"If anyone speaks, let it be as it were the very words of God. If anyone serves, let it be as of the strength which God supplies, that in all things God may be glorified through Jesus Christ, to whom belong the glory and the dominion forever and ever. Amen."},{"v":12,"t":"Beloved, don’t be astonished at the fiery trial which has come upon you to test you, as though a strange thing happened to you."},{"v":13,"t":"But because you are partakers of Christ’s sufferings, rejoice, that at the revelation of his glory you also may rejoice with exceeding joy."},{"v":14,"t":"If you are insulted for the name of Christ, you are blessed, because the Spirit of glory and of God rests on you. On their part he is blasphemed, but on your part he is glorified."},{"v":15,"t":"But let none of you suffer as a murderer, or a thief, or an evil doer, or a meddler in other men’s matters."},{"v":16,"t":"But if one of you suffers for being a Christian, let him not be ashamed; but let him glorify God in this matter."},{"v":17,"t":"For the time has come for judgment to begin with the household of God. If it begins first with us, what will happen to those who don’t obey the Good News of God?"},{"v":18,"t":"“If it is hard for the righteous to be saved, what will happen to the ungodly and the sinner?”"},{"v":19,"t":"Therefore let them also who suffer according to the will of God in doing good entrust their souls to him, as to a faithful Creator."}]},"5":{"en":[{"v":1,"t":"Therefore I exhort the elders among you, as a fellow elder and a witness of the sufferings of Christ, and who will also share in the glory that will be revealed:"},{"v":2,"t":"shepherd the flock of God which is among you, exercising the oversight, not under compulsion, but voluntarily; not for dishonest gain, but willingly;"},{"v":3,"t":"not as lording it over those entrusted to you, but making yourselves examples to the flock."},{"v":4,"t":"When the chief Shepherd is revealed, you will receive the crown of glory that doesn’t fade away."},{"v":5,"t":"Likewise, you younger ones, be subject to the elder. Yes, all of you clothe yourselves with humility and subject yourselves to one another; for “God resists the proud, but gives grace to the humble.”"},{"v":6,"t":"Humble yourselves therefore under the mighty hand of God, that he may exalt you in due time,"},{"v":7,"t":"casting all your worries on him, because he cares for you."},{"v":8,"t":"Be sober and self-controlled. Be watchful. Your adversary, the devil, walks around like a roaring lion, seeking whom he may devour."},{"v":9,"t":"Withstand him steadfast in your faith, knowing that your brothers who are in the world are undergoing the same sufferings."},{"v":10,"t":"But may the God of all grace, who called you to his eternal glory by Christ Jesus, after you have suffered a little while, perfect, establish, strengthen, and settle you."},{"v":11,"t":"To him be the glory and the power forever and ever. Amen."},{"v":12,"t":"Through Silvanus, our faithful brother, as I consider him, I have written to you briefly, exhorting and testifying that this is the true grace of God in which you stand."},{"v":13,"t":"She who is in Babylon, chosen together with you, greets you. So does Mark, my son."},{"v":14,"t":"Greet one another with a kiss of love. Peace be to all of you who are in Christ Jesus. Amen."}]}},"2PE":{"1":{"en":[{"v":1,"t":"Simon Peter, a servant and apostle of Jesus Christ, to those who have obtained a like precious faith with us in the righteousness of our God and Savior, Jesus Christ:"},{"v":2,"t":"Grace to you and peace be multiplied in the knowledge of God and of Jesus our Lord,"},{"v":3,"t":"seeing that his divine power has granted to us all things that pertain to life and godliness, through the knowledge of him who called us by his own glory and virtue,"},{"v":4,"t":"by which he has granted to us his precious and exceedingly great promises; that through these you may become partakers of the divine nature, having escaped from the corruption that is in the world by lust."},{"v":5,"t":"Yes, and for this very cause adding on your part all diligence, in your faith supply moral excellence; and in moral excellence, knowledge;"},{"v":6,"t":"and in knowledge, self-control; and in self-control, perseverance; and in perseverance, godliness;"},{"v":7,"t":"and in godliness, brotherly affection; and in brotherly affection, love."},{"v":8,"t":"For if these things are yours and abound, they make you to not be idle or unfruitful in the knowledge of our Lord Jesus Christ."},{"v":9,"t":"For he who lacks these things is blind, seeing only what is near, having forgotten the cleansing from his old sins."},{"v":10,"t":"Therefore, brothers, be more diligent to make your calling and election sure. For if you do these things, you will never stumble."},{"v":11,"t":"For thus you will be richly supplied with the entrance into the eternal Kingdom of our Lord and Savior, Jesus Christ."},{"v":12,"t":"Therefore I will not be negligent to remind you of these things, though you know them and are established in the present truth."},{"v":13,"t":"I think it right, as long as I am in this tent, to stir you up by reminding you,"},{"v":14,"t":"knowing that the putting off of my tent comes swiftly, even as our Lord Jesus Christ made clear to me."},{"v":15,"t":"Yes, I will make every effort that you may always be able to remember these things even after my departure."},{"v":16,"t":"For we didn’t follow cunningly devised fables when we made known to you the power and coming of our Lord Jesus Christ, but we were eyewitnesses of his majesty."},{"v":17,"t":"For he received from God the Father honor and glory when the voice came to him from the Majestic Glory, “This is my beloved Son, in whom I am well pleased.”"},{"v":18,"t":"We heard this voice come out of heaven when we were with him on the holy mountain."},{"v":19,"t":"We have the more sure word of prophecy; and you do well that you heed it as to a lamp shining in a dark place, until the day dawns and the morning star arises in your hearts,"},{"v":20,"t":"knowing this first, that no prophecy of Scripture is of private interpretation."},{"v":21,"t":"For no prophecy ever came by the will of man, but holy men of God spoke, being moved by the Holy Spirit."}]},"2":{"en":[{"v":1,"t":"But false prophets also arose among the people, as false teachers will also be among you, who will secretly bring in destructive heresies, denying even the Master who bought them, bringing on themselves swift destruction."},{"v":2,"t":"Many will follow their immoral ways, and as a result, the way of the truth will be maligned."},{"v":3,"t":"In covetousness they will exploit you with deceptive words: whose sentence now from of old doesn’t linger, and their destruction will not slumber."},{"v":4,"t":"For if God didn’t spare angels when they sinned, but cast them down to Tartarus, and committed them to pits of darkness to be reserved for judgment;"},{"v":5,"t":"and didn’t spare the ancient world, but preserved Noah with seven others, a preacher of righteousness, when he brought a flood on the world of the ungodly,"},{"v":6,"t":"and turning the cities of Sodom and Gomorrah into ashes, condemned them to destruction, having made them an example to those who would live in an ungodly way,"},{"v":7,"t":"and delivered righteous Lot, who was very distressed by the lustful life of the wicked"},{"v":8,"t":"(for that righteous man dwelling among them was tormented in his righteous soul from day to day with seeing and hearing lawless deeds),"},{"v":9,"t":"then the Lord knows how to deliver the godly out of temptation and to keep the unrighteous under punishment for the day of judgment,"},{"v":10,"t":"but chiefly those who walk after the flesh in the lust of defilement and despise authority. Daring, self-willed, they are not afraid to speak evil of dignitaries,"},{"v":11,"t":"whereas angels, though greater in might and power, don’t bring a slanderous judgment against them before the Lord."},{"v":12,"t":"But these, as unreasoning creatures, born natural animals to be taken and destroyed, speaking evil in matters about which they are ignorant, will in their destroying surely be destroyed,"},{"v":13,"t":"receiving the wages of unrighteousness; people who count it pleasure to revel in the daytime, spots and defects, reveling in their deceit while they feast with you;"},{"v":14,"t":"having eyes full of adultery, and who can’t cease from sin, enticing unsettled souls, having a heart trained in greed, accursed children!"},{"v":15,"t":"Forsaking the right way, they went astray, having followed the way of Balaam the son of Beor, who loved the wages of wrongdoing;"},{"v":16,"t":"but he was rebuked for his own disobedience. A speechless donkey spoke with a man’s voice and stopped the madness of the prophet."},{"v":17,"t":"These are wells without water, clouds driven by a storm, for whom the blackness of darkness has been reserved forever."},{"v":18,"t":"For, uttering great swelling words of emptiness, they entice in the lusts of the flesh, by licentiousness, those who are indeed escaping from those who live in error;"},{"v":19,"t":"promising them liberty, while they themselves are bondservants of corruption; for a man is brought into bondage by whoever overcomes him."},{"v":20,"t":"For if, after they have escaped the defilement of the world through the knowledge of the Lord and Savior Jesus Christ, they are again entangled in it and overcome, the last state has become worse for them than the first."},{"v":21,"t":"For it would be better for them not to have known the way of righteousness, than after knowing it, to turn back from the holy commandment delivered to them."},{"v":22,"t":"But it has happened to them according to the true proverb, “The dog turns to his own vomit again,” and “the sow that has washed to wallowing in the mire.”"}]},"3":{"en":[{"v":1,"t":"This is now, beloved, the second letter that I have written to you; and in both of them I stir up your sincere mind by reminding you"},{"v":2,"t":"that you should remember the words which were spoken before by the holy prophets and the commandment of us, the apostles of the Lord and Savior,"},{"v":3,"t":"knowing this first, that in the last days mockers will come, walking after their own lusts"},{"v":4,"t":"and saying, “Where is the promise of his coming? For, from the day that the fathers fell asleep, all things continue as they were from the beginning of the creation.”"},{"v":5,"t":"For they willfully forget that there were heavens from of old, and an earth formed out of water and amid water by the word of God,"},{"v":6,"t":"by which means the world that existed then, being overflowed with water, perished."},{"v":7,"t":"But the heavens that exist now and the earth, by the same word have been stored up for fire, being reserved against the day of judgment and destruction of ungodly men."},{"v":8,"t":"But don’t forget this one thing, beloved, that one day is with the Lord as a thousand years, and a thousand years as one day."},{"v":9,"t":"The Lord is not slow concerning his promise, as some count slowness; but he is patient with us, not wishing that anyone should perish, but that all should come to repentance."},{"v":10,"t":"But the day of the Lord will come as a thief in the night, in which the heavens will pass away with a great noise, and the elements will be dissolved with fervent heat; and the earth and the works that are in it will be burned up."},{"v":11,"t":"Therefore, since all these things will be destroyed like this, what kind of people ought you to be in holy living and godliness,"},{"v":12,"t":"looking for and earnestly desiring the coming of the day of God, which will cause the burning heavens to be dissolved, and the elements will melt with fervent heat?"},{"v":13,"t":"But, according to his promise, we look for new heavens and a new earth, in which righteousness dwells."},{"v":14,"t":"Therefore, beloved, seeing that you look for these things, be diligent to be found in peace, without defect and blameless in his sight."},{"v":15,"t":"Regard the patience of our Lord as salvation; even as our beloved brother Paul also, according to the wisdom given to him, wrote to you,"},{"v":16,"t":"as also in all of his letters, speaking in them of these things. In those, there are some things that are hard to understand, which the ignorant and unsettled twist, as they also do to the other Scriptures, to their own destruction."},{"v":17,"t":"You therefore, beloved, knowing these things beforehand, beware, lest being carried away with the error of the wicked, you fall from your own steadfastness."},{"v":18,"t":"But grow in the grace and knowledge of our Lord and Savior Jesus Christ. To him be the glory both now and forever. Amen."}]}},"1JN":{"1":{"en":[{"v":1,"t":"That which was from the beginning, that which we have heard, that which we have seen with our eyes, that which we saw, and our hands touched, concerning the Word of life"},{"v":2,"t":"(and the life was revealed, and we have seen, and testify, and declare to you the life, the eternal life, which was with the Father, and was revealed to us);"},{"v":3,"t":"that which we have seen and heard we declare to you, that you also may have fellowship with us. Yes, and our fellowship is with the Father and with his Son, Jesus Christ."},{"v":4,"t":"And we write these things to you, that our joy may be fulfilled."},{"v":5,"t":"This is the message which we have heard from him and announce to you, that God is light, and in him is no darkness at all."},{"v":6,"t":"If we say that we have fellowship with him and walk in the darkness, we lie and don’t tell the truth."},{"v":7,"t":"But if we walk in the light as he is in the light, we have fellowship with one another, and the blood of Jesus Christ his Son, cleanses us from all sin."},{"v":8,"t":"If we say that we have no sin, we deceive ourselves, and the truth is not in us."},{"v":9,"t":"If we confess our sins, he is faithful and righteous to forgive us the sins and to cleanse us from all unrighteousness."},{"v":10,"t":"If we say that we haven’t sinned, we make him a liar, and his word is not in us."}]},"2":{"en":[{"v":1,"t":"My little children, I write these things to you so that you may not sin. If anyone sins, we have a Counselor with the Father, Jesus Christ, the righteous."},{"v":2,"t":"And he is the atoning sacrifice for our sins, and not for ours only, but also for the whole world."},{"v":3,"t":"This is how we know that we know him: if we keep his commandments."},{"v":4,"t":"One who says, “I know him,” and doesn’t keep his commandments, is a liar, and the truth isn’t in him."},{"v":5,"t":"But God’s love has most certainly been perfected in whoever keeps his word. This is how we know that we are in him:"},{"v":6,"t":"he who says he remains in him ought himself also to walk just like he walked."},{"v":7,"t":"Brothers, I write no new commandment to you, but an old commandment which you had from the beginning. The old commandment is the word which you heard from the beginning."},{"v":8,"t":"Again, I write a new commandment to you, which is true in him and in you, because the darkness is passing away and the true light already shines."},{"v":9,"t":"He who says he is in the light and hates his brother is in the darkness even until now."},{"v":10,"t":"He who loves his brother remains in the light, and there is no occasion for stumbling in him."},{"v":11,"t":"But he who hates his brother is in the darkness, and walks in the darkness, and doesn’t know where he is going, because the darkness has blinded his eyes."},{"v":12,"t":"I write to you, little children, because your sins are forgiven you for his name’s sake."},{"v":13,"t":"I write to you, fathers, because you know him who is from the beginning. I write to you, young men, because you have overcome the evil one. I write to you, little children, because you know the Father."},{"v":14,"t":"I have written to you, fathers, because you know him who is from the beginning. I have written to you, young men, because you are strong, and the word of God remains in you, and you have overcome the evil one."},{"v":15,"t":"Don’t love the world or the things that are in the world. If anyone loves the world, the Father’s love isn’t in him."},{"v":16,"t":"For all that is in the world—the lust of the flesh, the lust of the eyes, and the pride of life—isn’t the Father’s, but is the world’s."},{"v":17,"t":"The world is passing away with its lusts, but he who does God’s will remains forever."},{"v":18,"t":"Little children, these are the end times, and as you heard that the Antichrist is coming, even now many antichrists have arisen. By this we know that it is the final hour."},{"v":19,"t":"They went out from us, but they didn’t belong to us; for if they had belonged to us, they would have continued with us. But they left, that they might be revealed that none of them belong to us."},{"v":20,"t":"You have an anointing from the Holy One, and you all have knowledge."},{"v":21,"t":"I have not written to you because you don’t know the truth, but because you know it, and because no lie is of the truth."},{"v":22,"t":"Who is the liar but he who denies that Jesus is the Christ? This is the Antichrist, he who denies the Father and the Son."},{"v":23,"t":"Whoever denies the Son doesn’t have the Father. He who confesses the Son has the Father also."},{"v":24,"t":"Therefore, as for you, let that remain in you which you heard from the beginning. If that which you heard from the beginning remains in you, you also will remain in the Son, and in the Father."},{"v":25,"t":"This is the promise which he promised us, the eternal life."},{"v":26,"t":"These things I have written to you concerning those who would lead you astray."},{"v":27,"t":"As for you, the anointing which you received from him remains in you, and you don’t need for anyone to teach you. But as his anointing teaches you concerning all things, and is true, and is no lie, and even as it taught you, you will remain in him."},{"v":28,"t":"Now, little children, remain in him, that when he appears, we may have boldness and not be ashamed before him at his coming."},{"v":29,"t":"If you know that he is righteous, you know that everyone who practices righteousness has been born of him."}]},"3":{"en":[{"v":1,"t":"See how great a love the Father has given to us, that we should be called children of God! For this cause the world doesn’t know us, because it didn’t know him."},{"v":2,"t":"Beloved, now we are children of God. It is not yet revealed what we will be; but we know that when he is revealed, we will be like him, for we will see him just as he is."},{"v":3,"t":"Everyone who has this hope set on him purifies himself, even as he is pure."},{"v":4,"t":"Everyone who sins also commits lawlessness. Sin is lawlessness."},{"v":5,"t":"You know that he was revealed to take away our sins, and no sin is in him."},{"v":6,"t":"Whoever remains in him doesn’t sin. Whoever sins hasn’t seen him and doesn’t know him."},{"v":7,"t":"Little children, let no one lead you astray. He who does righteousness is righteous, even as he is righteous."},{"v":8,"t":"He who sins is of the devil, for the devil has been sinning from the beginning. To this end the Son of God was revealed: that he might destroy the works of the devil."},{"v":9,"t":"Whoever is born of God doesn’t commit sin, because his seed remains in him, and he can’t sin, because he is born of God."},{"v":10,"t":"In this the children of God are revealed, and the children of the devil. Whoever doesn’t do righteousness is not of God, neither is he who doesn’t love his brother."},{"v":11,"t":"For this is the message which you heard from the beginning, that we should love one another—"},{"v":12,"t":"unlike Cain, who was of the evil one and killed his brother. Why did he kill him? Because his deeds were evil, and his brother’s righteous."},{"v":13,"t":"Don’t be surprised, my brothers, if the world hates you."},{"v":14,"t":"We know that we have passed out of death into life, because we love the brothers. He who doesn’t love his brother remains in death."},{"v":15,"t":"Whoever hates his brother is a murderer, and you know that no murderer has eternal life remaining in him."},{"v":16,"t":"By this we know love, because he laid down his life for us. And we ought to lay down our lives for the brothers."},{"v":17,"t":"But whoever has the world’s goods and sees his brother in need, then closes his heart of compassion against him, how does God’s love remain in him?"},{"v":18,"t":"My little children, let’s not love in word only, or with the tongue only, but in deed and truth."},{"v":19,"t":"And by this we know that we are of the truth and persuade our hearts before him,"},{"v":20,"t":"because if our heart condemns us, God is greater than our heart, and knows all things."},{"v":21,"t":"Beloved, if our hearts don’t condemn us, we have boldness toward God;"},{"v":22,"t":"so whatever we ask, we receive from him, because we keep his commandments and do the things that are pleasing in his sight."},{"v":23,"t":"This is his commandment, that we should believe in the name of his Son, Jesus Christ, and love one another, even as he commanded."},{"v":24,"t":"He who keeps his commandments remains in him, and he in him. By this we know that he remains in us, by the Spirit which he gave us."}]},"4":{"en":[{"v":1,"t":"Beloved, don’t believe every spirit, but test the spirits, whether they are of God, because many false prophets have gone out into the world."},{"v":2,"t":"By this you know the Spirit of God: every spirit who confesses that Jesus Christ has come in the flesh is of God,"},{"v":3,"t":"and every spirit who doesn’t confess that Jesus Christ has come in the flesh is not of God; and this is the spirit of the Antichrist, of whom you have heard that it comes. Now it is in the world already."},{"v":4,"t":"You are of God, little children, and have overcome them, because greater is he who is in you than he who is in the world."},{"v":5,"t":"They are of the world. Therefore they speak of the world, and the world hears them."},{"v":6,"t":"We are of God. He who knows God listens to us. He who is not of God doesn’t listen to us. By this we know the spirit of truth, and the spirit of error."},{"v":7,"t":"Beloved, let’s love one another, for love is of God; and everyone who loves has been born of God and knows God."},{"v":8,"t":"He who doesn’t love doesn’t know God, for God is love."},{"v":9,"t":"By this God’s love was revealed in us, that God has sent his only born Son into the world that we might live through him."},{"v":10,"t":"In this is love, not that we loved God, but that he loved us, and sent his Son as the atoning sacrifice for our sins."},{"v":11,"t":"Beloved, if God loved us in this way, we also ought to love one another."},{"v":12,"t":"No one has seen God at any time. If we love one another, God remains in us, and his love has been perfected in us."},{"v":13,"t":"By this we know that we remain in him and he in us, because he has given us of his Spirit."},{"v":14,"t":"We have seen and testify that the Father has sent the Son as the Savior of the world."},{"v":15,"t":"Whoever confesses that Jesus is the Son of God, God remains in him, and he in God."},{"v":16,"t":"We know and have believed the love which God has for us. God is love, and he who remains in love remains in God, and God remains in him."},{"v":17,"t":"In this, love has been made perfect among us, that we may have boldness in the day of judgment, because as he is, even so we are in this world."},{"v":18,"t":"There is no fear in love; but perfect love casts out fear, because fear has punishment. He who fears is not made perfect in love."},{"v":19,"t":"We love him, because he first loved us."},{"v":20,"t":"If a man says, “I love God,” and hates his brother, he is a liar; for he who doesn’t love his brother whom he has seen, how can he love God whom he has not seen?"},{"v":21,"t":"This commandment we have from him, that he who loves God should also love his brother."}]},"5":{"en":[{"v":1,"t":"Whoever believes that Jesus is the Christ has been born of God. Whoever loves the Father also loves the child who is born of him."},{"v":2,"t":"By this we know that we love the children of God, when we love God and keep his commandments."},{"v":3,"t":"For this is loving God, that we keep his commandments. His commandments are not grievous."},{"v":4,"t":"For whatever is born of God overcomes the world. This is the victory that has overcome the world: your faith."},{"v":5,"t":"Who is he who overcomes the world, but he who believes that Jesus is the Son of God?"},{"v":6,"t":"This is he who came by water and blood, Jesus Christ; not with the water only, but with the water and the blood. It is the Spirit who testifies, because the Spirit is the truth."},{"v":7,"t":"For there are three who testify:"},{"v":8,"t":"the Spirit, the water, and the blood; and the three agree as one."},{"v":9,"t":"If we receive the witness of men, the witness of God is greater; for this is God’s testimony which he has testified concerning his Son."},{"v":10,"t":"He who believes in the Son of God has the testimony in himself. He who doesn’t believe God has made him a liar, because he has not believed in the testimony that God has given concerning his Son."},{"v":11,"t":"The testimony is this: that God gave to us eternal life, and this life is in his Son."},{"v":12,"t":"He who has the Son has the life. He who doesn’t have God’s Son doesn’t have the life."},{"v":13,"t":"These things I have written to you who believe in the name of the Son of God, that you may know that you have eternal life, and that you may continue to believe in the name of the Son of God."},{"v":14,"t":"This is the boldness which we have toward him, that if we ask anything according to his will, he listens to us."},{"v":15,"t":"And if we know that he listens to us, whatever we ask, we know that we have the petitions which we have asked of him."},{"v":16,"t":"If anyone sees his brother sinning a sin not leading to death, he shall ask, and God will give him life for those who sin not leading to death. There is sin leading to death. I don’t say that he should make a request concerning this."},{"v":17,"t":"All unrighteousness is sin, and there is sin not leading to death."},{"v":18,"t":"We know that whoever is born of God doesn’t sin, but he who was born of God keeps himself, and the evil one doesn’t touch him."},{"v":19,"t":"We know that we are of God, and the whole world lies in the power of the evil one."},{"v":20,"t":"We know that the Son of God has come and has given us an understanding, that we know him who is true; and we are in him who is true, in his Son Jesus Christ. This is the true God and eternal life."},{"v":21,"t":"Little children, keep yourselves from idols."}]}},"2JN":{"1":{"en":[{"v":1,"t":"The elder, to the chosen lady and her children, whom I love in truth, and not I only, but also all those who know the truth,"},{"v":2,"t":"for the truth’s sake, which remains in us, and it will be with us forever:"},{"v":3,"t":"Grace, mercy, and peace will be with us, from God the Father and from the Lord Jesus Christ, the Son of the Father, in truth and love."},{"v":4,"t":"I rejoice greatly that I have found some of your children walking in truth, even as we have been commanded by the Father."},{"v":5,"t":"Now I beg you, dear lady, not as though I wrote to you a new commandment, but that which we had from the beginning, that we love one another."},{"v":6,"t":"This is love, that we should walk according to his commandments. This is the commandment, even as you heard from the beginning, that you should walk in it."},{"v":7,"t":"For many deceivers have gone out into the world, those who don’t confess that Jesus Christ came in the flesh. This is the deceiver and the Antichrist."},{"v":8,"t":"Watch yourselves, that we don’t lose the things which we have accomplished, but that we receive a full reward."},{"v":9,"t":"Whoever transgresses and doesn’t remain in the teaching of Christ doesn’t have God. He who remains in the teaching has both the Father and the Son."},{"v":10,"t":"If anyone comes to you and doesn’t bring this teaching, don’t receive him into your house, and don’t welcome him,"},{"v":11,"t":"for he who welcomes him participates in his evil deeds."},{"v":12,"t":"Having many things to write to you, I don’t want to do so with paper and ink, but I hope to come to you and to speak face to face, that our joy may be made full."},{"v":13,"t":"The children of your chosen sister greet you. Amen."}]}},"3JN":{"1":{"en":[{"v":1,"t":"The elder to Gaius the beloved, whom I love in truth."},{"v":2,"t":"Beloved, I pray that you may prosper in all things and be healthy, even as your soul prospers."},{"v":3,"t":"For I rejoiced greatly when brothers came and testified about your truth, even as you walk in truth."},{"v":4,"t":"I have no greater joy than this: to hear about my children walking in truth."},{"v":5,"t":"Beloved, you do a faithful work in whatever you accomplish for those who are brothers and strangers."},{"v":6,"t":"They have testified about your love before the assembly. You will do well to send them forward on their journey in a way worthy of God,"},{"v":7,"t":"because for the sake of the Name they went out, taking nothing from the Gentiles."},{"v":8,"t":"We therefore ought to receive such, that we may be fellow workers for the truth."},{"v":9,"t":"I wrote to the assembly, but Diotrephes, who loves to be first among them, doesn’t accept what we say."},{"v":10,"t":"Therefore, if I come, I will call attention to his deeds which he does, unjustly accusing us with wicked words. Not content with this, he doesn’t receive the brothers himself, and those who would, he forbids and throws out of the assembly."},{"v":11,"t":"Beloved, don’t imitate that which is evil, but that which is good. He who does good is of God. He who does evil hasn’t seen God."},{"v":12,"t":"Demetrius has the testimony of all, and of the truth itself; yes, we also testify, and you know that our testimony is true."},{"v":13,"t":"I had many things to write to you, but I am unwilling to write to you with ink and pen;"},{"v":14,"t":"but I hope to see you soon. Then we will speak face to face. Peace be to you. The friends greet you. Greet the friends by name."}]}},"JUD":{"1":{"en":[{"v":1,"t":"Jude, a servant of Jesus Christ, and brother of James, to those who are called, sanctified by God the Father, and kept for Jesus Christ:"},{"v":2,"t":"May mercy, peace, and love be multiplied to you."},{"v":3,"t":"Beloved, while I was very eager to write to you about our common salvation, I was constrained to write to you exhorting you to contend earnestly for the faith which was once for all delivered to the saints."},{"v":4,"t":"For there are certain men who crept in secretly, even those who were long ago written about for this condemnation: ungodly men, turning the grace of our God into indecency, and denying our only Master, God, and Lord, Jesus Christ."},{"v":5,"t":"Now I desire to remind you, though you already know this, that the Lord, having saved a people out of the land of Egypt, afterward destroyed those who didn’t believe."},{"v":6,"t":"Angels who didn’t keep their first domain, but deserted their own dwelling place, he has kept in everlasting bonds under darkness for the judgment of the great day."},{"v":7,"t":"Even as Sodom and Gomorrah and the cities around them, having in the same way as these given themselves over to sexual immorality and gone after strange flesh, are shown as an example, suffering the punishment of eternal fire."},{"v":8,"t":"Yet in the same way, these also in their dreaming defile the flesh, despise authority, and slander celestial beings."},{"v":9,"t":"But Michael, the archangel, when contending with the devil and arguing about the body of Moses, dared not bring against him an abusive condemnation, but said, “May the Lord rebuke you!”"},{"v":10,"t":"But these speak evil of whatever things they don’t know. They are destroyed in these things that they understand naturally, like the creatures without reason."},{"v":11,"t":"Woe to them! For they went in the way of Cain, and ran riotously in the error of Balaam for hire, and perished in Korah’s rebellion."},{"v":12,"t":"These are hidden rocky reefs in your love feasts when they feast with you, shepherds who without fear feed themselves; clouds without water, carried along by winds; autumn trees without fruit, twice dead, plucked up by the roots;"},{"v":13,"t":"wild waves of the sea, foaming out their own shame; wandering stars, for whom the blackness of darkness has been reserved forever."},{"v":14,"t":"About these also Enoch, the seventh from Adam, prophesied, saying, “Behold, the Lord came with ten thousands of his holy ones,"},{"v":15,"t":"to execute judgment on all, and to convict all the ungodly of all their works of ungodliness which they have done in an ungodly way, and of all the hard things which ungodly sinners have spoken against him.”"},{"v":16,"t":"These are murmurers and complainers, walking after their lusts—and their mouth speaks proud things—showing respect of persons to gain advantage."},{"v":17,"t":"But you, beloved, remember the words which have been spoken before by the apostles of our Lord Jesus Christ."},{"v":18,"t":"They said to you, “In the last time there will be mockers, walking after their own ungodly lusts.”"},{"v":19,"t":"These are those who cause divisions and are sensual, not having the Spirit."},{"v":20,"t":"But you, beloved, keep building up yourselves on your most holy faith, praying in the Holy Spirit."},{"v":21,"t":"Keep yourselves in God’s love, looking for the mercy of our Lord Jesus Christ to eternal life."},{"v":22,"t":"On some have compassion, making a distinction,"},{"v":23,"t":"and some save, snatching them out of the fire with fear, hating even the clothing stained by the flesh."},{"v":24,"t":"Now to him who is able to keep them from stumbling, and to present you faultless before the presence of his glory in great joy,"},{"v":25,"t":"to God our Savior, who alone is wise, be glory and majesty, dominion and power, both now and forever. Amen."}]}},"REV":{"1":{"en":[{"v":1,"t":"This is the Revelation of Jesus Christ, which God gave him to show to his servants the things which must happen soon, which he sent and made known by his angel to his servant, John,"},{"v":2,"t":"who testified to God’s word and of the testimony of Jesus Christ, about everything that he saw."},{"v":3,"t":"Blessed is he who reads and those who hear the words of the prophecy, and keep the things that are written in it, for the time is near."},{"v":4,"t":"John, to the seven assemblies that are in Asia: Grace to you and peace from God, who is and who was and who is to come; and from the seven Spirits who are before his throne;"},{"v":5,"t":"and from Jesus Christ, the faithful witness, the firstborn of the dead, and the ruler of the kings of the earth. To him who loves us, and washed us from our sins by his blood—"},{"v":6,"t":"and he made us to be a Kingdom, priests to his God and Father—to him be the glory and the dominion forever and ever. Amen."},{"v":7,"t":"Behold, he is coming with the clouds, and every eye will see him, including those who pierced him. All the tribes of the earth will mourn over him. Even so, Amen."},{"v":8,"t":"“I am the Alpha and the Omega,” says the Lord God, “who is and who was and who is to come, the Almighty.”"},{"v":9,"t":"I John, your brother and partner with you in the oppression, Kingdom, and perseverance in Christ Jesus, was on the isle that is called Patmos because of God’s Word and the testimony of Jesus Christ."},{"v":10,"t":"I was in the Spirit on the Lord’s day, and I heard behind me a loud voice, like a trumpet"},{"v":11,"t":"saying, “What you see, write in a book and send to the seven assemblies: to Ephesus, Smyrna, Pergamum, Thyatira, Sardis, Philadelphia, and to Laodicea.”"},{"v":12,"t":"I turned to see the voice that spoke with me. Having turned, I saw seven golden lamp stands."},{"v":13,"t":"And among the lamp stands was one like a son of man, clothed with a robe reaching down to his feet, and with a golden sash around his chest."},{"v":14,"t":"His head and his hair were white as white wool, like snow. His eyes were like a flame of fire."},{"v":15,"t":"His feet were like burnished brass, as if it had been refined in a furnace. His voice was like the voice of many waters."},{"v":16,"t":"He had seven stars in his right hand. Out of his mouth proceeded a sharp two-edged sword. His face was like the sun shining at its brightest."},{"v":17,"t":"When I saw him, I fell at his feet like a dead man. He laid his right hand on me, saying, “Don’t be afraid. I am the first and the last,"},{"v":18,"t":"and the Living one. I was dead, and behold, I am alive forever and ever. Amen. I have the keys of Death and of Hades."},{"v":19,"t":"Write therefore the things which you have seen, and the things which are, and the things which will happen hereafter."},{"v":20,"t":"The mystery of the seven stars which you saw in my right hand, and the seven golden lamp stands is this: The seven stars are the angels of the seven assemblies. The seven lamp stands are seven assemblies."}]},"2":{"en":[{"v":1,"t":"“To the angel of the assembly in Ephesus write: “He who holds the seven stars in his right hand, he who walks among the seven golden lamp stands says these things:"},{"v":2,"t":"“I know your works, and your toil and perseverance, and that you can’t tolerate evil men, and have tested those who call themselves apostles, and they are not, and found them false."},{"v":3,"t":"You have perseverance and have endured for my name’s sake, and have not grown weary."},{"v":4,"t":"But I have this against you, that you left your first love."},{"v":5,"t":"Remember therefore from where you have fallen, and repent and do the first works; or else I am coming to you swiftly, and will move your lamp stand out of its place, unless you repent."},{"v":6,"t":"But this you have, that you hate the works of the Nicolaitans, which I also hate."},{"v":7,"t":"He who has an ear, let him hear what the Spirit says to the assemblies. To him who overcomes I will give to eat from the tree of life, which is in the Paradise of my God."},{"v":8,"t":"“To the angel of the assembly in Smyrna write: “The first and the last, who was dead, and has come to life says these things:"},{"v":9,"t":"“I know your works, oppression, and your poverty (but you are rich), and the blasphemy of those who say they are Jews, and they are not, but are a synagogue of Satan."},{"v":10,"t":"Don’t be afraid of the things which you are about to suffer. Behold, the devil is about to throw some of you into prison, that you may be tested; and you will have oppression for ten days. Be faithful to death, and I will give you the crown of life."},{"v":11,"t":"He who has an ear, let him hear what the Spirit says to the assemblies. He who overcomes won’t be harmed by the second death."},{"v":12,"t":"“To the angel of the assembly in Pergamum write: “He who has the sharp two-edged sword says these things:"},{"v":13,"t":"“I know your works and where you dwell, where Satan’s throne is. You hold firmly to my name, and didn’t deny my faith in the days of Antipas my witness, my faithful one, who was killed among you, where Satan dwells."},{"v":14,"t":"But I have a few things against you, because you have there some who hold the teaching of Balaam, who taught Balak to throw a stumbling block before the children of Israel, to eat things sacrificed to idols, and to commit sexual immorality."},{"v":15,"t":"So also you likewise have some who hold to the teaching of the Nicolaitans."},{"v":16,"t":"Repent therefore, or else I am coming to you quickly and I will make war against them with the sword of my mouth."},{"v":17,"t":"He who has an ear, let him hear what the Spirit says to the assemblies. To him who overcomes, to him I will give of the hidden manna, and I will give him a white stone, and on the stone a new name written which no one knows but he who receives it."},{"v":18,"t":"“To the angel of the assembly in Thyatira write: “The Son of God, who has his eyes like a flame of fire, and his feet are like burnished brass, says these things:"},{"v":19,"t":"“I know your works, your love, faith, service, patient endurance, and that your last works are more than the first."},{"v":20,"t":"But I have this against you, that you tolerate your woman Jezebel, who calls herself a prophetess. She teaches and seduces my servants to commit sexual immorality and to eat things sacrificed to idols."},{"v":21,"t":"I gave her time to repent, but she refuses to repent of her sexual immorality."},{"v":22,"t":"Behold, I will throw her and those who commit adultery with her into a bed of great oppression, unless they repent of her works."},{"v":23,"t":"I will kill her children with Death, and all the assemblies will know that I am he who searches the minds and hearts. I will give to each one of you according to your deeds."},{"v":24,"t":"But to you I say, to the rest who are in Thyatira—as many as don’t have this teaching, who don’t know what some call ‘the deep things of Satan’—to you I say, I am not putting any other burden on you."},{"v":25,"t":"Nevertheless, hold that which you have firmly until I come."},{"v":26,"t":"He who overcomes, and he who keeps my works to the end, to him I will give authority over the nations."},{"v":27,"t":"He will rule them with a rod of iron, shattering them like clay pots, as I also have received of my Father;"},{"v":28,"t":"and I will give him the morning star."},{"v":29,"t":"He who has an ear, let him hear what the Spirit says to the assemblies."}]},"3":{"en":[{"v":1,"t":"“And to the angel of the assembly in Sardis write: “He who has the seven Spirits of God and the seven stars says these things: “I know your works, that you have a reputation of being alive, but you are dead."},{"v":2,"t":"Wake up and strengthen the things that remain, which you were about to throw away, for I have found no works of yours perfected before my God."},{"v":3,"t":"Remember therefore how you have received and heard. Keep it and repent. If therefore you won’t watch, I will come as a thief, and you won’t know what hour I will come upon you."},{"v":4,"t":"Nevertheless you have a few names in Sardis that didn’t defile their garments. They will walk with me in white, for they are worthy."},{"v":5,"t":"He who overcomes will be arrayed in white garments, and I will in no way blot his name out of the book of life, and I will confess his name before my Father, and before his angels."},{"v":6,"t":"He who has an ear, let him hear what the Spirit says to the assemblies."},{"v":7,"t":"“To the angel of the assembly in Philadelphia write: “He who is holy, he who is true, he who has the key of David, he who opens and no one can shut, and who shuts and no one opens, says these things:"},{"v":8,"t":"“I know your works (behold, I have set before you an open door, which no one can shut), that you have a little power, and kept my word, and didn’t deny my name."},{"v":9,"t":"Behold, I make some of the synagogue of Satan, of those who say they are Jews, and they are not, but lie—behold, I will make them to come and worship before your feet, and to know that I have loved you."},{"v":10,"t":"Because you kept my command to endure, I also will keep you from the hour of testing which is to come on the whole world, to test those who dwell on the earth."},{"v":11,"t":"I am coming quickly! Hold firmly that which you have, so that no one takes your crown."},{"v":12,"t":"He who overcomes, I will make him a pillar in the temple of my God, and he will go out from there no more. I will write on him the name of my God and the name of the city of my God, the new Jerusalem, which comes down out of heaven from my God, and my own new name."},{"v":13,"t":"He who has an ear, let him hear what the Spirit says to the assemblies."},{"v":14,"t":"“To the angel of the assembly in Laodicea write: “The Amen, the Faithful and True Witness, the Beginning of God’s creation, says these things:"},{"v":15,"t":"“I know your works, that you are neither cold nor hot. I wish you were cold or hot."},{"v":16,"t":"So, because you are lukewarm, and neither hot nor cold, I will vomit you out of my mouth."},{"v":17,"t":"Because you say, ‘I am rich, and have gotten riches, and have need of nothing,’ and don’t know that you are the wretched one, miserable, poor, blind, and naked;"},{"v":18,"t":"I counsel you to buy from me gold refined by fire, that you may become rich; and white garments, that you may clothe yourself, and that the shame of your nakedness may not be revealed; and eye salve to anoint your eyes, that you may see."},{"v":19,"t":"As many as I love, I reprove and chasten. Be zealous therefore, and repent."},{"v":20,"t":"Behold, I stand at the door and knock. If anyone hears my voice and opens the door, then I will come in to him and will dine with him, and he with me."},{"v":21,"t":"He who overcomes, I will give to him to sit down with me on my throne, as I also overcame and sat down with my Father on his throne."},{"v":22,"t":"He who has an ear, let him hear what the Spirit says to the assemblies.”"}]},"4":{"en":[{"v":1,"t":"After these things I looked and saw a door opened in heaven; and the first voice that I heard, like a trumpet speaking with me, was one saying, “Come up here, and I will show you the things which must happen after this.”"},{"v":2,"t":"Immediately I was in the Spirit. Behold, there was a throne set in heaven, and one sitting on the throne"},{"v":3,"t":"that looked like a jasper stone and a sardius. There was a rainbow around the throne, like an emerald to look at."},{"v":4,"t":"Around the throne were twenty-four thrones. On the thrones were twenty-four elders sitting, dressed in white garments, with crowns of gold on their heads."},{"v":5,"t":"Out of the throne proceed lightnings, sounds, and thunders. There were seven lamps of fire burning before his throne, which are the seven Spirits of God."},{"v":6,"t":"Before the throne was something like a sea of glass, similar to crystal. In the middle of the throne, and around the throne were four living creatures full of eyes before and behind."},{"v":7,"t":"The first creature was like a lion, the second creature like a calf, the third creature had a face like a man, and the fourth was like a flying eagle."},{"v":8,"t":"The four living creatures, each one of them having six wings, are full of eyes around and within. They have no rest day and night, saying, “Holy, holy, holy is the Lord God, the Almighty, who was and who is and who is to come!”"},{"v":9,"t":"When the living creatures give glory, honor, and thanks to him who sits on the throne, to him who lives forever and ever,"},{"v":10,"t":"the twenty-four elders fall down before him who sits on the throne and worship him who lives forever and ever, and throw their crowns before the throne, saying,"},{"v":11,"t":"“Worthy are you, our Lord and God, the Holy One, to receive the glory, the honor, and the power, for you created all things, and because of your desire they existed and were created!”"}]},"5":{"en":[{"v":1,"t":"I saw, in the right hand of him who sat on the throne, a book written inside and outside, sealed shut with seven seals."},{"v":2,"t":"I saw a mighty angel proclaiming with a loud voice, “Who is worthy to open the book, and to break its seals?”"},{"v":3,"t":"No one in heaven above, or on the earth, or under the earth, was able to open the book or to look in it."},{"v":4,"t":"Then I wept much, because no one was found worthy to open the book or to look in it."},{"v":5,"t":"One of the elders said to me, “Don’t weep. Behold, the Lion who is of the tribe of Judah, the Root of David, has overcome: he who opens the book and its seven seals.”"},{"v":6,"t":"I saw in the middle of the throne and of the four living creatures, and in the middle of the elders, a Lamb standing, as though it had been slain, having seven horns and seven eyes, which are the seven Spirits of God, sent out into all the earth."},{"v":7,"t":"Then he came, and he took it out of the right hand of him who sat on the throne."},{"v":8,"t":"Now when he had taken the book, the four living creatures and the twenty-four elders fell down before the Lamb, each one having a harp, and golden bowls full of incense, which are the prayers of the saints."},{"v":9,"t":"They sang a new song, saying, “You are worthy to take the book and to open its seals, for you were killed, and bought us for God with your blood out of every tribe, language, people, and nation,"},{"v":10,"t":"and made us kings and priests to our God; and we will reign on the earth.”"},{"v":11,"t":"I looked, and I heard something like a voice of many angels around the throne, the living creatures, and the elders. The number of them was ten thousands of ten thousands, and thousands of thousands,"},{"v":12,"t":"saying with a loud voice, “Worthy is the Lamb who has been killed to receive the power, wealth, wisdom, strength, honor, glory, and blessing!”"},{"v":13,"t":"I heard every created thing which is in heaven, on the earth, under the earth, on the sea, and everything in them, saying, “To him who sits on the throne and to the Lamb be the blessing, the honor, the glory, and the dominion, forever and ever! Amen!”"},{"v":14,"t":"The four living creatures said, “Amen!” Then the elders fell down and worshiped."}]},"6":{"en":[{"v":1,"t":"I saw that the Lamb opened one of the seven seals, and I heard one of the four living creatures saying, as with a voice of thunder, “Come and see!”"},{"v":2,"t":"Then a white horse appeared, and he who sat on it had a bow. A crown was given to him, and he came out conquering, and to conquer."},{"v":3,"t":"When he opened the second seal, I heard the second living creature saying, “Come!”"},{"v":4,"t":"Another came out, a red horse. To him who sat on it was given power to take peace from the earth, and that they should kill one another. There was given to him a great sword."},{"v":5,"t":"When he opened the third seal, I heard the third living creature saying, “Come and see!” And behold, a black horse, and he who sat on it had a balance in his hand."},{"v":6,"t":"I heard a voice in the middle of the four living creatures saying, “A choenix of wheat for a denarius, and three choenix of barley for a denarius! Don’t damage the oil and the wine!”"},{"v":7,"t":"When he opened the fourth seal, I heard the fourth living creature saying, “Come and see!”"},{"v":8,"t":"And behold, a pale horse, and the name of he who sat on it was Death. Hades followed with him. Authority over one fourth of the earth, to kill with the sword, with famine, with death, and by the wild animals of the earth was given to him."},{"v":9,"t":"When he opened the fifth seal, I saw underneath the altar the souls of those who had been killed for the Word of God, and for the testimony of the Lamb which they had."},{"v":10,"t":"They cried with a loud voice, saying, “How long, Master, the holy and true, until you judge and avenge our blood on those who dwell on the earth?”"},{"v":11,"t":"A long white robe was given to each of them. They were told that they should rest yet for a while, until their fellow servants and their brothers, who would also be killed even as they were, should complete their course."},{"v":12,"t":"I saw when he opened the sixth seal, and there was a great earthquake. The sun became black as sackcloth made of hair, and the whole moon became as blood."},{"v":13,"t":"The stars of the sky fell to the earth, like a fig tree dropping its unripe figs when it is shaken by a great wind."},{"v":14,"t":"The sky was removed like a scroll when it is rolled up. Every mountain and island was moved out of its place."},{"v":15,"t":"The kings of the earth, the princes, the commanding officers, the rich, the strong, and every slave and free person, hid themselves in the caves and in the rocks of the mountains."},{"v":16,"t":"They told the mountains and the rocks, “Fall on us, and hide us from the face of him who sits on the throne, and from the wrath of the Lamb,"},{"v":17,"t":"for the great day of his wrath has come, and who is able to stand?”"}]},"7":{"en":[{"v":1,"t":"After this, I saw four angels standing at the four corners of the earth, holding the four winds of the earth, so that no wind would blow on the earth, or on the sea, or on any tree."},{"v":2,"t":"I saw another angel ascend from the sunrise, having the seal of the living God. He cried with a loud voice to the four angels to whom it was given to harm the earth and the sea,"},{"v":3,"t":"saying, “Don’t harm the earth, the sea, or the trees, until we have sealed the bondservants of our God on their foreheads!”"},{"v":4,"t":"I heard the number of those who were sealed, one hundred forty-four thousand, sealed out of every tribe of the children of Israel:"},{"v":5,"t":"of the tribe of Judah twelve thousand were sealed, of the tribe of Reuben twelve thousand, of the tribe of Gad twelve thousand,"},{"v":6,"t":"of the tribe of Asher twelve thousand, of the tribe of Naphtali twelve thousand, of the tribe of Manasseh twelve thousand,"},{"v":7,"t":"of the tribe of Simeon twelve thousand, of the tribe of Levi twelve thousand, of the tribe of Issachar twelve thousand,"},{"v":8,"t":"of the tribe of Zebulun twelve thousand, of the tribe of Joseph twelve thousand, and of the tribe of Benjamin twelve thousand were sealed."},{"v":9,"t":"After these things I looked, and behold, a great multitude which no man could count, out of every nation and of all tribes, peoples, and languages, standing before the throne and before the Lamb, dressed in white robes, with palm branches in their hands."},{"v":10,"t":"They cried with a loud voice, saying, “Salvation be to our God, who sits on the throne, and to the Lamb!”"},{"v":11,"t":"All the angels were standing around the throne, the elders, and the four living creatures; and they fell on their faces before his throne, and worshiped God,"},{"v":12,"t":"saying, “Amen! Blessing, glory, wisdom, thanksgiving, honor, power, and might, be to our God forever and ever! Amen.”"},{"v":13,"t":"One of the elders answered, saying to me, “These who are arrayed in the white robes, who are they, and where did they come from?”"},{"v":14,"t":"I told him, “My lord, you know.” He said to me, “These are those who came out of the great suffering. They washed their robes and made them white in the Lamb’s blood."},{"v":15,"t":"Therefore they are before the throne of God, and they serve him day and night in his temple. He who sits on the throne will spread his tabernacle over them."},{"v":16,"t":"They will never be hungry or thirsty any more. The sun won’t beat on them, nor any heat;"},{"v":17,"t":"for the Lamb who is in the middle of the throne shepherds them and leads them to springs of life-giving waters. And God will wipe away every tear from their eyes.”"}]},"8":{"en":[{"v":1,"t":"When he opened the seventh seal, there was silence in heaven for about half an hour."},{"v":2,"t":"I saw the seven angels who stand before God, and seven trumpets were given to them."},{"v":3,"t":"Another angel came and stood over the altar, having a golden censer. Much incense was given to him, that he should add it to the prayers of all the saints on the golden altar which was before the throne."},{"v":4,"t":"The smoke of the incense, with the prayers of the saints, went up before God out of the angel’s hand."},{"v":5,"t":"The angel took the censer, and he filled it with the fire of the altar, then threw it on the earth. Thunders, sounds, lightnings, and an earthquake followed."},{"v":6,"t":"The seven angels who had the seven trumpets prepared themselves to sound."},{"v":7,"t":"The first sounded, and there followed hail and fire, mixed with blood, and they were thrown to the earth. One third of the earth was burned up, and one third of the trees were burned up, and all green grass was burned up."},{"v":8,"t":"The second angel sounded, and something like a great burning mountain was thrown into the sea. One third of the sea became blood,"},{"v":9,"t":"and one third of the living creatures which were in the sea died. One third of the ships were destroyed."},{"v":10,"t":"The third angel sounded, and a great star fell from the sky, burning like a torch, and it fell on one third of the rivers, and on the springs of water."},{"v":11,"t":"The name of the star is “Wormwood.” One third of the waters became wormwood. Many people died from the waters, because they were made bitter."},{"v":12,"t":"The fourth angel sounded, and one third of the sun was struck, and one third of the moon, and one third of the stars, so that one third of them would be darkened; and the day wouldn’t shine for one third of it, and the night in the same way."},{"v":13,"t":"I saw, and I heard an eagle, flying in mid heaven, saying with a loud voice, “Woe! Woe! Woe to those who dwell on the earth, because of the other blasts of the trumpets of the three angels, who are yet to sound!”"}]},"9":{"en":[{"v":1,"t":"The fifth angel sounded, and I saw a star from the sky which had fallen to the earth. The key to the pit of the abyss was given to him."},{"v":2,"t":"He opened the pit of the abyss, and smoke went up out of the pit, like the smoke from a burning furnace. The sun and the air were darkened because of the smoke from the pit."},{"v":3,"t":"Then out of the smoke came locusts on the earth, and power was given to them, as the scorpions of the earth have power."},{"v":4,"t":"They were told that they should not hurt the grass of the earth, neither any green thing, neither any tree, but only those people who don’t have God’s seal on their foreheads."},{"v":5,"t":"They were given power, not to kill them, but to torment them for five months. Their torment was like the torment of a scorpion when it strikes a person."},{"v":6,"t":"In those days people will seek death, and will in no way find it. They will desire to die, and death will flee from them."},{"v":7,"t":"The shapes of the locusts were like horses prepared for war. On their heads were something like golden crowns, and their faces were like people’s faces."},{"v":8,"t":"They had hair like women’s hair, and their teeth were like those of lions."},{"v":9,"t":"They had breastplates like breastplates of iron. The sound of their wings was like the sound of many chariots and horses rushing to war."},{"v":10,"t":"They have tails like those of scorpions, with stingers. In their tails they have power to harm men for five months."},{"v":11,"t":"They have over them as king the angel of the abyss. His name in Hebrew is “Abaddon”, but in Greek, he has the name “Apollyon”."},{"v":12,"t":"The first woe is past. Behold, there are still two woes coming after this."},{"v":13,"t":"The sixth angel sounded. I heard a voice from the horns of the golden altar which is before God,"},{"v":14,"t":"saying to the sixth angel who had the trumpet, “Free the four angels who are bound at the great river Euphrates!”"},{"v":15,"t":"The four angels were freed who had been prepared for that hour and day and month and year, so that they might kill one third of mankind."},{"v":16,"t":"The number of the armies of the horsemen was two hundred million. I heard the number of them."},{"v":17,"t":"Thus I saw the horses in the vision and those who sat on them, having breastplates of fiery red, hyacinth blue, and sulfur yellow; and the horses’ heads resembled lions’ heads. Out of their mouths proceed fire, smoke, and sulfur."},{"v":18,"t":"By these three plagues, one third of mankind was killed: by the fire, the smoke, and the sulfur, which proceeded out of their mouths."},{"v":19,"t":"For the power of the horses is in their mouths and in their tails. For their tails are like serpents, and have heads; and with them they harm."},{"v":20,"t":"The rest of mankind, who were not killed with these plagues, didn’t repent of the works of their hands, that they wouldn’t worship demons, and the idols of gold, and of silver, and of brass, and of stone, and of wood, which can’t see, hear, or walk."},{"v":21,"t":"They didn’t repent of their murders, their sorceries, their sexual immorality, or their thefts."}]},"10":{"en":[{"v":1,"t":"I saw a mighty angel coming down out of the sky, clothed with a cloud. A rainbow was on his head. His face was like the sun, and his feet like pillars of fire."},{"v":2,"t":"He had in his hand a little open book. He set his right foot on the sea, and his left on the land."},{"v":3,"t":"He cried with a loud voice, as a lion roars. When he cried, the seven thunders uttered their voices."},{"v":4,"t":"When the seven thunders sounded, I was about to write; but I heard a voice from the sky saying, “Seal up the things which the seven thunders said, and don’t write them.”"},{"v":5,"t":"The angel whom I saw standing on the sea and on the land lifted up his right hand to the sky"},{"v":6,"t":"and swore by him who lives forever and ever, who created heaven and the things that are in it, the earth and the things that are in it, and the sea and the things that are in it, that there will no longer be delay,"},{"v":7,"t":"but in the days of the voice of the seventh angel, when he is about to sound, then the mystery of God is finished, as he declared to his servants the prophets."},{"v":8,"t":"The voice which I heard from heaven, again speaking with me, said, “Go, take the book which is open in the hand of the angel who stands on the sea and on the land.”"},{"v":9,"t":"I went to the angel, telling him to give me the little book. He said to me, “Take it and eat it. It will make your stomach bitter, but in your mouth it will be as sweet as honey.”"},{"v":10,"t":"I took the little book out of the angel’s hand, and ate it. It was as sweet as honey in my mouth. When I had eaten it, my stomach was made bitter."},{"v":11,"t":"They told me, “You must prophesy again over many peoples, nations, languages, and kings.”"}]},"11":{"en":[{"v":1,"t":"A reed like a rod was given to me. Someone said, “Rise and measure God’s temple, and the altar, and those who worship in it."},{"v":2,"t":"Leave out the court which is outside of the temple, and don’t measure it, for it has been given to the nations. They will tread the holy city under foot for forty-two months."},{"v":3,"t":"I will give power to my two witnesses, and they will prophesy one thousand two hundred sixty days, clothed in sackcloth.”"},{"v":4,"t":"These are the two olive trees and the two lamp stands, standing before the Lord of the earth."},{"v":5,"t":"If anyone desires to harm them, fire proceeds out of their mouth and devours their enemies. If anyone desires to harm them, he must be killed in this way."},{"v":6,"t":"These have the power to shut up the sky, that it may not rain during the days of their prophecy. They have power over the waters, to turn them into blood, and to strike the earth with every plague, as often as they desire."},{"v":7,"t":"When they have finished their testimony, the beast that comes up out of the abyss will make war with them, and overcome them, and kill them."},{"v":8,"t":"Their dead bodies will be in the street of the great city, which spiritually is called Sodom and Egypt, where also their Lord was crucified."},{"v":9,"t":"From among the peoples, tribes, languages, and nations, people will look at their dead bodies for three and a half days, and will not allow their dead bodies to be laid in a tomb."},{"v":10,"t":"Those who dwell on the earth will rejoice over them, and they will be glad. They will give gifts to one another, because these two prophets tormented those who dwell on the earth."},{"v":11,"t":"After the three and a half days, the breath of life from God entered into them, and they stood on their feet. Great fear fell on those who saw them."},{"v":12,"t":"I heard a loud voice from heaven saying to them, “Come up here!” They went up into heaven in a cloud, and their enemies saw them."},{"v":13,"t":"In that day there was a great earthquake, and a tenth of the city fell. Seven thousand people were killed in the earthquake, and the rest were terrified and gave glory to the God of heaven."},{"v":14,"t":"The second woe is past. Behold, the third woe comes quickly."},{"v":15,"t":"The seventh angel sounded, and great voices in heaven followed, saying, “The kingdom of the world has become the Kingdom of our Lord and of his Christ. He will reign forever and ever!”"},{"v":16,"t":"The twenty-four elders, who sit on their thrones before God’s throne, fell on their faces and worshiped God,"},{"v":17,"t":"saying: “We give you thanks, Lord God, the Almighty, the one who is and who was, because you have taken your great power and reigned."},{"v":18,"t":"The nations were angry, and your wrath came, as did the time for the dead to be judged, and to give your bondservants the prophets, their reward, as well as to the saints and those who fear your name, to the small and the great, and to destroy those who destroy the earth.”"},{"v":19,"t":"God’s temple that is in heaven was opened, and the ark of the Lord’s covenant was seen in his temple. Lightnings, sounds, thunders, an earthquake, and great hail followed."}]},"12":{"en":[{"v":1,"t":"A great sign was seen in heaven: a woman clothed with the sun, and the moon under her feet, and on her head a crown of twelve stars."},{"v":2,"t":"She was with child. She cried out in pain, laboring to give birth."},{"v":3,"t":"Another sign was seen in heaven. Behold, a great red dragon, having seven heads and ten horns, and on his heads seven crowns."},{"v":4,"t":"His tail drew one third of the stars of the sky, and threw them to the earth. The dragon stood before the woman who was about to give birth, so that when she gave birth he might devour her child."},{"v":5,"t":"She gave birth to a son, a male child, who is to rule all the nations with a rod of iron. Her child was caught up to God and to his throne."},{"v":6,"t":"The woman fled into the wilderness, where she has a place prepared by God, that there they may nourish her one thousand two hundred sixty days."},{"v":7,"t":"There was war in the sky. Michael and his angels made war on the dragon. The dragon and his angels made war."},{"v":8,"t":"They didn’t prevail. No place was found for them any more in heaven."},{"v":9,"t":"The great dragon was thrown down, the old serpent, he who is called the devil and Satan, the deceiver of the whole world. He was thrown down to the earth, and his angels were thrown down with him."},{"v":10,"t":"I heard a loud voice in heaven, saying, “Now the salvation, the power, and the Kingdom of our God, and the authority of his Christ has come; for the accuser of our brothers has been thrown down, who accuses them before our God day and night."},{"v":11,"t":"They overcame him because of the Lamb’s blood, and because of the word of their testimony. They didn’t love their life, even to death."},{"v":12,"t":"Therefore rejoice, heavens, and you who dwell in them. Woe to the earth and to the sea, because the devil has gone down to you, having great wrath, knowing that he has but a short time.”"},{"v":13,"t":"When the dragon saw that he was thrown down to the earth, he persecuted the woman who gave birth to the male child."},{"v":14,"t":"Two wings of the great eagle were given to the woman, that she might fly into the wilderness to her place, so that she might be nourished for a time, times, and half a time, from the face of the serpent."},{"v":15,"t":"The serpent spewed water out of his mouth after the woman like a river, that he might cause her to be carried away by the stream."},{"v":16,"t":"The earth helped the woman, and the earth opened its mouth and swallowed up the river which the dragon spewed out of his mouth."},{"v":17,"t":"The dragon grew angry with the woman, and went away to make war with the rest of her offspring, who keep God’s commandments and hold Jesus’ testimony."}]},"13":{"en":[{"v":1,"t":"Then I stood on the sand of the sea. I saw a beast coming up out of the sea, having ten horns and seven heads. On his horns were ten crowns, and on his heads, blasphemous names."},{"v":2,"t":"The beast which I saw was like a leopard, and his feet were like those of a bear, and his mouth like the mouth of a lion. The dragon gave him his power, his throne, and great authority."},{"v":3,"t":"One of his heads looked like it had been wounded fatally. His fatal wound was healed, and the whole earth marveled at the beast."},{"v":4,"t":"They worshiped the dragon because he gave his authority to the beast; and they worshiped the beast, saying, “Who is like the beast? Who is able to make war with him?”"},{"v":5,"t":"A mouth speaking great things and blasphemy was given to him. Authority to make war for forty-two months was given to him."},{"v":6,"t":"He opened his mouth for blasphemy against God, to blaspheme his name, his dwelling, and those who dwell in heaven."},{"v":7,"t":"It was given to him to make war with the saints and to overcome them. Authority over every tribe, people, language, and nation was given to him."},{"v":8,"t":"All who dwell on the earth will worship him, everyone whose name has not been written from the foundation of the world in the book of life of the Lamb who has been killed."},{"v":9,"t":"If anyone has an ear, let him hear."},{"v":10,"t":"If anyone is to go into captivity, he will go into captivity. If anyone is to be killed with the sword, he must be killed. Here is the endurance and the faith of the saints."},{"v":11,"t":"I saw another beast coming up out of the earth. He had two horns like a lamb and it spoke like a dragon."},{"v":12,"t":"He exercises all the authority of the first beast in his presence. He makes the earth and those who dwell in it to worship the first beast, whose fatal wound was healed."},{"v":13,"t":"He performs great signs, even making fire come down out of the sky to the earth in the sight of people."},{"v":14,"t":"He deceives my own people who dwell on the earth because of the signs he was granted to do in front of the beast, saying to those who dwell on the earth that they should make an image to the beast who had the sword wound and lived."},{"v":15,"t":"It was given to him to give breath to the image of the beast, that the image of the beast should both speak, and cause as many as wouldn’t worship the image of the beast to be killed."},{"v":16,"t":"He causes all, the small and the great, the rich and the poor, and the free and the slave, to be given marks on their right hands or on their foreheads;"},{"v":17,"t":"and that no one would be able to buy or to sell unless he has that mark, which is the name of the beast or the number of his name."},{"v":18,"t":"Here is wisdom. He who has understanding, let him calculate the number of the beast, for it is the number of a man. His number is six hundred sixty-six."}]},"14":{"en":[{"v":1,"t":"I saw, and behold, the Lamb standing on Mount Zion, and with him a number, one hundred forty-four thousand, having his name and the name of his Father written on their foreheads."},{"v":2,"t":"I heard a sound from heaven like the sound of many waters and like the sound of a great thunder. The sound which I heard was like that of harpists playing on their harps."},{"v":3,"t":"They sing a new song before the throne and before the four living creatures and the elders. No one could learn the song except the one hundred forty-four thousand, those who had been redeemed out of the earth."},{"v":4,"t":"These are those who were not defiled with women, for they are virgins. These are those who follow the Lamb wherever he goes. These were redeemed by Jesus from among men, the first fruits to God and to the Lamb."},{"v":5,"t":"In their mouth was found no lie, for they are blameless."},{"v":6,"t":"I saw an angel flying in mid heaven, having an eternal Good News to proclaim to those who dwell on the earth—to every nation, tribe, language, and people."},{"v":7,"t":"He said with a loud voice, “Fear the Lord, and give him glory, for the hour of his judgment has come. Worship him who made the heaven, the earth, the sea, and the springs of waters!”"},{"v":8,"t":"Another, a second angel, followed, saying, “Babylon the great has fallen, which has made all the nations to drink of the wine of the wrath of her sexual immorality.”"},{"v":9,"t":"Another angel, a third, followed them, saying with a great voice, “If anyone worships the beast and his image, and receives a mark on his forehead or on his hand,"},{"v":10,"t":"he also will drink of the wine of the wrath of God, which is prepared unmixed in the cup of his anger. He will be tormented with fire and sulfur in the presence of the holy angels and in the presence of the Lamb."},{"v":11,"t":"The smoke of their torment goes up forever and ever. They have no rest day and night, those who worship the beast and his image, and whoever receives the mark of his name."},{"v":12,"t":"Here is the perseverance of the saints, those who keep the commandments of God and the faith of Jesus.”"},{"v":13,"t":"I heard a voice from heaven saying, “Write, ‘Blessed are the dead who die in the Lord from now on.’” “Yes,” says the Spirit, “that they may rest from their labors, for their works follow with them.”"},{"v":14,"t":"I looked, and saw a white cloud, and on the cloud one sitting like a son of man, having on his head a golden crown, and in his hand a sharp sickle."},{"v":15,"t":"Another angel came out of the temple, crying with a loud voice to him who sat on the cloud, “Send your sickle and reap, for the hour to reap has come; for the harvest of the earth is ripe!”"},{"v":16,"t":"He who sat on the cloud thrust his sickle on the earth, and the earth was reaped."},{"v":17,"t":"Another angel came out of the temple which is in heaven. He also had a sharp sickle."},{"v":18,"t":"Another angel came out from the altar, he who has power over fire, and he called with a great voice to him who had the sharp sickle, saying, “Send your sharp sickle and gather the clusters of the vine of the earth, for the earth’s grapes are fully ripe!”"},{"v":19,"t":"The angel thrust his sickle into the earth, and gathered the vintage of the earth and threw it into the great wine press of the wrath of God."},{"v":20,"t":"The wine press was trodden outside of the city, and blood came out of the wine press, up to the bridles of the horses, as far as one thousand six hundred stadia."}]},"15":{"en":[{"v":1,"t":"I saw another great and marvelous sign in the sky: seven angels having the seven last plagues, for in them God’s wrath is finished."},{"v":2,"t":"I saw something like a sea of glass mixed with fire, and those who overcame the beast, his image, and the number of his name, standing on the sea of glass, having harps of God."},{"v":3,"t":"They sang the song of Moses, the servant of God, and the song of the Lamb, saying, “Great and marvelous are your works, Lord God, the Almighty! Righteous and true are your ways, you King of the nations."},{"v":4,"t":"Who wouldn’t fear you, Lord, and glorify your name? For you only are holy. For all the nations will come and worship before you. For your righteous acts have been revealed.”"},{"v":5,"t":"After these things I looked, and the temple of the tabernacle of the testimony in heaven was opened."},{"v":6,"t":"The seven angels who had the seven plagues came out, clothed with pure, bright linen, and wearing golden sashes around their chests."},{"v":7,"t":"One of the four living creatures gave to the seven angels seven golden bowls full of the wrath of God, who lives forever and ever."},{"v":8,"t":"The temple was filled with smoke from the glory of God and from his power. No one was able to enter into the temple until the seven plagues of the seven angels would be finished."}]},"16":{"en":[{"v":1,"t":"I heard a loud voice out of the temple, saying to the seven angels, “Go and pour out the seven bowls of the wrath of God on the earth!”"},{"v":2,"t":"The first went, and poured out his bowl into the earth, and it became a harmful and painful sore on the people who had the mark of the beast, and who worshiped his image."},{"v":3,"t":"The second angel poured out his bowl into the sea, and it became blood as of a dead man. Every living thing in the sea died."},{"v":4,"t":"The third poured out his bowl into the rivers and springs of water, and they became blood."},{"v":5,"t":"I heard the angel of the waters saying, “You are righteous, who are and who were, O Holy One, because you have judged these things."},{"v":6,"t":"For they poured out the blood of saints and prophets, and you have given them blood to drink. They deserve this.”"},{"v":7,"t":"I heard the altar saying, “Yes, Lord God, the Almighty, true and righteous are your judgments.”"},{"v":8,"t":"The fourth poured out his bowl on the sun, and it was given to him to scorch men with fire."},{"v":9,"t":"People were scorched with great heat, and people blasphemed the name of God who has the power over these plagues. They didn’t repent and give him glory."},{"v":10,"t":"The fifth poured out his bowl on the throne of the beast, and his kingdom was darkened. They gnawed their tongues because of the pain,"},{"v":11,"t":"and they blasphemed the God of heaven because of their pains and their sores. They still didn’t repent of their works."},{"v":12,"t":"The sixth poured out his bowl on the great river, the Euphrates. Its water was dried up, that the way might be prepared for the kings that come from the sunrise."},{"v":13,"t":"I saw coming out of the mouth of the dragon, and out of the mouth of the beast, and out of the mouth of the false prophet, three unclean spirits, something like frogs;"},{"v":14,"t":"for they are spirits of demons, performing signs, which go out to the kings of the whole inhabited earth, to gather them together for the war of that great day of God the Almighty."},{"v":15,"t":"“Behold, I come like a thief. Blessed is he who watches, and keeps his clothes, so that he doesn’t walk naked, and they see his shame.”"},{"v":16,"t":"He gathered them together into the place which is called in Hebrew, “Harmagedon”."},{"v":17,"t":"The seventh poured out his bowl into the air. A loud voice came out of the temple of heaven, from the throne, saying, “It is done!”"},{"v":18,"t":"There were lightnings, sounds, and thunders; and there was a great earthquake such as has not happened since there were men on the earth—so great an earthquake and so mighty."},{"v":19,"t":"The great city was divided into three parts, and the cities of the nations fell. Babylon the great was remembered in the sight of God, to give to her the cup of the wine of the fierceness of his wrath."},{"v":20,"t":"Every island fled away, and the mountains were not found."},{"v":21,"t":"Great hailstones, about the weight of a talent, came down out of the sky on people. People blasphemed God because of the plague of the hail, for this plague was exceedingly severe."}]},"17":{"en":[{"v":1,"t":"One of the seven angels who had the seven bowls came and spoke with me, saying, “Come here. I will show you the judgment of the great prostitute who sits on many waters,"},{"v":2,"t":"with whom the kings of the earth committed sexual immorality. Those who dwell in the earth were made drunken with the wine of her sexual immorality.”"},{"v":3,"t":"He carried me away in the Spirit into a wilderness. I saw a woman sitting on a scarlet-colored beast, full of blasphemous names, having seven heads and ten horns."},{"v":4,"t":"The woman was dressed in purple and scarlet, and decked with gold and precious stones and pearls, having in her hand a golden cup full of abominations and the impurities of the sexual immorality of the earth."},{"v":5,"t":"And on her forehead a name was written, “MYSTERY, BABYLON THE GREAT, THE MOTHER OF THE PROSTITUTES AND OF THE ABOMINATIONS OF THE EARTH.”"},{"v":6,"t":"I saw the woman drunken with the blood of the saints and with the blood of the martyrs of Jesus. When I saw her, I wondered with great amazement."},{"v":7,"t":"The angel said to me, “Why do you wonder? I will tell you the mystery of the woman and of the beast that carries her, which has the seven heads and the ten horns."},{"v":8,"t":"The beast that you saw was, and is not; and is about to come up out of the abyss and to go into destruction. Those who dwell on the earth and whose names have not been written in the book of life from the foundation of the world will marvel when they see that the beast was, and is not, and shall be present."},{"v":9,"t":"Here is the mind that has wisdom. The seven heads are seven mountains on which the woman sits."},{"v":10,"t":"They are seven kings. Five have fallen, the one is, and the other has not yet come. When he comes, he must continue a little while."},{"v":11,"t":"The beast that was, and is not, is himself also an eighth, and is of the seven; and he goes to destruction."},{"v":12,"t":"The ten horns that you saw are ten kings who have received no kingdom as yet, but they receive authority as kings with the beast for one hour."},{"v":13,"t":"These have one mind, and they give their power and authority to the beast."},{"v":14,"t":"These will war against the Lamb, and the Lamb will overcome them, for he is Lord of lords and King of kings; and those who are with him are called, chosen, and faithful.”"},{"v":15,"t":"He said to me, “The waters which you saw, where the prostitute sits, are peoples, multitudes, nations, and languages."},{"v":16,"t":"The ten horns which you saw, they and the beast will hate the prostitute, will make her desolate, will strip her naked, will eat her flesh, and will burn her utterly with fire."},{"v":17,"t":"For God has put in their hearts to do what he has in mind, to be of one mind, and to give their kingdom to the beast, until the words of God should be accomplished."},{"v":18,"t":"The woman whom you saw is the great city which reigns over the kings of the earth.”"}]},"18":{"en":[{"v":1,"t":"After these things, I saw another angel coming down out of the sky, having great authority. The earth was illuminated with his glory."},{"v":2,"t":"He cried with a mighty voice, saying, “Fallen, fallen is Babylon the great, and she has become a habitation of demons, a prison of every unclean spirit, and a prison of every unclean and hated bird!"},{"v":3,"t":"For all the nations have drunk of the wine of the wrath of her sexual immorality, the kings of the earth committed sexual immorality with her, and the merchants of the earth grew rich from the abundance of her luxury.”"},{"v":4,"t":"I heard another voice from heaven, saying, “Come out of her, my people, that you have no participation in her sins, and that you don’t receive of her plagues,"},{"v":5,"t":"for her sins have reached to the sky, and God has remembered her iniquities."},{"v":6,"t":"Return to her just as she returned, and repay her double as she did, and according to her works. In the cup which she mixed, mix to her double."},{"v":7,"t":"However much she glorified herself and grew wanton, so much give her of torment and mourning. For she says in her heart, ‘I sit a queen, and am no widow, and will in no way see mourning.’"},{"v":8,"t":"Therefore in one day her plagues will come: death, mourning, and famine; and she will be utterly burned with fire, for the Lord God who has judged her is strong."},{"v":9,"t":"The kings of the earth who committed sexual immorality and lived wantonly with her will weep and wail over her, when they look at the smoke of her burning,"},{"v":10,"t":"standing far away for the fear of her torment, saying, ‘Woe, woe, the great city, Babylon, the strong city! For your judgment has come in one hour.’"},{"v":11,"t":"The merchants of the earth weep and mourn over her, for no one buys their merchandise any more:"},{"v":12,"t":"merchandise of gold, silver, precious stones, pearls, fine linen, purple, silk, scarlet, all expensive wood, every vessel of ivory, every vessel made of most precious wood, and of brass, and iron, and marble;"},{"v":13,"t":"and cinnamon, incense, perfume, frankincense, wine, olive oil, fine flour, wheat, cattle, sheep, horses, chariots, and people’s bodies and souls."},{"v":14,"t":"The fruits which your soul lusted after have been lost to you. All things that were dainty and sumptuous have perished from you, and you will find them no more at all."},{"v":15,"t":"The merchants of these things, who were made rich by her, will stand far away for the fear of her torment, weeping and mourning,"},{"v":16,"t":"saying, ‘Woe, woe, the great city, she who was dressed in fine linen, purple, and scarlet, and decked with gold and precious stones and pearls!"},{"v":17,"t":"For in an hour such great riches are made desolate.’ Every ship master, and everyone who sails anywhere, and mariners, and as many as gain their living by sea, stood far away,"},{"v":18,"t":"and cried out as they looked at the smoke of her burning, saying, ‘What is like the great city?’"},{"v":19,"t":"They cast dust on their heads, and cried, weeping and mourning, saying, ‘Woe, woe, the great city, in which all who had their ships in the sea were made rich by reason of her great wealth!’ For she is made desolate in one hour."},{"v":20,"t":"“Rejoice over her, O heaven, you saints, apostles, and prophets, for God has judged your judgment on her.”"},{"v":21,"t":"A mighty angel took up a stone like a great millstone and cast it into the sea, saying, “Thus with violence will Babylon, the great city, be thrown down, and will be found no more at all."},{"v":22,"t":"The voice of harpists, minstrels, flute players, and trumpeters will be heard no more at all in you. No craftsman of whatever craft will be found any more at all in you. The sound of a mill will be heard no more at all in you."},{"v":23,"t":"The light of a lamp will shine no more at all in you. The voice of the bridegroom and of the bride will be heard no more at all in you, for your merchants were the princes of the earth; for with your sorcery all the nations were deceived."},{"v":24,"t":"In her was found the blood of prophets and of saints, and of all who have been slain on the earth.”"}]},"19":{"en":[{"v":1,"t":"After these things I heard something like a loud voice of a great multitude in heaven, saying, “Hallelujah! Salvation, power, and glory belong to our God;"},{"v":2,"t":"for his judgments are true and righteous. For he has judged the great prostitute who corrupted the earth with her sexual immorality, and he has avenged the blood of his servants at her hand.”"},{"v":3,"t":"A second said, “Hallelujah! Her smoke goes up forever and ever.”"},{"v":4,"t":"The twenty-four elders and the four living creatures fell down and worshiped God who sits on the throne, saying, “Amen! Hallelujah!”"},{"v":5,"t":"A voice came from the throne, saying, “Give praise to our God, all you his servants, you who fear him, the small and the great!”"},{"v":6,"t":"I heard something like the voice of a great multitude, and like the voice of many waters, and like the voice of mighty thunders, saying, “Hallelujah! For the Lord our God, the Almighty, reigns!"},{"v":7,"t":"Let’s rejoice and be exceedingly glad, and let’s give the glory to him. For the wedding of the Lamb has come, and his wife has made herself ready.”"},{"v":8,"t":"It was given to her that she would array herself in bright, pure, fine linen, for the fine linen is the righteous acts of the saints."},{"v":9,"t":"He said to me, “Write, ‘Blessed are those who are invited to the wedding supper of the Lamb.’” He said to me, “These are true words of God.”"},{"v":10,"t":"I fell down before his feet to worship him. He said to me, “Look! Don’t do it! I am a fellow bondservant with you and with your brothers who hold the testimony of Jesus. Worship God, for the testimony of Jesus is the Spirit of Prophecy.”"},{"v":11,"t":"I saw the heaven opened, and behold, a white horse, and he who sat on it is called Faithful and True. In righteousness he judges and makes war."},{"v":12,"t":"His eyes are a flame of fire, and on his head are many crowns. He has names written and a name written which no one knows but he himself."},{"v":13,"t":"He is clothed in a garment sprinkled with blood. His name is called “The Word of God.”"},{"v":14,"t":"The armies which are in heaven, clothed in white, pure, fine linen, followed him on white horses."},{"v":15,"t":"Out of his mouth proceeds a sharp, double-edged sword that with it he should strike the nations. He will rule them with an iron rod. He treads the wine press of the fierceness of the wrath of God, the Almighty."},{"v":16,"t":"He has on his garment and on his thigh a name written, “KING OF KINGS AND LORD OF LORDS.”"},{"v":17,"t":"I saw an angel standing in the sun. He cried with a loud voice, saying to all the birds that fly in the sky, “Come! Be gathered together to the great supper of God,"},{"v":18,"t":"that you may eat the flesh of kings, the flesh of captains, the flesh of mighty men, and the flesh of horses and of those who sit on them, and the flesh of all men, both free and slave, small and great.”"},{"v":19,"t":"I saw the beast, the kings of the earth, and their armies, gathered together to make war against him who sat on the horse and against his army."},{"v":20,"t":"The beast was taken, and with him the false prophet who worked the signs in his sight, with which he deceived those who had received the mark of the beast and those who worshiped his image. These two were thrown alive into the lake of fire that burns with sulfur."},{"v":21,"t":"The rest were killed with the sword of him who sat on the horse, the sword which came out of his mouth. So all the birds were filled with their flesh."}]},"20":{"en":[{"v":1,"t":"I saw an angel coming down out of heaven, having the key of the abyss and a great chain in his hand."},{"v":2,"t":"He seized the dragon, the old serpent, who is the devil and Satan, who deceives the whole inhabited earth, and bound him for a thousand years,"},{"v":3,"t":"and cast him into the abyss, and shut it and sealed it over him, that he should deceive the nations no more until the thousand years were finished. After this, he must be freed for a short time."},{"v":4,"t":"I saw thrones, and they sat on them, and judgment was given to them. I saw the souls of those who had been beheaded for the testimony of Jesus and for the word of God, and such as didn’t worship the beast nor his image, and didn’t receive the mark on their forehead and on their hand. They lived and reigned with Christ for a thousand years."},{"v":5,"t":"The rest of the dead didn’t live until the thousand years were finished. This is the first resurrection."},{"v":6,"t":"Blessed and holy is he who has part in the first resurrection. Over these, the second death has no power, but they will be priests of God and of Christ, and will reign with him one thousand years."},{"v":7,"t":"And after the thousand years, Satan will be released from his prison"},{"v":8,"t":"and he will come out to deceive the nations which are in the four corners of the earth, Gog and Magog, to gather them together to the war, whose number is as the sand of the sea."},{"v":9,"t":"They went up over the width of the earth and surrounded the camp of the saints and the beloved city. Fire came down out of heaven from God and devoured them."},{"v":10,"t":"The devil who deceived them was thrown into the lake of fire and sulfur, where the beast and the false prophet are also. They will be tormented day and night forever and ever."},{"v":11,"t":"I saw a great white throne and him who sat on it, from whose face the earth and the heaven fled away. There was found no place for them."},{"v":12,"t":"I saw the dead, the great and the small, standing before the throne, and they opened books. Another book was opened, which is the book of life. The dead were judged out of the things which were written in the books, according to their works."},{"v":13,"t":"The sea gave up the dead who were in it. Death and Hades gave up the dead who were in them. They were judged, each one according to his works."},{"v":14,"t":"Death and Hades were thrown into the lake of fire. This is the second death, the lake of fire."},{"v":15,"t":"If anyone was not found written in the book of life, he was cast into the lake of fire."}]},"21":{"en":[{"v":1,"t":"I saw a new heaven and a new earth, for the first heaven and the first earth have passed away, and the sea is no more."},{"v":2,"t":"I saw the holy city, New Jerusalem, coming down out of heaven from God, prepared like a bride adorned for her husband."},{"v":3,"t":"I heard a loud voice out of heaven saying, “Behold, God’s dwelling is with people; and he will dwell with them, and they will be his people, and God himself will be with them as their God."},{"v":4,"t":"He will wipe away every tear from their eyes. Death will be no more; neither will there be mourning, nor crying, nor pain any more. The first things have passed away.”"},{"v":5,"t":"He who sits on the throne said, “Behold, I am making all things new.” He said, “Write, for these words of God are faithful and true.”"},{"v":6,"t":"He said to me, “I am the Alpha and the Omega, the Beginning and the End. I will give freely to him who is thirsty from the spring of the water of life."},{"v":7,"t":"He who overcomes, I will give him these things. I will be his God, and he will be my son."},{"v":8,"t":"But for the cowardly, unbelieving, sinners, abominable, murderers, sexually immoral, sorcerers, idolaters, and all liars, their part is in the lake that burns with fire and sulfur, which is the second death.”"},{"v":9,"t":"One of the seven angels who had the seven bowls which were loaded with the seven last plagues came, and he spoke with me, saying, “Come here. I will show you the bride, the Lamb’s wife.”"},{"v":10,"t":"He carried me away in the Spirit to a great and high mountain, and showed me the holy city, Jerusalem, coming down out of heaven from God,"},{"v":11,"t":"having the glory of God. Her light was like a most precious stone, like a jasper stone, clear as crystal;"},{"v":12,"t":"having a great and high wall with twelve gates, and at the gates twelve angels, and names written on them, which are the names of the twelve tribes of the children of Israel."},{"v":13,"t":"On the east were three gates, and on the north three gates, and on the south three gates, and on the west three gates."},{"v":14,"t":"The wall of the city had twelve foundations, and on them twelve names of the twelve Apostles of the Lamb."},{"v":15,"t":"He who spoke with me had for a measure a golden reed to measure the city, its gates, and its walls."},{"v":16,"t":"The city is square. Its length is as great as its width. He measured the city with the reed: twelve thousand twelve stadia. Its length, width, and height are equal."},{"v":17,"t":"Its wall is one hundred forty-four cubits, by the measure of a man, that is, of an angel."},{"v":18,"t":"The construction of its wall was jasper. The city was pure gold, like pure glass."},{"v":19,"t":"The foundations of the city’s wall were adorned with all kinds of precious stones. The first foundation was jasper, the second sapphire; the third chalcedony, the fourth emerald,"},{"v":20,"t":"the fifth sardonyx, the sixth sardius, the seventh chrysolite, the eighth beryl, the ninth topaz, the tenth chrysoprase, the eleventh jacinth, and the twelfth amethyst."},{"v":21,"t":"The twelve gates were twelve pearls. Each one of the gates was made of one pearl. The street of the city was pure gold, like transparent glass."},{"v":22,"t":"I saw no temple in it, for the Lord God the Almighty and the Lamb are its temple."},{"v":23,"t":"The city has no need for the sun or moon to shine, for the very glory of God illuminated it and its lamp is the Lamb."},{"v":24,"t":"The nations will walk in its light. The kings of the earth bring the glory and honor of the nations into it."},{"v":25,"t":"Its gates will in no way be shut by day (for there will be no night there),"},{"v":26,"t":"and they shall bring the glory and the honor of the nations into it so that they may enter."},{"v":27,"t":"There will in no way enter into it anything profane, or one who causes an abomination or a lie, but only those who are written in the Lamb’s book of life."}]},"22":{"en":[{"v":1,"t":"He showed me a river of water of life, clear as crystal, proceeding out of the throne of God and of the Lamb,"},{"v":2,"t":"in the middle of its street. On this side of the river and on that was the tree of life, bearing twelve kinds of fruits, yielding its fruit every month. The leaves of the tree were for the healing of the nations."},{"v":3,"t":"There will be no curse any more. The throne of God and of the Lamb will be in it, and his servants will serve him."},{"v":4,"t":"They will see his face, and his name will be on their foreheads."},{"v":5,"t":"There will be no night, and they need no lamp light or sun light; for the Lord God will illuminate them. They will reign forever and ever."},{"v":6,"t":"He said to me, “These words are faithful and true. The Lord God of the spirits of the prophets sent his angel to show to his bondservants the things which must happen soon.”"},{"v":7,"t":"“Behold, I am coming soon! Blessed is he who keeps the words of the prophecy of this book.”"},{"v":8,"t":"Now I, John, am the one who heard and saw these things. When I heard and saw, I fell down to worship before the feet of the angel who had shown me these things."},{"v":9,"t":"He said to me, “You must not do that! I am a fellow bondservant with you and with your brothers, the prophets, and with those who keep the words of this book. Worship God.”"},{"v":10,"t":"He said to me, “Don’t seal up the words of the prophecy of this book, for the time is at hand."},{"v":11,"t":"He who acts unjustly, let him act unjustly still. He who is filthy, let him be filthy still. He who is righteous, let him do righteousness still. He who is holy, let him be holy still.”"},{"v":12,"t":"“Behold, I am coming soon! My reward is with me, to repay to each man according to his work."},{"v":13,"t":"I am the Alpha and the Omega, the First and the Last, the Beginning and the End."},{"v":14,"t":"Blessed are those who do his commandments, that they may have the right to the tree of life, and may enter in by the gates into the city."},{"v":15,"t":"Outside are the dogs, the sorcerers, the sexually immoral, the murderers, the idolaters, and everyone who loves and practices falsehood."},{"v":16,"t":"I, Jesus, have sent my angel to testify these things to you for the assemblies. I am the root and the offspring of David, the Bright and Morning Star.”"},{"v":17,"t":"The Spirit and the bride say, “Come!” He who hears, let him say, “Come!” He who is thirsty, let him come. He who desires, let him take the water of life freely."},{"v":18,"t":"I testify to everyone who hears the words of the prophecy of this book: if anyone adds to them, God will add to him the plagues which are written in this book."},{"v":19,"t":"If anyone takes away from the words of the book of this prophecy, God will take away his part from the tree of life, and out of the holy city, which are written in this book."},{"v":20,"t":"He who testifies these things says, “Yes, I am coming soon.” Amen! Yes, come, Lord Jesus!"},{"v":21,"t":"The grace of the Lord Jesus Christ be with all the saints. Amen."}]}}});
